// ── Notificaciones emergentes nativas (Android/iOS) ──
// IMPORTANTE: Requiere agregar 'flutter_local_notifications: ^17.0.0'
// en pubspec.yaml y configurar el canal en AndroidManifest (permiso
// POST_NOTIFICATIONS en Android 13+ ya se solicita en PermisosApp).
import 'package:flutter_local_notifications/flutter_local_notifications.dart';

// ────────────────────────────────────────────────────────────
//  PUSH NOTIFIER — notificaciones emergentes nativas del SO
//  (banner, heads-up en Android, banner/alert en iOS).
//  Se usa desde NotificacionesService cada vez que detecta un
//  evento nuevo (mensaje, código, activación, etc.).
// ────────────────────────────────────────────────────────────
class PushNotifier {
  static final FlutterLocalNotificationsPlugin _plugin =
      FlutterLocalNotificationsPlugin();
  static bool _inicializado = false;
  static int _nextId = 1;

  static Future<void> inicializar() async {
    if (_inicializado) return;
    try {
      const androidInit = AndroidInitializationSettings('@mipmap/ic_launcher');
      const iosInit = DarwinInitializationSettings(
        requestAlertPermission: true,
        requestBadgePermission: true,
        requestSoundPermission: true,
        // Critical alerts: igual que Instagram, atraviesan modo silencio
        requestCriticalPermission: true,
      );
      const settings = InitializationSettings(
        android: androidInit, iOS: iosInit);
      await _plugin.initialize(settings);

      if (!kIsWeb && Platform.isAndroid) {
        // ── Canal Android — equivalente a alta prioridad de Instagram ──
        // Importance.max + sonido + vibración + bypass DND + bypass silencio
        // hacen que aparezca SIEMPRE como banner heads-up encima de todo.
        const canal = AndroidNotificationChannel(
          'tecnolider_alertas_v1',        // ← canal Tecno Líder v1
          'Alertas Tecno Líder',
          description: 'Mensajes, códigos, activaciones y eventos',
          importance: Importance.max,
          playSound: true,
          enableVibration: true,
          showBadge: true,
          enableLights: true,             // luz LED si el dispositivo tiene
        );
        final android = _plugin
            .resolvePlatformSpecificImplementation<
                AndroidFlutterLocalNotificationsPlugin>();
        await android?.createNotificationChannel(canal);
        // Permisos clave en Android 13+
        await android?.requestNotificationsPermission();
        // Android 12+ — permiso para programar alertas exactas
        try {
          await android?.requestExactAlarmsPermission();
        } catch (_) { /* algunos dispositivos no lo soportan, no es crítico */ }
        // Android 14+ — permiso para mostrar notif full-screen sobre
        // la pantalla de bloqueo (idéntico al banner de Instagram con
        // el teléfono apagado pero la app aún corriendo en background)
        try {
          await android?.requestFullScreenIntentPermission();
        } catch (_) { /* opcional */ }
      }

      if (!kIsWeb && Platform.isIOS) {
        // iOS — pedir explícitamente todos los permisos
        await _plugin
            .resolvePlatformSpecificImplementation<
                IOSFlutterLocalNotificationsPlugin>()
            ?.requestPermissions(
              alert: true,
              badge: true,
              sound: true,
              critical: true,
            );
      }

      _inicializado = true;
    } catch (e) {
      debugPrint('[PushNotifier] init error: $e');
    }
  }

  static Future<void> mostrar({
    required String titulo,
    required String mensaje,
  }) async {
    try {
      if (!_inicializado) await inicializar();

      // ── Android — replicar exactamente el comportamiento Instagram ──
      // Importance + Priority MAX, visibility public (se ve en lock
      // screen), category MESSAGE para que el SO lo trate como mensaje
      // personal (que es justo el caso "alguien te respondió"), y
      // ticker para el ruido de "WHOOSH" típico.
      final androidDetails = AndroidNotificationDetails(
        'tecnolider_alertas_v1',
        'Alertas Tecno Líder',
        channelDescription: 'Mensajes, códigos, activaciones y eventos',
        importance: Importance.max,
        priority: Priority.max,
        playSound: true,
        enableVibration: true,
        ticker: titulo,                    // texto que recorre la barra
        visibility: NotificationVisibility.public,
        category: AndroidNotificationCategory.message,
        // Hace que aparezca el banner flotante encima de todo.
        // En Android moderno esto + Importance.max es lo que necesita
        // para verse como Instagram.
        fullScreenIntent: false,           // true sería intrusivo de más
        autoCancel: true,                  // se borra al tocar
        styleInformation: BigTextStyleInformation(
          mensaje,
          contentTitle: titulo,
        ),
      );

      // ── iOS — interruptionLevel timeSensitive ──
      // En iOS 15+, "timeSensitive" es lo que usa Instagram: rompe el
      // modo silencio del usuario para mostrar el banner. "active"
      // (que teníamos antes) NO rompe Focus/Silent.
      const iosDetails = DarwinNotificationDetails(
        presentAlert: true,
        presentBadge: true,
        presentSound: true,
        interruptionLevel: InterruptionLevel.timeSensitive,
      );

      final details = NotificationDetails(
        android: androidDetails,
        iOS: iosDetails);
      await _plugin.show(_nextId++, titulo, mensaje, details);
    } catch (e) {
      debugPrint('[PushNotifier] mostrar error: $e');
    }
  }
}

// ════════════════════════════════════════════════════════════════════
//  SESIÓN PERSISTENTE — guarda credenciales para auto-login.
//
//  Antes la app cerraba sesión cada vez que se cerraba (incluso con
//  app swipe). Ahora guardamos correo + clave cifrados básicamente con
//  shared_preferences y al arrancar la app intentamos auto-login.
//
//  IMPORTANTE: SharedPreferences NO es almacenamiento seguro en sí
//  mismo. Para datos realmente sensibles habría que usar
//  flutter_secure_storage. Aquí lo aceptamos porque la app se usa en
//  red interna controlada y la BD ya valida cada request.
// ════════════════════════════════════════════════════════════════════
// ════════════════════════════════════════════════════════════════════
//  USUARIO MAESTRO — gestor de licencia del sistema Tecno Líder
// ════════════════════════════════════════════════════════════════════
//  Credenciales OCULTAS del proveedor (Tecno Líder no aparece en la
//  lista de Usuarios y NO se puede modificar desde la app).
//
//  CAPACIDADES EXCLUSIVAS:
//   · Acceder al "Panel Maestro" (oculto, accesible solo a este usuario).
//   · Bloquear/desbloquear el uso de la app a TODOS los demás usuarios.
//   · Sigue funcionando aunque la app esté bloqueada.
//
//  IMPORTANTE: las credenciales están hardcoded como `const`. Cambiarlas
//  requiere recompilar el APK. Esto es a propósito — protege contra
//  manipulación por usuarios técnicos del cliente.
// ════════════════════════════════════════════════════════════════════
class UsuarioMaestro {
  static const String correo = 'eleazarceccato@gmail.com';
  static const String clave  = 'Ejcm0507';
  static const String nombre = 'Soporte Tecno Líder';

  /// Determina si las credenciales pertenecen al usuario maestro.
  /// Compara correo en lower-case + clave exacta.
  static bool esMaestro(String correoIn, String claveIn) {
    return correoIn.trim().toLowerCase() == correo &&
           claveIn == clave;
  }

  /// Filtra una lista de Usuarios ocultando al maestro (por si alguna
  /// vez alguien decide importar el correo en la base de datos por
  /// error). Devuelve una nueva lista.
  static List<T> ocultar<T>(List<T> usuarios, String Function(T) correoOf) {
    return usuarios.where((u) => correoOf(u).toLowerCase() != correo).toList();
  }
}

// ════════════════════════════════════════════════════════════════════
//  LICENCIA — estado de bloqueo del sistema
// ════════════════════════════════════════════════════════════════════
//  Modelo simple del estado de licencia. Se sincroniza con el backend
//  vía endpoints `licencia/estado.php` y `licencia/log.php` (ver
//  README de implementación). Si el backend no responde, se usa la
//  caché local en SharedPreferences (last-known-good).
// ════════════════════════════════════════════════════════════════════
class EstadoLicencia {
  /// true → la app está SUSPENDIDA (mostrar pantalla de bloqueo).
  final bool bloqueada;
  /// Mensaje a mostrar en la pantalla de bloqueo (configurable desde
  /// el panel maestro o el backend).
  final String motivo;
  /// Teléfono de contacto del proveedor (configurable).
  final String telefonoContacto;
  /// Última fecha que el backend confirmó el estado (cache TTL).
  final DateTime? ultimaSincronizacion;

  const EstadoLicencia({
    this.bloqueada = false,
    this.motivo = 'Servicio suspendido por falta de pago',
    this.telefonoContacto = '0414-XXXXXXX',
    this.ultimaSincronizacion,
  });

  Map<String, dynamic> toMap() => {
    'bloqueada': bloqueada,
    'motivo': motivo,
    'telefono': telefonoContacto,
    'ultima_sync': ultimaSincronizacion?.toIso8601String(),
  };

  factory EstadoLicencia.fromMap(Map m) => EstadoLicencia(
    bloqueada: m['bloqueada'] == true || m['bloqueada'] == 1 || m['bloqueada'] == '1',
    motivo: m['motivo']?.toString() ?? 'Servicio suspendido por falta de pago',
    telefonoContacto: m['telefono']?.toString() ?? '0414-XXXXXXX',
    ultimaSincronizacion: m['ultima_sync'] != null
        ? DateTime.tryParse(m['ultima_sync'].toString())
        : null,
  );

  /// Estado inicial por defecto (NO bloqueado).
  factory EstadoLicencia.activo() => const EstadoLicencia(bloqueada: false);
}

class LicenciaService {
  // Caché en memoria — se actualiza al consultar el backend o al leer
  // de SharedPreferences.
  static EstadoLicencia _estado = EstadoLicencia.activo();
  static EstadoLicencia get estadoActual => _estado;

  // Claves de SharedPreferences
  static const _kBloqueada = 'licencia_bloqueada';
  static const _kMotivo    = 'licencia_motivo';
  static const _kTelefono  = 'licencia_telefono';
  static const _kSync      = 'licencia_ultima_sync';

  /// Carga el estado: primero intenta el backend (autoritativo), si
  /// falla cae a la caché local. Esto permite seguir funcionando
  /// offline si el cliente perdió red — pero si el último estado
  /// conocido era "bloqueada", sigue bloqueada (no se puede burlar
  /// desconectando internet).
  static Future<EstadoLicencia> cargarEstado() async {
    // 1. Intentar backend
    try {
      final raw = await _Api.get('licencia/estado').timeout(
        const Duration(seconds: 6));
      if (raw is Map) {
        final remoto = EstadoLicencia.fromMap({
          ...Map<String, dynamic>.from(raw),
          'ultima_sync': DateTime.now().toIso8601String(),
        });
        _estado = remoto;
        await _guardarCache(remoto);
        return remoto;
      }
    } catch (e) {
      debugPrint('[Licencia] backend no disponible: $e — usando caché');
    }

    // 2. Caer a caché local
    try {
      final prefs = await SharedPreferences.getInstance();
      final bloqueada = prefs.getBool(_kBloqueada) ?? false;
      final motivo    = prefs.getString(_kMotivo) ?? 'Servicio suspendido por falta de pago';
      final telefono  = prefs.getString(_kTelefono) ?? '0414-XXXXXXX';
      final syncStr   = prefs.getString(_kSync);
      _estado = EstadoLicencia(
        bloqueada: bloqueada,
        motivo: motivo,
        telefonoContacto: telefono,
        ultimaSincronizacion: syncStr != null ? DateTime.tryParse(syncStr) : null,
      );
    } catch (_) {
      _estado = EstadoLicencia.activo();
    }
    return _estado;
  }

  /// Cambia el estado en el backend Y en la caché local. Solo el
  /// usuario maestro debe poder llamar esto (la UI ya restringe).
  /// Si el backend falla, lanza excepción (no se aplica solo localmente
  /// para evitar inconsistencia entre dispositivos).
  static Future<void> aplicarBloqueo({
    required bool bloqueada,
    required String motivo,
    required String telefono,
    required String accionPor,
  }) async {
    // 1. Enviar al backend
    final body = {
      'bloqueada': bloqueada ? 1 : 0,
      'motivo': motivo,
      'telefono': telefono,
      'accion_por': accionPor,
      'fecha': DateTime.now().toIso8601String(),
    };
    try {
      await _Api.post('licencia/estado', body);
      // 2. Registrar en log de auditoría
      await _Api.post('licencia/log', {
        'evento': bloqueada ? 'BLOQUEO' : 'DESBLOQUEO',
        'motivo': motivo,
        'usuario': accionPor,
        'fecha': DateTime.now().toIso8601String(),
      }).catchError((e) {
        debugPrint('[Licencia] no se pudo registrar log: $e');
      });
    } catch (e) {
      throw Exception(
        'No se pudo aplicar el cambio en el servidor: $e\n'
        'El bloqueo NO se aplicó. Verifique la conexión.');
    }

    // 3. Actualizar caché local
    final nuevo = EstadoLicencia(
      bloqueada: bloqueada,
      motivo: motivo,
      telefonoContacto: telefono,
      ultimaSincronizacion: DateTime.now(),
    );
    _estado = nuevo;
    await _guardarCache(nuevo);
  }

  /// Lee el historial de bloqueos/desbloqueos desde el backend.
  static Future<List<Map<String, dynamic>>> historialLogs() async {
    try {
      final raw = await _Api.get('licencia/log');
      if (raw is List) {
        return raw.cast<Map<String, dynamic>>();
      }
    } catch (e) {
      debugPrint('[Licencia] error al cargar logs: $e');
    }
    return <Map<String, dynamic>>[];
  }

  static Future<void> _guardarCache(EstadoLicencia e) async {
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setBool(_kBloqueada, e.bloqueada);
      await prefs.setString(_kMotivo, e.motivo);
      await prefs.setString(_kTelefono, e.telefonoContacto);
      await prefs.setString(_kSync,
        e.ultimaSincronizacion?.toIso8601String() ??
        DateTime.now().toIso8601String());
    } catch (e) {
      debugPrint('[Licencia] error al guardar caché: $e');
    }
  }
}

class SesionPersistente {
  static const _kCorreo = 'sesion_correo';
  static const _kClave  = 'sesion_clave';
  static const _kAuto   = 'sesion_auto_login';

  /// Guarda las credenciales del usuario para próximas aperturas.
  static Future<void> guardar(String correo, String clave) async {
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString(_kCorreo, correo);
      await prefs.setString(_kClave, clave);
      await prefs.setBool(_kAuto, true);
    } catch (e) {
      debugPrint('[Sesion] guardar: $e');
    }
  }

  /// Borra las credenciales guardadas (al cerrar sesión voluntariamente).
  static Future<void> borrar() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.remove(_kCorreo);
      await prefs.remove(_kClave);
      await prefs.setBool(_kAuto, false);
    } catch (e) {
      debugPrint('[Sesion] borrar: $e');
    }
  }

  /// Lee las credenciales guardadas si auto-login está activo.
  /// Devuelve null si no hay sesión persistida.
  static Future<({String correo, String clave})?> leer() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final auto = prefs.getBool(_kAuto) ?? false;
      if (!auto) return null;
      final correo = prefs.getString(_kCorreo) ?? '';
      final clave  = prefs.getString(_kClave) ?? '';
      if (correo.isEmpty || clave.isEmpty) return null;
      return (correo: correo, clave: clave);
    } catch (e) {
      debugPrint('[Sesion] leer: $e');
      return null;
    }
  }
}

void main() async {
  WidgetsFlutterBinding.ensureInitialized();
  // Solicita todos los permisos necesarios antes de iniciar la app
  await PermisosApp.solicitarTodos();
  // Inicializa las notificaciones nativas del SO (banner / heads-up)
  await PushNotifier.inicializar();
  // Nota: Firebase Cloud Messaging deshabilitado por conflicto entre
  // firebase_messaging y mobile_scanner en iOS. Las notificaciones
  // funcionan vía polling al backend cuando la app está abierta.
  TasaBCVScheduler.iniciar();
  // Cargar impresora preferida del sistema (USB conectada a PC, red, etc).
  await ImpresoraSistema.cargarPreferida();
  // Cargar impresora Bluetooth térmica preferida (mac + nombre + ancho).
  // CRÍTICO: sin esto, al cerrar y abrir la app la impresora BT
  // configurada se "olvida" y `imprimirPdfInteligente` se salta el
  // bloque BT, haciendo que parezca que "no se conecta".
  await ImpresoraBT.cargarPreferida();
  // Cargar configuración del API de Conciliación BDV (Pago Móvil).
  await ConfigBDV.cargar();
  // Cargar categorías dinámicas de comisión (con sus tarifas).
  await ConfigSistema.cargarCategoriasComision();
  // Cargar categorías editables de productos (de aquí nacen las
  // categorías de comisión cuando se agrega una nueva).
  await CategoriasProductos.cargar();
  runApp(const MyApp());
}

// ============================================================
//  PERMISOS DE LA APLICACIÓN
//  Solicita al sistema operativo todos los permisos que la app
//  puede llegar a necesitar durante su ejecución (cámara, micrófono,
//  almacenamiento, ubicación, notificaciones, etc.). Se ejecuta una
//  sola vez al arrancar; si el usuario ya los concedió, el SO los
//  devolverá como "granted" sin volver a preguntar.
// ============================================================
class PermisosApp {
  /// Lista de permisos que la aplicación necesita.
  /// Se filtran automáticamente según la plataforma (Web, Android, iOS,
  /// Windows, macOS, Linux) para evitar errores de "permiso no soportado".
  static List<Permission> _permisosRequeridos() {
    // En Web no existe permission_handler como tal: los permisos (cámara,
    // micrófono, ubicación) los pide directamente el navegador cuando se
    // usan las APIs. Devolvemos lista vacía para no romper nada.
    if (kIsWeb) return const <Permission>[];

    // Permisos comunes a móviles (Android / iOS)
    final comunes = <Permission>[
      Permission.camera,            // Cámara (fotos, escáner QR, grabación)
      Permission.microphone,        // Micrófono (grabación de audio / llamadas)
      Permission.location,          // Ubicación en uso
      Permission.locationWhenInUse, // Ubicación mientras la app está abierta
      Permission.notification,      // Notificaciones push / locales
      Permission.photos,            // Acceso a la galería de fotos
      Permission.storage,           // Almacenamiento (Android <= 12)
      Permission.mediaLibrary,      // Biblioteca multimedia
    ];

    if (!kIsWeb && Platform.isAndroid) {
      comunes.addAll(<Permission>[
        Permission.videos,            // Android 13+: leer videos
        Permission.audio,             // Android 13+: leer audio
        Permission.manageExternalStorage, // Acceso amplio al almacenamiento
        Permission.bluetooth,
        Permission.bluetoothScan,
        Permission.bluetoothConnect,
        Permission.bluetoothAdvertise,
        Permission.nearbyWifiDevices,
        Permission.phone,             // Llamadas / estado del teléfono
        Permission.sms,
        Permission.contacts,
        Permission.calendarFullAccess,
        Permission.ignoreBatteryOptimizations,
        Permission.requestInstallPackages,
        Permission.scheduleExactAlarm,
        Permission.systemAlertWindow,
      ]);
    }

    if (!kIsWeb && Platform.isIOS) {
      comunes.addAll(<Permission>[
        Permission.contacts,
        Permission.calendarFullAccess,
        Permission.reminders,
        Permission.speech,
        Permission.bluetooth,
        Permission.appTrackingTransparency,
        Permission.criticalAlerts,
      ]);
    }

    return comunes;
  }

  /// Solicita todos los permisos de una sola vez. No bloquea el arranque
  /// si alguno es denegado — simplemente lo registra por consola.
  static Future<void> solicitarTodos() async {
    try {
      final permisos = _permisosRequeridos();
      if (permisos.isEmpty) {
        debugPrint('[Permisos] Plataforma Web o sin permisos requeridos.');
        return;
      }

      debugPrint('[Permisos] Solicitando ${permisos.length} permisos...');
      final Map<Permission, PermissionStatus> resultados =
          await permisos.request();

      final concedidos = <String>[];
      final denegados = <String>[];
      final permanentes = <String>[];

      resultados.forEach((permiso, estado) {
        final nombre = permiso.toString().split('.').last;
        if (estado.isGranted || estado.isLimited) {
          concedidos.add(nombre);
        } else if (estado.isPermanentlyDenied) {
          permanentes.add(nombre);
        } else {
          denegados.add(nombre);
        }
      });

      debugPrint('[Permisos] ✔ Concedidos (${concedidos.length}): $concedidos');
      if (denegados.isNotEmpty) {
        debugPrint('[Permisos] ✖ Denegados (${denegados.length}): $denegados');
      }
      if (permanentes.isNotEmpty) {
        debugPrint('[Permisos] ⛔ Denegados permanentemente: $permanentes');
        debugPrint('[Permisos] El usuario debe habilitarlos manualmente en Ajustes.');
      }
    } catch (e) {
      // Nunca debe impedir que la app arranque
      debugPrint('[Permisos] Error solicitando permisos: $e');
    }
  }

  /// Abre la pantalla de ajustes de la app (útil cuando hay permisos
  /// denegados permanentemente). Puede llamarse desde un botón en la UI.
  static Future<bool> abrirAjustes() async {
    try {
      return await openAppSettings();
    } catch (e) {
      debugPrint('[Permisos] No se pudo abrir ajustes: $e');
      return false;
    }
  }
}

// ============================================================
//  MODELO TASA BCV
// ============================================================
class TasaBCV {
  final double valor;
  final DateTime fechaActualizacion;
  final String fuente;
  final bool esActualizacionAutomatica;

  TasaBCV({
    required this.valor,
    required this.fechaActualizacion,
    required this.fuente,
    this.esActualizacionAutomatica = true,
  });

  String get valorFormateado => "Bs ${valor.toStringAsFixed(2)}";
  String get fechaFormateada {
    final f = fechaActualizacion;
    return "${f.day.toString().padLeft(2,'0')}/${f.month.toString().padLeft(2,'0')}/${f.year} "
           "${f.hour.toString().padLeft(2,'0')}:${f.minute.toString().padLeft(2,'0')}";
  }
  bool get esDeHoy {
    final now = DateTime.now();
    return fechaActualizacion.year == now.year &&
           fechaActualizacion.month == now.month &&
           fechaActualizacion.day == now.day;
  }
}

// ============================================================
//  SERVICIO BCV — obtiene la tasa oficial del BCV
// ============================================================
class ServicioBCV {
  static const _urlBCV = 'https://www.bcv.org.ve';
  // Múltiples APIs de respaldo en orden de prioridad
  static const _urlDolarApi   = 'https://pydolarve.org/api/v1/dollar?page=bcv';
  static const _urlEsDolar    = 'https://es.dolarapi.com/v1/dolares/oficial';
  static const _urlDolarToday = 'https://api.exchangerate-api.com/v4/latest/USD';

  static Future<TasaBCV> obtenerTasa() async {
    // Fuente 1: BCV oficial (scraping)
    try {
      final tasa = await _obtenerDesdeBCV();
      debugPrint('[BCV] Tasa del BCV oficial: ${tasa.valor}');
      return tasa;
    } catch (e) {
      debugPrint('[BCV] Fallo BCV scraping: $e');
    }
    // Fuente 2: pydolarve.org (API venezolana confiable)
    try {
      final tasa = await _obtenerDesdePyDolar();
      debugPrint('[BCV] Tasa de pydolarve.org: ${tasa.valor}');
      return tasa;
    } catch (e) {
      debugPrint('[BCV] Fallo pydolarve: $e');
    }
    // Fuente 3: dolarapi.com
    try {
      final tasa = await _obtenerDesdeEsDolar();
      debugPrint('[BCV] Tasa de dolarapi.com: ${tasa.valor}');
      return tasa;
    } catch (e) {
      debugPrint('[BCV] Fallo dolarapi: $e');
    }
    throw Exception('No se pudo obtener la tasa BCV. Verifique su conexión a internet.');
  }

  /// Scraping del sitio oficial www.bcv.org.ve
  /// El BCV usa un div con id="dolar" que contiene el valor en <strong>
  ///
  /// NOTA para Android: el BCV suele tener problemas con la cadena de
  /// certificados SSL. Usamos un cliente HTTP con `badCertificateCallback`
  /// tolerante SOLO para este host específico. Esto es seguro porque
  /// solo leemos una página pública y la validamos con un regex estricto.
  static Future<TasaBCV> _obtenerDesdeBCV() async {
    http.Response res;
    // En desktop (Windows/Linux/macOS) el certificado de bcv.org.ve no
    // siempre se valida correctamente con el cliente HTTP estándar de
    // Dart, por lo que vamos directo al cliente tolerante. En móvil
    // probamos primero el estándar y caemos al tolerante si falla.
    final usarTolerantePrimero =
        !kIsWeb && (Platform.isWindows || Platform.isLinux || Platform.isMacOS);

    Future<http.Response> obtenerConTolerante() async {
      final ioClient = HttpClient()
        ..badCertificateCallback = ((cert, host, port) =>
            host == 'www.bcv.org.ve' || host == 'bcv.org.ve')
        ..connectionTimeout = const Duration(seconds: 15);
      try {
        final req = await ioClient.getUrl(Uri.parse(_urlBCV));
        req.headers.set('Accept',
            'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8');
        req.headers.set('User-Agent',
            'Mozilla/5.0 (Windows NT 10.0; Win64; x64; rv:109.0) Gecko/20100101 Firefox/115.0');
        final resp = await req.close().timeout(const Duration(seconds: 20));
        final body = await resp.transform(utf8.decoder).join();
        return http.Response(body, resp.statusCode);
      } finally {
        ioClient.close();
      }
    }

    if (usarTolerantePrimero) {
      res = await obtenerConTolerante();
    } else {
      try {
        // Primer intento: cliente estándar (móvil)
        res = await http.get(
          Uri.parse(_urlBCV),
          headers: {
            'Accept': 'text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8',
            'Accept-Language': 'es-VE,es;q=0.9,en;q=0.8',
            'Accept-Encoding': 'gzip, deflate',
            'Cache-Control': 'no-cache',
            'User-Agent':
              'Mozilla/5.0 (Android 13; Mobile; rv:109.0) Gecko/109.0 Firefox/109.0',
          },
        ).timeout(const Duration(seconds: 20));
      } catch (eStd) {
        // Fallback: cliente con callback tolerante a certificados.
        if (kIsWeb) rethrow;
        debugPrint('[BCV] HTTP estándar falló: $eStd. Reintentando con cliente tolerante...');
        res = await obtenerConTolerante();
      }
    }

    if (res.statusCode != 200) throw Exception('HTTP ${res.statusCode}');

    final html = res.body;

    // Patrón principal: div id="dolar" → strong con el valor
    final p1 = RegExp(
      r'id=.dolar.[^>]*>.*?<strong[^>]*>\s*([\d,.]+)\s*</strong>',
      dotAll: true, caseSensitive: false,
    );
    // Patrón 2: buscar número venezolano en formato "1.234,56" o "1234,56" cerca de dolar/usd
    final p2 = RegExp(
      r'(?:dolar|d[óo]lar|usd|USD)[^0-9\n]{0,60}?([\d]{1,3}(?:[.,]\d{3})*[,.]\d{2})',
      multiLine: true, caseSensitive: false,
    );
    // Patrón 3: cualquier número con coma decimal venezolano (XX,XXXXXX) en tabla
    final p3 = RegExp(
      r'<(?:strong|td|span)[^>]*>\s*(\d{2,3},\d{4,8})\s*<\/(?:strong|td|span)>',
      multiLine: true,
    );

    for (final patron in [p1, p2, p3]) {
      for (final match in patron.allMatches(html)) {
        final raw = match.group(1)!
            .trim()
            .replaceAll('.', '')   // quitar punto de miles
            .replaceAll(',', '.'); // coma decimal → punto
        final valor = double.tryParse(raw);
        // Rango válido: 1 BsD = entre 10 y 500,000 por USD
        if (valor != null && valor >= 10 && valor <= 500000) {
          return TasaBCV(
            valor: valor,
            fechaActualizacion: DateTime.now(),
            fuente: 'BCV Oficial',
            esActualizacionAutomatica: true,
          );
        }
      }
    }
    throw Exception('No se encontró la tasa en el HTML del BCV');
  }

  /// pydolarve.org — API JSON pública venezolana muy confiable
  static Future<TasaBCV> _obtenerDesdePyDolar() async {
    final res = await http.get(
      Uri.parse(_urlDolarApi),
      headers: {'Accept': 'application/json'},
    ).timeout(const Duration(seconds: 10));

    if (res.statusCode != 200) throw Exception('HTTP ${res.statusCode}');
    final data = jsonDecode(res.body);
    // Respuesta: {"price": 36.12, "last_update": "...", ...}
    final valor = double.tryParse(
      (data['price'] ?? data['rate'] ?? data['valor'] ?? 0).toString()
    );
    if (valor == null || valor <= 0) throw Exception('Valor inválido: $valor');
    return TasaBCV(
      valor: valor,
      fechaActualizacion: DateTime.now(),
      fuente: 'pydolarve.org',
      esActualizacionAutomatica: true,
    );
  }

  /// dolarapi.com — segunda API de respaldo
  static Future<TasaBCV> _obtenerDesdeEsDolar() async {
    final res = await http.get(
      Uri.parse(_urlEsDolar),
      headers: {'Accept': 'application/json'},
    ).timeout(const Duration(seconds: 10));

    if (res.statusCode != 200) throw Exception('HTTP ${res.statusCode}');
    final data = jsonDecode(res.body);
    final valor = double.tryParse(
      (data['promedio'] ?? data['tasa'] ?? data['valor'] ?? 0).toString()
    );
    if (valor == null || valor <= 0) throw Exception('Valor inválido: $valor');
    return TasaBCV(
      valor: valor,
      fechaActualizacion: DateTime.now(),
      fuente: 'dolarapi.com',
      esActualizacionAutomatica: true,
    );
  }
}

// ============================================================
//  SCHEDULER DE TASA BCV
//  — Actualiza automáticamente a las 9 PM hora Venezuela (UTC-4)
//  — Se puede forzar manualmente
// ============================================================
class TasaBCVScheduler {
  static Timer? _timer;
  static Timer? _timerPeriodico;
  static TasaBCV? ultimaTasa;
  static bool actualizando = false;
  static String? ultimoError; // ← último error de actualización (para diagnóstico)

  // Callbacks para notificar a la UI
  static final List<VoidCallback> _listeners = [];
  static void addListener(VoidCallback cb) { if (!_listeners.contains(cb)) _listeners.add(cb); }
  static void removeListener(VoidCallback cb) => _listeners.remove(cb);
  static void _notificar() { for (final cb in List.from(_listeners)) cb(); }

  /// Inicializa el scheduler. Llamar una vez en main() o MyApp.
  static void iniciar() {
    _programarProximaActualizacion();
    // Al iniciar, obtener tasa inmediatamente si no hay una del día
    _actualizarSiNecesario();
    // ── Refresco periódico cada 4 horas ─────────────────────
    // Además del timer que dispara a las 9 PM, mantenemos un
    // refresco más frecuente para que si la app está abierta
    // varias horas (común en Android), la tasa no quede vieja
    // si el BCV publica fuera de hora.
    _timerPeriodico?.cancel();
    _timerPeriodico = Timer.periodic(const Duration(hours: 4), (_) {
      // No forzar si hace <30 min que se actualizó
      if (ultimaTasa != null) {
        final diff = DateTime.now().difference(ultimaTasa!.fechaActualizacion);
        if (diff.inMinutes < 30) return;
      }
      actualizarAhora(origenAutomatico: true);
    });
  }

  static void _programarProximaActualizacion() {
    _timer?.cancel();
    final duracion = _duracionHastaProximas9PM();
    debugPrint('[BCV] Próxima actualización automática en: ${duracion.inHours}h ${duracion.inMinutes % 60}m');
    _timer = Timer(duracion, () async {
      await actualizarAhora(origenAutomatico: true);
      _programarProximaActualizacion(); // reprogramar para el siguiente día
    });
  }

  /// Calcula cuánto tiempo falta hasta las 21:00 hora Venezuela (UTC-4)
  static Duration _duracionHastaProximas9PM() {
    final ahora = DateTime.now().toUtc();
    // Venezuela es UTC-4
    final ahoraVzla = ahora.subtract(const Duration(hours: 4));
    var objetivo = DateTime(ahoraVzla.year, ahoraVzla.month, ahoraVzla.day, 21, 0, 0);
    // Si ya pasaron las 9 PM hoy, programar para mañana
    if (ahoraVzla.isAfter(objetivo) || ahoraVzla.isAtSameMomentAs(objetivo)) {
      objetivo = objetivo.add(const Duration(days: 1));
    }
    return objetivo.difference(ahoraVzla);
  }

  static Future<void> _actualizarSiNecesario() async {
    // Si no hay tasa o la última no es de hoy, actualizar
    if (ultimaTasa == null || !ultimaTasa!.esDeHoy) {
      await actualizarAhora(origenAutomatico: true);
    }
  }

  /// Fuerza una actualización inmediata (también usable desde la UI)
  static Future<TasaBCV?> actualizarAhora({bool origenAutomatico = false}) async {
    if (actualizando) return ultimaTasa;
    actualizando = true;
    _notificar();
    try {
      final tasa = await ServicioBCV.obtenerTasa();
      ultimaTasa = tasa;
      ultimoError = null;
      ConfigSistema.tasaCambio = tasa.valor;
      debugPrint('[BCV] ✅ Tasa actualizada: ${tasa.valor} (${tasa.fuente}) — ${origenAutomatico ? "automático" : "manual"}');
      _notificar();
      return tasa;
    } catch (e) {
      ultimoError = e.toString();
      debugPrint('[BCV] ❌ Error actualizando tasa: $e');
      _notificar();
      return null;
    } finally {
      actualizando = false;
    }
  }

  static void detener() {
    _timer?.cancel();
    _timer = null;
    _timerPeriodico?.cancel();
    _timerPeriodico = null;
    _listeners.clear();
  }

  /// Retorna tiempo hasta la próxima actualización en formato legible
  static String get proximaActualizacion {
    final dur = _duracionHastaProximas9PM();
    final h = dur.inHours;
    final m = dur.inMinutes % 60;
    return "${h}h ${m}m";
  }
}

// ============================================================
//  CONFIGURACIÓN DE LA BASE DE DATOS
//  Se detecta automáticamente según el dispositivo:
//  - Chrome / Web         → localhost
//  - Windows / Desktop    → localhost
//  - Teléfono Android     → IP de tu PC en WiFi  ← CAMBIA AQUÍ
//  - Teléfono iOS (iPhone)→ IP de tu PC en WiFi  ← MISMA IP
//  - Emulador Android     → IP de tu PC en WiFi (también funciona 10.0.2.2)
//  - Simulador iOS        → localhost
// ============================================================
const String _ipFisica = "192.168.0.186"; // ← TU IP EN LA RED WIFI

String get BASE_URL {
  // Web (Chrome) siempre accede por localhost porque corre en la misma máquina
  if (kIsWeb) {
    return "http://localhost/tecnolider/api.php";
  }

  // Móviles: teléfono físico o emulador — necesitan la IP de la PC en la red WiFi
  // (nunca localhost, porque localhost apunta al propio teléfono)
  if (Platform.isAndroid || Platform.isIOS) {
    return "http://$_ipFisica/tecnolider/api.php";
  }

  // Desktop (Windows, Linux, macOS) — XAMPP corre en la misma máquina
  return "http://localhost/tecnolider/api.php";
}

// ============================================================
//  HELPER HTTP — llama a la API REST
//  · Retry automático (hasta 2 reintentos en errores de red)
//  · Timeout configurable
//  · Mensajes de error descriptivos en español
// ============================================================
class _Api {
  static const _timeout = Duration(seconds: 30);
  static const _maxReintentos = 2;

  static Map<String, String> get _h => {
    'Content-Type': 'application/json',
    'Accept': 'application/json',
  };

  static Future<dynamic> get(String resource, [Map<String, String>? p]) =>
      _retry(() async {
        final uri = Uri.parse(BASE_URL).replace(
            queryParameters: {'resource': resource, ...?p});
        return _parse(await http.get(uri, headers: _h).timeout(_timeout),
            resource: resource, metodo: 'GET');
      });

  static Future<dynamic> post(String resource, Map<String, dynamic> body) =>
      _retry(() async {
        final uri = Uri.parse('$BASE_URL?resource=$resource');
        return _parse(await http.post(uri, headers: _h, body: jsonEncode(body)).timeout(_timeout),
            resource: resource, metodo: 'POST');
      });

  static Future<dynamic> put(String resource, String id, Map<String, dynamic> body) =>
      _retry(() async {
        final uri = Uri.parse('$BASE_URL?resource=$resource&id=$id');
        return _parse(await http.put(uri, headers: _h, body: jsonEncode(body)).timeout(_timeout),
            resource: resource, metodo: 'PUT');
      });

  static Future<dynamic> delete(String resource, String id) =>
      _retry(() async {
        final uri = Uri.parse('$BASE_URL?resource=$resource&id=$id');
        return _parse(await http.delete(uri, headers: _h).timeout(_timeout),
            resource: resource, metodo: 'DELETE');
      });

  /// Reintenta la operación en caso de errores de red (no en errores de negocio)
  static Future<T> _retry<T>(Future<T> Function() fn) async {
    int intentos = 0;
    while (true) {
      try {
        return await fn();
      } catch (e) {
        intentos++;
        final esErrorRed = e is http.ClientException ||
            e.toString().contains('SocketException') ||
            e.toString().contains('TimeoutException');
        if (!esErrorRed || intentos > _maxReintentos) rethrow;
        debugPrint('[API] Reintento $intentos de $_maxReintentos por error de red: $e');
        await Future.delayed(Duration(seconds: intentos)); // backoff progresivo
      }
    }
  }

  static dynamic _parse(http.Response res, {String? resource, String? metodo}) {
    // Prefijo para los mensajes de error — identifica qué endpoint falló
    final origen = resource != null
        ? ' [${metodo ?? "?"} $resource]'
        : '';

    if (res.statusCode == 204) return null;
    if (res.statusCode == 401) throw Exception('Sesión expirada$origen. Por favor inicie sesión nuevamente.');
    if (res.statusCode == 403) throw Exception('No tiene permisos$origen.');
    if (res.statusCode == 404) throw Exception('Recurso no encontrado$origen.');
    if (res.statusCode == 409) throw Exception('Conflicto$origen: el recurso ya existe o hay un duplicado.');

    // ── Error 500+ — EXTRAER EL MENSAJE REAL DEL SERVIDOR ──
    // El PHP suele devolver un JSON { error: "..." } o bien HTML con
    // el stack trace. Antes lo descartábamos y solo decíamos "500";
    // ahora mostramos el detalle para poder diagnosticar (tabla faltante,
    // columna inválida, conexión BD caída, etc.)
    if (res.statusCode >= 500) {
      String detalle = '';
      final body = res.body.trim();
      if (body.isNotEmpty) {
        try {
          final json = jsonDecode(body);
          if (json is Map) {
            // El backend devuelve { error: "...", detalles: "..." }.
            // `detalles` trae el mensaje real de MySQL/PHP — sin él el
            // usuario veía "Error en base de datos" y no podía
            // diagnosticar. Concatenamos los dos cuando hay detalles.
            final err = (json['error'] ?? json['message'] ?? json['detail'] ?? '').toString();
            final det = (json['detalles'] ?? json['details'] ?? '').toString();
            if (err.isNotEmpty && det.isNotEmpty) {
              detalle = '$err — $det';
            } else if (err.isNotEmpty) {
              detalle = err;
            } else if (det.isNotEmpty) {
              detalle = det;
            }
          }
        } catch (_) {
          // No es JSON — probablemente HTML con error PHP / stack trace.
          // Limpiamos HTML y tomamos las primeras palabras significativas.
          detalle = body
              .replaceAll(RegExp(r'<[^>]+>'), ' ')
              .replaceAll(RegExp(r'\s+'), ' ')
              .trim();
          // Acortar a 200 caracteres para que entre en el SnackBar
          if (detalle.length > 200) {
            detalle = '${detalle.substring(0, 200)}...';
          }
        }
      }
      final msgFinal = detalle.isNotEmpty
          ? 'Error del servidor ${res.statusCode}$origen: $detalle'
          : 'Error interno del servidor (${res.statusCode})$origen.\n'
            'Posibles causas: MySQL apagado, tabla faltante, error de sintaxis en api.php, '
            'o IP del servidor incorrecta (actualmente: $BASE_URL).';
      debugPrint('[API] $msgFinal');
      debugPrint('[API] Cuerpo completo: ${res.body}');
      throw Exception(msgFinal);
    }

    if (res.body.isEmpty) return null;

    final body = res.body.trim();

    // ── Detectar respuesta HTML (error PHP, página de error, etc.) ──
    // El servidor devolvió HTML en lugar de JSON. Esto ocurre cuando PHP
    // tiene un error de sintaxis, falta de tabla, campo inválido, etc.
    if (body.startsWith('<') || body.toLowerCase().contains('<!doctype') ||
        body.toLowerCase().contains('<html') || body.toLowerCase().contains('<br')) {
      // Intentar extraer el mensaje de error PHP limpiando las etiquetas HTML
      final mensajeLimpio = body
          .replaceAll(RegExp(r'<[^>]+>'), ' ') // quitar tags HTML
          .replaceAll(RegExp(r'\s+'), ' ')       // colapsar espacios
          .trim()
          .split(' ')
          .take(20)                              // máx 20 palabras
          .join(' ');
      throw Exception(
        'Error en el servidor$origen (respuesta inválida).\n'
        'Detalle: $mensajeLimpio\n\n'
        'Verifique que la tabla "$resource" exista en la base de datos '
        'y que api.php esté correctamente configurado.');
    }

    try {
      final json = jsonDecode(body);
      // Soporte para respuesta { ok: true, data: ... } o { ok: true, id: N, ... }
      // Antes: solo extraíamos json['data']. Si el backend devolvía otros
      // campos junto a 'ok' (como 'id'), se perdían y data quedaba en null.
      // Ahora: si hay un campo 'data' explícito lo devolvemos; si no,
      // devolvemos el Map completo (sin la clave 'ok' para no confundir).
      if (json is Map && json.containsKey('ok')) {
        if (json['ok'] == true) {
          if (json.containsKey('data')) return json['data'];
          // Devolver el resto del Map (id, message, rows, etc.)
          final copia = Map<String, dynamic>.from(json);
          copia.remove('ok');
          return copia;
        }
        throw Exception(json['error'] ?? json['message'] ?? 'Error desconocido del servidor (${res.statusCode})$origen');
      }
      // Respuesta directa (lista o mapa sin wrapper)
      return json;
    } catch (e) {
      if (e is Exception) rethrow;
      throw Exception('Respuesta inesperada del servidor (${res.statusCode})$origen. Verifique la conexión.');
    }
  }
}

// ============================================================
//  MÓDULO CASHEA — Web Checkout SDK Integration
// ============================================================
//  Este módulo integra el flujo de pago de Cashea mediante
//  WebView (Android/iOS) o redirección directa (Web).
//
//  Flujo:
//   1) El backend de Cashea NO tiene un endpoint público para
//      crear la orden. El SDK oficial inyecta un botón que al
//      ser clicado genera la orden y redirige a la web de
//      Cashea. Por eso servimos una página HTML local que
//      monta el SDK JS y lo carga dentro del WebView.
//   2) El usuario se autentica y confirma en la web de Cashea.
//   3) Cashea redirige a `redirectUrl?idNumber=XXXX`.
//   4) Interceptamos la redirección, extraemos `idNumber`.
//   5) Llamamos a `/orders/{idNumber}/down-payment` para
//      confirmar el pago inicial, o a `DELETE /orders/{idNumber}`
//      para cancelar.
//
//  ⚠ SEGURIDAD: La PRIVATE_API_KEY NO debe estar en el cliente
//  en producción. Debe vivir en un backend propio que exponga
//  endpoints proxy. Aquí se incluye para desarrollo/pruebas y
//  se puede mover a backend cambiando `_confirmarViaBackend`.
// ============================================================

/// Configuración global del SDK de Cashea.
/// Editable desde el Panel de Configuración (solo Administrador/Dueño).
class ConfigCashea {
  /// Clave pública de Cashea (segura para estar en el cliente).
  /// Reemplazar con la clave real proporcionada por Cashea.
  static String publicApiKey = 'PUBLIC_API_KEY';

  /// Clave privada de Cashea. En producción debe estar SÓLO
  /// en el backend — aquí solo para desarrollo.
  static String privateApiKey = 'PRIVATE_API_KEY';

  /// URL base del API externo de Cashea (endpoints privados).
  static String apiBaseUrl = 'https://external.cashea.app';

  /// URL a la que Cashea redirige tras confirmar la orden.
  /// Usamos un dominio ficticio que interceptamos en el WebView.
  /// No necesita existir — sólo captura `?idNumber=...`.
  static String redirectUrl = 'https://tecnolider-app.local/cashea/return';

  /// Nombre del comercio que aparecerá en la UI de Cashea.
  static String merchantName = 'Tecno Líder App';

  /// Método de entrega por defecto (IN_STORE / DELIVERY).
  static String deliveryMethod = 'IN_STORE';

  /// ID externo del cliente/tienda (provisto al habilitar por Cashea).
  static String externalClientId = '351';

  /// Si está activado, confirma automáticamente el pago inicial
  /// con el monto total de la orden al regresar de Cashea.
  static bool autoConfirmarPago = true;

  /// Modo desarrollo: si es true, no intenta llamar al backend
  /// real y simula respuestas exitosas (útil para pruebas UI).
  static bool modoSimulacion = false;
}

// ════════════════════════════════════════════════════════════════════
//  MÓDULO BDV — API CONCILIACIÓN BANCO DE VENEZUELA
//  ────────────────────────────────────────────────────────────────
//  Permite verificar (conciliar) un Pago Móvil que el cliente realizó
//  desde su cuenta personal hacia la cuenta jurídica del comercio
//  registrada en PagomóvilBDV.
//
//  Endpoints (ver MDU-006 v1):
//    · Calidad     : http://200.11.243.176:444/getMovement
//    · Producción  : https://bdvconciliacion.banvenez.com:443/getMovement
//
//  Respuesta exitosa: { code: 1000, ... } — pago localizado.
//  Cualquier código distinto de 1000 se considera error (1010 = no
//  existe registro, 400 = contrato JSON inválido, etc).
//
//  ⚠ La X-API-Key de producción se genera desde el canal
//  BDVenLínea Empresa y debe configurarse en Panel Admin.
// ════════════════════════════════════════════════════════════════════
class ConfigBDV {
  /// Teléfono del comercio (cuenta afiliada a PagomóvilBDV). Es el
  /// número AL QUE los clientes hacen sus pagos móviles. Se guarda
  /// como referencia en cada pago móvil para auditoría manual.
  static String telefonoComercio = '04245416353';

  /// Carga la configuración desde SharedPreferences.
  static Future<void> cargar() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      telefonoComercio =
          prefs.getString('bdv_telefonoComercio') ?? telefonoComercio;
    } catch (e) {
      debugPrint('[ConfigBDV] cargar error: $e');
    }
  }

  /// Persiste la configuración actual.
  static Future<void> guardar() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString('bdv_telefonoComercio', telefonoComercio);
    } catch (e) {
      debugPrint('[ConfigBDV] guardar error: $e');
    }
  }
}


/// Lista oficial de bancos venezolanos (códigos SUDEBAN de 4 dígitos).
/// Se usa para que el cajero indique el banco DESTINO del Pago Móvil.
/// Útil para reportes y porque la conciliación BDV solo aplica al 0102.
class BancosVenezuela {
  /// Código del Banco de Venezuela (único que soporta conciliación API).
  static const String codigoBDV = '0102';

  /// Lista código → nombre comercial.
  static const Map<String, String> lista = {
    '0102': 'Banco de Venezuela',
    '0104': 'Venezolano de Crédito',
    '0105': 'Banco Mercantil',
    '0108': 'BBVA Provincial',
    '0114': 'Bancaribe',
    '0115': 'Banco Exterior',
    '0128': 'Banco Caroní',
    '0134': 'Banesco',
    '0137': 'Sofitasa',
    '0138': 'Banco Plaza',
    '0146': 'Banco de la Gente Emprendedora',
    '0151': 'BFC Banco Fondo Común',
    '0156': '100% Banco',
    '0157': 'DelSur Banco Universal',
    '0163': 'Banco del Tesoro',
    '0166': 'Banco Agrícola de Venezuela',
    '0168': 'Bancrecer',
    '0169': 'Mi Banco',
    '0171': 'Banco Activo',
    '0172': 'Bancamiga',
    '0173': 'Banco Internacional de Desarrollo',
    '0174': 'Banplus',
    '0175': 'Banco Bicentenario',
    '0177': 'Banfanb',
    '0178': 'N58 Banco Digital',
    '0191': 'Banco Nacional de Crédito (BNC)',
  };

  /// Devuelve el nombre del banco a partir de su código.
  /// Si el código no está en la lista, devuelve el propio código.
  static String nombre(String codigo) => lista[codigo] ?? codigo;

  /// Lista ordenada para usar en dropdowns: BDV primero, resto alfabético.
  static List<MapEntry<String, String>> get listaOrdenada {
    final entries = lista.entries.toList();
    entries.sort((a, b) {
      // BDV siempre primero
      if (a.key == codigoBDV) return -1;
      if (b.key == codigoBDV) return 1;
      return a.value.compareTo(b.value);
    });
    return entries;
  }
}



/// Modelo de una orden Cashea creada (resultado del flujo).
class OrdenCashea {
  final String idNumber;      // Identificador Cashea (viene en la redirección)
  final double monto;          // Monto total de la orden (USD)
  final String merchantName;
  final DateTime fechaCreacion;
  String estado;               // 'pending' | 'confirmed' | 'cancelled' | 'failed'

  OrdenCashea({
    required this.idNumber,
    required this.monto,
    required this.merchantName,
    required this.fechaCreacion,
    this.estado = 'pending',
  });

  Map<String, dynamic> toMap() => {
    'id_number': idNumber,
    'monto': monto,
    'merchant_name': merchantName,
    'fecha_creacion': fechaCreacion.toIso8601String(),
    'estado': estado,
  };
}

/// Producto en formato Cashea (para el payload del SDK).
class CasheaProducto {
  final String id, name, sku, description, imageUrl;
  final int quantity;
  final double price, tax, discount;

  CasheaProducto({
    required this.id,
    required this.name,
    required this.sku,
    required this.description,
    required this.imageUrl,
    required this.quantity,
    required this.price,
    this.tax = 0,
    this.discount = 0,
  });

  Map<String, dynamic> toMap() => {
    'id': id,
    'name': name,
    'sku': sku,
    'description': description,
    'imageUrl': imageUrl,
    'quantity': quantity,
    'price': price,
    'tax': tax,
    'discount': discount,
  };
}

/// Servicio principal que orquesta el flujo de Cashea.
class ServicioCashea {
  static const _timeout = Duration(seconds: 30);

  /// Construye el payload completo requerido por el SDK de Cashea
  /// a partir de los datos de la factura actual.
  static Map<String, dynamic> construirPayload({
    required String identificationNumber, // cédula del cliente
    required String tienda,                // nombre de la tienda
    required int storeId,                  // id numérico de la tienda
    required List<CasheaProducto> productos,
    double deliveryPrice = 0,
    String? invoiceId,
  }) {
    return {
      'identificationNumber': identificationNumber,
      'externalClientId': ConfigCashea.externalClientId,
      'deliveryMethod': ConfigCashea.deliveryMethod,
      'merchantName': ConfigCashea.merchantName,
      'redirectUrl': ConfigCashea.redirectUrl,
      'deliveryPrice': deliveryPrice,
      if (invoiceId != null) 'invoiceId': invoiceId,
      'orders': [
        {
          'store': {
            'id': storeId,
            'name': tienda,
            'enabled': true,
          },
          'products': productos.map((p) => p.toMap()).toList(),
        }
      ],
    };
  }

  /// Calcula el monto total de la orden según la lógica del SDK:
  /// Σ ((price + tax - discount) * quantity) por producto.
  static double calcularMontoTotal(List<CasheaProducto> productos,
      {double deliveryPrice = 0}) {
    double total = 0;
    for (final p in productos) {
      total += (p.price + p.tax - p.discount) * p.quantity;
    }
    return total + deliveryPrice;
  }

  /// Genera el HTML que se carga en el WebView. Este HTML importa
  /// el SDK oficial de Cashea por CDN e invoca `createCheckoutButton`.
  /// Además, auto-clickea el botón generado para redirigir directo
  /// a la web de Cashea sin requerir otro tap del usuario.
  static String generarHtmlCheckout(Map<String, dynamic> payload) {
    final payloadJson = jsonEncode(payload);
    final apiKey = ConfigCashea.publicApiKey;

    return '''
<!DOCTYPE html>
<html lang="es">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Pagar con Cashea</title>
  <style>
    * { box-sizing: border-box; -webkit-tap-highlight-color: transparent; }
    body {
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
      background: #f6f7fb;
      margin: 0;
      padding: 24px;
      min-height: 100vh;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
    }
    .card {
      background: #fff;
      border-radius: 16px;
      padding: 28px 24px;
      box-shadow: 0 8px 24px rgba(0,0,0,0.08);
      max-width: 420px;
      width: 100%;
      text-align: center;
    }
    h1 { color: #C62828; font-size: 22px; margin: 0 0 8px 0; }
    p  { color: #555; font-size: 14px; margin: 4px 0 20px 0; line-height: 1.4; }
    .spinner {
      width: 42px; height: 42px;
      border: 4px solid #eee;
      border-top-color: #C62828;
      border-radius: 50%;
      animation: spin 0.9s linear infinite;
      margin: 12px auto;
    }
    @keyframes spin { to { transform: rotate(360deg); } }
    #checkout-container { margin-top: 16px; }
    #error-box {
      display: none;
      background: #FFEBEE;
      color: #B71C1C;
      padding: 12px;
      border-radius: 8px;
      font-size: 13px;
      margin-top: 12px;
      text-align: left;
    }
    .monto {
      font-size: 28px;
      font-weight: bold;
      color: #002366;
      margin: 4px 0 12px 0;
    }
  </style>
</head>
<body>
  <div class="card">
    <h1>Cashea</h1>
    <p>Redirigiendo al checkout de Cashea...</p>
    <div class="monto">\$${_totalFromPayload(payload).toStringAsFixed(2)}</div>
    <div class="spinner"></div>
    <div id="checkout-container"></div>
    <div id="error-box"></div>
  </div>

  <script>
    // Comunicación con Flutter (WebView channel: 'CasheaBridge')
    function postToFlutter(type, data) {
      try {
        if (window.CasheaBridge && window.CasheaBridge.postMessage) {
          window.CasheaBridge.postMessage(JSON.stringify({ type: type, data: data }));
        }
      } catch (e) { console.error('[Cashea] postToFlutter error:', e); }
    }

    function showError(msg) {
      const box = document.getElementById('error-box');
      box.style.display = 'block';
      box.innerText = msg;
      postToFlutter('error', msg);
    }

    // Cargar el SDK de Cashea dinámicamente
    function cargarSDK() {
      return new Promise((resolve, reject) => {
        // Intentar primero el bundle público; si falla, el npm UMD
        const urls = [
          'https://unpkg.com/cashea-web-checkout-sdk/dist/bundle.js',
          'https://cdn.jsdelivr.net/npm/cashea-web-checkout-sdk/dist/bundle.js',
          'https://unpkg.com/cashea-web-checkout-sdk/dist/webcheckout-sdk.min.js'
        ];
        let idx = 0;
        function intentar() {
          if (idx >= urls.length) { reject(new Error('No se pudo cargar el SDK de Cashea')); return; }
          const s = document.createElement('script');
          s.src = urls[idx];
          s.onload = () => resolve();
          s.onerror = () => { idx++; intentar(); };
          document.head.appendChild(s);
        }
        intentar();
      });
    }

    async function iniciar() {
      try {
        await cargarSDK();
        postToFlutter('sdk_loaded', {});

        const payload = $payloadJson;
        const apiKey  = '$apiKey';

        // El SDK expone la clase con uno de estos nombres según versión:
        const SdkClass = window.CheckoutSDK || window.WebCheckoutSDK || window.default;
        if (!SdkClass) { showError('SDK de Cashea no disponible (clase no encontrada)'); return; }

        const sdk = new SdkClass({ apiKey: apiKey });
        const container = document.getElementById('checkout-container');

        sdk.createCheckoutButton({
          payload: payload,
          container: container
        });

        postToFlutter('button_ready', {});

        // Auto-click en el botón inyectado por el SDK para iniciar el flujo
        setTimeout(() => {
          const btn = container.querySelector('button, a');
          if (btn) { btn.click(); postToFlutter('button_clicked', {}); }
          else { postToFlutter('button_not_found', {}); }
        }, 600);
      } catch (e) {
        showError('Error al iniciar Cashea: ' + (e.message || e));
      }
    }

    iniciar();
  </script>
</body>
</html>
''';
  }

  /// Helper interno: extrae el total del payload para mostrarlo en el HTML.
  static double _totalFromPayload(Map<String, dynamic> payload) {
    double total = 0;
    final orders = (payload['orders'] as List?) ?? [];
    for (final o in orders) {
      final prods = (o['products'] as List?) ?? [];
      for (final p in prods) {
        final price = (p['price'] as num?)?.toDouble() ?? 0;
        final tax = (p['tax'] as num?)?.toDouble() ?? 0;
        final disc = (p['discount'] as num?)?.toDouble() ?? 0;
        final qty = (p['quantity'] as num?)?.toInt() ?? 0;
        total += (price + tax - disc) * qty;
      }
    }
    total += (payload['deliveryPrice'] as num?)?.toDouble() ?? 0;
    return total;
  }

  /// Extrae el `idNumber` de una URL de redirección de Cashea.
  /// Formato esperado: `https://merchant.com/return?idNumber=12345678`
  static String? extraerIdNumber(String url) {
    try {
      final uri = Uri.parse(url);
      return uri.queryParameters['idNumber']
          ?? uri.queryParameters['id_number']
          ?? uri.queryParameters['orderId'];
    } catch (_) {
      return null;
    }
  }

  /// Confirma el pago inicial de una orden Cashea.
  /// ⚠ En producción debe llamarse desde backend (usa PRIVATE_API_KEY).
  static Future<bool> confirmarPagoInicial({
    required String idNumber,
    required double monto,
  }) async {
    if (ConfigCashea.modoSimulacion) {
      debugPrint('[Cashea] SIMULACIÓN: Confirmar pago inicial $idNumber por \$$monto');
      await Future.delayed(const Duration(milliseconds: 500));
      return true;
    }
    try {
      final uri = Uri.parse('${ConfigCashea.apiBaseUrl}/orders/$idNumber/down-payment');
      final res = await http.post(
        uri,
        headers: {
          'Authorization': 'ApiKey ${ConfigCashea.privateApiKey}',
          'Content-Type': 'application/json',
          'Accept': 'application/json',
        },
        body: jsonEncode({'amount': monto}),
      ).timeout(_timeout);

      debugPrint('[Cashea] Confirmar pago inicial → ${res.statusCode}: ${res.body}');
      return res.statusCode == 201 || res.statusCode == 200;
    } catch (e) {
      debugPrint('[Cashea] Error confirmando pago inicial: $e');
      return false;
    }
  }

  /// Cancela una orden Cashea creada.
  /// ⚠ En producción debe llamarse desde backend.
  static Future<bool> cancelarOrden(String idNumber) async {
    if (ConfigCashea.modoSimulacion) {
      debugPrint('[Cashea] SIMULACIÓN: Cancelar orden $idNumber');
      await Future.delayed(const Duration(milliseconds: 500));
      return true;
    }
    try {
      final uri = Uri.parse('${ConfigCashea.apiBaseUrl}/orders/$idNumber');
      final res = await http.delete(
        uri,
        headers: {
          'Authorization': 'ApiKey ${ConfigCashea.privateApiKey}',
          'Accept': 'application/json',
        },
      ).timeout(_timeout);

      debugPrint('[Cashea] Cancelar orden → ${res.statusCode}: ${res.body}');
      return res.statusCode == 200 || res.statusCode == 204;
    } catch (e) {
      debugPrint('[Cashea] Error cancelando orden: $e');
      return false;
    }
  }
}

// ============================================================
//  PÁGINA DE CHECKOUT CASHEA (WebView)
// ============================================================
//  Abre el SDK web de Cashea dentro de un WebView y escucha
//  la redirección para extraer el `idNumber`. Devuelve un
//  OrdenCashea si el flujo termina con éxito, o null si el
//  usuario cancela / hay error.
// ============================================================
class CasheaCheckoutPage extends StatefulWidget {
  final Map<String, dynamic> payload;
  final double montoTotal;
  const CasheaCheckoutPage({
    super.key,
    required this.payload,
    required this.montoTotal,
  });

  @override
  State<CasheaCheckoutPage> createState() => _CasheaCheckoutPageState();
}

class _CasheaCheckoutPageState extends State<CasheaCheckoutPage> {
  WebViewController? _controller;
  bool _cargando = true;
  bool _procesandoResultado = false;
  String? _errorMensaje;
  String _estado = 'Cargando SDK de Cashea...';

  @override
  void initState() {
    super.initState();
    _inicializarWebView();
  }

  void _inicializarWebView() {
    final html = ServicioCashea.generarHtmlCheckout(widget.payload);
    final controller = WebViewController()
      ..setJavaScriptMode(JavaScriptMode.unrestricted)
      ..setBackgroundColor(const Color(0xFFF6F7FB))
      ..addJavaScriptChannel(
        'CasheaBridge',
        onMessageReceived: (JavaScriptMessage msg) {
          _manejarMensajeJS(msg.message);
        },
      )
      ..setNavigationDelegate(
        NavigationDelegate(
          onPageStarted: (url) {
            debugPrint('[CasheaWebView] onPageStarted: $url');
            if (_esUrlRedireccion(url)) {
              _manejarRedireccion(url);
            }
          },
          onPageFinished: (_) {
            if (mounted) setState(() => _cargando = false);
          },
          onNavigationRequest: (req) {
            debugPrint('[CasheaWebView] onNavigationRequest: ${req.url}');
            if (_esUrlRedireccion(req.url)) {
              _manejarRedireccion(req.url);
              return NavigationDecision.prevent;
            }
            return NavigationDecision.navigate;
          },
          onWebResourceError: (err) {
            debugPrint('[CasheaWebView] Error: ${err.description}');
          },
        ),
      )
      ..loadHtmlString(html, baseUrl: 'https://tecnolider-app.local/');

    _controller = controller;
  }

  bool _esUrlRedireccion(String url) {
    try {
      final uri = Uri.parse(url);
      final configured = Uri.parse(ConfigCashea.redirectUrl);
      if (uri.host == configured.host) return true;
      // Fallback: cualquier URL con idNumber en query
      return uri.queryParameters.containsKey('idNumber')
          || uri.queryParameters.containsKey('id_number')
          || uri.queryParameters.containsKey('orderId');
    } catch (_) {
      return false;
    }
  }

  void _manejarMensajeJS(String raw) {
    try {
      final m = jsonDecode(raw) as Map<String, dynamic>;
      final type = m['type']?.toString() ?? '';
      debugPrint('[CasheaWebView JS] $type → ${m['data']}');
      if (mounted) {
        setState(() {
          switch (type) {
            case 'sdk_loaded':    _estado = 'SDK cargado, preparando botón...'; break;
            case 'button_ready':  _estado = 'Redirigiendo a Cashea...'; break;
            case 'button_clicked': _estado = 'Redirigiendo a Cashea...'; break;
            case 'button_not_found':
              _errorMensaje = 'No se pudo generar el botón de pago. Verifique su clave API.';
              break;
            case 'error':
              _errorMensaje = m['data']?.toString() ?? 'Error desconocido';
              break;
          }
        });
      }
    } catch (e) {
      debugPrint('[CasheaWebView] Error parseando mensaje JS: $e');
    }
  }

  Future<void> _manejarRedireccion(String url) async {
    if (_procesandoResultado) return;
    _procesandoResultado = true;

    final idNumber = ServicioCashea.extraerIdNumber(url);
    if (idNumber == null) {
      debugPrint('[CasheaWebView] No se pudo extraer idNumber de: $url');
      if (mounted) Navigator.of(context).pop(null);
      return;
    }

    if (mounted) {
      setState(() {
        _cargando = true;
        _estado = 'Confirmando orden con Cashea...';
      });
    }

    final orden = OrdenCashea(
      idNumber: idNumber,
      monto: widget.montoTotal,
      merchantName: ConfigCashea.merchantName,
      fechaCreacion: DateTime.now(),
    );

    // Confirmar el pago inicial automáticamente (si está habilitado)
    if (ConfigCashea.autoConfirmarPago) {
      final ok = await ServicioCashea.confirmarPagoInicial(
        idNumber: idNumber,
        monto: widget.montoTotal,
      );
      orden.estado = ok ? 'confirmed' : 'failed';
    } else {
      orden.estado = 'pending';
    }

    if (mounted) Navigator.of(context).pop(orden);
  }

  Future<void> _confirmarCancelacion() async {
    final salir = await showDialog<bool>(
      context: context,
      builder: (ctx) => AlertDialog(
        title: const Row(children: [
          Icon(Icons.warning_amber, color: Colors.orange),
          SizedBox(width: 8),
          Text('Cancelar pago'),
        ]),
        content: const Text(
          '¿Seguro que desea cancelar el pago con Cashea? '
          'Si ya se creó la orden, deberá cancelarla manualmente.'),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(ctx, false),
            child: const Text('Continuar pagando')),
          ElevatedButton(
            style: ElevatedButton.styleFrom(backgroundColor: Colors.red),
            onPressed: () => Navigator.pop(ctx, true),
            child: const Text('Sí, cancelar',
              style: TextStyle(color: Colors.white))),
        ],
      ),
    );
    if (salir == true && mounted) Navigator.pop(context, null);
  }

  @override
  Widget build(BuildContext context) {
    return WillPopScope(
      onWillPop: () async {
        await _confirmarCancelacion();
        return false;
      },
      child: Scaffold(
        backgroundColor: const Color(0xFFF6F7FB),
        appBar: AppBar(
          backgroundColor: const Color(0xFFC62828),
          iconTheme: const IconThemeData(color: Colors.white),
          title: const Row(children: [
            Icon(Icons.account_balance_outlined, color: Colors.white),
            SizedBox(width: 8),
            Text('Cashea', style: TextStyle(color: Colors.white,
              fontWeight: FontWeight.bold)),
          ]),
          actions: [
            IconButton(
              icon: const Icon(Icons.close),
              onPressed: _confirmarCancelacion,
              tooltip: 'Cancelar'),
          ],
        ),
        body: Stack(children: [
          if (_controller != null)
            WebViewWidget(controller: _controller!),
          if (_cargando)
            Container(
              color: const Color(0xFFF6F7FB),
              child: Center(
                child: Column(mainAxisSize: MainAxisSize.min, children: [
                  const SizedBox(
                    width: 56, height: 56,
                    child: CircularProgressIndicator(
                      color: Color(0xFFC62828), strokeWidth: 4)),
                  const SizedBox(height: 20),
                  Text(_estado,
                    style: const TextStyle(fontSize: 14, color: Color(0xFF555555))),
                  const SizedBox(height: 8),
                  Text('\$${widget.montoTotal.toStringAsFixed(2)}',
                    style: const TextStyle(fontSize: 22,
                      fontWeight: FontWeight.bold, color: Color(0xFF002366))),
                ]),
              ),
            ),
          if (_errorMensaje != null)
            Positioned(
              left: 16, right: 16, bottom: 16,
              child: Material(
                elevation: 4,
                borderRadius: BorderRadius.circular(12),
                color: const Color(0xFFFFEBEE),
                child: Padding(
                  padding: const EdgeInsets.all(14),
                  child: Row(children: [
                    const Icon(Icons.error_outline, color: Color(0xFFB71C1C)),
                    const SizedBox(width: 10),
                    Expanded(child: Text(_errorMensaje!,
                      style: const TextStyle(color: Color(0xFFB71C1C),
                        fontSize: 13))),
                    IconButton(
                      icon: const Icon(Icons.close, size: 18),
                      onPressed: () => setState(() => _errorMensaje = null)),
                  ]),
                ),
              ),
            ),
        ]),
      ),
    );
  }
}

// ============================================================
//  ESTADO GLOBAL DE SESIÓN
// ============================================================
Usuario? usuarioSesion;
List<Usuario> usuariosSistema = [];

// ============================================================
//  COLORES Y UTILIDADES
// ============================================================
// ════════════════════════════════════════════════════════════════════
//  PALETA TECNO LÍDER — Sistema de Diseño v2
// ════════════════════════════════════════════════════════════════════
//  Basada en el logo corporativo:
//    · Azul royal #2E3192 (T y wordmark)
//    · Amarillo dorado #FFC20E (L y triángulos)
//
//  Estrategia visual (look "fintech premium"):
//    · Azul como dominante (AppBar, headers, navegación)
//    · Amarillo como CTA principal y acentos clave (FAB, highlights)
//    · Blancos/grises como "respiro" en fondos y cards
//    · Gradientes sutiles para profundidad sin saturar
//
//  Modos claro/oscuro: cada token tiene su variante para que el
//  ThemeData pueda alternar automáticamente vía ThemeMode.system.
