}

// ════════════════════════════════════════════════════════════════════
//  LOGO TECNO LÍDER — versión vectorial (CustomPainter)
// ════════════════════════════════════════════════════════════════════
//  Reproduce el logo "TL" con los triángulos de play como un widget
//  escalable. Ventajas vs el JPEG:
//    · Nítido en cualquier tamaño (4K, retina, pantallas pequeñas)
//    · Permite tematizar los colores en modo oscuro/contextos especiales
//    · Sin asset extra (todo está en el código)
//    · Animable (rotación, fade, etc.) sin perder calidad
//
//  Uso:
//    TecnoLiderLogo(size: 120)                  // Logo cuadrado
//    TecnoLiderLogo.full(width: 280)            // Con wordmark debajo
//    TecnoLiderLogo(size: 80, monochrome: true) // Versión monocroma
// ════════════════════════════════════════════════════════════════════
class TecnoLiderLogo extends StatelessWidget {
  /// Lado del cuadrado del logo TL (sin contar el wordmark).
  final double size;
  /// Si es true, muestra solo el TL. Si es false, muestra TL + wordmark.
  final bool soloIcono;
  /// Modo monocromo (todo en un solo color, útil para AppBars).
  final bool monochrome;
  /// Color para modo monocromo. Por defecto blanco.
  final Color monochromeColor;

  const TecnoLiderLogo({
    super.key,
    this.size = 120,
    this.soloIcono = true,
    this.monochrome = false,
    this.monochromeColor = Colors.white,
  });

  /// Constructor de conveniencia: logo + wordmark "TECNO LÍDER" debajo.
  /// El parámetro `width` controla el ancho total del bloque.
  const TecnoLiderLogo.full({
    super.key,
    double width = 280,
    this.monochrome = false,
    this.monochromeColor = Colors.white,
  })  : size = width * 0.55,
        soloIcono = false;

  @override
  Widget build(BuildContext context) {
    return Column(
      mainAxisSize: MainAxisSize.min,
      children: [
        // Icono TL (cuadrado)
        SizedBox(
          width: size, height: size,
          child: CustomPaint(
            painter: _TecnoLiderLogoPainter(
              monochrome: monochrome,
              monochromeColor: monochromeColor,
            ),
          ),
        ),
        if (!soloIcono) ...[
          SizedBox(height: size * 0.10),
          // Wordmark TECNO LÍDER
          Text('TECNO LÍDER',
            style: TextStyle(
              fontSize: size * 0.20,
              fontWeight: FontWeight.w900,
              letterSpacing: size * 0.025,
              color: monochrome ? monochromeColor : AppColors.brandBlue,
              height: 1.0,
            ),
          ),
        ],
      ],
    );
  }
}

class _TecnoLiderLogoPainter extends CustomPainter {
  final bool monochrome;
  final Color monochromeColor;

  _TecnoLiderLogoPainter({required this.monochrome, required this.monochromeColor});

  @override
  void paint(Canvas canvas, Size size) {
    final azul = monochrome ? monochromeColor : AppColors.brandBlue;
    final amarillo = monochrome ? monochromeColor : AppColors.brandYellow;

    final w = size.width;
    final h = size.height;

    // Las proporciones están normalizadas al cuadrado [0,1] y
    // multiplicadas por w/h para escalar.
    final paintAzul = Paint()..color = azul..style = PaintingStyle.fill;
    final paintAmarillo = Paint()..color = amarillo..style = PaintingStyle.fill;

    // ── Letra T (azul, izquierda) ─────────────────────────────
    // Barra superior horizontal de la T
    final tBarra = RRect.fromRectAndCorners(
      Rect.fromLTWH(w * 0.05, h * 0.05, w * 0.50, h * 0.18),
      topLeft: Radius.circular(w * 0.06),
      topRight: Radius.circular(w * 0.06),
      bottomLeft: Radius.circular(w * 0.02),
      bottomRight: Radius.circular(w * 0.02),
    );
    canvas.drawRRect(tBarra, paintAzul);
    // Tronco vertical de la T (ligeramente inclinado como el logo original)
    final tronco = Path()
      ..moveTo(w * 0.20, h * 0.20)
      ..lineTo(w * 0.42, h * 0.20)
      ..lineTo(w * 0.36, h * 0.78)
      ..lineTo(w * 0.14, h * 0.78)
      ..close();
    canvas.drawPath(tronco, paintAzul);

    // ── Letra L (amarilla, derecha) ───────────────────────────
    // Tronco vertical de la L (también inclinado)
    final lTronco = Path()
      ..moveTo(w * 0.50, h * 0.18)
      ..lineTo(w * 0.74, h * 0.18)
      ..lineTo(w * 0.68, h * 0.85)
      ..lineTo(w * 0.44, h * 0.85)
      ..close();
    canvas.drawPath(lTronco, paintAmarillo);
    // Pie horizontal de la L
    final lPie = RRect.fromRectAndCorners(
      Rect.fromLTWH(w * 0.44, h * 0.72, w * 0.50, h * 0.18),
      topLeft: Radius.circular(w * 0.02),
      topRight: Radius.circular(w * 0.06),
      bottomLeft: Radius.circular(w * 0.06),
      bottomRight: Radius.circular(w * 0.06),
    );
    canvas.drawRRect(lPie, paintAmarillo);

    // ── Triángulos de play (decorativos, abajo izquierda) ─────
    // Tres triángulos: azul, amarillo, azul — sugieren movimiento.
    final triBaseY = h * 0.78;
    final triH = h * 0.10;
    final triW = w * 0.07;
    final separacion = w * 0.02;
    final startX = w * 0.05;

    void dibujarTriangulo(double x, Color color) {
      final path = Path()
        ..moveTo(x, triBaseY)
        ..lineTo(x + triW, triBaseY + triH / 2)
        ..lineTo(x, triBaseY + triH)
        ..close();
      canvas.drawPath(path, Paint()..color = color..style = PaintingStyle.fill);
    }

    dibujarTriangulo(startX, azul);
    dibujarTriangulo(startX + triW + separacion, amarillo);
    dibujarTriangulo(startX + (triW + separacion) * 2, azul);
  }

  @override
  bool shouldRepaint(_TecnoLiderLogoPainter old) =>
      old.monochrome != monochrome || old.monochromeColor != monochromeColor;
}


String obtenerFechaActual() {
  DateTime now = DateTime.now();
  return "${now.day.toString().padLeft(2,'0')}/${now.month.toString().padLeft(2,'0')}/${now.year}";
}

/// Formatea un double como moneda: $1,234.56
String formatCurrency(double v, {String symbol = '\$', int decimals = 2}) {
  final parts = v.toStringAsFixed(decimals).split('.');
  final intPart = parts[0].replaceAllMapped(
    RegExp(r'(\d{1,3})(?=(\d{3})+(?!\d))'), (m) => '${m[1]},');
  return '$symbol$intPart.${parts[1]}';
}

/// Formatea un double como Bolívares: Bs 1.234,56
String formatBolivares(double v) {
  final parts = v.toStringAsFixed(2).split('.');
  final intPart = parts[0].replaceAllMapped(
    RegExp(r'(\d{1,3})(?=(\d{3})+(?!\d))'), (m) => '${m[1]}.');
  return 'Bs $intPart,${parts[1]}';
}

/// Métodos de pago en bolívares venezolanos (se muestran con "Bs")
const List<String> _metodosEnBolivares = [
  'Efectivo Bs',
  'Pago Móvil',
  'Pago Movil',   // por si se escribe sin acento
  'Transferencia',
  'Punto de venta',
];

/// Determina si un método de pago está denominado en bolívares (Bs).
bool esMetodoEnBolivares(String metodo) {
  final m = metodo.trim().toLowerCase();
  return _metodosEnBolivares.any((x) => x.toLowerCase() == m);
}

/// Formatea un monto aplicando la moneda correcta según el método de pago,
/// SIN multiplicar ni convertir por la tasa. El monto se muestra tal y como
/// el usuario lo ingresó al registrar el pago:
///  · Si el método está denominado en bolívares → se formatea como Bs.
///  · Si no → se formatea como USD.
///
/// Esto evita distorsionar el ticket cuando el cajero ya cobra directamente
/// en la moneda del método (por ejemplo: Pago Móvil se ingresa en Bs y debe
/// imprimirse en Bs sin aplicar tasa).
String formatMontoPorMetodo(double monto, String metodo) {
  if (esMetodoEnBolivares(metodo)) {
    return formatBolivares(monto);
  }
  return formatCurrency(monto);
}

