// ============================================================
//  WIDGET TASA BCV — muestra la tasa en tiempo real
//  Uso: TasaBCVBadge() en cualquier AppBar o pantalla
// ============================================================
class TasaBCVBadge extends StatefulWidget {
  final bool compact;
  const TasaBCVBadge({super.key, this.compact = false});
  @override State<TasaBCVBadge> createState() => _TasaBCVBadgeState();
}

class _TasaBCVBadgeState extends State<TasaBCVBadge> {
  @override
  void initState() {
    super.initState();
    TasaBCVScheduler.addListener(_onCambio);
  }
  @override
  void dispose() {
    TasaBCVScheduler.removeListener(_onCambio);
    super.dispose();
  }
  void _onCambio() { if (mounted) setState(() {}); }

  @override
  Widget build(BuildContext context) {
    final tasa = TasaBCVScheduler.ultimaTasa;
    final actualizando = TasaBCVScheduler.actualizando;

    if (actualizando) {
      return Padding(
        padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
        child: Row(mainAxisSize: MainAxisSize.min, children: [
          const SizedBox(width: 14, height: 14, child: CircularProgressIndicator(strokeWidth: 2, color: Colors.white70)),
          if (!widget.compact) ...[
            const SizedBox(width: 6),
            const Text("BCV...", style: TextStyle(color: Colors.white70, fontSize: 11)),
          ],
        ]),
      );
    }

    if (tasa == null) {
      return GestureDetector(
        onTap: () async {
          // Intento de refresh; si falla, mostramos el motivo real
          await TasaBCVScheduler.actualizarAhora();
          if (!context.mounted) return;
          if (TasaBCVScheduler.ultimaTasa == null &&
              TasaBCVScheduler.ultimoError != null) {
            showDialog(
              context: context,
              builder: (ctx) => AlertDialog(
                title: const Row(children: [
                  Icon(Icons.sync_problem, color: Colors.orange),
                  SizedBox(width: 8),
                  Text('Tasa BCV no disponible'),
                ]),
                content: Column(mainAxisSize: MainAxisSize.min,
                  crossAxisAlignment: CrossAxisAlignment.start, children: [
                  const Text('No se pudo obtener la tasa. Motivo:',
                    style: TextStyle(fontSize: 13)),
                  const SizedBox(height: 8),
                  SelectableText(TasaBCVScheduler.ultimoError!,
                    style: const TextStyle(fontSize: 12,
                      color: Colors.redAccent, fontFamily: 'monospace')),
                  const SizedBox(height: 12),
                  const Text('Posibles causas:',
                    style: TextStyle(fontWeight: FontWeight.bold, fontSize: 12)),
                  const Text('• Sin conexión a internet',
                    style: TextStyle(fontSize: 12)),
                  const Text('• El BCV está caído o su certificado SSL venció',
                    style: TextStyle(fontSize: 12)),
                  const Text('• El Wi-Fi bloquea DNS externos',
                    style: TextStyle(fontSize: 12)),
                ]),
                actions: [
                  TextButton(
                    onPressed: () => Navigator.pop(ctx),
                    child: const Text('Cerrar')),
                  ElevatedButton.icon(
                    icon: const Icon(Icons.refresh),
                    label: const Text('Reintentar'),
                    onPressed: () async {
                      Navigator.pop(ctx);
                      await TasaBCVScheduler.actualizarAhora();
                    }),
                ],
              ),
            );
          }
        },
        child: Container(
          padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
          decoration: BoxDecoration(color: Colors.orange.withValues(alpha: 0.2), borderRadius: BorderRadius.circular(6)),
          child: const Row(mainAxisSize: MainAxisSize.min, children: [
            Icon(Icons.sync_problem, color: Colors.orange, size: 14),
            SizedBox(width: 4),
            Text("Sin tasa", style: TextStyle(color: Colors.orange, fontSize: 11, fontWeight: FontWeight.bold)),
          ]),
        ),
      );
    }

    final color = tasa.esDeHoy ? Colors.greenAccent : Colors.amber;
    return GestureDetector(
      onTap: () => _mostrarDetalle(context, tasa),
      child: Container(
        padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
        decoration: BoxDecoration(
          color: Colors.white.withValues(alpha: 0.12),
          borderRadius: BorderRadius.circular(6),
          border: Border.all(color: Colors.white.withValues(alpha: 0.2)),
        ),
        child: widget.compact
            ? Text("Bs ${tasa.valor.toStringAsFixed(2)}", style: TextStyle(color: color, fontSize: 12, fontWeight: FontWeight.bold))
            : Row(mainAxisSize: MainAxisSize.min, children: [
                Icon(Icons.currency_exchange, color: color, size: 13),
                const SizedBox(width: 4),
                Column(crossAxisAlignment: CrossAxisAlignment.start, mainAxisSize: MainAxisSize.min, children: [
                  Text("BCV: ${tasa.valorFormateado}", style: TextStyle(color: color, fontSize: 12, fontWeight: FontWeight.bold)),
                  Text(tasa.esDeHoy ? "Hoy" : tasa.fechaFormateada.split(' ').first,
                    style: TextStyle(color: color.withValues(alpha: 0.7), fontSize: 9)),
                ]),
              ]),
      ),
    );
  }

  void _mostrarDetalle(BuildContext context, TasaBCV tasa) {
    showDialog(context: context, builder: (ctx) => AlertDialog(
      title: const Row(children: [
        Icon(Icons.account_balance, color: AppColors.royalBlue),
        SizedBox(width: 8),
        Text("Tasa BCV Oficial"),
      ]),
      content: Column(mainAxisSize: MainAxisSize.min, crossAxisAlignment: CrossAxisAlignment.start, children: [
        _filaDetalle("Tasa actual", tasa.valorFormateado, grande: true),
        _filaDetalle("Fuente", tasa.fuente),
        _filaDetalle("Actualizado", tasa.fechaFormateada),
        _filaDetalle("Tipo", tasa.esActualizacionAutomatica ? "Automática" : "Manual"),
        _filaDetalle("Estado", tasa.esDeHoy ? "✅ Al día" : "⚠️ Desactualizada"),
        _filaDetalle("Próx. actualización", "Hoy a las 9:00 PM (VET)"),
        const Divider(),
        const Text("La tasa se actualiza automáticamente cada día a las 9 PM hora Venezuela directamente desde el Banco Central de Venezuela.",
          style: TextStyle(fontSize: 11, color: Colors.grey)),
      ]),
      actions: [
        TextButton(onPressed: () => Navigator.pop(ctx), child: const Text("Cerrar")),
        ElevatedButton.icon(
          icon: TasaBCVScheduler.actualizando
              ? const SizedBox(width: 16, height: 16, child: CircularProgressIndicator(strokeWidth: 2, color: Colors.white))
              : const Icon(Icons.refresh),
          label: const Text("Actualizar ahora"),
          onPressed: TasaBCVScheduler.actualizando ? null : () async {
            Navigator.pop(ctx);
            await TasaBCVScheduler.actualizarAhora();
          },
        ),
      ],
    ));
  }

  Widget _filaDetalle(String label, String valor, {bool grande = false}) {
    return Padding(
      padding: const EdgeInsets.symmetric(vertical: 4),
      child: Row(mainAxisAlignment: MainAxisAlignment.spaceBetween, children: [
        Text(label, style: const TextStyle(color: Colors.grey, fontSize: 13)),
        Text(valor, style: TextStyle(
          fontWeight: FontWeight.bold,
          fontSize: grande ? 18 : 13,
          color: grande ? AppColors.primaryBlue : null,
        )),
      ]),
    );
  }
}

// ============================================================
//  MODELOS DE DATOS (con fromMap / toMap para la API)
// ============================================================

class MensajeInterno {
  final int? id;
  final String emisor, receptor, contenido, hora;
  final String? imagenPath, audioPath;

  /// Fecha+hora completa del mensaje (ISO). Si el backend devuelve sólo
  /// la columna `hora` (HH:MM) usamos la fecha actual como aproximación
  /// para los separadores de día. Cuando hay columna `fecha_envio` la
  /// usamos como fuente de verdad.
  final DateTime? fechaEnvio;

  // ── Reply / cita estilo WhatsApp ────────────────────────────
  final int? replyA;          // id del mensaje al que responde
  final String? replyEmisor;  // emisor del mensaje citado (cache)
  final String? replyContenido; // texto/preview del citado (cache)

  // ── Estado de lectura ────────────────────────────────────────
  /// 0 = enviado (✓), 1 = entregado (✓✓ gris), 2 = leído (✓✓ azul)
  final int estado;

  MensajeInterno({this.id, required this.emisor, required this.receptor,
      required this.contenido, required this.hora,
      this.imagenPath, this.audioPath, this.fechaEnvio,
      this.replyA, this.replyEmisor, this.replyContenido,
      this.estado = 0});

  factory MensajeInterno.fromMap(Map<String,dynamic> m) {
    DateTime? f;
    final raw = m['fecha_envio'] ?? m['created_at'] ?? m['fecha'];
    if (raw is String && raw.isNotEmpty) {
      f = DateTime.tryParse(raw);
    }
    int est = 0;
    final estRaw = m['estado'];
    if (estRaw != null) {
      if (estRaw is int) est = estRaw;
      else if (estRaw is String) est = int.tryParse(estRaw) ?? 0;
    } else {
      // Compatibilidad: si sólo hay `leido` (bool/int)
      final leido = m['leido'];
      if (leido == 1 || leido == '1' || leido == true) est = 2;
    }
    int? rA;
    final rRaw = m['reply_a'];
    if (rRaw is int) rA = rRaw;
    else if (rRaw is String) rA = int.tryParse(rRaw);

    return MensajeInterno(
      id: m['id'] is int ? m['id'] : (m['id'] is String ? int.tryParse(m['id']) : null),
      emisor: m['emisor']??'', receptor: m['receptor']??'',
      contenido: m['contenido']??'', hora: m['hora']??'',
      imagenPath: m['imagen_path'], audioPath: m['audio_path'],
      fechaEnvio: f,
      replyA: rA,
      replyEmisor: m['reply_emisor'],
      replyContenido: m['reply_contenido'],
      estado: est,
    );
  }

  Map<String,dynamic> toMap() => {
    'emisor':emisor,'receptor':receptor,
    'contenido':contenido,'hora':hora,
    'imagen_path':imagenPath,'audio_path':audioPath,
    if (replyA != null) 'reply_a': replyA,
    if (replyEmisor != null) 'reply_emisor': replyEmisor,
    if (replyContenido != null) 'reply_contenido': replyContenido,
  };

  /// True si el mensaje es para un grupo (receptor con prefijo "grupo:")
  bool get esGrupal => receptor.startsWith('grupo:');

  /// Nombre del grupo si es grupal, vacío si es privado.
  String get nombreGrupo => esGrupal ? receptor.substring(6) : '';
}

/// Helpers para identificar grupos y construir el receptor de un grupo.
String receptorGrupoTienda(String tienda) => 'grupo:$tienda';
bool esReceptorGrupo(String receptor) => receptor.startsWith('grupo:');
String nombreGrupoDeReceptor(String receptor) =>
    receptor.startsWith('grupo:') ? receptor.substring(6) : receptor;

/// Devuelve los grupos de tienda visibles para [u]:
/// - Dueño/Administrador/Gerente: todos los grupos.
/// - Resto: sólo el grupo de su propia tienda (si tiene una asignada).
List<String> gruposVisiblesParaUsuario(Usuario u) {
  if (u.rol == 'Dueño' || u.rol == 'Administrador' || u.rol == 'Gerente') {
    return List<String>.from(ConfigSistema.tiendas);
  }
  if (u.tienda.trim().isEmpty) return const [];
  return [u.tienda];
}

/// Devuelve true si [u] puede enviar mensajes al grupo [tienda].
bool puedeEnviarAlGrupo(Usuario u, String tienda) {
  if (u.rol == 'Dueño' || u.rol == 'Administrador' || u.rol == 'Gerente') {
    return true;
  }
  return u.tienda == tienda;
}

/// Servicio local de mensajes leídos. Mantiene un set de IDs en
/// SharedPreferences por usuario, así el indicador "no leído" no depende
/// del backend (que puede no soportar la columna `estado` aún).
///
/// Funcionamiento:
///  · Al abrir un chat, se llaman `marcarLeidos()` con los IDs vistos.
///  · La lista de chats consulta `estaLeido(id)` para decidir el badge.
///  · El servidor SIGUE intentando recibir el `estado=2` (best-effort)
///    para que las tildes ✓✓ azules funcionen en otros dispositivos.
class MensajesLeidosService {
  static const _kPrefix = 'mensajes_leidos_';
  static Set<int>? _cache;
  static String? _correoActual;

  static String get _key {
    final c = usuarioSesion?.correo ?? 'anon';
    return '$_kPrefix$c';
  }

  /// Carga el set desde disco (lazy). Si cambia el usuario en sesión,
  /// se invalida el cache y se relee.
  static Future<Set<int>> _cargar() async {
    final correoActual = usuarioSesion?.correo ?? 'anon';
    if (_cache != null && _correoActual == correoActual) return _cache!;
    try {
      final prefs = await SharedPreferences.getInstance();
      final lista = prefs.getStringList(_key) ?? const <String>[];
      _cache = lista.map(int.tryParse).whereType<int>().toSet();
      _correoActual = correoActual;
      // Limitar tamaño del set para no crecer indefinidamente. Conservamos
      // los 5000 IDs más recientes (los más altos).
      if (_cache!.length > 5000) {
        final ordenados = _cache!.toList()..sort((a, b) => b.compareTo(a));
        _cache = ordenados.take(5000).toSet();
        await _persistir();
      }
    } catch (_) {
      _cache = <int>{};
      _correoActual = correoActual;
    }
    return _cache!;
  }

  static Future<void> _persistir() async {
    if (_cache == null) return;
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setStringList(_key,
          _cache!.map((i) => i.toString()).toList());
    } catch (_) {}
  }

  /// Devuelve true si [id] ya está marcado como leído por este usuario.
  static Future<bool> estaLeido(int id) async {
    final s = await _cargar();
    return s.contains(id);
  }

  /// Marca varios IDs como leídos. Actualiza el cache en memoria
  /// de forma SÍNCRONA (sin esperar al await de `_cargar`) para que
  /// `estaLeidoSync` los vea inmediatamente, incluso si esta función
  /// se llama sin await desde un dispose(). La persistencia en disco
  /// se hace de forma asíncrona después.
  static Future<void> marcarLeidos(Iterable<int> ids) async {
    if (ids.isEmpty) return;
    // 1) Actualizar el cache en memoria YA, antes de cualquier await.
    //    Si el cache aún no se cargó, lo inicializamos vacío para que
    //    los IDs queden registrados en memoria sin esperar a la lectura
    //    de SharedPreferences.
    if (_cache == null) {
      _cache = <int>{};
      _correoActual = usuarioSesion?.correo ?? 'anon';
    } else if (_correoActual != (usuarioSesion?.correo ?? 'anon')) {
      // Cambió el usuario activo: re-inicializar
      _cache = <int>{};
      _correoActual = usuarioSesion?.correo ?? 'anon';
    }
    var cambio = false;
    for (final id in ids) {
      if (_cache!.add(id)) cambio = true;
    }
    if (!cambio) return;

    // 2) Asegurar que también merge con lo persistido (por si había
    //    IDs en disco que aún no estaban en memoria).
    try {
      final prefs = await SharedPreferences.getInstance();
      final lista = prefs.getStringList(_key) ?? const <String>[];
      for (final s in lista) {
        final i = int.tryParse(s);
        if (i != null) _cache!.add(i);
      }
      // Persistir cache combinado
      await prefs.setStringList(_key,
          _cache!.map((i) => i.toString()).toList());
    } catch (_) {}
  }

  /// Versión síncrona para usar dentro de filtros UI. Requiere haber
  /// llamado a `_cargar()` previamente (la lista de chats lo hace al
  /// inicio); devuelve false si el cache aún no está disponible.
  static bool estaLeidoSync(int id) {
    if (_cache == null) return false;
    if (_correoActual != (usuarioSesion?.correo ?? 'anon')) return false;
    return _cache!.contains(id);
  }

  /// Pre-carga el cache (úsalo al abrir la lista de chats).
  static Future<void> precargar() => _cargar();

  /// Limpia el cache (al cerrar sesión, por ejemplo).
  static void limpiarCache() {
    _cache = null;
    _correoActual = null;
  }
}

