class NotificacionSistema {
  /// id mutable: se asigna después del POST al backend para que las
  /// notificaciones recién creadas localmente puedan marcarse leídas.
  int? id;
  final String titulo, mensaje, fecha;
  bool leida;
  NotificacionSistema({this.id, required this.titulo, required this.mensaje,
      required this.fecha, this.leida = false});
  factory NotificacionSistema.fromMap(Map<String,dynamic> m) {
    // El campo `leida` puede venir del backend como int (1) o string ('1')
    // dependiendo del driver MySQL/PDO. Antes la comparación '== 1' fallaba
    // cuando llegaba como string, marcando todo como NO LEÍDO y mostrando
    // contador falso al usuario.
    final l = m['leida'];
    final esLeida = l == 1 || l == '1' || l == true;
    return NotificacionSistema(
      id: m['id'] is int ? m['id'] :
          (m['id'] is String ? int.tryParse(m['id']) : null),
      titulo: m['titulo']??'',
      mensaje: m['mensaje']??'',
      fecha: m['fecha']??'',
      leida: esLeida,
    );
  }
}

