/// Lista global de clientes (cache en memoria de la tabla `clientes` del backend).
List<ClienteModel> clientesGlobal = [];

/// Cache en memoria del conteo de compras por cédula (clave normalizada
/// sin letras ni guiones para tolerar variaciones como "V-12345678" vs
/// "12345678"). Se actualiza desde `actualizarConteoCompras()`.
Map<String, int> conteoComprasPorCedula = {};

/// Normaliza una cédula para usarla como clave del mapa de conteos.
/// Quita espacios, guiones y prefijos V / E.
String _normalizarCedula(String cedula) {
  return cedula.replaceAll(RegExp(r'[VEve\-\s]'), '').trim();
}

/// Devuelve cuántas facturas tiene registradas un cliente según su cédula.
/// Lee del cache `conteoComprasPorCedula`. Si no hay cache, devuelve 0.
int contarComprasCliente(String cedula) {
  return conteoComprasPorCedula[_normalizarCedula(cedula)] ?? 0;
}

/// Recalcula el cache de compras consultando la API de facturas.
/// Agrupa por cédula (normalizada) y cuenta cuántas facturas hay por
/// cada una. Debe llamarse después de cargar facturas o al refrescar
/// la ventana de Clientes / abrir el formulario de factura.
Future<void> actualizarConteoCompras() async {
  try {
    final raw = await _Api.get('facturas');
    final Map<String, int> mapa = {};
    for (final v in ((raw as List?) ?? [])) {
      final ced = _normalizarCedula((v['cedula'] ?? '').toString());
      if (ced.isEmpty) continue;
      mapa[ced] = (mapa[ced] ?? 0) + 1;
    }
    conteoComprasPorCedula = mapa;
  } catch (e) {
    debugPrint('[Clientes] Error actualizando conteo de compras: $e');
  }
}

/// Reconstruye la lista `clientesGlobal` a partir de las facturas.
/// Agrupa por cédula tomando los datos más recientes (nombre/teléfono)
/// disponibles. También actualiza `conteoComprasPorCedula`.
///
/// Esta función reemplaza cualquier carga previa desde el endpoint
/// `clientes`. Si `preservarImportados=true`, se mantienen los
/// clientes importados desde Excel que aún no han comprado.
Future<void> reconstruirClientesDesdeFacturas({bool preservarImportados = true}) async {
  try {
    final raw = await _Api.get('facturas');
    final Map<String, int> conteo = {};
    // Guardamos el último registro visto por cédula para quedarnos
    // con los datos más recientes del cliente.
    final Map<String, ClienteModel> mapaClientes = {};

    for (final v in ((raw as List?) ?? [])) {
      final cedulaOriginal = (v['cedula'] ?? '').toString();
      final ced = _normalizarCedula(cedulaOriginal);
      if (ced.isEmpty) continue;
      conteo[ced] = (conteo[ced] ?? 0) + 1;

      final nombre   = (v['cliente']  ?? '').toString().trim();
      final telefono = (v['telefono'] ?? '').toString().trim();
      if (nombre.isEmpty) continue;

      // Preservar correo previo si ya lo teníamos (el backend de
      // facturas no guarda correo, pero podría venir por importación).
      final previo = mapaClientes[ced];
      final correoPrevio = previo?.correo ?? '';

      mapaClientes[ced] = ClienteModel(
        cedula: cedulaOriginal.isNotEmpty ? cedulaOriginal : ced,
        nombre: nombre,
        telefono: telefono.isNotEmpty
            ? telefono
            : (previo?.telefono ?? ''),
        correo: correoPrevio,
      );
    }

    // Si hay clientes importados de Excel que aún no han comprado,
    // los conservamos en la lista para que sigan visibles.
    if (preservarImportados) {
      for (final c in clientesGlobal) {
        final ced = _normalizarCedula(c.cedula);
        if (ced.isEmpty) continue;
        if (!mapaClientes.containsKey(ced)) {
          mapaClientes[ced] = c;
        } else {
          // Si el cliente existía como importado y ahora tiene compras,
          // conservamos el correo que venía del Excel.
          final existente = mapaClientes[ced]!;
          if (existente.correo.isEmpty && c.correo.isNotEmpty) {
            mapaClientes[ced] = ClienteModel(
              cedula: existente.cedula,
              nombre: existente.nombre,
              telefono: existente.telefono,
              correo: c.correo,
            );
          }
        }
      }
    }

    clientesGlobal = mapaClientes.values.toList()
      ..sort((a, b) => a.nombre.toLowerCase()
          .compareTo(b.nombre.toLowerCase()));
    conteoComprasPorCedula = conteo;
  } catch (e) {
    debugPrint('[Clientes] Error reconstruyendo desde facturas: $e');
  }
}

// ── PRODUCTO ────────────────────────────────────────────────
class Producto {
  final String codigo, nombre, categoria, marca, modelo, tipo;
  final double precioCosto, precioVenta;
  int stockManual;
  int? porcentajeBateria;
  int stockTotal = 0; // se actualiza al cargar IMEIs
  /// Código del producto PADRE si éste es un subproducto (variante:
  /// color/almacenamiento/etc). Vacío si es producto principal.
  /// Permite agrupar variantes bajo un mismo modelo manteniendo SKUs
  /// independientes por variante.
  String productoPadreCodigo;
  /// Texto libre que describe la variante (ej. "Color blanco 64GB").
  /// Solo aplica a subproductos.
  String variante;

  Producto({required this.codigo, required this.nombre, required this.categoria,
      required this.marca, required this.modelo, required this.precioCosto,
      required this.tipo, required this.precioVenta,
      this.stockManual = 0, this.porcentajeBateria,
      this.productoPadreCodigo = '', this.variante = ''});

  /// true si este producto es una variante hija de otro.
  bool get esSubproducto => productoPadreCodigo.isNotEmpty;

  factory Producto.fromMap(Map<String,dynamic> m) => Producto(
    codigo: m['codigo']??'', nombre: m['nombre']??'', categoria: m['categoria']??'',
    marca: m['marca']??'', modelo: m['modelo']??'', tipo: m['tipo']??'',
    precioCosto: double.tryParse(m['precio_costo'].toString())??0,
    precioVenta: double.tryParse(m['precio_venta'].toString())??0,
    stockManual: int.tryParse(m['stock_manual'].toString())??0,
    porcentajeBateria: m['porcentaje_bateria']!=null ? int.tryParse(m['porcentaje_bateria'].toString()) : null,
    productoPadreCodigo: (m['producto_padre_codigo'] ?? '').toString(),
    variante: (m['variante'] ?? '').toString());

  Map<String,dynamic> toMap() => {'codigo':codigo,'nombre':nombre,'categoria':categoria,
    'marca':marca,'modelo':modelo,'tipo':tipo,'precio_costo':precioCosto,
    'precio_venta':precioVenta,'stock_manual':stockManual,
    'porcentaje_bateria':porcentajeBateria,
    'producto_padre_codigo': productoPadreCodigo,
    'variante': variante};
}

// ── IMEI ─────────────────────────────────────────────────────
class ImeiRegistro {
  final String imei;
  final Producto producto;
  final String fechaIngreso, proveedor, color;
  String ubicacion;
  final int? porcentajeBateria;
  bool vendido;

  ImeiRegistro({required this.imei, required this.producto, required this.fechaIngreso,
      required this.proveedor, required this.color, required this.ubicacion,
      this.porcentajeBateria, this.vendido = false});

  factory ImeiRegistro.fromMap(Map<String,dynamic> m) {
    // Datos crudos que vienen de la API (pueden estar vacíos si el backend
    // no hace JOIN con la tabla `productos`).
    final codigo = (m['producto_codigo'] ?? '').toString();
    String nombre = (m['producto_nombre'] ?? '').toString();
    String categoria = (m['categoria'] ?? '').toString();
    String marca = (m['marca'] ?? '').toString();
    String modelo = (m['modelo'] ?? '').toString();
    String tipo = (m['tipo'] ?? '').toString();
    double precioCosto = double.tryParse(m['precio_costo']?.toString() ?? '') ?? 0;
    double precioVenta = double.tryParse(m['precio_venta']?.toString() ?? '') ?? 0;

    // Si los campos del producto vienen vacíos (el JOIN no se hizo en el
    // backend o el endpoint sólo devuelve los datos crudos de stock_imei),
    // los completamos con `catalogoGlobal` cruzando por código de producto.
    if (codigo.isNotEmpty &&
        (nombre.isEmpty || marca.isEmpty || modelo.isEmpty || categoria.isEmpty)) {
      final p = catalogoGlobal.where((x) => x.codigo == codigo).firstOrNull;
      if (p != null) {
        if (nombre.isEmpty) nombre = p.nombre;
        if (categoria.isEmpty) categoria = p.categoria;
        if (marca.isEmpty) marca = p.marca;
        if (modelo.isEmpty) modelo = p.modelo;
        if (tipo.isEmpty) tipo = p.tipo;
        if (precioCosto == 0) precioCosto = p.precioCosto;
        if (precioVenta == 0) precioVenta = p.precioVenta;
      }
    }

    final prod = Producto(
      codigo: codigo, nombre: nombre,
      categoria: categoria, marca: marca,
      modelo: modelo, tipo: tipo,
      precioCosto: precioCosto, precioVenta: precioVenta);
    return ImeiRegistro(
      imei: m['imei']??'', producto: prod, fechaIngreso: m['fecha_ingreso']??'',
      proveedor: m['proveedor']??'', color: m['color']??'',
      ubicacion: m['ubicacion']??'Almacen',
      porcentajeBateria: m['porcentaje_bateria']!=null ? int.tryParse(m['porcentaje_bateria'].toString()) : null,
      vendido: (m['vendido']??0)==1);
  }
  Map<String,dynamic> toMap() => {'imei':imei,'producto_codigo':producto.codigo,
    'fecha_ingreso':fechaIngreso,'proveedor':proveedor,'color':color,
    'porcentaje_bateria':porcentajeBateria,'ubicacion':ubicacion,'vendido':vendido?1:0};
}

