    pagada: m['pagada'] == true || m['pagada'] == 1,
    fechaPago: m['fecha_pago']?.toString(),
  );

  Map<String, dynamic> toMap() => {
    'numero': numero,
    'monto': monto,
    'fecha': fecha,
    'pagada': pagada,
    'fecha_pago': fechaPago,
  };
}

class CuentaPorCobrar {
  int? id;
  final String cedula, nombre, telefono, correo;
  double montoTotal;
  List<Map<String,dynamic>> pagos;
  List<CuotaCobrar> cuotas;
  String notas;
  /// Nombre de la financiadora (Weppa, Cashea, FPB, Krece, etc.).
  /// Vacío si la cuenta no fue creada por una factura financiada.
  String financiadora;

  CuentaPorCobrar({this.id, required this.cedula, required this.nombre,
      required this.telefono, required this.correo, required this.montoTotal,
      this.notas = "", this.financiadora = "",
      List<Map<String,dynamic>>? pagos,
      List<CuotaCobrar>? cuotas})
      : pagos = pagos ?? [],
        cuotas = cuotas ?? [];

  /// Suma de todos los pagos libres registrados
  double get totalPagado =>
      pagos.fold(0.0, (s, p) => s + (double.tryParse(p['monto'].toString()) ?? 0));

  /// Suma de cuotas marcadas como pagadas
  double get totalCuotasPagadas =>
      cuotas.where((c) => c.pagada).fold(0.0, (s, c) => s + c.monto);

  double get saldoRestante =>
      (montoTotal - totalPagado - totalCuotasPagadas).clamp(0, double.infinity);

  /// Próxima cuota pendiente (la de menor número no pagada)
  CuotaCobrar? get proximaCuota =>
      cuotas.where((c) => !c.pagada).fold<CuotaCobrar?>(null, (prev, c) {
        if (prev == null) return c;
        return c.numero < prev.numero ? c : prev;
      });

  factory CuentaPorCobrar.fromMap(Map<String,dynamic> m) => CuentaPorCobrar(
    id: m['id'],
    cedula: m['cedula'] ?? '',
    nombre: m['nombre'] ?? '',
    telefono: m['telefono'] ?? '',
    correo: m['correo'] ?? '',
    montoTotal: double.tryParse(m['monto_total'].toString()) ?? 0,
    notas: m['notas'] ?? '',
    financiadora: (m['financiadora'] ?? '').toString(),
    pagos: List<Map<String,dynamic>>.from(m['pagos'] ?? []),
    cuotas: ((m['cuotas'] as List?) ?? [])
        .map((c) => CuotaCobrar.fromMap(c as Map<String, dynamic>))
        .toList()
      ..sort((a, b) => a.numero.compareTo(b.numero)),
  );

  Map<String,dynamic> toMap() => {
    'cedula': cedula, 'nombre': nombre, 'telefono': telefono,
    'correo': correo, 'monto_total': montoTotal, 'notas': notas,
    'financiadora': financiadora,
  };

  Map<String,dynamic> toMapConCuotas() => {
    ...toMap(),
    'cuotas': cuotas.map((c) => c.toMap()).toList(),
  };
}

