// ── USUARIO ───────────────────────────────────────────────────
class Usuario {
  int? id;
  final String nombre, cedula, correo, clave, rol;
  double sueldoBase;
  /// Tienda a la que pertenece el usuario. Vacío = todas las tiendas
  /// (sólo aplica a Administrador/Dueño/Gerente).
  String tienda;

  Usuario({this.id, required this.nombre, required this.cedula,
      required this.correo, required this.clave, required this.rol,
      this.sueldoBase = 0, this.tienda = ''});

  factory Usuario.fromMap(Map<String,dynamic> m) => Usuario(
    id: m['id'], nombre: m['nombre']??'', cedula: m['cedula']??'',
