    'clave':clave,'rol':rol,'sueldo_base':sueldoBase,'tienda':tienda};
}

// ── SERVICIO TÉCNICO ──────────────────────────────────────────
// Representa una orden de servicio técnico tal como aparece en la
// planilla física: datos del cliente, equipo, checklist de componentes
// recibidos, diagnóstico y estado de pago.
class ServicioTecnico {
  int? id;

  // ── Cabecera / montos ─────────────────────────────────────
  double monto;           // Monto total del servicio (lo que se cobra al cliente)
  double abono;           // Abono inicial del cliente
  double costoRepuestos;  // Costo de los repuestos/insumos usados (lo que GASTÓ el negocio)
  double get resta => (monto - abono).clamp(0, double.infinity);
  /// Ganancia neta del servicio: lo cobrado al cliente menos lo gastado
  /// en repuestos. Si todavía no se ha cargado el costo, devuelve `monto`.
  double get ganancia => monto - costoRepuestos;
  bool pagado;            // Si está completamente pagado

  // ── Fechas ────────────────────────────────────────────────
  final DateTime fecha;   // Fecha de recepción
  String horaRecibido;    // Hora en que se recibió el equipo
  String fechaEntrega;    // Fecha estimada/real de entrega (texto libre)

  // ── Cliente ───────────────────────────────────────────────
  String nombreCliente;
  String telefono;
  String rifCi;           // RIF o Cédula

  // ── Equipo ────────────────────────────────────────────────
  String modelo;
  String marca;
  String descripcion;     // Descripción del problema / motivo
  String imei;
  String contrasena;      // Patrón o PIN para que el técnico pueda probar

  // ── Checklist de componentes (cada uno: true=SI, false=NO, null=no revisado) ──
  // Columna izquierda
  bool? chip, memoria, bateria, tapa;
  bool? encendido, apagado, camara, corneta;
  bool? flash, flashConDefecto;
  // Columna derecha
  bool? tactilPartido, auricular, microfono, contrasenaChk;
  bool? track, botonVolumen, teclado, botonEncendido, pantallaConDefecto;

  // ── Notas finales ─────────────────────────────────────────
  String observacion;
  String tecnico;
  String estado; // Recibido, En reparación, Listo, Entregado

  /// Fotos del equipo al momento de la recepción. Se guardan como
  /// strings base64 (data URI o data crudo). El backend las persiste
  /// dentro del bloque __META__ de la descripción, así que no
  /// requieren columna extra. Útil para dejar constancia visual de
  /// rayones, manchas o piezas faltantes al recibir el equipo.
  List<String> fotosRecepcion;

  ServicioTecnico({
    this.id,
    required this.monto,
    required this.fecha,
    this.abono = 0,
    this.costoRepuestos = 0,
    this.pagado = false,
    this.horaRecibido = '',
    this.fechaEntrega = '',
    this.nombreCliente = '',
    this.telefono = '',
    this.rifCi = '',
    this.modelo = '',
    this.marca = '',
    this.descripcion = '',
    this.imei = '',
    this.contrasena = '',
    this.chip, this.memoria, this.bateria, this.tapa,
    this.encendido, this.apagado, this.camara, this.corneta,
    this.flash, this.flashConDefecto,
    this.tactilPartido, this.auricular, this.microfono, this.contrasenaChk,
    this.track, this.botonVolumen, this.teclado, this.botonEncendido,
    this.pantallaConDefecto,
    this.observacion = '',
    this.tecnico = '',
    this.estado = 'Recibido',
    List<String>? fotosRecepcion,
  }) : fotosRecepcion = fotosRecepcion ?? [];

  /// Alias retro-compatible con el campo "nota" original.
  /// Combina descripción + observación para la vista de lista.
  String get nota {
    final parts = <String>[];
    if (descripcion.isNotEmpty) parts.add(descripcion);
    if (observacion.isNotEmpty) parts.add('Obs: $observacion');
    return parts.join(' · ');
  }

  factory ServicioTecnico.fromMap(Map<String, dynamic> m) {
    // Helper: convierte un valor numérico o booleano opcional a bool?
    // 1 → true, 0 → false, null/vacío → null
    bool? _bn(dynamic v) {
      if (v == null) return null;
      if (v is bool) return v;
      final s = v.toString().trim();
      if (s.isEmpty || s == 'null') return null;
      if (s == '1' || s.toLowerCase() == 'true' || s.toLowerCase() == 'si') return true;
      if (s == '0' || s.toLowerCase() == 'false' || s.toLowerCase() == 'no') return false;
      return null;
    }

    // Helper: devuelve el primer valor no-null/no-vacío entre varias claves.
    // Útil cuando el backend responde con nombres de columna que varían
    // según la versión de la API (p.ej. 'nombre_cliente' vs 'cliente',
    // 'rif_ci' vs 'cedula', 'hora_recibido' vs 'horaRecibido', etc.).
    String _pickStr(List<String> keys) {
      for (final k in keys) {
        final v = m[k];
        if (v == null) continue;
        final s = v.toString();
        if (s.trim().isNotEmpty) return s;
      }
      return '';
    }

    // ═══════════════════════════════════════════════════════════
    //  DESEMPAQUETADO DEL BLOQUE __META__
    //  El backend no guarda varios campos (cédula, marca, modelo,
    //  contraseña, hora_recibido, fecha_entrega, checklist). Para
    //  persistirlos igualmente sin tocar el backend, los empaquetamos
    //  como JSON al INICIO del campo `descripcion` (que SÍ se guarda)
    //  con la marca `__META__{...}\n---\n`.
    //
    //  Al leer, detectamos esa marca, extraemos el JSON y dejamos en
    //  `descripcion` solo el texto real (lo que viene después de `---`).
    //  Si no hay marca, se lee la descripción tal cual.
    // ═══════════════════════════════════════════════════════════
    String descripcionRaw = _pickStr(['descripcion', 'nota']);
    Map<String, dynamic> meta = const {};
    String descripcionLimpia = descripcionRaw;

    if (descripcionRaw.startsWith('__META__')) {
      // Buscar el separador `\n---\n` o `\n---` al final de la línea META
      final idx = descripcionRaw.indexOf('\n---');
      if (idx > 0) {
        final jsonStr = descripcionRaw.substring('__META__'.length, idx);
        // Lo que viene después del separador es la descripción real
        final resto = descripcionRaw.substring(idx + '\n---'.length);
        descripcionLimpia = resto.startsWith('\n')
            ? resto.substring(1)
            : resto;
        try {
          final parsed = jsonDecode(jsonStr);
          if (parsed is Map) meta = Map<String, dynamic>.from(parsed);
        } catch (_) {
          // JSON corrupto: conservamos la descripción original completa
          descripcionLimpia = descripcionRaw;
        }
      }
    }

    // Helper: lee un bool? del META checklist
    bool? _metaBn(String key) {
      final chk = meta['chk'];
      if (chk is! Map) return null;
      return _bn(chk[key]);
    }

    // Helper: lee un string del META con fallback a las columnas sueltas
    // (así si algún día el backend sí empieza a guardar esos campos,
    // la lectura sigue funcionando).
    String _metaOrCol(String metaKey, List<String> colKeys) {
      final v = meta[metaKey];
      if (v != null && v.toString().trim().isNotEmpty) return v.toString();
      return _pickStr(colKeys);
    }

    return ServicioTecnico(
      id: m['id'] is int ? m['id'] : int.tryParse(m['id']?.toString() ?? ''),
      monto: double.tryParse(m['monto'].toString()) ?? 0,
      abono: double.tryParse(m['abono']?.toString() ?? '0') ?? 0,
      // Costo de repuestos: empaquetado en META (el backend no tiene
      // columna propia). Si el JSON META no lo tiene, queda en 0.
      costoRepuestos: double.tryParse(
        (meta['costoRepuestos'] ?? m['costo_repuestos'] ?? '0').toString()) ?? 0,
      pagado: (m['pagado'] ?? 0) == 1 || m['pagado'] == true,
      fecha: DateTime.tryParse(m['fecha'] ?? '') ?? DateTime.now(),

      // Campos empaquetados en META (con fallback a columnas, por si
      // el backend las guarda realmente en alguna instalación).
      horaRecibido  : _metaOrCol('hora',     ['hora_recibido', 'horaRecibido', 'hora']),
      fechaEntrega  : _metaOrCol('entrega',  ['fecha_entrega', 'fechaEntrega', 'entrega']),
      rifCi         : _metaOrCol('rif',      ['rif_ci', 'rifCi', 'rif', 'ci', 'cedula']),
      marca         : _metaOrCol('marca',    ['marca']),
      modelo        : _metaOrCol('modelo',   ['modelo']),
      contrasena    : _metaOrCol('pass',     ['contrasena', 'password']),

      // Campos que el backend sí guarda normalmente
      nombreCliente: _pickStr(['nombre_cliente', 'nombreCliente', 'cliente', 'nombre']),
      telefono: _pickStr(['telefono']),
      descripcion: descripcionLimpia.trim(),
      imei: _pickStr(['imei']),

      // Checklist: primero intentar del META, luego de columnas (fallback)
      chip:              _metaBn('chip')            ?? _bn(m['chip']),
      memoria:           _metaBn('memoria')         ?? _bn(m['memoria']),
      bateria:           _metaBn('bateria')         ?? _bn(m['bateria']),
      tapa:              _metaBn('tapa')            ?? _bn(m['tapa']),
      encendido:         _metaBn('encendido')       ?? _bn(m['encendido']),
      apagado:           _metaBn('apagado')         ?? _bn(m['apagado']),
      camara:            _metaBn('camara')          ?? _bn(m['camara']),
      corneta:           _metaBn('corneta')         ?? _bn(m['corneta']),
      flash:             _metaBn('flash')           ?? _bn(m['flash']),
      flashConDefecto:   _metaBn('flashDef')        ?? _bn(m['flash_con_defecto']),
      tactilPartido:     _metaBn('tactilPart')      ?? _bn(m['tactil_partido']),
      auricular:         _metaBn('auricular')       ?? _bn(m['auricular']),
      microfono:         _metaBn('microfono')       ?? _bn(m['microfono']),
      contrasenaChk:     _metaBn('passChk')         ?? _bn(m['contrasena_chk']),
      track:             _metaBn('track')           ?? _bn(m['track']),
      botonVolumen:      _metaBn('btnVol')          ?? _bn(m['boton_volumen']),
      teclado:           _metaBn('teclado')         ?? _bn(m['teclado']),
      botonEncendido:    _metaBn('btnEnc')          ?? _bn(m['boton_encendido']),
      pantallaConDefecto:_metaBn('pantallaDef')     ?? _bn(m['pantalla_con_defecto']),

      observacion: _pickStr(['observacion', 'observaciones']),
      tecnico: _pickStr(['tecnico']),
      estado: _pickStr(['estado']).isEmpty ? 'Recibido' : _pickStr(['estado']),
      // Fotos del meta (lista de strings base64). Si no hay, lista vacía.
      fotosRecepcion: (meta['fotos'] is List)
          ? List<String>.from(
              (meta['fotos'] as List).map((e) => e.toString()))
          : <String>[],
    );
  }

  Map<String, dynamic> toMap() {
    // Helper: serializa bool? como 1/0/null
    int? _bi(bool? v) => v == null ? null : (v ? 1 : 0);

    // ═══════════════════════════════════════════════════════════
    //  EMPAQUETADO DE CAMPOS NO PERSISTIDOS
    //  El backend solo guarda un subconjunto de columnas
    //  (monto, abono, pagado, fecha, telefono, imei, descripcion,
    //   nombre_cliente, observacion, tecnico, estado, nota).
    //  Los campos que no tienen columna propia los empaquetamos
    //  como JSON al inicio del campo `descripcion` con la marca
    //  `__META__{...}\n---\n`. Al releer se desempaquetan.
    // ═══════════════════════════════════════════════════════════
    final meta = <String, dynamic>{
      'rif'       : rifCi,
      'marca'     : marca,
      'modelo'    : modelo,
      'pass'      : contrasena,
      'hora'      : horaRecibido,
      'entrega'   : fechaEntrega,
      // Costo de repuestos: lo gastado en reparar este equipo.
      // El backend no tiene columna dedicada; lo guardamos aquí.
      'costoRepuestos': costoRepuestos,
      // Fotos de recepción (lista de base64). Cada foto deja
      // constancia del estado del equipo al recibirlo.
      'fotos': fotosRecepcion,
      'chk'       : {
        'chip'        : _bi(chip),
        'memoria'     : _bi(memoria),
        'bateria'     : _bi(bateria),
        'tapa'        : _bi(tapa),
        'encendido'   : _bi(encendido),
        'apagado'     : _bi(apagado),
        'camara'      : _bi(camara),
        'corneta'     : _bi(corneta),
        'flash'       : _bi(flash),
        'flashDef'    : _bi(flashConDefecto),
        'tactilPart'  : _bi(tactilPartido),
        'auricular'   : _bi(auricular),
        'microfono'   : _bi(microfono),
        'passChk'     : _bi(contrasenaChk),
        'track'       : _bi(track),
        'btnVol'      : _bi(botonVolumen),
        'teclado'     : _bi(teclado),
        'btnEnc'      : _bi(botonEncendido),
        'pantallaDef' : _bi(pantallaConDefecto),
      },
    };

    // Construir el campo descripción con META al inicio y la
    // descripción real después del separador.
    final descPersistida =
        '__META__${jsonEncode(meta)}\n---\n${descripcion.trim()}';

    return {
      // ── Montos / pago ──
      'monto': monto,
      'abono': abono,
      // Costo de repuestos: lo enviamos también como columna por si
      // el backend la tiene/agrega en el futuro. La fuente de verdad
      // sigue siendo el bloque META (ver arriba).
      'costo_repuestos': costoRepuestos,
      'pagado': pagado ? 1 : 0,

      // ── Fecha base ──
      'fecha': fecha.toIso8601String(),

      // ── Cliente: nombre y teléfono se guardan normalmente en sus columnas.
      //    La cédula/RIF va empaquetada en META. Enviamos igual las variantes
      //    por si el backend sí las acepta en columnas reales.
      'nombre_cliente': nombreCliente,
      'nombreCliente' : nombreCliente,
      'cliente'       : nombreCliente,
      'nombre'        : nombreCliente,
      'telefono'      : telefono,
      // Enviamos también RIF sueltos por si hay columna; el dato "de verdad"
      // viaja en META, así que no depende de esto.
      'rif_ci': rifCi,
      'rifCi' : rifCi,
      'cedula': rifCi,

      // ── Equipo: descripción lleva META + texto real ──
      'descripcion': descPersistida,
      'nota'       : descPersistida,  // alias para APIs viejas
      'imei'       : imei,

      // También enviamos marca/modelo/hora/entrega/contrasena sueltos por
      // si el backend SÍ los acepta en columnas reales; si no, al menos
      // quedan en META dentro de `descripcion`.
      'marca'        : marca,
      'modelo'       : modelo,
      'hora_recibido': horaRecibido,
      'fecha_entrega': fechaEntrega,
      'contrasena'   : contrasena,

      // ── Checklist: también enviamos las columnas sueltas como fallback ──
      'chip': _bi(chip),
      'memoria': _bi(memoria),
      'bateria': _bi(bateria),
      'tapa': _bi(tapa),
      'encendido': _bi(encendido),
      'apagado': _bi(apagado),
      'camara': _bi(camara),
      'corneta': _bi(corneta),
      'flash': _bi(flash),
      'flash_con_defecto': _bi(flashConDefecto),
      'tactil_partido': _bi(tactilPartido),
      'auricular': _bi(auricular),
      'microfono': _bi(microfono),
      'contrasena_chk': _bi(contrasenaChk),
      'track': _bi(track),
      'boton_volumen': _bi(botonVolumen),
      'teclado': _bi(teclado),
      'boton_encendido': _bi(botonEncendido),
      'pantalla_con_defecto': _bi(pantallaConDefecto),

      // ── Notas finales ──
      'observacion': observacion,
      'tecnico': tecnico,
      'estado': estado,
    };
  }
}

// ── FACTURA ───────────────────────────────────────────────────
class PagoFactura {
  final String metodo, tipo;
  /// FINANCIADOR = la persona/usuario que entrega el equipo al cliente.
  /// Es un nombre de usuario del sistema. Puede ser null si no aplica.
  final String? financiador;
  /// FINANCIADORA = la aplicación con la que el cliente se lleva el
  /// equipo (Cashea / Weppa / Krece). Viene del dropdown F/D.
  /// El Reporte por Financiadora se agrupa por ESTE campo.
  final String? financiadora;
  final double monto;

  // ── Datos extra para Pago Móvil (todos opcionales) ────────────
  // Se llenan SOLO cuando el método es "Pago Móvil". Para los demás
  // métodos quedan en null y el backend los ignora.
  /// Código SUDEBAN (4 dígitos) del banco DESTINO del pago móvil
  /// — la cuenta del comercio donde llega el dinero. Sólo aplica a
  /// Pago Móvil. "0102" = Banco de Venezuela (único que admite
  /// conciliación API).
  final String? bancoDestino;
  /// Código SUDEBAN del banco ORIGEN (de donde sale el dinero).
  final String? bancoOrigen;
  /// Referencia del pago móvil (la que aparece en el SMS / App).
  final String? referencia;
  /// Cédula del pagador con letra ("V12345678" / "E12345678" / "J...").
  final String? cedulaPagador;
  /// Teléfono celular asociado al pago.
  final String? telefonoPagador;
  /// Teléfono celular destino registrado en PagomóvilBDV.
  final String? telefonoDestino;
  /// Fecha del pago en formato "YYYY-MM-DD".
  final String? fechaPago;

  /// true si el vendedor marcó este pago como la INICIAL que el
  /// cliente paga de su bolsillo. El reporte por financiadora usa
  /// este flag para saber exactamente qué monto restar como inicial
  /// en la fórmula (Base − Inicial) − 3.5% = Deuda. Si ningún pago
  /// está marcado, el reporte cae al criterio anterior (pagos de
  /// tipo "Contado" o sin financiador).
  final bool esInicial;

  // ── Resultado de la conciliación con BDV ──────────────────────
  /// true si la conciliación con BDV devolvió code 1000 (transacción
  /// localizada). false si devolvió otro código o falló la red. null
  /// si nunca se intentó conciliar (por ejemplo banco distinto a BDV
  /// o conciliación deshabilitada en el panel admin).
  final bool? conciliadoBDV;
  /// Código de respuesta del API BDV (1000 OK, 1010 no existe, etc).
  final int? codigoConciliacion;
  /// Mensaje completo devuelto por el API BDV (para auditoría).
  final String? mensajeConciliacion;

  PagoFactura({
    required this.metodo,
    required this.monto,
    required this.tipo,
    this.financiador,
    this.financiadora,
    this.bancoDestino,
    this.bancoOrigen,
    this.referencia,
    this.cedulaPagador,
    this.telefonoPagador,
    this.telefonoDestino,
    this.fechaPago,
    this.esInicial = false,
    this.conciliadoBDV,
    this.codigoConciliacion,
    this.mensajeConciliacion,
  });

  factory PagoFactura.fromMap(Map<String,dynamic> m) => PagoFactura(
    metodo: m['metodo']??'', tipo: m['tipo']??'',
    financiador: m['financiador'],
    financiadora: m['financiadora'] as String?,
    monto: double.tryParse(m['monto'].toString())??0,
    bancoDestino       : m['banco_destino']        as String?,
    bancoOrigen        : m['banco_origen']         as String?,
    referencia         : m['referencia']           as String?,
    cedulaPagador      : m['cedula_pagador']       as String?,
    telefonoPagador    : m['telefono_pagador']     as String?,
    telefonoDestino    : m['telefono_destino']     as String?,
    fechaPago          : m['fecha_pago']           as String?,
    esInicial          : m['es_inicial'] == true || m['es_inicial'] == 1
        || m['es_inicial'].toString() == '1'
        || m['es_inicial'].toString().toLowerCase() == 'true',
    conciliadoBDV      : m['conciliado_bdv'] == null
        ? null
        : (m['conciliado_bdv'] == true || m['conciliado_bdv'] == 1
            || m['conciliado_bdv'].toString() == '1'
            || m['conciliado_bdv'].toString().toLowerCase() == 'true'),
    codigoConciliacion : m['codigo_conciliacion'] == null
        ? null
        : int.tryParse(m['codigo_conciliacion'].toString()),
    mensajeConciliacion: m['mensaje_conciliacion'] as String?,
  );

  Map<String,dynamic> toMap() => {
    'metodo':metodo,'tipo':tipo,'financiador':financiador,'monto':monto,
    'financiadora': financiadora,
    'es_inicial': esInicial,
    // Sólo se incluyen los campos extra si el método es Pago Móvil
    // (evita ensuciar el JSON de los pagos en efectivo, transferencia, etc).
    if (bancoDestino        != null) 'banco_destino'        : bancoDestino,
    if (bancoOrigen         != null) 'banco_origen'         : bancoOrigen,
    if (referencia          != null) 'referencia'           : referencia,
    if (cedulaPagador       != null) 'cedula_pagador'       : cedulaPagador,
    if (telefonoPagador     != null) 'telefono_pagador'     : telefonoPagador,
    if (telefonoDestino     != null) 'telefono_destino'     : telefonoDestino,
    if (fechaPago           != null) 'fecha_pago'           : fechaPago,
    if (conciliadoBDV       != null) 'conciliado_bdv'       : conciliadoBDV,
    if (codigoConciliacion  != null) 'codigo_conciliacion'  : codigoConciliacion,
    if (mensajeConciliacion != null) 'mensaje_conciliacion' : mensajeConciliacion,
  };
}

class FacturaModel {
  int? id;
  final String cliente, cedula, telefono, nroFactura, vendedor, fecha, tienda;
  final List<ImeiRegistro> equipos;
  final List<Producto> itemsSinImei;
  final List<PagoFactura> pagos;

  FacturaModel({this.id, required this.cliente, required this.cedula,
      required this.tienda, required this.telefono, required this.nroFactura,
      required this.equipos, required this.itemsSinImei, required this.pagos,
      required this.vendedor, required this.fecha});

  double get total => pagos.fold(0.0,(s,p) => s + p.monto);

  Map<String,dynamic> toApiMap() => {
    'nro_factura':nroFactura,'cedula':cedula,'cliente':cliente,'telefono':telefono,
    'vendedor':vendedor,'tienda':tienda,'fecha':fecha,'total':total,
    'equipos':equipos.map((e) => e.imei).toList(),
    'items':itemsSinImei.map((p) => p.codigo).toList(),
    'pagos':pagos.map((p) => p.toMap()).toList()};
}

/// Parser de fecha flexible que acepta:
///   · "dd/MM/yyyy"           (formato local, como guarda la app)
///   · "dd-MM-yyyy"
///   · "yyyy-MM-dd"           (ISO, como puede venir del backend)
///   · "yyyy-MM-dd HH:mm:ss"  (DATETIME MySQL)
///   · "yyyy-MM-ddTHH:mm:ss"  (ISO completo)
/// Devuelve null si no puede parsearla.
DateTime? parseFechaFlexible(String? texto) {
  if (texto == null) return null;
  final s = texto.trim();
  if (s.isEmpty) return null;

  // Intento 1: ISO directo
  final iso = DateTime.tryParse(s);
  if (iso != null) return iso;

  // Intento 2: dd/MM/yyyy o dd-MM-yyyy (con separador / o -)
  final m = RegExp(r'^(\d{1,2})[/\-](\d{1,2})[/\-](\d{4})(?:\s+(\d{1,2}):(\d{2})(?::(\d{2}))?)?$').firstMatch(s);
  if (m != null) {
    final d  = int.tryParse(m.group(1) ?? '') ?? 1;
    final mo = int.tryParse(m.group(2) ?? '') ?? 1;
    final y  = int.tryParse(m.group(3) ?? '') ?? 1970;
    final h  = int.tryParse(m.group(4) ?? '0') ?? 0;
    final mi = int.tryParse(m.group(5) ?? '0') ?? 0;
    final se = int.tryParse(m.group(6) ?? '0') ?? 0;
    return DateTime(y, mo, d, h, mi, se);
  }
  return null;
}

// ── EXTRACCIÓN ────────────────────────────────────────────────
class Extraccion {
  int? id;
  final String metodo, monto, motivo, fecha;
  Extraccion({this.id, required this.metodo, required this.monto, required this.motivo, required this.fecha});
  factory Extraccion.fromMap(Map<String,dynamic> m) => Extraccion(
    id: m['id'], metodo: m['metodo']??'', monto: m['monto']??'',
    motivo: m['motivo']??'', fecha: m['fecha']??'');
  Map<String,dynamic> toMap() => {'metodo':metodo,'monto':monto,'motivo':motivo,'fecha':fecha};
}

// ── CIERRE DE CAJA ────────────────────────────────────────────
class CierreCaja {
  final int? idDb;
  final String id, tienda, usuarioCierre;
  final DateTime fecha;
  final double montoTotal;
  final Map<String,double> metodosPago;

  CierreCaja({this.idDb, required this.id, required this.fecha, required this.tienda,
      required this.montoTotal, required this.usuarioCierre, required this.metodosPago});

  factory CierreCaja.fromMap(Map<String,dynamic> m) {
    final mets = <String,double>{};
    for (final met in (m['metodos'] as List? ?? [])) {
      mets[met['metodo']] = double.tryParse(met['monto'].toString())??0;
    }
    return CierreCaja(idDb: m['id'], id: m['uid']??'', tienda: m['tienda']??'',
      usuarioCierre: m['usuario_cierre']??'',
      fecha: DateTime.tryParse(m['fecha']??'')??DateTime.now(),
      montoTotal: double.tryParse(m['monto_total'].toString())??0, metodosPago: mets);
  }
  Map<String,dynamic> toApiMap() => {'uid':id,'tienda':tienda,'monto_total':montoTotal,
    'usuario_cierre':usuarioCierre,
    'metodos':metodosPago.entries.map((e) => {'metodo':e.key,'monto':e.value}).toList()};
}

// ── COMISIONES ────────────────────────────────────────────────
//
// El sistema de comisiones se basa en CATEGORÍAS DINÁMICAS:
// el administrador puede agregar/editar/eliminar categorías
// (ej: Accesorio, Teléfono, Servicio Técnico, etc.) desde el
// panel de configuración.
//
// Cada categoría tiene un "tipo de conteo" que determina cómo
// se cuenta: por categoría de producto vendido, por servicios
// técnicos pagados, por venta financiada con cierto financiador,
// o por porcentaje sobre ventas Weppa.
//
// Las 6 categorías originales (Accesorio, Teléfono, Línea,
// Televisor, Línea Blanca, Financiador) están "protegidas" — no
// se pueden eliminar, pero sí editar tarifa. Las nuevas que
// agregue el usuario son borrables.

/// Tipo de conteo de una categoría de comisión: define qué se cuenta
/// como "una unidad" para multiplicarla por la tarifa USD.
enum TipoConteoComision {
  /// Cuenta cada equipo/item vendido cuya categoría coincida con
  /// `valorConteo` (ej: "Accesorio", "Telefono", "Televisor",
  /// "Linea Blanca", "Servicio Tecnico"...).
  categoriaProducto,
  /// Cuenta cada activación de línea telefónica de la venta
  /// (independiente de la categoría del producto).
  lineaTelefonica,
  /// Cuenta cada venta financiada cuyo `financiador` se asigne a
  /// este vendedor — típicamente aplica al "vendedor financiador".
  ventaFinanciada,
  /// Cuenta cada servicio técnico ENTREGADO/PAGADO en el rango,
  /// atribuyéndolo al técnico de la ficha. La tarifa USD se aplica
  /// como una cantidad fija por servicio (igual que un producto).
  servicioTecnico,
  /// No usa tarifa fija: aplica un % sobre el precio de venta de
  /// cada producto vendido en una factura financiada con Weppa.
  /// El % se toma de la lista Weppa, no del campo `tarifaUSD`.
  porcentajeWeppa,
}

extension TipoConteoComisionX on TipoConteoComision {
  String get clave => toString().split('.').last;
  static TipoConteoComision desdeString(String s) {
    return TipoConteoComision.values.firstWhere(
      (t) => t.clave == s,
      orElse: () => TipoConteoComision.categoriaProducto);
  }
  String get descripcion {
    switch (this) {
      case TipoConteoComision.categoriaProducto:
        return 'Por cada producto vendido de cierta categoría';
      case TipoConteoComision.lineaTelefonica:
        return 'Por cada línea telefónica activada';
      case TipoConteoComision.ventaFinanciada:
        return 'Por cada venta financiada gestionada';
      case TipoConteoComision.servicioTecnico:
        return 'Por cada servicio técnico pagado/entregado';
      case TipoConteoComision.porcentajeWeppa:
        return 'Porcentaje sobre ventas Weppa (no usa tarifa fija)';
    }
  }
}

/// Modelo de una categoría de comisión configurable.
// ════════════════════════════════════════════════════════════
//  CATEGORÍAS DE PRODUCTOS (editables y persistidas)
// ════════════════════════════════════════════════════════════
//  Lista global y editable de categorías que se usan al crear
//  productos. De aquí también nacen las categorías de comisión:
//  cuando se agrega una categoría nueva acá, automáticamente se
//  crea (si no existía) una entrada equivalente en `categoriasGlobal`
//  de comisiones, lista para que el admin le configure la tarifa.
class CategoriasProductos {
  /// Lista en memoria. Por defecto trae las 6 originales del sistema.
  static List<String> lista = [
    'Telefono', 'Accesorio', 'Televisor', 'Linea Blanca',
    'Linea', 'Servicio Tecnico',
  ];

  static const String _prefsKey = 'categorias_productos_v1';

  /// Carga la lista desde SharedPreferences (al iniciar la app).
  static Future<void> cargar() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final json = prefs.getString(_prefsKey);
      if (json != null && json.isNotEmpty) {
        final dec = jsonDecode(json) as List;
        lista = dec.map((e) => e.toString()).toList();
      }
    } catch (e) {
      debugPrint('[CategoriasProductos] cargar error: $e');
    }
  }

  /// Persiste la lista actual.
  static Future<void> guardar() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString(_prefsKey, jsonEncode(lista));
    } catch (e) {
      debugPrint('[CategoriasProductos] guardar error: $e');
    }
  }

  /// Agrega una categoría nueva (si no existe). Devuelve true si se
  /// agregó. La comparación es case-insensitive trimeada.
  static Future<bool> agregar(String nombre) async {
    final n = nombre.trim();
    if (n.isEmpty) return false;
    final existe = lista.any((c) => c.toLowerCase() == n.toLowerCase());
    if (existe) return false;
    lista.add(n);
    await guardar();
    return true;
  }

  /// Renombra una categoría existente.
  static Future<bool> renombrar(String viejo, String nuevo) async {
    final n = nuevo.trim();
    if (n.isEmpty) return false;
    final idx = lista.indexWhere((c) => c == viejo);
    if (idx < 0) return false;
    lista[idx] = n;
    await guardar();
    return true;
  }

  /// Elimina una categoría. Devuelve true si se eliminó.
  static Future<bool> eliminar(String nombre) async {
    final n0 = lista.length;
    lista.removeWhere((c) => c == nombre);
    if (lista.length == n0) return false;
    await guardar();
    return true;
  }
}


class CategoriaComision {
  /// Identificador único e inmutable. Para las 6 originales son
  /// strings fijos ("accesorio", "telefono"...) — se usa como clave
  /// en `ResumenComision.conteos`. Para nuevas, se genera con timestamp.
  final String id;
  /// Nombre visible al usuario ("Accesorio", "Servicio Técnico"...).
  String nombre;
  /// Tarifa en USD por cada unidad contada.
  double tarifaUSD;
  /// Tipo de conteo: define cómo se cuentan las unidades.
  TipoConteoComision tipoConteo;
  /// Valor auxiliar del tipo de conteo. Para `categoriaProducto`
  /// es la categoría a buscar (ej: "Accesorio", "Televisor"). Para
  /// `ventaFinanciada` es el nombre del financiador a filtrar
  /// (vacío = cualquier financiador).
  String valorConteo;
  /// Clave de ícono — debe ser una de las claves de
  /// `CategoriaComision.iconosDisponibles`. Se persiste como string
  /// (no como codePoint dinámico) para preservar el tree-shaking de
  /// iconos en builds de release. Los IconData del mapa SON
  /// constantes en tiempo de compilación, así que el compilador
  /// puede saber exactamente qué iconos se usan.
  String iconoKey;
  /// Color hex (ej: "#FF0000") para mostrar en la tabla.
  String colorHex;
  /// Si es true, no se puede eliminar (las 6 originales).
  final bool protegida;

  CategoriaComision({
    required this.id,
    required this.nombre,
    required this.tarifaUSD,
    required this.tipoConteo,
    this.valorConteo = '',
    this.iconoKey = 'work',
    this.colorHex = '#1565C0',
    this.protegida = false,
  });

  /// Mapa de iconos disponibles. CADA IconData es una constante
  /// (`Icons.foo` es `const`), por lo que el compilador puede hacer
  /// tree-shaking. Esta lista define TODOS los iconos que las
  /// categorías de comisión pueden usar — si necesitas más, hay que
  /// agregarlos aquí (no se pueden cargar dinámicamente).
  static const Map<String, IconData> iconosDisponibles = {
    'work':           Icons.work_outline,
    'extension':      Icons.extension_outlined,
    'phone_android':  Icons.phone_android_outlined,
    'sim_card':       Icons.sim_card_outlined,
    'tv':             Icons.tv_outlined,
    'kitchen':        Icons.kitchen_outlined,
    'account_balance': Icons.account_balance_outlined,
    'build':          Icons.build_outlined,
    'handyman':       Icons.handyman_outlined,
    'support_agent':  Icons.support_agent_outlined,
    'store':          Icons.store_outlined,
    'local_shipping': Icons.local_shipping_outlined,
    'headset_mic':    Icons.headset_mic_outlined,
    'shield':         Icons.shield_outlined,
    'savings':        Icons.savings_outlined,
    'card_giftcard':  Icons.card_giftcard_outlined,
    'computer':       Icons.computer_outlined,
    'tablet_mac':     Icons.tablet_mac_outlined,
    'watch':          Icons.watch_outlined,
    'devices':        Icons.devices_outlined,
  };

  /// Devuelve el IconData asociado a `iconoKey`, o un fallback si la
  /// clave no existe en el mapa (por ejemplo, datos viejos que tenían
  /// un codePoint pero ahora migran a clave).
  IconData get icono =>
      iconosDisponibles[iconoKey] ?? Icons.work_outline;

  Color get color {
    final h = colorHex.replaceAll('#', '');
    return Color(int.parse('FF$h', radix: 16));
  }

  Map<String, dynamic> toMap() => {
        'id': id,
        'nombre': nombre,
        'tarifa_usd': tarifaUSD,
        'tipo_conteo': tipoConteo.clave,
        'valor_conteo': valorConteo,
        'icono_key': iconoKey,
        'color_hex': colorHex,
        'protegida': protegida,
      };

  factory CategoriaComision.fromMap(Map<String, dynamic> m) {
    // RETROCOMPATIBILIDAD: si el dato guardado tiene `icono_code_point`
    // (versión vieja del modelo, antes del refactor a iconoKey),
    // intentamos mapear ese codePoint a una clave conocida. Si no
    // se encuentra, usamos el icono por defecto.
    String iconoKey = m['icono_key']?.toString() ?? '';
    if (iconoKey.isEmpty) {
      final cp = int.tryParse(m['icono_code_point']?.toString() ?? '');
      if (cp != null) {
        // Buscar la clave cuyo IconData tenga este codePoint
        iconoKey = iconosDisponibles.entries
                .firstWhere(
                  (e) => e.value.codePoint == cp,
                  orElse: () => const MapEntry('work', Icons.work_outline),
                )
                .key;
      } else {
        iconoKey = 'work';
      }
    }
    return CategoriaComision(
      id: m['id']?.toString() ?? '',
      nombre: m['nombre']?.toString() ?? '',
      tarifaUSD: double.tryParse(m['tarifa_usd'].toString()) ?? 0,
      tipoConteo: TipoConteoComisionX.desdeString(
          m['tipo_conteo']?.toString() ?? 'categoriaProducto'),
      valorConteo: m['valor_conteo']?.toString() ?? '',
      iconoKey: iconoKey,
      colorHex: m['color_hex']?.toString() ?? '#1565C0',
      protegida: m['protegida'] == true || m['protegida'] == 1
          || m['protegida'].toString() == '1'
          || m['protegida'].toString().toLowerCase() == 'true',
    );
  }

  /// Devuelve la lista predeterminada con las 6 categorías originales.
  /// Estas son las que existían antes del refactor — se mantienen como
  /// "protegidas" para no romper los datos guardados ni la lógica.
  static List<CategoriaComision> defaults() => [
        CategoriaComision(
          id: 'accesorio',
          nombre: 'Accesorio',
          tarifaUSD: 0.50,
          tipoConteo: TipoConteoComision.categoriaProducto,
          valorConteo: 'Accesorio',
          iconoKey: 'extension',
          colorHex: '#009688',
          protegida: true,
        ),
        CategoriaComision(
          id: 'telefono',
          nombre: 'Teléfono',
          tarifaUSD: 1.00,
          tipoConteo: TipoConteoComision.categoriaProducto,
          valorConteo: 'Telefono',
          iconoKey: 'phone_android',
          colorHex: '#1565C0',
          protegida: true,
        ),
        CategoriaComision(
          id: 'linea',
          nombre: 'Línea',
          tarifaUSD: 0.50,
          tipoConteo: TipoConteoComision.lineaTelefonica,
          iconoKey: 'sim_card',
          colorHex: '#7B1FA2',
          protegida: true,
        ),
        CategoriaComision(
          id: 'televisor',
          nombre: 'Televisor',
          tarifaUSD: 2.00,
