class ResumenComision {
  String vendedor;
  /// Conteos por categoría: clave = `CategoriaComision.id`,
  /// valor = cantidad de unidades contadas para esa categoría.
  /// Reemplaza los antiguos campos individuales (accesorios,
  /// telefonos, etc) — el sistema ahora es completamente dinámico.
  final Map<String, int> conteos = {};
  /// Snapshot de tarifas USD por categoría usadas al momento de
  /// generar este resumen. Permite que un historial conserve los
  /// montos correctos aunque el admin cambie las tarifas después.
  final Map<String, double> tarifasUsadas = {};
  /// Snapshot de los nombres de categoría al momento de generar
  /// (para mostrar columnas con el nombre correcto en histórico).
  final Map<String, String> nombresCategorias = {};
  double base = 40, domingo = 0, descuentoBs = 0;
  /// Comisión adicional por financiamiento Weppa: % sobre el precio
  /// de venta de los productos financiados con Weppa.
  double comisionWeppa = 0;

  ResumenComision({required this.vendedor}) {
    base = ConfigSistema.comisionBaseDefault;
  }

  /// Total de comisión en USD: suma de (conteo × tarifa) por cada
  /// categoría, más la comisión Weppa acumulada.
  double get totalComision {
    double total = 0;
    for (final entry in conteos.entries) {
      final tarifa = tarifasUsadas[entry.key] ?? 0;
      total += entry.value * tarifa;
    }
    return total + comisionWeppa;
  }

  /// Total a pagar al vendedor en USD (comisión + base + domingo).
  double totalPagar() => totalComision + base + domingo;

  /// Total a pagar convertido a Bolívares: usa la tasa proporcionada
  /// (BCV o manual según la pantalla de comisiones) y resta el
  /// descuento que el admin haya capturado en Bs.
  double totalBs(double tasa) => (totalPagar() * tasa) - descuentoBs;

  /// Helper: lee el conteo de una categoría específica (0 si no existe).
  int conteoDe(String idCategoria) => conteos[idCategoria] ?? 0;

  Map<String, dynamic> toMap() => {
        'vendedor': vendedor,
        'conteos': conteos,
        'tarifas_usadas': tarifasUsadas,
        'nombres_categorias': nombresCategorias,
        'base': base,
        'domingo': domingo,
        'descuento_bs': descuentoBs,
        'comision_weppa': comisionWeppa,
        // ── RETROCOMPATIBILIDAD ──
        // Mantenemos los campos antiguos en el JSON para que cualquier
        // backend o reporte que los lea siga funcionando. Se computan
        // desde `conteos` usando los IDs originales.
        'accesorios': conteos['accesorio'] ?? 0,
        'telefonos': conteos['telefono'] ?? 0,
        'lineas': conteos['linea'] ?? 0,
        'televisores': conteos['televisor'] ?? 0,
        'linea_blanca': conteos['linea_blanca'] ?? 0,
        'financiador': conteos['financiador'] ?? 0,
      };

  factory ResumenComision.fromMap(Map<String, dynamic> m) {
    final r = ResumenComision(vendedor: m['vendedor'] ?? '');
    // Si el JSON tiene la estructura nueva (`conteos`), la usamos.
    if (m['conteos'] is Map) {
      (m['conteos'] as Map).forEach((k, v) {
        r.conteos[k.toString()] =
            int.tryParse(v.toString()) ?? 0;
      });
    } else {
      // RETROCOMPATIBILIDAD: histórico guardado con campos antiguos.
      r.conteos['accesorio']    = int.tryParse(m['accesorios'].toString())   ?? 0;
      r.conteos['telefono']     = int.tryParse(m['telefonos'].toString())    ?? 0;
      r.conteos['linea']        = int.tryParse(m['lineas'].toString())       ?? 0;
      r.conteos['televisor']    = int.tryParse(m['televisores'].toString())  ?? 0;
      r.conteos['linea_blanca'] = int.tryParse(m['linea_blanca'].toString()) ?? 0;
      r.conteos['financiador']  = int.tryParse(m['financiador'].toString())  ?? 0;
    }
    if (m['tarifas_usadas'] is Map) {
      (m['tarifas_usadas'] as Map).forEach((k, v) {
        r.tarifasUsadas[k.toString()] =
            double.tryParse(v.toString()) ?? 0;
      });
    } else {
      // Para histórico viejo, usar tarifas actuales (mejor que nada).
      for (final c in ConfigSistema.categoriasComision) {
        r.tarifasUsadas[c.id] = c.tarifaUSD;
      }
    }
    if (m['nombres_categorias'] is Map) {
      (m['nombres_categorias'] as Map).forEach((k, v) {
        r.nombresCategorias[k.toString()] = v.toString();
      });
    }
    r.base = double.tryParse(m['base'].toString()) ?? ConfigSistema.comisionBaseDefault;
    r.domingo = double.tryParse(m['domingo'].toString()) ?? 0;
    r.descuentoBs = double.tryParse(m['descuento_bs'].toString()) ?? 0;
    r.comisionWeppa = double.tryParse((m['comision_weppa'] ?? 0).toString()) ?? 0;
    return r;
  }
}

class HistorialComision {
  int? id;
  final DateTime fechaInicio, fechaFin;
  final double tasa;
  final List<ResumenComision> data;
  HistorialComision({this.id, required this.fechaInicio, required this.fechaFin,
      required this.tasa, required this.data});
  factory HistorialComision.fromMap(Map<String,dynamic> m) => HistorialComision(
    id: m['id'],
    fechaInicio: DateTime.tryParse(m['fecha_inicio']??'')??DateTime.now(),
    fechaFin: DateTime.tryParse(m['fecha_fin']??'')??DateTime.now(),
    tasa: double.tryParse(m['tasa'].toString())??1,
    data: List<Map<String,dynamic>>.from(m['detalle']??[])
        .map((d) => ResumenComision.fromMap(d)).toList());
}

// ── LISTAS DE PRECIOS ─────────────────────────────────────────
class ColumnaPrecio { String nombre; ColumnaPrecio({required this.nombre}); }

class ItemListaPrecio {
  final Producto producto;
  Map<String,double> preciosPorColumna;
  int stockDisponible;
  ItemListaPrecio({required this.producto, required this.preciosPorColumna, this.stockDisponible = 0});
}

class ListaPrecio {
  int? id;
  String nombre, fechaCreacion;
  String categoria;
  String marcaFiltro;
  List<ColumnaPrecio> columnas;
  List<ItemListaPrecio> items;
  bool esEnBolivares;
  double tasaDelDia;
  // ── Nuevos campos ──────────────────────────────────────────
  double porcentajeAdicional; // % que se suma al precio venta
  bool esFinanciamiento;
  String? financiadora;
  double porcentajeInicial;   // % para calcular la inicial
  int numeroCuotas;
  // ── % de comisión Weppa ─────────────────────────────────────
  // Solo aplica cuando la financiadora es Weppa. Se utiliza para
  // calcular comisiones del vendedor en base al precio de venta
  // del producto vendido con financiamiento Weppa.
  double porcentajeComisionWeppa;
  // ── % de recargo sobre el total a financiar ────────────────
  // Se aplica al monto total de cuotas antes de dividir entre el
  // número de cuotas. Ej: resto=$60, recargo=20%, cuotas=6
  //   → total a financiar = 60 × 1.20 = 72 → cuota = 72/6 = $12
  double porcentajeRecargoCuotas;

  ListaPrecio({
    this.id,
    required this.nombre,
    required this.fechaCreacion,
    this.categoria = "Todos",
    this.marcaFiltro = "Todas",
    List<ColumnaPrecio>? columnas,
    List<ItemListaPrecio>? items,
    this.esEnBolivares = false,
    this.tasaDelDia = 1.0,
    this.porcentajeAdicional = 0.0,
    this.esFinanciamiento = false,
    this.financiadora,
    this.porcentajeInicial = 0.0,
    this.numeroCuotas = 12,
    this.porcentajeComisionWeppa = 0.0,
    this.porcentajeRecargoCuotas = 0.0,
  }) : columnas = columnas ?? [], items = items ?? [];

  Map<String, dynamic> toMap() => {
    if (id != null) 'id': id,
    'nombre': nombre,
    'fecha_creacion': fechaCreacion,
    'categoria': categoria,
    'marca_filtro': marcaFiltro,
    'es_en_bolivares': esEnBolivares ? 1 : 0,
    'tasa_del_dia': tasaDelDia,
    'porcentaje_adicional': porcentajeAdicional,
    'es_financiamiento': esFinanciamiento ? 1 : 0,
    'financiadora': financiadora,
    'porcentaje_inicial': porcentajeInicial,
    'numero_cuotas': numeroCuotas,
    'porcentaje_comision_weppa': porcentajeComisionWeppa,
    'porcentaje_recargo_cuotas': porcentajeRecargoCuotas,
    // Las columnas e items van en arrays nested que `guardarListaPrecios`
    // del backend procesa como tablas relacionales separadas.
    'columnas': columnas.map((c) => {
      'nombre': c.nombre,
    }).toList(),
    'items': items.map((it) => {
      'producto_codigo': it.producto.codigo,
      'stock_disponible': it.stockDisponible,
      // e.key es el nombre de la columna (String), e.value el precio (double)
      'valores': it.preciosPorColumna.entries.map((e) => {
        'columna_nombre': e.key,
        'precio': e.value,
      }).toList(),
    }).toList(),
  };

  factory ListaPrecio.fromMap(Map<String, dynamic> m) {
    int? toInt(dynamic v) {
      if (v == null) return null;
      if (v is int) return v;
      return int.tryParse(v.toString());
    }
    double toDouble(dynamic v) {
      if (v == null) return 0;
      if (v is double) return v;
      if (v is int) return v.toDouble();
      return double.tryParse(v.toString()) ?? 0;
    }
    bool toBool(dynamic v) =>
        v == 1 || v == '1' || v == true;

    // Reconstruir columnas
    final cols = <ColumnaPrecio>[];
    if (m['columnas'] is List) {
      for (final c in (m['columnas'] as List)) {
        cols.add(ColumnaPrecio(nombre: '${c['nombre'] ?? ''}'));
      }
    }
    if (cols.isEmpty) cols.add(ColumnaPrecio(nombre: 'Precio'));

    // Reconstruir items (necesitamos el catálogo global para encontrar
    // el Producto correspondiente al código)
    final items = <ItemListaPrecio>[];
    if (m['items'] is List) {
      for (final it in (m['items'] as List)) {
        final codigo = '${it['producto_codigo'] ?? ''}';
        final prod = catalogoGlobal
            .where((p) => p.codigo == codigo)
            .firstOrNull;
        if (prod == null) continue; // producto no existe ya
        // El mapa usa el NOMBRE de la columna como clave, no el objeto.
        final precios = <String, double>{};
        if (it['valores'] is List) {
          for (final v in (it['valores'] as List)) {
            final colNombre = '${v['columna_nombre'] ?? ''}';
            if (colNombre.isEmpty) continue;
            precios[colNombre] = toDouble(v['precio']);
          }
        }
        items.add(ItemListaPrecio(
          producto: prod,
          preciosPorColumna: precios,
          stockDisponible: toInt(it['stock_disponible']) ?? 0,
        ));
      }
    }

    return ListaPrecio(
      id: toInt(m['id']),
      nombre: '${m['nombre'] ?? ''}',
      fechaCreacion: '${m['fecha_creacion'] ?? ''}',
      categoria: '${m['categoria'] ?? 'Todos'}',
      marcaFiltro: '${m['marca_filtro'] ?? 'Todas'}',
      esEnBolivares: toBool(m['es_en_bolivares']),
      tasaDelDia: toDouble(m['tasa_del_dia']),
      porcentajeAdicional: toDouble(m['porcentaje_adicional']),
      esFinanciamiento: toBool(m['es_financiamiento']),
      financiadora: m['financiadora']?.toString(),
      porcentajeInicial: toDouble(m['porcentaje_inicial']),
      numeroCuotas: toInt(m['numero_cuotas']) ?? 12,
      porcentajeComisionWeppa: toDouble(m['porcentaje_comision_weppa']),
      porcentajeRecargoCuotas: toDouble(m['porcentaje_recargo_cuotas']),
      columnas: cols,
      items: items,
    );
  }
}

