// ────────────────────────────────────────────────────────────
//  HELPERS DE PERMISOS POR TIENDA
//  Administrador, Dueño y Gerente pueden ver todas las tiendas.
//  El resto sólo ve la tienda que tiene asignada.
// ────────────────────────────────────────────────────────────
bool puedeVerTodasLasTiendas() {
  final rol = usuarioSesion?.rol;
  return rol == 'Administrador' || rol == 'Dueño' || rol == 'Gerente';
}

/// Devuelve la tienda asignada al usuario actual. Vacío = sin restricción
/// (normalmente sólo para roles altos que no tienen tienda configurada).
String tiendaUsuarioActual() => usuarioSesion?.tienda ?? '';

/// Filtra una lista de registros (mapas) dejando sólo los que pertenecen
/// a la tienda que el usuario puede ver. Si `puedeVerTodasLasTiendas()` es
/// true, respeta `tiendaFiltro` (null/"Todas" = no filtra).
List<Map<String, dynamic>> filtrarPorTienda(
    List<Map<String, dynamic>> registros, {String? tiendaFiltro}) {
  if (puedeVerTodasLasTiendas()) {
    if (tiendaFiltro == null || tiendaFiltro.isEmpty || tiendaFiltro == 'Todas') {
      return registros;
    }
    return registros.where((r) =>
        (r['tienda'] ?? '').toString() == tiendaFiltro).toList();
  }
  final miTienda = tiendaUsuarioActual();
  if (miTienda.isEmpty) return registros; // sin tienda asignada: no filtra
  return registros.where((r) =>
      (r['tienda'] ?? '').toString() == miTienda).toList();
}

// ── Buscar producto por código (versión async que consulta la API) ──
Future<Producto?> buscarProductoPorCodigoAsync(String codigo) async {
  try {
    final raw = await _Api.get('productos', {'codigo': codigo});
    if (raw != null) return Producto.fromMap(raw);
  } catch (e) { debugPrint('buscarProducto por código: $e'); }
  try {
    final imeiRaw = await _Api.get('stock_imei', {'imei': codigo});
    if (imeiRaw != null && imeiRaw['vendido'] == 0) {
      final prodRaw = await _Api.get('productos', {'codigo': imeiRaw['producto_codigo']});
      if (prodRaw != null) return Producto.fromMap(prodRaw);
    }
  } catch (e) { debugPrint('buscarProducto por IMEI: $e'); }
  return null;
}

// Versión síncrona que usa las listas en memoria
Producto? buscarProductoPorCodigo(String codigo) {
  // firstWhere lanza StateError si no encuentra — usamos orElse para evitarlo
  final porCodigo = catalogoGlobal.where((p) => p.codigo == codigo).firstOrNull;
  if (porCodigo != null) return porCodigo;
  final imei = stockImeiGlobal.where((i) => i.imei == codigo && !i.vendido).firstOrNull;
  if (imei != null) {
    return catalogoGlobal.where((p) => p.codigo == imei.producto.codigo).firstOrNull;
  }
  return null;
}

// ── CONTRATO WEPPA ────────────────────────────────────────────
//  Modelo para los contratos de venta a cuotas de Weppa Group.
//  Cada contrato queda guardado en el historial (tabla
//  `contratos_weppa` del backend) y se envía por correo al cliente.
// ============================================================
class CuotaContrato {
  int numero;
  DateTime fecha;
  double monto;
  CuotaContrato({required this.numero, required this.fecha, required this.monto});

  Map<String, dynamic> toMap() => {
    'numero': numero,
    'fecha': "${fecha.year}-${fecha.month.toString().padLeft(2,'0')}-${fecha.day.toString().padLeft(2,'0')}",
    'monto': monto,
  };

  factory CuotaContrato.fromMap(Map m) {
    DateTime parseFecha(String s) {
      try { return DateTime.parse(s); } catch (_) { return DateTime.now(); }
    }
    return CuotaContrato(
      numero: (m['numero'] is int) ? m['numero'] : int.tryParse('${m['numero']}') ?? 0,
      fecha: parseFecha('${m['fecha'] ?? ''}'),
      monto: (m['monto'] is num) ? (m['monto'] as num).toDouble() : double.tryParse('${m['monto']}') ?? 0,
    );
  }
}


// ── CONTRATO DE CAMBIO DE SIM CARD / eSIM ────────────────────
//  Modelo para el "Formato de Autorización para Cambio de Sim
//  Card y Cambio de Número" de Telefónica Venezolana (Movistar).
//  Se genera automáticamente desde la ventana de Líneas cuando
//  el tipo es "Sim a Sim", "eSim a eSIM", "Sim a eSIM" o
//  "eSIM a Sim". Guarda el registro en el historial
//  (tabla `contratos_simcard` del backend).
// ============================================================
class ContratoSimCard {
  int? id;
  String fechaCreacion;          // ISO yyyy-MM-dd HH:mm:ss
  String fechaSolicitud;         // Fecha que aparece en el formato (dd/mm/yyyy)
  String tipoCambio;             // "Sim a Sim", "eSim a eSIM", etc.
  // Datos de la gestión
  String centroServicio;         // Centro de Servicio / AA
  String numeroCuenta;           // Cuenta Movistar
  // Datos del cliente titular
  String nombreCliente;
  String cedulaCliente;
  String correoCliente;
  String numeroMovil;            // Nº móvil de contacto del titular
  // Datos SIM/eSIM
  String iccidAnterior;
  String iccidNuevo;
  String numeroTelefonicoAnterior;
  String numeroTelefonicoNuevo;
  // Datos del vendedor
  String codigoVentaAA;          // VI_____
  String nombreVendedor;
  // Firma y huellas
  String? firmaBase64;
  String? huellaPulgarIzquierdoBase64;
  String? huellaIndiceDerechoBase64;
  // Foto de cédula (opcional)
  String? cedulaFotoBase64;
  // Estado y PDF
  String estado;                 // Activo, Anulado
  String? pdfBase64;
  // Referencia a la línea asociada (si se creó desde Líneas)
  int? lineaId;

  ContratoSimCard({
    this.id,
    required this.fechaCreacion,
    required this.fechaSolicitud,
    required this.tipoCambio,
    this.centroServicio = '',
    this.numeroCuenta = '',
    required this.nombreCliente,
    required this.cedulaCliente,
    this.correoCliente = '',
    this.numeroMovil = '',
    this.iccidAnterior = '',
    this.iccidNuevo = '',
    this.numeroTelefonicoAnterior = '',
    this.numeroTelefonicoNuevo = '',
    this.codigoVentaAA = '',
    this.nombreVendedor = '',
    this.firmaBase64,
    this.huellaPulgarIzquierdoBase64,
    this.huellaIndiceDerechoBase64,
    this.cedulaFotoBase64,
    this.estado = 'Activo',
    this.pdfBase64,
    this.lineaId,
  });

  Map<String, dynamic> toMap() => {
    if (id != null) 'id': id,
    'fecha_creacion': fechaCreacion,
    'fecha_solicitud': fechaSolicitud,
    'tipo_cambio': tipoCambio,
    'centro_servicio': centroServicio,
    'numero_cuenta': numeroCuenta,
    'nombre_cliente': nombreCliente,
    'cedula_cliente': cedulaCliente,
    'correo_cliente': correoCliente,
    'numero_movil': numeroMovil,
    'iccid_anterior': iccidAnterior,
    'iccid_nuevo': iccidNuevo,
    'numero_telefonico_anterior': numeroTelefonicoAnterior,
    'numero_telefonico_nuevo': numeroTelefonicoNuevo,
    'codigo_venta_aa': codigoVentaAA,
    'nombre_vendedor': nombreVendedor,
    'estado': estado,
    if (firmaBase64 != null) 'firma_base64': firmaBase64,
    if (huellaPulgarIzquierdoBase64 != null)
      'huella_pulgar_izquierdo_base64': huellaPulgarIzquierdoBase64,
    if (huellaIndiceDerechoBase64 != null)
      'huella_indice_derecho_base64': huellaIndiceDerechoBase64,
    if (cedulaFotoBase64 != null) 'cedula_foto_base64': cedulaFotoBase64,
    if (pdfBase64 != null) 'pdf_base64': pdfBase64,
    if (lineaId != null) 'linea_id': lineaId,
  };

  factory ContratoSimCard.fromMap(Map m) {
    int toInt(dynamic v) =>
        (v is int) ? v : int.tryParse('${v ?? 0}') ?? 0;
    return ContratoSimCard(
      id: m['id'] == null ? null : toInt(m['id']),
      fechaCreacion: '${m['fecha_creacion'] ?? ''}',
      fechaSolicitud: '${m['fecha_solicitud'] ?? ''}',
      tipoCambio: '${m['tipo_cambio'] ?? ''}',
      centroServicio: '${m['centro_servicio'] ?? ''}',
      numeroCuenta: '${m['numero_cuenta'] ?? ''}',
      nombreCliente: '${m['nombre_cliente'] ?? ''}',
      cedulaCliente: '${m['cedula_cliente'] ?? ''}',
      correoCliente: '${m['correo_cliente'] ?? ''}',
      numeroMovil: '${m['numero_movil'] ?? ''}',
      iccidAnterior: '${m['iccid_anterior'] ?? ''}',
      iccidNuevo: '${m['iccid_nuevo'] ?? ''}',
      numeroTelefonicoAnterior: '${m['numero_telefonico_anterior'] ?? ''}',
      numeroTelefonicoNuevo: '${m['numero_telefonico_nuevo'] ?? ''}',
      codigoVentaAA: '${m['codigo_venta_aa'] ?? ''}',
      nombreVendedor: '${m['nombre_vendedor'] ?? ''}',
      firmaBase64: m['firma_base64'] as String?,
      huellaPulgarIzquierdoBase64:
          m['huella_pulgar_izquierdo_base64'] as String?,
      huellaIndiceDerechoBase64:
          m['huella_indice_derecho_base64'] as String?,
      cedulaFotoBase64: m['cedula_foto_base64'] as String?,
      estado: '${m['estado'] ?? 'Activo'}',
      pdfBase64: m['pdf_base64'] as String?,
      lineaId: m['linea_id'] == null ? null : toInt(m['linea_id']),
    );
  }
}

/// Lista global de contratos SIM Card (historial en memoria).
List<ContratoSimCard> contratosSimCardGlobal = [];

// ============================================================
//  FUNCIONES DE CARGA DESDE API (llenan las listas globales)
//  Usa Future.wait para cargar en paralelo y reducir el tiempo
//  total de inicio de sesión.
// ============================================================
Future<void> cargarTodosLosDatos() async {
  // Cargar productos, IMEIs, líneas, usuarios y clientes en paralelo
  final results = await Future.wait([
    _Api.get('productos').catchError((e) { debugPrint('Error productos: $e'); return null; }),
    _Api.get('stock_imei').catchError((e) { debugPrint('Error stock_imei: $e'); return null; }),
    _Api.get('lineas').catchError((e) { debugPrint('Error lineas: $e'); return null; }),
    _Api.get('usuarios').catchError((e) { debugPrint('Error usuarios: $e'); return null; }),
  ]);

  // ── Productos ──────────────────────────────────────────────
  if (results[0] != null) {
    catalogoGlobal = ((results[0] as List?) ?? [])
        .map((m) => Producto.fromMap(m)).toList();
  }

  // ── IMEIs + stock de teléfonos ────────────────────────────
  if (results[1] != null) {
    stockImeiGlobal = ((results[1] as List?) ?? [])
        .map((m) => ImeiRegistro.fromMap(m)).toList();
    for (final p in catalogoGlobal) {
      if (p.categoria == 'Telefono') {
        p.stockTotal = stockImeiGlobal
            .where((i) => i.producto.codigo == p.codigo && !i.vendido)
            .length;
      } else {
        p.stockTotal = p.stockManual;
      }
    }
  }

  // ── Líneas ────────────────────────────────────────────────
  if (results[2] != null) {
    lineasGlobal = ((results[2] as List?) ?? [])
        .map((m) => LineaModel.fromMap(m)).toList();
  }

  // ── Usuarios ──────────────────────────────────────────────
  if (results[3] != null) {
    final todos = ((results[3] as List?) ?? [])
        .map((m) => Usuario.fromMap(m)).toList();
    // Excluir al UsuarioMaestro de la lista global (no debe aparecer
    // en selectores de vendedor, comisiones, ranking, etc.).
    usuariosSistema = UsuarioMaestro.ocultar<Usuario>(
        todos, (u) => u.correo);
  }

  // ── Clientes ──────────────────────────────────────────────
  // Los clientes NO se cargan desde un endpoint propio — se
  // reconstruyen a partir de las facturas (agrupando por cédula).
  // La función `reconstruirClientesDesdeFacturas()` se llama junto
  // con `actualizarConteoCompras()` más abajo.

  // ── Conteo de compras por cliente + lista de clientes ──────
  // Carga las facturas, cuenta cuántas veces ha comprado cada cédula
  // y genera el listado global de clientes desde esa misma fuente.
  // No bloquea la app si falla (solo queda todo vacío).
  await reconstruirClientesDesdeFacturas();

  // ── Garantizar que el admin maestro siempre esté presente ─
  // (Aunque no esté en la BD o la API haya fallado.)
  // TODO: configurar correo admin real de Tecno Líder
  const _adminCorreoMaestro = 'tecnolider@gmail.com';
  final tieneAdmin = usuariosSistema.any((u) =>
      u.correo.toLowerCase() == _adminCorreoMaestro);
  if (!tieneAdmin) {
    usuariosSistema.insert(0, Usuario(
      id: 1,
      nombre: 'Administrador',
      cedula: 'ADMIN',
      correo: _adminCorreoMaestro,
      clave: 'TecnoLider.1508', // TODO: cambiar clave por defecto
      rol: 'Administrador',
      sueldoBase: 0,
    ));
  }

  // Facturas: se carga vacío al inicio, se llenan por pantalla
  ventasGlobal = [];
}

