class MyApp extends StatelessWidget {
  const MyApp({super.key});
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      debugShowCheckedModeBanner: false,
      title: 'Tecno Líder',
      // Tema CLARO siempre. La app NO sigue el modo oscuro del SO —
      // se mantiene siempre con la identidad visual clara de Tecno
      // Líder (azul royal + amarillo dorado sobre fondos claros).
      themeMode: ThemeMode.light,
      theme: _buildAppTheme(Brightness.light),
      home: const LoginPage(),
    );
  }
}

// ════════════════════════════════════════════════════════════════════
//  CONSTRUCTOR DEL TEMA — CLARO Y OSCURO
// ════════════════════════════════════════════════════════════════════
//  Genera un ThemeData consistente con la identidad visual Tecno
//  Líder. Toma `Brightness.light` o `Brightness.dark` y configura
//  todos los componentes (AppBar, botones, inputs, cards, dialogs,
//  snackbars, FAB) acordes al modo.
//
//  Decisiones clave:
//    · `useMaterial3: true` → usa Material You / M3 (UI moderna)
//    · ColorScheme generado desde el azul de marca como semilla
//    · AppBar SIEMPRE en azul royal (refuerza marca, ambos modos)
//    · FAB SIEMPRE en amarillo (CTA visualmente distintivo)
//    · Inputs con bordes redondeados y focus en amarillo
//      (el amarillo "energiza" el campo activo, mejor que azul
//       sobre azul que se pierde visualmente)
//    · Card sombra de marca en claro, profunda en oscuro
// ════════════════════════════════════════════════════════════════════
ThemeData _buildAppTheme(Brightness brightness) {
  final isDark = brightness == Brightness.dark;

  // Superficies que cambian entre modos
  final surface       = isDark ? AppColors.darkSurface     : AppColors.surfaceCard;
  final surfaceAlt    = isDark ? AppColors.darkSurfaceAlt  : AppColors.surfaceTintBlueSoft;
  final scaffoldBg    = isDark ? AppColors.darkBackground  : AppColors.surfaceTintBlue;
  final textPrimary   = isDark ? AppColors.darkTextPrimary : AppColors.textPrimary;
  final textSecondary = isDark ? AppColors.darkTextSecondary : AppColors.textSecondary;
  final divider       = isDark ? AppColors.darkBorder      : AppColors.cardBorderTinted;

  return ThemeData(
    useMaterial3: true,
    brightness: brightness,
    colorScheme: ColorScheme.fromSeed(
      seedColor: AppColors.brandBlue,
      brightness: brightness,
      primary: AppColors.brandBlue,
      onPrimary: Colors.white,
      secondary: AppColors.brandYellow,
      onSecondary: AppColors.brandBlueDeeper,
      tertiary: AppColors.brandBlueDark,
      surface: surface,
      onSurface: textPrimary,
      error: AppColors.statusRed,
      onError: Colors.white,
    ),

    scaffoldBackgroundColor: scaffoldBg,
    canvasColor: surface,

    // ── AppBar: azul royal con sombra sutil amarilla (marca) ──
    appBarTheme: const AppBarTheme(
      backgroundColor: AppColors.brandBlueDark,
      foregroundColor: Colors.white,
      surfaceTintColor: Colors.transparent,
      elevation: 0,
      scrolledUnderElevation: 4,
      shadowColor: AppColors.brandBlueDeeper,
      centerTitle: false,
      titleTextStyle: TextStyle(
        color: Colors.white,
        fontSize: 18,
        fontWeight: FontWeight.w800,
        letterSpacing: 0.4,
      ),
      iconTheme: IconThemeData(color: Colors.white),
      actionsIconTheme: IconThemeData(color: Colors.white),
    ),

    // ── Botón principal: gradient implícito vía estilo ────────
    elevatedButtonTheme: ElevatedButtonThemeData(
      style: ElevatedButton.styleFrom(
        backgroundColor: AppColors.brandBlueDark,
        foregroundColor: Colors.white,
        padding: const EdgeInsets.symmetric(horizontal: 24, vertical: 14),
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(12)),
        elevation: 0,
        textStyle: const TextStyle(
          fontSize: 15, fontWeight: FontWeight.w600, letterSpacing: 0.5),
      ),
    ),

    // ── Botón outline ─────────────────────────────────────────
    outlinedButtonTheme: OutlinedButtonThemeData(
      style: OutlinedButton.styleFrom(
        foregroundColor: AppColors.brandBlue,
        side: const BorderSide(color: AppColors.brandBlue, width: 1.5),
        padding: const EdgeInsets.symmetric(horizontal: 22, vertical: 13),
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(12)),
      ),
    ),

    // ── Botón texto ───────────────────────────────────────────
    textButtonTheme: TextButtonThemeData(
      style: TextButton.styleFrom(
        foregroundColor: AppColors.brandBlue,
        padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 10),
      ),
    ),

    // ── Inputs: focus en azul de marca (cohesión total) ──────
    inputDecorationTheme: InputDecorationTheme(
      filled: true,
      fillColor: surfaceAlt,
      labelStyle: TextStyle(color: textSecondary, fontWeight: FontWeight.w500),
      hintStyle: TextStyle(color: textSecondary.withValues(alpha: 0.7)),
      prefixIconColor: AppColors.brandBlue,
      suffixIconColor: textSecondary,
      border: OutlineInputBorder(
        borderRadius: BorderRadius.circular(12),
        borderSide: BorderSide.none,
      ),
      enabledBorder: OutlineInputBorder(
        borderRadius: BorderRadius.circular(12),
        borderSide: BorderSide(color: divider, width: 1),
      ),
      focusedBorder: OutlineInputBorder(
        borderRadius: BorderRadius.circular(12),
        borderSide: const BorderSide(color: AppColors.brandBlue, width: 2),
      ),
      errorBorder: OutlineInputBorder(
        borderRadius: BorderRadius.circular(12),
        borderSide: const BorderSide(color: AppColors.statusRed, width: 1.5),
      ),
      focusedErrorBorder: OutlineInputBorder(
        borderRadius: BorderRadius.circular(12),
        borderSide: const BorderSide(color: AppColors.statusRed, width: 2),
      ),
      contentPadding: const EdgeInsets.symmetric(horizontal: 16, vertical: 16),
    ),

    // ── Cards: bordes sutiles azules + sombra cálida ──────────
    cardTheme: CardThemeData(
      color: surface,
      elevation: isDark ? 0 : 1,
      shadowColor: isDark
          ? Colors.black.withValues(alpha: 0.3)
          : AppColors.brandBlue.withValues(alpha: 0.10),
      surfaceTintColor: Colors.transparent,
      shape: RoundedRectangleBorder(
        borderRadius: BorderRadius.circular(16),
        side: BorderSide(
          color: isDark
              ? divider
              : AppColors.brandBlue.withValues(alpha: 0.08),
          width: 1,
        ),
      ),
      margin: EdgeInsets.zero,
    ),

    // ── FAB: amarillo de marca (ambos modos) ─────────────────
    floatingActionButtonTheme: const FloatingActionButtonThemeData(
      backgroundColor: AppColors.brandYellow,
      foregroundColor: AppColors.brandBlueDeeper,
      elevation: 6,
      focusElevation: 8,
      hoverElevation: 8,
      highlightElevation: 4,
      shape: RoundedRectangleBorder(
        borderRadius: BorderRadius.all(Radius.circular(16)),
      ),
    ),

    // ── Chips ─────────────────────────────────────────────────
    chipTheme: ChipThemeData(
      backgroundColor: surfaceAlt,
      selectedColor: AppColors.brandBlue.withValues(alpha: 0.15),
      labelStyle: TextStyle(color: textPrimary, fontWeight: FontWeight.w500),
      side: BorderSide(color: divider),
      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(20)),
    ),

    // ── SnackBar ──────────────────────────────────────────────
    snackBarTheme: SnackBarThemeData(
      behavior: SnackBarBehavior.floating,
      backgroundColor: isDark ? AppColors.darkSurface : AppColors.brandBlueDark,
      contentTextStyle: const TextStyle(color: Colors.white),
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.all(Radius.circular(12)),
      ),
      actionTextColor: AppColors.brandYellow,
    ),

    // ── Diálogos ─────────────────────────────────────────────
    dialogTheme: DialogThemeData(
      backgroundColor: surface,
      surfaceTintColor: Colors.transparent,
      elevation: 8,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.all(Radius.circular(20)),
      ),
      titleTextStyle: TextStyle(
        color: textPrimary,
        fontSize: 18,
        fontWeight: FontWeight.w700,
      ),
      contentTextStyle: TextStyle(color: textPrimary, fontSize: 14),
    ),

    // ── BottomSheet ───────────────────────────────────────────
    bottomSheetTheme: BottomSheetThemeData(
      backgroundColor: surface,
      surfaceTintColor: Colors.transparent,
      elevation: 8,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(24)),
      ),
    ),

    // ── Divider ───────────────────────────────────────────────
    dividerTheme: DividerThemeData(
      color: divider,
      space: 1,
      thickness: 1,
    ),

    // ── ListTile ──────────────────────────────────────────────
    listTileTheme: ListTileThemeData(
      iconColor: AppColors.brandBlue,
      textColor: textPrimary,
      titleTextStyle: TextStyle(
        color: textPrimary, fontSize: 15, fontWeight: FontWeight.w500),
      subtitleTextStyle: TextStyle(color: textSecondary, fontSize: 13),
      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
    ),

    // ── Switch / Checkbox / Radio: amarillo cuando activo ────
    switchTheme: SwitchThemeData(
      thumbColor: WidgetStateProperty.resolveWith(
        (states) => states.contains(WidgetState.selected)
            ? AppColors.brandYellow
            : Colors.grey,
      ),
      trackColor: WidgetStateProperty.resolveWith(
        (states) => states.contains(WidgetState.selected)
            ? AppColors.brandYellow.withValues(alpha: 0.4)
            : Colors.grey.withValues(alpha: 0.3),
      ),
    ),
    checkboxTheme: CheckboxThemeData(
      fillColor: WidgetStateProperty.resolveWith(
        (states) => states.contains(WidgetState.selected)
            ? AppColors.brandBlue : Colors.transparent,
      ),
      checkColor: const WidgetStatePropertyAll(Colors.white),
      side: BorderSide(color: divider, width: 1.5),
      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(4)),
    ),

    // ── ProgressIndicator ─────────────────────────────────────
    progressIndicatorTheme: const ProgressIndicatorThemeData(
      color: AppColors.brandYellow,
      linearTrackColor: Color(0x33FFC20E),
      circularTrackColor: Color(0x22FFC20E),
    ),

    // ── Tipografía ────────────────────────────────────────────
    textTheme: TextTheme(
      headlineLarge:  TextStyle(color: textPrimary, fontWeight: FontWeight.w800),
      headlineMedium: TextStyle(color: textPrimary, fontWeight: FontWeight.w700),
      titleLarge:     TextStyle(color: textPrimary, fontWeight: FontWeight.w700),
      titleMedium:    TextStyle(color: textPrimary, fontWeight: FontWeight.w600),
      bodyLarge:      TextStyle(color: textPrimary),
      bodyMedium:     TextStyle(color: textPrimary),
      bodySmall:      TextStyle(color: textSecondary),
      labelLarge:     TextStyle(color: textPrimary, fontWeight: FontWeight.w600),
    ),

    iconTheme: IconThemeData(color: textSecondary),
    primaryIconTheme: const IconThemeData(color: Colors.white),

    // ── Tab bar ───────────────────────────────────────────────
    tabBarTheme: const TabBarThemeData(
      labelColor: Colors.white,
      unselectedLabelColor: Colors.white70,
      indicatorColor: AppColors.brandYellow,
      indicatorSize: TabBarIndicatorSize.label,
      labelStyle: TextStyle(fontWeight: FontWeight.w700),
    ),
  );
}

// ============================================================
//  LOGIN — consulta la base de datos real
// ============================================================
class LoginPage extends StatefulWidget {
  const LoginPage({super.key});
  @override State<LoginPage> createState() => _LoginPageState();
}

class _LoginPageState extends State<LoginPage> with SingleTickerProviderStateMixin {
  final _u = TextEditingController(), _p = TextEditingController();
  bool _cargando = false;
  bool _verClave = false; // toggle visibilidad contraseña
  bool _intentandoAutoLogin = true;

  /// Tienda seleccionada antes de iniciar sesión. Si está marcada,
  /// el flujo de login NO mostrará el diálogo de selección posterior
  /// (mejora la UX en dispositivos donde el operador siempre trabaja
  /// en el mismo PDV). Null = preguntar después como antes.
  String? _tiendaSeleccionada;

  // ── Animación de entrada ──────────────────────────────────
  late final AnimationController _animCtrl;
  late final Animation<double> _animFade;
  late final Animation<Offset> _animSlide;

  @override
  void initState() {
    super.initState();
    _animCtrl = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 700),
    );
    _animFade = CurvedAnimation(parent: _animCtrl, curve: Curves.easeOut);
    _animSlide = Tween<Offset>(
      begin: const Offset(0, 0.08),
      end: Offset.zero,
    ).animate(CurvedAnimation(parent: _animCtrl, curve: Curves.easeOutCubic));
    _animCtrl.forward();
    _intentarAutoLogin();
  }

  @override
  void dispose() {
    _animCtrl.dispose();
    _u.dispose();
    _p.dispose();
    super.dispose();
  }

  /// Intenta auto-login con las credenciales guardadas. Si tiene éxito,
  /// navega directamente a la pantalla principal sin mostrar el form.
  /// Si falla (credenciales inválidas o sin sesión guardada), muestra
  /// el formulario normal de login.
  Future<void> _intentarAutoLogin() async {
    try {
      final cred = await SesionPersistente.leer();
      if (cred == null) {
        if (mounted) setState(() => _intentandoAutoLogin = false);
        return;
      }
      // Pre-llenar los campos para que si el auto-login falla, el
      // usuario vea sus credenciales y pueda corregir/reintentar.
      _u.text = cred.correo;
      _p.text = cred.clave;
      // Disparar el flujo normal de login
      await _login();
    } catch (e) {
      debugPrint('[Sesion] auto-login: $e');
    } finally {
      if (mounted) setState(() => _intentandoAutoLogin = false);
    }
  }

  Future<void> _login() async {
    final correo = _u.text.trim().toLowerCase();
    final clave  = _p.text; // NO aplicar trim a contraseñas

    // ── Validaciones locales ────────────────────────────────
    if (correo.isEmpty) {
      _mostrarError("Por favor ingrese su correo o usuario.");
      return;
    }
    // Validación básica de formato de correo
    final emailRegex = RegExp(r'^[^@\s]+@[^@\s]+\.[^@\s]+$');
    if (!emailRegex.hasMatch(correo)) {
      _mostrarError("Ingrese un correo electrónico válido.");
      return;
    }
    if (clave.isEmpty) {
      _mostrarError("Por favor ingrese su contraseña.");
      return;
    }
    if (clave.length < 4) {
      _mostrarError("La contraseña debe tener al menos 4 caracteres.");
      return;
    }

    setState(() => _cargando = true);

    // ═══════════════════════════════════════════════════════════════
    //  RECONOCIMIENTO DEL USUARIO MAESTRO (proveedor Tecno Líder)
    //  El maestro tiene credenciales hardcoded (UsuarioMaestro.correo
    //  + clave) y bypasea TODAS las verificaciones: API, BD, licencia.
    //  Usado para soporte y para gestionar el bloqueo del sistema.
    // ═══════════════════════════════════════════════════════════════
    final esUsuarioMaestro = UsuarioMaestro.esMaestro(correo, clave);

    // Mantenemos el "admin maestro" antiguo (admin de la empresa cliente)
    // como fallback de emergencia si la API se cae. Esto NO es el maestro
    // del proveedor — solo un admin de respaldo del cliente.
    // TODO: configurar correo admin real de Tecno Líder
    const _adminCorreo = 'tecnolider@gmail.com';
    const _adminClave  = 'TecnoLider.1508'; // TODO: cambiar clave por defecto
    final esAdminMaestro = (correo == _adminCorreo && clave == _adminClave);

    // ═══════════════════════════════════════════════════════════════
    //  VERIFICACIÓN DE LICENCIA — solo aplica a usuarios normales
    //  El UsuarioMaestro PUEDE entrar siempre (es quien controla el
    //  bloqueo). Los demás son rechazados si la app está suspendida.
    // ═══════════════════════════════════════════════════════════════
    if (!esUsuarioMaestro) {
      try {
        await LicenciaService.cargarEstado();
      } catch (_) { /* ignoramos errores; usaremos el último estado */ }

      final estado = LicenciaService.estadoActual;
      if (estado.bloqueada) {
        if (!mounted) return;
        setState(() => _cargando = false);
        // Mostrar pantalla de bloqueo en lugar de la pantalla principal.
        Navigator.pushReplacement(
          context,
          MaterialPageRoute(builder: (_) => const PantallaBloqueoLicencia()),
        );
        return;
      }
    }

    try {
      dynamic raw;

      if (esUsuarioMaestro) {
        // Maestro: NO consultamos BD. Construimos su sesión directamente.
        debugPrint('[Login] ✔ Acceso UsuarioMaestro (proveedor)');
        raw = null; // se manejará en el bloque de fallback
      } else {
        try {
          raw = await _Api.get('usuarios', {'correo': correo, 'clave': clave});
        } catch (e) {
          // Si la API falla pero son las credenciales del admin maestro
          // local, permitimos el ingreso offline (modo de emergencia).
          if (!esAdminMaestro) rethrow;
          debugPrint('[Login] API no disponible, usando admin local: $e');
          raw = null;
        }
      }

      if (raw == null) {
        if (esUsuarioMaestro) {
          // Sesión del UsuarioMaestro (proveedor Tecno Líder).
          // NO se persiste, NO aparece en lista de Usuarios. Tiene rol
          // especial 'Maestro' que da acceso al Panel Maestro oculto.
          usuarioSesion = Usuario(
            id: -1,  // ID negativo = no real, no afecta BD
            nombre: UsuarioMaestro.nombre,
            cedula: 'MAESTRO',
            correo: UsuarioMaestro.correo,
            clave: UsuarioMaestro.clave,
            rol: 'Maestro',
            sueldoBase: 0,
          );
          debugPrint('[Login] ✔ Ingreso como UsuarioMaestro');
        } else if (esAdminMaestro) {
          // Fallback: admin local de la empresa cliente cuando la API
          // está caída.
          usuarioSesion = Usuario(
            id: 1,
            nombre: 'Administrador',
            cedula: 'ADMIN',
            correo: _adminCorreo,
            clave: _adminClave,
            rol: 'Administrador',
            sueldoBase: 0,
          );
          debugPrint('[Login] ✔ Ingreso como admin maestro (fallback local)');
        } else {
          if (!mounted) return;
          _mostrarError(
            "Credenciales incorrectas. Verifique su usuario y contraseña.",
            duracion: const Duration(seconds: 5),
          );
          return;
        }
      } else {
        usuarioSesion = Usuario.fromMap(raw);
      }

      // ── Guardar sesión persistente ──
      // Próxima vez que se abra la app, hará auto-login con estas
      // credenciales sin pedir el formulario de login.
      // EXCEPCIÓN: el UsuarioMaestro NO se persiste por seguridad
      // (sus credenciales no quedan guardadas en el dispositivo).
      if (usuarioSesion != null && !esUsuarioMaestro) {
        await SesionPersistente.guardar(correo, clave);
      }

      // Cargar datos globales al iniciar sesión (en paralelo donde sea posible)
      if (mounted) {
        // Mostrar indicador de carga mientras se cargan los datos
        ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
          content: Row(children: [
            SizedBox(width: 16, height: 16,
              child: CircularProgressIndicator(color: Colors.white, strokeWidth: 2)),
            SizedBox(width: 12),
            Text("Cargando datos del sistema..."),
          ]),
          duration: Duration(seconds: 10),
          backgroundColor: AppColors.royalBlue,
        ));
      }

      await cargarTodosLosDatos();
      NotificacionesService.iniciar();

      if (!mounted) return;
      ScaffoldMessenger.of(context).hideCurrentSnackBar();

      // Selección de tienda — si el usuario ya eligió en el formulario
      // del login (selector visible), saltamos este diálogo y vamos
      // directo a Ventas. Si no, se muestra como antes para no romper
      // el flujo en sesiones donde la preferencia no se cargó.
      String? tiendaSeleccionada = _tiendaSeleccionada;
      if (tiendaSeleccionada != null &&
          ConfigSistema.tiendas.contains(tiendaSeleccionada)) {
        // Validamos que la tienda elegida exista en la lista actual
        // (la lista se actualiza en `cargarTodosLosDatos`).
      } else {
        tiendaSeleccionada = await showDialog<String>(
        context: context,
        barrierDismissible: false,
        builder: (context) => AlertDialog(
          title: const Row(children: [
            Icon(Icons.store, color: AppColors.primaryBlue),
            SizedBox(width: 8),
            Text("Seleccione Punto de Venta"),
          ]),
          content: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              Text(
                "Bienvenido, ${usuarioSesion?.nombre ?? 'Usuario'}",
                style: const TextStyle(color: AppColors.textSecondary, fontSize: 13),
              ),
              const SizedBox(height: 12),
              ...ConfigSistema.tiendas.map((tienda) => Padding(
                padding: const EdgeInsets.only(bottom: 6),
                child: ListTile(
                  leading: Container(
                    padding: const EdgeInsets.all(8),
                    decoration: BoxDecoration(
                      color: AppColors.primaryBlue.withValues(alpha: 0.1),
                      borderRadius: BorderRadius.circular(8),
                    ),
                    child: const Icon(Icons.storefront_outlined, color: AppColors.royalBlue, size: 20),
                  ),
                  title: Text(tienda, style: const TextStyle(fontWeight: FontWeight.w600)),
                  shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
                  tileColor: AppColors.surfaceGrey,
                  contentPadding: const EdgeInsets.symmetric(horizontal: 12, vertical: 4),
                  trailing: const Icon(Icons.arrow_forward_ios, size: 14, color: AppColors.textSecondary),
                  onTap: () => Navigator.pop(context, tienda),
                ),
              )),
            ],
          ),
        ),
        );
      }

      if (!mounted) return;
      if (tiendaSeleccionada != null) {
        final tiendaFinal = tiendaSeleccionada;
        Navigator.pushReplacement(
          context,
          MaterialPageRoute(builder: (c) => VentasPrincipal(tienda: tiendaFinal)),
        );
      }

    } catch (e) {
      debugPrint('[_login] Error: $e');
      if (!mounted) return;
      ScaffoldMessenger.of(context).hideCurrentSnackBar();

      final esTimeout    = e.toString().contains('TimeoutException');
      final esConexion   = e.toString().contains('SocketException') ||
                           e.toString().contains('ClientException') ||
                           e.toString().contains('Connection refused');
      final esCredencial = e.toString().toLowerCase().contains('credencial') ||
                           e.toString().contains('401') ||
                           e.toString().contains('403');

      final mensaje = esTimeout
          ? "Tiempo de espera agotado. Verifique su conexión a la red."
          : esConexion
              ? "No se pudo conectar al servidor.\nRevise que el servidor esté encendido y la IP configurada sea correcta."
              : esCredencial
                  ? "Credenciales incorrectas. Verifique su usuario y contraseña."
                  : "Error al iniciar sesión. Intente de nuevo.";

      ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Text(mensaje),
        duration: const Duration(seconds: 6),
        backgroundColor: AppColors.statusRed,
        action: (esConexion || esTimeout)
            ? SnackBarAction(
                label: "Config.",
                textColor: Colors.white,
                onPressed: () => Navigator.push(context,
                  MaterialPageRoute(builder: (_) => const VentanaConfiguracion())),
              )
            : null,
      ));
    } finally {
      if (mounted) setState(() => _cargando = false);
    }
  }

  /// Muestra un SnackBar de error con estilo uniforme.
  void _mostrarError(String mensaje, {Duration duracion = const Duration(seconds: 4)}) {
    if (!mounted) return;
    ScaffoldMessenger.of(context).showSnackBar(SnackBar(
      content: Row(children: [
        const Icon(Icons.error_outline, color: Colors.white, size: 18),
        const SizedBox(width: 8),
        Expanded(child: Text(mensaje)),
      ]),
      backgroundColor: AppColors.statusRed,
      duration: duracion,
      behavior: SnackBarBehavior.floating,
    ));
  }

