  // ────────────────────────────────────────────────────────────
  //  WIDGETS DEL LOGIN — extraídos por legibilidad
  // ────────────────────────────────────────────────────────────

  Widget _buildCampoCorreo() {
    return TextField(
      controller: _u,
      keyboardType: TextInputType.emailAddress,
      textInputAction: TextInputAction.next,
      autofillHints: const [AutofillHints.email, AutofillHints.username],
      style: const TextStyle(
        color: AppColors.textPrimary,
        fontWeight: FontWeight.w500,
      ),
      decoration: InputDecoration(
        labelText: 'Correo electrónico',
        hintText: 'usuario@tecnolider.com',
        prefixIcon: const Icon(Icons.alternate_email_rounded,
          color: AppColors.brandBlue, size: 22),
        filled: true,
        fillColor: AppColors.surfaceGrey,
        border: OutlineInputBorder(
          borderRadius: BorderRadius.circular(14),
          borderSide: BorderSide.none,
        ),
        enabledBorder: OutlineInputBorder(
          borderRadius: BorderRadius.circular(14),
          borderSide: BorderSide(
            color: AppColors.cardBorder.withValues(alpha: 0.5),
          ),
        ),
        focusedBorder: OutlineInputBorder(
          borderRadius: BorderRadius.circular(14),
          borderSide: const BorderSide(
            color: AppColors.brandBlue,
            width: 2,
          ),
        ),
      ),
    );
  }

  Widget _buildCampoClave() {
    return TextField(
      controller: _p,
      obscureText: !_verClave,
      textInputAction: TextInputAction.done,
      autofillHints: const [AutofillHints.password],
      onSubmitted: (_) => _cargando ? null : _login(),
      style: const TextStyle(
        color: AppColors.textPrimary,
        fontWeight: FontWeight.w500,
      ),
      decoration: InputDecoration(
        labelText: 'Contraseña',
        hintText: '••••••••',
        prefixIcon: const Icon(Icons.lock_outline_rounded,
          color: AppColors.brandBlue, size: 22),
        suffixIcon: IconButton(
          icon: Icon(
            _verClave
                ? Icons.visibility_off_outlined
                : Icons.visibility_outlined,
            color: AppColors.textSecondary,
            size: 22,
          ),
          tooltip: _verClave ? 'Ocultar contraseña' : 'Mostrar contraseña',
          onPressed: () => setState(() => _verClave = !_verClave),
        ),
        filled: true,
        fillColor: AppColors.surfaceGrey,
        border: OutlineInputBorder(
          borderRadius: BorderRadius.circular(14),
          borderSide: BorderSide.none,
        ),
        enabledBorder: OutlineInputBorder(
          borderRadius: BorderRadius.circular(14),
          borderSide: BorderSide(
            color: AppColors.cardBorder.withValues(alpha: 0.5),
          ),
        ),
        focusedBorder: OutlineInputBorder(
          borderRadius: BorderRadius.circular(14),
          borderSide: const BorderSide(
            color: AppColors.brandBlue,
            width: 2,
          ),
        ),
      ),
    );
  }

  /// Selector de tienda visible en el formulario.
  /// Si solo hay una tienda configurada, se muestra como tile fijo
  /// (sin opciones). Si hay más de una, dropdown.
  /// Permite no elegir → se preguntará después como antes.
  Widget _buildSelectorTienda() {
    final tiendas = ConfigSistema.tiendas;

    // Si la tienda preseleccionada ya no existe en la lista actualizada
    // (porque el usuario cambió la config), la limpiamos.
    if (_tiendaSeleccionada != null && !tiendas.contains(_tiendaSeleccionada)) {
      _tiendaSeleccionada = null;
    }

    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 4),
      decoration: BoxDecoration(
        color: AppColors.surfaceGrey,
        borderRadius: BorderRadius.circular(14),
        border: Border.all(
          color: _tiendaSeleccionada != null
              ? AppColors.brandYellow.withValues(alpha: 0.6)
              : AppColors.cardBorder.withValues(alpha: 0.5),
          width: _tiendaSeleccionada != null ? 1.5 : 1,
        ),
      ),
      child: DropdownButtonHideUnderline(
        child: DropdownButton<String>(
          value: _tiendaSeleccionada,
          isExpanded: true,
          icon: const Icon(Icons.expand_more_rounded,
            color: AppColors.textSecondary),
          hint: Row(children: const [
            Icon(Icons.storefront_outlined,
              color: AppColors.brandBlue, size: 22),
            SizedBox(width: 12),
            Text('Punto de venta (opcional)',
              style: TextStyle(
                color: AppColors.textSecondary,
                fontSize: 14,
              )),
          ]),
          style: const TextStyle(
            color: AppColors.textPrimary,
            fontSize: 14,
            fontWeight: FontWeight.w500,
          ),
          dropdownColor: Colors.white,
          borderRadius: BorderRadius.circular(12),
          items: tiendas
              .map((t) => DropdownMenuItem(
                    value: t,
                    child: Row(children: [
                      const Icon(Icons.storefront_rounded,
                        color: AppColors.brandBlue, size: 20),
                      const SizedBox(width: 12),
                      Expanded(
                        child: Text(t,
                          style: const TextStyle(
                            fontWeight: FontWeight.w600,
                          ),
                          overflow: TextOverflow.ellipsis),
                      ),
                    ]),
                  ))
              .toList(),
          onChanged: (v) => setState(() => _tiendaSeleccionada = v),
        ),
      ),
    );
  }

  Widget _buildBotonAcceder() {
    return SizedBox(
      width: double.infinity, height: 56,
      child: AnimatedContainer(
        duration: const Duration(milliseconds: 200),
        decoration: BoxDecoration(
          gradient: _cargando ? null : AppColors.gradientCTA,
          color: _cargando ? AppColors.brandYellow.withValues(alpha: 0.7) : null,
          borderRadius: BorderRadius.circular(14),
          boxShadow: _cargando ? [] : AppColors.shadowYellowGlow(),
        ),
        child: Material(
          color: Colors.transparent,
          child: InkWell(
            onTap: _cargando ? null : _login,
            borderRadius: BorderRadius.circular(14),
            child: Center(
              child: _cargando
                  ? const SizedBox(
                      width: 24, height: 24,
                      child: CircularProgressIndicator(
                        color: AppColors.brandBlueDeeper,
                        strokeWidth: 2.8,
                      ),
                    )
                  : Row(
                      mainAxisAlignment: MainAxisAlignment.center,
                      children: const [
                        Text('ACCEDER',
                          style: TextStyle(
                            color: AppColors.brandBlueDeeper,
                            fontSize: 15,
                            fontWeight: FontWeight.w900,
                            letterSpacing: 2.5,
                          ),
                        ),
                        SizedBox(width: 10),
                        Icon(
                          Icons.arrow_forward_rounded,
                          color: AppColors.brandBlueDeeper,
                          size: 22,
                        ),
                      ],
                    ),
            ),
          ),
        ),
      ),
    );
  }
}

