                    ),
                    const SizedBox(height: 30),
                    if (estado.ultimaSincronizacion != null)
                      Text(
                        'Última verificación: '
                        '${_fmtFechaHora(estado.ultimaSincronizacion!)}',
                        style: TextStyle(
                          color: Colors.white.withValues(alpha: 0.4),
                          fontSize: 11,
                        ),
                      ),
                  ],
                ),
              ),
            ),
          ),
        ),
      ]),
    );
  }

  static String _fmtFechaHora(DateTime d) {
    String pad(int n) => n.toString().padLeft(2, '0');
    return '${pad(d.day)}/${pad(d.month)}/${d.year} '
           '${pad(d.hour)}:${pad(d.minute)}';
  }
}

// ════════════════════════════════════════════════════════════════════
//  PANEL MAESTRO — control del bloqueo y auditoría
// ════════════════════════════════════════════════════════════════════
//  Pantalla accesible SOLO al UsuarioMaestro (bloqueada para todos
//  los demás roles). Permite:
//   · Ver el estado actual de la licencia (bloqueada / activa)
//   · Cambiar el motivo del bloqueo y teléfono de contacto
//   · Bloquear/Desbloquear el sistema con un click
//   · Ver el historial de bloqueos/desbloqueos (auditoría)
//
//  Se accede desde el drawer (un item solo visible al rol 'Maestro').
// ════════════════════════════════════════════════════════════════════
class VentanaPanelMaestro extends StatefulWidget {
  const VentanaPanelMaestro({super.key});
  @override
  State<VentanaPanelMaestro> createState() => _VentanaPanelMaestroState();
}

class _VentanaPanelMaestroState extends State<VentanaPanelMaestro> {
  EstadoLicencia _estado = EstadoLicencia.activo();
  bool _cargando = true;
  bool _aplicando = false;
  late TextEditingController _motivoCtrl;
  late TextEditingController _telefonoCtrl;
  List<Map<String, dynamic>> _logs = [];

  @override
  void initState() {
    super.initState();
    _motivoCtrl   = TextEditingController();
    _telefonoCtrl = TextEditingController();
    _cargar();
  }

  @override
  void dispose() {
    _motivoCtrl.dispose();
    _telefonoCtrl.dispose();
    super.dispose();
  }

  Future<void> _cargar() async {
    setState(() => _cargando = true);
    final est = await LicenciaService.cargarEstado();
    final logs = await LicenciaService.historialLogs();
    if (!mounted) return;
    setState(() {
      _estado = est;
      _motivoCtrl.text = est.motivo;
      _telefonoCtrl.text = est.telefonoContacto;
      _logs = logs;
      _cargando = false;
    });
  }

  Future<void> _aplicar({required bool bloquear}) async {
    final motivo = _motivoCtrl.text.trim().isEmpty
        ? 'Servicio suspendido por falta de pago'
        : _motivoCtrl.text.trim();
    final telefono = _telefonoCtrl.text.trim().isEmpty
        ? '0414-XXXXXXX'
        : _telefonoCtrl.text.trim();

    // Confirmación antes de aplicar
    final ok = await showDialog<bool>(
      context: context,
      builder: (ctx) => AlertDialog(
        icon: Icon(
          bloquear ? Icons.lock_outline : Icons.lock_open,
          color: bloquear ? AppColors.statusRed : AppColors.statusGreen,
          size: 36,
        ),
        title: Text(bloquear ? '¿Bloquear sistema?' : '¿Desbloquear sistema?'),
        content: Text(
          bloquear
              ? 'TODOS los usuarios (excepto el maestro) verán la pantalla '
                'de bloqueo y no podrán usar la app hasta el desbloqueo.\n\n'
                '¿Confirmar?'
              : 'Todos los usuarios podrán usar la app de nuevo.\n\n'
                '¿Confirmar?',
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(ctx, false),
            child: const Text('Cancelar'),
          ),
          ElevatedButton(
            style: ElevatedButton.styleFrom(
              backgroundColor: bloquear
                  ? AppColors.statusRed
                  : AppColors.statusGreen,
            ),
            onPressed: () => Navigator.pop(ctx, true),
            child: Text(
              bloquear ? 'BLOQUEAR' : 'DESBLOQUEAR',
              style: const TextStyle(color: Colors.white),
            ),
          ),
        ],
      ),
    );
    if (ok != true) return;

    setState(() => _aplicando = true);
    try {
      await LicenciaService.aplicarBloqueo(
        bloqueada: bloquear,
        motivo: motivo,
        telefono: telefono,
        accionPor: usuarioSesion?.correo ?? UsuarioMaestro.correo,
      );
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(bloquear
              ? '🔒 Sistema bloqueado correctamente'
              : '🔓 Sistema desbloqueado correctamente'),
          backgroundColor: AppColors.statusGreen,
        ),
      );
      await _cargar();
    } catch (e) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text('Error: $e'),
          backgroundColor: AppColors.statusRed,
          duration: const Duration(seconds: 6),
        ),
      );
    } finally {
      if (mounted) setState(() => _aplicando = false);
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: AppColors.surfaceTintBlue,
      appBar: AppBar(
        title: const Text('Panel Maestro'),
        actions: [
          IconButton(
            icon: const Icon(Icons.refresh),
            tooltip: 'Recargar',
            onPressed: _cargando ? null : _cargar,
          ),
        ],
      ),
      body: _cargando
          ? const Center(child: CircularProgressIndicator())
          : RefreshIndicator(
              onRefresh: _cargar,
              child: ListView(
                padding: const EdgeInsets.all(16),
                children: [
                  // ── Banner de estado ─────────────────────────
                  Container(
                    padding: const EdgeInsets.all(20),
                    decoration: BoxDecoration(
                      gradient: LinearGradient(
                        colors: _estado.bloqueada
                            ? [AppColors.statusRed,
                               AppColors.statusRed.withValues(alpha: 0.7)]
                            : [AppColors.statusGreen,
                               AppColors.statusGreen.withValues(alpha: 0.7)],
                      ),
                      borderRadius: BorderRadius.circular(16),
                    ),
                    child: Row(children: [
                      Icon(
                        _estado.bloqueada
                            ? Icons.lock_outline
                            : Icons.lock_open_rounded,
                        size: 48,
                        color: Colors.white,
                      ),
                      const SizedBox(width: 16),
                      Expanded(
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: [
                            Text(
                              _estado.bloqueada
                                  ? 'SISTEMA BLOQUEADO'
                                  : 'SISTEMA ACTIVO',
                              style: const TextStyle(
                                color: Colors.white,
                                fontSize: 20,
                                fontWeight: FontWeight.w900,
                                letterSpacing: 1.2,
                              ),
                            ),
                            const SizedBox(height: 4),
                            Text(
                              _estado.bloqueada
                                  ? 'Los usuarios no pueden iniciar sesión'
                                  : 'Todos los usuarios tienen acceso',
                              style: TextStyle(
                                color: Colors.white.withValues(alpha: 0.9),
                                fontSize: 13,
                              ),
                            ),
                          ],
                        ),
                      ),
                    ]),
                  ),
                  const SizedBox(height: 20),

                  // ── Configuración del bloqueo ────────────────
                  const Text('Configuración',
                    style: TextStyle(
                      fontSize: 16,
                      fontWeight: FontWeight.w800,
                      color: AppColors.textPrimary,
                    )),
                  const SizedBox(height: 12),
                  Card(
                    child: Padding(
                      padding: const EdgeInsets.all(16),
                      child: Column(children: [
                        TextField(
                          controller: _motivoCtrl,
                          maxLines: 2,
                          enabled: !_aplicando,
                          decoration: const InputDecoration(
                            labelText: 'Motivo del bloqueo',
                            hintText: 'Ej: Falta de pago - cuota Octubre 2025',
                            prefixIcon: Icon(Icons.info_outline),
                          ),
                        ),
                        const SizedBox(height: 12),
                        TextField(
                          controller: _telefonoCtrl,
                          enabled: !_aplicando,
                          keyboardType: TextInputType.phone,
                          decoration: const InputDecoration(
                            labelText: 'Teléfono de contacto',
                            hintText: '0414-1234567',
                            prefixIcon: Icon(Icons.phone_outlined),
                          ),
                        ),
                      ]),
                    ),
                  ),
                  const SizedBox(height: 16),

                  // ── Botones de acción ────────────────────────
                  if (_estado.bloqueada)
                    SizedBox(
                      width: double.infinity, height: 56,
                      child: ElevatedButton.icon(
                        icon: const Icon(Icons.lock_open_rounded),
                        label: Text(_aplicando
                            ? 'Aplicando...'
                            : 'DESBLOQUEAR SISTEMA'),
                        style: ElevatedButton.styleFrom(
                          backgroundColor: AppColors.statusGreen,
                          foregroundColor: Colors.white,
                          textStyle: const TextStyle(
                            fontSize: 15,
                            fontWeight: FontWeight.w900,
                            letterSpacing: 1.2,
                          ),
                        ),
                        onPressed: _aplicando
                            ? null
                            : () => _aplicar(bloquear: false),
                      ),
                    )
                  else
                    SizedBox(
                      width: double.infinity, height: 56,
                      child: ElevatedButton.icon(
                        icon: const Icon(Icons.lock_outline_rounded),
                        label: Text(_aplicando
                            ? 'Aplicando...'
                            : 'BLOQUEAR SISTEMA'),
                        style: ElevatedButton.styleFrom(
                          backgroundColor: AppColors.statusRed,
                          foregroundColor: Colors.white,
                          textStyle: const TextStyle(
                            fontSize: 15,
                            fontWeight: FontWeight.w900,
                            letterSpacing: 1.2,
                          ),
                        ),
                        onPressed: _aplicando
                            ? null
                            : () => _aplicar(bloquear: true),
                      ),
                    ),
                  const SizedBox(height: 28),

                  // ── Historial de auditoría ───────────────────
                  Row(children: [
                    const Text('Historial de bloqueos',
                      style: TextStyle(
                        fontSize: 16,
                        fontWeight: FontWeight.w800,
                        color: AppColors.textPrimary,
                      )),
                    const Spacer(),
                    Text('${_logs.length} eventos',
                      style: const TextStyle(
                        color: AppColors.textSecondary,
                        fontSize: 12,
                      )),
                  ]),
                  const SizedBox(height: 12),
                  if (_logs.isEmpty)
                    Card(
                      child: Padding(
                        padding: const EdgeInsets.all(20),
                        child: Center(
                          child: Column(children: [
                            Icon(Icons.history,
                              color: AppColors.textSecondary
                                  .withValues(alpha: 0.5),
                              size: 36),
                            const SizedBox(height: 8),
                            const Text('Sin eventos registrados',
                              style: TextStyle(
                                color: AppColors.textSecondary,
                              )),
                          ]),
                        ),
                      ),
                    )
                  else
                    ..._logs.map((log) => _buildLogTile(log)),

                  const SizedBox(height: 24),
                  // ── Info de sincronización ───────────────────
                  if (_estado.ultimaSincronizacion != null)
                    Center(
                      child: Text(
                        'Última sincronización: '
                        '${_fmtFechaHora(_estado.ultimaSincronizacion!)}',
                        style: const TextStyle(
                          color: AppColors.textSecondary,
                          fontSize: 11,
                        ),
                      ),
                    ),
                ],
              ),
            ),
    );
  }

  Widget _buildLogTile(Map<String, dynamic> log) {
    final evento = log['evento']?.toString() ?? '';
    final esBloqueo = evento == 'BLOQUEO';
    final fecha = log['fecha']?.toString() ?? '';
    DateTime? f;
    try { f = DateTime.parse(fecha); } catch (_) {}

    return Card(
      margin: const EdgeInsets.only(bottom: 8),
      child: ListTile(
        leading: Container(
          width: 40, height: 40,
          decoration: BoxDecoration(
            color: (esBloqueo ? AppColors.statusRed : AppColors.statusGreen)
                .withValues(alpha: 0.15),
            borderRadius: BorderRadius.circular(10),
          ),
          child: Icon(
            esBloqueo ? Icons.lock_outline : Icons.lock_open_rounded,
            color: esBloqueo ? AppColors.statusRed : AppColors.statusGreen,
          ),
        ),
        title: Text(
          esBloqueo ? 'Bloqueo del sistema' : 'Desbloqueo del sistema',
          style: const TextStyle(fontWeight: FontWeight.w700),
        ),
        subtitle: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            if (log['motivo'] != null && log['motivo'].toString().isNotEmpty)
              Text(log['motivo'].toString()),
            const SizedBox(height: 2),
            Text(
              'Por: ${log['usuario'] ?? "—"}'
              '${f != null ? "  ·  ${_fmtFechaHora(f)}" : ""}',
              style: const TextStyle(
                fontSize: 11,
                color: AppColors.textSecondary,
              ),
            ),
          ],
        ),
        isThreeLine: true,
      ),
    );
  }

  static String _fmtFechaHora(DateTime d) {
    String pad(int n) => n.toString().padLeft(2, '0');
    return '${pad(d.day)}/${pad(d.month)}/${d.year} '
           '${pad(d.hour)}:${pad(d.minute)}';
  }
}

// ============================================================
//  HELPER: construye el encabezado PDF de la sede
// ============================================================

/// Helper para mostrar "Etiqueta: Valor" en el PDF A4
pw.Widget _pdfDato(String etiqueta, String valor) => pw.RichText(
  text: pw.TextSpan(children: [
    pw.TextSpan(text: "$etiqueta  ",
      style: pw.TextStyle(
        fontSize: 8,
        color: PdfColors.grey600,
        letterSpacing: 0.8)),
    pw.TextSpan(text: valor.isEmpty ? '—' : valor,
      style: pw.TextStyle(
        fontSize: 11,
        fontWeight: pw.FontWeight.bold,
        color: PdfColors.black)),
  ]),
);

// Retira el prefijo "FAC-" del número de factura (para impresión).
// Se usa tanto en el layout A4 como en el layout térmico para asegurar
// que la factura impresa NUNCA muestre el prefijo "FAC", aun si la
// factura fue creada con versiones previas del sistema que lo incluían.
String _sinPrefijoFacGlobal(String nro) {
  final s = nro.trim();
  if (s.toUpperCase().startsWith('FAC-')) return s.substring(4);
  if (s.toUpperCase().startsWith('FAC'))  return s.substring(3).replaceFirst(RegExp(r'^[-\s]+'), '');
  return s;
}

// ────────────────────────────────────────────────────────────────
// Resuelve el NOMBRE REAL del vendedor para impresión.
//
// Problema: algunas facturas (especialmente antiguas) guardan en el
// campo `vendedor` el ROL del usuario (ej: "Vendedor", "Cajero",
// "Administrador") en vez de su nombre real. Esto ocurre porque
// en la BD el campo `nombre` del usuario se registró con el rol,
// o porque el fallback `?? "Vendedor"` se activó al crear la factura.
//
// Este helper intenta recuperar el nombre real:
//   1) Si el valor guardado coincide con el NOMBRE de algún usuario
//      cargado en `usuariosSistema`, se asume que ya es un nombre real
//      y se devuelve tal cual.
//   2) Si coincide con el ROL de exactamente UN usuario (sin ambigüedad),
//      se devuelve el NOMBRE de ese usuario.
//   3) En cualquier otro caso (ambiguo, vacío, no encontrado), se
//      devuelve el valor original para no inventar datos.
//
// Nota: esto NO modifica la BD; solo afecta la impresión de la factura.
String _resolverNombreVendedor(String guardado) {
  final valor = guardado.trim();
  if (valor.isEmpty) return valor;

  // 1) ¿Ya es el nombre de un usuario conocido? → devolver tal cual.
  final coincideNombre = usuariosSistema.any(
      (u) => u.nombre.trim().toLowerCase() == valor.toLowerCase());
  if (coincideNombre) return valor;

  // 2) ¿Coincide con un rol? Buscar usuarios con ese rol.
  final candidatos = usuariosSistema.where(
      (u) => u.rol.trim().toLowerCase() == valor.toLowerCase()).toList();

  if (candidatos.length == 1) {
    // Un único usuario con ese rol: asumimos que fue quien facturó.
    final n = candidatos.first.nombre.trim();
    if (n.isNotEmpty) return n;
  }

  // 3) Ambigüedad o no encontrado: devolver lo que había.
  return valor;
}

pw.Widget _buildEncabezadoPDF(FacturaModel factura, {pw.ImageProvider? logo}) {
  return pw.Column(crossAxisAlignment: pw.CrossAxisAlignment.stretch, children: [
    // ═══════════════════════════════════════════════════════════
    //  ENCABEZADO ELEGANTE — solo logo + badge de garantía
    // ═══════════════════════════════════════════════════════════
    pw.Row(
      crossAxisAlignment: pw.CrossAxisAlignment.center,
      children: [
        // Izquierda: LOGO grande (único elemento de marca)
        pw.Expanded(
          child: pw.Column(
            crossAxisAlignment: pw.CrossAxisAlignment.start,
            children: [
              if (logo != null)
                pw.SizedBox(
                  height: 80,
                  child: pw.Image(logo, fit: pw.BoxFit.contain,
                    alignment: pw.Alignment.centerLeft))
              else
                pw.SizedBox(height: 80),
            ],
          ),
        ),
        pw.SizedBox(width: 16),
        // Derecha: badge GARANTÍA + número + fecha
        pw.Column(
          crossAxisAlignment: pw.CrossAxisAlignment.end,
          children: [
            pw.Container(
              padding: const pw.EdgeInsets.symmetric(horizontal: 16, vertical: 6),
              decoration: const pw.BoxDecoration(
                color: PdfColors.black,
                borderRadius: pw.BorderRadius.all(pw.Radius.circular(3)),
              ),
              child: pw.Text("GARANTÍA",
                style: pw.TextStyle(
                  fontSize: 14,
                  fontWeight: pw.FontWeight.bold,
                  color: PdfColors.white,
                  letterSpacing: 2.5)),
            ),
            pw.SizedBox(height: 6),
            pw.Text(_sinPrefijoFacGlobal(factura.nroFactura),
              style: pw.TextStyle(
                fontSize: 13,
                fontWeight: pw.FontWeight.bold,
                color: PdfColors.black,
                letterSpacing: 0.5)),
            pw.SizedBox(height: 2),
            pw.Text(factura.fecha,
              style: pw.TextStyle(
                fontSize: 10,
                fontWeight: pw.FontWeight.bold,
                color: PdfColors.black)),
          ]),
      ],
    ),
    pw.SizedBox(height: 8),
    // Línea divisoria elegante
    pw.Container(height: 1.2, color: PdfColors.black),
    pw.SizedBox(height: 2),
    pw.Container(height: 0.4, color: PdfColors.grey600),
  ]);
}

// ============================================================
//  HELPER DE IMPRESIÓN ADAPTATIVA
//  Permite imprimir en diferentes tamaños de papel:
//    · A4 / Carta (tamaño estándar de oficina)
//    · Rollo térmico 80mm (ticket POS estándar)
//    · Rollo térmico 58mm (ticket compacto)
//  El usuario elige el formato la primera vez (o puede cambiarlo
//  desde Configuración → Impresión).
// ============================================================
enum FormatoImpresion {
  a4,         // 210 x 297 mm
  carta,      // 215.9 x 279.4 mm (US Letter)
  termica80,  // 80mm de ancho x alto continuo
  termica58,  // 58mm de ancho x alto continuo
  preguntar,  // Preguntar cada vez
}

class ImpresionHelper {
  /// Formato preferido del usuario (se guarda entre sesiones en memoria).
  /// Si es `preguntar`, se mostrará el diálogo antes de cada impresión.
  static FormatoImpresion preferido = FormatoImpresion.preguntar;

  /// Tamaños de página en puntos PDF (1mm = 2.83465 pt)
  ///
  /// IMPORTANTE: las impresoras térmicas tienen un ÁREA IMPRIMIBLE menor
  /// al ancho físico del papel. Para una térmica de 80mm, el área real es
  /// ~72mm; para una de 58mm, es ~48mm. Usamos esos valores reducidos
  /// para que el contenido NUNCA se corte en el borde derecho.
  static PdfPageFormat formatoPdf(FormatoImpresion f) {
    switch (f) {
      case FormatoImpresion.a4:
        return PdfPageFormat.a4;
      case FormatoImpresion.carta:
        return PdfPageFormat.letter;
      case FormatoImpresion.termica80:
        // Ancho 72mm efectivo (no 80mm) y altura double.infinity para que
        // el PDF se ajuste AL CONTENIDO. Usamos infinity en vez de un alto
        // fijo porque algunas facturas largas requieren espacio variable;
        // el rasterizado posterior se encargará de recortar el blanco
        // sobrante. El package pdf interpreta infinity como "el alto del
        // contenido" en pw.Page (no en pw.MultiPage).
        return const PdfPageFormat(
          72 * PdfPageFormat.mm,
          double.infinity,
          marginAll: 2 * PdfPageFormat.mm,
        );
      case FormatoImpresion.termica58:
        return const PdfPageFormat(
          48 * PdfPageFormat.mm,
          double.infinity,
          marginAll: 1.5 * PdfPageFormat.mm,
        );
      case FormatoImpresion.preguntar:
        return PdfPageFormat.a4;
    }
  }

  /// Ancho de caracteres que caben por línea en cada formato.
  /// Ajustado al ancho REAL imprimible (no al papel completo).
  static int charsPorLinea(FormatoImpresion f) {
    switch (f) {
      case FormatoImpresion.termica80: return 36;  // reducido de 40
      case FormatoImpresion.termica58: return 24;  // reducido de 28
      case FormatoImpresion.a4:
      case FormatoImpresion.carta:     return 80;
      case FormatoImpresion.preguntar: return 80;
    }
  }

  /// Indica si el formato es un rollo térmico (sin alto fijo).
  static bool esTermica(FormatoImpresion f) =>
      f == FormatoImpresion.termica80 || f == FormatoImpresion.termica58;

  /// Escala de fuente según formato (1.0 = tamaño base para A4)
  static double escalaFuente(FormatoImpresion f) {
    switch (f) {
      case FormatoImpresion.a4:        return 1.0;
      case FormatoImpresion.carta:     return 1.0;
      case FormatoImpresion.termica80: return 0.78; // reducido de 0.85
      case FormatoImpresion.termica58: return 0.65; // reducido de 0.72
      case FormatoImpresion.preguntar: return 1.0;
    }
  }

  /// Nombre legible
  static String nombre(FormatoImpresion f) {
    switch (f) {
      case FormatoImpresion.a4:        return 'A4 (210 × 297 mm)';
      case FormatoImpresion.carta:     return 'Carta (216 × 279 mm)';
      case FormatoImpresion.termica80: return 'Térmica 80 mm';
      case FormatoImpresion.termica58: return 'Térmica 58 mm';
      case FormatoImpresion.preguntar: return 'Preguntar siempre';
    }
  }

  /// Ícono representativo
  static IconData icono(FormatoImpresion f) {
    switch (f) {
      case FormatoImpresion.a4:
      case FormatoImpresion.carta:     return Icons.description_outlined;
      case FormatoImpresion.termica80:
      case FormatoImpresion.termica58: return Icons.receipt_long_outlined;
      case FormatoImpresion.preguntar: return Icons.help_outline;
    }
  }

  /// Muestra un diálogo para que el usuario elija el formato.
  /// Retorna el formato elegido o null si cancela.
  static Future<FormatoImpresion?> elegirFormato(BuildContext context) async {
    final opciones = [
      FormatoImpresion.a4,
      FormatoImpresion.carta,
      FormatoImpresion.termica80,
      FormatoImpresion.termica58,
    ];
    return showDialog<FormatoImpresion>(
      context: context,
      builder: (ctx) => AlertDialog(
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(16)),
        title: const Row(children: [
          Icon(Icons.print_outlined, color: AppColors.royalBlue),
          SizedBox(width: 8),
          Text('Formato de impresión'),
        ]),
        content: Column(mainAxisSize: MainAxisSize.min,
          children: opciones.map((f) {
            final esActual = preferido == f;
            return InkWell(
              onTap: () => Navigator.pop(ctx, f),
              borderRadius: BorderRadius.circular(10),
              child: Container(
                margin: const EdgeInsets.symmetric(vertical: 4),
                padding: const EdgeInsets.all(12),
                decoration: BoxDecoration(
                  color: esActual ? AppColors.primaryBlue.withValues(alpha: 0.1) : null,
                  borderRadius: BorderRadius.circular(10),
                  border: Border.all(
                    color: esActual ? AppColors.primaryBlue : AppColors.cardBorder,
                    width: esActual ? 1.5 : 1),
                ),
                child: Row(children: [
                  Icon(icono(f), color: AppColors.royalBlue),
                  const SizedBox(width: 12),
                  Expanded(child: Text(nombre(f),
                    style: TextStyle(
                      fontSize: 14,
                      fontWeight: esActual ? FontWeight.bold : FontWeight.normal))),
                  if (esActual)
                    const Icon(Icons.check_circle, color: AppColors.statusGreen, size: 18),
                ]),
              ),
            );
          }).toList(),
        ),
        actions: [
          TextButton(onPressed: () => Navigator.pop(ctx), child: const Text('Cancelar')),
        ],
      ),
    );
  }

  /// Obtiene el formato a usar: si es `preguntar` abre el diálogo;
  /// si ya hay un preferido, lo usa directamente.
  /// Si `forzarPregunta` es true, siempre pregunta.
  static Future<FormatoImpresion?> obtenerFormato(
    BuildContext context, {
    bool forzarPregunta = false,
  }) async {
    if (!forzarPregunta && preferido != FormatoImpresion.preguntar) {
      return preferido;
    }
    final elegido = await elegirFormato(context);
    if (elegido != null) preferido = elegido;
    return elegido;
  }

  /// Imprime un `pw.Document` YA construido adaptando su impresión
  /// al formato elegido. La página DENTRO del documento debe usar
  /// `ImpresionHelper.formatoPdf(formato)` como pageFormat.
  /// Imprime un `pw.Document` YA construido adaptando su impresión
  /// al formato elegido. La página DENTRO del documento debe usar
  /// `ImpresionHelper.formatoPdf(formato)` como pageFormat.
  ///
  /// Usa el flujo "inteligente": si hay impresora BT/USB/del sistema
  /// configurada, imprime directo. Si no, cae al diálogo del sistema.
  static Future<void> imprimirDocumento({
    required BuildContext context,
    required Future<pw.Document> Function(FormatoImpresion formato) construirPdf,
    String nombreArchivo = 'documento',
    bool forzarPregunta = false,
  }) async {
    final formato = await obtenerFormato(context, forzarPregunta: forzarPregunta);
    if (formato == null) return; // usuario canceló

    try {
      final pdf = await construirPdf(formato);
      final bytes = await pdf.save();
      await imprimirPdfInteligente(
        context: context,
        pdfBytes: Uint8List.fromList(bytes),
        formato: formato,
        nombreArchivo: nombreArchivo,
      );
    } catch (e) {
      if (context.mounted) {
        ScaffoldMessenger.of(context).showSnackBar(SnackBar(
          content: Text('Error al imprimir: $e'),
          backgroundColor: AppColors.statusRed));
      }
    }
  }

  /// Guarda bytes PDF pre-generados y los manda a la impresora del
  /// usuario (BT, USB o sistema) sin pasar siempre por el diálogo del SO.
  static Future<void> imprimirBytes({
    required BuildContext context,
    required Uint8List bytes,
    String nombreArchivo = 'documento',
  }) async {
    final formato = await obtenerFormato(context);
    if (formato == null) return;

    await imprimirPdfInteligente(
      context: context,
      pdfBytes: bytes,
      formato: formato,
      nombreArchivo: nombreArchivo,
    );
  }

  /// Envía los bytes de un PDF a la impresora:
  ///  · Si el formato es térmico Y hay impresora Bluetooth preferida,
  ///    intenta imprimir directo por Bluetooth (sin drivers).
  ///  · Si falla o no hay impresora Bluetooth configurada,
  ///    abre el diálogo del sistema como fallback.
  ///
  /// Retorna true si la impresión se envió correctamente.
  /// Envía los bytes de un PDF a la impresora siguiendo el orden de
  /// preferencias:
  ///  1. Impresora **Bluetooth** preferida (térmica directa).
  ///  2. Impresora del **sistema** ya configurada (USB/red en PC).
  ///  3. Diálogo del **sistema operativo** (último recurso).
  ///
  /// Si el usuario tiene una impresora BT/USB configurada, la app
  /// NUNCA mostrará el diálogo del SO — irá directo a esa impresora,
  /// incluso si el formato seleccionado no es térmico.
  ///
  /// Retorna true si la impresión se envió correctamente.
  static Future<bool> imprimirPdfInteligente({
    required BuildContext context,
    required Uint8List pdfBytes,
    required FormatoImpresion formato,
    required String nombreArchivo,
  }) async {
    // ── 1. Bluetooth (impresora térmica configurada) ────────────
    //    Si el usuario tiene una impresora BT preferida, va directo
    //    aquí — incluso si el formato seleccionado es A4/Carta. La
    //    intención del usuario al configurar una impresora BT es
    //    imprimir SIEMPRE por ahí; el diálogo del sistema no debe
    //    aparecer mientras la BT esté configurada.
    //
    // ORDEN IMPORTANTE: primero CONECTAMOS, luego compactamos. Si lo
    // hacemos al revés, la compactación de un PDF mediano puede tardar
    // 3-8 segundos rasterizando, durante los cuales iOS suspende el
    // Bluetooth en background y la conexión muere antes de mandar nada.
    // Conectar primero garantiza tráfico BLE temprano y mantiene viva
    // la conexión hasta el final del job.
    if (ImpresoraBT.macImpresoraPreferida != null) {
      // 1.a) Asegurar conexión activa ANTES de procesar el PDF.
      //      Esto es crítico para que iOS no suspenda el BT durante
      //      la rasterización.
      if (context.mounted) {
        ScaffoldMessenger.of(context).showSnackBar(SnackBar(
          content: Row(children: const [
            SizedBox(width: 18, height: 18,
                child: CircularProgressIndicator(
                    strokeWidth: 2, color: Colors.white)),
            SizedBox(width: 12),
            Text("Conectando con la impresora..."),
          ]),
          duration: const Duration(seconds: 4),
          backgroundColor: AppColors.primaryBlue,
        ));
      }
      bool listo = await ImpresoraBT.estaConectada();
      if (!listo) {
        listo = await ImpresoraBT.conectarPorId(
            ImpresoraBT.macImpresoraPreferida!);
      }
      if (!listo) {
        // Sin conexión no hay forma de imprimir — mostrar error y salir.
        if (context.mounted) {
          ScaffoldMessenger.of(context).hideCurrentSnackBar();
          await showDialog<void>(
            context: context,
            builder: (c) => AlertDialog(
              icon: const Icon(Icons.print_disabled,
                  color: AppColors.statusRed, size: 40),
              title: const Text("No se pudo conectar"),
              content: Text(
                "No fue posible conectar con \"${ImpresoraBT.nombreImpresoraPreferida ?? 'la impresora'}\".\n\n"
                "Verifica:\n"
                "• La impresora está encendida.\n"
                "• Está dentro del rango (Bluetooth ~10 m).\n"
                "• El Bluetooth del teléfono está activo.\n"
                "• La impresora no está siendo usada por otra app.\n\n"
                "Si el problema persiste, vuelve a Configuración → Impresora "
                "y selecciónala de nuevo.",
                style: const TextStyle(fontSize: 13),
              ),
              actions: [
                TextButton(
                  onPressed: () => Navigator.pop(c),
                  child: const Text("Cerrar"),
                ),
              ],
            ),
          );
        }
        return false;
      }

      // 1.b) Compactar PDF (ahora que ya estamos conectados).
      //      La rasterización tarda, pero la conexión BT ya está activa
      //      así que iOS no la suspenderá.
      Uint8List bytesAImprimir = pdfBytes;
      if (!esTermica(formato)) {
        // PDF en A4/Carta pero impresora térmica — recompactar a rollo
        try {
          bytesAImprimir = await _compactarPdfParaTermica(
            pdfBytes,
            anchoMm: ImpresoraBT.anchoPapel,
          );
        } catch (e) {
          debugPrint('[Impresión] compactar para BT no-térmico falló: $e');
        }
      } else {
        // PDF ya térmico — solo ajustar ancho según formato.
        // NO compactamos: el PDF ya viene con dimensiones correctas
        // y rasterizarlo dos veces (una aquí + otra en imprimirPdf)
        // produce artefactos y a veces hace que la impresora rechace
        // los bytes. La página de prueba funciona porque va directo a
        // imprimirPdf SIN pasar por compactación — replicamos ese flujo.
        ImpresoraBT.anchoPapel =
            formato == FormatoImpresion.termica58 ? 58 : 80;
      }

      // 1.c) Enviar a la impresora (conexión sigue viva)
      final ok = await ImpresoraBT.imprimirPdf(bytesAImprimir);
      if (ok) {
        if (context.mounted) {
          ScaffoldMessenger.of(context).hideCurrentSnackBar();
          ScaffoldMessenger.of(context).showSnackBar(SnackBar(
            content: Text("✓ Enviado a ${ImpresoraBT.nombreImpresoraPreferida ?? 'impresora'}"),
            backgroundColor: AppColors.statusGreen,
            duration: const Duration(seconds: 2)));
        }
        return true;
      }
      // BT configurada pero falló al imprimir.
      if (context.mounted) {
        ScaffoldMessenger.of(context).hideCurrentSnackBar();
        await showDialog<void>(
          context: context,
          builder: (c) => AlertDialog(
            icon: const Icon(Icons.print_disabled,
                color: AppColors.statusRed, size: 40),
            title: const Text("No se pudo imprimir"),
            content: Text(
              "Conectó con \"${ImpresoraBT.nombreImpresoraPreferida ?? 'la impresora'}\" "
              "pero la impresión falló a mitad de camino.\n\n"
              "Verifica:\n"
              "• La impresora tiene papel.\n"
              "• La tapa de la impresora está cerrada correctamente.\n"
              "• La batería de la impresora no está crítica.\n\n"
              "Intenta de nuevo. Si persiste, reinicia la impresora.",
              style: const TextStyle(fontSize: 13),
            ),
            actions: [
              TextButton(
                onPressed: () => Navigator.pop(c),
                child: const Text("Cerrar"),
              ),
            ],
          ),
        );
      }
      return false;
    }

    // ── COMPACTACIÓN para flujos sin BT (sistema o diálogo SO) ─
    Uint8List bytesAImprimir = pdfBytes;
    if (esTermica(formato)) {
      try {
        bytesAImprimir = await _compactarPdfParaTermica(
          pdfBytes,
          anchoMm: formato == FormatoImpresion.termica58 ? 58 : 80,
        );
      } catch (e) {
        debugPrint('[Impresión] compactar PDF falló: $e — se usará el original');
      }
    }

    // ── 2. Impresora del sistema (USB conectada a PC, red, etc) ──
    if (ImpresoraSistema.urlImpresoraPreferida != null) {
      final ok = await ImpresoraSistema.imprimirPdf(
        bytesAImprimir,
        nombreArchivo: nombreArchivo,
      );
      if (ok) {
        if (context.mounted) {
          ScaffoldMessenger.of(context).showSnackBar(SnackBar(
            content: Text("✓ Enviado a ${ImpresoraSistema.nombreImpresoraPreferida ?? 'impresora'}"),
            backgroundColor: AppColors.statusGreen,
            duration: const Duration(seconds: 2)));
        }
        return true;
      }
      if (context.mounted) {
        ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
          content: Text("⚠ La impresora del sistema no respondió. Abriendo diálogo del sistema…"),
          backgroundColor: AppColors.statusOrange,
          duration: Duration(seconds: 2)));
      }
    }

    // ── 3. Diálogo estándar del sistema (último recurso) ────────
    //    Solo se llega aquí si NO hay ninguna impresora configurada
    //    en la app, o si las configuradas fallaron.
    await Printing.layoutPdf(
      onLayout: (_) async => bytesAImprimir,
      name: nombreArchivo,
      format: formatoPdf(formato));
    return true;
  }

  /// Convierte un PDF en una sola imagen recortada al contenido y la
  /// vuelve a empaquetar en un PDF nuevo cuya página mide EXACTAMENTE
  /// lo que ocupa el contenido. Esto evita que las impresoras térmicas
  /// alimenten papel sobrante al final (algunos drivers ignoran la
  /// directiva `double.infinity` del PDF original y siguen avanzando
  /// hasta llenar la "página" declarada).
  static Future<Uint8List> _compactarPdfParaTermica(
    Uint8List pdfBytes, {
    required int anchoMm,
  }) async {
    // 1) Rasterizar todas las páginas del PDF en imágenes
    final paginas = <img.Image>[];
    final anchoPx = anchoMm == 58 ? 384 : 576;
    await for (final page in Printing.raster(pdfBytes, dpi: 200)) {
      final png = await page.toPng();
      final dec = img.decodeImage(png);
      if (dec == null) continue;
      final resized = img.copyResize(dec, width: anchoPx);
      paginas.add(_recortarBlancoInferior(resized));
    }
    if (paginas.isEmpty) return pdfBytes;

    // 2) Apilar todas las páginas en una sola imagen vertical
    final altoTotal = paginas.fold<int>(0, (acc, p) => acc + p.height);
    final lienzo = img.Image(width: anchoPx, height: altoTotal,
        backgroundColor: img.ColorRgb8(255, 255, 255));
    int y = 0;
    for (final p in paginas) {
      img.compositeImage(lienzo, p, dstX: 0, dstY: y);
      y += p.height;
    }
    final lienzoRecortado = _recortarBlancoInferior(lienzo);

    // 3) Codificar la imagen y empaquetarla en un PDF de página única
    //    cuya altura sea exactamente la del contenido.
    final pngBytes = img.encodePng(lienzoRecortado);
    final mmPorPx = anchoMm / anchoPx; // mm por píxel
    final altoMm = lienzoRecortado.height * mmPorPx;
    final nuevoPdf = pw.Document();
    final imagenPdf = pw.MemoryImage(Uint8List.fromList(pngBytes));
    nuevoPdf.addPage(pw.Page(
      pageFormat: PdfPageFormat(
        anchoMm * PdfPageFormat.mm,
        altoMm * PdfPageFormat.mm,
        marginAll: 0,
      ),
      build: (_) => pw.Image(imagenPdf, fit: pw.BoxFit.contain),
    ));
    return await nuevoPdf.save();
  }
}

// ============================================================
//  IMPRESORA BLUETOOTH TÉRMICA (sin drivers, protocolo ESC/POS)
//
//  Esta clase permite conectarse DIRECTAMENTE a impresoras
//  térmicas por Bluetooth Classic (SPP) sin instalar drivers
//  ni depender del diálogo de impresión del sistema.
//
//  Funciona con impresoras que soporten ESC/POS:
//   · XPrinter XP-80 / XP-58
//   · Goojprt / Munbyn / Rongta / Zjiang / Bixolon
//   · Epson TM-T20 / TM-T88 Bluetooth
//   · Star TSP / HS-58 / y muchos genéricos chinos de 80mm/58mm
// ============================================================

/// Recorta filas blancas/casi-blancas de los bordes superior E inferior de
/// una imagen. Esto resuelve el problema de recibos térmicos cortos que
/// quedan rasterizados en una página muy alta (la impresora avanza
/// papel proporcional al alto del raster, así que cualquier espacio en
/// blanco se traduce a papel desperdiciado).
///
/// Algoritmo:
///  1. Una fila se considera "con contenido" si tiene al menos 8 píxeles
///     oscuros (luminancia < 150). Esto exige tinta real, no ruido gris.
///  2. Buscamos la PRIMERA y ÚLTIMA fila con contenido.
///  3. Para evitar que líneas perdidas (rayas/manchas/bordes mal
///     rasterizados) extiendan artificialmente el contenido, además
///     verificamos que la última fila no esté aislada: si entre la
///     última fila con contenido y la siguiente hay más de 200px en
///     blanco continuo, asumimos que la "última real" es la de antes.
img.Image _recortarBlancoInferior(img.Image imagen, {int umbralBlanco = 150}) {
  try {
    // Para que una fila se considere "con contenido" debe tener al
    // menos 8 píxeles claramente oscuros (lum < 150). Más estricto que
    // antes para descartar ruido y antialiasing.
    bool filaTieneContenido(int y) {
      int oscuros = 0;
      for (int x = 0; x < imagen.width; x++) {
        final p = imagen.getPixel(x, y);
        final lum = (p.r + p.g + p.b) / 3;
        if (lum < umbralBlanco) {
          oscuros++;
          if (oscuros >= 8) return true;
        }
      }
      return false;
    }

    // 1) Encontrar primera fila con contenido (desde arriba)
    int primeraFila = -1;
    for (int y = 0; y < imagen.height; y++) {
      if (filaTieneContenido(y)) { primeraFila = y; break; }
    }
    if (primeraFila < 0) return imagen; // sin contenido detectable

    // 2) Encontrar la ÚLTIMA fila con contenido REAL (no aislada).
    //    Estrategia: recorremos de abajo hacia arriba, pero si encontramos
    //    una fila con contenido, verificamos que en las siguientes 100 filas
    //    hacia arriba haya al menos 5 filas más con contenido. Si no, era
    //    ruido aislado y seguimos buscando.
    int ultimaFila = -1;
    for (int y = imagen.height - 1; y >= primeraFila; y--) {
      if (!filaTieneContenido(y)) continue;
      // Verificar densidad: contar filas con contenido en los 100px
      // anteriores. Si hay densidad real, es la última genuina.
      int densidad = 0;
      final inicioVerif = (y - 100).clamp(primeraFila, y);
      for (int yy = inicioVerif; yy < y; yy++) {
        if (filaTieneContenido(yy)) {
          densidad++;
          if (densidad >= 3) break; // suficiente densidad
        }
      }
      if (densidad >= 3 || y - primeraFila < 100) {
        ultimaFila = y;
        break;
      }
      // Si no había densidad y la fila estaba "aislada", sigue buscando
      // saltando hacia arriba para no quedar atorado en ruido.
      y = inicioVerif; // continuará en y-- de la siguiente iteración
    }
    if (ultimaFila < 0) ultimaFila = primeraFila;

    if (ultimaFila <= primeraFila) {
      return imagen;
    }

    // Margen: 4px arriba y 8px abajo del contenido real.
    final yInicio = (primeraFila - 4).clamp(0, imagen.height - 1);
    final yFin    = (ultimaFila  + 8).clamp(1, imagen.height);
    final nuevoAlto = yFin - yInicio;
    if (nuevoAlto >= imagen.height && yInicio == 0) return imagen;
    return img.copyCrop(imagen, x: 0, y: yInicio,
        width: imagen.width, height: nuevoAlto);
  } catch (e) {
    debugPrint('[Impresión] Error al recortar blanco: $e');
    return imagen;
  }
}

class ImpresoraBT {
  // ─── Identificadores UUID estándar ESC/POS ──────────────────
  /// UUID del servicio SPP estándar (Serial Port Profile).
  /// La mayoría de impresoras térmicas BLE usan este perfil.
  static const String _uuidServicio = "000018f0-0000-1000-8000-00805f9b34fb";
  /// UUID del característico de escritura (para enviar comandos).
  static const String _uuidCaracteristica = "00002af1-0000-1000-8000-00805f9b34fb";

  // ─── Estado de la impresora preferida ───────────────────────
  /// ID del dispositivo BLE preferido (almacenado en memoria).
  static String? macImpresoraPreferida;
  /// Nombre amigable de la impresora BLE preferida.
  static String? nombreImpresoraPreferida;

  /// Ancho del papel en mm (80 para rollos estándar, 58 para compactos).
  static int anchoPapel = 80;

  /// Referencia al dispositivo conectado actualmente (cache en memoria).
  static BluetoothDevice? _dispositivoActual;
  static BluetoothCharacteristic? _caracteristicaEscritura;

  // ─── Permisos ───────────────────────────────────────────────
  /// Solicita permisos de Bluetooth necesarios (Android 12+).
  ///
  /// Nota técnica: aunque AndroidManifest.xml declare los permisos,
  /// en Android 12+ (API 31) los permisos runtime BLUETOOTH_SCAN,
  /// BLUETOOTH_CONNECT y BLUETOOTH_ADVERTISE deben pedirse EN TIEMPO
  /// DE EJECUCIÓN. Si el usuario los denegó anteriormente, este método
  /// devuelve false y se debe redirigir a ajustes.
  ///
  /// En Android <12 se requiere ACCESS_FINE_LOCATION para escanear BLE,
  /// por eso también se pide Permission.locationWhenInUse.
  static Future<bool> solicitarPermisos() async {
    if (kIsWeb) return false;
    if (!Platform.isAndroid && !Platform.isIOS) return false;
    try {
      // Lista completa de permisos relacionados con BT.
      // Cada uno se pide explícitamente (no vale con tenerlos en el manifest).
      final solicitud = <Permission>[
        Permission.bluetoothConnect,   // Android 12+: conectar a dispositivos
        Permission.bluetoothScan,      // Android 12+: escanear dispositivos
        Permission.bluetoothAdvertise, // Android 12+: anunciar (requerido por algunos flavors)
        Permission.bluetooth,          // Android <12: permiso clásico
        Permission.locationWhenInUse,  // Android <12: BLE scan requiere ubicación
      ];

      final status = await solicitud.request();

      // Diagnóstico detallado — útil para ver en logs qué se denegó
      final denegadosPermanentemente = <String>[];
      status.forEach((permiso, estado) {
        final nombre = permiso.toString().split('.').last;
        debugPrint('[ImpresoraBT] $nombre: $estado');
        if (estado.isPermanentlyDenied) {
          denegadosPermanentemente.add(nombre);
        }
      });

      if (denegadosPermanentemente.isNotEmpty) {
        debugPrint('[ImpresoraBT] ⛔ Permisos denegados PERMANENTEMENTE: '
            '$denegadosPermanentemente. El usuario debe habilitarlos '
            'manualmente en Ajustes → Apps → [Esta app] → Permisos.');
      }

      // Consideramos OK si los 2 críticos están concedidos.
      // (bluetoothAdvertise no siempre es necesario, y bluetooth clásico
      //  solo existe en Android <12)
      final scanOk = status[Permission.bluetoothScan]?.isGranted == true ||
                     status[Permission.bluetooth]?.isGranted == true;
      final connectOk = status[Permission.bluetoothConnect]?.isGranted == true ||
                        status[Permission.bluetooth]?.isGranted == true;
      return scanOk && connectOk;
    } catch (e) {
      debugPrint('[ImpresoraBT] solicitarPermisos error: $e');
      return false;
    }
  }

  /// Verifica si el Bluetooth del dispositivo está activado. Si NO lo está,
  /// intenta encenderlo pidiendo permiso al usuario (Android).
  static Future<bool> bluetoothActivo({bool intentarActivar = true}) async {
    try {
      if (await FlutterBluePlus.isSupported == false) {
        debugPrint('[ImpresoraBT] Dispositivo sin soporte BT');
        return false;
      }
      final estado = await FlutterBluePlus.adapterState.first;
      if (estado == BluetoothAdapterState.on) return true;

      // Intentar activarlo (solo Android; en iOS no está permitido)
      if (intentarActivar && Platform.isAndroid) {
        try {
          debugPrint('[ImpresoraBT] BT apagado, solicitando activación...');
          await FlutterBluePlus.turnOn();
          // Esperar hasta 5s a que cambie el estado
          final nuevoEstado = await FlutterBluePlus.adapterState
              .where((s) => s == BluetoothAdapterState.on)
              .first
              .timeout(const Duration(seconds: 5),
                  onTimeout: () => BluetoothAdapterState.off);
          return nuevoEstado == BluetoothAdapterState.on;
        } catch (e) {
          debugPrint('[ImpresoraBT] No se pudo activar BT: $e');
          return false;
        }
      }
      return false;
    } catch (e) {
      debugPrint('[ImpresoraBT] bluetoothActivo error: $e');
      return false;
    }
  }

  // ─── Escaneo y selección ────────────────────────────────────
  /// Escanea y retorna dispositivos Bluetooth cercanos.
  /// Combina:
  ///  · Dispositivos emparejados con el sistema (bondedDevices) — los más
  ///    importantes para impresoras térmicas que usan SPP/BT Clásico.
  ///  · Dispositivos ya conectados en este momento.
  ///  · Dispositivos detectados por escaneo BLE activo.
  static Future<List<BluetoothDevice>> escanearDispositivos({
    Duration tiempo = const Duration(seconds: 8),
  }) async {
    final List<BluetoothDevice> resultado = [];
    final idsVistos = <String>{};

    try {
      // 1) Dispositivos ya emparejados con el sistema. Las impresoras
      //    térmicas BT-Classic SOLO aparecen aquí (no en escaneo BLE).
      final bonded = await FlutterBluePlus.bondedDevices;
      for (final d in bonded) {
        if (idsVistos.add(d.remoteId.str)) resultado.add(d);
      }
    } catch (e) {
      debugPrint('[ImpresoraBT] bondedDevices: $e');
    }

    try {
      // 2) Dispositivos actualmente conectados (cualquier app).
      final conectados = FlutterBluePlus.connectedDevices;
      for (final d in conectados) {
        if (idsVistos.add(d.remoteId.str)) resultado.add(d);
      }
    } catch (e) {
      debugPrint('[ImpresoraBT] connectedDevices: $e');
    }

    try {
      // 3) Escaneo activo de dispositivos BLE visibles
      await FlutterBluePlus.stopScan();
      await FlutterBluePlus.startScan(timeout: tiempo);

      final sub = FlutterBluePlus.scanResults.listen((results) {
        for (final r in results) {
          if (idsVistos.add(r.device.remoteId.str)) {
            resultado.add(r.device);
          }
        }
      });

      // Esperar que termine el escaneo
      await Future.delayed(tiempo);
      await sub.cancel();
      await FlutterBluePlus.stopScan();
    } catch (e) {
      debugPrint('[ImpresoraBT] escaneo: $e');
    }

    return resultado;
  }

  // ─── Conexión ───────────────────────────────────────────────
  /// Conecta a un dispositivo por su remoteId.
  ///
  /// Maneja casos edge:
  /// - Si ya está conectado al MISMO dispositivo, no hace nada y reusa
  ///   la conexión (evita "ya conectado" errors en flutter_blue_plus).
  /// - Si está conectado a OTRO dispositivo, lo desconecta primero.
  /// - Si la llamada `connect()` lanza "already connected", lo trata
  ///   como éxito (es un caso normal cuando iOS persiste el bond).
  static Future<bool> conectar(BluetoothDevice device) async {
    try {
      final targetId = device.remoteId.str;
      debugPrint('[ImpresoraBT] Conectando a $targetId...');

      // Si ya estamos conectados al MISMO dispositivo y tenemos
      // characteristic, reusar la conexión existente.
      if (_dispositivoActual != null &&
          _dispositivoActual!.remoteId.str == targetId &&
          _caracteristicaEscritura != null) {
        try {
          // Verificar que la conexión siga viva
          final estado = await _dispositivoActual!.connectionState.first
              .timeout(const Duration(seconds: 1),
                  onTimeout: () => BluetoothConnectionState.disconnected);
          if (estado == BluetoothConnectionState.connected) {
            debugPrint('[ImpresoraBT] Ya conectado al mismo dispositivo, reusando');
            return true;
          }
        } catch (_) {/* sigue al flujo normal de conexión */}
      }

      // Desconectar el dispositivo anterior si era distinto
      if (_dispositivoActual != null &&
          _dispositivoActual!.remoteId.str != targetId) {
        try { await _dispositivoActual!.disconnect(); } catch (_) {}
        _dispositivoActual = null;
        _caracteristicaEscritura = null;
      }

      // Conectar con timeout generoso. Si el SO ya tiene el bond del
      // dispositivo, la llamada puede lanzar "already connected" — lo
      // ignoramos porque significa que ya estamos OK.
      try {
        await device.connect(
          timeout: const Duration(seconds: 15),
          autoConnect: false);
      } catch (e) {
        final msg = e.toString().toLowerCase();
        if (msg.contains('already') && msg.contains('connect')) {
          debugPrint('[ImpresoraBT] Ya conectado a nivel SO (ignorando excepción)');
        } else {
          rethrow;
        }
      }

      // Descubrir servicios y buscar un characteristic con write
      final servicios = await device.discoverServices();
      BluetoothCharacteristic? writeChar;

      // Preferir SPP estándar si existe
      for (final srv in servicios) {
        for (final ch in srv.characteristics) {
          if (ch.properties.write || ch.properties.writeWithoutResponse) {
            writeChar = ch;
            // Si además coincide con el UUID estándar, lo preferimos
            if (ch.uuid.toString().toLowerCase().contains(
                _uuidCaracteristica.substring(4, 8))) {
              _dispositivoActual = device;
              _caracteristicaEscritura = ch;
              debugPrint('[ImpresoraBT] Conectado (SPP): ${ch.uuid}');
              return true;
            }
          }
        }
      }

      if (writeChar == null) {
        debugPrint('[ImpresoraBT] ⚠ No se encontró characteristic writable');
        return false;
      }

      _dispositivoActual = device;
      _caracteristicaEscritura = writeChar;
      debugPrint('[ImpresoraBT] Conectado (genérico): ${writeChar.uuid}');
      return true;
    } catch (e) {
      debugPrint('[ImpresoraBT] conectar error: $e');
      return false;
    }
  }

  /// Conecta usando el remoteId guardado en SharedPreferences.
  ///
  /// En iOS, `BluetoothDevice.fromId()` crea un wrapper sobre un UUID
  /// que puede no estar en el cache del CoreBluetooth si la conexión
  /// anterior se cerró hace rato. Por eso, antes de intentar conectar,
  /// buscamos el dispositivo en la lista de `bondedDevices` (los que
  /// el SO recuerda) — eso "calienta" el cache del SO.
  ///
  /// Si el dispositivo no está en bonded, igual intentamos `fromId()`
  /// como fallback (puede funcionar si el SO mantiene el UUID en su
  /// cache de sesiones recientes).
  static Future<bool> conectarPorId(String remoteId) async {
    try {
      // Estrategia 1: buscar en dispositivos emparejados/conocidos.
      // Esto refresca el cache del SO y devuelve un objeto BluetoothDevice
      // con metadatos completos (no solo el ID).
      try {
        final bonded = await FlutterBluePlus.bondedDevices;
        for (final d in bonded) {
          if (d.remoteId.str == remoteId) {
            debugPrint('[ImpresoraBT] Encontrado en bondedDevices');
            return await conectar(d);
          }
        }
      } catch (e) {
        debugPrint('[ImpresoraBT] bondedDevices error: $e');
      }

      // Estrategia 2: revisar dispositivos ya conectados al sistema.
      try {
        final connected = FlutterBluePlus.connectedDevices;
        for (final d in connected) {
          if (d.remoteId.str == remoteId) {
            debugPrint('[ImpresoraBT] Ya conectado al SO');
            return await conectar(d);
          }
        }
      } catch (e) {
        debugPrint('[ImpresoraBT] connectedDevices error: $e');
      }

      // Estrategia 3: fallback con fromId (puede o no funcionar).
      debugPrint('[ImpresoraBT] No estaba en bonded/connected, '
          'intentando fromId como fallback');
      final device = BluetoothDevice.fromId(remoteId);
      return await conectar(device);
    } catch (e) {
      debugPrint('[ImpresoraBT] conectarPorId error: $e');
      return false;
    }
  }

  /// Verifica si hay una conexión activa CON el dispositivo preferido.
  ///
  /// Bug histórico arreglado: la versión anterior tenía
  ///   `return await estado == BluetoothConnectionState.connected`
  /// que por precedencia de operadores se evaluaba como
  ///   `await (Future<...> == enum)` → siempre false.
  /// Esto causaba que la app reconectara en CADA impresión incluso
  /// cuando ya había conexión, y en iOS las reconexiones por ID
  /// pueden fallar (los remoteId no son tan estables como en Android).
  static Future<bool> estaConectada() async {
    try {
      if (_dispositivoActual == null) return false;
      // Obtener el estado actual (no el Stream completo) — usamos
      // .first.timeout para no quedarnos esperando indefinidamente
      // si el stream nunca emite.
      final estado = await _dispositivoActual!.connectionState.first
          .timeout(const Duration(seconds: 2),
              onTimeout: () => BluetoothConnectionState.disconnected);
      return estado == BluetoothConnectionState.connected;
    } catch (_) {
      return false;
    }
  }

  /// Desconecta el dispositivo actual.
  static Future<void> desconectar() async {
    try {
      if (_dispositivoActual != null) {
        await _dispositivoActual!.disconnect();
      }
    } catch (_) {}
    _dispositivoActual = null;
    _caracteristicaEscritura = null;
  }

  // ─── Persistencia de la impresora preferida ─────────────────
  // CRÍTICO: sin esto, los campos `macImpresoraPreferida` y
  // `nombreImpresoraPreferida` solo viven en memoria. Cuando el usuario
  // selecciona una impresora desde Configuración y luego cierra la app,
  // al volver a abrirla las variables son null y `imprimirPdfInteligente`
  // se salta el bloque BT — entonces parece que "no se conecta a la
  // impresora configurada" cuando en realidad la app olvidó cuál era.

  /// Persiste la impresora preferida actual en SharedPreferences.
  static Future<void> guardarPreferida() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      if (macImpresoraPreferida == null) {
        await prefs.remove('impresora_bt_mac');
        await prefs.remove('impresora_bt_nombre');
        await prefs.remove('impresora_bt_ancho');
      } else {
        await prefs.setString('impresora_bt_mac', macImpresoraPreferida!);
        await prefs.setString('impresora_bt_nombre',
            nombreImpresoraPreferida ?? 'Impresora BT');
        await prefs.setInt('impresora_bt_ancho', anchoPapel);
      }
    } catch (e) {
      debugPrint('[ImpresoraBT] guardarPreferida error: $e');
    }
  }

  /// Carga la impresora preferida desde SharedPreferences. Se llama al
  /// arrancar la app desde main(). Si no hay nada guardado, deja los
  /// campos en null (comportamiento idéntico a no tener impresora).
  static Future<void> cargarPreferida() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      macImpresoraPreferida = prefs.getString('impresora_bt_mac');
      nombreImpresoraPreferida = prefs.getString('impresora_bt_nombre');
      anchoPapel = prefs.getInt('impresora_bt_ancho') ?? 80;
      if (macImpresoraPreferida != null) {
        debugPrint('[ImpresoraBT] Preferida restaurada: '
            '$nombreImpresoraPreferida ($macImpresoraPreferida) '
            'ancho=${anchoPapel}mm');
      }
    } catch (e) {
      debugPrint('[ImpresoraBT] cargarPreferida error: $e');
      macImpresoraPreferida = null;
      nombreImpresoraPreferida = null;
    }
  }

  /// Limpia la impresora preferida (memoria y disco). Se llama desde la
  /// UI cuando el usuario pulsa "Quitar impresora".
  static Future<void> limpiarPreferida() async {
    macImpresoraPreferida = null;
    nombreImpresoraPreferida = null;
    await guardarPreferida(); // persiste el null (borra las claves)
  }

  // ─── Envío de datos ─────────────────────────────────────────
  /// Envía bytes a la impresora en chunks (BLE tiene límite de 180-512 bytes).
  static Future<bool> enviarBytes(List<int> bytes) async {
    try {
      if (_caracteristicaEscritura == null) {
        debugPrint('[ImpresoraBT] No hay characteristic activa');
        return false;
      }
      // Chunk de 180 bytes (seguro para la mayoría de dispositivos BLE)
      const chunkSize = 180;
      for (var i = 0; i < bytes.length; i += chunkSize) {
        final fin = (i + chunkSize < bytes.length) ? i + chunkSize : bytes.length;
        final chunk = bytes.sublist(i, fin);
        await _caracteristicaEscritura!.write(
          chunk,
          withoutResponse: _caracteristicaEscritura!.properties.writeWithoutResponse);
        // Pequeña pausa para no saturar el buffer de la impresora
        await Future.delayed(const Duration(milliseconds: 20));
      }
      return true;
    } catch (e) {
      debugPrint('[ImpresoraBT] enviarBytes error: $e');
      return false;
    }
  }

  // ─── Impresión de PDF → ESC/POS ─────────────────────────────
  /// Imprime un PDF convirtiéndolo a comandos ESC/POS.
  /// El PDF debe haber sido generado con formato térmico (80 o 58mm).
  ///
  /// Al terminar:
  ///  · Espera a que la impresora drene el buffer (los chunks se envían
  ///    con un delay, pero la última escritura aún puede estar en
  ///    tránsito cuando retornamos).
  ///  · Envía un comando explícito de cierre de trabajo (init + cut).
  ///  · Desconecta del dispositivo BLE para liberar el GATT y permitir
  ///    que el siguiente trabajo se conecte limpiamente. Sin esto,
  ///    algunas impresoras quedan en estado "ocupado" y siguen
  ///    alimentando papel hasta el siguiente reset.
  static Future<bool> imprimirPdf(Uint8List pdfBytes, {int? ancho}) async {
    bool ok = false;
    try {
      final anchoFinal = ancho ?? anchoPapel;

      // 1) Generador ESC/POS
      final perfil = await CapabilityProfile.load();
      final papelEnum = anchoFinal == 58 ? PaperSize.mm58 : PaperSize.mm80;
      final generador = Generator(papelEnum, perfil);

      // 2) Rasterizar cada página del PDF a imagen
      final List<int> bytes = [];
      // Iniciar con reset para limpiar cualquier estado previo
      bytes.addAll(generador.reset());

      await for (final page in Printing.raster(pdfBytes, dpi: 200)) {
        final imgBytes = await page.toPng();
        final imagen = img.decodeImage(imgBytes);
        if (imagen == null) continue;

        // Re-escalar al ancho físico de la impresora
        // (576 px para 80mm, 384 px para 58mm a 203 dpi de la impresora)
        final anchoPx = anchoFinal == 58 ? 384 : 576;
        final imgResize = img.copyResize(imagen, width: anchoPx);

        // Recortar las filas blancas/aisladas tanto arriba como abajo
        // del contenido real. Es CRÍTICO para no desperdiciar papel —
        // muchos PDFs térmicos se renderizan con páginas enormes y la
        // impresora avanza papel proporcional al alto del raster.
        var imgRecortada = _recortarBlancoInferior(imgResize);

        // Salvavidas final: si después del recorte la imagen sigue
        // siendo MUCHO más alta que el ancho (proporción >5:1), es
        // señal de que sobrevivió mucho blanco. Forzamos un segundo
        // recorte más estricto buscando la última columna densa.
        if (imgRecortada.height > imgRecortada.width * 5) {
          imgRecortada = _recortarBlancoInferior(imgRecortada,
              umbralBlanco: 130);
        }

        // Convertir imagen a bytes ESC/POS (raster mode)
        bytes.addAll(generador.image(imgRecortada));
      }

      // 3) Alimentar SOLO lo necesario para que el corte no se trague
      //    la última línea (3 puntos = ~1mm). Antes era feed(1) que
      //    avanza una línea entera (~3mm).
      bytes.addAll(generador.feed(1));
      bytes.addAll(generador.cut());
      // Reset final: previene que la impresora interprete los próximos
      // bytes que reciba (de cualquier app) con formato heredado.
      bytes.addAll(generador.reset());

      // 4) Si no hay conexión, reconectar con la impresora preferida.
      //    Hacemos hasta 2 intentos: el segundo es un escaneo previo
      //    (a veces iOS pierde el "cache" del dispositivo y necesita
      //    re-descubrirlo antes de que `BluetoothDevice.fromId` funcione).
      final conectada = await estaConectada();
      if (!conectada) {
        if (macImpresoraPreferida == null) {
          debugPrint('[ImpresoraBT] No hay impresora preferida configurada');
          return false;
        }
        debugPrint('[ImpresoraBT] No conectado, reconectando a '
            '$macImpresoraPreferida...');
        var ok2 = await conectarPorId(macImpresoraPreferida!);
        if (!ok2) {
          // Segundo intento: escanear primero para refrescar el cache
          // del SO y luego volver a conectar. Útil en iOS sobre todo,
          // donde los UUIDs de dispositivo pueden invalidarse.
          debugPrint('[ImpresoraBT] Primer intento falló, '
              'escaneando antes del segundo intento...');
          try {
            await escanearDispositivos(
                tiempo: const Duration(seconds: 4));
          } catch (_) {/**/}
          ok2 = await conectarPorId(macImpresoraPreferida!);
          if (!ok2) {
            debugPrint('[ImpresoraBT] Segundo intento de reconexión '
                'también falló. La impresora puede estar apagada o '
                'fuera de rango.');
            return false;
          }
        }
        debugPrint('[ImpresoraBT] Reconexión exitosa');
      }

      // 5) Enviar a la impresora
      ok = await enviarBytes(bytes);

      // 6) Esperar a que la impresora drene el buffer y procese el cut.
      //    700ms son suficientes para que la cuchilla termine de cortar
      //    físicamente antes de que cerremos el enlace BT. Si cerramos
      //    antes, algunas impresoras dejan el job a medias.
      await Future.delayed(const Duration(milliseconds: 700));
      return ok;
    } catch (e) {
      debugPrint('[ImpresoraBT] imprimirPdf error: $e');
      return false;
    } finally {
      // CRÍTICO: desconectar al final del trabajo.
      //
      // Por qué hay que desconectar:
      //   1) La impresora térmica interpreta el GATT abierto como
      //      "trabajo en curso" — queda con luz de actividad permanente.
      //   2) En iOS, mantener una conexión BLE abierta sin tráfico
      //      hace que el SO la suspenda en background, dejando el
      //      objeto `_dispositivoActual` apuntando a un socket muerto.
      //      La siguiente impresión falla con "no conectada".
      //
      // Por qué no era problema antes:
      //   La página de prueba va por un camino directo — conecta y
      //   manda bytes sin pasar por estados intermedios. Las facturas
      //   pasan por la lógica de reconexión, donde el bug se manifiesta.
      //
      // Hacer la desconexión SIEMPRE (en finally) garantiza que cada
      // impresión empieza desde estado limpio.
      try {
        await desconectar();
        // Pequeña pausa para que el SO procese el cierre y libere
        // recursos antes de la próxima conexión.
        await Future.delayed(const Duration(milliseconds: 200));
      } catch (_) {}
    }
  }

  // ─── Diálogo de selección de impresora ──────────────────────
  /// Muestra un diálogo con las impresoras Bluetooth disponibles
  /// y guarda la selección como preferida. Incluye botón de escaneo.
  static Future<bool> seleccionarImpresoraDialog(BuildContext context) async {
    // 1) Permisos
    final permisos = await solicitarPermisos();
    if (!permisos) {
      if (context.mounted) {
        // Diálogo con botón para ir a Ajustes (los permisos pueden estar
        // denegados permanentemente y el SO ya no mostrará el prompt).
        final irAAjustes = await showDialog<bool>(
          context: context,
          builder: (c) => AlertDialog(
            icon: const Icon(Icons.bluetooth_disabled,
                color: AppColors.statusRed, size: 40),
            title: const Text("Permisos de Bluetooth"),
            content: const Text(
              "La app no tiene los permisos necesarios para usar Bluetooth.\n\n"
              "Esto suele pasar cuando se pulsó 'Denegar' anteriormente. "
              "Abre los ajustes del sistema y habilita:\n\n"
              "  • Dispositivos cercanos (Bluetooth)\n"
              "  • Ubicación (para escanear)\n\n"
              "¿Abrir ajustes ahora?",
              style: TextStyle(fontSize: 13),
            ),
            actions: [
              TextButton(
                onPressed: () => Navigator.pop(c, false),
                child: const Text("Cancelar"),
              ),
              ElevatedButton.icon(
                icon: const Icon(Icons.settings, size: 18),
                label: const Text("Abrir ajustes"),
                onPressed: () => Navigator.pop(c, true),
              ),
            ],
          ),
        );
        if (irAAjustes == true) {
          await openAppSettings();
        }
      }
      return false;
    }

    // 2) Bluetooth activo (con intento automático de encenderlo)
    final activo = await bluetoothActivo(intentarActivar: true);
    if (!activo) {
      if (context.mounted) {
        ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
          content: Text("No se pudo activar el Bluetooth. Actívalo manualmente desde los ajustes rápidos del teléfono."),
          backgroundColor: AppColors.statusOrange,
          duration: Duration(seconds: 4)));
      }
      return false;
    }

    if (!context.mounted) return false;

    // 3) Abrir diálogo con escaneo en vivo
    BluetoothDevice? seleccionado;
    bool escaneando = true;
    List<BluetoothDevice> dispositivos = [];

    await showDialog(
      context: context,
      barrierDismissible: false,
      builder: (c) => StatefulBuilder(builder: (dialogCtx, setS) {
        // Escaneo inicial al abrir diálogo
        if (escaneando && dispositivos.isEmpty) {
          escanearDispositivos(tiempo: const Duration(seconds: 6))
              .then((lista) {
                if (dialogCtx.mounted) {
                  setS(() {
                    dispositivos = lista;
                    escaneando = false;
                  });
                }
              });
        }

        return AlertDialog(
          title: Row(children: [
            const Icon(Icons.bluetooth_searching, color: AppColors.primaryBlue),
            const SizedBox(width: 8),
            const Expanded(child: Text("Seleccionar impresora")),
            if (escaneando)
              const SizedBox(width: 18, height: 18,
                child: CircularProgressIndicator(strokeWidth: 2)),
          ]),
          content: SizedBox(
            width: double.maxFinite,
            child: dispositivos.isEmpty
              ? Padding(
                  padding: const EdgeInsets.all(16),
                  child: Column(mainAxisSize: MainAxisSize.min, children: [
                    const Icon(Icons.bluetooth_disabled,
                        size: 48, color: Colors.grey),
                    const SizedBox(height: 10),
                    Text(escaneando
                      ? "Buscando impresoras..."
                      : "No se encontraron impresoras",
                      style: const TextStyle(
                        fontSize: 14, fontWeight: FontWeight.bold,
                        color: AppColors.textPrimary),
                      textAlign: TextAlign.center),
                    if (!escaneando) ...[
                      const SizedBox(height: 12),
                      Container(
                        padding: const EdgeInsets.all(10),
                        decoration: BoxDecoration(
                          color: AppColors.brandBlue.withValues(alpha: 0.08),
                          borderRadius: BorderRadius.circular(8),
                          border: Border.all(color: AppColors.brandBlue.withValues(alpha: 0.3)!),
                        ),
                        child: const Column(
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: [
                            Row(children: [
                              Icon(Icons.info_outline,
                                  size: 16, color: AppColors.brandBlue),
                              SizedBox(width: 6),
                              Expanded(child: Text("Pasos para conectar:",
                                style: TextStyle(
                                  fontSize: 12, fontWeight: FontWeight.bold,
                                  color: AppColors.brandBlue))),
                            ]),
                            SizedBox(height: 8),
                            Text(
                              "1. Enciende la impresora térmica\n"
                              "2. Empareja la impresora desde\n"
                              "    Ajustes del sistema → Bluetooth\n"
                              "3. Vuelve aquí y toca \"Buscar de nuevo\"",
                              style: TextStyle(fontSize: 11.5,
                                color: AppColors.textPrimary, height: 1.4)),
                            SizedBox(height: 8),
                            Text(
                              "Nota: muchas impresoras térmicas usan "
                              "Bluetooth Clásico (SPP), no BLE. DEBEN "
                              "estar emparejadas en los ajustes del "
                              "sistema para que la app las detecte.",
                              style: TextStyle(fontSize: 10.5,
                                fontStyle: FontStyle.italic,
                                color: AppColors.textSecondary)),
                          ],
                        ),
                      ),
                    ],
                  ]))
              : ListView.builder(
                  shrinkWrap: true,
                  itemCount: dispositivos.length,
                  itemBuilder: (_, i) {
                    final d = dispositivos[i];
                    final nombre = d.platformName.isNotEmpty
                      ? d.platformName : d.advName.isNotEmpty
                      ? d.advName : "Sin nombre";
                    final esActual = d.remoteId.str == macImpresoraPreferida;
                    return ListTile(
                      leading: Icon(Icons.print_outlined,
                        color: esActual ? AppColors.statusGreen : AppColors.primaryBlue),
                      title: Text(nombre,
                        style: TextStyle(
                          fontWeight: esActual ? FontWeight.bold : FontWeight.normal)),
                      subtitle: Text(d.remoteId.str,
                        style: const TextStyle(fontSize: 11,
                          color: AppColors.textSecondary)),
                      trailing: esActual
                        ? const Icon(Icons.check_circle, color: AppColors.statusGreen)
                        : null,
                      onTap: () { seleccionado = d; Navigator.pop(c); },
                    );
                  },
                ),
          ),
          actions: [
            TextButton.icon(
              icon: const Icon(Icons.refresh, size: 18),
              label: const Text("Buscar de nuevo"),
              onPressed: escaneando ? null : () {
                setS(() {
                  escaneando = true;
                  dispositivos = [];
                });
              }),
            TextButton(onPressed: () => Navigator.pop(c),
              child: const Text("Cancelar")),
          ],
        );
      }),
    );

    if (seleccionado == null) return false;

    final nombre = seleccionado!.platformName.isNotEmpty
      ? seleccionado!.platformName : seleccionado!.advName;
    macImpresoraPreferida = seleccionado!.remoteId.str;
    nombreImpresoraPreferida = nombre.isEmpty ? "Impresora BT" : nombre;

    // Persistir en SharedPreferences para que sobreviva al cierre
    // de la app. Sin este paso, la próxima vez que el usuario abra
    // la app la impresora preferida estará en null y `imprimirPdf
    // Inteligente` se saltará el bloque Bluetooth.
    await guardarPreferida();

    // Probar conexión
    final conectado = await conectar(seleccionado!);
    if (context.mounted) {
      ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Text(conectado
          ? "✓ Conectado a $nombreImpresoraPreferida"
          : "⚠ No se pudo conectar a $nombreImpresoraPreferida"),
        backgroundColor: conectado
          ? AppColors.statusGreen : AppColors.statusRed));
    }
    return conectado;
  }
}

// ============================================================
//  IMPRESORA USB TÉRMICA (conexión directa via USB OTG)
// ============================================================
class ImpresoraUSB {
  static UsbPort? _puerto;
  static UsbDevice? _dispositivoActual;

  /// Lista los dispositivos USB conectados (cables OTG en Android).
  static Future<List<UsbDevice>> listarDispositivos() async {
    try {
      return await UsbSerial.listDevices();
    } catch (e) {
      debugPrint('[ImpresoraUSB] listarDispositivos: $e');
      return [];
    }
  }

  /// Conecta a un dispositivo USB específico.
  static Future<bool> conectar(UsbDevice dispositivo) async {
    try {
      _puerto = await dispositivo.create();
      if (_puerto == null) return false;
      final abierto = await _puerto!.open();
      if (!abierto) { _puerto = null; return false; }
      await _puerto!.setDTR(true);
      await _puerto!.setRTS(true);
      await _puerto!.setPortParameters(
        9600, UsbPort.DATABITS_8, UsbPort.STOPBITS_1, UsbPort.PARITY_NONE);
      _dispositivoActual = dispositivo;
      return true;
    } catch (e) {
      debugPrint('[ImpresoraUSB] conectar error: $e');
      return false;
    }
  }

  /// Desconecta el puerto USB.
  static Future<void> desconectar() async {
    try { await _puerto?.close(); } catch (_) {}
    _puerto = null;
    _dispositivoActual = null;
  }

  /// Envía bytes por USB.
  static Future<bool> enviarBytes(List<int> bytes) async {
    try {
      if (_puerto == null) return false;
      await _puerto!.write(Uint8List.fromList(bytes));
      return true;
    } catch (e) {
      debugPrint('[ImpresoraUSB] enviarBytes error: $e');
      return false;
    }
  }

  /// Imprime un PDF convirtiéndolo a ESC/POS y enviándolo por USB.
  /// Al terminar drena el buffer y cierra el puerto para que el sistema
  /// marque el job como finalizado y no quede alimentando papel.
  static Future<bool> imprimirPdf(Uint8List pdfBytes, {int ancho = 80}) async {
    bool ok = false;
    try {
      final perfil = await CapabilityProfile.load();
      final papelEnum = ancho == 58 ? PaperSize.mm58 : PaperSize.mm80;
      final generador = Generator(papelEnum, perfil);

      final List<int> bytes = [];
      // Reset inicial: elimina cualquier estado heredado.
      bytes.addAll(generador.reset());

      await for (final page in Printing.raster(pdfBytes, dpi: 200)) {
        final imgBytes = await page.toPng();
        final imagen = img.decodeImage(imgBytes);
        if (imagen == null) continue;
        final anchoPx = ancho == 58 ? 384 : 576;
        final imgResize = img.copyResize(imagen, width: anchoPx);
        // Recortar espacio en blanco para no desperdiciar papel.
        var imgRecortada = _recortarBlancoInferior(imgResize);
        // Salvavidas: si quedó muy alta proporcionalmente, recortar más.
        if (imgRecortada.height > imgRecortada.width * 5) {
          imgRecortada = _recortarBlancoInferior(imgRecortada,
              umbralBlanco: 130);
        }
        bytes.addAll(generador.image(imgRecortada));
      }
      bytes.addAll(generador.feed(1));
      bytes.addAll(generador.cut());
      // Reset final: cierra el trabajo limpiamente.
      bytes.addAll(generador.reset());

      ok = await enviarBytes(bytes);
      // Esperar a que la impresora termine de procesar antes de soltar
      // el puerto; si lo cerramos demasiado rápido, algunas impresoras
      // siguen alimentando papel hasta el siguiente reset.
      await Future.delayed(const Duration(milliseconds: 400));
      return ok;
    } catch (e) {
      debugPrint('[ImpresoraUSB] imprimirPdf error: $e');
      return false;
    } finally {
      // Cerrar el puerto para finalizar el trabajo. Esto libera el
      // dispositivo para el siguiente job y evita papel en blanco.
      try { await desconectar(); } catch (_) {}
    }
  }
}

// ============================================================
//  IMPRESORA DEL SISTEMA (USB conectada a la PC, red, AirPrint)
//
//  A diferencia de ImpresoraBT (BLE) e ImpresoraUSB (USB-OTG en
//  Android), esta clase usa el sistema de impresión NATIVO del
//  sistema operativo via el paquete `printing`. Esto permite:
//
//    · Windows: cualquier impresora instalada en el panel de
//      control (USB, red, compartida).
//    · macOS: cualquier impresora del sistema (CUPS).
//    · Linux: CUPS.
//    · Android: integración con servicios de impresión Mopria,
//      HP Print, Samsung Mobile Print, etc.
//    · iOS: AirPrint.
//
//  Es la opción RECOMENDADA cuando la impresora está conectada
//  físicamente a la PC por USB, porque evita el problema de
//  drivers USB-OTG (que solo funciona en Android conectado
//  directamente a la impresora con un cable OTG, no a la PC).
// ============================================================
class ImpresoraSistema {
  /// Nombre/URL de la impresora preferida del sistema. Persiste
  /// en SharedPreferences. Si está vacío, se mostrará el diálogo
  /// del sistema (selector estándar) al imprimir.
  static String? nombreImpresoraPreferida;
  static String? urlImpresoraPreferida;

  /// Listar las impresoras disponibles en el sistema.
  static Future<List<Printer>> listarImpresoras() async {
    try {
      return await Printing.listPrinters();
    } catch (e) {
      debugPrint('[ImpresoraSistema] listarImpresoras: $e');
      return [];
    }
  }

  /// Imprime un PDF directamente en la impresora preferida (sin
  /// mostrar diálogo). Si no hay impresora configurada o la URL
  /// es inválida, retorna false.
  static Future<bool> imprimirPdf(Uint8List pdfBytes,
      {String? nombreArchivo}) async {
    try {
      if (urlImpresoraPreferida == null || urlImpresoraPreferida!.isEmpty) {
        return false;
      }
      final printers = await Printing.listPrinters();
      final p = printers.where((x) => x.url == urlImpresoraPreferida)
          .firstOrNull;
      if (p == null) {
        debugPrint('[ImpresoraSistema] La impresora preferida ya no existe en el sistema.');
        return false;
      }
      return await Printing.directPrintPdf(
        printer: p,
        onLayout: (_) async => pdfBytes,
        name: nombreArchivo ?? 'Documento',
      );
    } catch (e) {
      debugPrint('[ImpresoraSistema] imprimirPdf: $e');
      return false;
    }
  }

  /// Persiste la impresora elegida en SharedPreferences.
  static Future<void> guardarPreferida(Printer p) async {
    nombreImpresoraPreferida = p.name;
    urlImpresoraPreferida = p.url;
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString('impresora_sistema_url', p.url);
      await prefs.setString('impresora_sistema_nombre', p.name);
    } catch (_) {}
  }

  /// Carga la preferida desde SharedPreferences (al iniciar la app).
  static Future<void> cargarPreferida() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      urlImpresoraPreferida = prefs.getString('impresora_sistema_url');
      nombreImpresoraPreferida = prefs.getString('impresora_sistema_nombre');
    } catch (_) {}
  }

  /// Olvida la impresora preferida.
  static Future<void> olvidarPreferida() async {
    nombreImpresoraPreferida = null;
    urlImpresoraPreferida = null;
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.remove('impresora_sistema_url');
      await prefs.remove('impresora_sistema_nombre');
    } catch (_) {}
  }
}

// ============================================================
//  FACTURA PDF
// ============================================================
Future<File?> generarFacturaPDF(FacturaModel factura) async {
  if (kIsWeb) return null; // File no disponible en web
  final pdf = pw.Document();
  final tasa = ConfigSistema.tasaCambio;
  final totalBs = factura.total * tasa;

  // Cargar logo de la sede si existe
  pw.ImageProvider? logo;
  final enc = ConfigSistema.encabezadoDe(factura.tienda);
  if (enc.logoBytes != null) {
    try { logo = pw.MemoryImage(enc.logoBytes!); } catch (_) {}
  }

  pdf.addPage(pw.Page(
    pageFormat: PdfPageFormat.a4,
    margin: const pw.EdgeInsets.all(36),
    build: (pw.Context context) {
      return pw.Column(crossAxisAlignment: pw.CrossAxisAlignment.start, children: [
        // ── Encabezado con logo y datos de sede ──────────────
        _buildEncabezadoPDF(factura, logo: logo),
        pw.SizedBox(height: 14),

        // ── Datos del cliente ────────────────────────────────
        pw.Container(
          padding: const pw.EdgeInsets.all(10),
          decoration: pw.BoxDecoration(
            color: PdfColors.grey100,
            borderRadius: const pw.BorderRadius.all(pw.Radius.circular(6))),
          child: pw.Column(crossAxisAlignment: pw.CrossAxisAlignment.start, children: [
            pw.Text("DATOS DEL CLIENTE",
              style: pw.TextStyle(fontSize: 10, fontWeight: pw.FontWeight.bold, color: PdfColors.grey600)),
            pw.SizedBox(height: 6),
            pw.Row(children: [
              pw.Expanded(child: pw.Text("Nombre: ${factura.cliente}", style: const pw.TextStyle(fontSize: 11))),
              pw.Expanded(child: pw.Text("Cédula: ${factura.cedula}", style: const pw.TextStyle(fontSize: 11))),
            ]),
            pw.SizedBox(height: 3),
            pw.Row(children: [
              pw.Expanded(child: pw.Text("Teléfono: ${factura.telefono}", style: const pw.TextStyle(fontSize: 11))),
              pw.Expanded(child: pw.Text("Vendedor: ${_resolverNombreVendedor(factura.vendedor)}", style: const pw.TextStyle(fontSize: 11))),
            ]),
          ]),
        ),
        pw.SizedBox(height: 14),

        // ── Productos / IMEIs ────────────────────────────────
        if (factura.equipos.isNotEmpty || factura.itemsSinImei.isNotEmpty) ...[
          pw.Text("PRODUCTOS / EQUIPOS",
            style: pw.TextStyle(fontSize: 11, fontWeight: pw.FontWeight.bold, color: PdfColors.blue900)),
          pw.SizedBox(height: 4),
          pw.Table(
            border: pw.TableBorder.all(color: PdfColors.grey300, width: 0.5),
            columnWidths: {
              0: const pw.FlexColumnWidth(3),
              1: const pw.FlexColumnWidth(3),
            },
            children: [
              pw.TableRow(
                decoration: const pw.BoxDecoration(color: PdfColors.blue900),
                children: [
                  pw.Padding(padding: const pw.EdgeInsets.all(5),
                    child: pw.Text("DESCRIPCIÓN", style: pw.TextStyle(fontSize: 9, fontWeight: pw.FontWeight.bold, color: PdfColors.white))),
                  pw.Padding(padding: const pw.EdgeInsets.all(5),
                    child: pw.Text("IMEI / CÓDIGO", style: pw.TextStyle(fontSize: 9, fontWeight: pw.FontWeight.bold, color: PdfColors.white))),
                ],
              ),
              ...factura.equipos.map((e) {
                final modelo = e.producto.modelo.trim();
                final mm = modelo;
                return pw.TableRow(children: [
                  pw.Padding(padding: const pw.EdgeInsets.all(5),
                    child: pw.Column(
                      crossAxisAlignment: pw.CrossAxisAlignment.start,
                      children: [
                        pw.Text(e.producto.nombre,
                          style: const pw.TextStyle(fontSize: 10)),
                        if (mm.isNotEmpty)
                          pw.Text(mm,
                            style: pw.TextStyle(
                              fontSize: 9, color: PdfColors.grey700,
                              fontWeight: pw.FontWeight.bold)),
                      ],
                    )),
                  pw.Padding(padding: const pw.EdgeInsets.all(5),
                    child: pw.Text(e.imei,
                      style: const pw.TextStyle(fontSize: 9))),
                ]);
              }),
              ...factura.itemsSinImei.map((p) => pw.TableRow(children: [
                pw.Padding(padding: const pw.EdgeInsets.all(5),
                  child: pw.Text(p.nombre, style: const pw.TextStyle(fontSize: 10))),
                pw.Padding(padding: const pw.EdgeInsets.all(5),
                  child: pw.Text(p.codigo, style: const pw.TextStyle(fontSize: 9))),
              ])),
            ],
          ),
          pw.SizedBox(height: 14),
        ],

        // ── Pagos ────────────────────────────────────────────
        if (factura.pagos.isNotEmpty) ...[
          pw.Text("FORMA DE PAGO",
            style: pw.TextStyle(fontSize: 11, fontWeight: pw.FontWeight.bold, color: PdfColors.blue900)),
          pw.SizedBox(height: 4),
          ...factura.pagos.map((p) => pw.Padding(
            padding: const pw.EdgeInsets.symmetric(vertical: 2),
            child: pw.Row(mainAxisAlignment: pw.MainAxisAlignment.spaceBetween, children: [
              pw.Text("• ${p.metodo}", style: const pw.TextStyle(fontSize: 11)),
              pw.Text(formatMontoPorMetodo(p.monto, p.metodo),
                style: pw.TextStyle(fontSize: 11, fontWeight: pw.FontWeight.bold)),
            ]))),
          pw.SizedBox(height: 10),
        ],

        // ── Total ────────────────────────────────────────────
        pw.Divider(thickness: 1.5, color: PdfColors.blue900),
        pw.SizedBox(height: 6),
        pw.Row(mainAxisAlignment: pw.MainAxisAlignment.spaceBetween, children: [
          pw.Text("TOTAL  (tasa ${tasa.toStringAsFixed(2)})",
            style: pw.TextStyle(fontSize: 13, fontWeight: pw.FontWeight.bold, color: PdfColors.grey700)),
          pw.Text(formatBolivares(totalBs),
            style: pw.TextStyle(fontSize: 17, fontWeight: pw.FontWeight.bold, color: PdfColors.blue900)),
        ]),
        pw.SizedBox(height: 20),

        // ── Pie ──────────────────────────────────────────────
        pw.Divider(color: PdfColors.grey400),
        pw.SizedBox(height: 4),
        pw.Text(ConfigSistema.textoFacturaPie,
          style: const pw.TextStyle(fontSize: 9, color: PdfColors.grey600)),
        pw.SizedBox(height: 2),
        pw.Text(
          ConfigSistema.nombreEmpresa.trim().isEmpty
            ? "Garantía: ${ConfigSistema.diasGarantia} días"
            : "Garantía: ${ConfigSistema.diasGarantia} días · ${ConfigSistema.nombreEmpresa}",
          style: const pw.TextStyle(fontSize: 9, color: PdfColors.grey500)),
      ]);
    }));
  final dir = await getTemporaryDirectory();
  final file = File("${dir.path}/factura_${factura.nroFactura}.pdf");
  await file.writeAsBytes(await pdf.save());
  return file;
}

// ============================================================
//  Helper: construye un FacturaModel completo con equipos + items
//  desde el JSON devuelto por la API. Busca los productos en el
//  catálogo global (catalogoGlobal + stockImeiGlobal) para saber
//  el nombre y precio correctos.
// ============================================================
FacturaModel construirFacturaModelDesdeJson(Map<String, dynamic> j) {
  final rawEquipos = (j['equipos'] as List?) ?? [];
  final rawItems   = (j['items']   as List?) ?? [];
  final rawPagos   = (j['pagos']   as List?) ?? [];

  // ── Equipos (IMEIs) ──
  // Cada entrada puede ser un string (IMEI) o un Map completo
  final List<ImeiRegistro> equipos = [];
  for (final e in rawEquipos) {
    String imei = '';
    String prodCodigo = '';
    String prodModelo = '';
    String prodMarca = '';
    String prodNombre = '';
    if (e is String) {
      imei = e;
    } else if (e is Map) {
      imei = (e['imei'] ?? '').toString();
      prodCodigo = (e['producto_codigo'] ?? e['codigo'] ?? '').toString();
      prodModelo = (e['modelo'] ?? '').toString();
      prodMarca  = (e['marca'] ?? '').toString();
      prodNombre = (e['producto_nombre'] ?? e['nombre'] ?? '').toString();
    }
    if (imei.isEmpty) continue;

    // Buscar el IMEI en el stock global para obtener producto
    final encontrado = stockImeiGlobal.where((i) => i.imei == imei).firstOrNull;
    if (encontrado != null) {
      // Aún si está en stock, podríamos tener modelo vacío ahí (caso
      // donde stock_imei se cargó antes que productos). Re-enriquecer
      // desde el catálogo si es necesario.
      if (encontrado.producto.modelo.trim().isEmpty &&
          encontrado.producto.codigo.isNotEmpty) {
        final p = catalogoGlobal
            .where((x) => x.codigo == encontrado.producto.codigo)
            .firstOrNull;
        if (p != null) {
          equipos.add(ImeiRegistro(
            imei: encontrado.imei,
            producto: Producto(
              codigo: p.codigo, nombre: p.nombre,
              categoria: p.categoria, marca: p.marca,
              modelo: p.modelo, tipo: p.tipo,
              precioCosto: p.precioCosto, precioVenta: p.precioVenta),
            fechaIngreso: encontrado.fechaIngreso,
            proveedor: encontrado.proveedor,
            color: encontrado.color,
            ubicacion: encontrado.ubicacion,
            porcentajeBateria: encontrado.porcentajeBateria,
            vendido: encontrado.vendido,
          ));
          continue;
        }
      }
      equipos.add(encontrado);
    } else {
      // No está en el stock (fue vendido y eliminado o no cargado);
      // creamos un placeholder buscando primero en el catálogo de
      // productos por código para conservar nombre/modelo.
      String codigo = prodCodigo;
      String nombre = prodNombre.isNotEmpty ? prodNombre : 'Equipo IMEI $imei';
      String marca  = prodMarca;
      String modelo = prodModelo;
      if (codigo.isNotEmpty &&
          (modelo.isEmpty || marca.isEmpty || prodNombre.isEmpty)) {
        final p = catalogoGlobal.where((x) => x.codigo == codigo).firstOrNull;
        if (p != null) {
          if (modelo.isEmpty) modelo = p.modelo;
          if (marca.isEmpty)  marca  = p.marca;
          if (prodNombre.isEmpty) nombre = p.nombre;
        }
      }
      equipos.add(ImeiRegistro(
        imei: imei,
        producto: Producto(
          codigo: codigo, nombre: nombre,
          categoria: 'Telefono', marca: marca, modelo: modelo,
          tipo: '', precioCosto: 0, precioVenta: 0),
        fechaIngreso: '', proveedor: '', color: '',
        ubicacion: '', vendido: true,
      ));
    }
  }

  // ── Items (códigos de producto sin IMEI) ──
  final List<Producto> items = [];
  for (final i in rawItems) {
    String codigo = '';
    if (i is String) codigo = i;
    else if (i is Map) codigo = (i['producto_codigo'] ?? i['codigo'] ?? '').toString();
    if (codigo.isEmpty) continue;

    final encontrado = catalogoGlobal.where((p) => p.codigo == codigo).firstOrNull;
    if (encontrado != null) {
      items.add(encontrado);
    } else {
      items.add(Producto(
        codigo: codigo, nombre: 'Producto $codigo',
        categoria: 'Accesorio', marca: '', modelo: '',
        tipo: '', precioCosto: 0, precioVenta: 0));
    }
  }

  // ── Pagos ──
  final List<PagoFactura> pagos = rawPagos.map((p) {
    final map = p is Map ? p : {'metodo': p.toString(), 'monto': 0};
    return PagoFactura(
      metodo: (map['metodo'] ?? '').toString(),
      monto: double.tryParse(map['monto'].toString()) ?? 0,
      tipo: (map['tipo'] ?? 'Contado').toString(),
      financiador: map['financiador']?.toString(),
    );
  }).toList();

  return FacturaModel(
    id        : int.tryParse(j['id']?.toString() ?? ''),
    cliente   : (j['cliente']   ?? '').toString(),
    cedula    : (j['cedula']    ?? '').toString(),
    telefono  : (j['telefono']  ?? '').toString(),
    nroFactura: (j['nro_factura'] ?? '').toString(),
    vendedor  : (j['vendedor']  ?? '').toString(),
    tienda    : (j['tienda']    ?? '').toString(),
    fecha     : (j['fecha']     ?? '').toString(),
    equipos   : equipos,
    itemsSinImei: items,
    pagos     : pagos,
  );
}

Future<void> imprimirFactura(FacturaModel factura, [BuildContext? context]) async {
  // Si no se pasa context, no podemos preguntar → usar A4 por defecto.
  FormatoImpresion formato = FormatoImpresion.a4;
  if (context != null) {
    final elegido = await ImpresionHelper.obtenerFormato(context);
    if (elegido == null) return;
    formato = elegido;
  }

  final tasa = ConfigSistema.tasaCambio;
  final totalBs = factura.total * tasa;
  final pdf = pw.Document();

  // Cargar logo de la sede si existe
  pw.ImageProvider? logo;
  final enc = ConfigSistema.encabezadoDe(factura.tienda);
  if (enc.logoBytes != null) {
    try { logo = pw.MemoryImage(enc.logoBytes!); } catch (_) {}
  }

  final esTermica = ImpresionHelper.esTermica(formato);
  final escala = ImpresionHelper.escalaFuente(formato);
  final ancho = ImpresionHelper.charsPorLinea(formato);

  // Helpers de tamaño adaptativos
  double fs(double base) => base * escala;

  // Separador como Divider gráfico (respeta el ancho real del papel).
  // Para térmicas usamos líneas delgadas; para A4 divisores normales.
  pw.Widget separadorFino() => pw.Container(
    height: 0.4, color: PdfColors.black,
    margin: const pw.EdgeInsets.symmetric(vertical: 2));
  pw.Widget separadorGrueso() => pw.Container(
    height: 0.8, color: PdfColors.black,
    margin: const pw.EdgeInsets.symmetric(vertical: 2));

  // Título de sección con estilo (para térmica). Fondo negro + texto blanco
  // para asegurar que se lea bien en papel térmico (el gris claro del fondo
  // anterior se confundía con el papel y el título se perdía).
  pw.Widget _seccionTermica(String titulo, double Function(double) fs) =>
      pw.Container(
        width: double.infinity,
        padding: const pw.EdgeInsets.symmetric(vertical: 3, horizontal: 5),
        margin: const pw.EdgeInsets.only(bottom: 3, top: 2),
        decoration: const pw.BoxDecoration(
          color: PdfColors.black,
          borderRadius: pw.BorderRadius.all(pw.Radius.circular(2))),
        child: pw.Text(titulo,
          style: pw.TextStyle(
            fontSize: fs(8.5),
            fontWeight: pw.FontWeight.bold,
            color: PdfColors.white,
            letterSpacing: 0.8)));

  // Línea de dato tipo "Etiqueta: valor" para encabezado térmico.
  // Texto en negro y tamaño aumentado para asegurar legibilidad al
  // imprimirse en papel térmico (el papel térmico tiene bajo contraste
  // y los tonos grises no se reproducen bien).
  pw.Widget _lineaDato(String etiqueta, String valor,
      double Function(double) fs) => pw.Padding(
    padding: const pw.EdgeInsets.symmetric(vertical: 0.8),
    child: pw.RichText(text: pw.TextSpan(children: [
      pw.TextSpan(text: "$etiqueta: ",
        style: pw.TextStyle(
          fontSize: fs(9),
          fontWeight: pw.FontWeight.bold,
          color: PdfColors.black)),
      pw.TextSpan(text: valor,
        style: pw.TextStyle(fontSize: fs(9.5),
          fontWeight: pw.FontWeight.bold,
          color: PdfColors.black)),
    ])),
  );

  // Trunca un texto si excede el ancho (para evitar overflow visual).
  String tr(String s, [int? max]) {
    final m = max ?? ancho;
    if (s.length <= m) return s;
    return s.substring(0, m - 1) + '…';
  }

  // Retira el prefijo "FAC-" del número de factura solo a efectos de
  // impresión. Se aplica por si la factura fue guardada antiguamente con
  // ese prefijo (las facturas nuevas ya se generan sin él).
  String _sinPrefijoFac(String nro) {
    final s = nro.trim();
    if (s.toUpperCase().startsWith('FAC-')) return s.substring(4);
    if (s.toUpperCase().startsWith('FAC'))  return s.substring(3).replaceFirst(RegExp(r'^[-\s]+'), '');
    return s;
  }

  // ═════════════════════════════════════════════════════════════
  //  LAYOUT TÉRMICO (80mm / 58mm) — usa MultiPage para que el
  //  contenido fluya y no se corte si es largo.
  // ═════════════════════════════════════════════════════════════
  if (esTermica) {
    pdf.addPage(pw.MultiPage(
      pageFormat: ImpresionHelper.formatoPdf(formato),
      margin: formato == FormatoImpresion.termica58
          ? const pw.EdgeInsets.all(2)
          : const pw.EdgeInsets.all(3),
      build: (pw.Context ctx) => [
        // ═══════════════════════════════════════════════════════
        //  ENCABEZADO — Logo grande centrado (sin nombre tienda)
        // ═══════════════════════════════════════════════════════
        if (logo != null) ...[
          pw.Center(child: pw.SizedBox(
            height: formato == FormatoImpresion.termica58 ? 70 : 90,
            child: pw.Image(logo, fit: pw.BoxFit.contain))),
          pw.SizedBox(height: 6),
        ] else ...[
          // Sin logo configurado: espacio vacío elegante
          pw.SizedBox(height: 10),
        ],

        pw.SizedBox(height: 2),

        // ═══════════════════════════════════════════════════════
        //  BADGE DE GARANTÍA (caja destacada)
        // ═══════════════════════════════════════════════════════
        pw.Container(
          width: double.infinity,
          padding: const pw.EdgeInsets.symmetric(vertical: 5, horizontal: 6),
          decoration: pw.BoxDecoration(
            color: PdfColors.black,
            borderRadius: const pw.BorderRadius.all(pw.Radius.circular(3))),
          child: pw.Center(child: pw.Text(
            tr("GARANTÍA  ${_sinPrefijoFac(factura.nroFactura)}"),
            style: pw.TextStyle(
              fontSize: fs(10),
              fontWeight: pw.FontWeight.bold,
              color: PdfColors.white,
              letterSpacing: 1.2))),
        ),
        pw.SizedBox(height: 4),
        pw.Center(child: pw.Text(factura.fecha,
          style: pw.TextStyle(
            fontSize: fs(10.5),
            fontWeight: pw.FontWeight.bold,
            color: PdfColors.black,
            letterSpacing: 0.5))),
        pw.SizedBox(height: 6),

        // ═══════════════════════════════════════════════════════
        //  DATOS DEL CLIENTE
        // ═══════════════════════════════════════════════════════
        _seccionTermica("CLIENTE", fs),
        pw.Text(factura.cliente,
          style: pw.TextStyle(fontSize: fs(9.5), fontWeight: pw.FontWeight.bold),
          maxLines: 2),
        if (factura.cedula.isNotEmpty)
          _lineaDato("C.I.", factura.cedula, fs),
        if (factura.telefono.isNotEmpty)
          _lineaDato("Tel.", factura.telefono, fs),

        pw.SizedBox(height: 4),

        // ═══════════════════════════════════════════════════════
        //  VENDEDOR (usuario que facturó) — sección propia para
        //  que quede bien claro quién atendió la venta.
        // ═══════════════════════════════════════════════════════
        _seccionTermica("VENDEDOR", fs),
        pw.Text(tr(_resolverNombreVendedor(factura.vendedor), ancho),
          style: pw.TextStyle(
            fontSize: fs(9.5),
            fontWeight: pw.FontWeight.bold,
            color: PdfColors.black),
          maxLines: 1, overflow: pw.TextOverflow.clip),

        pw.SizedBox(height: 4),
        separadorFino(),
        pw.SizedBox(height: 3),

        // ═══════════════════════════════════════════════════════
        //  PRODUCTOS (sin distinguir categoría "EQUIPOS" /
        //  "ACCESORIOS" — todo bajo un mismo encabezado para no
        //  revelar la categoría interna del producto).
        // ═══════════════════════════════════════════════════════
        if (factura.equipos.isNotEmpty || factura.itemsSinImei.isNotEmpty) ...[
          _seccionTermica("PRODUCTOS", fs),
          // Productos con IMEI (barra lateral negra + nombre + IMEI)
          ...factura.equipos.map((e) {
            final modelo = e.producto.modelo.trim();
            final mm = modelo;
            return pw.Container(
              margin: const pw.EdgeInsets.only(bottom: 4),
              padding: const pw.EdgeInsets.only(left: 2, right: 2, top: 2, bottom: 3),
              decoration: const pw.BoxDecoration(
                border: pw.Border(
                  left: pw.BorderSide(width: 2, color: PdfColors.black))),
              child: pw.Column(
                crossAxisAlignment: pw.CrossAxisAlignment.stretch,
                children: [
                  // Solo se imprime nombre + IMEI. Sin categoría ni código.
                  pw.Padding(
                    padding: const pw.EdgeInsets.only(left: 4),
                    child: pw.Text(e.producto.nombre,
                      style: pw.TextStyle(
                        fontSize: fs(9.5),
                        fontWeight: pw.FontWeight.bold,
                        color: PdfColors.black),
                      maxLines: 2)),
                  if (mm.isNotEmpty)
                    pw.Padding(
                      padding: const pw.EdgeInsets.only(left: 4, top: 1),
                      child: pw.Text(mm,
                        style: pw.TextStyle(
                          fontSize: fs(8.5),
                          fontWeight: pw.FontWeight.bold,
                          color: PdfColors.black),
                        maxLines: 1, overflow: pw.TextOverflow.clip)),
                  pw.Padding(
                    padding: const pw.EdgeInsets.only(left: 4, top: 1),
                    child: pw.Text("IMEI: ${e.imei}",
                      style: pw.TextStyle(
                        fontSize: fs(8.5),
                        fontWeight: pw.FontWeight.bold,
                        color: PdfColors.black),
                      maxLines: 1, overflow: pw.TextOverflow.clip)),
                ],
              ),
            );
          }),
          // Productos sin IMEI (solo nombre, sin categoría ni código)
          ...factura.itemsSinImei.map((p) => pw.Padding(
            padding: const pw.EdgeInsets.only(bottom: 3, top: 1),
            child: pw.Column(
              crossAxisAlignment: pw.CrossAxisAlignment.stretch,
              children: [
                pw.Text(p.nombre,
                  style: pw.TextStyle(
                    fontSize: fs(9.5),
                    fontWeight: pw.FontWeight.bold,
                    color: PdfColors.black),
                  maxLines: 2),
              ],
            ),
          )),
        ],

        if (factura.equipos.isEmpty && factura.itemsSinImei.isEmpty)
          pw.Padding(
            padding: const pw.EdgeInsets.symmetric(vertical: 4),
            child: pw.Center(child: pw.Text("(Sin detalle de productos)",
              style: pw.TextStyle(
                fontSize: fs(7.5),
                color: PdfColors.black,
                fontStyle: pw.FontStyle.italic))),
          ),

        pw.SizedBox(height: 3),
        separadorFino(),
        pw.SizedBox(height: 3),

        // ═══════════════════════════════════════════════════════
        //  MÉTODOS DE PAGO
        // ═══════════════════════════════════════════════════════
        if (factura.pagos.isNotEmpty) ...[
          _seccionTermica("MÉTODOS DE PAGO", fs),
          ...factura.pagos.map((p) => pw.Padding(
            padding: const pw.EdgeInsets.symmetric(vertical: 1),
            child: pw.Row(
              crossAxisAlignment: pw.CrossAxisAlignment.start,
              children: [
                pw.Expanded(child: pw.Text(p.metodo,
                  style: pw.TextStyle(fontSize: fs(8.5)),
                  maxLines: 1, overflow: pw.TextOverflow.clip)),
                pw.SizedBox(width: 4),
                pw.Text(formatMontoPorMetodo(p.monto, p.metodo),
                  style: pw.TextStyle(
                    fontSize: fs(9),
                    fontWeight: pw.FontWeight.bold)),
              ])),
          ),
          pw.SizedBox(height: 3),
        ],

        // ═══════════════════════════════════════════════════════
        //  PIE DE FACTURA (sin total — ya no se muestra)
        // ═══════════════════════════════════════════════════════
        separadorGrueso(),
        pw.SizedBox(height: 6),

        pw.Center(child: pw.Text(ConfigSistema.textoFacturaPie,
          style: pw.TextStyle(
            fontSize: fs(8.5),
            color: PdfColors.black,
            fontWeight: pw.FontWeight.bold),
          textAlign: pw.TextAlign.center,
          maxLines: 3)),
        pw.SizedBox(height: 3),
        pw.Center(child: pw.Container(
          padding: const pw.EdgeInsets.symmetric(horizontal: 6, vertical: 2),
          decoration: pw.BoxDecoration(
            border: pw.Border.all(color: PdfColors.black, width: 0.5),
            borderRadius: const pw.BorderRadius.all(pw.Radius.circular(2))),
          child: pw.Text("Garantía: ${ConfigSistema.diasGarantia} días",
            style: pw.TextStyle(
              fontSize: fs(7.5),
              fontWeight: pw.FontWeight.bold)))),

        pw.SizedBox(height: 5),
        pw.Center(child: pw.Text("¡ Gracias por su compra !",
          style: pw.TextStyle(
            fontSize: fs(9.5),
            fontWeight: pw.FontWeight.bold,
            letterSpacing: 0.8))),
        pw.SizedBox(height: 22), // espacio para corte del papel
      ],
    ));
  } else {
    // ═════════════════════════════════════════════════════════
    //  LAYOUT A4 / CARTA (original + equipos/items agregados)
    // ═════════════════════════════════════════════════════════
    pdf.addPage(pw.Page(
      pageFormat: ImpresionHelper.formatoPdf(formato),
      margin: const pw.EdgeInsets.all(36),
      build: (pw.Context ctx) {
        return pw.Column(crossAxisAlignment: pw.CrossAxisAlignment.start, children: [
          _buildEncabezadoPDF(factura, logo: logo),
          pw.SizedBox(height: 18),

          // ═══════════════════════════════════════════════════════
          //  DATOS DEL CLIENTE — caja minimalista
          // ═══════════════════════════════════════════════════════
          pw.Container(
            padding: const pw.EdgeInsets.all(14),
            decoration: pw.BoxDecoration(
              color: PdfColors.grey100,
              // NOTA: no se puede usar borderRadius con un Border no
              // uniforme (solo-izquierdo). El PDF lanzaba assertion
              // "A borderRadius can only be given for a uniform Border".
              border: pw.Border(
                left: pw.BorderSide(width: 3, color: PdfColors.black))),
            child: pw.Column(
              crossAxisAlignment: pw.CrossAxisAlignment.start, children: [
                pw.Text("DATOS DEL CLIENTE",
                  style: pw.TextStyle(
                    fontSize: 9,
                    fontWeight: pw.FontWeight.bold,
                    color: PdfColors.grey600,
                    letterSpacing: 1.5)),
                pw.SizedBox(height: 8),
                pw.Row(children: [
                  pw.Expanded(child: _pdfDato("Nombre", factura.cliente)),
                  pw.Expanded(child: _pdfDato("Cédula", factura.cedula)),
                ]),
                pw.SizedBox(height: 5),
                pw.Row(children: [
                  pw.Expanded(child: _pdfDato("Teléfono", factura.telefono)),
                  pw.Expanded(child: _pdfDato("Vendedor", _resolverNombreVendedor(factura.vendedor))),
                ]),
              ]),
          ),
          pw.SizedBox(height: 16),

          // ═══════════════════════════════════════════════════════
          //  PRODUCTOS FACTURADOS — tabla elegante monocromo
          // ═══════════════════════════════════════════════════════
          if (factura.equipos.isNotEmpty || factura.itemsSinImei.isNotEmpty) ...[
            pw.Container(
              padding: const pw.EdgeInsets.symmetric(horizontal: 10, vertical: 5),
              decoration: const pw.BoxDecoration(
                color: PdfColors.black,
                borderRadius: pw.BorderRadius.only(
                  topLeft: pw.Radius.circular(4),
                  topRight: pw.Radius.circular(4))),
              child: pw.Text("PRODUCTOS",
                style: pw.TextStyle(
                  fontSize: 10,
                  fontWeight: pw.FontWeight.bold,
                  color: PdfColors.white,
                  letterSpacing: 1.5)),
            ),
            pw.Table(
              border: pw.TableBorder.all(width: 0.4, color: PdfColors.grey500),
              columnWidths: const {
                0: pw.FlexColumnWidth(3.5),
                1: pw.FlexColumnWidth(3),
              },
              children: [
                pw.TableRow(
                  decoration: const pw.BoxDecoration(color: PdfColors.grey200),
                  children: [
                    pw.Padding(padding: const pw.EdgeInsets.all(6),
                      child: pw.Text("Descripción",
                        style: pw.TextStyle(fontSize: 9,
                          fontWeight: pw.FontWeight.bold,
                          letterSpacing: 0.5))),
                    pw.Padding(padding: const pw.EdgeInsets.all(6),
                      child: pw.Text("Código / IMEI",
                        style: pw.TextStyle(fontSize: 9,
                          fontWeight: pw.FontWeight.bold,
                          letterSpacing: 0.5))),
                  ],
                ),
                // Equipos con IMEI (sin mostrar código interno del producto)
                ...factura.equipos.map((e) {
                  final modelo = e.producto.modelo.trim();
                  final mm = modelo;
                  return pw.TableRow(children: [
                    pw.Padding(padding: const pw.EdgeInsets.all(7),
                      child: pw.Column(
                        crossAxisAlignment: pw.CrossAxisAlignment.start,
                        children: [
                          pw.Text(e.producto.nombre,
                            style: pw.TextStyle(
                              fontSize: 10, fontWeight: pw.FontWeight.bold)),
                          if (mm.isNotEmpty)
                            pw.Text(mm,
                              style: pw.TextStyle(
                                fontSize: 9, color: PdfColors.grey700,
                                fontWeight: pw.FontWeight.bold)),
                        ],
                      )),
                    pw.Padding(padding: const pw.EdgeInsets.all(7),
                      child: pw.Text("IMEI: ${e.imei}",
                        style: const pw.TextStyle(fontSize: 9))),
                  ]);
                }),
                // Items sin IMEI (solo nombre, sin código interno)
                ...factura.itemsSinImei.map((p) => pw.TableRow(children: [
                  pw.Padding(padding: const pw.EdgeInsets.all(7),
                    child: pw.Text(p.nombre,
                      style: pw.TextStyle(fontSize: 10, fontWeight: pw.FontWeight.bold))),
                  pw.Padding(padding: const pw.EdgeInsets.all(7),
                    child: pw.Text("—",
                      style: const pw.TextStyle(fontSize: 9))),
                ])),
              ],
            ),
            pw.SizedBox(height: 16),
          ],

          // ═══════════════════════════════════════════════════════
          //  FORMA DE PAGO — lista elegante
          // ═══════════════════════════════════════════════════════
          if (factura.pagos.isNotEmpty) ...[
            pw.Container(
              padding: const pw.EdgeInsets.all(12),
              decoration: pw.BoxDecoration(
                color: PdfColors.grey100,
                // Sin borderRadius: incompatible con Border no uniforme
                // (solo-izquierdo). El paquete pdf lanza assertion.
                border: pw.Border(
                  left: pw.BorderSide(width: 3, color: PdfColors.black))),
              child: pw.Column(
                crossAxisAlignment: pw.CrossAxisAlignment.start, children: [
                  pw.Text("FORMA DE PAGO",
                    style: pw.TextStyle(
                      fontSize: 9,
                      fontWeight: pw.FontWeight.bold,
                      color: PdfColors.grey600,
                      letterSpacing: 1.5)),
                  pw.SizedBox(height: 6),
                  ...factura.pagos.map((p) => pw.Padding(
                    padding: const pw.EdgeInsets.symmetric(vertical: 2),
                    child: pw.Row(
                      mainAxisAlignment: pw.MainAxisAlignment.spaceBetween,
                      children: [
                        pw.Row(children: [
                          pw.Container(
                            width: 4, height: 4,
                            decoration: const pw.BoxDecoration(
                              color: PdfColors.black,
                              shape: pw.BoxShape.circle)),
                          pw.SizedBox(width: 6),
                          pw.Text(p.metodo,
                            style: const pw.TextStyle(fontSize: 10)),
                        ]),
                        pw.Text(formatMontoPorMetodo(p.monto, p.metodo),
                          style: pw.TextStyle(
                            fontSize: 10,
                            fontWeight: pw.FontWeight.bold)),
                      ]))),
                ]),
            ),
          ],

          // ═══════════════════════════════════════════════════════
          //  PIE DE GARANTÍA — elegante, monocromo
          // ═══════════════════════════════════════════════════════
          pw.SizedBox(height: 24),
          pw.Container(height: 0.4, color: PdfColors.grey400),
          pw.SizedBox(height: 14),
          pw.Center(child: pw.Text(ConfigSistema.textoFacturaPie,
            style: pw.TextStyle(
              fontSize: 9,
              color: PdfColors.grey700,
              fontStyle: pw.FontStyle.italic),
            textAlign: pw.TextAlign.center)),
          pw.SizedBox(height: 10),
          pw.Center(child: pw.Container(
            padding: const pw.EdgeInsets.symmetric(horizontal: 16, vertical: 6),
            decoration: pw.BoxDecoration(
              border: pw.Border.all(color: PdfColors.black, width: 1),
              borderRadius: const pw.BorderRadius.all(pw.Radius.circular(3))),
            child: pw.Text(
              "GARANTÍA · ${ConfigSistema.diasGarantia} DÍAS",
              style: pw.TextStyle(
                fontSize: 10,
                fontWeight: pw.FontWeight.bold,
                letterSpacing: 2)))),
          pw.SizedBox(height: 14),
          pw.Center(child: pw.Text("Gracias por su compra",
            style: pw.TextStyle(
              fontSize: 11,
              fontWeight: pw.FontWeight.bold,
              letterSpacing: 1.2,
              color: PdfColors.grey700))),
        ]);
      },
    ));
  }

  final bytes = await pdf.save();

  // Intenta Bluetooth directo si es térmica y hay impresora configurada;
  // si falla o no hay, abre el diálogo del sistema.
  if (context != null && context.mounted) {
    await ImpresionHelper.imprimirPdfInteligente(
      context: context,
      pdfBytes: Uint8List.fromList(bytes),
      formato: formato,
      nombreArchivo: 'garantia_${factura.nroFactura}');
  } else {
    await Printing.layoutPdf(
      onLayout: (_) async => Uint8List.fromList(bytes),
      name: 'garantia_${factura.nroFactura}',
      format: ImpresionHelper.formatoPdf(formato),
    );
  }
}

// ============================================================
//  VENTAS PRINCIPAL — carga facturas desde la API
// ============================================================
class VentasPrincipal extends StatefulWidget {
  final String tienda;
  const VentasPrincipal({super.key, required this.tienda});
  @override State<VentasPrincipal> createState() => _VentasPrincipalState();
}

class _VentasPrincipalState extends State<VentasPrincipal> {
  String _searchQuery = "";
  List<Map<String,dynamic>> _facturasRaw = [];
  bool _cargando = true;
  /// Filtro de tienda visible sólo para roles altos.
  /// 'Todas' = ver todas; '' inicial se normaliza.
  String _tiendaFiltro = 'Todas';

  /// Devuelve true si el usuario actual tiene uno de los roles indicados.
  /// El UsuarioMaestro (rol 'Maestro') SIEMPRE tiene acceso — no importa
  /// qué roles se pasen, el maestro pasa todos los checks.
  ///
  /// Adicionalmente, los roles 'Dueño', 'Administrador' y 'Gerente'
  /// tienen los MISMOS permisos que el Maestro EXCEPTO el de bloquear
  /// la aplicación (eso queda exclusivo del Maestro). Para distinguir
  /// la verificación específica de "bloquear", el código que la
  /// requiera debe pasar la lista `['Maestro']` exacta (solo Maestro).
  bool checkAccess(List<String> roles) {
    final rolActual = usuarioSesion?.rol;
    if (rolActual == 'Maestro') return true; // bypass total
    // Si la verificación es EXCLUSIVA del Maestro (ej. bloquear app),
    // los demás roles NO pasan aunque sean administrativos.
    final esExclusivoMaestro =
        roles.length == 1 && roles.first == 'Maestro';
    if (esExclusivoMaestro) return false;
    // Dueño / Administrador / Gerente tienen los mismos permisos
    // que el Maestro para todo lo demás.
    if (rolActual == 'Dueño'
        || rolActual == 'Administrador'
        || rolActual == 'Gerente') {
      return true;
    }
    return roles.contains(rolActual);
  }

  @override
  void initState() { super.initState(); _cargarFacturas(); }

  Future<void> _cargarFacturas() async {
    setState(() => _cargando = true);
    try {
      final raw = await _Api.get('facturas');
      _facturasRaw = List<Map<String,dynamic>>.from(
          (raw as List? ?? []).map((e) => e as Map<String, dynamic>));
      // Ordenar por fecha descendente (más recientes primero)
      _facturasRaw.sort((a, b) {
        try {
          final partsA = (a['fecha'] as String? ?? '').split('/');
          final partsB = (b['fecha'] as String? ?? '').split('/');
          if (partsA.length == 3 && partsB.length == 3) {
            final dA = DateTime(int.parse(partsA[2]), int.parse(partsA[1]), int.parse(partsA[0]));
            final dB = DateTime(int.parse(partsB[2]), int.parse(partsB[1]), int.parse(partsB[0]));
            return dB.compareTo(dA);
          }
        } catch (_) {}
        return (b['id'] ?? 0).compareTo(a['id'] ?? 0);
      });
    } catch (e) {
      debugPrint('[_cargarFacturas] Error: $e');
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Row(children: [
          const Icon(Icons.error_outline, color: Colors.white, size: 16),
          const SizedBox(width: 8),
          Expanded(child: Text('Error al cargar facturas: $e')),
        ]),
        backgroundColor: AppColors.statusRed,
        duration: const Duration(seconds: 4)));
    } finally {
      if (mounted) setState(() => _cargando = false);
    }
  }

  @override
  Widget build(BuildContext context) {
    // Aplica el filtro de tienda antes del de búsqueda.
    // Vendedor/Activador/Encargado ven sólo su tienda.
    // Administrador/Dueño/Gerente pueden elegir (por defecto 'Todas').
    final facturasPorTienda = filtrarPorTienda(
      _facturasRaw,
      tiendaFiltro: _tiendaFiltro,
    );

    final filtradas = facturasPorTienda.where((v) =>
      (v['cliente']??'').toLowerCase().contains(_searchQuery.toLowerCase()) ||
      (v['cedula']??'').toLowerCase().contains(_searchQuery.toLowerCase()) ||
      (v['nro_factura']??'').toLowerCase().contains(_searchQuery.toLowerCase()) ||
      (v['vendedor']??'').toLowerCase().contains(_searchQuery.toLowerCase())).toList();

    return Scaffold(
      appBar: AppBar(
        backgroundColor: AppColors.royalBlue,
        title: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
          Text(widget.tienda, style: const TextStyle(fontSize: 16, fontWeight: FontWeight.bold)),
          Text(usuarioSesion?.nombre ?? '', style: const TextStyle(fontSize: 11, color: Colors.white70)),
        ]),
        actions: [
          const TasaBCVBadge(),
          const SizedBox(width: 4),
          IconButton(icon: const Icon(Icons.refresh), tooltip: "Actualizar", onPressed: _cargarFacturas),
        ],
      ),
      drawer: _buildDrawer(),
      body: Column(children: [
        // Barra de búsqueda
        Container(
          color: Colors.white,
          padding: const EdgeInsets.fromLTRB(12, 8, 12, 12),
          child: TextField(
            style: const TextStyle(color: AppColors.textPrimary),
            decoration: InputDecoration(
              hintText: "Buscar por cliente, cédula, factura o vendedor...",
              hintStyle: const TextStyle(color: AppColors.textSecondary, fontSize: 13),
              prefixIcon: const Icon(Icons.search, color: AppColors.primaryBlue),
              suffixIcon: _searchQuery.isNotEmpty
                ? IconButton(icon: const Icon(Icons.clear, size: 18), onPressed: () => setState(() => _searchQuery = ''))
                : null,
              filled: true,
              fillColor: AppColors.surfaceGrey,
              contentPadding: const EdgeInsets.symmetric(horizontal: 16, vertical: 0),
              border: OutlineInputBorder(borderRadius: BorderRadius.circular(12), borderSide: BorderSide.none),
            ),
            onChanged: (v) => setState(() => _searchQuery = v),
          ),
        ),
        // ── Selector de tienda (sólo roles altos) ──────────────
        if (puedeVerTodasLasTiendas() && ConfigSistema.tiendas.length > 1)
          Container(
            color: Colors.white,
            padding: const EdgeInsets.fromLTRB(12, 0, 12, 8),
            child: Row(children: [
              const Icon(Icons.store_outlined,
                size: 18, color: AppColors.textSecondary),
              const SizedBox(width: 6),
              const Text('Tienda:',
                style: TextStyle(fontSize: 12,
                  color: AppColors.textSecondary,
                  fontWeight: FontWeight.w600)),
              const SizedBox(width: 8),
              Expanded(
                child: SingleChildScrollView(
                  scrollDirection: Axis.horizontal,
                  child: Row(children: [
                    ChoiceChip(
                      label: const Text('Todas', style: TextStyle(fontSize: 12)),
                      selected: _tiendaFiltro == 'Todas',
                      onSelected: (_) => setState(() => _tiendaFiltro = 'Todas'),
                    ),
                    const SizedBox(width: 6),
                    ...ConfigSistema.tiendas.map((t) => Padding(
                      padding: const EdgeInsets.only(right: 6),
                      child: ChoiceChip(
                        label: Text(t, style: const TextStyle(fontSize: 12)),
                        selected: _tiendaFiltro == t,
                        onSelected: (_) => setState(() => _tiendaFiltro = t),
                      ),
                    )),
                  ]),
                ),
              ),
            ]),
          ),
        // Indicador de "viendo solo mi tienda" para vendedor/activador
        if (!puedeVerTodasLasTiendas() && tiendaUsuarioActual().isNotEmpty)
          Container(
            color: AppColors.royalBlue.withValues(alpha: 0.06),
            padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),
            child: Row(children: [
              const Icon(Icons.store_outlined,
                size: 14, color: AppColors.royalBlue),
              const SizedBox(width: 6),
              Text('Viendo ventas de: ${tiendaUsuarioActual()}',
                style: const TextStyle(fontSize: 11,
                  color: AppColors.royalBlue, fontWeight: FontWeight.w600)),
            ]),
          ),
        if (_cargando)
          const Expanded(child: Center(child: CircularProgressIndicator()))
        else if (filtradas.isEmpty)
          Expanded(child: EmptyState(
            mensaje: _searchQuery.isEmpty
              ? "No hay facturas registradas.\nPresione + para crear una."
              : "No se encontraron resultados para \"$_searchQuery\".",
            icono: Icons.receipt_long_outlined,
          ))
        else
          Expanded(child: RefreshIndicator(
            onRefresh: _cargarFacturas,
            child: ListView.builder(
              padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
              itemCount: filtradas.length,
              itemBuilder: (c, i) {
                final factura = filtradas[i];
                final total = double.tryParse(factura['total'].toString()) ?? 0;
                final pagos = (factura['pagos'] as List?) ?? [];

                return Card(
                  margin: const EdgeInsets.only(bottom: 8),
                  shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(12)),
                  elevation: 1,
                  child: InkWell(
                    borderRadius: BorderRadius.circular(12),
                    onTap: () => _mostrarDetalleFactura(factura),
                    child: Padding(
                      padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 12),
                      child: Row(crossAxisAlignment: CrossAxisAlignment.start, children: [
                        // Avatar
                        CircleAvatar(
                          backgroundColor: AppColors.royalBlue.withValues(alpha: 0.1),
                          radius: 22,
                          child: Text(
                            ((factura['cliente'] ?? '?') as String).isNotEmpty
                              ? (factura['cliente'] as String)[0].toUpperCase()
                              : '?',
                            style: const TextStyle(color: AppColors.royalBlue, fontWeight: FontWeight.bold, fontSize: 16),
                          ),
                        ),
                        const SizedBox(width: 12),
                        // Info central
                        Expanded(child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                          Text(factura['cliente'] ?? '',
                            style: const TextStyle(fontWeight: FontWeight.w600, color: AppColors.textPrimary, fontSize: 14)),
                          const SizedBox(height: 2),
                          Text(
                            "Fact. ${factura['nro_factura'] ?? ''} · ${factura['fecha'] ?? ''}",
                            style: const TextStyle(fontSize: 11, color: AppColors.textSecondary)),
                          Text(
                            "${factura['tienda'] ?? ''} · ${factura['vendedor'] ?? ''}",
                            style: const TextStyle(fontSize: 11, color: AppColors.textSecondary)),
                          // ── Chips de métodos de pago ──────────────
                          if (pagos.isNotEmpty) ...[
                            const SizedBox(height: 6),
                            Wrap(spacing: 4, runSpacing: 4, children: pagos.map((p) {
                              final metodo = p['metodo']?.toString() ?? '';
                              final monto  = double.tryParse(p['monto'].toString()) ?? 0;
                              final color  = _colorMetodoPago(metodo);
                              return Container(
                                padding: const EdgeInsets.symmetric(horizontal: 7, vertical: 3),
                                decoration: BoxDecoration(
                                  color: color.withValues(alpha: 0.10),
                                  borderRadius: BorderRadius.circular(20),
                                  border: Border.all(color: color.withValues(alpha: 0.35)),
                                ),
                                child: Row(mainAxisSize: MainAxisSize.min, children: [
                                  Icon(_iconoMetodoPago(metodo), size: 11, color: color),
                                  const SizedBox(width: 3),
                                  Text(
                                    "$metodo ${formatMontoPorMetodo(monto, metodo)}",
                                    style: TextStyle(fontSize: 10, color: color, fontWeight: FontWeight.w600),
                                  ),
                                ]),
                              );
                            }).toList()),
                          ],
                        ])),
                        // Total
                        const SizedBox(width: 8),
                        Column(mainAxisAlignment: MainAxisAlignment.start, crossAxisAlignment: CrossAxisAlignment.end, children: [
                          Text(formatCurrency(total),
                            style: const TextStyle(fontWeight: FontWeight.bold, color: AppColors.primaryBlue, fontSize: 15)),
                          const SizedBox(height: 4),
                          const Icon(Icons.chevron_right, size: 16, color: AppColors.textSecondary),
                        ]),
                      ]),
                    ),
                  ),
                );
              },
            ),
          )),
      ]),
      floatingActionButton: FloatingActionButton.extended(
        backgroundColor: AppColors.primaryBlue,
        onPressed: () async {
          final res = await Navigator.push(context,
            MaterialPageRoute(builder: (c) => FormularioFactura(tienda: widget.tienda)));
          if (res != null) _cargarFacturas();
        },
        icon: const Icon(Icons.add, color: Colors.white),
        label: const Text("Nueva Factura", style: TextStyle(color: Colors.white, fontWeight: FontWeight.w600)),
      ),
    );
  }

  void _mostrarDetalleFactura(Map<String,dynamic> factura) {
    final total = double.tryParse(factura['total'].toString()) ?? 0;
    final tasa  = ConfigSistema.tasaCambio;
    final pagos = (factura['pagos'] as List?) ?? [];

    showModalBottomSheet(
      context: context,
      isScrollControlled: true,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(20))),
      builder: (context) => DraggableScrollableSheet(
        initialChildSize: 0.70,
        maxChildSize: 0.95,
        minChildSize: 0.4,
        expand: false,
        builder: (_, ctrl) => Column(children: [
          // Handle
          Container(
            margin: const EdgeInsets.only(top: 12, bottom: 8),
            width: 40, height: 4,
            decoration: BoxDecoration(color: Colors.grey[300], borderRadius: BorderRadius.circular(2)),
          ),
          Expanded(child: SingleChildScrollView(
            controller: ctrl,
            padding: const EdgeInsets.fromLTRB(24, 8, 24, 24),
            child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
              // ── Encabezado ────────────────────────────────────
              Row(children: [
                Expanded(child: Text("Factura ${factura['nro_factura'] ?? ''}",
                  style: const TextStyle(fontSize: 20, fontWeight: FontWeight.bold))),
                Container(
                  padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 4),
                  decoration: BoxDecoration(
                    color: AppColors.statusGreen.withValues(alpha: 0.12),
                    borderRadius: BorderRadius.circular(20)),
                  child: const Text("Pagada", style: TextStyle(
                    color: AppColors.statusGreen, fontWeight: FontWeight.bold, fontSize: 12)),
                ),
              ]),
              const SizedBox(height: 16),

              // ── Datos del cliente ─────────────────────────────
              _detalleRow(Icons.person_outline, "Cliente", factura['cliente'] ?? ''),
              _detalleRow(Icons.badge_outlined, "Cédula", factura['cedula'] ?? ''),
              _detalleRow(Icons.phone_outlined, "Teléfono", factura['telefono'] ?? ''),
              _detalleRow(Icons.store_outlined, "Tienda", factura['tienda'] ?? ''),
              _detalleRow(Icons.sell_outlined, "Vendedor", factura['vendedor'] ?? ''),
              _detalleRow(Icons.calendar_today_outlined, "Fecha", factura['fecha'] ?? ''),

              // ── Productos facturados (equipos + items) ────────
              Builder(builder: (_) {
                // Construir lista de productos con IMEI/código
                final rawEquipos = (factura['equipos'] as List?) ?? [];
                final rawItems   = (factura['items']   as List?) ?? [];
                if (rawEquipos.isEmpty && rawItems.isEmpty) {
                  // Fallback al campo antiguo 'imeis' si existe
                  if ((factura['imeis'] ?? '').toString().isNotEmpty &&
                      factura['imeis'] != 'ninguno') {
                    return _detalleRow(Icons.smartphone_outlined, "IMEIs",
                      factura['imeis'] ?? '');
                  }
                  return const SizedBox.shrink();
                }

                return Padding(
                  padding: const EdgeInsets.only(top: 16),
                  child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                    Row(children: [
                      const Icon(Icons.inventory_2_outlined, size: 16, color: AppColors.royalBlue),
                      const SizedBox(width: 6),
                      const Text("Productos facturados",
                        style: TextStyle(fontSize: 14, fontWeight: FontWeight.bold,
                          color: AppColors.royalBlue)),
                      const Spacer(),
                      Container(
                        padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 2),
                        decoration: BoxDecoration(
                          color: AppColors.royalBlue.withValues(alpha: 0.1),
                          borderRadius: BorderRadius.circular(12)),
                        child: Text("${rawEquipos.length + rawItems.length}",
                          style: const TextStyle(fontSize: 11, color: AppColors.royalBlue,
                            fontWeight: FontWeight.w600)),
                      ),
                    ]),
                    const SizedBox(height: 10),

                    // Equipos con IMEI
                    ...rawEquipos.map((e) {
                      String imei = '';
                      if (e is String) imei = e;
                      else if (e is Map) imei = (e['imei'] ?? '').toString();

                      // Buscar en stock global para conocer el producto
                      final reg = stockImeiGlobal
                        .where((i) => i.imei == imei).firstOrNull;
                      final nombre = reg?.producto.nombre ?? 'Equipo';
                      final codigo = reg?.producto.codigo ?? '';
                      String modelo = (reg?.producto.modelo ?? '').trim();
                      // Fallback: si el modelo está vacío en el registro
                      // de stock, intentamos resolverlo desde el catálogo
                      // de productos por código.
                      if (modelo.isEmpty && codigo.isNotEmpty) {
                        final prod = catalogoGlobal
                            .where((p) => p.codigo == codigo).firstOrNull;
                        if (prod != null) modelo = prod.modelo.trim();
                      }
                      final precio = reg?.producto.precioVenta ?? 0;

                      return Container(
                        margin: const EdgeInsets.only(bottom: 6),
                        padding: const EdgeInsets.all(10),
                        decoration: BoxDecoration(
                          color: AppColors.primaryBlue.withValues(alpha: 0.05),
                          borderRadius: BorderRadius.circular(8),
                          border: Border.all(
                            color: AppColors.primaryBlue.withValues(alpha: 0.2)),
                        ),
                        child: Row(children: [
                          Container(
                            width: 36, height: 36,
                            decoration: BoxDecoration(
                              color: AppColors.primaryBlue.withValues(alpha: 0.15),
                              borderRadius: BorderRadius.circular(8)),
                            child: const Icon(Icons.phone_android_outlined,
                              size: 18, color: AppColors.primaryBlue),
                          ),
                          const SizedBox(width: 10),
                          Expanded(child: Column(
                            crossAxisAlignment: CrossAxisAlignment.start,
                            children: [
                              Text(nombre,
                                style: const TextStyle(fontSize: 13,
                                  fontWeight: FontWeight.w600)),
                              if (modelo.isNotEmpty) ...[
                                const SizedBox(height: 3),
                                Row(children: [
                                  const Icon(Icons.devices_other_outlined,
                                    size: 12, color: AppColors.primaryBlue),
                                  const SizedBox(width: 4),
                                  Flexible(
                                    child: Text(modelo,
                                      style: const TextStyle(fontSize: 11.5,
                                        color: AppColors.primaryBlue,
                                        fontWeight: FontWeight.w600),
                                      overflow: TextOverflow.ellipsis),
                                  ),
                                ]),
                              ],
                              const SizedBox(height: 2),
                              Text("IMEI: $imei",
                                style: const TextStyle(fontSize: 11,
                                  color: AppColors.textSecondary,
                                  fontFamily: 'monospace')),
                              if (codigo.isNotEmpty)
                                Text("Cód: $codigo",
                                  style: const TextStyle(fontSize: 10,
                                    color: AppColors.textSecondary)),
                            ])),
                          if (precio > 0)
                            Text(formatCurrency(precio),
                              style: const TextStyle(fontSize: 13,
                                fontWeight: FontWeight.bold,
                                color: AppColors.primaryBlue)),
                        ]),
                      );
                    }),

                    // Items sin IMEI
                    ...rawItems.map((i) {
                      String cod = '';
                      if (i is String) cod = i;
                      else if (i is Map) cod = (i['producto_codigo'] ?? i['codigo'] ?? '').toString();

                      final prod = catalogoGlobal
                        .where((p) => p.codigo == cod).firstOrNull;
                      final nombre = prod?.nombre ?? 'Producto $cod';
                      final precio = prod?.precioVenta ?? 0;

                      return Container(
                        margin: const EdgeInsets.only(bottom: 6),
                        padding: const EdgeInsets.all(10),
                        decoration: BoxDecoration(
                          color: AppColors.statusGreen.withValues(alpha: 0.05),
                          borderRadius: BorderRadius.circular(8),
                          border: Border.all(
                            color: AppColors.statusGreen.withValues(alpha: 0.2)),
                        ),
                        child: Row(children: [
                          Container(
                            width: 36, height: 36,
                            decoration: BoxDecoration(
                              color: AppColors.statusGreen.withValues(alpha: 0.15),
                              borderRadius: BorderRadius.circular(8)),
                            child: const Icon(Icons.extension_outlined,
                              size: 18, color: AppColors.statusGreen),
                          ),
                          const SizedBox(width: 10),
                          Expanded(child: Column(
                            crossAxisAlignment: CrossAxisAlignment.start,
                            children: [
                              Text(nombre,
                                style: const TextStyle(fontSize: 13,
                                  fontWeight: FontWeight.w600)),
                              const SizedBox(height: 2),
                              Text("Cód: $cod",
                                style: const TextStyle(fontSize: 11,
                                  color: AppColors.textSecondary,
                                  fontFamily: 'monospace')),
                            ])),
                          if (precio > 0)
                            Text(formatCurrency(precio),
                              style: const TextStyle(fontSize: 13,
                                fontWeight: FontWeight.bold,
                                color: AppColors.statusGreen)),
                        ]),
                      );
                    }),
                  ]),
                );
              }),

              // ── Métodos de Pago (sección visual) ─────────────
              const SizedBox(height: 16),
              Row(children: [
                const Icon(Icons.payments_outlined, size: 16, color: AppColors.royalBlue),
                const SizedBox(width: 6),
                const Text("Métodos de Pago",
                  style: TextStyle(fontSize: 14, fontWeight: FontWeight.bold,
                    color: AppColors.royalBlue)),
                const Spacer(),
                if (pagos.isNotEmpty)
                  Container(
                    padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 2),
                    decoration: BoxDecoration(
                      color: AppColors.royalBlue.withValues(alpha: 0.1),
                      borderRadius: BorderRadius.circular(12)),
                    child: Text("${pagos.length} método${pagos.length != 1 ? 's' : ''}",
                      style: const TextStyle(fontSize: 11, color: AppColors.royalBlue,
                        fontWeight: FontWeight.w600)),
                  ),
              ]),
              const SizedBox(height: 10),

              if (pagos.isEmpty)
                Container(
                  padding: const EdgeInsets.all(14),
                  decoration: BoxDecoration(
                    color: Colors.grey[100],
                    borderRadius: BorderRadius.circular(10)),
                  child: const Row(children: [
                    Icon(Icons.info_outline, size: 16, color: AppColors.textSecondary),
                    SizedBox(width: 8),
                    Text("Sin detalle de pagos registrado.",
                      style: TextStyle(color: AppColors.textSecondary, fontSize: 13)),
                  ]),
                )
              else
                ...pagos.map((p) {
                  final metodo = p['metodo']?.toString() ?? '';
                  final monto  = double.tryParse(p['monto'].toString()) ?? 0;
                  final tipo   = p['tipo']?.toString() ?? '';
                  final financiador = p['financiador']?.toString() ?? '';
                  final color  = _colorMetodoPago(metodo);
                  return Container(
                    margin: const EdgeInsets.only(bottom: 8),
                    padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 12),
                    decoration: BoxDecoration(
                      color: color.withValues(alpha: 0.06),
                      borderRadius: BorderRadius.circular(10),
                      border: Border.all(color: color.withValues(alpha: 0.25)),
                    ),
                    child: Row(children: [
                      Container(
                        width: 38, height: 38,
                        decoration: BoxDecoration(
                          color: color.withValues(alpha: 0.12),
                          borderRadius: BorderRadius.circular(8)),
                        child: Icon(_iconoMetodoPago(metodo), color: color, size: 20),
                      ),
                      const SizedBox(width: 12),
                      Expanded(child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                        Text(metodo,
                          style: TextStyle(fontWeight: FontWeight.w600, fontSize: 14, color: color)),
                        if (tipo.isNotEmpty && tipo != 'Contado')
                          Text(tipo, style: const TextStyle(fontSize: 11, color: AppColors.textSecondary)),
                        if (financiador != null && financiador.isNotEmpty)
                          Text("Financiador: $financiador",
                            style: const TextStyle(fontSize: 11, color: AppColors.textSecondary)),
                      ])),
                      Text(formatMontoPorMetodo(monto, metodo),
                        style: TextStyle(fontWeight: FontWeight.bold, fontSize: 16, color: color)),
                    ]),
                  );
                }),

              // ── Botones de acción ─────────────────────────────
              const SizedBox(height: 20),
              SizedBox(
                width: double.infinity,
                child: ElevatedButton.icon(
                  icon: const Icon(Icons.print_outlined),
                  label: const Text("Imprimir Factura"),
                  style: ElevatedButton.styleFrom(
                    backgroundColor: AppColors.royalBlue,
                    padding: const EdgeInsets.symmetric(vertical: 13),
                    shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
                  ),
                  onPressed: () async {
                    // Construir el FacturaModel completo con equipos e items
                    // reales (busca en catalogoGlobal + stockImeiGlobal).
                    final fm = construirFacturaModelDesdeJson(factura);
                    try {
                      await imprimirFactura(fm, context);
                    } catch (e) {
                      if (context.mounted) {
                        ScaffoldMessenger.of(context).showSnackBar(SnackBar(
                          content: Text("Error al imprimir: $e"),
                          backgroundColor: AppColors.statusRed));
                      }
                    }
                  },
                ),
              ),
              const SizedBox(height: 10),
              Row(children: [
                // ── Editar y Eliminar: SOLO para Administrador ─────────
                // Estas acciones modifican/eliminan datos contables, así
                // que se restringen al rol 'Administrador' únicamente.
                // Otros roles (incluido 'Dueño', 'Gerente', etc.) no ven
                // estos botones.
                if (checkAccess(['Administrador'])) ...[
                  Expanded(child: OutlinedButton.icon(
                    icon: const Icon(Icons.edit_outlined, color: AppColors.primaryBlue),
                    label: const Text("Editar",
                      style: TextStyle(color: AppColors.primaryBlue)),
                    style: OutlinedButton.styleFrom(
                      side: const BorderSide(color: AppColors.primaryBlue),
                      padding: const EdgeInsets.symmetric(vertical: 13),
                      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
                    ),
                    onPressed: () => _editarFactura(factura),
                  )),
                  const SizedBox(width: 10),
                  Expanded(child: OutlinedButton.icon(
                    icon: const Icon(Icons.delete_outline, color: Colors.red),
                    label: const Text("Eliminar", style: TextStyle(color: Colors.red)),
                    style: OutlinedButton.styleFrom(
                      side: const BorderSide(color: Colors.red),
                      padding: const EdgeInsets.symmetric(vertical: 13),
                      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
                    ),
                    onPressed: () => _confirmarEliminar(context, factura),
                  )),
                  const SizedBox(width: 10),
                ],
                Expanded(child: OutlinedButton.icon(
                  icon: const Icon(Icons.close),
                  label: const Text("Cerrar"),
                  style: OutlinedButton.styleFrom(
                    padding: const EdgeInsets.symmetric(vertical: 13),
                    shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
                  ),
                  onPressed: () => Navigator.pop(context),
                )),
              ]),
            ]),
          )),
        ]),
      ),
    );
  }

  Widget _detalleRow(IconData icon, String label, String value) => Padding(
    padding: const EdgeInsets.symmetric(vertical: 6),
    child: Row(children: [
      Icon(icon, size: 18, color: AppColors.textSecondary),
      const SizedBox(width: 8),
      Text("$label: ", style: const TextStyle(color: AppColors.textSecondary, fontSize: 13)),
      Expanded(child: Text(value, style: const TextStyle(fontWeight: FontWeight.w500, fontSize: 13))),
    ]),
  );

  /// Abre el formulario de factura en modo EDICIÓN.
  /// Solo accesible desde el botón "Editar" del detalle, que a su vez
  /// solo se muestra al rol 'Administrador' (ver _mostrarDetalleFactura).
  ///
  /// Convierte el Map que viene de la API al FacturaModel completo
  /// (con equipos, items y pagos resueltos desde el catálogo global)
  /// y lo pasa al FormularioFactura.
  Future<void> _editarFactura(Map<String, dynamic> factura) async {
    // Doble verificación de rol: aunque el botón esté oculto para no
    // administradores, protegemos también aquí por si se invocara por
    // otro camino (navegación directa, atajo, etc.).
    if (!checkAccess(['Administrador'])) {
      ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
        content: Text("Solo un Administrador puede editar facturas."),
        backgroundColor: AppColors.statusRed));
      return;
    }

    // Convertir el Map a FacturaModel completo (equipos + items + pagos)
    final modelo = construirFacturaModelDesdeJson(factura);

    // Cerrar el bottom sheet del detalle y abrir el formulario
    Navigator.pop(context);
    final res = await Navigator.push(context,
      MaterialPageRoute(builder: (c) => FormularioFactura(
        tienda: widget.tienda,
        facturaAEditar: modelo)));
    if (res != null && mounted) _cargarFacturas();
  }

  Future<void> _confirmarEliminar(BuildContext ctx, Map<String,dynamic> factura) async {
    final confirmar = await showDialog<bool>(
      context: ctx,
      builder: (c) => AlertDialog(
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(16)),
        title: const Row(children: [
          Icon(Icons.warning_amber, color: AppColors.statusRed),
          SizedBox(width: 8),
          Text("Eliminar Factura"),
        ]),
        content: Column(mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.start, children: [
          Text("¿Está seguro de eliminar la factura ${factura['nro_factura'] ?? ''}?",
            style: const TextStyle(fontWeight: FontWeight.w500)),
          const SizedBox(height: 8),
          const Text("Esta acción no se puede deshacer.",
            style: TextStyle(color: AppColors.statusRed, fontSize: 12)),
          const SizedBox(height: 4),
          const Text(
            "Los equipos vendidos volverán automáticamente al inventario "
            "(IMEIs disponibles y accesorios con stock restaurado).",
            style: TextStyle(color: AppColors.statusGreen, fontSize: 12,
              fontStyle: FontStyle.italic)),
        ]),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(c, false),
            child: const Text("Cancelar")),
          ElevatedButton.icon(
            style: ElevatedButton.styleFrom(
              backgroundColor: AppColors.statusRed),
            icon: const Icon(Icons.delete_forever_outlined, size: 16, color: Colors.white),
            label: const Text("Eliminar Definitivamente",
              style: TextStyle(color: Colors.white)),
            onPressed: () => Navigator.pop(c, true)),
        ],
      ));

    if (confirmar != true || !mounted) return;

    try {
      await _Api.delete('facturas', factura['id'].toString());
      if (!mounted) return;
      Navigator.pop(context); // cierra el bottom sheet
      await _cargarFacturas();
      ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Text("Factura ${factura['nro_factura'] ?? ''} eliminada."),
        backgroundColor: AppColors.statusRed,
        duration: const Duration(seconds: 3)));
    } catch (e) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Text("Error al eliminar: $e"),
        backgroundColor: AppColors.statusRed));
    }
  }

  // ── Helpers de métodos de pago ──────────────────────────────
  IconData _iconoMetodoPago(String metodo) {
    final m = metodo.toLowerCase();
    if (m.contains('efectivo') || m.contains('cash')) return Icons.payments_outlined;
    if (m.contains('transferencia') || m.contains('transfer')) return Icons.swap_horiz;
    if (m.contains('tarjeta') || m.contains('débito') || m.contains('credito')) return Icons.credit_card;
    if (m.contains('zelle')) return Icons.send_to_mobile;
    if (m.contains('pago') && m.contains('movil')) return Icons.phone_android;
    if (m.contains('dolar') || m.contains('divisas') || m.contains('usd')) return Icons.attach_money;
    if (m.contains('bolivar') || m.contains('bs')) return Icons.currency_exchange;
    if (m.contains('cashea') || m.contains('weppa') || m.contains('krece') || m.contains('financ')) return Icons.account_balance_outlined;
    return Icons.payment;
  }

  Color _colorMetodoPago(String metodo) {
    final m = metodo.toLowerCase();
    if (m.contains('efectivo') || m.contains('cash'))           return const Color(0xFF2E7D32);
    if (m.contains('transferencia') || m.contains('transfer'))  return const Color(0xFF1565C0);
    if (m.contains('tarjeta') || m.contains('débito') || m.contains('credito')) return const Color(0xFF6A1B9A);
    if (m.contains('zelle'))                                    return const Color(0xFF6200EA);
    if (m.contains('pago') && m.contains('movil'))              return const Color(0xFFE65100);
    if (m.contains('dolar') || m.contains('usd'))               return const Color(0xFF00695C);
    if (m.contains('bolivar') || m.contains('bs'))              return const Color(0xFF283593);
    if (m.contains('cashea'))                                   return const Color(0xFFC62828);
    if (m.contains('weppa') || m.contains('krece'))             return const Color(0xFF00838F);
    return AppColors.primaryBlue;
  }

