// ============================================================
//  VENTANA DISPONIBLE
// ============================================================
class VentanaDisponible extends StatefulWidget {
  const VentanaDisponible({super.key});
  @override State<VentanaDisponible> createState() => _VentanaDisponibleState();
}

class _VentanaDisponibleState extends State<VentanaDisponible> {
  List<Producto> _productos = [];
  List<ImeiRegistro> _imeis = [];
  bool _cargando = true;
  String _query = '';
  String _filtroCategoria = 'Todos';

  @override
  void initState() { super.initState(); _cargar(); }

  Future<void> _cargar() async {
    setState(() => _cargando = true);
    try {
      final results = await Future.wait([
        _Api.get('productos'),
        _Api.get('stock_imei'),
      ]);
      final rawP = results[0];
      final rawI = results[1];

      // PRIMERO productos (catalogoGlobal lo necesita ImeiRegistro.fromMap)
      _productos = ((rawP as List?) ?? [])
          .map((m) => Producto.fromMap(m))
          .toList();
      catalogoGlobal = _productos;

      // DESPUÉS IMEIs (ya con catalogoGlobal listo)
      _imeis = ((rawI as List?) ?? [])
          .map((m) => ImeiRegistro.fromMap(m))
          .toList();
      stockImeiGlobal = _imeis;

      // Calcular stockTotal por producto
      for (final p in _productos) {
        if (p.categoria == 'Telefono') {
          p.stockTotal = _imeis
              .where((i) => i.producto.codigo == p.codigo && !i.vendido)
              .length;
        } else {
          p.stockTotal = p.stockManual;
        }
      }

      // Sumar el stock de los SUBPRODUCTOS al padre — el padre es lo
      // que se muestra; el stock debe reflejar el total agregado.
      final hijosPorPadre = <String, List<Producto>>{};
      for (final p in _productos) {
        if (p.productoPadreCodigo.isNotEmpty) {
          hijosPorPadre.putIfAbsent(p.productoPadreCodigo, () => [])
              .add(p);
        }
      }
      for (final padre in _productos.where((p) => p.productoPadreCodigo.isEmpty)) {
        final hijos = hijosPorPadre[padre.codigo] ?? const <Producto>[];
        for (final h in hijos) {
          padre.stockTotal += h.stockTotal;
        }
      }

      // Ordenar: más stock primero
      _productos.sort((a, b) => b.stockTotal.compareTo(a.stockTotal));
    } catch (e) {
      debugPrint('[VentanaDisponible._cargar] Error: $e');
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Error al cargar datos: $e'),
          backgroundColor: AppColors.statusRed,
          duration: const Duration(seconds: 4)));
    } finally {
      if (mounted) setState(() => _cargando = false);
    }
  }

  List<Producto> get _productosFiltrados {
    return _productos.where((p) {
      // EXCLUIR subproductos — solo padres en el listado.
      if (p.productoPadreCodigo.isNotEmpty) return false;

      final matchQuery = _query.isEmpty ||
          p.nombre.toLowerCase().contains(_query.toLowerCase()) ||
          p.codigo.toLowerCase().contains(_query.toLowerCase()) ||
          p.marca.toLowerCase().contains(_query.toLowerCase());
      final matchCat = _filtroCategoria == 'Todos' || p.categoria == _filtroCategoria;
      return matchQuery && matchCat && p.stockTotal > 0;
    }).toList();
  }

  @override
  Widget build(BuildContext context) {
    final categorias = ['Todos', ...{ for (var p in _productos) p.categoria }];
    final filtrados = _productosFiltrados;
    final totalUnidades = filtrados.fold(0, (s, p) => s + p.stockTotal);

    return Scaffold(
      appBar: AppBar(
        title: const Text("Stock Disponible"),
        actions: [IconButton(icon: const Icon(Icons.refresh), tooltip: "Actualizar", onPressed: _cargar)],
      ),
      body: Column(children: [
        // Barra de búsqueda y filtros
        Container(
          color: Colors.white,
          padding: const EdgeInsets.fromLTRB(12, 8, 12, 0),
          child: Column(children: [
            TextField(
              decoration: InputDecoration(
                hintText: "Buscar producto, código o marca...",
                prefixIcon: const Icon(Icons.search, color: AppColors.primaryBlue),
                suffixIcon: _query.isNotEmpty
                  ? IconButton(icon: const Icon(Icons.clear, size: 18), onPressed: () => setState(() => _query = ''))
                  : null,
                filled: true, fillColor: AppColors.surfaceGrey,
                border: OutlineInputBorder(borderRadius: BorderRadius.circular(12), borderSide: BorderSide.none),
                contentPadding: const EdgeInsets.symmetric(vertical: 0, horizontal: 16),
              ),
              onChanged: (v) => setState(() => _query = v),
            ),
            const SizedBox(height: 8),
            SizedBox(height: 34, child: ListView(scrollDirection: Axis.horizontal, children: [
              ...categorias.map((cat) => Padding(
                padding: const EdgeInsets.only(right: 8),
                child: FilterChip(
                  label: Text(cat, style: const TextStyle(fontSize: 12)),
                  selected: _filtroCategoria == cat,
                  onSelected: (_) => setState(() => _filtroCategoria = cat),
                  selectedColor: AppColors.primaryBlue.withValues(alpha: 0.15),
                  checkmarkColor: AppColors.primaryBlue,
                ),
              )),
            ])),
            const SizedBox(height: 8),
          ]),
        ),
        // Resumen
        Container(
          padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 10),
          color: AppColors.surfaceGrey,
          child: Row(children: [
            Text("${filtrados.length} productos · $totalUnidades unidades",
              style: const TextStyle(color: AppColors.textSecondary, fontSize: 13)),
          ]),
        ),
        if (_cargando)
          const Expanded(child: Center(child: CircularProgressIndicator()))
        else if (filtrados.isEmpty)
          const Expanded(child: EmptyState(mensaje: "No hay productos disponibles.", icono: Icons.inventory_2_outlined))
        else
          Expanded(child: RefreshIndicator(
            onRefresh: _cargar,
            child: ListView.builder(
              padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
              itemCount: filtrados.length,
              itemBuilder: (context, index) {
                final p = filtrados[index];
                final stockColor = p.stockTotal >= 5 ? AppColors.statusGreen
                    : p.stockTotal >= 2 ? AppColors.statusOrange
                    : AppColors.statusRed;
                return Card(
                  margin: const EdgeInsets.only(bottom: 8),
                  shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(12)),
                  elevation: 1,
                  child: ListTile(
                    contentPadding: const EdgeInsets.symmetric(horizontal: 16, vertical: 8),
                    leading: Container(
                      width: 44, height: 44,
                      decoration: BoxDecoration(
                        color: stockColor.withValues(alpha: 0.1),
                        borderRadius: BorderRadius.circular(10),
                      ),
                      child: Center(child: Text("${p.stockTotal}",
                        style: TextStyle(fontWeight: FontWeight.bold, fontSize: 18, color: stockColor))),
                    ),
                    title: Text("${p.nombre}",
                      style: const TextStyle(fontWeight: FontWeight.w600, color: AppColors.textPrimary)),
                    subtitle: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                      Text("${p.codigo} · ${p.marca}", style: const TextStyle(fontSize: 12, color: AppColors.textSecondary)),
                      if (p.categoria == "iPhone" && p.porcentajeBateria != null)
                        Row(children: [
                          const Icon(Icons.battery_charging_full, size: 13, color: AppColors.statusGreen),
                          const SizedBox(width: 2),
                          Text("Batería: ${p.porcentajeBateria}%",
                            style: const TextStyle(fontSize: 11, color: AppColors.statusGreen)),
                        ]),
                    ]),
                    trailing: Column(mainAxisAlignment: MainAxisAlignment.center, children: [
                      Text(formatCurrency(p.precioVenta),
                        style: const TextStyle(fontWeight: FontWeight.bold, color: AppColors.primaryBlue)),
                      const Icon(Icons.chevron_right, size: 16, color: AppColors.textSecondary),
                    ]),
                    onTap: () => _mostrarUbicaciones(p),
                  ),
                );
              },
            ),
          )),
      ]),
    );
  }

  void _mostrarUbicaciones(Producto p) {
    final imeis = _imeis.where((i) => i.producto.codigo == p.codigo && !i.vendido).toList();
    Map<String,List<ImeiRegistro>> porUbicacion = {};
    for (var i in imeis) {
      porUbicacion.putIfAbsent(i.ubicacion, () => []).add(i);
    }
    showModalBottomSheet(
      context: context,
      shape: const RoundedRectangleBorder(borderRadius: BorderRadius.vertical(top: Radius.circular(20))),
      builder: (c) => Padding(
        padding: const EdgeInsets.all(24),
        child: Column(mainAxisSize: MainAxisSize.min, crossAxisAlignment: CrossAxisAlignment.start, children: [
          Text(p.nombre, style: const TextStyle(fontSize: 18, fontWeight: FontWeight.bold)),
          Text("${p.codigo} · ${imeis.length} unidades", style: const TextStyle(color: AppColors.textSecondary)),
          const Divider(height: 24),
          ...porUbicacion.entries.map((e) => ListTile(
            contentPadding: EdgeInsets.zero,
            leading: const Icon(Icons.location_on_outlined, color: AppColors.primaryBlue),
            title: Text(e.key, style: const TextStyle(fontWeight: FontWeight.w600)),
            trailing: Container(
              padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 4),
              decoration: BoxDecoration(color: AppColors.primaryBlue.withValues(alpha: 0.1), borderRadius: BorderRadius.circular(12)),
              child: Text("${e.value.length} uds", style: const TextStyle(color: AppColors.primaryBlue, fontWeight: FontWeight.bold)),
            ),
          )),
          const SizedBox(height: 8),
        ]),
      ),
    );
  }
}

