  Widget _ir(IconData icon, String label, String value) =>
    value.isEmpty ? const SizedBox() :
    Row(mainAxisSize: MainAxisSize.min, children: [
      Icon(icon, size: 14, color: AppColors.textSecondary),
      const SizedBox(width: 4),
      Text("$label: ", style: const TextStyle(
        fontSize: 12, color: AppColors.textSecondary)),
      _resaltar(value, const TextStyle(fontSize: 12, fontWeight: FontWeight.w500)),
    ]);

  /// Resalta en amarillo las coincidencias del query dentro del texto.
  Widget _resaltar(String texto, TextStyle estilo) {
    final q = widget.queryResaltado.toLowerCase().trim();
    if (q.isEmpty) return Text(texto, style: estilo);
    final lower = texto.toLowerCase();
    final idx = lower.indexOf(q);
    if (idx == -1) return Text(texto, style: estilo);
    return RichText(
      text: TextSpan(style: estilo, children: <InlineSpan>[
        if (idx > 0) TextSpan(text: texto.substring(0, idx)),
        TextSpan(
          text: texto.substring(idx, idx + q.length),
          style: estilo.copyWith(
            backgroundColor: Colors.yellow.shade300,
            fontWeight: FontWeight.bold,
            color: Colors.black87)),
        if (idx + q.length < texto.length)
          TextSpan(text: texto.substring(idx + q.length)),
      ]),
    );
  }
}

