// ─── Eliminadas: clases (líneas 13422-14478 originales) ─── eliminado en rediseño v2.1
class VentanaServicioTecnico extends StatefulWidget {
  const VentanaServicioTecnico({super.key});
  @override State<VentanaServicioTecnico> createState() => _VentanaServicioTecnicoState();
}

class _VentanaServicioTecnicoState extends State<VentanaServicioTecnico> {
  List<ServicioTecnico> _servicios = [];
  bool _cargando = true;
  String? _error;
  String _query = '';

  @override
  void initState() { super.initState(); _cargar(); }

  Future<void> _cargar() async {
    setState(() { _cargando = true; _error = null; });
    try {
      final raw = await _Api.get('servicios');
      _servicios = ((raw as List?) ?? []).map((m) => ServicioTecnico.fromMap(m)).toList();
      _servicios.sort((a, b) => b.fecha.compareTo(a.fecha));
      serviciosGlobal = _servicios;
    } catch (e) {
      debugPrint('[Servicios._cargar] Error: $e');
      _error = e.toString();
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Error al cargar datos: $e'),
          backgroundColor: AppColors.statusRed,
          duration: const Duration(seconds: 4)));
    } finally {
      if (mounted) setState(() => _cargando = false);
    }
  }

  List<ServicioTecnico> get _filtrados {
    if (_query.trim().isEmpty) return _servicios;
    final q = _query.toLowerCase();
    return _servicios.where((s) =>
      s.nombreCliente.toLowerCase().contains(q) ||
      s.telefono.toLowerCase().contains(q) ||
      s.rifCi.toLowerCase().contains(q) ||
      s.marca.toLowerCase().contains(q) ||
      s.modelo.toLowerCase().contains(q) ||
      s.imei.toLowerCase().contains(q) ||
      s.descripcion.toLowerCase().contains(q)
    ).toList();
  }

  @override
  Widget build(BuildContext context) {
    final servicios = _filtrados;
    double total = servicios.fold(0, (sum, item) => sum + item.monto);
    double totalAbonos = servicios.fold(0, (sum, item) => sum + item.abono);
    double totalPendiente = servicios.fold(0, (sum, item) => sum + item.resta);
    double totalCostos = servicios.fold(0, (sum, item) => sum + item.costoRepuestos);
    double totalGanancia = total - totalCostos;

    return Scaffold(
      appBar: AppBar(
        title: const Text("Servicio Técnico"),
        actions: [
          IconButton(
            icon: const Icon(Icons.assessment_outlined),
            tooltip: "Reporte de rentabilidad",
            onPressed: () => Navigator.push(context, MaterialPageRoute(
              builder: (_) => VentanaReporteRentabilidadServicios(servicios: _servicios))),
          ),
          IconButton(
            icon: const Icon(Icons.refresh),
            tooltip: "Actualizar",
            onPressed: _cargar),
        ],
      ),
      body: Column(children: [
        // ── Banner resumen con KPIs (cobrado / costos / ganancia) ──
        Container(
          padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 14),
          decoration: const BoxDecoration(
            gradient: LinearGradient(
              colors: [AppColors.brandBlue, AppColors.brandBlueDark],
              begin: Alignment.topLeft, end: Alignment.bottomRight,
            ),
          ),
          width: double.infinity,
          child: Column(
            children: [
              // Fila 1: Cobrado / Abonado / Pendiente
              Row(mainAxisAlignment: MainAxisAlignment.spaceAround, children: [
                _kpi("Cobrado", formatCurrency(total), Colors.white),
                Container(width: 1, height: 34, color: Colors.white24),
                _kpi("Abonado", formatCurrency(totalAbonos), AppColors.brandYellow),
                Container(width: 1, height: 34, color: Colors.white24),
                _kpi("Pendiente", formatCurrency(totalPendiente), Colors.white70),
                Container(width: 1, height: 34, color: Colors.white24),
                _kpi("Servicios", "${servicios.length}", Colors.white),
              ]),
              const SizedBox(height: 10),
              const Divider(color: Colors.white12, height: 1),
              const SizedBox(height: 10),
              // Fila 2: Cobrado / Costos / Ganancia
              Row(mainAxisAlignment: MainAxisAlignment.spaceAround, children: [
                _kpi("Costo Repuestos", formatCurrency(totalCostos), Colors.orangeAccent),
                Container(width: 1, height: 34, color: Colors.white24),
                _kpi("Ganancia",
                    formatCurrency(totalGanancia),
                    totalGanancia >= 0 ? AppColors.brandYellow : Colors.redAccent),
                Container(width: 1, height: 34, color: Colors.white24),
                _kpi("Margen",
                    total > 0 ? "${(totalGanancia / total * 100).toStringAsFixed(1)}%" : "0%",
                    totalGanancia >= 0 ? Colors.greenAccent : Colors.redAccent),
              ]),
            ],
          ),
        ),

        // ── Buscador ──
        Container(
          color: Colors.white,
          padding: const EdgeInsets.fromLTRB(12, 10, 12, 10),
          child: TextField(
            decoration: InputDecoration(
              hintText: "Buscar por cliente, teléfono, IMEI, marca...",
              prefixIcon: const Icon(Icons.search, color: AppColors.primaryBlue),
              suffixIcon: _query.isNotEmpty
                ? IconButton(
                    icon: const Icon(Icons.clear, size: 18),
                    onPressed: () => setState(() => _query = ''))
                : null,
              filled: true, fillColor: AppColors.surfaceGrey,
              border: OutlineInputBorder(
                borderRadius: BorderRadius.circular(12),
                borderSide: BorderSide.none),
              contentPadding: const EdgeInsets.symmetric(vertical: 0, horizontal: 16),
            ),
            onChanged: (v) => setState(() => _query = v),
          ),
        ),

        // ── Lista ──
        if (_cargando)
          const Expanded(child: Center(child: CircularProgressIndicator()))
        else if (_error != null)
          Expanded(child: ErrorCard(mensaje: _error!, onReintentar: _cargar))
        else if (servicios.isEmpty)
          const Expanded(child: EmptyState(
            mensaje: "No hay servicios registrados.\nPresione + para agregar uno.",
            icono: Icons.build_outlined))
        else
          Expanded(child: RefreshIndicator(
            onRefresh: _cargar,
            child: ListView.builder(
              padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
              itemCount: servicios.length,
              itemBuilder: (c, i) => _buildCardServicio(servicios[i]),
            ),
          )),
      ]),
      floatingActionButton: FloatingActionButton.extended(
        onPressed: _mostrarFormularioNuevo,
        icon: const Icon(Icons.add, color: Colors.white),
        label: const Text("Nuevo", style: TextStyle(color: Colors.white)),
      ),
    );
  }

  Widget _kpi(String label, String value, Color color) => Column(children: [
    Text(label, style: const TextStyle(color: Colors.white70, fontSize: 10)),
    Text(value, style: TextStyle(color: color, fontSize: 15, fontWeight: FontWeight.bold)),
  ]);

  Widget _buildCardServicio(ServicioTecnico s) {
    final estadoColor = {
      'Recibido': AppColors.statusOrange,
      'En reparación': AppColors.primaryBlue,
      'Listo': AppColors.statusGreen,
      'Entregado': Colors.grey,
    }[s.estado] ?? AppColors.statusOrange;

    return Card(
      margin: const EdgeInsets.only(bottom: 8),
      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(12)),
      elevation: 1,
      child: InkWell(
        borderRadius: BorderRadius.circular(12),
        onTap: () => _abrirDetalle(s),
        child: Padding(
          padding: const EdgeInsets.all(12),
          child: Row(children: [
            // ── Icono categoría ──
            Container(
              width: 46, height: 46,
              decoration: BoxDecoration(
                color: AppColors.royalBlue.withValues(alpha: 0.1),
                borderRadius: BorderRadius.circular(10)),
              child: const Icon(Icons.build_outlined,
                color: AppColors.royalBlue, size: 24),
            ),
            const SizedBox(width: 12),

            // ── Info ──
            Expanded(child: Column(
              crossAxisAlignment: CrossAxisAlignment.start, children: [
              Row(children: [
                Expanded(child: Text(
                  s.nombreCliente.isNotEmpty ? s.nombreCliente : '(sin nombre)',
                  style: const TextStyle(fontWeight: FontWeight.w600, fontSize: 14),
                  overflow: TextOverflow.ellipsis)),
                // Badge estado
                Container(
                  padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 2),
                  decoration: BoxDecoration(
                    color: estadoColor.withValues(alpha: 0.15),
                    borderRadius: BorderRadius.circular(10)),
                  child: Text(s.estado,
                    style: TextStyle(fontSize: 10, fontWeight: FontWeight.bold,
                      color: estadoColor)),
                ),
              ]),
              const SizedBox(height: 3),
              Text(
                [if (s.marca.isNotEmpty) s.marca,
                 if (s.modelo.isNotEmpty) s.modelo,
                 if (s.imei.isNotEmpty) "IMEI ${s.imei}"].join(' · '),
                style: const TextStyle(fontSize: 12, color: AppColors.textSecondary),
                maxLines: 1, overflow: TextOverflow.ellipsis),
              if (s.descripcion.isNotEmpty) ...[
                const SizedBox(height: 2),
                Text(s.descripcion,
                  style: const TextStyle(fontSize: 11, color: AppColors.textSecondary),
                  maxLines: 1, overflow: TextOverflow.ellipsis),
              ],
              const SizedBox(height: 4),
              Row(children: [
                Text(formatCurrency(s.monto),
                  style: const TextStyle(fontWeight: FontWeight.bold,
                    color: AppColors.primaryBlue, fontSize: 13)),
                if (s.resta > 0) ...[
                  const SizedBox(width: 8),
                  Text("Resta: ${formatCurrency(s.resta)}",
                    style: const TextStyle(fontSize: 11, color: AppColors.statusRed)),
                ],
                if (s.pagado) ...[
                  const SizedBox(width: 8),
                  Container(
                    padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 1),
                    decoration: BoxDecoration(
                      color: AppColors.statusGreen.withValues(alpha: 0.15),
                      borderRadius: BorderRadius.circular(6)),
                    child: const Text("PAGADO",
                      style: TextStyle(fontSize: 9, fontWeight: FontWeight.bold,
                        color: AppColors.statusGreen)),
                  ),
                ],
                const Spacer(),
                Text(_formatoFecha(s.fecha),
                  style: const TextStyle(fontSize: 10, color: AppColors.textSecondary)),
              ]),
            ])),
          ]),
        ),
      ),
    );
  }

  String _formatoFecha(DateTime f) =>
    "${f.day.toString().padLeft(2,'0')}/${f.month.toString().padLeft(2,'0')}/${f.year}";

  // ── Navegar a vista de detalle ───────────────────────────
  Future<void> _abrirDetalle(ServicioTecnico s) async {
    await Navigator.push(context, MaterialPageRoute(
      builder: (_) => _DetalleServicioTecnico(servicio: s)));
    if (mounted) _cargar();
  }

  // ── Eliminar servicio ────────────────────────────────────
  Future<void> _eliminarServicio(ServicioTecnico s) async {
    final confirmar = await showDialog<bool>(
      context: context,
      builder: (ctx) => AlertDialog(
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(16)),
        title: const Row(children: [
          Icon(Icons.delete_outline, color: AppColors.statusRed),
          SizedBox(width: 8),
          Text("Eliminar Servicio"),
        ]),
        content: Text("¿Eliminar el servicio de '${s.nombreCliente}'? Esta acción no se puede deshacer."),
        actions: [
          TextButton(onPressed: () => Navigator.pop(ctx, false), child: const Text("Cancelar")),
          ElevatedButton.icon(
            style: ElevatedButton.styleFrom(backgroundColor: AppColors.statusRed),
            icon: const Icon(Icons.delete_forever_outlined, size: 16, color: Colors.white),
            label: const Text("Eliminar", style: TextStyle(color: Colors.white)),
            onPressed: () => Navigator.pop(ctx, true)),
        ],
      ),
    );
    if (confirmar != true || !mounted) return;
    try {
      if (s.id == null) throw Exception('Servicio sin ID. Recargue la pantalla.');
      await _Api.delete('servicios', s.id!.toString());
      setState(() => _servicios.removeWhere((x) => x.id == s.id));
      serviciosGlobal.removeWhere((x) => x.id == s.id);
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
        content: Text("Servicio eliminado correctamente."),
        backgroundColor: AppColors.statusGreen));
    } catch (e) {
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Text("Error al eliminar: $e"),
        backgroundColor: AppColors.statusRed));
    }
  }

  // ── Abrir formulario para crear nuevo servicio ───────────
  Future<void> _mostrarFormularioNuevo() async {
    await Navigator.push(context, MaterialPageRoute(
      builder: (_) => const _FormularioServicioTecnico()));
    if (mounted) _cargar();
  }
}

// ============================================================
//  FORMULARIO DE SERVICIO TÉCNICO  (crear / editar)
//  Replica la planilla física: datos del cliente, equipo,
//  checklist de componentes, observaciones y montos.
// ============================================================
class _FormularioServicioTecnico extends StatefulWidget {
  final ServicioTecnico? servicio;   // null = nuevo
  const _FormularioServicioTecnico({this.servicio});

  @override
  State<_FormularioServicioTecnico> createState() => _FormularioServicioTecnicoState();
}

class _FormularioServicioTecnicoState extends State<_FormularioServicioTecnico> {
  final _formKey = GlobalKey<FormState>();

  // Controladores
  late TextEditingController _montoCtrl, _abonoCtrl, _costoRepuestosCtrl;
  late TextEditingController _nombreCtrl, _telefonoCtrl, _rifCtrl;
  late TextEditingController _modeloCtrl, _marcaCtrl, _descripcionCtrl;
  late TextEditingController _imeiCtrl, _contrasenaCtrl;
  late TextEditingController _observacionCtrl, _tecnicoCtrl;
  late TextEditingController _horaRecibidoCtrl, _fechaEntregaCtrl;

  // Checklist — cada uno puede ser true/false/null (no revisado)
  bool? chip, memoria, bateria, tapa;
  bool? encendido, apagado, camara, corneta;
  bool? flash, flashConDefecto;
  bool? tactilPartido, auricular, microfono, contrasenaChk;
  bool? track, botonVolumen, teclado, botonEncendido, pantallaConDefecto;

  bool _pagado = false;
  String _estado = 'Recibido';
  late DateTime _fecha;
  bool _guardando = false;
  /// Fotos del equipo al recibirlo (base64). Vacío por defecto.
  List<String> _fotosRecepcion = [];

  final List<String> _estados = ['Recibido', 'En reparación', 'Listo', 'Entregado'];

  @override
  void initState() {
    super.initState();
    final s = widget.servicio;
    _fecha = s?.fecha ?? DateTime.now();

    // Helper local: formatea un monto para un TextField sin mostrar ".0"
    // innecesario (150.0 → "150", 150.5 → "150.5"). Si es 0 o null,
    // devuelve cadena vacía para que el hint del campo sea visible.
    String _numToField(double? v) {
      if (v == null || v == 0) return '';
      // Si es entero (ej: 150.0) → "150". Si no, como está (ej: 150.5 → "150.5").
      return v == v.roundToDouble() ? v.toInt().toString() : v.toString();
    }

    _montoCtrl         = TextEditingController(text: _numToField(s?.monto));
    _abonoCtrl         = TextEditingController(text: _numToField(s?.abono));
    _costoRepuestosCtrl = TextEditingController(text: _numToField(s?.costoRepuestos));
    _nombreCtrl        = TextEditingController(text: s?.nombreCliente ?? '');
    _telefonoCtrl      = TextEditingController(text: s?.telefono ?? '');
    _rifCtrl           = TextEditingController(text: s?.rifCi ?? '');
    _modeloCtrl        = TextEditingController(text: s?.modelo ?? '');
    _marcaCtrl         = TextEditingController(text: s?.marca ?? '');
    _descripcionCtrl   = TextEditingController(text: s?.descripcion ?? '');
    _imeiCtrl          = TextEditingController(text: s?.imei ?? '');
    _contrasenaCtrl    = TextEditingController(text: s?.contrasena ?? '');
    _observacionCtrl   = TextEditingController(text: s?.observacion ?? '');
    _tecnicoCtrl       = TextEditingController(text: s?.tecnico ?? (usuarioSesion?.nombre ?? ''));
    _horaRecibidoCtrl  = TextEditingController(text: s?.horaRecibido ?? _horaActual());
    _fechaEntregaCtrl  = TextEditingController(text: s?.fechaEntrega ?? '');

    chip                = s?.chip;
    memoria             = s?.memoria;
    bateria             = s?.bateria;
    tapa                = s?.tapa;
    encendido           = s?.encendido;
    apagado             = s?.apagado;
    camara              = s?.camara;
    corneta             = s?.corneta;
    flash               = s?.flash;
    flashConDefecto     = s?.flashConDefecto;
    tactilPartido       = s?.tactilPartido;
    auricular           = s?.auricular;
    microfono           = s?.microfono;
    contrasenaChk       = s?.contrasenaChk;
    track               = s?.track;
    botonVolumen        = s?.botonVolumen;
    teclado             = s?.teclado;
    botonEncendido      = s?.botonEncendido;
    pantallaConDefecto  = s?.pantallaConDefecto;
    _pagado             = s?.pagado ?? false;
    // Si el backend devuelve un estado desconocido (datos antiguos, case
    // distinto, etc.), el Dropdown explotaría porque `value` no estaría
    // en `items`. Caemos a 'Recibido' por defecto para evitarlo.
    final estadoCargado = s?.estado ?? 'Recibido';
    _estado = _estados.contains(estadoCargado) ? estadoCargado : 'Recibido';
    // Cargar fotos existentes (al editar) o lista vacía
    _fotosRecepcion = List<String>.from(s?.fotosRecepcion ?? const <String>[]);
  }

  @override
  void dispose() {
    _montoCtrl.dispose(); _abonoCtrl.dispose(); _costoRepuestosCtrl.dispose();
    _nombreCtrl.dispose(); _telefonoCtrl.dispose(); _rifCtrl.dispose();
    _modeloCtrl.dispose(); _marcaCtrl.dispose(); _descripcionCtrl.dispose();
    _imeiCtrl.dispose(); _contrasenaCtrl.dispose();
    _observacionCtrl.dispose(); _tecnicoCtrl.dispose();
    _horaRecibidoCtrl.dispose(); _fechaEntregaCtrl.dispose();
    super.dispose();
  }

  String _horaActual() {
    final n = DateTime.now();
    return "${n.hour.toString().padLeft(2,'0')}:${n.minute.toString().padLeft(2,'0')}";
  }

  @override
  Widget build(BuildContext context) {
    final esEdicion = widget.servicio != null;
    return Scaffold(
      appBar: AppBar(
        title: Text(esEdicion ? "Editar Servicio Técnico" : "Nuevo Servicio Técnico"),
      ),
      body: Form(
        key: _formKey,
        child: ListView(
          padding: const EdgeInsets.all(16),
          children: [
            // ── SECCIÓN 1: MONTOS ──────────────────────────
            _seccion("Montos", Icons.attach_money),
            Row(children: [
              Expanded(child: TextFormField(
                controller: _montoCtrl,
                keyboardType: const TextInputType.numberWithOptions(decimal: true),
                decoration: const InputDecoration(
                  labelText: "Monto Total *",
                  prefixIcon: Icon(Icons.monetization_on_outlined)),
                validator: (v) {
                  final d = double.tryParse(v?.trim() ?? '');
                  if (d == null || d <= 0) return "Monto inválido";
                  return null;
                },
                onChanged: (_) => setState(() {}),
              )),
              const SizedBox(width: 10),
              Expanded(child: TextFormField(
                controller: _abonoCtrl,
                keyboardType: const TextInputType.numberWithOptions(decimal: true),
                decoration: const InputDecoration(
                  labelText: "Abono",
                  prefixIcon: Icon(Icons.payments_outlined)),
                onChanged: (_) => setState(() {}),
              )),
            ]),
            const SizedBox(height: 10),
            // ── Costo de repuestos (lo que GASTÓ el negocio) ──
            TextFormField(
              controller: _costoRepuestosCtrl,
              keyboardType: const TextInputType.numberWithOptions(decimal: true),
              decoration: const InputDecoration(
                labelText: "Costo de repuestos / insumos",
                helperText: "Lo que se gastó en reparar el equipo (para calcular ganancia)",
                prefixIcon: Icon(Icons.build_outlined),
              ),
              onChanged: (_) => setState(() {}),
            ),
            const SizedBox(height: 10),
            // Mostrar "Resta" + "Ganancia" calculadas en vivo
            Builder(builder: (_) {
              final monto = double.tryParse(_montoCtrl.text) ?? 0;
              final abono = double.tryParse(_abonoCtrl.text) ?? 0;
              final costo = double.tryParse(_costoRepuestosCtrl.text) ?? 0;
              final resta = (monto - abono).clamp(0, double.infinity);
              final ganancia = monto - costo;
              final margen = monto > 0 ? (ganancia / monto * 100) : 0;
              return Container(
                padding: const EdgeInsets.all(12),
                decoration: BoxDecoration(
                  color: AppColors.brandBlue.withValues(alpha: 0.06),
                  borderRadius: BorderRadius.circular(10),
                  border: Border.all(
                    color: AppColors.brandBlue.withValues(alpha: 0.15),
                  ),
                ),
                child: Column(children: [
                  Row(children: [
                    const Icon(Icons.account_balance_wallet_outlined,
                      size: 18, color: AppColors.brandBlue),
                    const SizedBox(width: 8),
                    const Text("Resta por cobrar:",
                      style: TextStyle(color: AppColors.textSecondary)),
                    const Spacer(),
                    Text(formatCurrency(resta.toDouble()),
                      style: const TextStyle(
                        fontWeight: FontWeight.w700,
                        color: AppColors.brandBlue,
                      )),
                  ]),
                  const SizedBox(height: 6),
                  const Divider(height: 8),
                  const SizedBox(height: 6),
                  Row(children: [
                    Icon(Icons.trending_up,
                      size: 18,
                      color: ganancia >= 0
                          ? AppColors.statusGreen
                          : AppColors.statusRed),
                    const SizedBox(width: 8),
                    const Text("Ganancia estimada:",
                      style: TextStyle(color: AppColors.textSecondary)),
                    const Spacer(),
                    Text(
                      "${formatCurrency(ganancia)}  (${margen.toStringAsFixed(1)}%)",
                      style: TextStyle(
                        fontWeight: FontWeight.w800,
                        color: ganancia >= 0
                            ? AppColors.statusGreen
                            : AppColors.statusRed,
                      ),
                    ),
                  ]),
                ]),
              );
            }),
            const SizedBox(height: 10),
            SwitchListTile(
              value: _pagado,
              onChanged: (v) => setState(() => _pagado = v),
              title: const Text("¿Está pagado completamente?"),
              activeColor: AppColors.statusGreen,
              contentPadding: EdgeInsets.zero,
            ),
            const SizedBox(height: 20),

            // ── SECCIÓN 2: CLIENTE ─────────────────────────
            _seccion("Datos del cliente", Icons.person_outline),
            TextFormField(
              controller: _nombreCtrl,
              textCapitalization: TextCapitalization.words,
              decoration: const InputDecoration(
                labelText: "Nombre y apellido *",
                prefixIcon: Icon(Icons.badge_outlined)),
              validator: (v) => (v?.trim().isEmpty ?? true) ? "Requerido" : null,
            ),
            const SizedBox(height: 10),
            Row(children: [
              Expanded(child: TextFormField(
                controller: _telefonoCtrl,
                keyboardType: TextInputType.phone,
                decoration: const InputDecoration(
                  labelText: "Teléfono",
                  prefixIcon: Icon(Icons.phone_outlined)),
              )),
              const SizedBox(width: 10),
              Expanded(child: TextFormField(
                controller: _rifCtrl,
                decoration: const InputDecoration(
                  labelText: "RIF / C.I.",
                  prefixIcon: Icon(Icons.credit_card)),
              )),
            ]),
            const SizedBox(height: 20),

            // ── SECCIÓN 3: FECHAS ──────────────────────────
            _seccion("Fechas y horas", Icons.calendar_today_outlined),
            Row(children: [
              Expanded(child: TextFormField(
                controller: _horaRecibidoCtrl,
                decoration: const InputDecoration(
                  labelText: "Hora recibido",
                  hintText: "Ej: 14:30",
                  prefixIcon: Icon(Icons.access_time)),
              )),
              const SizedBox(width: 10),
              Expanded(child: TextFormField(
                controller: _fechaEntregaCtrl,
                decoration: const InputDecoration(
                  labelText: "Fecha de entrega",
                  hintText: "Ej: 20/04/2026",
                  prefixIcon: Icon(Icons.event_outlined)),
                readOnly: true,
                onTap: () async {
                  final f = await showDatePicker(
                    context: context,
                    initialDate: DateTime.now().add(const Duration(days: 2)),
                    firstDate: DateTime.now(),
                    lastDate: DateTime.now().add(const Duration(days: 365)));
                  if (f != null) {
                    _fechaEntregaCtrl.text =
                      "${f.day.toString().padLeft(2,'0')}/${f.month.toString().padLeft(2,'0')}/${f.year}";
                  }
                },
              )),
            ]),
            const SizedBox(height: 20),

            // ── SECCIÓN 4: EQUIPO ──────────────────────────
            _seccion("Datos del equipo", Icons.phone_android_outlined),
            Row(children: [
              Expanded(child: TextFormField(
                controller: _marcaCtrl,
                textCapitalization: TextCapitalization.words,
                decoration: const InputDecoration(
                  labelText: "Marca",
                  prefixIcon: Icon(Icons.business_outlined)),
              )),
              const SizedBox(width: 10),
              Expanded(child: TextFormField(
                controller: _modeloCtrl,
                decoration: const InputDecoration(
                  labelText: "Modelo",
                  prefixIcon: Icon(Icons.phonelink_outlined)),
              )),
            ]),
            const SizedBox(height: 10),
            TextFormField(
              controller: _descripcionCtrl,
              maxLines: 2,
              textCapitalization: TextCapitalization.sentences,
              decoration: const InputDecoration(
                labelText: "Descripción del problema",
                prefixIcon: Icon(Icons.description_outlined),
                hintText: "Ej: Se moja, pantalla rota, no enciende..."),
            ),
            const SizedBox(height: 10),

            // ── Fotos de recepción ───────────────────────────────
            // Permite tomar varias fotos del equipo al recibirlo
            // (cámara o galería). Cada foto se guarda como base64
            // dentro del bloque META del servicio.
            _seccionFotosRecepcion(),
            const SizedBox(height: 10),
            Row(children: [
              Expanded(child: TextFormField(
                controller: _imeiCtrl,
                keyboardType: TextInputType.number,
                decoration: InputDecoration(
                  labelText: "IMEI",
                  prefixIcon: const Icon(Icons.pin_outlined),
                  // Botón de scanner integrado al campo IMEI: abre cámara
                  // y, al detectar el código de barras, lo escribe aquí.
                  suffixIcon: IconButton(
                    icon: const Icon(Icons.qr_code_scanner,
                        color: AppColors.primaryBlue),
                    tooltip: "Escanear IMEI",
                    onPressed: () => Navigator.push(context,
                      MaterialPageRoute(builder: (_) => ScannerPage(
                        onDetect: (c) => setState(() => _imeiCtrl.text = c)))),
                  ),
                ),
              )),
              const SizedBox(width: 10),
              Expanded(child: TextFormField(
                controller: _contrasenaCtrl,
                decoration: const InputDecoration(
                  labelText: "Contraseña / Patrón",
                  prefixIcon: Icon(Icons.lock_outline)),
              )),
            ]),
            const SizedBox(height: 24),

            // ── SECCIÓN 5: CHECKLIST ───────────────────────
            _seccion("Checklist del equipo", Icons.checklist_outlined),
            const Text(
              "Marque según el estado en que se recibe cada componente:",
              style: TextStyle(fontSize: 12, color: AppColors.textSecondary),
            ),
            const SizedBox(height: 10),
            // Grid en dos columnas igual que la planilla
            Row(children: [
              Expanded(child: Column(children: [
                _triCheck("Chip",                 chip,               (v) => setState(() => chip = v)),
                _triCheck("Memoria",              memoria,            (v) => setState(() => memoria = v)),
                _triCheck("Batería",              bateria,            (v) => setState(() => bateria = v)),
                _triCheck("Tapa",                 tapa,               (v) => setState(() => tapa = v)),
                _triCheck("Encendido",            encendido,          (v) => setState(() => encendido = v)),
                _triCheck("Apagado",              apagado,            (v) => setState(() => apagado = v)),
                _triCheck("Cámara",               camara,             (v) => setState(() => camara = v)),
                _triCheck("Corneta",              corneta,            (v) => setState(() => corneta = v)),
                _triCheck("Flash",                flash,              (v) => setState(() => flash = v)),
                _triCheck("Flash con defecto",    flashConDefecto,    (v) => setState(() => flashConDefecto = v)),
              ])),
              const SizedBox(width: 8),
              Expanded(child: Column(children: [
                _triCheck("Táctil partido",       tactilPartido,      (v) => setState(() => tactilPartido = v)),
                _triCheck("Auricular",            auricular,          (v) => setState(() => auricular = v)),
                _triCheck("Micrófono",            microfono,          (v) => setState(() => microfono = v)),
                _triCheck("Contraseña",           contrasenaChk,      (v) => setState(() => contrasenaChk = v)),
                _triCheck("Track",                track,              (v) => setState(() => track = v)),
                _triCheck("Botón de volumen",     botonVolumen,       (v) => setState(() => botonVolumen = v)),
                _triCheck("Teclado",              teclado,            (v) => setState(() => teclado = v)),
                _triCheck("Botón de encendido",   botonEncendido,     (v) => setState(() => botonEncendido = v)),
                _triCheck("Pantalla con defecto", pantallaConDefecto, (v) => setState(() => pantallaConDefecto = v)),
              ])),
            ]),
            const SizedBox(height: 20),

            // ── SECCIÓN 6: OBSERVACIONES + ESTADO ──────────
            _seccion("Observaciones y estado", Icons.notes_outlined),
            TextFormField(
              controller: _observacionCtrl,
              maxLines: 2,
              textCapitalization: TextCapitalization.sentences,
              decoration: const InputDecoration(
                labelText: "Observación",
                prefixIcon: Icon(Icons.comment_outlined)),
            ),
            const SizedBox(height: 10),
            TextFormField(
              controller: _tecnicoCtrl,
              textCapitalization: TextCapitalization.words,
              decoration: const InputDecoration(
                labelText: "Técnico a cargo",
                prefixIcon: Icon(Icons.engineering_outlined)),
            ),
            const SizedBox(height: 10),
            DropdownButtonFormField<String>(
              value: _estado,
              decoration: const InputDecoration(
                labelText: "Estado del servicio",
                prefixIcon: Icon(Icons.flag_outlined)),
              items: _estados.map((e) =>
                DropdownMenuItem(value: e, child: Text(e))).toList(),
              onChanged: (v) => setState(() => _estado = v!),
            ),
            const SizedBox(height: 30),

            // ── BOTÓN GUARDAR ──────────────────────────────
            SizedBox(
              width: double.infinity,
              child: ElevatedButton.icon(
                style: ElevatedButton.styleFrom(
                  backgroundColor: AppColors.royalBlue,
                  padding: const EdgeInsets.all(15)),
                icon: _guardando
                  ? const SizedBox(width: 20, height: 20,
                      child: CircularProgressIndicator(
                        color: Colors.white, strokeWidth: 2))
                  : const Icon(Icons.save_outlined, color: Colors.white),
                label: Text(_guardando
                  ? "Guardando..."
                  : (esEdicion ? "ACTUALIZAR SERVICIO" : "GUARDAR SERVICIO"),
                  style: const TextStyle(color: Colors.white, fontSize: 15)),
                onPressed: _guardando ? null : _guardar,
              ),
            ),
            const SizedBox(height: 20),
          ],
        ),
      ),
    );
  }

  // ── Encabezado de sección ──
  Widget _seccion(String titulo, IconData icono) => Padding(
    padding: const EdgeInsets.only(bottom: 10, top: 4),
    child: Row(children: [
      Icon(icono, color: AppColors.royalBlue, size: 20),
      const SizedBox(width: 8),
      Text(titulo, style: const TextStyle(
        fontSize: 15, fontWeight: FontWeight.bold, color: AppColors.royalBlue)),
      const SizedBox(width: 8),
      const Expanded(child: Divider(color: AppColors.cardBorder)),
    ]),
  );

  // ── Tri-state checkbox: null (gris) / SI (verde) / NO (rojo) ──
  Widget _triCheck(String label, bool? value, Function(bool?) onChange) {
    // Texto que se muestra: "—" / "SI" / "NO"
    String txt;
    Color color;
    if (value == null) { txt = "—"; color = Colors.grey; }
    else if (value)    { txt = "SI"; color = AppColors.statusGreen; }
    else               { txt = "NO"; color = AppColors.statusRed; }

    return InkWell(
      onTap: () {
        // Ciclo: null → true → false → null
        if (value == null) onChange(true);
        else if (value)    onChange(false);
        else               onChange(null);
      },
      borderRadius: BorderRadius.circular(8),
      child: Padding(
        padding: const EdgeInsets.symmetric(vertical: 4, horizontal: 6),
        child: Row(children: [
          Expanded(child: Text(label, style: const TextStyle(fontSize: 12))),
          Container(
            width: 38,
            padding: const EdgeInsets.symmetric(vertical: 3),
            decoration: BoxDecoration(
              color: color.withValues(alpha: 0.15),
              borderRadius: BorderRadius.circular(6),
              border: Border.all(color: color.withValues(alpha: 0.5), width: 1),
            ),
            child: Text(txt,
              textAlign: TextAlign.center,
              style: TextStyle(fontSize: 11, fontWeight: FontWeight.bold, color: color)),
          ),
        ]),
      ),
    );
  }

  /// Widget reutilizable que muestra las fotos de recepción y permite
  /// agregar nuevas (cámara o galería). Las fotos se almacenan en
  /// memoria como base64; al guardar el servicio se persisten dentro
  /// del bloque META de la descripción.
  Widget _seccionFotosRecepcion() {
    return Container(
      padding: const EdgeInsets.all(12),
      decoration: BoxDecoration(
        color: AppColors.surfaceTintBlue,
        borderRadius: BorderRadius.circular(10),
        border: Border.all(
            color: AppColors.brandBlue.withValues(alpha: 0.15)),
      ),
      child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
        Row(children: [
          const Icon(Icons.photo_library_outlined,
              color: AppColors.brandBlue, size: 20),
          const SizedBox(width: 8),
          const Expanded(child: Text(
              "Fotos de recepción del equipo",
              style: TextStyle(
                  fontWeight: FontWeight.w700, fontSize: 13.5))),
          Text("${_fotosRecepcion.length}",
              style: const TextStyle(
                  color: AppColors.brandBlue,
                  fontWeight: FontWeight.w800)),
        ]),
        const SizedBox(height: 4),
        const Text(
            "Toma fotos para dejar constancia del estado en que se "
            "recibe el equipo (rayones, manchas, piezas faltantes, etc.).",
            style: TextStyle(fontSize: 11,
                color: AppColors.textSecondary)),
        const SizedBox(height: 10),
        // ── Grid de previews ─────────────────────────────────
        if (_fotosRecepcion.isNotEmpty)
          SizedBox(
            height: 90,
            child: ListView.separated(
              scrollDirection: Axis.horizontal,
              itemCount: _fotosRecepcion.length,
              separatorBuilder: (_,__) => const SizedBox(width: 8),
              itemBuilder: (_, i) => _previewFoto(i),
            ),
          ),
        if (_fotosRecepcion.isNotEmpty) const SizedBox(height: 10),
        // ── Botones para agregar ─────────────────────────────
        Row(children: [
          Expanded(child: OutlinedButton.icon(
            icon: const Icon(Icons.camera_alt, size: 18),
            label: const Text("Tomar foto"),
            onPressed: () => _tomarFoto(desdeCamara: true),
          )),
          const SizedBox(width: 8),
          Expanded(child: OutlinedButton.icon(
            icon: const Icon(Icons.photo_library, size: 18),
            label: const Text("Desde galería"),
            onPressed: () => _tomarFoto(desdeCamara: false),
          )),
        ]),
      ]),
    );
  }

  /// Preview de una foto + botón para eliminarla.
  Widget _previewFoto(int idx) {
    final dataB64 = _fotosRecepcion[idx];
    Uint8List? bytes;
    try {
      // Soporta tanto "data:image/...;base64,XXX" como "XXX" plano.
      final cleanB64 = dataB64.contains(',')
          ? dataB64.split(',').last
          : dataB64;
      bytes = base64Decode(cleanB64);
    } catch (_) {
      bytes = null;
    }
    return Stack(children: [
      Container(
        width: 90, height: 90,
        decoration: BoxDecoration(
          borderRadius: BorderRadius.circular(8),
          border: Border.all(color: Colors.grey.shade300),
          color: Colors.white,
        ),
        clipBehavior: Clip.antiAlias,
        child: bytes != null
            ? Image.memory(bytes, fit: BoxFit.cover)
            : const Center(child: Icon(Icons.broken_image)),
      ),
      Positioned(
        top: 2, right: 2,
        child: GestureDetector(
          onTap: () => setState(() => _fotosRecepcion.removeAt(idx)),
          child: Container(
            decoration: const BoxDecoration(
              color: Colors.black54, shape: BoxShape.circle),
            padding: const EdgeInsets.all(2),
            child: const Icon(Icons.close,
                color: Colors.white, size: 16),
          ),
        ),
      ),
    ]);
  }

  /// Toma una foto con la cámara o la elige de la galería. La
  /// convierte a base64 y la agrega a la lista.
  Future<void> _tomarFoto({required bool desdeCamara}) async {
    try {
      final picker = ImagePicker();
      final xfile = await picker.pickImage(
        source: desdeCamara ? ImageSource.camera : ImageSource.gallery,
        // Calidad agresiva para mantener el payload pequeño. Una foto
        // de evidencia no necesita alta resolución; lo importante es
        // que se pueda identificar el estado del equipo. Con estos
        // valores cada foto pesa ~30-80 KB en base64.
        imageQuality: 50,
        maxWidth: 900,
      );
      if (xfile == null) return;
      final bytes = await xfile.readAsBytes();
      final b64 = base64Encode(bytes);
      setState(() => _fotosRecepcion.add(b64));
    } catch (e) {
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(SnackBar(
          content: Text("No se pudo capturar la foto: $e"),
          backgroundColor: AppColors.statusRed));
    }
  }

  // ── Guardar en la API ──
  Future<void> _guardar() async {
    if (!_formKey.currentState!.validate()) return;

    // Validaciones adicionales que el validador del campo no cubre
    final monto = double.tryParse(_montoCtrl.text.trim()) ?? 0;
    final abono = double.tryParse(_abonoCtrl.text.trim()) ?? 0;

    if (abono < 0) {
      ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
        content: Text("El abono no puede ser negativo"),
        backgroundColor: AppColors.statusOrange));
      return;
    }
    if (abono > monto) {
      ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
        content: Text("El abono no puede ser mayor al monto total"),
        backgroundColor: AppColors.statusOrange));
      return;
    }

    // Si el usuario marcó "Pagado completamente", aseguramos coherencia:
    // abono = monto. Si no lo marcó pero el abono ya cubre el monto,
    // marcamos automáticamente como pagado.
    bool pagado = _pagado;
    double abonoFinal = abono;
    if (pagado) {
      abonoFinal = monto;
    } else if (monto > 0 && abono >= monto) {
      pagado = true;
      abonoFinal = monto;
    }

    // Técnico: si queda vacío, usar el nombre del usuario de sesión
    String tecnico = _tecnicoCtrl.text.trim();
    if (tecnico.isEmpty) {
      tecnico = (usuarioSesion?.nombre ?? '').trim();
    }

    setState(() => _guardando = true);

    try {
      final costoRepuestos = double.tryParse(_costoRepuestosCtrl.text.trim()) ?? 0;
      final servicio = ServicioTecnico(
        id: widget.servicio?.id,
        monto: monto,
        abono: abonoFinal,
        costoRepuestos: costoRepuestos,
        pagado: pagado,
        fecha: _fecha,
        horaRecibido: _horaRecibidoCtrl.text.trim(),
        fechaEntrega: _fechaEntregaCtrl.text.trim(),
        nombreCliente: _nombreCtrl.text.trim(),
        telefono: _telefonoCtrl.text.trim(),
        rifCi: _rifCtrl.text.trim(),
        modelo: _modeloCtrl.text.trim(),
        marca: _marcaCtrl.text.trim(),
        descripcion: _descripcionCtrl.text.trim(),
        imei: _imeiCtrl.text.trim(),
        contrasena: _contrasenaCtrl.text.trim(),
        chip: chip, memoria: memoria, bateria: bateria, tapa: tapa,
        encendido: encendido, apagado: apagado, camara: camara, corneta: corneta,
        flash: flash, flashConDefecto: flashConDefecto,
        tactilPartido: tactilPartido, auricular: auricular, microfono: microfono,
        contrasenaChk: contrasenaChk,
        track: track, botonVolumen: botonVolumen, teclado: teclado,
        botonEncendido: botonEncendido, pantallaConDefecto: pantallaConDefecto,
        observacion: _observacionCtrl.text.trim(),
        tecnico: tecnico,
        estado: _estado,
        fotosRecepcion: _fotosRecepcion,
      );

      if (widget.servicio != null && widget.servicio!.id != null) {
        // ── Edición: PUT al backend ───────────────────────
        final payload = servicio.toMap();
        final descLen = (payload['descripcion'] as String? ?? '').length;
        debugPrint(
          '[ServicioTecnico] PUT #${widget.servicio!.id} → '
          'fotos=${servicio.fotosRecepcion.length}, '
          'descripcion_bytes=$descLen');
        final resp = await _Api.put('servicios', widget.servicio!.id!.toString(), payload);
        debugPrint('[ServicioTecnico] PUT respuesta: $resp');
        // Mantener el id local que ya teníamos
        servicio.id = widget.servicio!.id;
      } else {
        // ── Creación: POST y LEER el id devuelto ─────────
        // BUG anterior: el id devuelto por el backend se descartaba.
        // Eso provocaba que, tras crear un servicio, si el usuario
        // volvía a pulsar "Guardar" se creara un duplicado, o que el
        // servicio recién creado quedara sin id en la lista local.
        final payload = servicio.toMap();
        // Log de DIAGNÓSTICO: no imprimimos el JSON completo porque
        // con fotos base64 puede pesar cientos de KB y el log de
        // Android lo trunca. En su lugar mostramos un resumen útil
        // para detectar si las fotos van o no van en el payload.
        final descLen = (payload['descripcion'] as String? ?? '').length;
        debugPrint(
          '[ServicioTecnico] POST → '
          'fotos=${servicio.fotosRecepcion.length}, '
          'descripcion_bytes=$descLen, '
          'cliente="${servicio.nombreCliente}"');
        final data = await _Api.post('servicios', payload);
        debugPrint('[ServicioTecnico] POST respuesta: $data');
        if (data is Map) {
          servicio.id = data['id'] is int
              ? data['id']
              : int.tryParse(data['id']?.toString() ?? '');
        }
      }

      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
        content: Text("✅ Servicio guardado correctamente"),
        backgroundColor: AppColors.statusGreen));
      // Devolvemos el servicio guardado a quien abrió el formulario, por
      // si quiere actualizar su vista sin recargar toda la lista.
      Navigator.pop(context, servicio);
    } catch (e) {
      if (!mounted) return;
      setState(() => _guardando = false);
      ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Text("Error al guardar: $e"),
        backgroundColor: AppColors.statusRed));
    }
  }
}

// ============================================================
//  DETALLE DE SERVICIO TÉCNICO  (vista + imprimir + editar)
// ============================================================
class _DetalleServicioTecnico extends StatefulWidget {
  final ServicioTecnico servicio;
  const _DetalleServicioTecnico({required this.servicio});

  @override
  State<_DetalleServicioTecnico> createState() => _DetalleServicioTecnicoState();
}

class _DetalleServicioTecnicoState extends State<_DetalleServicioTecnico> {
  late ServicioTecnico s;
  bool _refrescando = false;

  @override
  void initState() {
    super.initState();
    s = widget.servicio;
    // Si el servicio tiene id (ya está guardado), lo refrescamos
    // desde el backend para que se vea la versión real persistida
    // — útil después de guardar para confirmar que las fotos y
    // el resto de metadata realmente quedaron en MySQL.
    if (s.id != null) {
      _refrescarDesdeBackend();
    }
  }

  Future<void> _refrescarDesdeBackend() async {
    if (s.id == null) return;
    setState(() => _refrescando = true);
    try {
      // Traemos la lista de servicios y buscamos el de este id.
      // (No hay endpoint GET por id en el sistema actual, así que
      // usamos el listado.)
      final raw = await _Api.get('servicios');
      final lista = (raw as List?) ?? [];
      final m = lista.cast<Map<String, dynamic>>().firstWhere(
          (e) => (e['id']?.toString() ?? '') == s.id.toString(),
          orElse: () => <String, dynamic>{});
      if (m.isNotEmpty) {
        final fresco = ServicioTecnico.fromMap(m);
        if (mounted) setState(() => s = fresco);
        debugPrint('[DetalleServicio] refrescado: '
            'fotos=${s.fotosRecepcion.length}');
      }
    } catch (e) {
      debugPrint('[DetalleServicio] error al refrescar: $e');
    } finally {
      if (mounted) setState(() => _refrescando = false);
    }
  }

