          fontWeight: FontWeight.bold)),
      ]),
    ));
  }

  /// Grid de fotos de recepción. Cada foto es un thumbnail que al
  /// tocarse abre un viewer a pantalla completa con zoom y deslizar
  /// entre fotos. Las fotos se decodifican desde base64.
  Widget _galeriaFotosRecepcion() {
    return Card(
      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(12)),
      elevation: 1,
      child: Padding(
        padding: const EdgeInsets.all(12),
        child: GridView.builder(
          shrinkWrap: true,
          physics: const NeverScrollableScrollPhysics(),
          itemCount: s.fotosRecepcion.length,
          gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(
            crossAxisCount: 3,
            crossAxisSpacing: 8,
            mainAxisSpacing: 8,
            childAspectRatio: 1.0,
          ),
          itemBuilder: (_, i) => _miniaturaFoto(i),
        ),
      ),
    );
  }

  /// Miniatura cuadrada que abre el viewer al pulsarla.
  Widget _miniaturaFoto(int idx) {
    final dataB64 = s.fotosRecepcion[idx];
    Uint8List? bytes;
    try {
      final clean = dataB64.contains(',')
          ? dataB64.split(',').last : dataB64;
      bytes = base64Decode(clean);
    } catch (_) {
      bytes = null;
    }
    return GestureDetector(
      onTap: bytes == null ? null : () => _abrirViewerFotos(idx),
      child: Container(
        decoration: BoxDecoration(
          borderRadius: BorderRadius.circular(8),
          border: Border.all(color: Colors.grey.shade300),
          color: Colors.grey.shade100,
        ),
        clipBehavior: Clip.antiAlias,
        child: bytes != null
            ? Stack(fit: StackFit.expand, children: [
                Image.memory(bytes, fit: BoxFit.cover),
                // Ícono indicando que se puede ampliar
                const Positioned(
                  bottom: 4, right: 4,
                  child: Icon(Icons.zoom_in,
                      color: Colors.white, size: 18,
                      shadows: [Shadow(blurRadius: 4,
                          color: Colors.black54)]),
                ),
              ])
            : const Center(
                child: Icon(Icons.broken_image,
                    color: Colors.grey)),
      ),
    );
  }

