  Widget _filaInfo(String label, String valor) => Padding(
    padding: const EdgeInsets.symmetric(vertical: 4),
    child: Row(crossAxisAlignment: CrossAxisAlignment.start, children: [
      SizedBox(width: 110, child: Text("$label:",
        style: const TextStyle(color: AppColors.textSecondary, fontSize: 12))),
      Expanded(child: Text(valor.isEmpty ? '—' : valor,
        style: const TextStyle(fontSize: 13, fontWeight: FontWeight.w500))),
    ]),
  );

  Widget _chkRow(String label, bool? value) {
    String txt; Color color;
    if (value == null) { txt = "—"; color = Colors.grey; }
    else if (value)    { txt = "SI"; color = AppColors.statusGreen; }
    else               { txt = "NO"; color = AppColors.statusRed; }
    return Padding(
      padding: const EdgeInsets.symmetric(vertical: 3),
      child: Row(children: [
        Expanded(child: Text(label, style: const TextStyle(fontSize: 11))),
        Container(
          width: 30, padding: const EdgeInsets.symmetric(vertical: 2),
          decoration: BoxDecoration(
            color: color.withValues(alpha: 0.15),
            borderRadius: BorderRadius.circular(4),
            border: Border.all(color: color.withValues(alpha: 0.5), width: 0.8)),
          child: Text(txt, textAlign: TextAlign.center,
            style: TextStyle(fontSize: 9, fontWeight: FontWeight.bold, color: color)),
        ),
      ]),
    );
  }

  // ── Acciones ─────────────────────────────────────────────
  Future<void> _editar() async {
    await Navigator.push(context, MaterialPageRoute(
      builder: (_) => _FormularioServicioTecnico(servicio: s)));
    if (!mounted) return;
    // Al volver, recargar el servicio para mostrar cambios
    if (s.id != null) {
      try {
        final raw = await _Api.get('servicios', {'id': s.id!.toString()});
        if (!mounted) return;
        if (raw != null) {
          final actualizado = ServicioTecnico.fromMap(raw is List ? raw.first : raw);
          setState(() => s = actualizado);
        }
      } catch (_) {
        // si falla, cerrar para volver a la lista
        if (mounted) Navigator.pop(context);
      }
    } else {
      if (mounted) Navigator.pop(context);
    }
  }

  Future<void> _eliminar() async {
    final confirmar = await showDialog<bool>(
      context: context,
      builder: (ctx) => AlertDialog(
        title: const Text("¿Eliminar servicio?"),
        content: const Text("Esta acción no se puede deshacer."),
        actions: [
          TextButton(onPressed: () => Navigator.pop(ctx, false),
            child: const Text("Cancelar")),
          ElevatedButton(
            style: ElevatedButton.styleFrom(backgroundColor: AppColors.statusRed),
            onPressed: () => Navigator.pop(ctx, true),
            child: const Text("Eliminar", style: TextStyle(color: Colors.white))),
        ],
      ),
    );
    if (confirmar != true || !mounted) return;
    try {
      if (s.id != null) {
        await _Api.delete('servicios', s.id!.toString());
      }
      if (!mounted) return;
      Navigator.pop(context);
      ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
        content: Text("Servicio eliminado."),
        backgroundColor: AppColors.statusGreen));
    } catch (e) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Text("Error: $e"), backgroundColor: AppColors.statusRed));
    }
  }

  // ── Generar y mostrar PDF para imprimir ──────────────────
  Future<void> _imprimir() async {
    // Preguntar formato al usuario (o usar el preferido si ya lo eligió)
    final formato = await ImpresionHelper.obtenerFormato(context);
    if (formato == null) return;
    final esTermica = ImpresionHelper.esTermica(formato);
    final escala = ImpresionHelper.escalaFuente(formato);
    double fs(double base) => base * escala;

    try {
      final pdf = pw.Document();

      // Encabezado de la sede (si hay configurado)
      String nombreSede = ConfigSistema.tiendas.isNotEmpty
          ? ConfigSistema.tiendas.first
          : ConfigSistema.nombreEmpresa;
      final enc = ConfigSistema.encabezadoDe(nombreSede);

      // Helper para renderizar una casilla SI/NO (tamaño adaptativo)
      pw.Widget _chkPdf(String label, bool? v) {
        final txt = v == null ? '—' : (v ? 'SI' : 'NO');
        return pw.Padding(
          padding: const pw.EdgeInsets.symmetric(vertical: 1.5),
          child: pw.Row(children: [
            pw.Expanded(child: pw.Text(label, style: pw.TextStyle(fontSize: fs(9)))),
            pw.Container(
              width: esTermica ? 22 : 26,
              padding: const pw.EdgeInsets.symmetric(vertical: 1),
              decoration: pw.BoxDecoration(
                border: pw.Border.all(width: 0.5),
                borderRadius: pw.BorderRadius.circular(2)),
              child: pw.Text(txt, textAlign: pw.TextAlign.center,
                style: pw.TextStyle(fontSize: fs(8), fontWeight: pw.FontWeight.bold)),
            ),
          ]),
        );
      }

      pw.Widget _celda(String label, String val) => pw.Padding(
        padding: const pw.EdgeInsets.symmetric(vertical: 2),
        child: pw.RichText(
          text: pw.TextSpan(children: [
            pw.TextSpan(text: "$label: ",
              style: pw.TextStyle(
                fontSize: fs(10),
                color: PdfColors.black,
                fontWeight: pw.FontWeight.normal)),
            pw.TextSpan(text: val.isEmpty ? '—' : val,
              style: pw.TextStyle(
                fontSize: fs(10),
                fontWeight: pw.FontWeight.bold,
                color: PdfColors.black)),
          ]),
        ),
      );

      // ═══════════════════════════════════════════════════════════
      //  LAYOUT TÉRMICO (80mm / 58mm) — elegante y compacto
      // ═══════════════════════════════════════════════════════════
      if (esTermica) {
        // Helpers locales para este layout.
        // Header de sección: fondo NEGRO + texto BLANCO, igual que el
        // ticket de factura. El gris claro anterior (grey200) se perdía
        // totalmente en papel térmico (bajo contraste).
        pw.Widget secHdr(String t) => pw.Container(
          width: double.infinity,
          padding: const pw.EdgeInsets.symmetric(vertical: 3, horizontal: 5),
          margin: const pw.EdgeInsets.only(bottom: 3, top: 2),
          decoration: const pw.BoxDecoration(
            color: PdfColors.black,
            borderRadius: pw.BorderRadius.all(pw.Radius.circular(2))),
          child: pw.Text(t,
            style: pw.TextStyle(
              fontSize: fs(8.5),
              fontWeight: pw.FontWeight.bold,
              color: PdfColors.white,
              letterSpacing: 0.8)));

        pw.Widget sep() => pw.Container(
          height: 0.4, color: PdfColors.black,
          margin: const pw.EdgeInsets.symmetric(vertical: 3));
        pw.Widget sepG() => pw.Container(
          height: 0.8, color: PdfColors.black,
          margin: const pw.EdgeInsets.symmetric(vertical: 3));

        pdf.addPage(pw.MultiPage(
          pageFormat: ImpresionHelper.formatoPdf(formato),
          margin: const pw.EdgeInsets.all(4),
          build: (_) => [
            // ═══════════════════════════════════════════════════
            //  ENCABEZADO — badge destacado
            // ═══════════════════════════════════════════════════
            pw.Container(
              width: double.infinity,
              padding: const pw.EdgeInsets.symmetric(vertical: 5, horizontal: 6),
              decoration: const pw.BoxDecoration(
                color: PdfColors.black,
                borderRadius: pw.BorderRadius.all(pw.Radius.circular(2))),
              child: pw.Center(child: pw.Text('SERVICIO TÉCNICO',
                style: pw.TextStyle(
                  fontSize: fs(12),
                  fontWeight: pw.FontWeight.bold,
                  color: PdfColors.white,
                  letterSpacing: 1.2))),
            ),
            pw.SizedBox(height: 5),

            // Datos de empresa (sin tienda específica).
            // Solo imprime si hay un nombre configurado; si está vacío,
            // omitimos la línea completamente para no dejar espacio en blanco.
            if (ConfigSistema.nombreEmpresa.trim().isNotEmpty)
              pw.Center(child: pw.Text(ConfigSistema.nombreEmpresa,
                style: pw.TextStyle(
                  fontSize: fs(10),
                  fontWeight: pw.FontWeight.bold))),
            if (enc.rif.isNotEmpty)
              pw.Center(child: pw.Text("RIF: ${enc.rif}",
                style: pw.TextStyle(
                  fontSize: fs(8),
                  fontWeight: pw.FontWeight.bold,
                  color: PdfColors.black))),
            if (enc.telefono.isNotEmpty)
              pw.Center(child: pw.Text("Tel: ${enc.telefono}",
                style: pw.TextStyle(
                  fontSize: fs(8),
                  fontWeight: pw.FontWeight.bold,
                  color: PdfColors.black))),

            pw.SizedBox(height: 4),
            sepG(),

            // ═══════════════════════════════════════════════════
            //  ORDEN Y FECHA
            // ═══════════════════════════════════════════════════
            pw.Row(mainAxisAlignment: pw.MainAxisAlignment.spaceBetween, children: [
              pw.Container(
                padding: const pw.EdgeInsets.symmetric(horizontal: 5, vertical: 2),
                decoration: pw.BoxDecoration(
                  border: pw.Border.all(width: 0.8, color: PdfColors.black),
                  borderRadius: const pw.BorderRadius.all(pw.Radius.circular(2))),
                child: pw.Text("ORDEN Nº ${s.id ?? "—"}",
                  style: pw.TextStyle(
                    fontSize: fs(9),
                    fontWeight: pw.FontWeight.bold)),
              ),
              pw.Text(
                "${s.fecha.day.toString().padLeft(2,'0')}/"
                "${s.fecha.month.toString().padLeft(2,'0')}/"
                "${s.fecha.year}",
                style: pw.TextStyle(
                  fontSize: fs(9),
                  fontWeight: pw.FontWeight.bold)),
            ]),
            pw.SizedBox(height: 4),

            // ═══════════════════════════════════════════════════
            //  CLIENTE
            // ═══════════════════════════════════════════════════
            secHdr("CLIENTE"),
            pw.Text(s.nombreCliente.isEmpty ? '—' : s.nombreCliente,
              style: pw.TextStyle(
                fontSize: fs(9.5),
                fontWeight: pw.FontWeight.bold)),
            if (s.rifCi.isNotEmpty) _celda("C.I./RIF", s.rifCi),
            if (s.telefono.isNotEmpty) _celda("Tel", s.telefono),
            if (s.horaRecibido.isNotEmpty) _celda("Recibido", s.horaRecibido),
            if (s.fechaEntrega.isNotEmpty) _celda("Entrega", s.fechaEntrega),
            sep(),

            // ═══════════════════════════════════════════════════
            //  EQUIPO (con borde lateral tipo acento)
            // ═══════════════════════════════════════════════════
            secHdr("EQUIPO"),
            pw.Container(
              padding: const pw.EdgeInsets.only(left: 6, right: 2, top: 2, bottom: 4),
              decoration: const pw.BoxDecoration(
                border: pw.Border(
                  left: pw.BorderSide(width: 2, color: PdfColors.black))),
              child: pw.Column(
                crossAxisAlignment: pw.CrossAxisAlignment.start,
                children: [
                  if (s.marca.isNotEmpty || s.modelo.isNotEmpty)
                    pw.Text("${s.marca} ${s.modelo}".trim(),
                      style: pw.TextStyle(
                        fontSize: fs(9.5),
                        fontWeight: pw.FontWeight.bold)),
                  if (s.imei.isNotEmpty) _celda("IMEI", s.imei),
                  if (s.contrasena.isNotEmpty) _celda("Contraseña", s.contrasena),
                  if (s.descripcion.isNotEmpty) _celda("Descripción", s.descripcion),
                ],
              ),
            ),
            sep(),

            // ═══════════════════════════════════════════════════
            //  MONTOS (caja con borde negro nítido)
            // ═══════════════════════════════════════════════════
            secHdr("MONTOS"),
            pw.Container(
              padding: const pw.EdgeInsets.all(5),
              decoration: pw.BoxDecoration(
                border: pw.Border.all(width: 0.6, color: PdfColors.black),
                borderRadius: const pw.BorderRadius.all(pw.Radius.circular(2))),
              child: pw.Column(children: [
                pw.Row(mainAxisAlignment: pw.MainAxisAlignment.spaceBetween, children: [
                  pw.Text("Total",
                    style: pw.TextStyle(
                      fontSize: fs(9),
                      color: PdfColors.black)),
                  pw.Text(formatCurrency(s.monto),
                    style: pw.TextStyle(
                      fontSize: fs(9.5),
                      fontWeight: pw.FontWeight.bold,
                      color: PdfColors.black)),
                ]),
                pw.SizedBox(height: 2),
                pw.Row(mainAxisAlignment: pw.MainAxisAlignment.spaceBetween, children: [
                  pw.Text("Abono",
                    style: pw.TextStyle(
                      fontSize: fs(9),
                      color: PdfColors.black)),
                  pw.Text(formatCurrency(s.abono),
                    style: pw.TextStyle(
                      fontSize: fs(9.5),
                      fontWeight: pw.FontWeight.bold,
                      color: PdfColors.black)),
                ]),
                pw.Container(height: 0.5, color: PdfColors.black,
                  margin: const pw.EdgeInsets.symmetric(vertical: 3)),
                pw.Row(mainAxisAlignment: pw.MainAxisAlignment.spaceBetween, children: [
                  pw.Text("RESTA",
                    style: pw.TextStyle(
                      fontSize: fs(10),
                      fontWeight: pw.FontWeight.bold,
                      color: PdfColors.black)),
                  pw.Text(formatCurrency(s.resta),
                    style: pw.TextStyle(
                      fontSize: fs(11),
                      fontWeight: pw.FontWeight.bold,
                      color: PdfColors.black)),
                ]),
              ]),
            ),
            pw.SizedBox(height: 3),
            // Estado de pago
            pw.Center(child: pw.Container(
              padding: const pw.EdgeInsets.symmetric(horizontal: 8, vertical: 2),
              decoration: pw.BoxDecoration(
                color: s.pagado ? PdfColors.black : PdfColors.white,
                border: pw.Border.all(width: 0.8, color: PdfColors.black),
                borderRadius: const pw.BorderRadius.all(pw.Radius.circular(2))),
              child: pw.Text(s.pagado ? "✓  PAGADO" : "✗  PENDIENTE",
                style: pw.TextStyle(
                  fontSize: fs(9),
                  fontWeight: pw.FontWeight.bold,
                  color: s.pagado ? PdfColors.white : PdfColors.black,
                  letterSpacing: 1)))),
            sep(),

            // ═══════════════════════════════════════════════════
            //  CHECKLIST — solo ítems marcados (SI / NO)
            //  Los ítems no revisados (null) se omiten para mantener
            //  el ticket limpio y legible. Se separan los "SI" (estado
            //  correcto al recibir) de los "NO" (componentes faltantes
            //  o con defecto al recibir el equipo).
            // ═══════════════════════════════════════════════════
            ...(() {
              final items = <MapEntry<String, bool>>[
                if (s.chip               != null) MapEntry("Chip",                 s.chip!),
                if (s.memoria            != null) MapEntry("Memoria",              s.memoria!),
                if (s.bateria            != null) MapEntry("Batería",              s.bateria!),
                if (s.tapa               != null) MapEntry("Tapa",                 s.tapa!),
                if (s.encendido          != null) MapEntry("Encendido",            s.encendido!),
                if (s.apagado            != null) MapEntry("Apagado",              s.apagado!),
                if (s.camara             != null) MapEntry("Cámara",               s.camara!),
                if (s.corneta            != null) MapEntry("Corneta",              s.corneta!),
                if (s.flash              != null) MapEntry("Flash",                s.flash!),
                if (s.flashConDefecto    != null) MapEntry("Flash con defecto",    s.flashConDefecto!),
                if (s.tactilPartido      != null) MapEntry("Táctil partido",       s.tactilPartido!),
                if (s.auricular          != null) MapEntry("Auricular",            s.auricular!),
                if (s.microfono          != null) MapEntry("Micrófono",            s.microfono!),
                if (s.contrasenaChk      != null) MapEntry("Contraseña OK",        s.contrasenaChk!),
                if (s.track              != null) MapEntry("Track",                s.track!),
                if (s.botonVolumen       != null) MapEntry("Botón volumen",        s.botonVolumen!),
                if (s.teclado            != null) MapEntry("Teclado",              s.teclado!),
                if (s.botonEncendido     != null) MapEntry("Botón encendido",      s.botonEncendido!),
                if (s.pantallaConDefecto != null) MapEntry("Pantalla con defecto", s.pantallaConDefecto!),
              ];
              if (items.isEmpty) return <pw.Widget>[];
              return <pw.Widget>[
                secHdr("CHECKLIST DEL EQUIPO"),
                ...items.map((it) => _chkPdf(it.key, it.value)),
                sep(),
              ];
            })(),

            // ═══════════════════════════════════════════════════
            //  NOTAS FINALES
            // ═══════════════════════════════════════════════════
            if (s.observacion.isNotEmpty) ...[
              secHdr("OBSERVACIÓN"),
              pw.Text(s.observacion,
                style: pw.TextStyle(fontSize: fs(8.5))),
              pw.SizedBox(height: 3),
            ],
            pw.Row(children: [
              pw.Expanded(child: _celda("Técnico", _resolverNombreVendedor(s.tecnico))),
            ]),
            pw.Row(children: [
              pw.Expanded(child: _celda("Estado", s.estado)),
            ]),

            pw.SizedBox(height: 5),
            sepG(),
            pw.SizedBox(height: 4),

            // ═══════════════════════════════════════════════════
            //  CONDICIONES (caja con borde nítido)
            // ═══════════════════════════════════════════════════
            pw.Container(
              width: double.infinity,
              padding: const pw.EdgeInsets.all(5),
              decoration: pw.BoxDecoration(
                border: pw.Border.all(width: 0.6, color: PdfColors.black),
                borderRadius: const pw.BorderRadius.all(pw.Radius.circular(2))),
              child: pw.Column(
                crossAxisAlignment: pw.CrossAxisAlignment.start,
                children: [
                  pw.Text("CONDICIONES:",
                    style: pw.TextStyle(
                      fontSize: fs(8),
                      fontWeight: pw.FontWeight.bold,
                      color: PdfColors.black,
                      letterSpacing: 0.5)),
                  pw.SizedBox(height: 2),
                  pw.Text(
                    "• Por favor retirar chip, tapa, batería y memoria. "
                    "No nos hacemos responsables si los dejan sin nuestro consentimiento.",
                    style: pw.TextStyle(
                      fontSize: fs(7),
                      color: PdfColors.black),
                    textAlign: pw.TextAlign.justify),
                  pw.SizedBox(height: 2),
                  pw.Text(
                    "• No respondemos por equipos dejados más de 15 días.",
                    style: pw.TextStyle(
                      fontSize: fs(7),
                      color: PdfColors.black),
                    textAlign: pw.TextAlign.justify),
                ],
              ),
            ),

            // ═══════════════════════════════════════════════════
            //  FIRMAS
            // ═══════════════════════════════════════════════════
            pw.SizedBox(height: 28),
            pw.Center(child: pw.Container(
              width: 140, height: 0.6, color: PdfColors.black)),
            pw.Center(child: pw.Text("Firma del Cliente",
              style: pw.TextStyle(
                fontSize: fs(8),
                fontWeight: pw.FontWeight.bold))),

            pw.SizedBox(height: 22),
            pw.Center(child: pw.Container(
              width: 140, height: 0.6, color: PdfColors.black)),
            pw.Center(child: pw.Text("Quien Recibe",
              style: pw.TextStyle(
                fontSize: fs(8),
                fontWeight: pw.FontWeight.bold))),

            pw.SizedBox(height: 20),
          ],
        ));
      } else {
        // ═══════════════════════════════════════════════════════════
        //  LAYOUT A4 / CARTA — diseño profesional con caja destacada
        // ═══════════════════════════════════════════════════════════
        pdf.addPage(pw.Page(
          pageFormat: ImpresionHelper.formatoPdf(formato),
          margin: const pw.EdgeInsets.all(28),
          build: (context) => pw.Column(
            crossAxisAlignment: pw.CrossAxisAlignment.start,
            children: [
              // ═══════════════════════════════════════════════════
              //  ENCABEZADO con banda oscura
              // ═══════════════════════════════════════════════════
              pw.Container(
                padding: const pw.EdgeInsets.all(14),
                decoration: pw.BoxDecoration(
                  color: PdfColors.grey100,
                  borderRadius: const pw.BorderRadius.all(pw.Radius.circular(6)),
                  border: pw.Border.all(width: 1, color: PdfColors.grey400)),
                child: pw.Row(
                  crossAxisAlignment: pw.CrossAxisAlignment.center,
                  children: [
                    // Izquierda: título + empresa
                    pw.Expanded(child: pw.Column(
                      crossAxisAlignment: pw.CrossAxisAlignment.start,
                      children: [
                        pw.Container(
                          padding: const pw.EdgeInsets.symmetric(horizontal: 8, vertical: 4),
                          decoration: const pw.BoxDecoration(
                            color: PdfColors.black,
                            borderRadius: pw.BorderRadius.all(pw.Radius.circular(3))),
                          child: pw.Text('SERVICIO TÉCNICO',
                            style: pw.TextStyle(
                              fontSize: 16,
                              fontWeight: pw.FontWeight.bold,
                              color: PdfColors.white,
                              letterSpacing: 1.2)),
                        ),
                        pw.SizedBox(height: 8),
                        if (ConfigSistema.nombreEmpresa.trim().isNotEmpty)
                          pw.Text(ConfigSistema.nombreEmpresa,
                            style: pw.TextStyle(
                              fontSize: 14,
                              fontWeight: pw.FontWeight.bold)),
                        if (enc.rif.isNotEmpty)
                          pw.Text("RIF: ${enc.rif}",
                            style: pw.TextStyle(
                              fontSize: 9,
                              fontWeight: pw.FontWeight.normal,
                              color: PdfColors.black)),
                        if (enc.direccion.isNotEmpty)
                          pw.Text(enc.direccion,
                            style: pw.TextStyle(
                              fontSize: 9,
                              fontWeight: pw.FontWeight.normal,
                              color: PdfColors.black)),
                        if (enc.telefono.isNotEmpty)
                          pw.Text("Tel: ${enc.telefono}",
                            style: pw.TextStyle(
                              fontSize: 9,
                              fontWeight: pw.FontWeight.normal,
                              color: PdfColors.black)),
                      ])),
                    // Derecha: orden + fecha
                    pw.Column(
                      crossAxisAlignment: pw.CrossAxisAlignment.end,
                      children: [
                        if (s.id != null)
                          pw.Container(
