                        letterSpacing: 0.5)),
                    pw.SizedBox(height: 5),
                    pw.Text(
                      "• Por favor retirar chip, tapa, batería y memoria de su equipo. "
                      "No nos hacemos responsables si los dejan sin nuestro consentimiento.",
                      style: const pw.TextStyle(fontSize: 8)),
                    pw.SizedBox(height: 3),
                    pw.Text(
                      "• No respondemos por equipos dejados por más de 15 días.",
                      style: const pw.TextStyle(fontSize: 8)),
                  ]),
              ),

              // ═══════════════════════════════════════════════════
              //  FIRMAS
              // ═══════════════════════════════════════════════════
              pw.SizedBox(height: 40),
              pw.Row(children: [
                pw.Expanded(child: pw.Column(children: [
                  pw.Container(height: 0.8, color: PdfColors.black),
                  pw.SizedBox(height: 4),
                  pw.Text("Firma del Cliente",
                    style: pw.TextStyle(fontSize: 10, fontWeight: pw.FontWeight.bold)),
                ])),
                pw.SizedBox(width: 40),
                pw.Expanded(child: pw.Column(children: [
                  pw.Container(height: 0.8, color: PdfColors.black),
                  pw.SizedBox(height: 4),
                  pw.Text("Quien Recibe",
                    style: pw.TextStyle(fontSize: 10, fontWeight: pw.FontWeight.bold)),
                ])),
              ]),
            ],
          ),
        ));
      }

      // Imprimir: intenta Bluetooth directo si es térmica y hay impresora;
      // si no, abre el diálogo del sistema.
      final bytes = await pdf.save();
      if (mounted) {
        await ImpresionHelper.imprimirPdfInteligente(
          context: context,
          pdfBytes: bytes,
          formato: formato,
          nombreArchivo: 'servicio_tecnico_${s.id ?? "nuevo"}');
      }
    } catch (e) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Text("Error al imprimir: $e"),
        backgroundColor: AppColors.statusRed));
    }
  }
}

// ════════════════════════════════════════════════════════════
//  VISOR DE FOTOS DE RECEPCIÓN (pantalla completa)
// ════════════════════════════════════════════════════════════
//  Muestra las fotos del servicio en pantalla completa con:
//   · Swipe horizontal para cambiar de foto
//   · Zoom con pellizco
//   · Indicador "1 / N" en la barra superior
class _ViewerFotosServicio extends StatefulWidget {
  final List<String> fotos;
  final int indiceInicial;
  const _ViewerFotosServicio({
    required this.fotos, required this.indiceInicial});
  @override State<_ViewerFotosServicio> createState() =>
      _ViewerFotosServicioState();
}

class _ViewerFotosServicioState extends State<_ViewerFotosServicio> {
  late PageController _pageCtrl;
  late int _indice;

  @override
  void initState() {
    super.initState();
    _indice = widget.indiceInicial;
    _pageCtrl = PageController(initialPage: widget.indiceInicial);
  }

  @override
  void dispose() {
    _pageCtrl.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: Colors.black,
      appBar: AppBar(
        backgroundColor: Colors.black,
        foregroundColor: Colors.white,
        title: Text("${_indice + 1} / ${widget.fotos.length}"),
      ),
      body: PageView.builder(
        controller: _pageCtrl,
        itemCount: widget.fotos.length,
        onPageChanged: (i) => setState(() => _indice = i),
        itemBuilder: (_, i) {
          Uint8List? bytes;
          try {
            final raw = widget.fotos[i];
            final clean = raw.contains(',')
                ? raw.split(',').last : raw;
            bytes = base64Decode(clean);
          } catch (_) {
            bytes = null;
          }
          if (bytes == null) {
            return const Center(child: Icon(Icons.broken_image,
                color: Colors.white54, size: 80));
          }
          // InteractiveViewer permite zoom con pellizco y pan
          return InteractiveViewer(
            minScale: 1.0,
            maxScale: 4.0,
            child: Center(child: Image.memory(bytes,
                fit: BoxFit.contain)),
          );
        },
      ),
    );
  }
}

// ============================================================
//  USUARIOS — carga y guarda en la API
// ============================================================
class VentanaUsuarios extends StatefulWidget {
  const VentanaUsuarios({super.key});
  @override State<VentanaUsuarios> createState() => _VentanaUsuariosState();
}

class _VentanaUsuariosState extends State<VentanaUsuarios> {
  List<Usuario> _usuarios = [];
  bool _cargando = true;

  @override
  void initState() { super.initState(); _cargar(); }

  Future<void> _cargar() async {
    setState(() => _cargando = true);
    try {
      final raw = await _Api.get('usuarios');
      final todos = ((raw as List?) ?? [])
          .map((m) => Usuario.fromMap(m)).toList();
      // ── Ocultar al UsuarioMaestro (proveedor Tecno Líder) ──
      // Si por algún motivo su correo terminó en la BD, no debe
      // aparecer ni ser editable desde la ventana de Usuarios.
      _usuarios = UsuarioMaestro.ocultar<Usuario>(
          todos, (u) => u.correo);
      usuariosSistema = _usuarios;
    } catch (e) {
      debugPrint('[_cargar] Error: $e');
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Error al cargar datos: $e'), backgroundColor: AppColors.statusRed, duration: const Duration(seconds: 4)));
    } finally {
      if (mounted) setState(() => _cargando = false);
    }
  }

  void _editarUsuario(Usuario usuario) {
    final correoCtrl = TextEditingController(text: usuario.correo);
    final claveCtrl = TextEditingController(text: usuario.clave);
    final nombreCtrl = TextEditingController(text: usuario.nombre);
    final cedulaCtrl = TextEditingController(text: usuario.cedula);
    final sueldoCtrl = TextEditingController(text: usuario.sueldoBase.toStringAsFixed(2));
    String rol = usuario.rol;
    // Tienda asignada al usuario. Vacío = sin asignar / todas (roles altos).
    String tiendaAsignada = usuario.tienda;
    bool verClave = false;
    bool guardando = false;
    final formKey = GlobalKey<FormState>();

    showDialog(context: context, builder: (ctx) => StatefulBuilder(
      builder: (context, setS) => AlertDialog(
        title: Row(children: [
          CircleAvatar(
            radius: 18,
            backgroundColor: _colorRol(usuario.rol).withValues(alpha: 0.15),
            child: Text(usuario.nombre.isNotEmpty ? usuario.nombre[0].toUpperCase() : '?',
              style: TextStyle(color: _colorRol(usuario.rol), fontWeight: FontWeight.bold)),
          ),
          const SizedBox(width: 10),
          const Text("Editar Usuario"),
        ]),
        content: SingleChildScrollView(
          child: Form(
            key: formKey,
            child: Column(mainAxisSize: MainAxisSize.min, children: [
              TextFormField(
                controller: nombreCtrl,
                textCapitalization: TextCapitalization.words,
                decoration: const InputDecoration(labelText: "Nombre completo *", prefixIcon: Icon(Icons.person_outline)),
                validator: (v) => (v == null || v.trim().isEmpty) ? "El nombre es obligatorio" : null,
              ),
              const SizedBox(height: 10),
              TextFormField(
                controller: cedulaCtrl,
                keyboardType: TextInputType.number,
                decoration: const InputDecoration(labelText: "Cédula", prefixIcon: Icon(Icons.badge_outlined)),
              ),
              const SizedBox(height: 10),
              TextFormField(
                controller: correoCtrl,
                keyboardType: TextInputType.emailAddress,
                decoration: const InputDecoration(labelText: "Correo / Usuario *", prefixIcon: Icon(Icons.email_outlined)),
                validator: (v) {
                  if (v == null || v.trim().isEmpty) return "El correo es obligatorio";
                  final emailRegex = RegExp(r'^[^@\s]+@[^@\s]+\.[^@\s]+$');
                  if (!emailRegex.hasMatch(v.trim())) return "Ingrese un correo válido";
                  return null;
                },
              ),
              const SizedBox(height: 10),
              TextFormField(
                controller: claveCtrl,
                obscureText: !verClave,
                decoration: InputDecoration(
                  labelText: "Contraseña *",
                  prefixIcon: const Icon(Icons.lock_outline),
                  suffixIcon: IconButton(
                    icon: Icon(verClave ? Icons.visibility_off_outlined : Icons.visibility_outlined),
                    onPressed: () => setS(() => verClave = !verClave),
                  ),
                ),
                validator: (v) {
                  if (v == null || v.isEmpty) return "La contraseña es obligatoria";
                  if (v.length < 4) return "La contraseña debe tener al menos 4 caracteres";
                  return null;
                },
              ),
              const SizedBox(height: 10),
              TextFormField(
                controller: sueldoCtrl,
                keyboardType: const TextInputType.numberWithOptions(decimal: true),
                decoration: const InputDecoration(labelText: "Sueldo base (\$)", prefixIcon: Icon(Icons.attach_money)),
              ),
              const SizedBox(height: 10),
              DropdownButtonFormField<String>(
                value: rol,
                items: ["Dueño","Administrador","Gerente","Encargado","Activador","Vendedor"]
                    .map((e) => DropdownMenuItem(value: e, child: Text(e))).toList(),
                onChanged: (v) { if (v != null) setS(() => rol = v); },
                decoration: const InputDecoration(labelText: "Rol / Permisos", prefixIcon: Icon(Icons.security_outlined)),
              ),
              const SizedBox(height: 10),
              // ── Tienda asignada ──
              // Roles altos (Dueño/Administrador/Gerente) pueden tener tienda vacía
              // para ver todas las tiendas. Vendedor/Activador/Encargado deben
              // tener una asignada.
              DropdownButtonFormField<String>(
                value: ConfigSistema.tiendas.contains(tiendaAsignada)
                    ? tiendaAsignada : '',
                items: [
                  const DropdownMenuItem(value: '', child: Text('— Todas / sin asignar —')),
                  ...ConfigSistema.tiendas.map((t) =>
                      DropdownMenuItem(value: t, child: Text(t))),
                ],
                onChanged: (v) => setS(() => tiendaAsignada = v ?? ''),
                decoration: const InputDecoration(
                  labelText: "Tienda asignada",
                  prefixIcon: Icon(Icons.store_outlined),
                  helperText: 'Vendedor / Activador: debe tener una tienda asignada',
                ),
              ),
            ]),
          ),
        ),
        actions: [
          TextButton(child: const Text("Cancelar"), onPressed: () => Navigator.pop(ctx)),
          ElevatedButton.icon(
            icon: guardando
              ? const SizedBox(width: 16, height: 16, child: CircularProgressIndicator(strokeWidth: 2, color: Colors.white))
              : const Icon(Icons.save_outlined, size: 18),
            label: const Text("Guardar"),
            onPressed: guardando ? null : () async {
              if (!formKey.currentState!.validate()) return;
              setS(() => guardando = true);
              try {
                if (usuario.id == null) throw Exception('Usuario sin ID');
                  await _Api.put('usuarios', usuario.id!.toString(), {
                  'nombre': nombreCtrl.text.trim(),
                  'cedula': cedulaCtrl.text.trim(),
                  'correo': correoCtrl.text.trim(),
                  'clave': claveCtrl.text.trim(),
                  'rol': rol,
                  'sueldo_base': double.tryParse(sueldoCtrl.text) ?? 0,
                  'tienda': tiendaAsignada,
                });
                if (!ctx.mounted) return;
                Navigator.pop(ctx);
                await _cargar();
                if (mounted) ScaffoldMessenger.of(context).showSnackBar(
                  const SnackBar(content: Text("Usuario actualizado correctamente"), backgroundColor: AppColors.statusGreen));
              } catch (e) {
                setS(() => guardando = false);
                if (ctx.mounted) ScaffoldMessenger.of(context).showSnackBar(
                  SnackBar(content: Text('Error: $e'), backgroundColor: AppColors.statusRed));
              }
            },
          ),
        ],
      ),
    ));
  }

  void _crearUsuario() {
    final correoCtrl = TextEditingController();
    final claveCtrl = TextEditingController();
    final confirmarClaveCtrl = TextEditingController();
    final nombreCtrl = TextEditingController();
    final cedulaCtrl = TextEditingController();
    final sueldoCtrl = TextEditingController(text: "0");
    String rol = "Vendedor";
    String tiendaAsignada = ConfigSistema.tiendas.isNotEmpty
        ? ConfigSistema.tiendas.first : '';
    bool verClave = false;
    bool guardando = false;
    final formKey = GlobalKey<FormState>();

    showDialog(context: context, builder: (ctx) => StatefulBuilder(
      builder: (context, setS) => AlertDialog(
        title: const Row(children: [
          Icon(Icons.person_add_outlined, color: AppColors.royalBlue),
          SizedBox(width: 8),
          Text("Nuevo Usuario"),
        ]),
        content: SingleChildScrollView(
          child: Form(
            key: formKey,
            child: Column(mainAxisSize: MainAxisSize.min, children: [
              TextFormField(
                controller: nombreCtrl,
                textCapitalization: TextCapitalization.words,
                decoration: const InputDecoration(labelText: "Nombre completo *", prefixIcon: Icon(Icons.person_outline)),
                validator: (v) => (v == null || v.trim().isEmpty) ? "El nombre es obligatorio" : null,
              ),
              const SizedBox(height: 10),
              TextFormField(
                controller: cedulaCtrl,
                keyboardType: TextInputType.number,
                decoration: const InputDecoration(labelText: "Cédula", prefixIcon: Icon(Icons.badge_outlined)),
              ),
              const SizedBox(height: 10),
              TextFormField(
                controller: correoCtrl,
                keyboardType: TextInputType.emailAddress,
                decoration: const InputDecoration(labelText: "Correo / Usuario *", prefixIcon: Icon(Icons.email_outlined)),
                validator: (v) {
                  if (v == null || v.trim().isEmpty) return "El correo es obligatorio";
                  final emailRegex = RegExp(r'^[^@\s]+@[^@\s]+\.[^@\s]+$');
                  if (!emailRegex.hasMatch(v.trim())) return "Ingrese un correo válido";
                  // Verificar si ya existe en el sistema
                  final existe = usuariosSistema.any(
                    (u) => u.correo.toLowerCase() == v.trim().toLowerCase());
                  if (existe) return "Este correo ya está registrado";
                  return null;
                },
              ),
              const SizedBox(height: 10),
              TextFormField(
                controller: claveCtrl,
                obscureText: !verClave,
                decoration: InputDecoration(
                  labelText: "Contraseña *",
                  prefixIcon: const Icon(Icons.lock_outline),
                  suffixIcon: IconButton(
                    icon: Icon(verClave ? Icons.visibility_off_outlined : Icons.visibility_outlined),
                    onPressed: () => setS(() => verClave = !verClave),
                  ),
                ),
                validator: (v) {
                  if (v == null || v.isEmpty) return "La contraseña es obligatoria";
                  if (v.length < 4) return "Mínimo 4 caracteres";
                  return null;
                },
              ),
              const SizedBox(height: 10),
              TextFormField(
                controller: confirmarClaveCtrl,
                obscureText: !verClave,
                decoration: const InputDecoration(labelText: "Confirmar contraseña *", prefixIcon: Icon(Icons.lock_outline)),
                validator: (v) => v != claveCtrl.text ? "Las contraseñas no coinciden" : null,
              ),
              const SizedBox(height: 10),
              TextFormField(
                controller: sueldoCtrl,
                keyboardType: const TextInputType.numberWithOptions(decimal: true),
                decoration: const InputDecoration(labelText: "Sueldo base (\$)", prefixIcon: Icon(Icons.attach_money)),
              ),
              const SizedBox(height: 10),
              DropdownButtonFormField<String>(
                value: rol,
                items: ["Dueño","Administrador","Gerente","Encargado","Activador","Vendedor"]
                    .map((e) => DropdownMenuItem(value: e, child: Text(e))).toList(),
                onChanged: (v) { if (v != null) setS(() => rol = v); },
                decoration: const InputDecoration(labelText: "Rol / Permisos", prefixIcon: Icon(Icons.security_outlined)),
              ),
              const SizedBox(height: 10),
              // ── Tienda asignada ──
              DropdownButtonFormField<String>(
                value: ConfigSistema.tiendas.contains(tiendaAsignada)
                    ? tiendaAsignada : '',
                items: [
                  const DropdownMenuItem(value: '', child: Text('— Todas / sin asignar —')),
                  ...ConfigSistema.tiendas.map((t) =>
                      DropdownMenuItem(value: t, child: Text(t))),
                ],
                onChanged: (v) => setS(() => tiendaAsignada = v ?? ''),
                decoration: const InputDecoration(
                  labelText: "Tienda asignada",
                  prefixIcon: Icon(Icons.store_outlined),
                  helperText: 'Vendedor / Activador: debe tener una tienda asignada',
                ),
              ),
            ]),
          ),
        ),
        actions: [
          TextButton(child: const Text("Cancelar"), onPressed: () => Navigator.pop(ctx)),
          ElevatedButton.icon(
            icon: guardando
              ? const SizedBox(width: 16, height: 16, child: CircularProgressIndicator(strokeWidth: 2, color: Colors.white))
              : const Icon(Icons.person_add_outlined, size: 18),
            label: const Text("Crear"),
            onPressed: guardando ? null : () async {
              if (!formKey.currentState!.validate()) return;
              setS(() => guardando = true);
              try {
                await _Api.post('usuarios', {
                  'nombre': nombreCtrl.text.trim(),
                  'cedula': cedulaCtrl.text.trim(),
                  'correo': correoCtrl.text.trim(),
                  'clave': claveCtrl.text.trim(),
                  'rol': rol,
                  'sueldo_base': double.tryParse(sueldoCtrl.text) ?? 0,
                  'tienda': tiendaAsignada,
                });
                if (!ctx.mounted) return;
                Navigator.pop(ctx);
                await _cargar();
                if (mounted) ScaffoldMessenger.of(context).showSnackBar(
                  SnackBar(content: Text("Usuario '${nombreCtrl.text.trim()}' creado exitosamente"),
                    backgroundColor: AppColors.statusGreen));
              } catch (e) {
                setS(() => guardando = false);
                if (ctx.mounted) ScaffoldMessenger.of(context).showSnackBar(
                  SnackBar(content: Text('Error: $e'), backgroundColor: AppColors.statusRed));
              }
            },
          ),
        ],
      ),
    ));
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text("Gestión de Usuarios"),
        actions: [IconButton(icon: const Icon(Icons.refresh), tooltip: "Actualizar", onPressed: _cargar)],
      ),
      body: _cargando
        ? const Center(child: CircularProgressIndicator())
        : _usuarios.isEmpty
          ? const EmptyState(mensaje: "No hay usuarios registrados.", icono: Icons.people_outline)
          : ListView.builder(
            padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
            itemCount: _usuarios.length,
            itemBuilder: (c, i) {
              final u = _usuarios[i];
              final esYo = u.correo == usuarioSesion?.correo;
              final colorRol = _colorRol(u.rol);
              return Card(
                margin: const EdgeInsets.only(bottom: 8),
                shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(12)),
                elevation: 1,
                child: ListTile(
                  contentPadding: const EdgeInsets.symmetric(horizontal: 16, vertical: 8),
                  leading: CircleAvatar(
                    backgroundColor: colorRol.withValues(alpha: 0.15),
                    radius: 24,
                    child: Text(u.nombre.isNotEmpty ? u.nombre[0].toUpperCase() : '?',
                      style: TextStyle(color: colorRol, fontWeight: FontWeight.bold, fontSize: 18)),
                  ),
                  title: Row(children: [
                    Expanded(child: Text(u.nombre,
                      style: const TextStyle(fontWeight: FontWeight.w600, color: AppColors.textPrimary))),
                    if (esYo) Container(
                      padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 2),
                      decoration: BoxDecoration(
                        color: AppColors.primaryBlue.withValues(alpha: 0.1),
                        borderRadius: BorderRadius.circular(10)),
                      child: const Text("Yo", style: TextStyle(fontSize: 11, color: AppColors.primaryBlue, fontWeight: FontWeight.bold)),
                    ),
                  ]),
                  subtitle: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                    const SizedBox(height: 2),
                    Row(children: [
                      const Icon(Icons.email_outlined, size: 13, color: AppColors.textSecondary),
                      const SizedBox(width: 4),
                      Text(u.correo, style: const TextStyle(fontSize: 12, color: AppColors.textSecondary)),
                    ]),
                    const SizedBox(height: 2),
                    Row(children: [
                      Container(
                        padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 2),
                        decoration: BoxDecoration(
                          color: colorRol.withValues(alpha: 0.1),
                          borderRadius: BorderRadius.circular(10),
                        ),
                        child: Text(u.rol, style: TextStyle(fontSize: 11, color: colorRol, fontWeight: FontWeight.bold)),
                      ),
                      if (u.sueldoBase > 0) ...[
                        const SizedBox(width: 8),
                        Text("Sueldo: ${formatCurrency(u.sueldoBase)}",
                          style: const TextStyle(fontSize: 11, color: AppColors.textSecondary)),
                      ],
                    ]),
                  ]),
                  trailing: Row(mainAxisSize: MainAxisSize.min, children: [
                    IconButton(
                      icon: const Icon(Icons.edit_outlined, color: AppColors.primaryBlue, size: 20),
                      tooltip: "Editar usuario",
                      onPressed: () => _editarUsuario(u)),
                    // Eliminar: solo si no es el usuario actual y solo Administrador/Dueño
                    if (!esYo &&
                        ((usuarioSesion?.rol == 'Administrador' || usuarioSesion?.rol == 'Maestro') ||
                         (usuarioSesion?.rol == 'Dueño' || usuarioSesion?.rol == 'Maestro')))
                      IconButton(
                        icon: const Icon(Icons.delete_outline, color: AppColors.statusRed, size: 20),
                        tooltip: "Eliminar usuario",
                        onPressed: () => _confirmarEliminarUsuario(u)),
                  ]),
                  onTap: () => _editarUsuario(u),
                ),
              );
            },
          ),
      floatingActionButton: FloatingActionButton(
        onPressed: _crearUsuario,
        child: const Icon(Icons.person_add_outlined)),
    );
  }

  Color _colorRol(String rol) {
    switch (rol) {
      case 'Dueño': return const Color(0xFF6B21A8);
      case 'Administrador': return AppColors.statusRed;
      case 'Gerente': return AppColors.royalBlue;
      case 'Encargado': return AppColors.statusOrange;
      case 'Activador': return AppColors.primaryBlue;
      default: return AppColors.statusGreen;
    }
  }

  Future<void> _confirmarEliminarUsuario(Usuario u) async {
    final confirmar = await showDialog<bool>(
      context: context,
      builder: (ctx) => AlertDialog(
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(16)),
        title: const Row(children: [
          Icon(Icons.delete_forever_outlined, color: AppColors.statusRed),
          SizedBox(width: 8),
          Text("Eliminar Usuario"),
        ]),
        content: Column(mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.start, children: [
          Container(
            padding: const EdgeInsets.all(12),
            decoration: BoxDecoration(
              color: AppColors.surfaceGrey,
              borderRadius: BorderRadius.circular(10),
              border: Border.all(color: AppColors.cardBorder)),
            child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
              Text(u.nombre, style: const TextStyle(fontWeight: FontWeight.w600, fontSize: 14)),
              const SizedBox(height: 4),
              Text(u.correo, style: const TextStyle(fontSize: 12, color: AppColors.textSecondary)),
              Text("Rol: ${u.rol}", style: const TextStyle(fontSize: 12, color: AppColors.textSecondary)),
            ]),
          ),
          const SizedBox(height: 12),
          const Text("Esta acción eliminará el usuario permanentemente.",
            style: TextStyle(color: AppColors.statusRed, fontSize: 12)),
          const SizedBox(height: 4),
          const Text("Sus facturas y registros históricos se mantendrán.",
            style: TextStyle(color: AppColors.textSecondary, fontSize: 11,
              fontStyle: FontStyle.italic)),
        ]),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(ctx, false),
            child: const Text("Cancelar")),
          ElevatedButton.icon(
            style: ElevatedButton.styleFrom(backgroundColor: AppColors.statusRed),
            icon: const Icon(Icons.delete_forever_outlined, size: 16, color: Colors.white),
            label: const Text("Eliminar", style: TextStyle(color: Colors.white)),
            onPressed: () => Navigator.pop(ctx, true)),
        ],
      ),
    );
    if (confirmar != true || !mounted) return;
    try {
      if (u.id == null) throw Exception('Usuario sin ID');
      await _Api.delete('usuarios', u.id!.toString());
      await _cargar();
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Text("Usuario '${u.nombre}' eliminado correctamente."),
        backgroundColor: AppColors.statusGreen));
    } catch (e) {
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Text("Error al eliminar usuario: $e"),
        backgroundColor: AppColors.statusRed));
    }
  }
}

// ============================================================
//  CUENTAS POR COBRAR — carga desde la API
// ============================================================
class VentanaCuentasPorCobrar extends StatefulWidget {
  const VentanaCuentasPorCobrar({super.key});
  @override State<VentanaCuentasPorCobrar> createState() => _VentanaCuentasPorCobrarState();
}

class _VentanaCuentasPorCobrarState extends State<VentanaCuentasPorCobrar> {
  List<CuentaPorCobrar> _cuentas = [];
  bool _cargando = true;
  String _query = '';
  bool get puedeEditar => (usuarioSesion?.rol == "Administrador" || usuarioSesion?.rol == "Maestro" || usuarioSesion?.rol == "Dueño");

  @override
  void initState() { super.initState(); _cargar(); }

  Future<void> _cargar() async {
    setState(() => _cargando = true);
    try {
      final raw = await _Api.get('cuentas_cobrar');
      _cuentas = ((raw as List?) ?? []).map((m) => CuentaPorCobrar.fromMap(m)).toList();
      _cuentas.sort((a, b) => b.saldoRestante.compareTo(a.saldoRestante));
      cuentasGlobal = _cuentas;
    } catch (e) {
      debugPrint('[_cargar] Error: $e');
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Error al cargar datos: $e'), backgroundColor: AppColors.statusRed, duration: const Duration(seconds: 4)));
    } finally {
      if (mounted) setState(() => _cargando = false);
    }
  }

  List<CuentaPorCobrar> get _filtradas => _cuentas.where((c) =>
    _query.isEmpty ||
    c.nombre.toLowerCase().contains(_query.toLowerCase()) ||
    c.cedula.contains(_query)).toList();

  @override
  Widget build(BuildContext context) {
    final totalPendiente = _filtradas.fold(0.0, (s, c) => s + c.saldoRestante);
    return Scaffold(
      appBar: AppBar(
        title: const Text("Cuentas por Cobrar"),
        actions: [IconButton(icon: const Icon(Icons.refresh), tooltip: "Actualizar", onPressed: _cargar)],
      ),
      body: Column(children: [
        // Banner
        Container(
          width: double.infinity,
          padding: const EdgeInsets.symmetric(horizontal: 20, vertical: 14),
          color: AppColors.royalBlue,
          child: Row(children: [
            Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
              const Text("TOTAL POR COBRAR", style: TextStyle(color: Colors.white70, fontSize: 11, letterSpacing: 1)),
              Text(formatCurrency(totalPendiente),
                style: const TextStyle(color: Colors.white, fontSize: 28, fontWeight: FontWeight.bold)),
            ]),
            const Spacer(),
            Column(crossAxisAlignment: CrossAxisAlignment.end, children: [
              const Text("Cuentas", style: TextStyle(color: Colors.white70, fontSize: 11)),
              Text("${_filtradas.length}", style: const TextStyle(color: Colors.white, fontSize: 22, fontWeight: FontWeight.bold)),
            ]),
          ]),
        ),
        // Búsqueda
        Padding(
          padding: const EdgeInsets.all(12),
          child: TextField(
            decoration: InputDecoration(
              hintText: "Buscar por nombre o cédula...",
              prefixIcon: const Icon(Icons.search, color: AppColors.primaryBlue),
              filled: true, fillColor: Colors.white,
              border: OutlineInputBorder(borderRadius: BorderRadius.circular(12), borderSide: BorderSide.none),
              contentPadding: const EdgeInsets.symmetric(vertical: 0, horizontal: 16),
            ),
            onChanged: (v) => setState(() => _query = v),
          ),
        ),
        if (_cargando)
          const Expanded(child: Center(child: CircularProgressIndicator()))
        else if (_filtradas.isEmpty)
          const Expanded(child: EmptyState(mensaje: "No hay cuentas por cobrar.", icono: Icons.money_off_outlined))
        else
          Expanded(child: RefreshIndicator(
            onRefresh: _cargar,
            child: ListView.builder(
              padding: const EdgeInsets.symmetric(horizontal: 12),
              itemCount: _filtradas.length,
              itemBuilder: (c, i) {
                final cuenta = _filtradas[i];
                final pct = cuenta.montoTotal > 0
                    ? (1 - cuenta.saldoRestante / cuenta.montoTotal).clamp(0.0, 1.0)
                    : 1.0;
                final saldado = cuenta.saldoRestante <= 0;
                return Card(
                  margin: const EdgeInsets.only(bottom: 8),
                  shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(12)),
                  elevation: 1,
                  child: InkWell(
                    borderRadius: BorderRadius.circular(12),
                    onTap: () => Navigator.push(context,
                      MaterialPageRoute(builder: (_) => DetalleCuentaCobrar(cuenta: cuenta)))
                      .then((_) => _cargar()),
                    child: Padding(
                      padding: const EdgeInsets.all(14),
                      child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                        Row(children: [
                          CircleAvatar(
                            radius: 20,
                            backgroundColor: (saldado ? AppColors.statusGreen : AppColors.statusRed).withValues(alpha: 0.12),
                            child: Text(cuenta.nombre.isNotEmpty ? cuenta.nombre[0].toUpperCase() : "?",
                              style: TextStyle(
                                color: saldado ? AppColors.statusGreen : AppColors.statusRed,
                                fontWeight: FontWeight.bold)),
                          ),
                          const SizedBox(width: 10),
                          Expanded(child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                            Text(cuenta.nombre, style: const TextStyle(fontWeight: FontWeight.w600)),
                            Text("C.I.: ${cuenta.cedula} · ${cuenta.telefono}",
                              style: const TextStyle(fontSize: 12, color: AppColors.textSecondary)),
                          ])),
                          Column(crossAxisAlignment: CrossAxisAlignment.end, children: [
                            Text(formatCurrency(cuenta.saldoRestante),
                              style: TextStyle(fontWeight: FontWeight.bold, fontSize: 16,
                                color: saldado ? AppColors.statusGreen : AppColors.statusRed)),
                            Text("de ${formatCurrency(cuenta.montoTotal)}",
                              style: const TextStyle(fontSize: 11, color: AppColors.textSecondary)),
                          ]),
                        ]),
                        const SizedBox(height: 10),
                        ClipRRect(
                          borderRadius: BorderRadius.circular(4),
                          child: LinearProgressIndicator(
                            value: pct,
                            minHeight: 5,
                            backgroundColor: Colors.grey[200],
                            valueColor: AlwaysStoppedAnimation<Color>(
                              saldado ? AppColors.statusGreen : (pct > 0.5 ? AppColors.statusOrange : AppColors.statusRed)),
                          ),
                        ),
                        const SizedBox(height: 4),
                        Row(children: [
                          Text("${(pct * 100).toStringAsFixed(0)}% pagado",
                            style: const TextStyle(fontSize: 11, color: AppColors.textSecondary)),
                          const Spacer(),
                          // Mostrar próxima cuota si existe
                          if (cuenta.proximaCuota != null)
                            Container(
                              padding: const EdgeInsets.symmetric(horizontal: 7, vertical: 2),
                              decoration: BoxDecoration(
                                color: AppColors.statusOrange.withValues(alpha: 0.1),
                                borderRadius: BorderRadius.circular(8),
                                border: Border.all(color: AppColors.statusOrange.withValues(alpha: 0.4), width: 0.7),
                              ),
                              child: Row(mainAxisSize: MainAxisSize.min, children: [
                                const Icon(Icons.event_outlined, size: 11, color: AppColors.statusOrange),
                                const SizedBox(width: 3),
                                Text(
                                  "Cuota ${cuenta.proximaCuota!.numero}: ${formatCurrency(cuenta.proximaCuota!.monto)} · ${cuenta.proximaCuota!.fecha}",
                                  style: const TextStyle(fontSize: 10, color: AppColors.statusOrange),
                                ),
                              ]),
                            )
                          else if (cuenta.cuotas.isNotEmpty && saldado)
                            const Text("Todas las cuotas pagadas ✓",
                              style: TextStyle(fontSize: 11, color: AppColors.statusGreen)),
                        ]),
                      ]),
                    ),
                  ),
                );
              },
            ),
          )),
      ]),
      floatingActionButton: puedeEditar
          ? FloatingActionButton.extended(
              onPressed: _crearCuenta,
              icon: const Icon(Icons.add),
              label: const Text("Nueva Cuenta"),
            )
          : null,
    );
  }

  void _crearCuenta() {
    final cedCtrl   = TextEditingController();
    final nomCtrl   = TextEditingController();
    final telCtrl   = TextEditingController();
    final corCtrl   = TextEditingController();
    final deudaCtrl = TextEditingController();
    final notasCtrl = TextEditingController();
    final formKey   = GlobalKey<FormState>();
    bool guardando  = false;

    // ── Estado interno del builder para cuotas ──
    bool usarCuotas = false;
    int  numCuotas  = 1;
    // Lista dinámica de controladores por cuota: [montoCtrl, fechaCtrl]
    List<List<TextEditingController>> cuotasCtrl = [
      [TextEditingController(), TextEditingController()],
    ];

    // Usamos una variable de función para evitar problemas de captura
    // en closures anidados (StatefulBuilder → onPressed)
    late void Function(void Function(void Function()), int) actualizarCuotas;
    actualizarCuotas = (setS, nuevaCant) {
      setS(() {
        numCuotas = nuevaCant.clamp(1, 60);
        while (cuotasCtrl.length < numCuotas) {
          cuotasCtrl.add([TextEditingController(), TextEditingController()]);
        }
        while (cuotasCtrl.length > numCuotas) {
          for (final c in cuotasCtrl.last) c.dispose();
          cuotasCtrl.removeLast();
        }
        final total = double.tryParse(deudaCtrl.text.trim()) ?? 0;
        if (total > 0 && numCuotas > 0) {
          final porCuota = (total / numCuotas).toStringAsFixed(2);
          for (final par in cuotasCtrl) {
            par[0].text = porCuota;
          }
        }
      });
    };

    showModalBottomSheet(
      context: context,
      isScrollControlled: true,
      shape: const RoundedRectangleBorder(
          borderRadius: BorderRadius.vertical(top: Radius.circular(20))),
      builder: (ctx) => StatefulBuilder(
        builder: (context, setS) => DraggableScrollableSheet(
          initialChildSize: 0.92,
          minChildSize: 0.5,
          maxChildSize: 0.97,
          expand: false,
          builder: (_, scrollCtrl) => Padding(
            padding: EdgeInsets.only(
              bottom: MediaQuery.of(ctx).viewInsets.bottom,
              left: 24, right: 24, top: 20),
            child: Form(
              key: formKey,
              child: ListView(
                controller: scrollCtrl,
                children: [
                  // ── Título ──────────────────────────────────
                  Row(children: [
                    const Icon(Icons.money_off_outlined, color: AppColors.royalBlue),
                    const SizedBox(width: 8),
                    const Text("Nueva Cuenta por Cobrar",
                        style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold)),
                    const Spacer(),
                    IconButton(
                        icon: const Icon(Icons.close),
                        onPressed: () => Navigator.pop(ctx)),
                  ]),
                  const Divider(),
                  const SizedBox(height: 8),

                  // ── Datos del cliente ────────────────────────
                  const Text("Datos del cliente",
                      style: TextStyle(fontWeight: FontWeight.w600,
                          color: AppColors.royalBlue, fontSize: 13)),
                  const SizedBox(height: 10),
                  TextFormField(
                    controller: cedCtrl,
                    keyboardType: TextInputType.number,
                    textInputAction: TextInputAction.next,
                    decoration: const InputDecoration(
                        labelText: "Cédula *",
                        prefixIcon: Icon(Icons.badge_outlined)),
                    validator: (v) => (v?.trim().isEmpty ?? true)
                        ? "La cédula es obligatoria"
                        : null,
                  ),
                  const SizedBox(height: 10),
                  TextFormField(
                    controller: nomCtrl,
                    textCapitalization: TextCapitalization.words,
                    textInputAction: TextInputAction.next,
                    decoration: const InputDecoration(
                        labelText: "Nombre completo *",
                        prefixIcon: Icon(Icons.person_outline)),
                    validator: (v) => (v?.trim().isEmpty ?? true)
                        ? "El nombre es obligatorio"
                        : null,
                  ),
                  const SizedBox(height: 10),
                  Row(children: [
                    Expanded(
                      child: TextFormField(
                        controller: telCtrl,
                        keyboardType: TextInputType.phone,
                        textInputAction: TextInputAction.next,
                        decoration: const InputDecoration(
                            labelText: "Teléfono",
                            prefixIcon: Icon(Icons.phone_outlined)),
                      ),
                    ),
                    const SizedBox(width: 10),
                    Expanded(
                      child: TextFormField(
                        controller: corCtrl,
                        keyboardType: TextInputType.emailAddress,
                        textInputAction: TextInputAction.next,
                        decoration: const InputDecoration(
                            labelText: "Correo",
                            prefixIcon: Icon(Icons.email_outlined)),
                      ),
                    ),
                  ]),
                  const SizedBox(height: 10),
                  TextFormField(
                    controller: deudaCtrl,
                    keyboardType:
                        const TextInputType.numberWithOptions(decimal: true),
                    textInputAction: TextInputAction.next,
                    decoration: const InputDecoration(
                      labelText: "Monto total deuda *",
                      prefixIcon: Icon(Icons.attach_money),
                      
                    ),
                    onChanged: (_) {
                      if (usarCuotas) {
                        actualizarCuotas(setS, numCuotas);
                      }
                    },
                    validator: (v) {
                      final d = double.tryParse(v?.trim() ?? '');
                      if (d == null || d <= 0)
                        return "Ingrese un monto válido mayor a 0";
                      return null;
                    },
                  ),
                  const SizedBox(height: 10),
                  TextFormField(
                    controller: notasCtrl,
                    maxLines: 2,
                    textInputAction: TextInputAction.done,
                    decoration: const InputDecoration(
                        labelText: "Notas / observaciones",
                        prefixIcon: Icon(Icons.notes_outlined)),
                  ),
                  const SizedBox(height: 18),

                  // ── Sección Cuotas ───────────────────────────
                  Container(
                    decoration: BoxDecoration(
                      color: AppColors.surfaceGrey,
                      borderRadius: BorderRadius.circular(12),
                      border: Border.all(color: AppColors.cardBorder),
                    ),
                    child: Column(children: [
                      // Toggle cuotas
                      SwitchListTile(
                        value: usarCuotas,
                        onChanged: (v) =>
                            setS(() => usarCuotas = v),
                        title: const Text("Dividir en cuotas",
                            style: TextStyle(fontWeight: FontWeight.w600)),
                        subtitle: const Text(
                            "Define número, fecha y monto de cada cuota",
                            style: TextStyle(fontSize: 11)),
                        secondary: const Icon(Icons.calendar_month_outlined,
                            color: AppColors.royalBlue),
                        activeColor: AppColors.royalBlue,
                      ),
                      if (usarCuotas) ...[
                        const Divider(height: 1),
                        Padding(
                          padding: const EdgeInsets.fromLTRB(16, 12, 16, 4),
                          child: Row(children: [
                            const Text("Número de cuotas:",
                                style: TextStyle(fontWeight: FontWeight.w500)),
                            const Spacer(),
                            IconButton(
                              icon: const Icon(Icons.remove_circle_outline,
                                  color: AppColors.statusRed),
                              onPressed: () =>
                                  actualizarCuotas(setS, numCuotas - 1),
                            ),
                            Container(
                              width: 40,
                              alignment: Alignment.center,
                              child: Text("$numCuotas",
                                  style: const TextStyle(
                                      fontSize: 20,
                                      fontWeight: FontWeight.bold)),
                            ),
                            IconButton(
                              icon: const Icon(Icons.add_circle_outline,
                                  color: AppColors.statusGreen),
                              onPressed: () =>
                                  actualizarCuotas(setS, numCuotas + 1),
                            ),
                          ]),
                        ),
                        // Tabla de cuotas
                        Padding(
                          padding:
                              const EdgeInsets.fromLTRB(16, 0, 16, 16),
                          child: Column(
                            children: List.generate(numCuotas, (i) {
                              final mc = cuotasCtrl[i][0];
                              final fc = cuotasCtrl[i][1];
                              return Padding(
                                padding:
                                    const EdgeInsets.only(bottom: 10),
                                child: Row(children: [
                                  // Número
                                  Container(
                                    width: 28,
                                    height: 28,
                                    decoration: BoxDecoration(
                                      color: AppColors.royalBlue,
                                      shape: BoxShape.circle,
                                    ),
                                    child: Center(
                                      child: Text("${i + 1}",
                                          style: const TextStyle(
                                              color: Colors.white,
                                              fontSize: 12,
                                              fontWeight:
                                                  FontWeight.bold)),
                                    ),
                                  ),
                                  const SizedBox(width: 8),
                                  // Monto
                                  Expanded(
                                    flex: 2,
                                    child: TextFormField(
                                      controller: mc,
                                      keyboardType:
                                          const TextInputType
                                              .numberWithOptions(
                                                  decimal: true),
                                      decoration: InputDecoration(
                                        labelText: "Monto", isDense: true,
                                        
                                        border: OutlineInputBorder(
                                            borderRadius:
                                                BorderRadius.circular(
                                                    8)),
                                      ),
                                      validator: (v) {
                                        if (!usarCuotas) return null;
                                        final d = double.tryParse(
                                            v?.trim() ?? '');
                                        if (d == null || d <= 0)
                                          return "Requerido";
                                        return null;
                                      },
                                    ),
                                  ),
                                  const SizedBox(width: 8),
                                  // Fecha
                                  Expanded(
                                    flex: 3,
                                    child: TextFormField(
                                      controller: fc,
                                      readOnly: true,
                                      decoration: InputDecoration(
                                        labelText: "Fecha venc.", isDense: true,
                                        prefixIcon: const Icon(
                                            Icons.event_outlined,
                                            size: 16),
                                        border: OutlineInputBorder(
                                            borderRadius:
                                                BorderRadius.circular(
                                                    8)),
                                      ),
                                      onTap: () async {
                                        final picked =
                                            await showDatePicker(
                                          context: context,
                                          initialDate: DateTime.now()
                                              .add(Duration(
                                                  days: 30 * (i + 1))),
                                          firstDate: DateTime.now()
                                              .subtract(const Duration(
                                                  days: 1)),
                                          lastDate: DateTime.now().add(
                                              const Duration(
                                                  days: 1825)),
                                        );
                                        if (picked != null) {
                                          setS(() => fc.text =
                                              "${picked.day.toString().padLeft(2, '0')}/${picked.month.toString().padLeft(2, '0')}/${picked.year}");
                                        }
                                      },
                                      validator: (v) {
                                        if (!usarCuotas) return null;
                                        if (v == null || v.trim().isEmpty)
                                          return "Requerida";
                                        return null;
                                      },
                                    ),
                                  ),
                                ]),
                              );
                            }),
                          ),
                        ),
                        // Resumen suma cuotas
                        Padding(
                          padding:
                              const EdgeInsets.fromLTRB(16, 0, 16, 12),
                          child: Builder(builder: (_) {
                            final sumaCuotas = cuotasCtrl.fold(
                                0.0,
                                (s, par) =>
                                    s +
                                    (double.tryParse(
                                            par[0].text.trim()) ??
                                        0));
                            final total = double.tryParse(
                                    deudaCtrl.text.trim()) ??
                                0;
                            final diff = (total - sumaCuotas).abs();
                            final ok = diff < 0.01;
                            return Container(
                              padding: const EdgeInsets.all(10),
                              decoration: BoxDecoration(
                                color: ok
                                    ? AppColors.statusGreen
                                        .withValues(alpha: 0.08)
                                    : AppColors.statusOrange
                                        .withValues(alpha: 0.08),
                                borderRadius: BorderRadius.circular(8),
                                border: Border.all(
                                    color: ok
                                        ? AppColors.statusGreen
                                        : AppColors.statusOrange,
                                    width: 0.8),
                              ),
                              child: Row(children: [
                                Icon(
                                    ok
                                        ? Icons.check_circle_outline
                                        : Icons.info_outline,
                                    size: 16,
                                    color: ok
                                        ? AppColors.statusGreen
                                        : AppColors.statusOrange),
                                const SizedBox(width: 6),
                                Expanded(
                                  child: Text(
                                    ok
                                        ? "Total cuotas: ${formatCurrency(sumaCuotas)} ✓"
                                        : "Total cuotas: ${formatCurrency(sumaCuotas)}  (diferencia: ${formatCurrency(diff)})",
                                    style: TextStyle(
                                        fontSize: 12,
                                        color: ok
                                            ? AppColors.statusGreen
                                            : AppColors.statusOrange),
                                  ),
                                ),
                              ]),
                            );
                          }),
                        ),
                      ],
                    ]),
                  ),
                  const SizedBox(height: 20),

                  // ── Botón guardar ────────────────────────────
                  SizedBox(
                    width: double.infinity,
                    child: ElevatedButton.icon(
                      icon: guardando
                          ? const SizedBox(
                              width: 18,
                              height: 18,
                              child: CircularProgressIndicator(
                                  strokeWidth: 2, color: Colors.white))
                          : const Icon(Icons.save_outlined),
                      label: const Text("Crear Cuenta"),
                      style: ElevatedButton.styleFrom(
                        backgroundColor: AppColors.royalBlue,
                        padding:
                            const EdgeInsets.symmetric(vertical: 14),
                        shape: RoundedRectangleBorder(
                            borderRadius: BorderRadius.circular(10)),
                      ),
                      onPressed: guardando
                          ? null
                          : () async {
                              if (!formKey.currentState!.validate())
                                return;
                              // Validar suma cuotas vs total si se usan
                              if (usarCuotas) {
                                final sumaCuotas = cuotasCtrl.fold(
                                    0.0,
                                    (s, par) =>
                                        s +
                                        (double.tryParse(
                                                par[0].text.trim()) ??
                                            0));
                                final total = double.tryParse(
                                        deudaCtrl.text.trim()) ??
                                    0;
                                if ((total - sumaCuotas).abs() >= 0.01) {
                                  ScaffoldMessenger.of(context)
                                      .showSnackBar(const SnackBar(
                                    content: Text(
                                        "La suma de cuotas no coincide con el total de la deuda"),
                                    backgroundColor:
                                        AppColors.statusOrange,
                                  ));
                                  return;
                                }
                              }
                              setS(() => guardando = true);
                              try {
                                final cuotas = usarCuotas
                                    ? List.generate(numCuotas, (i) => {
                                          'numero': i + 1,
                                          'monto': double.tryParse(
                                                  cuotasCtrl[i][0]
                                                      .text
                                                      .trim()) ??
                                              0,
                                          'fecha': cuotasCtrl[i][1]
                                              .text
                                              .trim(),
                                          'pagada': false,
                                        })
                                    : <Map<String, dynamic>>[];

                                await _Api.post('cuentas_cobrar', {
                                  'cedula': cedCtrl.text.trim(),
                                  'nombre': nomCtrl.text.trim(),
                                  'telefono': telCtrl.text.trim(),
                                  'correo': corCtrl.text.trim(),
                                  'monto_total':
                                      double.tryParse(
                                              deudaCtrl.text.trim()) ??
                                          0,
                                  'notas': notasCtrl.text.trim(),
                                  'cuotas': cuotas,
                                });
                                if (!mounted) return;
                                Navigator.pop(ctx);
                                await _cargar();
                                if (mounted)
                                  ScaffoldMessenger.of(context)
                                      .showSnackBar(const SnackBar(
                                    content: Text(
                                        "Cuenta por cobrar creada exitosamente"),
                                    backgroundColor: AppColors.statusGreen,
                                  ));
                              } catch (e) {
                                setS(() => guardando = false);
                                if (mounted)
                                  ScaffoldMessenger.of(context)
                                      .showSnackBar(SnackBar(
                                          content: Text("Error: $e"),
                                          backgroundColor:
                                              AppColors.statusRed));
                              }
                            },
                    ),
                  ),
                  const SizedBox(height: 24),
                ],
              ),
            ),
          ),
        ),
      ),
    );
  }
}

class DetalleCuentaCobrar extends StatefulWidget {
  final CuentaPorCobrar cuenta;
  const DetalleCuentaCobrar({super.key, required this.cuenta});
  @override State<DetalleCuentaCobrar> createState() => _DetalleCuentaCobrarState();
}

class _DetalleCuentaCobrarState extends State<DetalleCuentaCobrar> {
  bool get puedeEditar => (usuarioSesion?.rol == "Administrador" || usuarioSesion?.rol == "Maestro" || usuarioSesion?.rol == "Dueño");

  void _registrarPago() {
    final montoController = TextEditingController();
    final tasaController = TextEditingController(text: ConfigSistema.tasaCambio.toStringAsFixed(2));
    String metodo = "Efectivo \$";
    bool guardando = false;
    final formKey = GlobalKey<FormState>();

    showDialog(context: context, builder: (ctx) => StatefulBuilder(
      builder: (context, setS) {
        bool requiereTasa = metodo == "Efectivo Bs" || metodo == "Pago móvil" ||
            metodo == "Transferencia" || metodo == "Punto";
        return AlertDialog(
          title: const Row(children: [
            Icon(Icons.attach_money, color: AppColors.statusGreen),
            SizedBox(width: 8),
            Text("Registrar Pago"),
          ]),
          content: Form(
            key: formKey,
            child: SingleChildScrollView(child: Column(mainAxisSize: MainAxisSize.min, children: [
              // Saldo pendiente
              Container(
                width: double.infinity,
                padding: const EdgeInsets.all(10),
                decoration: BoxDecoration(
                  color: AppColors.statusRed.withValues(alpha: 0.07),
                  borderRadius: BorderRadius.circular(8),
                ),
                child: Row(mainAxisAlignment: MainAxisAlignment.spaceBetween, children: [
                  const Text("Saldo pendiente:", style: TextStyle(fontSize: 13, color: AppColors.textSecondary)),
                  Text(formatCurrency(widget.cuenta.saldoRestante),
                    style: const TextStyle(fontSize: 15, fontWeight: FontWeight.bold, color: AppColors.statusRed)),
                ]),
              ),
              const SizedBox(height: 12),
              DropdownButtonFormField<String>(
                value: metodo,
                items: ConfigSistema.metodossPago.isNotEmpty
                  ? ConfigSistema.metodossPago.map((e) => DropdownMenuItem(value: e, child: Text(e))).toList()
                  : ["Efectivo \$","Efectivo Bs","Pago móvil","Transferencia","Zelle","Punto"]
                      .map((e) => DropdownMenuItem(value: e, child: Text(e))).toList(),
                onChanged: (v) { if (v != null) setS(() => metodo = v); },
                decoration: const InputDecoration(labelText: "Método de pago", prefixIcon: Icon(Icons.payment_outlined)),
              ),
              const SizedBox(height: 10),
              TextFormField(
                controller: montoController,
                keyboardType: const TextInputType.numberWithOptions(decimal: true),
                decoration: InputDecoration(
                  labelText: requiereTasa ? "Monto en Bolívares (Bs)" : "Monto en Dólares \$",
                  prefixIcon: const Icon(Icons.attach_money),
                ),
                validator: (v) {
                  final d = double.tryParse(v?.trim() ?? '');
                  if (d == null || d <= 0) return "Ingrese un monto válido";
                  return null;
                },
              ),
              if (requiereTasa) ...[
                const SizedBox(height: 10),
                TextFormField(
                  controller: tasaController,
                  keyboardType: const TextInputType.numberWithOptions(decimal: true),
                  decoration: const InputDecoration(
                    labelText: "Tasa de cambio (Bs/\$)",
                    prefixIcon: Icon(Icons.currency_exchange),
                  ),
                  validator: (v) {
                    final d = double.tryParse(v?.trim() ?? '');
                    if (d == null || d <= 0) return "Ingrese una tasa válida";
                    return null;
                  },
                ),
              ],
            ])),
          ),
          actions: [
            TextButton(onPressed: () => Navigator.pop(ctx), child: const Text("Cancelar")),
            ElevatedButton.icon(
              icon: guardando
                ? const SizedBox(width: 16, height: 16, child: CircularProgressIndicator(strokeWidth: 2, color: Colors.white))
                : const Icon(Icons.check, size: 18),
              label: const Text("Registrar"),
              style: ElevatedButton.styleFrom(backgroundColor: AppColors.statusGreen),
              onPressed: guardando ? null : () async {
                if (!formKey.currentState!.validate()) return;
                double monto = double.tryParse(montoController.text) ?? 0;
                double montoFinal = monto;
                if (requiereTasa) {
                  final tasa = double.tryParse(tasaController.text) ?? ConfigSistema.tasaCambio;
                  montoFinal = tasa > 0 ? monto / tasa : monto;
                }
                setS(() => guardando = true);
                try {
                  if (widget.cuenta.id == null) throw Exception("Cuenta sin ID. Recargue la pantalla.");
                  final nuevoPago = {
                    'monto': montoFinal,
                    'fecha': obtenerFechaActual(),
                    'metodo': metodo,
                  };
                  // ── Guardar de forma robusta ──────────────────────
                  // 1) Agregamos el pago a la lista local ANTES de enviar
                  // 2) Enviamos: (a) el pago individual bajo 'pago'
                  //    (compatibilidad con el endpoint antiguo), y
                  //    (b) la lista completa de 'pagos' + campos base
                  //    por si el backend rehidrata el registro completo.
                  final pagosActualizados = [
                    ...widget.cuenta.pagos.map((p) => Map<String, dynamic>.from(p)),
                    nuevoPago,
                  ];
                  final payload = <String, dynamic>{
                    ...widget.cuenta.toMap(),
                    'pago': nuevoPago,
                    'pagos': pagosActualizados,
                  };
                  await _Api.put('cuentas_cobrar', widget.cuenta.id.toString(), payload);
                  if (!ctx.mounted) return;
                  setState(() {
                    widget.cuenta.pagos.add(nuevoPago);
                  });
                  Navigator.pop(ctx);
                  if (mounted) ScaffoldMessenger.of(context).showSnackBar(
                    SnackBar(
                      content: Text("Pago de ${formatCurrency(montoFinal)} registrado correctamente"),
                      backgroundColor: AppColors.statusGreen));
                } catch (e) {
                  setS(() => guardando = false);
                  if (ctx.mounted) ScaffoldMessenger.of(context).showSnackBar(
                    SnackBar(content: Text('Error al registrar pago: $e'), backgroundColor: AppColors.statusRed));
                }
              },
            ),
          ],
        );
      },
    ));
  }

  @override
  Widget build(BuildContext context) {
    final cuenta = widget.cuenta;
    final pct = cuenta.montoTotal > 0
        ? (1 - cuenta.saldoRestante / cuenta.montoTotal).clamp(0.0, 1.0)
        : 1.0;
    final saldado = cuenta.saldoRestante <= 0;
    final tieneCuotas = cuenta.cuotas.isNotEmpty;
    final cuotasPendientes = cuenta.cuotas.where((c) => !c.pagada).length;

    return Scaffold(
      appBar: AppBar(title: Text(cuenta.nombre)),
      body: SingleChildScrollView(
        padding: const EdgeInsets.all(16),
        child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
          // Card resumen
          Card(
            shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(14)),
            child: Padding(
              padding: const EdgeInsets.all(16),
              child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                Row(children: [
                  const Icon(Icons.person_outline, color: AppColors.royalBlue),
                  const SizedBox(width: 8),
                  Expanded(child: Text(cuenta.nombre,
                      style: const TextStyle(fontWeight: FontWeight.bold, fontSize: 16))),
                  if (saldado)
                    Container(
                      padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 4),
                      decoration: BoxDecoration(
                          color: AppColors.statusGreen.withValues(alpha: 0.12),
                          borderRadius: BorderRadius.circular(20)),
                      child: const Text("SALDADO",
                          style: TextStyle(fontSize: 11, fontWeight: FontWeight.bold,
                              color: AppColors.statusGreen)),
                    ),
                ]),
                const Divider(height: 20),
                _infoRow(Icons.badge_outlined, "Cédula", cuenta.cedula),
                _infoRow(Icons.phone_outlined, "Teléfono", cuenta.telefono),
                if (cuenta.correo.isNotEmpty)
                  _infoRow(Icons.email_outlined, "Correo", cuenta.correo),
                if (cuenta.notas.isNotEmpty)
                  _infoRow(Icons.notes_outlined, "Notas", cuenta.notas),
                const SizedBox(height: 12),
                // Barra de progreso
                Row(mainAxisAlignment: MainAxisAlignment.spaceBetween, children: [
                  Text("Deuda total: ${formatCurrency(cuenta.montoTotal)}",
                      style: const TextStyle(color: AppColors.textSecondary, fontSize: 13)),
                  Text("${(pct * 100).toStringAsFixed(0)}% pagado",
                      style: const TextStyle(color: AppColors.textSecondary, fontSize: 13)),
                ]),
                const SizedBox(height: 6),
                ClipRRect(
                  borderRadius: BorderRadius.circular(6),
                  child: LinearProgressIndicator(
                    value: pct, minHeight: 10,
                    backgroundColor: Colors.grey[200],
                    valueColor: AlwaysStoppedAnimation<Color>(
                        saldado ? AppColors.statusGreen : AppColors.statusRed),
                  ),
                ),
                const SizedBox(height: 12),
                Container(
                  width: double.infinity,
                  padding: const EdgeInsets.all(12),
                  decoration: BoxDecoration(
                    color: (saldado ? AppColors.statusGreen : AppColors.statusRed)
                        .withValues(alpha: 0.08),
                    borderRadius: BorderRadius.circular(10),
                  ),
                  child: Row(mainAxisAlignment: MainAxisAlignment.spaceBetween, children: [
                    Text("SALDO RESTANTE",
                        style: TextStyle(
                            color: saldado ? AppColors.statusGreen : AppColors.statusRed,
                            fontWeight: FontWeight.w600, fontSize: 12, letterSpacing: 0.5)),
                    Text(formatCurrency(cuenta.saldoRestante),
                        style: TextStyle(
                            color: saldado ? AppColors.statusGreen : AppColors.statusRed,
                            fontWeight: FontWeight.bold, fontSize: 22)),
                  ]),
                ),
              ]),
            ),
          ),
          const SizedBox(height: 16),

          // ── CUOTAS ──────────────────────────────────────────
          if (tieneCuotas) ...[
            Row(children: [
              const Text("Plan de Cuotas",
                  style: TextStyle(fontSize: 16, fontWeight: FontWeight.bold)),
              const SizedBox(width: 8),
              Container(
                padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 2),
                decoration: BoxDecoration(
                    color: AppColors.primaryBlue.withValues(alpha: 0.1),
                    borderRadius: BorderRadius.circular(10)),
                child: Text(
                    "$cuotasPendientes pendiente${cuotasPendientes != 1 ? 's' : ''}",
                    style: const TextStyle(
                        fontSize: 11, color: AppColors.primaryBlue,
                        fontWeight: FontWeight.w600)),
              ),
            ]),
            const SizedBox(height: 8),
            ...cuenta.cuotas.map((cuota) {
              final vencimiento = cuota.fecha;
              return Card(
                margin: const EdgeInsets.only(bottom: 8),
                shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
                elevation: 1,
                child: ListTile(
                  contentPadding:
                      const EdgeInsets.symmetric(horizontal: 14, vertical: 6),
                  leading: Container(
                    width: 36,
                    height: 36,
                    decoration: BoxDecoration(
                      color: cuota.pagada
                          ? AppColors.statusGreen.withValues(alpha: 0.12)
                          : AppColors.statusOrange.withValues(alpha: 0.12),
                      shape: BoxShape.circle,
                    ),
                    child: Center(
                        child: Text("${cuota.numero}",
                            style: TextStyle(
                                fontWeight: FontWeight.bold,
                                color: cuota.pagada
                                    ? AppColors.statusGreen
                                    : AppColors.statusOrange))),
                  ),
                  title: Row(children: [
                    Text(formatCurrency(cuota.monto),
                        style: TextStyle(
                            fontWeight: FontWeight.bold,
                            fontSize: 15,
                            color: cuota.pagada
                                ? AppColors.statusGreen
                                : AppColors.textPrimary)),
                    const Spacer(),
                    if (cuota.pagada)
                      Container(
                        padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 2),
                        decoration: BoxDecoration(
                            color: AppColors.statusGreen.withValues(alpha: 0.1),
                            borderRadius: BorderRadius.circular(8)),
                        child: const Text("Pagada",
                            style: TextStyle(fontSize: 11,
                                color: AppColors.statusGreen,
                                fontWeight: FontWeight.w600)),
                      )
                    else if (puedeEditar)
                      TextButton.icon(
                        icon: const Icon(Icons.check_circle_outline, size: 16),
                        label: const Text("Pagar", style: TextStyle(fontSize: 12)),
                        style: TextButton.styleFrom(
                          foregroundColor: AppColors.statusGreen,
                          padding: const EdgeInsets.symmetric(
                              horizontal: 8, vertical: 4),
                          minimumSize: Size.zero,
                          tapTargetSize: MaterialTapTargetSize.shrinkWrap,
                        ),
                        onPressed: () => _pagarCuota(cuota),
                      ),
                  ]),
                  subtitle: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      Row(children: [
                        Icon(Icons.event_outlined, size: 12,
                            color: AppColors.textSecondary),
                        const SizedBox(width: 4),
                        Text("Vence: $vencimiento",
                            style: const TextStyle(
                                fontSize: 11, color: AppColors.textSecondary)),
                      ]),
                      if (cuota.pagada && cuota.fechaPago != null)
                        Row(children: [
                          const Icon(Icons.check_outlined, size: 12,
                              color: AppColors.statusGreen),
                          const SizedBox(width: 4),
                          Text("Pagada el: ${cuota.fechaPago}",
                              style: const TextStyle(
                                  fontSize: 11, color: AppColors.statusGreen)),
                        ]),
                    ],
                  ),
                ),
              );
            }),
            const SizedBox(height: 16),
          ],

          // ── Historial de pagos libres ─────────────────────
          const Text("Historial de Pagos",
              style: TextStyle(fontSize: 16, fontWeight: FontWeight.bold)),
          const SizedBox(height: 8),
          if (cuenta.pagos.isEmpty && !tieneCuotas)
            const EmptyState(
                mensaje: "Sin pagos registrados aún.",
                icono: Icons.payment_outlined)
          else if (cuenta.pagos.isEmpty)
            Padding(
              padding: const EdgeInsets.symmetric(vertical: 8),
              child: Text("Sin abonos adicionales registrados.",
                  style: TextStyle(
                      fontSize: 13, color: AppColors.textSecondary)),
            )
          else
            ...cuenta.pagos.map((pago) => Card(
                  margin: const EdgeInsets.only(bottom: 6),
                  shape: RoundedRectangleBorder(
                      borderRadius: BorderRadius.circular(10)),
                  elevation: 1,
                  child: ListTile(
                    leading: const CircleAvatar(
                        backgroundColor: Color(0xFFE8F5E9),
                        child: Icon(Icons.payment_outlined,
                            color: AppColors.statusGreen, size: 20)),
                    title: Text(
                        formatCurrency(
                            double.tryParse(pago['monto'].toString()) ?? 0),
                        style: const TextStyle(
                            fontWeight: FontWeight.bold,
                            color: AppColors.statusGreen)),
                    subtitle: Text(
                        "${pago['metodo']} · ${pago['fecha']}",
                        style: const TextStyle(
                            fontSize: 12, color: AppColors.textSecondary)),
                  ),
                )),
          const SizedBox(height: 80),
        ]),
      ),
      floatingActionButton: puedeEditar && !saldado
          ? FloatingActionButton.extended(
              onPressed: _registrarPago,
              icon: const Icon(Icons.attach_money),
              label: const Text("Registrar Pago"),
            )
          : null,
    );
  }

  /// Marca una cuota individual como pagada
  void _pagarCuota(CuotaCobrar cuota) {
    if (widget.cuenta.id == null) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text("Error: cuenta sin ID. Recargue la pantalla."),
          backgroundColor: AppColors.statusRed));
      return;
    }
    showDialog(
      context: context,
      builder: (ctx) => AlertDialog(
        title: Row(children: [
          const Icon(Icons.check_circle_outline, color: AppColors.statusGreen),
          const SizedBox(width: 8),
          Text("Pagar Cuota ${cuota.numero}"),
        ]),
        content: Column(mainAxisSize: MainAxisSize.min, children: [
          ListTile(
            contentPadding: EdgeInsets.zero,
            leading: const Icon(Icons.attach_money, color: AppColors.statusGreen),
            title: Text("Monto: ${formatCurrency(cuota.monto)}",
                style: const TextStyle(fontWeight: FontWeight.bold)),
            subtitle: Text("Vencimiento: ${cuota.fecha}"),
          ),
          const Text("¿Confirma que esta cuota fue pagada hoy?"),
        ]),
        actions: [
          TextButton(onPressed: () => Navigator.pop(ctx), child: const Text("Cancelar")),
          ElevatedButton.icon(
            icon: const Icon(Icons.check, size: 16),
            label: const Text("Confirmar pago"),
            style: ElevatedButton.styleFrom(backgroundColor: AppColors.statusGreen),
            onPressed: () async {
              Navigator.pop(ctx);
              try {
                final fechaHoy = obtenerFechaActual();
                await _Api.put('cuentas_cobrar', widget.cuenta.id.toString(), {
                  'cuota_pagada': {
                    'numero': cuota.numero,
                    'fecha_pago': fechaHoy,
                  }
                });
                if (!mounted) return;
                setState(() {
                  cuota.pagada = true;
                  cuota.fechaPago = fechaHoy;
                });
                ScaffoldMessenger.of(context).showSnackBar(SnackBar(
                  content: Text(
                      "Cuota ${cuota.numero} marcada como pagada (${formatCurrency(cuota.monto)})"),
                  backgroundColor: AppColors.statusGreen));
              } catch (e) {
                if (mounted) ScaffoldMessenger.of(context).showSnackBar(SnackBar(
                    content: Text("Error al registrar pago de cuota: $e"),
                    backgroundColor: AppColors.statusRed));
              }
            },
          ),
        ],
      ),
    );
  }

  Widget _infoRow(IconData icon, String label, String value) => Padding(
    padding: const EdgeInsets.symmetric(vertical: 3),
    child: Row(children: [
      Icon(icon, size: 16, color: AppColors.textSecondary),
      const SizedBox(width: 6),
      Text("$label: ", style: const TextStyle(color: AppColors.textSecondary, fontSize: 13)),
      Text(value, style: const TextStyle(fontWeight: FontWeight.w500, fontSize: 13)),
    ]),
  );
}

// ============================================================
//  CUENTAS POR PAGAR — carga desde la API
// ============================================================
class VentanaCuentasPorPagar extends StatefulWidget {
  const VentanaCuentasPorPagar({super.key});
  @override State<VentanaCuentasPorPagar> createState() => _VentanaCuentasPorPagarState();
}

class _VentanaCuentasPorPagarState extends State<VentanaCuentasPorPagar> {
  List<CuentaPorPagar> _cuentas = [];
  bool _cargando = true;
  String _query = '';
  bool get puedeEditar => (usuarioSesion?.rol == "Administrador" || usuarioSesion?.rol == "Maestro" || usuarioSesion?.rol == "Dueño");

  @override
  void initState() { super.initState(); _cargar(); }

  Future<void> _cargar() async {
    setState(() => _cargando = true);
    try {
      final raw = await _Api.get('cuentas_pagar');
      _cuentas = ((raw as List?) ?? []).map((m) => CuentaPorPagar.fromMap(m)).toList();
      _cuentas.sort((a, b) => b.saldoRestante.compareTo(a.saldoRestante));
      cuentasPorPagarGlobal = _cuentas;
    } catch (e) {
      debugPrint('[_cargar] Error: $e');
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Error al cargar datos: $e'), backgroundColor: AppColors.statusRed, duration: const Duration(seconds: 4)));
    } finally {
      if (mounted) setState(() => _cargando = false);
    }
  }

  List<CuentaPorPagar> get _filtradas => _cuentas.where((c) =>
    _query.isEmpty ||
    c.nombre.toLowerCase().contains(_query.toLowerCase()) ||
    c.rif.contains(_query)).toList();

  void _crearCuenta() {
    final rifCtrl   = TextEditingController();
    final nomCtrl   = TextEditingController();
    final telCtrl   = TextEditingController();
    final corCtrl   = TextEditingController();
    final deudaCtrl = TextEditingController();
    final notasCtrl = TextEditingController();
    final formKey   = GlobalKey<FormState>();
    bool guardando  = false;
    bool usarCuotas = false;
    int  numCuotas  = 1;
    List<List<TextEditingController>> cuotasCtrl = [
      [TextEditingController(), TextEditingController()],
    ];

    late void Function(void Function(void Function()), int) actualizarCuotas;
    actualizarCuotas = (setS, nuevaCant) {
      setS(() {
        numCuotas = nuevaCant.clamp(1, 60);
        while (cuotasCtrl.length < numCuotas) {
          cuotasCtrl.add([TextEditingController(), TextEditingController()]);
        }
        while (cuotasCtrl.length > numCuotas) {
          for (final c in cuotasCtrl.last) c.dispose();
          cuotasCtrl.removeLast();
        }
        final total = double.tryParse(deudaCtrl.text.trim()) ?? 0;
        if (total > 0) {
          final porCuota = (total / numCuotas).toStringAsFixed(2);
          for (final par in cuotasCtrl) par[0].text = porCuota;
        }
      });
    };

    showModalBottomSheet(
      context: context,
      isScrollControlled: true,
      shape: const RoundedRectangleBorder(
          borderRadius: BorderRadius.vertical(top: Radius.circular(20))),
      builder: (ctx) => StatefulBuilder(
        builder: (context, setS) => DraggableScrollableSheet(
          initialChildSize: 0.92,
          minChildSize: 0.5,
          maxChildSize: 0.97,
          expand: false,
          builder: (_, scrollCtrl) => Padding(
            padding: EdgeInsets.only(
                bottom: MediaQuery.of(ctx).viewInsets.bottom,
                left: 24, right: 24, top: 20),
            child: Form(
              key: formKey,
              child: ListView(
                controller: scrollCtrl,
                children: [
                  Row(children: [
                    const Icon(Icons.request_quote_outlined, color: AppColors.royalBlue),
                    const SizedBox(width: 8),
                    const Text("Nueva Cuenta por Pagar",
                        style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold)),
                    const Spacer(),
                    IconButton(icon: const Icon(Icons.close), onPressed: () => Navigator.pop(ctx)),
                  ]),
                  const Divider(),
                  const SizedBox(height: 8),
                  const Text("Datos del proveedor / acreedor",
                      style: TextStyle(fontWeight: FontWeight.w600, color: AppColors.royalBlue, fontSize: 13)),
                  const SizedBox(height: 10),
                  TextFormField(
                    controller: rifCtrl,
                    textCapitalization: TextCapitalization.characters,
                    textInputAction: TextInputAction.next,
                    decoration: const InputDecoration(labelText: "RIF / Documento *", prefixIcon: Icon(Icons.receipt_outlined)),
                    validator: (v) => (v?.trim().isEmpty ?? true) ? "El RIF es obligatorio" : null,
                  ),
                  const SizedBox(height: 10),
                  TextFormField(
                    controller: nomCtrl,
                    textCapitalization: TextCapitalization.words,
                    textInputAction: TextInputAction.next,
                    decoration: const InputDecoration(labelText: "Proveedor / Nombre *", prefixIcon: Icon(Icons.business_outlined)),
                    validator: (v) => (v?.trim().isEmpty ?? true) ? "El nombre es obligatorio" : null,
                  ),
                  const SizedBox(height: 10),
                  Row(children: [
                    Expanded(child: TextFormField(
                      controller: telCtrl,
                      keyboardType: TextInputType.phone,
                      textInputAction: TextInputAction.next,
                      decoration: const InputDecoration(labelText: "Teléfono", prefixIcon: Icon(Icons.phone_outlined)),
                    )),
                    const SizedBox(width: 10),
                    Expanded(child: TextFormField(
                      controller: corCtrl,
                      keyboardType: TextInputType.emailAddress,
                      textInputAction: TextInputAction.next,
                      decoration: const InputDecoration(labelText: "Correo", prefixIcon: Icon(Icons.email_outlined)),
                    )),
                  ]),
                  const SizedBox(height: 10),
                  TextFormField(
                    controller: deudaCtrl,
                    keyboardType: const TextInputType.numberWithOptions(decimal: true),
                    textInputAction: TextInputAction.next,
                    decoration: const InputDecoration(
                        labelText: "Monto total *",
                        prefixIcon: Icon(Icons.attach_money),
                        ),
                    onChanged: (_) { if (usarCuotas) actualizarCuotas(setS, numCuotas); },
                    validator: (v) {
                      final d = double.tryParse(v?.trim() ?? '');
                      return (d == null || d <= 0) ? "Ingrese un monto válido mayor a 0" : null;
                    },
                  ),
                  const SizedBox(height: 10),
                  TextFormField(
                    controller: notasCtrl,
                    maxLines: 2,
                    textInputAction: TextInputAction.done,
                    decoration: const InputDecoration(labelText: "Notas / concepto", prefixIcon: Icon(Icons.notes_outlined)),
                  ),
                  const SizedBox(height: 18),
                  // ── Sección Cuotas ──────────────────────────
                  Container(
                    decoration: BoxDecoration(
                      color: AppColors.surfaceGrey,
                      borderRadius: BorderRadius.circular(12),
                      border: Border.all(color: AppColors.cardBorder),
                    ),
                    child: Column(children: [
                      SwitchListTile(
                        value: usarCuotas,
                        onChanged: (v) => setS(() => usarCuotas = v),
                        title: const Text("Dividir en cuotas", style: TextStyle(fontWeight: FontWeight.w600)),
                        subtitle: const Text("Define número, fecha y monto de cada cuota", style: TextStyle(fontSize: 11)),
                        secondary: const Icon(Icons.calendar_month_outlined, color: AppColors.royalBlue),
                        activeColor: AppColors.royalBlue,
                      ),
                      if (usarCuotas) ...[
                        const Divider(height: 1),
                        Padding(
                          padding: const EdgeInsets.fromLTRB(16, 12, 16, 4),
                          child: Row(children: [
                            const Text("Número de cuotas:", style: TextStyle(fontWeight: FontWeight.w500)),
                            const Spacer(),
                            IconButton(
                              icon: const Icon(Icons.remove_circle_outline, color: AppColors.statusRed),
                              onPressed: () => actualizarCuotas(setS, numCuotas - 1),
                            ),
                            Container(width: 40, alignment: Alignment.center,
                              child: Text("$numCuotas", style: const TextStyle(fontSize: 20, fontWeight: FontWeight.bold))),
                            IconButton(
                              icon: const Icon(Icons.add_circle_outline, color: AppColors.statusGreen),
                              onPressed: () => actualizarCuotas(setS, numCuotas + 1),
                            ),
                          ]),
                        ),
                        Padding(
                          padding: const EdgeInsets.fromLTRB(16, 0, 16, 16),
                          child: Column(
                            children: List.generate(numCuotas, (i) {
                              final mc = cuotasCtrl[i][0];
                              final fc = cuotasCtrl[i][1];
                              return Padding(
                                padding: const EdgeInsets.only(bottom: 10),
                                child: Row(children: [
                                  Container(
                                    width: 28, height: 28,
                                    decoration: const BoxDecoration(color: AppColors.royalBlue, shape: BoxShape.circle),
                                    child: Center(child: Text("${i + 1}",
                                        style: const TextStyle(color: Colors.white, fontSize: 12, fontWeight: FontWeight.bold))),
                                  ),
                                  const SizedBox(width: 8),
                                  Expanded(flex: 2, child: TextFormField(
                                    controller: mc,
                                    keyboardType: const TextInputType.numberWithOptions(decimal: true),
                                    decoration: InputDecoration(
                                        labelText: "Monto", isDense: true, 
                                        border: OutlineInputBorder(borderRadius: BorderRadius.circular(8))),
                                    validator: (v) {
                                      if (!usarCuotas) return null;
                                      final d = double.tryParse(v?.trim() ?? '');
                                      return (d == null || d <= 0) ? "Requerido" : null;
                                    },
                                  )),
                                  const SizedBox(width: 8),
                                  Expanded(flex: 3, child: TextFormField(
                                    controller: fc,
                                    readOnly: true,
                                    decoration: InputDecoration(
                                        labelText: "Fecha venc.", isDense: true,
                                        prefixIcon: const Icon(Icons.event_outlined, size: 16),
                                        border: OutlineInputBorder(borderRadius: BorderRadius.circular(8))),
                                    onTap: () async {
                                      final picked = await showDatePicker(
                                        context: context,
                                        initialDate: DateTime.now().add(Duration(days: 30 * (i + 1))),
                                        firstDate: DateTime.now().subtract(const Duration(days: 1)),
                                        lastDate: DateTime.now().add(const Duration(days: 1825)),
                                      );
                                      if (picked != null) {
                                        setS(() => fc.text =
                                            "${picked.day.toString().padLeft(2, '0')}/${picked.month.toString().padLeft(2, '0')}/${picked.year}");
                                      }
                                    },
                                    validator: (v) {
                                      if (!usarCuotas) return null;
                                      return (v == null || v.trim().isEmpty) ? "Requerida" : null;
                                    },
                                  )),
                                ]),
                              );
                            }),
                          ),
                        ),
                        // Resumen suma
                        Padding(
                          padding: const EdgeInsets.fromLTRB(16, 0, 16, 12),
                          child: Builder(builder: (_) {
                            final suma = cuotasCtrl.fold(0.0, (s, p) => s + (double.tryParse(p[0].text.trim()) ?? 0));
                            final total = double.tryParse(deudaCtrl.text.trim()) ?? 0;
                            final ok = (total - suma).abs() < 0.01;
                            return Container(
                              padding: const EdgeInsets.all(10),
                              decoration: BoxDecoration(
                                color: (ok ? AppColors.statusGreen : AppColors.statusOrange).withValues(alpha: 0.08),
                                borderRadius: BorderRadius.circular(8),
                                border: Border.all(color: ok ? AppColors.statusGreen : AppColors.statusOrange, width: 0.8),
                              ),
                              child: Row(children: [
                                Icon(ok ? Icons.check_circle_outline : Icons.info_outline,
                                    size: 16, color: ok ? AppColors.statusGreen : AppColors.statusOrange),
                                const SizedBox(width: 6),
                                Expanded(child: Text(
                                  ok ? "Total cuotas: ${formatCurrency(suma)} ✓"
                                      : "Total cuotas: ${formatCurrency(suma)}  (diferencia: ${formatCurrency((total - suma).abs())})",
                                  style: TextStyle(fontSize: 12, color: ok ? AppColors.statusGreen : AppColors.statusOrange),
                                )),
                              ]),
                            );
                          }),
                        ),
                      ],
                    ]),
                  ),
                  const SizedBox(height: 20),
                  SizedBox(
                    width: double.infinity,
                    child: ElevatedButton.icon(
                      icon: guardando
                          ? const SizedBox(width: 18, height: 18, child: CircularProgressIndicator(strokeWidth: 2, color: Colors.white))
                          : const Icon(Icons.save_outlined),
                      label: const Text("Crear Cuenta"),
                      style: ElevatedButton.styleFrom(
                          backgroundColor: AppColors.royalBlue,
                          padding: const EdgeInsets.symmetric(vertical: 14),
                          shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10))),
                      onPressed: guardando ? null : () async {
                        if (!formKey.currentState!.validate()) return;
                        if (usarCuotas) {
                          final suma = cuotasCtrl.fold(0.0, (s, p) => s + (double.tryParse(p[0].text.trim()) ?? 0));
                          final total = double.tryParse(deudaCtrl.text.trim()) ?? 0;
                          if ((total - suma).abs() >= 0.01) {
                            ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
                              content: Text("La suma de cuotas no coincide con el total"),
                              backgroundColor: AppColors.statusOrange));
                            return;
                          }
                        }
                        setS(() => guardando = true);
                        try {
                          final cuotas = usarCuotas
                              ? List.generate(numCuotas, (i) => {
                                    'numero': i + 1,
                                    'monto': double.tryParse(cuotasCtrl[i][0].text.trim()) ?? 0,
                                    'fecha': cuotasCtrl[i][1].text.trim(),
                                    'pagada': false,
                                  })
                              : <Map<String, dynamic>>[];
                          await _Api.post('cuentas_pagar', {
                            'rif': rifCtrl.text.trim(),
                            'nombre': nomCtrl.text.trim(),
                            'telefono': telCtrl.text.trim(),
                            'correo': corCtrl.text.trim(),
                            'monto_total': double.tryParse(deudaCtrl.text.trim()) ?? 0,
                            'notas': notasCtrl.text.trim(),
                            'cuotas': cuotas,
                          });
                          if (!mounted) return;
                          Navigator.pop(ctx);
                          await _cargar();
                          if (mounted) ScaffoldMessenger.of(context).showSnackBar(
                              const SnackBar(content: Text("Cuenta por pagar creada exitosamente"), backgroundColor: AppColors.statusGreen));
                        } catch (e) {
                          setS(() => guardando = false);
                          if (mounted) ScaffoldMessenger.of(context).showSnackBar(
                              SnackBar(content: Text("Error: $e"), backgroundColor: AppColors.statusRed));
                        }
                      },
                    ),
                  ),
                  const SizedBox(height: 24),
                ],
              ),
            ),
          ),
        ),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    final filtradas = _filtradas;
    final totalPendiente = filtradas.fold(0.0, (s, c) => s + c.saldoRestante);
    return Scaffold(
      appBar: AppBar(
        title: const Text("Cuentas por Pagar"),
        actions: [IconButton(icon: const Icon(Icons.refresh), tooltip: "Actualizar", onPressed: _cargar)],
      ),
      body: Column(children: [
        Container(
          width: double.infinity,
          padding: const EdgeInsets.symmetric(horizontal: 20, vertical: 14),
          color: AppColors.statusRed,
          child: Row(children: [
            Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
              const Text("TOTAL POR PAGAR", style: TextStyle(color: Colors.white70, fontSize: 11, letterSpacing: 1)),
              Text(formatCurrency(totalPendiente),
                style: const TextStyle(color: Colors.white, fontSize: 28, fontWeight: FontWeight.bold)),
            ]),
            const Spacer(),
            Column(crossAxisAlignment: CrossAxisAlignment.end, children: [
              const Text("Cuentas", style: TextStyle(color: Colors.white70, fontSize: 11)),
              Text("${filtradas.length}", style: const TextStyle(color: Colors.white, fontSize: 22, fontWeight: FontWeight.bold)),
            ]),
          ]),
        ),
        Padding(
          padding: const EdgeInsets.all(12),
          child: TextField(
            decoration: InputDecoration(
              hintText: "Buscar por nombre o RIF...",
              prefixIcon: const Icon(Icons.search, color: AppColors.primaryBlue),
              filled: true, fillColor: Colors.white,
              border: OutlineInputBorder(borderRadius: BorderRadius.circular(12), borderSide: BorderSide.none),
              contentPadding: const EdgeInsets.symmetric(vertical: 0, horizontal: 16),
            ),
            onChanged: (v) => setState(() => _query = v),
          ),
        ),
        if (_cargando)
          const Expanded(child: Center(child: CircularProgressIndicator()))
        else if (filtradas.isEmpty)
          const Expanded(child: EmptyState(mensaje: "No hay cuentas por pagar.", icono: Icons.request_quote_outlined))
        else
          Expanded(child: RefreshIndicator(
            onRefresh: _cargar,
            child: ListView.builder(
              padding: const EdgeInsets.symmetric(horizontal: 12),
              itemCount: filtradas.length,
              itemBuilder: (c, i) {
                final cuenta = filtradas[i];
                final pct = cuenta.montoTotal > 0
                    ? (1 - cuenta.saldoRestante / cuenta.montoTotal).clamp(0.0, 1.0)
                    : 1.0;
                final saldado = cuenta.saldoRestante <= 0;
                return Card(
                  margin: const EdgeInsets.only(bottom: 8),
                  shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(12)),
                  elevation: 1,
                  child: InkWell(
                    borderRadius: BorderRadius.circular(12),
                    onTap: () => Navigator.push(context,
                      MaterialPageRoute(builder: (_) => DetalleCuentaPorPagar(cuenta: cuenta)))
                      .then((_) => _cargar()),
                    child: Padding(
                      padding: const EdgeInsets.all(14),
                      child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                        Row(children: [
                          CircleAvatar(
                            radius: 20,
                            backgroundColor: (saldado ? AppColors.statusGreen : AppColors.statusRed).withValues(alpha: 0.12),
                            child: Icon(Icons.business_outlined, size: 18,
                              color: saldado ? AppColors.statusGreen : AppColors.statusRed),
                          ),
                          const SizedBox(width: 10),
                          Expanded(child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                            Text(cuenta.nombre, style: const TextStyle(fontWeight: FontWeight.w600)),
                            Text("RIF: ${cuenta.rif}", style: const TextStyle(fontSize: 12, color: AppColors.textSecondary)),
                          ])),
                          Column(crossAxisAlignment: CrossAxisAlignment.end, children: [
                            Text(formatCurrency(cuenta.saldoRestante),
                              style: TextStyle(fontWeight: FontWeight.bold, fontSize: 16,
                                color: saldado ? AppColors.statusGreen : AppColors.statusRed)),
                            Text("de ${formatCurrency(cuenta.montoTotal)}",
                              style: const TextStyle(fontSize: 11, color: AppColors.textSecondary)),
                          ]),
                        ]),
                        const SizedBox(height: 10),
                        ClipRRect(
                          borderRadius: BorderRadius.circular(4),
                          child: LinearProgressIndicator(
                            value: pct, minHeight: 5,
                            backgroundColor: Colors.grey[200],
                            valueColor: AlwaysStoppedAnimation<Color>(
                              saldado ? AppColors.statusGreen : (pct > 0.5 ? AppColors.statusOrange : AppColors.statusRed)),
                          ),
                        ),
                        const SizedBox(height: 4),
                        Row(children: [
                          Text("${(pct * 100).toStringAsFixed(0)}% pagado",
                            style: const TextStyle(fontSize: 11, color: AppColors.textSecondary)),
                          const Spacer(),
                          if (cuenta.proximaCuota != null)
                            Container(
                              padding: const EdgeInsets.symmetric(horizontal: 7, vertical: 2),
                              decoration: BoxDecoration(
                                color: AppColors.statusOrange.withValues(alpha: 0.1),
                                borderRadius: BorderRadius.circular(8),
                                border: Border.all(color: AppColors.statusOrange.withValues(alpha: 0.4), width: 0.7),
                              ),
                              child: Row(mainAxisSize: MainAxisSize.min, children: [
                                const Icon(Icons.event_outlined, size: 11, color: AppColors.statusOrange),
                                const SizedBox(width: 3),
                                Text(
                                  "Cuota ${cuenta.proximaCuota!.numero}: ${formatCurrency(cuenta.proximaCuota!.monto)} · ${cuenta.proximaCuota!.fecha}",
                                  style: const TextStyle(fontSize: 10, color: AppColors.statusOrange),
                                ),
                              ]),
                            )
                          else if (cuenta.cuotas.isNotEmpty && saldado)
                            const Text("Todas las cuotas pagadas ✓",
                              style: TextStyle(fontSize: 11, color: AppColors.statusGreen)),
                        ]),
                      ]),
                    ),
                  ),
                );
              },
            ),
          )),
      ]),
      floatingActionButton: puedeEditar
          ? FloatingActionButton.extended(
              onPressed: _crearCuenta,
              icon: const Icon(Icons.add),
              label: const Text("Nueva Cuenta"),
            )
          : null,
    );
  }
}

class DetalleCuentaPorPagar extends StatefulWidget {
  final CuentaPorPagar cuenta;
  const DetalleCuentaPorPagar({super.key, required this.cuenta});
  @override State<DetalleCuentaPorPagar> createState() => _DetalleCuentaPorPagarState();
}

class _DetalleCuentaPorPagarState extends State<DetalleCuentaPorPagar> {
  bool get puedeEditar => (usuarioSesion?.rol == "Administrador" || usuarioSesion?.rol == "Maestro" || usuarioSesion?.rol == "Dueño");

  void _registrarPago() {
    final montoController = TextEditingController();
    final tasaController = TextEditingController(
      text: ConfigSistema.tasaCambio.toStringAsFixed(2));
    String metodo = "Efectivo \$";
    final formKey = GlobalKey<FormState>();

    showModalBottomSheet(
      context: context,
      isScrollControlled: true,
      shape: const RoundedRectangleBorder(borderRadius: BorderRadius.vertical(top: Radius.circular(20))),
      builder: (c) => StatefulBuilder(
        builder: (ctx, setLocal) {
          final requiereTasa = metodo == "Efectivo Bs" || metodo == "Pago móvil" ||
              metodo == "Transferencia" || metodo == "Punto";
          return Padding(
            padding: EdgeInsets.only(
              bottom: MediaQuery.of(ctx).viewInsets.bottom,
              left: 24, right: 24, top: 24),
            child: Form(key: formKey, child: Column(mainAxisSize: MainAxisSize.min, children: [
              const Text("Registrar Pago", style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold)),
              const SizedBox(height: 16),
              DropdownButtonFormField<String>(
                value: metodo,
                decoration: const InputDecoration(labelText: "Método de pago", prefixIcon: Icon(Icons.payment_outlined)),
                items: ConfigSistema.metodossPago
                    .map((e) => DropdownMenuItem(value: e, child: Text(e))).toList(),
                onChanged: (v) => setLocal(() => metodo = v!),
              ),
              const SizedBox(height: 12),
              TextFormField(
                controller: montoController,
                keyboardType: const TextInputType.numberWithOptions(decimal: true),
                decoration: InputDecoration(
                  labelText: requiereTasa ? "Monto en Bolívares (Bs)" : "Monto en Dólares (\$)",
                  prefixIcon: const Icon(Icons.attach_money)),
                validator: (v) {
                  final d = double.tryParse(v?.trim() ?? '');
                  return (d == null || d <= 0) ? "Ingrese un monto válido" : null;
                },
              ),
              if (requiereTasa) ...[
                const SizedBox(height: 12),
                TextFormField(
                  controller: tasaController,
                  keyboardType: const TextInputType.numberWithOptions(decimal: true),
                  decoration: const InputDecoration(
                    labelText: "Tasa de cambio (Bs/\$)",
                    prefixIcon: Icon(Icons.currency_exchange),
                    helperText: "Tasa BCV cargada automáticamente"),
                  validator: (v) {
                    final d = double.tryParse(v?.trim() ?? '');
                    return (d == null || d <= 0) ? "Ingrese una tasa válida" : null;
                  },
                ),
              ],
              const SizedBox(height: 20),
              SizedBox(width: double.infinity, child: ElevatedButton(
                onPressed: () async {
                  if (!formKey.currentState!.validate()) return;
                  // Tolerar coma decimal (formato venezolano)
                  final montoRaw = double.tryParse(
                    montoController.text.trim().replaceAll(',', '.')) ?? 0;
                  final tasaNum = double.tryParse(
                    tasaController.text.trim().replaceAll(',', '.')) ?? 0;
                  if (montoRaw <= 0) {
                    ScaffoldMessenger.of(context).showSnackBar(
                      const SnackBar(content: Text('Monto inválido'),
                        backgroundColor: AppColors.statusRed));
                    return;
                  }
                  if (requiereTasa && tasaNum <= 0) {
                    ScaffoldMessenger.of(context).showSnackBar(
                      const SnackBar(content: Text('Tasa inválida'),
                        backgroundColor: AppColors.statusRed));
                    return;
                  }
                  double montoFinal = requiereTasa
                    ? montoRaw / tasaNum
                    : montoRaw;
                  try {
                    if (widget.cuenta.id == null) throw Exception('Cuenta sin ID');
                    final nuevoPago = {
                      'monto': montoFinal,
                      'fecha': obtenerFechaActual(),
                      'metodo': metodo,
                    };
                    // Enviamos estado completo para garantizar persistencia
                    final pagosActualizados = [
                      ...widget.cuenta.pagos.map((p) => Map<String, dynamic>.from(p)),
                      nuevoPago,
                    ];
                    final payload = <String, dynamic>{
                      ...widget.cuenta.toMap(),
                      'pago': nuevoPago,
                      'pagos': pagosActualizados,
                    };
                    await _Api.put('cuentas_pagar', widget.cuenta.id!.toString(), payload);
                    if (!mounted) return;
                    setState(() {
                      widget.cuenta.pagos.add(nuevoPago);
                    });
                    Navigator.pop(ctx);
                    ScaffoldMessenger.of(context).showSnackBar(
                      SnackBar(content: Text("Pago de ${formatCurrency(montoFinal)} registrado"),
                        backgroundColor: AppColors.statusGreen));
                  } catch (e) {
                    if (!mounted) return;
                    ScaffoldMessenger.of(context).showSnackBar(SnackBar(content: Text("Error: $e")));
                  }
                },
                child: const Text("Registrar Pago"),
              )),
              const SizedBox(height: 16),
            ])),
          );
        },
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    final cuenta = widget.cuenta;
    final pct = cuenta.montoTotal > 0
        ? (1 - cuenta.saldoRestante / cuenta.montoTotal).clamp(0.0, 1.0)
        : 1.0;
    final saldado = cuenta.saldoRestante <= 0;
    final tieneCuotas = cuenta.cuotas.isNotEmpty;
    final cuotasPendientes = cuenta.cuotas.where((c) => !c.pagada).length;
    return Scaffold(
      appBar: AppBar(title: Text(cuenta.nombre)),
      body: SingleChildScrollView(
        padding: const EdgeInsets.all(16),
        child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
          Card(
            shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(14)),
            child: Padding(
              padding: const EdgeInsets.all(16),
              child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                Row(children: [
                  const Icon(Icons.business_outlined, color: AppColors.royalBlue),
                  const SizedBox(width: 8),
                  Expanded(child: Text(cuenta.nombre,
                      style: const TextStyle(fontWeight: FontWeight.bold, fontSize: 16))),
                  if (saldado)
                    Container(
                      padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 4),
                      decoration: BoxDecoration(color: AppColors.statusGreen.withValues(alpha: 0.12), borderRadius: BorderRadius.circular(20)),
                      child: const Text("SALDADO", style: TextStyle(fontSize: 11, fontWeight: FontWeight.bold, color: AppColors.statusGreen)),
                    ),
                ]),
                const Divider(height: 20),
                _iRow(Icons.receipt_outlined, "RIF", cuenta.rif),
                _iRow(Icons.phone_outlined, "Teléfono", cuenta.telefono),
                if (cuenta.correo.isNotEmpty) _iRow(Icons.email_outlined, "Correo", cuenta.correo),
                if (cuenta.notas.isNotEmpty) _iRow(Icons.notes_outlined, "Notas", cuenta.notas),
                const SizedBox(height: 12),
                Row(mainAxisAlignment: MainAxisAlignment.spaceBetween, children: [
                  Text("Deuda total: ${formatCurrency(cuenta.montoTotal)}",
                      style: const TextStyle(color: AppColors.textSecondary, fontSize: 13)),
                  Text("${(pct * 100).toStringAsFixed(0)}% pagado",
                      style: const TextStyle(color: AppColors.textSecondary, fontSize: 13)),
                ]),
                const SizedBox(height: 6),
                ClipRRect(
                  borderRadius: BorderRadius.circular(6),
                  child: LinearProgressIndicator(
                    value: pct, minHeight: 10,
                    backgroundColor: Colors.grey[200],
                    valueColor: AlwaysStoppedAnimation<Color>(saldado ? AppColors.statusGreen : AppColors.statusRed),
                  ),
                ),
                const SizedBox(height: 12),
                Container(
                  width: double.infinity,
                  padding: const EdgeInsets.all(12),
                  decoration: BoxDecoration(
                    color: (saldado ? AppColors.statusGreen : AppColors.statusRed).withValues(alpha: 0.08),
                    borderRadius: BorderRadius.circular(10),
                  ),
                  child: Row(mainAxisAlignment: MainAxisAlignment.spaceBetween, children: [
                    Text("SALDO RESTANTE", style: TextStyle(
                        color: saldado ? AppColors.statusGreen : AppColors.statusRed,
                        fontWeight: FontWeight.w600, fontSize: 12, letterSpacing: 0.5)),
                    Text(formatCurrency(cuenta.saldoRestante), style: TextStyle(
                        color: saldado ? AppColors.statusGreen : AppColors.statusRed,
                        fontWeight: FontWeight.bold, fontSize: 22)),
                  ]),
                ),
              ]),
            ),
          ),
          const SizedBox(height: 16),
          // ── Cuotas ───────────────────────────────────────
          if (tieneCuotas) ...[
            Row(children: [
              const Text("Plan de Cuotas", style: TextStyle(fontSize: 16, fontWeight: FontWeight.bold)),
              const SizedBox(width: 8),
              Container(
                padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 2),
                decoration: BoxDecoration(
                    color: AppColors.primaryBlue.withValues(alpha: 0.1), borderRadius: BorderRadius.circular(10)),
                child: Text("$cuotasPendientes pendiente${cuotasPendientes != 1 ? 's' : ''}",
                    style: const TextStyle(fontSize: 11, color: AppColors.primaryBlue, fontWeight: FontWeight.w600)),
              ),
            ]),
            const SizedBox(height: 8),
            ...cuenta.cuotas.map((cuota) => Card(
              margin: const EdgeInsets.only(bottom: 8),
              shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
              elevation: 1,
              child: ListTile(
                contentPadding: const EdgeInsets.symmetric(horizontal: 14, vertical: 6),
                leading: Container(
                  width: 36, height: 36,
                  decoration: BoxDecoration(
                    color: (cuota.pagada ? AppColors.statusGreen : AppColors.statusOrange).withValues(alpha: 0.12),
                    shape: BoxShape.circle,
                  ),
                  child: Center(child: Text("${cuota.numero}", style: TextStyle(
                      fontWeight: FontWeight.bold,
                      color: cuota.pagada ? AppColors.statusGreen : AppColors.statusOrange))),
                ),
                title: Row(children: [
                  Text(formatCurrency(cuota.monto), style: TextStyle(
                      fontWeight: FontWeight.bold, fontSize: 15,
                      color: cuota.pagada ? AppColors.statusGreen : AppColors.textPrimary)),
                  const Spacer(),
                  if (cuota.pagada)
                    Container(
                      padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 2),
                      decoration: BoxDecoration(color: AppColors.statusGreen.withValues(alpha: 0.1), borderRadius: BorderRadius.circular(8)),
                      child: const Text("Pagada", style: TextStyle(fontSize: 11, color: AppColors.statusGreen, fontWeight: FontWeight.w600)),
                    )
                  else if (puedeEditar)
                    TextButton.icon(
                      icon: const Icon(Icons.check_circle_outline, size: 16),
                      label: const Text("Pagar", style: TextStyle(fontSize: 12)),
                      style: TextButton.styleFrom(
                          foregroundColor: AppColors.statusGreen,
                          padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
                          minimumSize: Size.zero, tapTargetSize: MaterialTapTargetSize.shrinkWrap),
                      onPressed: () => _pagarCuota(cuota),
                    ),
                ]),
                subtitle: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                  Row(children: [
                    const Icon(Icons.event_outlined, size: 12, color: AppColors.textSecondary),
                    const SizedBox(width: 4),
                    Text("Vence: ${cuota.fecha}", style: const TextStyle(fontSize: 11, color: AppColors.textSecondary)),
                  ]),
                  if (cuota.pagada && cuota.fechaPago != null)
                    Row(children: [
                      const Icon(Icons.check_outlined, size: 12, color: AppColors.statusGreen),
                      const SizedBox(width: 4),
                      Text("Pagada el: ${cuota.fechaPago}", style: const TextStyle(fontSize: 11, color: AppColors.statusGreen)),
                    ]),
                ]),
              ),
            )),
            const SizedBox(height: 16),
          ],
          // ── Historial de pagos libres ─────────────────────
          const Text("Historial de Pagos", style: TextStyle(fontSize: 16, fontWeight: FontWeight.bold)),
          const SizedBox(height: 8),
          if (cuenta.pagos.isEmpty && !tieneCuotas)
            const EmptyState(mensaje: "Sin pagos registrados aún.", icono: Icons.payment_outlined)
          else if (cuenta.pagos.isEmpty)
            Padding(
              padding: const EdgeInsets.symmetric(vertical: 8),
              child: Text("Sin abonos adicionales registrados.",
                  style: const TextStyle(fontSize: 13, color: AppColors.textSecondary)),
            )
          else
            ...cuenta.pagos.map((pago) => Card(
              margin: const EdgeInsets.only(bottom: 6),
              shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
              elevation: 1,
              child: ListTile(
                leading: const CircleAvatar(
                    backgroundColor: Color(0xFFE8F5E9),
                    child: Icon(Icons.payment_outlined, color: AppColors.statusGreen, size: 20)),
                title: Text(formatCurrency(double.tryParse(pago['monto'].toString()) ?? 0),
                    style: const TextStyle(fontWeight: FontWeight.bold, color: AppColors.statusGreen)),
                subtitle: Text("${pago['metodo']} · ${pago['fecha']}",
                    style: const TextStyle(fontSize: 12, color: AppColors.textSecondary)),
              ),
            )),
          const SizedBox(height: 80),
        ]),
      ),
      floatingActionButton: puedeEditar && !saldado
          ? FloatingActionButton.extended(
              onPressed: _registrarPago,
              icon: const Icon(Icons.attach_money),
              label: const Text("Registrar Pago"),
            )
          : null,
    );
  }

  void _pagarCuota(CuotaCobrar cuota) {
    showDialog(
      context: context,
      builder: (ctx) => AlertDialog(
        title: Row(children: [
          const Icon(Icons.check_circle_outline, color: AppColors.statusGreen),
          const SizedBox(width: 8),
          Text("Pagar Cuota ${cuota.numero}"),
        ]),
        content: Column(mainAxisSize: MainAxisSize.min, children: [
          ListTile(
            contentPadding: EdgeInsets.zero,
            leading: const Icon(Icons.attach_money, color: AppColors.statusGreen),
            title: Text("Monto: ${formatCurrency(cuota.monto)}", style: const TextStyle(fontWeight: FontWeight.bold)),
            subtitle: Text("Vencimiento: ${cuota.fecha}"),
          ),
          const Text("¿Confirma que esta cuota fue pagada hoy?"),
        ]),
        actions: [
          TextButton(onPressed: () => Navigator.pop(ctx), child: const Text("Cancelar")),
          ElevatedButton.icon(
            icon: const Icon(Icons.check, size: 16),
            label: const Text("Confirmar pago"),
            style: ElevatedButton.styleFrom(backgroundColor: AppColors.statusGreen),
            onPressed: () async {
              Navigator.pop(ctx);
              try {
                final fechaHoy = obtenerFechaActual();
                if (widget.cuenta.id == null) throw Exception('Cuenta sin ID');
                    await _Api.put('cuentas_pagar', widget.cuenta.id!.toString(), {
                  'cuota_pagada': {'numero': cuota.numero, 'fecha_pago': fechaHoy}
                });
                if (!mounted) return;
                setState(() { cuota.pagada = true; cuota.fechaPago = fechaHoy; });
                ScaffoldMessenger.of(context).showSnackBar(SnackBar(
                    content: Text("Cuota ${cuota.numero} pagada (${formatCurrency(cuota.monto)})"),
                    backgroundColor: AppColors.statusGreen));
              } catch (e) {
                if (mounted) ScaffoldMessenger.of(context).showSnackBar(SnackBar(
                    content: Text("Error: $e"), backgroundColor: AppColors.statusRed));
              }
            },
          ),
        ],
      ),
    );
  }

  Widget _iRow(IconData icon, String label, String value) => Padding(
    padding: const EdgeInsets.symmetric(vertical: 3),
    child: Row(children: [
      Icon(icon, size: 16, color: AppColors.textSecondary),
      const SizedBox(width: 6),
      Text("$label: ", style: const TextStyle(color: AppColors.textSecondary, fontSize: 13)),
      Expanded(child: Text(value, style: const TextStyle(fontWeight: FontWeight.w500, fontSize: 13))),
    ]),
  );
}

// ============================================================
//  CUENTAS POR PAGAR PROVEEDOR
// ============================================================
class VentanaCuentasPorPagarProveedor extends StatefulWidget {
  const VentanaCuentasPorPagarProveedor({super.key});
  @override State<VentanaCuentasPorPagarProveedor> createState() => _VentanaCuentasPorPagarProveedorState();
}

class _VentanaCuentasPorPagarProveedorState extends State<VentanaCuentasPorPagarProveedor> {
  List<CuentaPorPagarProveedor> _cuentas = [];
  bool _cargando = true;
  bool get puedeEditar => (usuarioSesion?.rol == "Administrador" || usuarioSesion?.rol == "Maestro" || usuarioSesion?.rol == "Dueño");

  @override
  void initState() { super.initState(); _cargar(); }

  Future<void> _cargar() async {
    setState(() => _cargando = true);
    try {
      final raw = await _Api.get('cuentas_pagar_proveedor');
      _cuentas = ((raw as List?) ?? []).map((m) => CuentaPorPagarProveedor.fromMap(m)).toList();
      cuentasPorPagarProveedorGlobal = _cuentas;
    } catch (e) {
      debugPrint('[_cargar] Error: $e');
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Error al cargar datos: $e'), backgroundColor: AppColors.statusRed, duration: const Duration(seconds: 4)));
    } finally {
      if (mounted) setState(() => _cargando = false);
    }
  }

  void _crearCuenta() {
    final rifCtrl         = TextEditingController();
    final nomCtrl         = TextEditingController();
    final telCtrl         = TextEditingController();
    final corCtrl         = TextEditingController();
    final deudaCtrl       = TextEditingController();
    final fechaLimiteCtrl = TextEditingController();
    final formKey         = GlobalKey<FormState>();
    bool guardando        = false;
    bool usarCuotas       = false;
    int  numCuotas        = 1;
    List<List<TextEditingController>> cuotasCtrl = [
      [TextEditingController(), TextEditingController()],
    ];

    late void Function(void Function(void Function()), int) actualizarCuotas;
    actualizarCuotas = (setS, nuevaCant) {
      setS(() {
        numCuotas = nuevaCant.clamp(1, 60);
        while (cuotasCtrl.length < numCuotas) {
          cuotasCtrl.add([TextEditingController(), TextEditingController()]);
        }
        while (cuotasCtrl.length > numCuotas) {
          for (final c in cuotasCtrl.last) c.dispose();
          cuotasCtrl.removeLast();
        }
        final total = double.tryParse(deudaCtrl.text.trim()) ?? 0;
        if (total > 0) {
          final porCuota = (total / numCuotas).toStringAsFixed(2);
          for (final par in cuotasCtrl) par[0].text = porCuota;
        }
      });
    };

    showModalBottomSheet(
      context: context,
      isScrollControlled: true,
      shape: const RoundedRectangleBorder(
          borderRadius: BorderRadius.vertical(top: Radius.circular(20))),
      builder: (ctx) => StatefulBuilder(
        builder: (context, setS) => DraggableScrollableSheet(
          initialChildSize: 0.92,
          minChildSize: 0.5,
          maxChildSize: 0.97,
          expand: false,
          builder: (_, scrollCtrl) => Padding(
            padding: EdgeInsets.only(
                bottom: MediaQuery.of(ctx).viewInsets.bottom,
                left: 24, right: 24, top: 20),
            child: Form(
              key: formKey,
              child: ListView(
                controller: scrollCtrl,
                children: [
                  Row(children: [
                    const Icon(Icons.business_center, color: AppColors.royalBlue),
                    const SizedBox(width: 8),
                    const Text("Nueva CxP Proveedor",
                        style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold)),
                    const Spacer(),
                    IconButton(icon: const Icon(Icons.close), onPressed: () => Navigator.pop(ctx)),
                  ]),
                  const Divider(),
                  const SizedBox(height: 8),
                  const Text("Datos del proveedor",
                      style: TextStyle(fontWeight: FontWeight.w600, color: AppColors.royalBlue, fontSize: 13)),
                  const SizedBox(height: 10),
                  TextFormField(
                    controller: rifCtrl,
                    textCapitalization: TextCapitalization.characters,
                    textInputAction: TextInputAction.next,
                    decoration: const InputDecoration(labelText: "RIF *", prefixIcon: Icon(Icons.receipt_outlined)),
                    validator: (v) => (v?.trim().isEmpty ?? true) ? "El RIF es obligatorio" : null,
                  ),
                  const SizedBox(height: 10),
                  TextFormField(
                    controller: nomCtrl,
                    textCapitalization: TextCapitalization.words,
                    textInputAction: TextInputAction.next,
                    decoration: const InputDecoration(labelText: "Nombre proveedor *", prefixIcon: Icon(Icons.business_outlined)),
                    validator: (v) => (v?.trim().isEmpty ?? true) ? "El nombre es obligatorio" : null,
                  ),
                  const SizedBox(height: 10),
                  Row(children: [
                    Expanded(child: TextFormField(
                      controller: telCtrl,
                      keyboardType: TextInputType.phone,
                      textInputAction: TextInputAction.next,
                      decoration: const InputDecoration(labelText: "Teléfono", prefixIcon: Icon(Icons.phone_outlined)),
                    )),
                    const SizedBox(width: 10),
                    Expanded(child: TextFormField(
                      controller: corCtrl,
                      keyboardType: TextInputType.emailAddress,
                      textInputAction: TextInputAction.next,
                      decoration: const InputDecoration(labelText: "Correo", prefixIcon: Icon(Icons.email_outlined)),
                    )),
                  ]),
                  const SizedBox(height: 10),
                  TextFormField(
                    controller: deudaCtrl,
                    keyboardType: const TextInputType.numberWithOptions(decimal: true),
                    textInputAction: TextInputAction.next,
                    decoration: const InputDecoration(
                        labelText: "Monto total *",
                        prefixIcon: Icon(Icons.attach_money),
                        ),
                    onChanged: (_) { if (usarCuotas) actualizarCuotas(setS, numCuotas); },
                    validator: (v) {
                      final d = double.tryParse(v?.trim() ?? '');
                      return (d == null || d <= 0) ? "Ingrese un monto válido" : null;
                    },
                  ),
                  const SizedBox(height: 10),
                  TextFormField(
                    controller: fechaLimiteCtrl,
                    readOnly: true,
                    decoration: const InputDecoration(
                        labelText: "Fecha límite *",
                        prefixIcon: Icon(Icons.event_outlined)),
                    onTap: () async {
                      final picked = await showDatePicker(
                        context: context,
                        initialDate: DateTime.now().add(const Duration(days: 30)),
                        firstDate: DateTime.now(),
                        lastDate: DateTime.now().add(const Duration(days: 1825)),
                      );
                      if (picked != null) {
                        setS(() => fechaLimiteCtrl.text =
                            "${picked.day.toString().padLeft(2, '0')}/${picked.month.toString().padLeft(2, '0')}/${picked.year}");
                      }
                    },
                    validator: (v) => (v == null || v.trim().isEmpty) ? "Ingrese la fecha límite" : null,
                  ),
                  const SizedBox(height: 18),
                  // ── Sección Cuotas ──────────────────────────
                  Container(
                    decoration: BoxDecoration(
                      color: AppColors.surfaceGrey,
                      borderRadius: BorderRadius.circular(12),
                      border: Border.all(color: AppColors.cardBorder),
                    ),
                    child: Column(children: [
                      SwitchListTile(
                        value: usarCuotas,
                        onChanged: (v) => setS(() => usarCuotas = v),
                        title: const Text("Dividir en cuotas", style: TextStyle(fontWeight: FontWeight.w600)),
                        subtitle: const Text("Define número, fecha y monto de cada cuota", style: TextStyle(fontSize: 11)),
                        secondary: const Icon(Icons.calendar_month_outlined, color: AppColors.royalBlue),
                        activeColor: AppColors.royalBlue,
                      ),
                      if (usarCuotas) ...[
                        const Divider(height: 1),
                        Padding(
                          padding: const EdgeInsets.fromLTRB(16, 12, 16, 4),
                          child: Row(children: [
                            const Text("Número de cuotas:", style: TextStyle(fontWeight: FontWeight.w500)),
                            const Spacer(),
                            IconButton(
                              icon: const Icon(Icons.remove_circle_outline, color: AppColors.statusRed),
                              onPressed: () => actualizarCuotas(setS, numCuotas - 1),
                            ),
                            Container(width: 40, alignment: Alignment.center,
                              child: Text("$numCuotas", style: const TextStyle(fontSize: 20, fontWeight: FontWeight.bold))),
                            IconButton(
                              icon: const Icon(Icons.add_circle_outline, color: AppColors.statusGreen),
                              onPressed: () => actualizarCuotas(setS, numCuotas + 1),
                            ),
                          ]),
                        ),
                        Padding(
                          padding: const EdgeInsets.fromLTRB(16, 0, 16, 16),
                          child: Column(
                            children: List.generate(numCuotas, (i) {
                              final mc = cuotasCtrl[i][0];
                              final fc = cuotasCtrl[i][1];
                              return Padding(
                                padding: const EdgeInsets.only(bottom: 10),
                                child: Row(children: [
                                  Container(
                                    width: 28, height: 28,
                                    decoration: const BoxDecoration(color: AppColors.royalBlue, shape: BoxShape.circle),
                                    child: Center(child: Text("${i + 1}",
                                        style: const TextStyle(color: Colors.white, fontSize: 12, fontWeight: FontWeight.bold))),
                                  ),
                                  const SizedBox(width: 8),
                                  Expanded(flex: 2, child: TextFormField(
                                    controller: mc,
                                    keyboardType: const TextInputType.numberWithOptions(decimal: true),
                                    decoration: InputDecoration(
                                        labelText: "Monto", isDense: true, 
                                        border: OutlineInputBorder(borderRadius: BorderRadius.circular(8))),
                                    validator: (v) {
                                      if (!usarCuotas) return null;
                                      final d = double.tryParse(v?.trim() ?? '');
                                      return (d == null || d <= 0) ? "Requerido" : null;
                                    },
                                  )),
                                  const SizedBox(width: 8),
                                  Expanded(flex: 3, child: TextFormField(
                                    controller: fc,
                                    readOnly: true,
                                    decoration: InputDecoration(
                                        labelText: "Fecha venc.", isDense: true,
                                        prefixIcon: const Icon(Icons.event_outlined, size: 16),
                                        border: OutlineInputBorder(borderRadius: BorderRadius.circular(8))),
                                    onTap: () async {
                                      final picked = await showDatePicker(
                                        context: context,
                                        initialDate: DateTime.now().add(Duration(days: 30 * (i + 1))),
                                        firstDate: DateTime.now().subtract(const Duration(days: 1)),
                                        lastDate: DateTime.now().add(const Duration(days: 1825)),
                                      );
                                      if (picked != null) {
                                        setS(() => fc.text =
                                            "${picked.day.toString().padLeft(2, '0')}/${picked.month.toString().padLeft(2, '0')}/${picked.year}");
                                      }
                                    },
                                    validator: (v) {
                                      if (!usarCuotas) return null;
                                      return (v == null || v.trim().isEmpty) ? "Requerida" : null;
                                    },
                                  )),
                                ]),
                              );
                            }),
                          ),
                        ),
                        Padding(
                          padding: const EdgeInsets.fromLTRB(16, 0, 16, 12),
                          child: Builder(builder: (_) {
                            final suma = cuotasCtrl.fold(0.0, (s, p) => s + (double.tryParse(p[0].text.trim()) ?? 0));
                            final total = double.tryParse(deudaCtrl.text.trim()) ?? 0;
                            final ok = (total - suma).abs() < 0.01;
                            return Container(
                              padding: const EdgeInsets.all(10),
                              decoration: BoxDecoration(
                                color: (ok ? AppColors.statusGreen : AppColors.statusOrange).withValues(alpha: 0.08),
                                borderRadius: BorderRadius.circular(8),
                                border: Border.all(color: ok ? AppColors.statusGreen : AppColors.statusOrange, width: 0.8),
                              ),
                              child: Row(children: [
                                Icon(ok ? Icons.check_circle_outline : Icons.info_outline,
                                    size: 16, color: ok ? AppColors.statusGreen : AppColors.statusOrange),
                                const SizedBox(width: 6),
                                Expanded(child: Text(
                                  ok ? "Total cuotas: ${formatCurrency(suma)} ✓"
                                      : "Total cuotas: ${formatCurrency(suma)}  (diferencia: ${formatCurrency((total - suma).abs())})",
                                  style: TextStyle(fontSize: 12, color: ok ? AppColors.statusGreen : AppColors.statusOrange),
                                )),
                              ]),
                            );
                          }),
                        ),
                      ],
                    ]),
                  ),
                  const SizedBox(height: 20),
                  SizedBox(
                    width: double.infinity,
                    child: ElevatedButton.icon(
                      icon: guardando
                          ? const SizedBox(width: 18, height: 18, child: CircularProgressIndicator(strokeWidth: 2, color: Colors.white))
                          : const Icon(Icons.save_outlined),
                      label: const Text("Crear Cuenta"),
                      style: ElevatedButton.styleFrom(
                          backgroundColor: AppColors.royalBlue,
                          padding: const EdgeInsets.symmetric(vertical: 14),
                          shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10))),
                      onPressed: guardando ? null : () async {
                        if (!formKey.currentState!.validate()) return;
                        if (usarCuotas) {
                          final suma = cuotasCtrl.fold(0.0, (s, p) => s + (double.tryParse(p[0].text.trim()) ?? 0));
                          final total = double.tryParse(deudaCtrl.text.trim()) ?? 0;
                          if ((total - suma).abs() >= 0.01) {
                            ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
                              content: Text("La suma de cuotas no coincide con el total"),
                              backgroundColor: AppColors.statusOrange));
                            return;
                          }
                        }
                        setS(() => guardando = true);
                        try {
                          final cuotas = usarCuotas
                              ? List.generate(numCuotas, (i) => {
                                    'numero': i + 1,
                                    'monto': double.tryParse(cuotasCtrl[i][0].text.trim()) ?? 0,
                                    'fecha': cuotasCtrl[i][1].text.trim(),
                                    'pagada': false,
                                  })
                              : <Map<String, dynamic>>[];
                          await _Api.post('cuentas_pagar_proveedor', {
                            'rif': rifCtrl.text.trim(),
                            'nombre': nomCtrl.text.trim(),
                            'telefono': telCtrl.text.trim(),
                            'correo': corCtrl.text.trim(),
                            'monto_total': double.tryParse(deudaCtrl.text) ?? 0,
                            'fecha_limite': fechaLimiteCtrl.text.trim(),
                            'cuotas': cuotas,
                          });
                          if (!ctx.mounted) return;
                          Navigator.pop(ctx);
                          await _cargar();
                          if (mounted) ScaffoldMessenger.of(context).showSnackBar(
                              const SnackBar(content: Text("Cuenta creada exitosamente"), backgroundColor: AppColors.statusGreen));
                        } catch (e) {
                          setS(() => guardando = false);
                          if (ctx.mounted) ScaffoldMessenger.of(context).showSnackBar(
                              SnackBar(content: Text("Error: $e"), backgroundColor: AppColors.statusRed));
                        }
                      },
                    ),
                  ),
                  const SizedBox(height: 24),
                ],
              ),
            ),
          ),
        ),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    final total = _cuentas.fold(0.0, (sum, c) => sum + c.saldoRestante);
    final vencidas = _cuentas.where((c) => c.saldoRestante > 0).length;

    return Scaffold(
      appBar: AppBar(
        title: const Text("CxP Proveedores"),
        actions: [IconButton(icon: const Icon(Icons.refresh), tooltip: "Actualizar", onPressed: _cargar)],
      ),
      body: Column(children: [
        // Header con estadísticas
        Container(
          width: double.infinity,
          padding: const EdgeInsets.fromLTRB(20, 16, 20, 20),
          decoration: const BoxDecoration(
            gradient: LinearGradient(
              colors: [AppColors.royalBlue, Color(0xFF003580)],
              begin: Alignment.topLeft,
              end: Alignment.bottomRight,
            ),
          ),
          child: Row(children: [
            Expanded(child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
              const Text("TOTAL POR PAGAR", style: TextStyle(color: Colors.white60, fontSize: 11, letterSpacing: 1)),
              const SizedBox(height: 4),
              Text(formatCurrency(total),
                style: const TextStyle(color: Colors.white, fontSize: 28, fontWeight: FontWeight.bold)),
            ])),
            Column(crossAxisAlignment: CrossAxisAlignment.end, children: [
              Container(
                padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),
                decoration: BoxDecoration(
                  color: Colors.white.withValues(alpha: 0.15),
                  borderRadius: BorderRadius.circular(20),
                ),
                child: Text("$vencidas pendientes",
                  style: const TextStyle(color: Colors.white, fontSize: 12, fontWeight: FontWeight.w600)),
              ),
            ]),
          ]),
        ),
        if (_cargando)
          const Expanded(child: Center(child: CircularProgressIndicator()))
        else if (_cuentas.isEmpty)
          const Expanded(child: EmptyState(mensaje: "No hay cuentas por pagar registradas.", icono: Icons.business_outlined))
        else
          Expanded(child: RefreshIndicator(
            onRefresh: _cargar,
            child: ListView.builder(
              padding: const EdgeInsets.all(12),
              itemCount: _cuentas.length,
              itemBuilder: (c, i) {
                final cuenta = _cuentas[i];
                final saldado = cuenta.saldoRestante <= 0;
                final pct = cuenta.montoTotal > 0
                  ? (1 - cuenta.saldoRestante / cuenta.montoTotal).clamp(0.0, 1.0)
                  : 1.0;
                return Card(
                  margin: const EdgeInsets.only(bottom: 8),
                  shape: RoundedRectangleBorder(
                    borderRadius: BorderRadius.circular(12),
                    side: saldado
                      ? const BorderSide(color: AppColors.statusGreen, width: 1)
                      : BorderSide.none,
                  ),
                  child: InkWell(
                    borderRadius: BorderRadius.circular(12),
                    onTap: () => Navigator.push(context,
                      MaterialPageRoute(builder: (_) => DetalleCuentaProveedor(cuenta: cuenta)))
                      .then((_) => _cargar()),
                    child: Padding(
                      padding: const EdgeInsets.all(14),
                      child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                        Row(children: [
                          Container(
                            padding: const EdgeInsets.all(8),
                            decoration: BoxDecoration(
                              color: (saldado ? AppColors.statusGreen : AppColors.statusRed).withValues(alpha: 0.1),
                              borderRadius: BorderRadius.circular(8),
                            ),
                            child: Icon(Icons.business_outlined,
                              color: saldado ? AppColors.statusGreen : AppColors.statusRed, size: 20),
                          ),
                          const SizedBox(width: 10),
                          Expanded(child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                            Text(cuenta.nombre,
                              style: const TextStyle(fontWeight: FontWeight.w600, fontSize: 14)),
                            Text("RIF: ${cuenta.rif} · Vence: ${cuenta.fechaLimite}",
                              style: const TextStyle(fontSize: 11, color: AppColors.textSecondary)),
                          ])),
                          Column(crossAxisAlignment: CrossAxisAlignment.end, children: [
                            Text(formatCurrency(cuenta.saldoRestante),
                              style: TextStyle(
                                fontWeight: FontWeight.bold, fontSize: 15,
                                color: saldado ? AppColors.statusGreen : AppColors.statusRed)),
                            Text(saldado ? "SALDADO" : "PENDIENTE",
                              style: TextStyle(
                                fontSize: 9, fontWeight: FontWeight.bold, letterSpacing: 0.5,
                                color: saldado ? AppColors.statusGreen : AppColors.statusRed)),
                          ]),
                        ]),
                        const SizedBox(height: 10),
                        ClipRRect(
                          borderRadius: BorderRadius.circular(4),
                          child: LinearProgressIndicator(
                            value: pct, minHeight: 6,
                            backgroundColor: Colors.grey[200],
                            valueColor: AlwaysStoppedAnimation<Color>(
                              saldado ? AppColors.statusGreen : AppColors.primaryBlue),
                          ),
                        ),
                        const SizedBox(height: 4),
                        Row(children: [
                          Expanded(
                            child: Text(
                              "${(pct * 100).toStringAsFixed(0)}% pagado de ${formatCurrency(cuenta.montoTotal)}",
                              style: const TextStyle(fontSize: 10, color: AppColors.textSecondary)),
                          ),
                          if (cuenta.proximaCuota != null)
                            Container(
                              padding: const EdgeInsets.symmetric(horizontal: 7, vertical: 2),
                              decoration: BoxDecoration(
                                color: AppColors.statusOrange.withValues(alpha: 0.1),
                                borderRadius: BorderRadius.circular(8),
                                border: Border.all(
                                    color: AppColors.statusOrange.withValues(alpha: 0.4),
                                    width: 0.7),
                              ),
                              child: Row(mainAxisSize: MainAxisSize.min, children: [
                                const Icon(Icons.event_outlined,
                                    size: 11, color: AppColors.statusOrange),
                                const SizedBox(width: 3),
                                Text(
                                  "Cuota ${cuenta.proximaCuota!.numero}: ${formatCurrency(cuenta.proximaCuota!.monto)} · ${cuenta.proximaCuota!.fecha}",
                                  style: const TextStyle(
                                      fontSize: 10, color: AppColors.statusOrange),
                                ),
                              ]),
                            )
                          else if (cuenta.cuotas.isNotEmpty && saldado)
                            const Text("Todas las cuotas pagadas ✓",
                                style: TextStyle(fontSize: 10, color: AppColors.statusGreen)),
                        ]),
                      ]),
                    ),
                  ),
                );
              },
            ),
          )),
      ]),
      floatingActionButton: puedeEditar
          ? FloatingActionButton.extended(
              onPressed: _crearCuenta,
              icon: const Icon(Icons.add),
              label: const Text("Nueva Cuenta"),
            )
          : null,
    );
  }
}

class DetalleCuentaProveedor extends StatefulWidget {
  final CuentaPorPagarProveedor cuenta;
  const DetalleCuentaProveedor({super.key, required this.cuenta});
  @override State<DetalleCuentaProveedor> createState() => _DetalleCuentaProveedorState();
}

class _DetalleCuentaProveedorState extends State<DetalleCuentaProveedor> {
  bool get puedeEditar => (usuarioSesion?.rol == "Administrador" || usuarioSesion?.rol == "Maestro" || usuarioSesion?.rol == "Dueño");

  void _registrarPago() {
    final montoController = TextEditingController();
    final tasaController = TextEditingController(text: ConfigSistema.tasaCambio.toStringAsFixed(2));
    String metodo = "Efectivo \$";
    bool guardando = false;
    final formKey = GlobalKey<FormState>();

    showDialog(context: context, builder: (ctx) => StatefulBuilder(
      builder: (context, setS) {
        bool requiereTasa = metodo == "Efectivo Bs" || metodo == "Pago móvil" ||
            metodo == "Transferencia" || metodo == "Punto";
        return AlertDialog(
          title: const Row(children: [
            Icon(Icons.attach_money, color: AppColors.statusGreen),
            SizedBox(width: 8),
            Text("Registrar Pago"),
          ]),
          content: Form(
            key: formKey,
            child: SingleChildScrollView(child: Column(mainAxisSize: MainAxisSize.min, children: [
              // Saldo pendiente
              Container(
                width: double.infinity,
                padding: const EdgeInsets.all(10),
                decoration: BoxDecoration(
                  color: AppColors.statusRed.withValues(alpha: 0.07),
                  borderRadius: BorderRadius.circular(8),
                ),
                child: Row(mainAxisAlignment: MainAxisAlignment.spaceBetween, children: [
                  const Text("Saldo pendiente:", style: TextStyle(fontSize: 13, color: AppColors.textSecondary)),
                  Text(formatCurrency(widget.cuenta.saldoRestante),
                    style: const TextStyle(fontSize: 15, fontWeight: FontWeight.bold, color: AppColors.statusRed)),
                ]),
              ),
              const SizedBox(height: 12),
              DropdownButtonFormField<String>(
                value: metodo,
                items: ConfigSistema.metodossPago.isNotEmpty
                  ? ConfigSistema.metodossPago.map((e) => DropdownMenuItem(value: e, child: Text(e))).toList()
                  : ["Efectivo \$","Efectivo Bs","Pago móvil","Transferencia","Zelle","Punto"]
                      .map((e) => DropdownMenuItem(value: e, child: Text(e))).toList(),
                onChanged: (v) { if (v != null) setS(() => metodo = v); },
                decoration: const InputDecoration(labelText: "Método de pago", prefixIcon: Icon(Icons.payment_outlined)),
              ),
              const SizedBox(height: 10),
              TextFormField(
                controller: montoController,
                keyboardType: const TextInputType.numberWithOptions(decimal: true),
                decoration: InputDecoration(
                  labelText: requiereTasa ? "Monto en Bolívares (Bs)" : "Monto en Dólares \$",
                  prefixIcon: const Icon(Icons.attach_money),
                ),
                validator: (v) {
                  final d = double.tryParse(v?.trim() ?? '');
                  if (d == null || d <= 0) return "Ingrese un monto válido";
                  return null;
                },
              ),
              if (requiereTasa) ...[
                const SizedBox(height: 10),
                TextFormField(
                  controller: tasaController,
                  keyboardType: const TextInputType.numberWithOptions(decimal: true),
                  decoration: const InputDecoration(
                    labelText: "Tasa de cambio (Bs/\$)",
                    prefixIcon: Icon(Icons.currency_exchange),
                  ),
                  validator: (v) {
                    final d = double.tryParse(v?.trim() ?? '');
                    if (d == null || d <= 0) return "Ingrese una tasa válida";
                    return null;
                  },
                ),
              ],
            ])),
          ),
          actions: [
            TextButton(onPressed: () => Navigator.pop(ctx), child: const Text("Cancelar")),
            ElevatedButton.icon(
              icon: guardando
                ? const SizedBox(width: 16, height: 16, child: CircularProgressIndicator(strokeWidth: 2, color: Colors.white))
                : const Icon(Icons.check, size: 18),
              label: const Text("Registrar"),
              style: ElevatedButton.styleFrom(backgroundColor: AppColors.statusGreen),
              onPressed: guardando ? null : () async {
                if (!formKey.currentState!.validate()) return;
                double monto = double.tryParse(montoController.text) ?? 0;
                double montoFinal = monto;
                if (requiereTasa) {
                  final tasa = double.tryParse(tasaController.text) ?? ConfigSistema.tasaCambio;
                  montoFinal = tasa > 0 ? monto / tasa : monto;
                }
                setS(() => guardando = true);
                try {
                  if (widget.cuenta.id == null) throw Exception('Cuenta sin ID');
                  final nuevoPago = {
                    'monto': montoFinal,
                    'fecha': obtenerFechaActual(),
                    'metodo': metodo,
                  };
                  // Enviamos estado completo para garantizar persistencia
                  final pagosActualizados = [
                    ...widget.cuenta.pagos.map((p) => Map<String, dynamic>.from(p)),
                    nuevoPago,
                  ];
                  final payload = <String, dynamic>{
                    ...widget.cuenta.toMap(),
                    'pago': nuevoPago,
                    'pagos': pagosActualizados,
                  };
                  await _Api.put('cuentas_pagar_proveedor', widget.cuenta.id!.toString(), payload);
                  if (!ctx.mounted) return;
                  setState(() {
                    widget.cuenta.pagos.add(nuevoPago);
                  });
                  Navigator.pop(ctx);
                  if (mounted) ScaffoldMessenger.of(context).showSnackBar(
                    SnackBar(
                      content: Text("Pago de ${formatCurrency(montoFinal)} registrado correctamente"),
                      backgroundColor: AppColors.statusGreen));
                } catch (e) {
                  setS(() => guardando = false);
                  if (ctx.mounted) ScaffoldMessenger.of(context).showSnackBar(
                    SnackBar(content: Text('Error al registrar pago: $e'), backgroundColor: AppColors.statusRed));
                }
              },
            ),
          ],
        );
      },
    ));
  }

  @override
  Widget build(BuildContext context) {
    final cuenta = widget.cuenta;
    final pct = cuenta.montoTotal > 0
        ? (1 - cuenta.saldoRestante / cuenta.montoTotal).clamp(0.0, 1.0)
        : 1.0;
    final saldado = cuenta.saldoRestante <= 0;
    final tieneCuotas = cuenta.cuotas.isNotEmpty;
    final cuotasPendientes = cuenta.cuotas.where((c) => !c.pagada).length;

    return Scaffold(
      appBar: AppBar(title: Text(cuenta.nombre)),
      body: SingleChildScrollView(
        padding: const EdgeInsets.all(16),
        child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
          // ── Card resumen ─────────────────────────────────
          Card(
            shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(14)),
            child: Padding(
              padding: const EdgeInsets.all(16),
              child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                Row(children: [
                  const Icon(Icons.business_outlined, color: AppColors.royalBlue),
                  const SizedBox(width: 8),
                  Expanded(child: Text(cuenta.nombre,
                      style: const TextStyle(fontWeight: FontWeight.bold, fontSize: 16))),
                  if (saldado)
                    Container(
                      padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 4),
                      decoration: BoxDecoration(
                          color: AppColors.statusGreen.withValues(alpha: 0.12),
                          borderRadius: BorderRadius.circular(20)),
                      child: const Text("SALDADO",
                          style: TextStyle(fontSize: 11, fontWeight: FontWeight.bold,
                              color: AppColors.statusGreen)),
                    ),
                ]),
                const Divider(height: 20),
                _infoRow(Icons.receipt_outlined, "RIF", cuenta.rif),
                _infoRow(Icons.phone_outlined, "Teléfono", cuenta.telefono),
                if (cuenta.correo.isNotEmpty)
                  _infoRow(Icons.email_outlined, "Correo", cuenta.correo),
                _infoRow(Icons.event_outlined, "Fecha límite", cuenta.fechaLimite),
                const SizedBox(height: 12),
                Row(mainAxisAlignment: MainAxisAlignment.spaceBetween, children: [
                  Text("Deuda total: ${formatCurrency(cuenta.montoTotal)}",
                      style: const TextStyle(color: AppColors.textSecondary, fontSize: 13)),
                  Text("${(pct * 100).toStringAsFixed(0)}% pagado",
                      style: const TextStyle(color: AppColors.textSecondary, fontSize: 13)),
                ]),
                const SizedBox(height: 6),
                ClipRRect(
                  borderRadius: BorderRadius.circular(6),
                  child: LinearProgressIndicator(
                    value: pct, minHeight: 10,
                    backgroundColor: Colors.grey[200],
                    valueColor: AlwaysStoppedAnimation<Color>(
                        saldado ? AppColors.statusGreen : AppColors.statusRed),
                  ),
                ),
                const SizedBox(height: 12),
                Container(
                  width: double.infinity,
                  padding: const EdgeInsets.all(12),
                  decoration: BoxDecoration(
                    color: (saldado ? AppColors.statusGreen : AppColors.statusRed)
                        .withValues(alpha: 0.08),
                    borderRadius: BorderRadius.circular(10),
                  ),
                  child: Row(mainAxisAlignment: MainAxisAlignment.spaceBetween, children: [
                    Text("SALDO RESTANTE",
                        style: TextStyle(
                            color: saldado ? AppColors.statusGreen : AppColors.statusRed,
                            fontWeight: FontWeight.w600, fontSize: 12, letterSpacing: 0.5)),
                    Text(formatCurrency(cuenta.saldoRestante),
                        style: TextStyle(
                            color: saldado ? AppColors.statusGreen : AppColors.statusRed,
                            fontWeight: FontWeight.bold, fontSize: 22)),
                  ]),
                ),
              ]),
            ),
          ),
          const SizedBox(height: 16),

          // ── Plan de Cuotas ───────────────────────────────
          if (tieneCuotas) ...[
            Row(children: [
              const Text("Plan de Cuotas",
                  style: TextStyle(fontSize: 16, fontWeight: FontWeight.bold)),
              const SizedBox(width: 8),
              Container(
                padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 2),
                decoration: BoxDecoration(
                    color: AppColors.primaryBlue.withValues(alpha: 0.1),
                    borderRadius: BorderRadius.circular(10)),
                child: Text(
                    "$cuotasPendientes pendiente${cuotasPendientes != 1 ? 's' : ''}",
                    style: const TextStyle(fontSize: 11,
                        color: AppColors.primaryBlue, fontWeight: FontWeight.w600)),
              ),
            ]),
            const SizedBox(height: 8),
            ...cuenta.cuotas.map((cuota) => Card(
              margin: const EdgeInsets.only(bottom: 8),
              shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
              elevation: 1,
              child: ListTile(
                contentPadding: const EdgeInsets.symmetric(horizontal: 14, vertical: 6),
                leading: Container(
                  width: 36, height: 36,
                  decoration: BoxDecoration(
                    color: (cuota.pagada ? AppColors.statusGreen : AppColors.statusOrange)
                        .withValues(alpha: 0.12),
                    shape: BoxShape.circle,
                  ),
                  child: Center(
                    child: Text("${cuota.numero}",
                        style: TextStyle(
                            fontWeight: FontWeight.bold,
                            color: cuota.pagada
                                ? AppColors.statusGreen
                                : AppColors.statusOrange)),
                  ),
                ),
                title: Row(children: [
                  Text(formatCurrency(cuota.monto),
                      style: TextStyle(
                          fontWeight: FontWeight.bold,
                          fontSize: 15,
                          color: cuota.pagada
                              ? AppColors.statusGreen
                              : AppColors.textPrimary)),
                  const Spacer(),
                  if (cuota.pagada)
                    Container(
                      padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 2),
                      decoration: BoxDecoration(
                          color: AppColors.statusGreen.withValues(alpha: 0.1),
                          borderRadius: BorderRadius.circular(8)),
                      child: const Text("Pagada",
                          style: TextStyle(fontSize: 11,
                              color: AppColors.statusGreen,
                              fontWeight: FontWeight.w600)),
                    )
                  else if (puedeEditar)
                    TextButton.icon(
                      icon: const Icon(Icons.check_circle_outline, size: 16),
                      label: const Text("Pagar", style: TextStyle(fontSize: 12)),
                      style: TextButton.styleFrom(
                          foregroundColor: AppColors.statusGreen,
                          padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
                          minimumSize: Size.zero,
                          tapTargetSize: MaterialTapTargetSize.shrinkWrap),
                      onPressed: () => _pagarCuota(cuota),
                    ),
                ]),
                subtitle: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                  Row(children: [
                    const Icon(Icons.event_outlined, size: 12, color: AppColors.textSecondary),
                    const SizedBox(width: 4),
                    Text("Vence: ${cuota.fecha}",
                        style: const TextStyle(fontSize: 11, color: AppColors.textSecondary)),
                  ]),
                  if (cuota.pagada && cuota.fechaPago != null)
                    Row(children: [
                      const Icon(Icons.check_outlined, size: 12, color: AppColors.statusGreen),
                      const SizedBox(width: 4),
                      Text("Pagada el: ${cuota.fechaPago}",
                          style: const TextStyle(fontSize: 11, color: AppColors.statusGreen)),
                    ]),
                ]),
              ),
            )),
            const SizedBox(height: 16),
          ],

          // ── Historial de pagos libres ─────────────────────
          const Text("Historial de Pagos",
              style: TextStyle(fontSize: 16, fontWeight: FontWeight.bold)),
          const SizedBox(height: 8),
          if (cuenta.pagos.isEmpty && !tieneCuotas)
            const EmptyState(
                mensaje: "Sin pagos registrados aún.",
                icono: Icons.payment_outlined)
          else if (cuenta.pagos.isEmpty)
            Padding(
              padding: const EdgeInsets.symmetric(vertical: 8),
              child: Text("Sin abonos adicionales registrados.",
                  style: const TextStyle(fontSize: 13, color: AppColors.textSecondary)),
            )
          else
            ...cuenta.pagos.map((pago) => Card(
              margin: const EdgeInsets.only(bottom: 6),
              shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
              elevation: 1,
              child: ListTile(
                leading: const CircleAvatar(
                    backgroundColor: Color(0xFFE8F5E9),
                    child: Icon(Icons.payment_outlined,
                        color: AppColors.statusGreen, size: 20)),
                title: Text(
                    formatCurrency(double.tryParse(pago['monto'].toString()) ?? 0),
                    style: const TextStyle(
                        fontWeight: FontWeight.bold, color: AppColors.statusGreen)),
                subtitle: Text("${pago['metodo']} · ${pago['fecha']}",
                    style: const TextStyle(
                        fontSize: 12, color: AppColors.textSecondary)),
              ),
            )),
          const SizedBox(height: 80),
        ]),
      ),
      floatingActionButton: puedeEditar && !saldado
          ? FloatingActionButton.extended(
              onPressed: _registrarPago,
              icon: const Icon(Icons.attach_money),
              label: const Text("Registrar Pago"),
            )
          : null,
    );
  }

  void _pagarCuota(CuotaCobrar cuota) {
    showDialog(
      context: context,
      builder: (ctx) => AlertDialog(
        title: Row(children: [
          const Icon(Icons.check_circle_outline, color: AppColors.statusGreen),
          const SizedBox(width: 8),
          Text("Pagar Cuota ${cuota.numero}"),
        ]),
        content: Column(mainAxisSize: MainAxisSize.min, children: [
          ListTile(
            contentPadding: EdgeInsets.zero,
            leading: const Icon(Icons.attach_money, color: AppColors.statusGreen),
            title: Text("Monto: ${formatCurrency(cuota.monto)}",
                style: const TextStyle(fontWeight: FontWeight.bold)),
            subtitle: Text("Vencimiento: ${cuota.fecha}"),
          ),
          const Text("¿Confirma que esta cuota fue pagada hoy?"),
        ]),
        actions: [
          TextButton(
              onPressed: () => Navigator.pop(ctx),
              child: const Text("Cancelar")),
          ElevatedButton.icon(
            icon: const Icon(Icons.check, size: 16),
            label: const Text("Confirmar pago"),
            style: ElevatedButton.styleFrom(backgroundColor: AppColors.statusGreen),
            onPressed: () async {
              Navigator.pop(ctx);
              try {
                if (widget.cuenta.id == null) throw Exception('Cuenta sin ID. Recargue.');
                final fechaHoy = obtenerFechaActual();
                await _Api.put('cuentas_pagar_proveedor',
                    widget.cuenta.id!.toString(), {
                  'cuota_pagada': {'numero': cuota.numero, 'fecha_pago': fechaHoy}
                });
                if (!mounted) return;
                setState(() {
                  cuota.pagada = true;
                  cuota.fechaPago = fechaHoy;
                });
                ScaffoldMessenger.of(context).showSnackBar(SnackBar(
                    content: Text(
                        "Cuota ${cuota.numero} pagada (${formatCurrency(cuota.monto)})"),
                    backgroundColor: AppColors.statusGreen));
              } catch (e) {
                if (mounted)
                  ScaffoldMessenger.of(context).showSnackBar(SnackBar(
                      content: Text("Error: $e"),
                      backgroundColor: AppColors.statusRed));
              }
            },
          ),
        ],
      ),
    );
  }

  Widget _infoRow(IconData icon, String label, String value) => Padding(
    padding: const EdgeInsets.symmetric(vertical: 3),
    child: Row(children: [
      Icon(icon, size: 16, color: AppColors.textSecondary),
      const SizedBox(width: 6),
      Text("$label: ", style: const TextStyle(color: AppColors.textSecondary, fontSize: 13)),
      Expanded(child: Text(value, style: const TextStyle(fontWeight: FontWeight.w500, fontSize: 13))),
    ]),
  );
}

// ============================================================
//  INVENTARIO — carga desde la API
// ============================================================
class VentanaInventario extends StatefulWidget {
  const VentanaInventario({super.key});
  @override State<VentanaInventario> createState() => _VentanaInventarioState();
}

class _VentanaInventarioState extends State<VentanaInventario> {
  List<Producto> _productos = [];
  bool _cargando = true;
  String _query = '';
  String _filtroCategoria = 'Todos';

  @override
  void initState() { super.initState(); _cargar(); }

  Future<void> _cargar() async {
    setState(() => _cargando = true);
    try {
      // Traer productos e IMEIs en paralelo para mayor velocidad
      final results = await Future.wait([
        _Api.get('productos'),
        _Api.get('stock_imei'),
      ]);

      final rawP  = results[0];
      final rawI  = results[1];

      // ── PASO 1: cargar productos PRIMERO ────────────────────────
      // Es CRÍTICO actualizar catalogoGlobal ANTES de mapear los IMEIs.
      // ImeiRegistro.fromMap usa catalogoGlobal para resolver los datos
      // del producto (nombre, marca, modelo, precios) cuando el backend
      // no hace JOIN. Si lo hacemos al revés, los IMEIs quedan con
      // producto vacío y el stockTotal cuenta 0.
      _productos = ((rawP as List?) ?? [])
          .map((m) => Producto.fromMap(m))
          .toList();
      catalogoGlobal = _productos;

      // ── PASO 2: ahora sí cargar IMEIs (con catalogoGlobal listo) ──
      final imeis = ((rawI as List?) ?? [])
          .map((m) => ImeiRegistro.fromMap(m))
          .toList();
      stockImeiGlobal = imeis;

      // ── PASO 3: calcular stockTotal de cada producto ────────────
      // Teléfonos  → contar IMEIs no vendidos de ese código
      // Otros      → stock_manual de la BD (decrementado al vender)
      for (final p in _productos) {
        if (p.categoria == 'Telefono') {
          p.stockTotal = imeis
              .where((i) => i.producto.codigo == p.codigo && !i.vendido)
              .length;
        } else {
          p.stockTotal = p.stockManual;
        }
      }

      // ── PASO 4: sumar el stock de los SUBPRODUCTOS al padre ─────
      // Los subproductos NO se muestran en el listado del inventario
      // (solo el padre). Pero el stock total mostrado en el padre
      // debe reflejar también el stock de sus variantes — si no, el
      // dueño vería un Redmi A5 con 0 unidades cuando en realidad
      // tiene 5 blancos + 3 negros + 2 azules.
      final hijosPorPadre = <String, List<Producto>>{};
      for (final p in _productos) {
        if (p.productoPadreCodigo.isNotEmpty) {
          hijosPorPadre.putIfAbsent(p.productoPadreCodigo, () => [])
              .add(p);
        }
      }
      for (final padre in _productos.where((p) => p.productoPadreCodigo.isEmpty)) {
        final hijos = hijosPorPadre[padre.codigo] ?? const <Producto>[];
        for (final h in hijos) {
          padre.stockTotal += h.stockTotal;
        }
      }

    } catch (e) {
      debugPrint('[VentanaInventario._cargar] Error: $e');
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text('Error al cargar inventario: $e'),
          backgroundColor: AppColors.statusRed,
          duration: const Duration(seconds: 4)));
    } finally {
      if (mounted) setState(() => _cargando = false);
    }
  }

  /// Cantidad de subproductos (variantes) que tiene un padre.
  int _cantidadVariantes(String codigoPadre) {
    return _productos
        .where((p) => p.productoPadreCodigo == codigoPadre)
        .length;
  }

  List<Producto> get _filtrados => _productos.where((p) {
    // EXCLUIR subproductos del listado — solo se muestran los padres.
    // El padre suma el stock de sus variantes (ver PASO 4 de _cargar).
    if (p.productoPadreCodigo.isNotEmpty) return false;

    final matchQuery = _query.isEmpty ||
        p.nombre.toLowerCase().contains(_query.toLowerCase()) ||
        p.codigo.toLowerCase().contains(_query.toLowerCase()) ||
        p.marca.toLowerCase().contains(_query.toLowerCase());
    final matchCat = _filtroCategoria == 'Todos' || p.categoria == _filtroCategoria;
    return matchQuery && matchCat;
  }).toList();

  Widget _buildTotalInfo(String label, String value, Color valueColor) => Column(children: [
    Text(label, style: const TextStyle(color: Colors.white70, fontSize: 10)),
    Text(value, style: TextStyle(color: valueColor, fontSize: 18, fontWeight: FontWeight.bold)),
  ]);

  @override
  Widget build(BuildContext context) {
    final filtrados = _filtrados;
    final categorias = ['Todos', ...{ for (var p in _productos) p.categoria }];
    double totalCosto = filtrados.fold(0, (sum, p) => sum + (p.precioCosto * p.stockTotal));
    double totalVenta = filtrados.fold(0, (sum, p) => sum + (p.precioVenta * p.stockTotal));

    return Scaffold(
      appBar: AppBar(
        title: const Text("Inventario General"),
        actions: [IconButton(icon: const Icon(Icons.refresh), tooltip: "Actualizar", onPressed: _cargar)],
      ),
      body: Column(children: [
        // Banner KPI
        Container(
          padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 12),
          color: AppColors.royalBlue,
          child: Row(mainAxisAlignment: MainAxisAlignment.spaceAround, children: [
            _buildTotalInfo("COSTO TOTAL", formatCurrency(totalCosto), Colors.white),
            Container(width: 1, height: 40, color: Colors.white24),
            _buildTotalInfo("VENTA PROYECTADA", formatCurrency(totalVenta), AppColors.statusYellow),
            Container(width: 1, height: 40, color: Colors.white24),
            _buildTotalInfo("PRODUCTOS", "${filtrados.length}", Colors.white70),
          ]),
        ),
        // Búsqueda + filtros
        Container(
          color: Colors.white,
          padding: const EdgeInsets.fromLTRB(12, 10, 12, 0),
          child: Column(children: [
            TextField(
              decoration: InputDecoration(
                hintText: "Buscar por nombre, código o marca...",
                prefixIcon: const Icon(Icons.search, color: AppColors.primaryBlue),
                suffixIcon: _query.isNotEmpty
                  ? IconButton(icon: const Icon(Icons.clear, size: 18), onPressed: () => setState(() => _query = ''))
                  : null,
                filled: true, fillColor: AppColors.surfaceGrey,
                border: OutlineInputBorder(borderRadius: BorderRadius.circular(12), borderSide: BorderSide.none),
                contentPadding: const EdgeInsets.symmetric(vertical: 0, horizontal: 16),
              ),
              onChanged: (v) => setState(() => _query = v),
            ),
            const SizedBox(height: 8),
            SizedBox(height: 34, child: ListView(scrollDirection: Axis.horizontal, children: [
              ...categorias.map((cat) => Padding(
                padding: const EdgeInsets.only(right: 8),
                child: FilterChip(
                  label: Text(cat, style: const TextStyle(fontSize: 12)),
                  selected: _filtroCategoria == cat,
                  onSelected: (_) => setState(() => _filtroCategoria = cat),
                  selectedColor: AppColors.primaryBlue.withValues(alpha: 0.15),
                  checkmarkColor: AppColors.primaryBlue,
                ),
              )),
            ])),
            const SizedBox(height: 8),
          ]),
        ),
        if (_cargando)
          const Expanded(child: Center(child: CircularProgressIndicator()))
        else if (filtrados.isEmpty)
          const Expanded(child: EmptyState(mensaje: "No se encontraron productos.", icono: Icons.inventory_2_outlined))
        else
          Expanded(child: RefreshIndicator(
            onRefresh: _cargar,
            child: ListView.builder(
              padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
              itemCount: filtrados.length,
              itemBuilder: (c, i) {
                final p = filtrados[i];
                final stockColor = p.stockTotal >= 3
                    ? AppColors.statusGreen
                    : p.stockTotal >= 1
                        ? AppColors.statusOrange
                        : AppColors.statusRed;
                final stockLabel = p.stockTotal == 0
                    ? "Sin stock"
                    : p.stockTotal == 1 ? "Último" : "En stock";
                // Cantidad de variantes (subproductos) del padre, para
                // mostrar un badge informativo en la tile.
                final numVariantes = _cantidadVariantes(p.codigo);

                return Card(
                  margin: const EdgeInsets.only(bottom: 8),
                  shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(12)),
                  elevation: 1,
                  child: Padding(
                    padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 10),
                    child: Row(children: [
                      // ── Ícono categoría ──────────────────────
                      Container(
                        width: 44, height: 44,
                        decoration: BoxDecoration(
                          color: AppColors.royalBlue.withValues(alpha: 0.08),
                          borderRadius: BorderRadius.circular(10),
                        ),
                        child: Icon(
                          p.categoria == 'Telefono' ? Icons.phone_android
                            : p.categoria == 'Televisor' ? Icons.tv_outlined
                            : Icons.extension_outlined,
                          color: AppColors.royalBlue, size: 22),
                      ),
                      const SizedBox(width: 12),

                      // ── Info del producto ────────────────────
                      Expanded(child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: [
                          Row(children: [
                            Expanded(child: Text(p.nombre,
                              style: const TextStyle(fontWeight: FontWeight.w600,
                                color: AppColors.textPrimary, fontSize: 14))),
                            // Badge: cuántas variantes tiene este producto
                            if (numVariantes > 0) ...[
                              const SizedBox(width: 6),
                              Container(
                                padding: const EdgeInsets.symmetric(
                                    horizontal: 8, vertical: 3),
                                decoration: BoxDecoration(
                                  color: AppColors.brandBlue
                                      .withValues(alpha: 0.12),
                                  borderRadius: BorderRadius.circular(10),
                                  border: Border.all(
                                      color: AppColors.brandBlue
                                          .withValues(alpha: 0.3)),
                                ),
                                child: Row(
                                    mainAxisSize: MainAxisSize.min,
                                    children: [
                                  const Icon(Icons.account_tree_outlined,
                                      size: 12,
                                      color: AppColors.brandBlue),
                                  const SizedBox(width: 3),
                                  Text(
                                      "$numVariantes "
                                      "${numVariantes == 1 ? 'variante' : 'variantes'}",
                                      style: const TextStyle(
                                          fontSize: 10,
                                          fontWeight: FontWeight.w700,
                                          color: AppColors.brandBlue)),
                                ]),
                              ),
                            ],
                          ]),
                          const SizedBox(height: 2),
                          Text("${p.codigo} · ${p.categoria} · ${p.marca}",
                            style: const TextStyle(fontSize: 11, color: AppColors.textSecondary)),
                          const SizedBox(height: 4),
                          Row(children: [
                            Text("Costo: ${formatCurrency(p.precioCosto)}",
                              style: const TextStyle(fontSize: 11, color: AppColors.textSecondary)),
                            const SizedBox(width: 8),
                            Text("Venta: ${formatCurrency(p.precioVenta)}",
                              style: const TextStyle(fontSize: 11,
                                color: AppColors.primaryBlue, fontWeight: FontWeight.w500)),
                          ]),
                        ],
                      )),

                      // ── STOCK DESTACADO ──────────────────────
                      Column(mainAxisAlignment: MainAxisAlignment.center, children: [
                        Container(
                          width: 54,
                          padding: const EdgeInsets.symmetric(vertical: 6),
                          decoration: BoxDecoration(
                            color: stockColor,
                            borderRadius: BorderRadius.circular(10),
                          ),
                          child: Column(children: [
                            Text("${p.stockTotal}",
                              textAlign: TextAlign.center,
                              style: const TextStyle(fontWeight: FontWeight.bold,
                                fontSize: 22, color: Colors.white, height: 1.1)),
                            Text("uds", textAlign: TextAlign.center,
                              style: const TextStyle(fontSize: 9,
                                color: Colors.white70, letterSpacing: 0.5)),
                          ]),
                        ),
                        const SizedBox(height: 3),
                        Text(stockLabel,
                          style: TextStyle(fontSize: 9,
                            fontWeight: FontWeight.w600, color: stockColor)),
                      ]),
                      const SizedBox(width: 6),

                      // ── Botón editar ─────────────────────────
                      IconButton(
                        icon: const Icon(Icons.edit_outlined,
                          color: AppColors.primaryBlue, size: 20),
                        padding: EdgeInsets.zero,
                        constraints: const BoxConstraints(),
                        onPressed: () async {
                          await Navigator.push(context, MaterialPageRoute(
                            builder: (c) => FormularioProducto(productoAEditar: p)));
                          if (mounted) _cargar();
                        }),
                    ]),
                  ),
                );
              },
            ),
          )),
      ]),
      floatingActionButton: FloatingActionButton.extended(
        onPressed: () async {
          await Navigator.push(context, MaterialPageRoute(builder: (c) => const FormularioProducto()));
          if (mounted) _cargar();
        },
        icon: const Icon(Icons.add, color: Colors.white),
        label: const Text("Nuevo Producto", style: TextStyle(color: Colors.white)),
      ),
    );
  }
}

// ============================================================
//  FORMULARIO PRODUCTO — guarda en la API
// ============================================================
class FormularioProducto extends StatefulWidget {
  final Producto? productoAEditar;
  const FormularioProducto({super.key, this.productoAEditar});
  @override State<FormularioProducto> createState() => _FormularioProductoState();
}

class _FormularioProductoState extends State<FormularioProducto> {
  late TextEditingController _cod, _nom, _marca, _modelo, _prov, _pc, _pv, _cant, _imeiInput;
  late String _categoria;
  String _colorSel = "";
  List<String> _imeisTemporales = [];
  /// Variantes (subproductos) que el usuario agrega DURANTE la creación
  /// del producto principal. Quedan en memoria hasta que se guarde el
  /// padre — después se persisten todas en cadena. Al editar, este
  /// arreglo no se usa (las variantes se persisten directamente).
  final List<Producto> _variantesPendientes = [];

  // Marcas conocidas para el autocompletado
  static const _marcasSugeridas = [
    "Apple","Samsung","Xiaomi","Motorola","Huawei","OPPO","Vivo",
    "OnePlus","Realme","Nokia","LG","Sony","ZTE","Alcatel","Honor",
  ];

  @override
  void initState() {
    super.initState();
    final p = widget.productoAEditar;
    _cod      = TextEditingController(text: p?.codigo ?? "");
    _nom      = TextEditingController(text: p?.nombre ?? "");
    _marca    = TextEditingController(text: p?.marca != "Genérico" ? (p?.marca ?? "") : "");
    _modelo   = TextEditingController(text: p?.modelo != "N/A" ? (p?.modelo ?? "") : "");
    _prov     = TextEditingController(text: "");
    _pc       = TextEditingController(text: p?.precioCosto.toString() ?? "");
    _pv       = TextEditingController(text: p?.precioVenta.toString() ?? "");
    _cant     = TextEditingController(text: p?.stockManual.toString() ?? "0");
    _imeiInput = TextEditingController();
    _categoria = p?.categoria ?? "Accesorio";
    if (p != null && p.categoria == "Telefono") {
      _imeisTemporales = stockImeiGlobal
          .where((i) => i.producto.codigo == p.codigo && !i.vendido)
          .map((i) => i.imei).toList();
    }
  }

  @override
  void dispose() {
    _cod.dispose(); _nom.dispose(); _marca.dispose(); _modelo.dispose();
    _prov.dispose(); _pc.dispose(); _pv.dispose(); _cant.dispose();
    _imeiInput.dispose();
    super.dispose();
  }

  /// Abre un dialog para gestionar las categorías de productos.
  /// Permite agregar, renombrar y eliminar. Al cerrar, la lista
  /// editada queda guardada en SharedPreferences vía
  /// `CategoriasProductos.guardar()`. Si se agrega una categoría
  /// nueva, se sincroniza también una nueva categoría de comisión.
  Future<void> _abrirGestorCategorias() async {
    final nuevoCtrl = TextEditingController();
    await showDialog<void>(
      context: context,
      builder: (ctx) => StatefulBuilder(builder: (ctx, setS) {
        return AlertDialog(
          title: const Row(children: [
            Icon(Icons.category, color: AppColors.brandBlue),
            SizedBox(width: 8),
            Text("Gestionar categorías"),
          ]),
          content: SizedBox(
            width: 420,
            child: Column(mainAxisSize: MainAxisSize.min, children: [
              const Text(
                "Las categorías que crees aquí estarán disponibles "
                "al registrar productos. Al agregar una nueva, también "
                "se crea automáticamente la categoría equivalente en "
                "Comisiones (con tarifa \$0 — la configuras desde la "
                "ventana de Comisiones).",
                style: TextStyle(fontSize: 12,
                    color: AppColors.textSecondary)),
              const SizedBox(height: 12),
              Row(children: [
                Expanded(child: TextField(
                  controller: nuevoCtrl,
                  decoration: const InputDecoration(
                      labelText: "Nueva categoría",
                      isDense: true,
                      border: OutlineInputBorder()),
                )),
                const SizedBox(width: 8),
                FilledButton.icon(
                  icon: const Icon(Icons.add, size: 18),
                  label: const Text("Agregar"),
                  onPressed: () async {
                    final nombre = nuevoCtrl.text.trim();
                    if (nombre.isEmpty) return;
                    final ok = await CategoriasProductos.agregar(nombre);
                    if (ok) {
                      // Crear categoría de comisión equivalente si no existe
                      await _sincronizarCategoriaComision(nombre);
                      nuevoCtrl.clear();
                      setS(() {});
                    } else {
                      if (ctx.mounted) {
                        ScaffoldMessenger.of(ctx).showSnackBar(
                          const SnackBar(content: Text(
                              "Esa categoría ya existe")));
                      }
                    }
                  },
                ),
              ]),
              const SizedBox(height: 12),
              const Divider(),
              ConstrainedBox(
                constraints: const BoxConstraints(maxHeight: 320),
                child: ListView.separated(
                  shrinkWrap: true,
                  itemCount: CategoriasProductos.lista.length,
                  separatorBuilder: (_,__) => const Divider(height: 1),
                  itemBuilder: (_, i) {
                    final cat = CategoriasProductos.lista[i];
                    return ListTile(
                      dense: true,
                      leading: const Icon(Icons.label_outline),
                      title: Text(cat),
                      trailing: Row(mainAxisSize: MainAxisSize.min, children: [
                        IconButton(
                          icon: const Icon(Icons.edit_outlined, size: 18),
                          tooltip: "Renombrar",
                          onPressed: () async {
                            final ctrl = TextEditingController(text: cat);
                            final nuevo = await showDialog<String>(
                              context: ctx,
                              builder: (c) => AlertDialog(
                                title: const Text("Renombrar"),
                                content: TextField(controller: ctrl,
                                    autofocus: true),
                                actions: [
                                  TextButton(
                                    onPressed: () => Navigator.pop(c),
                                    child: const Text("Cancelar")),
                                  FilledButton(
                                    onPressed: () => Navigator.pop(c,
                                        ctrl.text.trim()),
                                    child: const Text("Guardar")),
                                ],
                              ),
                            );
                            if (nuevo != null && nuevo.isNotEmpty
                                && nuevo != cat) {
                              await CategoriasProductos.renombrar(cat, nuevo);
                              setS(() {});
                            }
                          },
                        ),
                        IconButton(
                          icon: const Icon(Icons.delete_outline,
                              size: 18, color: Colors.red),
                          tooltip: "Eliminar",
                          onPressed: () async {
                            final ok = await showDialog<bool>(
                              context: ctx,
                              builder: (c) => AlertDialog(
                                title: const Text("Eliminar categoría"),
                                content: Text(
                                    "¿Eliminar la categoría \"$cat\"?\n"
                                    "Los productos con esta categoría no "
                                    "se eliminan, pero quedarán con la "
                                    "categoría asignada."),
                                actions: [
                                  TextButton(
                                    onPressed: () => Navigator.pop(c, false),
                                    child: const Text("Cancelar")),
                                  FilledButton(
                                    style: FilledButton.styleFrom(
                                        backgroundColor: Colors.red),
                                    onPressed: () => Navigator.pop(c, true),
                                    child: const Text("Eliminar")),
                                ],
                              ),
                            );
                            if (ok == true) {
                              await CategoriasProductos.eliminar(cat);
                              setS(() {});
                            }
                          },
                        ),
                      ]),
                    );
                  },
                ),
              ),
            ]),
          ),
          actions: [
            FilledButton(
              onPressed: () => Navigator.pop(ctx),
              child: const Text("Cerrar")),
          ],
        );
      }),
    );
  }

  /// Cuando se agrega una nueva categoría de producto, también
  /// crea la entrada equivalente en categorías de comisión (si no
  /// existía ya). El admin después configura la tarifa desde la
  /// ventana de Comisiones.
  Future<void> _sincronizarCategoriaComision(String nombre) async {
    // ¿Ya existe una comisión con ese mismo nombre?
    final yaExiste = ConfigSistema.categoriasComision.any(
        (c) => c.nombre.toLowerCase().trim()
            == nombre.toLowerCase().trim());
    if (yaExiste) return;
    // Crear con tarifa 0 — el admin la ajustará
    ConfigSistema.categoriasComision.add(CategoriaComision(
      id: 'cat_${DateTime.now().millisecondsSinceEpoch}',
      nombre: nombre,
      tarifaUSD: 0.0,
      tipoConteo: TipoConteoComision.categoriaProducto,
      valorConteo: nombre,
      iconoKey: 'work',
      colorHex: '#1565C0',
    ));
    await ConfigSistema.guardarCategoriasComision();
  }

  @override
  Widget build(BuildContext context) {
    final esEdicion = widget.productoAEditar != null;
    final esTelefono = _categoria == "Telefono";
    // Si la categoría actual no está en la lista dinámica (caso raro al
    // editar un producto viejo), la agregamos al menos en el dropdown.
    final cats = List<String>.from(CategoriasProductos.lista);
    if (!cats.contains(_categoria)) cats.add(_categoria);
    return Scaffold(
      appBar: AppBar(
        title: Text(esEdicion ? "Editar Producto" : "Nuevo Producto"),
        actions: [
          IconButton(
            icon: const Icon(Icons.tune),
            tooltip: "Gestionar categorías",
