              controller: _cod,
              decoration: const InputDecoration(
                  labelText: "Código SKU",
                  prefixIcon: Icon(Icons.qr_code_2)),
            )),
            const SizedBox(width: 8),
            // Botón para escanear código de barras directamente al SKU
            IconButton.filledTonal(
              icon: const Icon(Icons.qr_code_scanner),
              tooltip: "Escanear código de barras",
              onPressed: () async {
                await Navigator.push(context, MaterialPageRoute(
                  builder: (_) => ScannerPage(
                    onDetect: (code) {
                      _cod.text = code;
                    }),
                ));
                if (mounted) setState(() {});
              },
            ),
          ]),
          const SizedBox(height: 12),

          // ── Marca (obligatoria para teléfonos, con autocompletado) ──
          if (esTelefono) ...[
            Autocomplete<String>(
              optionsBuilder: (tv) {
                if (tv.text.isEmpty) return _marcasSugeridas;
                return _marcasSugeridas.where(
                  (m) => m.toLowerCase().contains(tv.text.toLowerCase()));
              },
              fieldViewBuilder: (ctx, ctrl, node, onSub) {
                // Vincular con _marca al seleccionar
                return TextFormField(
                  controller: _marca,
                  focusNode: node,
                  onChanged: (_) => setState(() {}),
                  decoration: InputDecoration(
                    labelText: "Marca *",
                    hintText: "Ej: Apple, Samsung, Xiaomi...",
                    prefixIcon: const Icon(Icons.business),
                    errorText: _marca.text.trim().isEmpty ? "Obligatorio para teléfonos" : null,
                  ),
                );
              },
              onSelected: (sel) => setState(() { _marca.text = sel; }),
              displayStringForOption: (s) => s,
            ),
            const SizedBox(height: 12),

            // ── Modelo ──
            TextField(
              controller: _modelo,
              onChanged: (_) => setState(() {}),
              decoration: const InputDecoration(
                labelText: "Modelo",
                hintText: "Ej: iPhone 15 Pro, Galaxy S24 Ultra...",
                prefixIcon: Icon(Icons.phone_android)),
            ),
            const SizedBox(height: 12),
          ],

          // ── Código SKU ──
          TextField(
            controller: _cod,
            decoration: const InputDecoration(
              labelText: 'Código (SKU)',
              prefixIcon: Icon(Icons.qr_code)),
            readOnly: esEdicion),
          const SizedBox(height: 8),

          // ── Nombre (con sugerencia automática marca+modelo) ──
          TextField(
            controller: _nom,
            onChanged: (_) => setState(() {}),
            decoration: InputDecoration(
              labelText: 'Nombre del Producto',
              prefixIcon: const Icon(Icons.label),
              suffixIcon: esTelefono && _marca.text.isNotEmpty && _modelo.text.isNotEmpty
                  ? IconButton(
                      icon: const Icon(Icons.auto_fix_high, color: AppColors.primaryBlue),
                      tooltip: "Completar con Marca + Modelo",
                      onPressed: () => setState(() =>
                          _nom.text = "${_marca.text.trim()} ${_modelo.text.trim()}"))
                  : null,
              helperText: esTelefono && _marca.text.isNotEmpty && _modelo.text.isNotEmpty
                  ? "💡 Toca ✨ para usar: ${_marca.text.trim()} ${_modelo.text.trim()}"
                  : null),
          ),
          const SizedBox(height: 8),

          // ── Precios ──
          Row(children: [
            Expanded(child: TextField(
              controller: _pc,
              decoration: const InputDecoration(
                labelText: 'Costo \$', prefixIcon: Icon(Icons.attach_money)),
              keyboardType: TextInputType.numberWithOptions(decimal: true))),
            const SizedBox(width: 10),
            Expanded(child: TextField(
              controller: _pv,
              decoration: const InputDecoration(
                labelText: 'Precio Venta \$', prefixIcon: Icon(Icons.sell)),
              keyboardType: TextInputType.numberWithOptions(decimal: true))),
          ]),
          const SizedBox(height: 8),

          if (esTelefono) ...[
            // ── Proveedor ──
            TextField(
              controller: _prov,
              decoration: const InputDecoration(
                labelText: "Proveedor",
                hintText: "Nombre del proveedor o distribuidor",
                prefixIcon: Icon(Icons.local_shipping)),
            ),
            const SizedBox(height: 20),

            // ── Gestión de IMEIs ──
            Row(children: [
              const Icon(Icons.smartphone, color: AppColors.primaryBlue),
              const SizedBox(width: 8),
              const Text("IMEIs de entrada", style: TextStyle(fontWeight: FontWeight.bold, fontSize: 15)),
              const Spacer(),
              if (_imeisTemporales.isNotEmpty)
                Chip(
                  backgroundColor: AppColors.primaryBlue.withValues(alpha: 0.12),
                  label: Text("${_imeisTemporales.length} equipo(s)",
                    style: const TextStyle(color: AppColors.primaryBlue, fontWeight: FontWeight.bold, fontSize: 12))),
            ]),
            const SizedBox(height: 8),
            Row(children: [
              Expanded(child: TextField(
                controller: _imeiInput,
                keyboardType: TextInputType.number,
                decoration: const InputDecoration(
                  hintText: "Ingrese o escanee IMEI",
                  prefixIcon: Icon(Icons.pin), isDense: true),
                onSubmitted: (_) => _agregarImei())),
              IconButton(
                icon: const Icon(Icons.add_box, color: Colors.green, size: 34),
                tooltip: "Agregar IMEI",
                onPressed: _agregarImei),
              IconButton(
                icon: const Icon(Icons.qr_code_scanner, color: AppColors.primaryBlue, size: 28),
                tooltip: "Escanear",
                onPressed: () => Navigator.push(context,
                  MaterialPageRoute(builder: (_) => ScannerPage(onDetect: (c) {
                    setState(() { if (!_imeisTemporales.contains(c)) _imeisTemporales.add(c); });
                  })))),
            ]),
            if (_imeisTemporales.isNotEmpty) ...[
              const SizedBox(height: 10),
              Wrap(spacing: 8, runSpacing: 4,
                children: _imeisTemporales.map((imei) => Chip(
                  label: Text(imei, style: const TextStyle(fontSize: 12)),
                  deleteIcon: const Icon(Icons.close, size: 16),
                  onDeleted: () => setState(() => _imeisTemporales.remove(imei)),
                )).toList()),
            ],
          ] else ...[
            TextField(
              controller: _cant,
              decoration: const InputDecoration(
                labelText: 'Cantidad en Stock', prefixIcon: Icon(Icons.inventory)),
              keyboardType: TextInputType.number),
          ],
          const SizedBox(height: 24),

          // ── Subproductos (variantes con SKU propio) ───────────
          // Al EDITAR: las variantes se persisten directamente contra
          // el backend (necesitamos el código del padre, que ya existe).
          // Al CREAR: las variantes se acumulan en _variantesPendientes
          // y se guardan en cadena DESPUÉS de crear el padre.
          if (esEdicion && widget.productoAEditar != null) ...[
            _seccionSubproductos(widget.productoAEditar!),
            const SizedBox(height: 24),
          ] else ...[
            _seccionVariantesPendientes(),
            const SizedBox(height: 24),
          ],

          ElevatedButton(
            style: ElevatedButton.styleFrom(
              backgroundColor: AppColors.royalBlue, padding: const EdgeInsets.all(15)),
            onPressed: _guardar,
            child: Text(esEdicion ? "ACTUALIZAR PRODUCTO" : "GUARDAR PRODUCTO",
              style: const TextStyle(color: Colors.white, fontSize: 15))),
        ]),
      ),
    );
  }

  /// Sección que lista las variantes (subproductos) del producto y
  /// permite agregar/eliminar. Cada variante tiene su propio SKU
  /// independiente y es buscable/escaneable como cualquier producto.
  Widget _seccionSubproductos(Producto padre) {
    final hijos = catalogoGlobal
        .where((p) => p.productoPadreCodigo == padre.codigo)
        .toList();
    return Container(
      padding: const EdgeInsets.all(12),
      decoration: BoxDecoration(
        color: AppColors.surfaceTintBlue,
        borderRadius: BorderRadius.circular(10),
        border: Border.all(color: AppColors.brandBlue.withValues(alpha: 0.15)),
      ),
      child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
        Row(children: [
          const Icon(Icons.account_tree_outlined,
              color: AppColors.brandBlue, size: 20),
          const SizedBox(width: 8),
          const Expanded(child: Text("Subproductos / variantes",
              style: TextStyle(
                  fontWeight: FontWeight.w700, fontSize: 14))),
          OutlinedButton.icon(
            icon: const Icon(Icons.add, size: 16),
            label: const Text("Agregar variante"),
            onPressed: () => _dialogNuevoSubproducto(padre),
          ),
        ]),
        const SizedBox(height: 4),
        const Text(
          "Variantes del producto (color/almacenamiento/etc), cada "
          "una con su propio SKU escaneable.",
          style: TextStyle(fontSize: 11, color: AppColors.textSecondary)),
        const SizedBox(height: 8),
        if (hijos.isEmpty)
          const Padding(
            padding: EdgeInsets.symmetric(vertical: 8),
            child: Text("Sin variantes registradas.",
                style: TextStyle(
                    color: AppColors.textSecondary,
                    fontStyle: FontStyle.italic, fontSize: 12)),
          )
        else
          ...hijos.map((h) => Container(
            margin: const EdgeInsets.only(bottom: 6),
            padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 8),
            decoration: BoxDecoration(
              color: Colors.white,
              borderRadius: BorderRadius.circular(8),
              border: Border.all(color: Colors.grey.shade300),
            ),
            child: Row(children: [
              const Icon(Icons.qr_code_2,
                  color: AppColors.brandBlue, size: 18),
              const SizedBox(width: 8),
              Expanded(child: Column(
                crossAxisAlignment: CrossAxisAlignment.start, children: [
                  Text(h.variante.isEmpty ? h.nombre : h.variante,
                      style: const TextStyle(
                          fontWeight: FontWeight.w600, fontSize: 13)),
                  Text("SKU: ${h.codigo}",
                      style: const TextStyle(
                          fontSize: 11,
                          color: AppColors.textSecondary)),
                ])),
              Text("\$${h.precioVenta.toStringAsFixed(2)}",
                  style: const TextStyle(
                      fontWeight: FontWeight.w600,
                      color: AppColors.brandBlue)),
              IconButton(
                icon: const Icon(Icons.delete_outline,
                    size: 18, color: Colors.red),
                tooltip: "Eliminar variante",
                onPressed: () => _eliminarSubproducto(h),
              ),
            ]),
          )),
      ]),
    );
  }

  /// Dialog para crear un subproducto. Hereda categoría/marca/modelo
  /// del padre y solo pide los datos propios de la variante.
  /// Sección de variantes para el modo CREACIÓN. Las variantes
  /// quedan en `_variantesPendientes` (memoria) y se guardan en
  /// cadena cuando el usuario pulse "GUARDAR PRODUCTO".
  Widget _seccionVariantesPendientes() {
    return Container(
      padding: const EdgeInsets.all(12),
      decoration: BoxDecoration(
        color: AppColors.surfaceTintBlue,
        borderRadius: BorderRadius.circular(10),
        border: Border.all(
            color: AppColors.brandBlue.withValues(alpha: 0.15)),
      ),
      child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
        Row(children: [
          const Icon(Icons.account_tree_outlined,
              color: AppColors.brandBlue, size: 20),
          const SizedBox(width: 8),
          const Expanded(child: Text("Subproductos / variantes",
              style: TextStyle(
                  fontWeight: FontWeight.w700, fontSize: 14))),
          OutlinedButton.icon(
            icon: const Icon(Icons.add, size: 16),
            label: const Text("Agregar variante"),
            onPressed: _dialogVariantePendiente,
          ),
        ]),
        const SizedBox(height: 4),
        const Text(
          "Variantes del mismo modelo con SKU propio (ej: color blanco, "
          "color negro, almacenamiento distinto). Se guardarán junto "
          "con el producto cuando pulses GUARDAR.",
          style: TextStyle(fontSize: 11, color: AppColors.textSecondary)),
        const SizedBox(height: 8),
        if (_variantesPendientes.isEmpty)
          const Padding(
            padding: EdgeInsets.symmetric(vertical: 8),
            child: Text("Sin variantes agregadas.",
                style: TextStyle(
                    color: AppColors.textSecondary,
                    fontStyle: FontStyle.italic, fontSize: 12)),
          )
        else
          ..._variantesPendientes.asMap().entries.map((entry) {
            final i = entry.key;
            final v = entry.value;
            return Container(
              margin: const EdgeInsets.only(bottom: 6),
              padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 8),
              decoration: BoxDecoration(
                color: Colors.white,
                borderRadius: BorderRadius.circular(8),
                border: Border.all(color: Colors.grey.shade300),
              ),
              child: Row(children: [
                const Icon(Icons.qr_code_2,
                    color: AppColors.brandBlue, size: 18),
                const SizedBox(width: 8),
                Expanded(child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start, children: [
                    Text(v.variante.isEmpty ? v.nombre : v.variante,
                        style: const TextStyle(
                            fontWeight: FontWeight.w600, fontSize: 13)),
                    Text("SKU: ${v.codigo}",
                        style: const TextStyle(
                            fontSize: 11,
                            color: AppColors.textSecondary)),
                  ])),
                Text("\$${v.precioVenta.toStringAsFixed(2)}",
                    style: const TextStyle(
                        fontWeight: FontWeight.w600,
                        color: AppColors.brandBlue)),
                IconButton(
                  icon: const Icon(Icons.delete_outline,
                      size: 18, color: Colors.red),
                  tooltip: "Quitar variante",
                  onPressed: () => setState(
                      () => _variantesPendientes.removeAt(i)),
                ),
              ]),
            );
          }),
      ]),
    );
  }

  /// Dialog para agregar una variante PENDIENTE (modo creación).
  /// No persiste al backend — solo la añade a _variantesPendientes.
  /// Hereda marca/modelo de los campos actuales del formulario.
  Future<void> _dialogVariantePendiente() async {
    final ctrlSku = TextEditingController();
    final ctrlVar = TextEditingController();
    final ctrlCant = TextEditingController(text: "0");
    // Precios SOLO de lectura — se muestran como info y al guardar
    // se leen DIRECTAMENTE de los campos del padre (_pc / _pv).
    final pcPadre = double.tryParse(_pc.text.trim()) ?? 0;
    final pvPadre = double.tryParse(_pv.text.trim()) ?? 0;

    await showDialog(
      context: context,
      builder: (ctx) => StatefulBuilder(builder: (ctx, setS) => AlertDialog(
        title: Text(
            "Nueva variante de ${_modelo.text.isEmpty ? 'producto' : _modelo.text}",
            style: const TextStyle(fontSize: 16)),
        content: SizedBox(
          width: 400,
          child: Column(mainAxisSize: MainAxisSize.min, children: [
            Row(children: [
              Expanded(child: TextField(
                controller: ctrlSku,
                decoration: const InputDecoration(
                  labelText: "Código SKU",
                  prefixIcon: Icon(Icons.qr_code_2),
                ))),
              const SizedBox(width: 6),
              IconButton.filledTonal(
                icon: const Icon(Icons.qr_code_scanner),
                tooltip: "Escanear",
                onPressed: () async {
                  await Navigator.push(ctx, MaterialPageRoute(
                    builder: (_) => ScannerPage(onDetect: (code) {
                      ctrlSku.text = code;
                    }),
                  ));
                  setS(() {});
                },
              ),
            ]),
            const SizedBox(height: 10),
            TextField(
              controller: ctrlVar,
              decoration: const InputDecoration(
                labelText: "Variante (ej. Color blanco 64GB)",
                prefixIcon: Icon(Icons.palette_outlined),
              )),
            const SizedBox(height: 10),
            TextField(
              controller: ctrlCant,
              keyboardType: TextInputType.number,
              decoration: const InputDecoration(
                labelText: "Stock",
                prefixIcon: Icon(Icons.inventory_2_outlined),
              )),
            const SizedBox(height: 12),
            // Aviso de que los precios se heredan del padre
            Container(
              padding: const EdgeInsets.all(10),
              decoration: BoxDecoration(
                color: AppColors.surfaceTintBlue,
                borderRadius: BorderRadius.circular(8),
                border: Border.all(
                    color: AppColors.brandBlue.withValues(alpha: 0.2)),
              ),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  const Row(children: [
                    Icon(Icons.info_outline,
                        size: 16, color: AppColors.brandBlue),
                    SizedBox(width: 6),
                    Text("Precios heredados del producto principal",
                        style: TextStyle(
                            fontSize: 12,
                            fontWeight: FontWeight.w700,
                            color: AppColors.brandBlue)),
                  ]),
                  const SizedBox(height: 6),
                  Row(children: [
                    Expanded(child: Text(
                        "P. Costo: \$${pcPadre.toStringAsFixed(2)}",
                        style: const TextStyle(fontSize: 12))),
                    Expanded(child: Text(
                        "P. Venta: \$${pvPadre.toStringAsFixed(2)}",
                        style: const TextStyle(fontSize: 12))),
                  ]),
                ],
              ),
            ),
          ]),
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(ctx),
            child: const Text("Cancelar")),
          FilledButton(
            onPressed: () {
              final sku = ctrlSku.text.trim();
              if (sku.isEmpty) {
                ScaffoldMessenger.of(ctx).showSnackBar(
                  const SnackBar(content: Text("El SKU es obligatorio")));
                return;
              }
              // Validar contra catálogo global Y contra otras variantes
              // pendientes (que aún no se han guardado).
              if (catalogoGlobal.any((p) => p.codigo == sku)
                  || _variantesPendientes.any((v) => v.codigo == sku)) {
                ScaffoldMessenger.of(ctx).showSnackBar(
                  const SnackBar(content: Text(
                      "Ya existe un producto/variante con ese SKU")));
                return;
              }
              final variante = ctrlVar.text.trim();
              // Los precios SE HEREDAN del padre. La fuente de verdad
              // son los campos del formulario (_pc / _pv) al momento
              // de _guardar — si el usuario cambia el precio del padre
              // antes de guardar, las variantes lo reflejarán.
              // Aquí guardamos los precios actuales como valor inicial;
              // en _guardar se sobreescriben con los del padre final.
              _variantesPendientes.add(Producto(
                codigo: sku,
                nombre: '${_nom.text.trim()} - $variante',
                categoria: _categoria,
                marca: _marca.text.trim(),
                modelo: _modelo.text.trim(),
                tipo: '',
                precioCosto: pcPadre,
                precioVenta: pvPadre,
                stockManual: int.tryParse(ctrlCant.text.trim()) ?? 0,
                productoPadreCodigo: '', // se asigna en _guardar
                variante: variante,
              ));
              Navigator.pop(ctx);
              setState(() {});
            },
            child: const Text("Agregar")),
        ],
      )),
    );
  }

  Future<void> _dialogNuevoSubproducto(Producto padre) async {
    final ctrlSku    = TextEditingController();
    final ctrlVar    = TextEditingController();
    final ctrlCant   = TextEditingController(text: "0");

    await showDialog(
      context: context,
      builder: (ctx) => StatefulBuilder(builder: (ctx, setS) => AlertDialog(
        title: Text("Nueva variante de ${padre.modelo}",
            style: const TextStyle(fontSize: 16)),
        content: SizedBox(
          width: 400,
          child: Column(mainAxisSize: MainAxisSize.min, children: [
            Row(children: [
              Expanded(child: TextField(
                controller: ctrlSku,
                decoration: const InputDecoration(
                  labelText: "Código SKU",
                  prefixIcon: Icon(Icons.qr_code_2),
                ))),
              const SizedBox(width: 6),
              IconButton.filledTonal(
                icon: const Icon(Icons.qr_code_scanner),
                tooltip: "Escanear",
                onPressed: () async {
                  await Navigator.push(ctx, MaterialPageRoute(
                    builder: (_) => ScannerPage(onDetect: (code) {
                      ctrlSku.text = code;
                    }),
                  ));
                  setS(() {});
                },
              ),
            ]),
            const SizedBox(height: 10),
            TextField(
              controller: ctrlVar,
              decoration: const InputDecoration(
                labelText: "Variante (ej. Color blanco 64GB)",
                prefixIcon: Icon(Icons.palette_outlined),
              )),
            const SizedBox(height: 10),
            TextField(
              controller: ctrlCant,
              keyboardType: TextInputType.number,
              decoration: const InputDecoration(
                labelText: "Stock",
                prefixIcon: Icon(Icons.inventory_2_outlined),
              )),
            const SizedBox(height: 12),
            // Aviso visual: precios heredados del padre
            Container(
              padding: const EdgeInsets.all(10),
              decoration: BoxDecoration(
                color: AppColors.surfaceTintBlue,
                borderRadius: BorderRadius.circular(8),
                border: Border.all(
                    color: AppColors.brandBlue.withValues(alpha: 0.2)),
              ),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  const Row(children: [
                    Icon(Icons.info_outline,
                        size: 16, color: AppColors.brandBlue),
                    SizedBox(width: 6),
                    Text("Precios heredados del producto principal",
                        style: TextStyle(
                            fontSize: 12,
                            fontWeight: FontWeight.w700,
                            color: AppColors.brandBlue)),
                  ]),
                  const SizedBox(height: 6),
                  Row(children: [
                    Expanded(child: Text(
                        "P. Costo: \$${padre.precioCosto.toStringAsFixed(2)}",
                        style: const TextStyle(fontSize: 12))),
                    Expanded(child: Text(
                        "P. Venta: \$${padre.precioVenta.toStringAsFixed(2)}",
                        style: const TextStyle(fontSize: 12))),
                  ]),
                ],
              ),
            ),
          ]),
        ),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(ctx),
            child: const Text("Cancelar")),
          FilledButton(
            onPressed: () async {
              final sku = ctrlSku.text.trim();
              if (sku.isEmpty) {
                ScaffoldMessenger.of(ctx).showSnackBar(
                  const SnackBar(content: Text("El SKU es obligatorio")));
                return;
              }
              if (catalogoGlobal.any((p) => p.codigo == sku)) {
                ScaffoldMessenger.of(ctx).showSnackBar(
                  const SnackBar(content: Text("Ya existe un producto con ese SKU")));
                return;
              }
              final variante = ctrlVar.text.trim();
              final sub = Producto(
                codigo: sku,
                nombre: '${padre.nombre} - $variante',
                categoria: padre.categoria,
                marca: padre.marca,
                modelo: padre.modelo,
                tipo: padre.tipo,
                // Precios SIEMPRE heredados del padre
                precioCosto: padre.precioCosto,
                precioVenta: padre.precioVenta,
