              );
              try {
                await _Api.post('productos', sub.toMap());
                catalogoGlobal.add(sub);
                if (ctx.mounted) Navigator.pop(ctx);
                if (mounted) setState(() {});
              } catch (e) {
                if (ctx.mounted) ScaffoldMessenger.of(ctx).showSnackBar(
                    SnackBar(content: Text("Error: $e")));
              }
            },
            child: const Text("Guardar variante")),
        ],
      )),
    );
  }

  Future<void> _eliminarSubproducto(Producto sub) async {
    final ok = await showDialog<bool>(
      context: context,
      builder: (c) => AlertDialog(
        title: const Text("Eliminar variante"),
        content: Text("¿Eliminar la variante \"${sub.variante.isEmpty ? sub.nombre : sub.variante}\"?"),
        actions: [
          TextButton(onPressed: () => Navigator.pop(c, false),
              child: const Text("Cancelar")),
          FilledButton(
            style: FilledButton.styleFrom(backgroundColor: Colors.red),
            onPressed: () => Navigator.pop(c, true),
            child: const Text("Eliminar")),
        ],
      ),
    );
    if (ok != true) return;
    try {
      // Buscar por código en la API (el endpoint usa id, no codigo)
      final raw = await _Api.get('productos');
      final fila = (raw as List).cast<Map<String,dynamic>>().firstWhere(
          (m) => m['codigo'] == sub.codigo,
          orElse: () => <String,dynamic>{});
      if (fila['id'] != null) {
        await _Api.delete('productos', fila['id'].toString());
      }
      catalogoGlobal.removeWhere((p) => p.codigo == sub.codigo);
      if (mounted) setState(() {});
    } catch (e) {
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(content: Text("Error: $e")));
    }
  }

  void _agregarImei() {
    final imei = _imeiInput.text.trim();
    if (imei.isEmpty) return;
    if (_imeisTemporales.contains(imei)) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text("Este IMEI ya está en la lista")));
      return;
    }
    setState(() { _imeisTemporales.add(imei); _imeiInput.clear(); });
  }

  Future<void> _guardar() async {
    final esEdicion = widget.productoAEditar != null;
    final esTelefono = _categoria == "Telefono";

    if (_cod.text.trim().isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text("Ingrese el código SKU")));
      return;
    }
    if (_nom.text.trim().isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text("Ingrese el nombre del producto")));
      return;
    }
    if (esTelefono && _marca.text.trim().isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: const Text("La marca es obligatoria para teléfonos"),
        backgroundColor: Colors.orange[700]));
      return;
    }
    if (esTelefono && _imeisTemporales.isEmpty && !esEdicion) {
      final continuar = await showDialog<bool>(
        context: context,
        builder: (ctx) => AlertDialog(
          title: const Text("Sin IMEIs"),
          content: const Text("No ingresó ningún IMEI. ¿Desea guardar el producto sin stock?"),
          actions: [
            TextButton(onPressed: () => Navigator.pop(ctx, false), child: const Text("Agregar IMEIs")),
            ElevatedButton(onPressed: () => Navigator.pop(ctx, true), child: const Text("Guardar igual")),
          ]));
      if (continuar != true || !mounted) return;
    }

    final marcaFinal  = esTelefono ? _marca.text.trim() : "General";
    final modeloFinal = esTelefono
        ? (_modelo.text.trim().isEmpty ? _nom.text.trim() : _modelo.text.trim())
        : "N/A";

    final prod = Producto(
      codigo: _cod.text.trim(), nombre: _nom.text.trim(), tipo: _nom.text.trim(),
      categoria: _categoria, marca: marcaFinal, modelo: modeloFinal,
      precioCosto: double.tryParse(_pc.text) ?? 0,
      precioVenta: double.tryParse(_pv.text) ?? 0,
      stockManual: int.tryParse(_cant.text) ?? 0);

    try {
      if (esEdicion) {
        await _Api.put('productos', widget.productoAEditar!.codigo, prod.toMap());
      } else {
        await _Api.post('productos', prod.toMap());
      }

      // ── Persistir variantes pendientes (solo en modo creación) ──
      // Cada variante se guarda como un Producto independiente con
      // su propio SKU, apuntando al padre vía productoPadreCodigo.
      if (!esEdicion && _variantesPendientes.isNotEmpty) {
        int okVar = 0;
        int failVar = 0;
        for (final v in _variantesPendientes) {
          try {
            // Heredar marca/modelo/categoría del padre que se acaba
            // de crear (por si el usuario los cambió tras agregar
            // variantes). Asignar productoPadreCodigo correctamente.
            final variante = Producto(
              codigo: v.codigo,
              nombre: '${prod.nombre} - ${v.variante}',
              categoria: prod.categoria,
              marca: prod.marca,
              modelo: prod.modelo,
              tipo: prod.tipo,
              precioCosto: prod.precioCosto, // hereda del padre
              precioVenta: prod.precioVenta, // hereda del padre
              stockManual: v.stockManual,
              productoPadreCodigo: prod.codigo,
              variante: v.variante,
            );
            await _Api.post('productos', variante.toMap());
            catalogoGlobal.add(variante);
            okVar++;
          } catch (e) {
            debugPrint('Variante ${v.codigo} error: $e');
            failVar++;
          }
        }
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(SnackBar(
            content: Text(failVar == 0
                ? "✅ Producto + $okVar variante(s) guardadas"
                : "⚠ Producto guardado, $okVar variantes OK, $failVar fallaron"),
            backgroundColor: failVar == 0
                ? AppColors.statusGreen : AppColors.statusOrange));
        }
      }

      if (esTelefono && _imeisTemporales.isNotEmpty) {
        final proveedor = _prov.text.trim().isEmpty ? "Sin especificar" : _prov.text.trim();
        int guardados = 0;
        for (final imei in _imeisTemporales) {
          try {
            await _Api.post('stock_imei', {
              'imei': imei, 'producto_codigo': prod.codigo,
              'fecha_ingreso': obtenerFechaActual(),
              'proveedor': proveedor, 'color': 'N/A',
              'ubicacion': ConfigSistema.ubicacionesAlmacen.isNotEmpty
                  ? ConfigSistema.ubicacionesAlmacen.first : 'Almacen',
              'vendido': 0,
            });
            guardados++;
          } catch (e) { debugPrint('IMEI $imei error: $e'); }
        }
        if (!mounted) return;
        ScaffoldMessenger.of(context).showSnackBar(SnackBar(
          content: Text("✅ ${prod.nombre} guardado con $guardados IMEI(s)"),
          backgroundColor: AppColors.statusGreen));
      }

      if (!mounted) return;
      Navigator.pop(context);
    } catch (e) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Text("Error al guardar: $e"), backgroundColor: AppColors.statusRed));
    }
  }
}

// ============================================================
//  BUSCADOR IMEI — carga desde la API
// ============================================================
class VentanaImei extends StatefulWidget {
  const VentanaImei({super.key});
  @override State<VentanaImei> createState() => _VentanaImeiState();
}

class _VentanaImeiState extends State<VentanaImei> {
  final _search = TextEditingController();
  String _filtroUbicacion = "Todos";
  List<ImeiRegistro> _listaCompleta = [];
  bool _cargando = true;

  /// Solo Administrador y Dueño pueden eliminar IMEIs.
  bool get _puedeEliminar =>
      (usuarioSesion?.rol == 'Administrador' || usuarioSesion?.rol == 'Maestro') ||
      (usuarioSesion?.rol == 'Dueño' || usuarioSesion?.rol == 'Maestro');

  @override
  void initState() { super.initState(); _cargar(); }

  @override
  void dispose() {
    _search.dispose();
    super.dispose();
  }

  Future<void> _cargar() async {
    setState(() => _cargando = true);
    try {
      // Asegurar que catalogoGlobal esté cargado para que ImeiRegistro
      // pueda resolver marca/modelo desde productos cuando el backend
      // no haga JOIN. Si ya está poblado, no recargamos.
      if (catalogoGlobal.isEmpty) {
        try {
          final rawProd = await _Api.get('productos');
          catalogoGlobal = ((rawProd as List?) ?? [])
              .map((m) => Producto.fromMap(m)).toList();
        } catch (e) {
          debugPrint('[VentanaImei] productos: $e');
        }
      }

      final raw = await _Api.get('stock_imei');
      _listaCompleta = ((raw as List?) ?? []).map((m) => ImeiRegistro.fromMap(m)).toList();
      stockImeiGlobal = _listaCompleta;
    } catch (e) {
      debugPrint('[_cargar] Error: $e');
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Error al cargar datos: $e'), backgroundColor: AppColors.statusRed, duration: const Duration(seconds: 4)));
    } finally {
      if (mounted) setState(() => _cargando = false);
    }
  }

  // ── Eliminar IMEI con confirmación ────────────────────────────
  Future<void> _eliminarImei(ImeiRegistro reg, {VoidCallback? onSuccess}) async {
    // Advertencia adicional si el equipo está marcado como vendido
    final esVendido = reg.vendido;

    final confirmar = await showDialog<bool>(
      context: context,
      builder: (ctx) => AlertDialog(
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(16)),
        title: const Row(children: [
          Icon(Icons.delete_forever_outlined, color: AppColors.statusRed),
          SizedBox(width: 8),
          Flexible(child: Text("Eliminar IMEI")),
        ]),
        content: Column(mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.start, children: [
          // Tarjeta resumen del equipo
          Container(
            padding: const EdgeInsets.all(12),
            decoration: BoxDecoration(
              color: AppColors.surfaceGrey,
              borderRadius: BorderRadius.circular(10),
              border: Border.all(color: AppColors.cardBorder),
            ),
            child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
              Text(reg.producto.nombre,
                style: const TextStyle(fontWeight: FontWeight.w600, fontSize: 14)),
              const SizedBox(height: 4),
              Row(children: [
                const Icon(Icons.pin_outlined, size: 13, color: AppColors.textSecondary),
                const SizedBox(width: 4),
                Expanded(child: Text("IMEI: ${reg.imei}",
                  style: const TextStyle(fontSize: 12,
                    color: AppColors.textSecondary, fontFamily: 'monospace'))),
              ]),
              const SizedBox(height: 2),
              Row(children: [
                const Icon(Icons.location_on_outlined, size: 13, color: AppColors.textSecondary),
                const SizedBox(width: 4),
                Text(reg.ubicacion,
                  style: const TextStyle(fontSize: 12, color: AppColors.textSecondary)),
              ]),
              const SizedBox(height: 4),
              // Estado actual
              Container(
                padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 3),
                decoration: BoxDecoration(
                  color: (esVendido ? Colors.grey : AppColors.statusGreen).withValues(alpha: 0.12),
                  borderRadius: BorderRadius.circular(8),
                ),
                child: Text(
                  esVendido ? "VENDIDO" : "DISPONIBLE",
                  style: TextStyle(
                    fontSize: 11, fontWeight: FontWeight.bold,
                    color: esVendido ? Colors.grey : AppColors.statusGreen)),
              ),
            ]),
          ),
          const SizedBox(height: 12),
          // Alerta si está vendido
          if (esVendido)
            Container(
              padding: const EdgeInsets.all(10),
              decoration: BoxDecoration(
                color: AppColors.statusOrange.withValues(alpha: 0.08),
                borderRadius: BorderRadius.circular(8),
                border: Border.all(color: AppColors.statusOrange.withValues(alpha: 0.3)),
              ),
              child: const Row(children: [
                Icon(Icons.warning_amber, size: 16, color: AppColors.statusOrange),
                SizedBox(width: 8),
                Expanded(child: Text(
                  "Este equipo está marcado como VENDIDO. "
                  "Eliminarlo no revertirá la factura asociada.",
                  style: TextStyle(fontSize: 11, color: AppColors.statusOrange))),
              ]),
            ),
          if (!esVendido)
            const Text("Esta acción es permanente. El equipo se quitará del stock disponible.",
              style: TextStyle(color: AppColors.statusRed, fontSize: 12)),
        ]),
        actions: [
          TextButton(
            onPressed: () => Navigator.pop(ctx, false),
            child: const Text("Cancelar")),
          ElevatedButton.icon(
            style: ElevatedButton.styleFrom(
              backgroundColor: AppColors.statusRed),
            icon: const Icon(Icons.delete_forever_outlined,
              size: 16, color: Colors.white),
            label: const Text("Eliminar Definitivamente",
              style: TextStyle(color: Colors.white)),
            onPressed: () => Navigator.pop(ctx, true)),
        ],
      ),
    );

    if (confirmar != true || !mounted) return;

    try {
      await _Api.delete('stock_imei', reg.imei);

      // Actualizar listas en memoria
      setState(() => _listaCompleta.removeWhere((x) => x.imei == reg.imei));
      stockImeiGlobal.removeWhere((x) => x.imei == reg.imei);

      // Actualizar stock del producto en catalogoGlobal
      final prodIdx = catalogoGlobal.indexWhere(
        (p) => p.codigo == reg.producto.codigo);
      if (prodIdx != -1 && !esVendido) {
        catalogoGlobal[prodIdx].stockTotal =
            (catalogoGlobal[prodIdx].stockTotal - 1).clamp(0, 999999);
      }

      onSuccess?.call(); // cerrar el bottom sheet si viene de _mostrarDetalle

      if (mounted) ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Row(children: [
          const Icon(Icons.check_circle_outline, color: Colors.white, size: 16),
          const SizedBox(width: 8),
          Expanded(child: Text("IMEI ${reg.imei} eliminado correctamente.")),
        ]),
        backgroundColor: AppColors.statusGreen,
        duration: const Duration(seconds: 3)));
    } catch (e) {
      if (!mounted) return;
      ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Text("Error al eliminar IMEI: $e"),
        backgroundColor: AppColors.statusRed,
        duration: const Duration(seconds: 4)));
    }
  }

  @override
  Widget build(BuildContext context) {
    final listaFiltrada = _listaCompleta.where((i) {
      final coincideBusqueda = i.imei.contains(_search.text) ||
          i.producto.nombre.toLowerCase().contains(_search.text.toLowerCase()) ||
          i.proveedor.toLowerCase().contains(_search.text.toLowerCase());
      final coincideUbicacion = _filtroUbicacion == "Todos" || i.ubicacion == _filtroUbicacion;
      return coincideBusqueda && coincideUbicacion;
    }).toList();

    final totalDisponibles = listaFiltrada.where((i) => !i.vendido).length;
    final totalVendidos = listaFiltrada.where((i) => i.vendido).length;

    return Scaffold(
      appBar: AppBar(
        title: const Text("Gestión de IMEIs"),
        actions: [
          if (_puedeEliminar)
            Padding(
              padding: const EdgeInsets.symmetric(horizontal: 4, vertical: 8),
              child: Container(
                padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 2),
                decoration: BoxDecoration(
                  color: Colors.white.withValues(alpha: 0.18),
                  borderRadius: BorderRadius.circular(12),
                  border: Border.all(color: Colors.white.withValues(alpha: 0.3)),
                ),
                child: Row(mainAxisSize: MainAxisSize.min, children: [
                  const Icon(Icons.admin_panel_settings, size: 13, color: AppColors.statusYellow),
                  const SizedBox(width: 4),
                  Text(usuarioSesion?.rol ?? '',
                    style: const TextStyle(
                      color: AppColors.statusYellow, fontSize: 10,
                      fontWeight: FontWeight.bold)),
                ]),
              ),
            ),
          IconButton(icon: const Icon(Icons.refresh), tooltip: "Actualizar", onPressed: _cargar),
          IconButton(
            icon: const Icon(Icons.add_circle_outline),
            tooltip: "Registrar IMEI",
            onPressed: () => _abrirFormularioIngreso(context)),
        ],
      ),
      body: Column(children: [
        // Barra de búsqueda y filtros
        Container(
          padding: const EdgeInsets.fromLTRB(12, 12, 12, 8),
          color: AppColors.royalBlue,
          child: Column(children: [
            TextField(
              controller: _search,
              onChanged: (v) => setState(() {}),
              style: const TextStyle(color: Colors.white),
              decoration: InputDecoration(
                hintText: "Buscar por IMEI, modelo o proveedor...",
                hintStyle: const TextStyle(color: Colors.white70),
                prefixIcon: const Icon(Icons.search, color: Colors.white),
                suffixIcon: _search.text.isNotEmpty
                  ? IconButton(
                      icon: const Icon(Icons.clear, color: Colors.white70, size: 18),
                      onPressed: () => setState(() => _search.clear()))
                  : null,
                filled: true,
                fillColor: Colors.white.withValues(alpha: 0.12),
                border: OutlineInputBorder(borderRadius: BorderRadius.circular(10), borderSide: BorderSide.none),
                contentPadding: const EdgeInsets.symmetric(vertical: 0, horizontal: 16),
              ),
            ),
            const SizedBox(height: 8),
            SingleChildScrollView(
              scrollDirection: Axis.horizontal,
              child: Row(
                children: ["Todos", ...ConfigSistema.ubicacionesAlmacen].map((u) => Padding(
                  padding: const EdgeInsets.only(right: 8),
                  child: ChoiceChip(
                    label: Text(u, style: TextStyle(
                      color: _filtroUbicacion == u ? Colors.white : Colors.white70,
                      fontSize: 12)),
                    selected: _filtroUbicacion == u,
                    selectedColor: AppColors.primaryBlue,
                    backgroundColor: Colors.white.withValues(alpha: 0.1),
                    onSelected: (val) => setState(() => _filtroUbicacion = u),
                  ),
                )).toList(),
              ),
            ),
            const SizedBox(height: 6),
            // Estadísticas rápidas
            Row(children: [
              _statChip(Icons.check_circle_outline, "$totalDisponibles disponibles", Colors.greenAccent),
              const SizedBox(width: 8),
              _statChip(Icons.sell_outlined, "$totalVendidos vendidos", Colors.orange.shade200),
            ]),
          ]),
