                        Expanded(child: Column(
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: [
                            Text(reg.producto.nombre,
                              style: TextStyle(
                                fontWeight: FontWeight.w600,
                                color: reg.vendido
                                  ? AppColors.textSecondary
                                  : AppColors.textPrimary)),
                            // Modelo (si está disponible)
                            if (reg.producto.modelo.trim().isNotEmpty) ...[
                              const SizedBox(height: 2),
                              Text("Modelo: ${reg.producto.modelo}",
                                style: TextStyle(
                                  fontSize: 12,
                                  fontWeight: FontWeight.w500,
                                  color: reg.vendido
                                    ? AppColors.textSecondary
                                    : AppColors.primaryBlue)),
                            ],
                            const SizedBox(height: 2),
                            Text("IMEI: ${reg.imei}",
                              style: const TextStyle(fontSize: 12,
                                fontFamily: 'monospace', color: AppColors.textSecondary)),
                            Row(children: [
                              const Icon(Icons.location_on_outlined,
                                size: 12, color: AppColors.textSecondary),
                              const SizedBox(width: 2),
                              Text(reg.ubicacion,
                                style: const TextStyle(fontSize: 11,
                                  color: AppColors.textSecondary)),
                              if (reg.proveedor.isNotEmpty) ...[
                                const Text(" · ",
                                  style: TextStyle(color: AppColors.textSecondary)),
                                Text(reg.proveedor,
                                  style: const TextStyle(fontSize: 11,
                                    color: AppColors.textSecondary)),
                              ],
                            ]),
                          ],
                        )),

                        // ── Badge estado ────────────────────────────
                        Container(
                          padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 3),
                          decoration: BoxDecoration(
                            color: (reg.vendido ? Colors.grey : AppColors.statusGreen)
                                .withValues(alpha: 0.1),
                            borderRadius: BorderRadius.circular(8),
                          ),
                          child: Text(
                            reg.vendido ? "VENDIDO" : "DISP.",
                            style: TextStyle(
                              fontSize: 10, fontWeight: FontWeight.bold,
                              color: reg.vendido ? Colors.grey : AppColors.statusGreen)),
                        ),

                        // ── Botón eliminar (solo admin/dueño) ───────
                        if (_puedeEliminar) ...[
                          const SizedBox(width: 4),
                          IconButton(
                            icon: const Icon(Icons.delete_outline,
                              color: AppColors.statusRed, size: 20),
                            padding: EdgeInsets.zero,
                            constraints: const BoxConstraints(),
                            tooltip: "Eliminar IMEI",
                            onPressed: () => _eliminarImei(reg)),
                        ],
                      ]),
                    ),
                  ),
                );
              },
            ),
          )),
      ]),
    );
  }

  Widget _statChip(IconData icon, String label, Color color) => Row(mainAxisSize: MainAxisSize.min, children: [
    Icon(icon, size: 13, color: color),
    const SizedBox(width: 4),
    Text(label, style: TextStyle(color: color, fontSize: 11, fontWeight: FontWeight.w500)),
  ]);

  void _mostrarDetalle(ImeiRegistro reg) {
    showModalBottomSheet(
      context: context,
      isScrollControlled: true,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(20))),
      builder: (ctx) => Padding(
        padding: const EdgeInsets.all(24),
        child: Column(mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.start, children: [
          // Handle
          Center(child: Container(
            width: 40, height: 4,
            decoration: BoxDecoration(
              color: Colors.grey[300], borderRadius: BorderRadius.circular(2)),
          )),
          const SizedBox(height: 16),

          // ── Header ──────────────────────────────────────────
          Row(children: [
            Container(
              padding: const EdgeInsets.all(10),
              decoration: BoxDecoration(
                color: (reg.vendido ? Colors.grey : AppColors.primaryBlue)
                    .withValues(alpha: 0.1),
                borderRadius: BorderRadius.circular(10),
              ),
              child: Icon(Icons.smartphone,
                color: reg.vendido ? Colors.grey : AppColors.primaryBlue,
                size: 28),
            ),
            const SizedBox(width: 12),
            Expanded(child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
              Text(reg.producto.nombre,
                style: const TextStyle(fontSize: 18, fontWeight: FontWeight.bold,
                  color: AppColors.royalBlue)),
              Container(
                padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 2),
                decoration: BoxDecoration(
                  color: (reg.vendido ? Colors.grey : AppColors.statusGreen)
                      .withValues(alpha: 0.1),
                  borderRadius: BorderRadius.circular(8),
                ),
                child: Text(
                  reg.vendido ? "VENDIDO" : "DISPONIBLE",
                  style: TextStyle(
                    fontSize: 11, fontWeight: FontWeight.bold,
                    color: reg.vendido ? Colors.grey : AppColors.statusGreen)),
              ),
            ])),
          ]),
          const Divider(height: 24),

          // ── Datos ────────────────────────────────────────────
          if (reg.producto.modelo.trim().isNotEmpty)
            _itemInfoRow(Icons.devices_outlined, "Modelo", reg.producto.modelo),
          _itemInfoRow(Icons.pin_outlined, "IMEI", reg.imei),
          _itemInfoRow(Icons.local_shipping_outlined, "Proveedor",
            reg.proveedor.isEmpty ? "N/A" : reg.proveedor),
          _itemInfoRow(Icons.palette_outlined, "Color",
            reg.color.isEmpty ? "N/A" : reg.color),
          _itemInfoRow(Icons.calendar_today_outlined, "Fecha Ingreso",
            reg.fechaIngreso),
          _itemInfoRow(Icons.location_on_outlined, "Ubicación", reg.ubicacion),
          if (reg.porcentajeBateria != null)
            _itemInfoRow(Icons.battery_charging_full_outlined,
              "Batería", "${reg.porcentajeBateria}%"),
