  Widget _itemInfoRow(IconData icon, String label, String val) => Padding(
    padding: const EdgeInsets.symmetric(vertical: 5),
    child: Row(children: [
      Icon(icon, size: 16, color: AppColors.textSecondary),
      const SizedBox(width: 8),
      Text("$label: ", style: const TextStyle(color: AppColors.textSecondary, fontSize: 13)),
      Expanded(child: Text(val, style: const TextStyle(fontWeight: FontWeight.w500, fontSize: 13))),
    ]),
  );

  Widget _itemInfo(String label, String val) => Padding(
    padding: const EdgeInsets.symmetric(vertical: 2),
    child: Row(children: [
      Text("$label: ", style: const TextStyle(fontWeight: FontWeight.bold)),
      Text(val),
    ]),
  );

  void _moverImei(ImeiRegistro reg) {
    showDialog(
      context: context,
      builder: (ctx) => AlertDialog(
        title: Row(children: [
          const Icon(Icons.swap_horiz, color: AppColors.royalBlue),
          const SizedBox(width: 8),
          Expanded(child: Text("Mover: ${reg.producto.nombre}",
            style: const TextStyle(fontSize: 15))),
        ]),
        content: Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            Text("Ubicación actual: ${reg.ubicacion}",
              style: const TextStyle(color: AppColors.textSecondary, fontSize: 13)),
            const SizedBox(height: 12),
            ...ConfigSistema.ubicacionesAlmacen
              .where((u) => u != reg.ubicacion)
              .map((u) => ListTile(
                contentPadding: EdgeInsets.zero,
                leading: const Icon(Icons.location_on_outlined, color: AppColors.primaryBlue),
                title: Text(u, style: const TextStyle(fontWeight: FontWeight.w500)),
                trailing: const Icon(Icons.arrow_forward_ios, size: 14, color: AppColors.textSecondary),
                onTap: () async {
                  final anterior = reg.ubicacion;
                  Navigator.pop(ctx);
                  try {
                    reg.ubicacion = u;
                    await _Api.put('stock_imei', reg.imei, reg.toMap());
                    if (mounted) {
                      setState(() {});
                      ScaffoldMessenger.of(context).showSnackBar(
                        SnackBar(
                          content: Text("Movido de '$anterior' → '$u'"),
                          backgroundColor: AppColors.statusGreen));
                    }
                  } catch (e) {
                    reg.ubicacion = anterior; // revertir
                    if (mounted) ScaffoldMessenger.of(context).showSnackBar(
                      SnackBar(content: Text("Error al mover: $e"), backgroundColor: AppColors.statusRed));
                  }
                },
              )).toList(),
          ],
        ),
        actions: [
          TextButton(onPressed: () => Navigator.pop(ctx), child: const Text("Cancelar")),
        ],
      ),
    );
  }

  void _abrirFormularioIngreso(BuildContext parentContext) {
    // Lista de IMEIs a ingresar (permite agregar varios)
    final List<TextEditingController> imeiCtrls = [TextEditingController()];
    final tProv = TextEditingController();
    final tCol  = TextEditingController();
    final tBat  = TextEditingController();

    Producto? pSel;
    String uSel = ConfigSistema.ubicacionesAlmacen.isNotEmpty
        ? ConfigSistema.ubicacionesAlmacen.first
        : "Almacen";

    // Todos los teléfonos del catálogo ordenados por nombre
    final todosModelos = catalogoGlobal
        .where((p) => p.categoria == "Telefono")
        .toList()
      ..sort((a, b) => a.nombre.compareTo(b.nombre));

    showDialog(context: parentContext, builder: (dialogContext) {
      return StatefulBuilder(builder: (ctx, setL) {
        final esIphone = pSel?.nombre.toLowerCase().contains("iphone") == true;

        return AlertDialog(
          title: const Row(children: [
            Icon(Icons.smartphone, color: AppColors.primaryBlue),
            SizedBox(width: 8),
            Text("Ingresar Equipos"),
          ]),
          content: SizedBox(
            width: double.maxFinite,
            child: SingleChildScrollView(child: Column(
              mainAxisSize: MainAxisSize.min,
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                // ── Modelo (sin requerir marca) ──────────────────
                const Text("Modelo *",
                  style: TextStyle(fontWeight: FontWeight.bold,
                    fontSize: 12, color: AppColors.royalBlue)),
                const SizedBox(height: 6),

                // Buscar producto por SKU (manual o escaneando)
                Row(children: [
                  Expanded(child: TextField(
                    decoration: const InputDecoration(
                      labelText: "Buscar por SKU",
                      hintText: "Pega o escanea el código",
                      prefixIcon: Icon(Icons.qr_code_2, size: 18),
                      isDense: true,
                      border: OutlineInputBorder(),
                    ),
                    onSubmitted: (sku) {
                      final s = sku.trim();
                      if (s.isEmpty) return;
                      final encontrado = todosModelos.firstWhere(
                        (p) => p.codigo == s,
                        orElse: () => Producto(
                            codigo: '', nombre: '', categoria: '',
                            marca: '', modelo: '', precioCosto: 0,
                            tipo: '', precioVenta: 0),
                      );
                      if (encontrado.codigo.isNotEmpty) {
                        setL(() => pSel = encontrado);
                      } else {
                        ScaffoldMessenger.of(ctx).showSnackBar(SnackBar(
                          content: Text("SKU no encontrado: $s"),
                          backgroundColor: Colors.orange));
                      }
                    },
                  )),
                  const SizedBox(width: 6),
                  IconButton.filledTonal(
                    icon: const Icon(Icons.qr_code_scanner),
                    tooltip: "Escanear SKU",
                    onPressed: () async {
                      await Navigator.push(ctx, MaterialPageRoute(
                        builder: (_) => ScannerPage(onDetect: (code) {
                          final encontrado = todosModelos.firstWhere(
                            (p) => p.codigo == code,
                            orElse: () => Producto(
                                codigo: '', nombre: '', categoria: '',
                                marca: '', modelo: '', precioCosto: 0,
                                tipo: '', precioVenta: 0),
                          );
                          if (encontrado.codigo.isNotEmpty) {
                            setL(() => pSel = encontrado);
                          } else {
                            ScaffoldMessenger.of(ctx).showSnackBar(SnackBar(
                              content: Text("SKU no encontrado: $code"),
                              backgroundColor: Colors.orange));
                          }
                        }),
                      ));
                    },
                  ),
                ]),
                const SizedBox(height: 8),

                DropdownButtonFormField<Producto>(
                  value: pSel,
                  hint: const Text("O elige el modelo aquí..."),
                  decoration: const InputDecoration(
                    isDense: true,
                    prefixIcon: Icon(Icons.phone_android, size: 18),
                    border: OutlineInputBorder()),
                  isExpanded: true,
                  items: todosModelos.map((p) => DropdownMenuItem(
                    value: p,
                    child: Text("${p.nombre} (${p.marca})",
                      overflow: TextOverflow.ellipsis))).toList(),
                  onChanged: (v) => setL(() => pSel = v),
                ),
                const SizedBox(height: 14),

                // ── Datos adicionales ─────────────────────────────
                TextField(
                  controller: tProv,
                  decoration: const InputDecoration(
                    labelText: "Proveedor",
                    prefixIcon: Icon(Icons.local_shipping), isDense: true, border: OutlineInputBorder())),
                const SizedBox(height: 8),
                TextField(
                  controller: tCol,
                  decoration: const InputDecoration(
                    labelText: "Color",
                    prefixIcon: Icon(Icons.color_lens), isDense: true, border: OutlineInputBorder())),
                if (esIphone) ...[
                  const SizedBox(height: 8),
                  TextField(
                    controller: tBat,
                    keyboardType: TextInputType.number,
                    decoration: const InputDecoration(
                      labelText: "% Batería",
                      prefixIcon: Icon(Icons.battery_charging_full), isDense: true, border: OutlineInputBorder())),
                ],
                const SizedBox(height: 8),
                DropdownButtonFormField<String>(
                  value: uSel,
                  decoration: const InputDecoration(
                    labelText: "Ubicación",
                    prefixIcon: Icon(Icons.warehouse), isDense: true, border: OutlineInputBorder()),
                  items: ConfigSistema.ubicacionesAlmacen
                      .map((u) => DropdownMenuItem(value: u, child: Text(u))).toList(),
                  onChanged: (v) => setL(() => uSel = v ?? uSel)),
                const SizedBox(height: 16),

                // ── IMEIs (múltiples) ──────────────────────────────
                Row(children: [
                  const Text("IMEIs a ingresar *",
                    style: TextStyle(fontWeight: FontWeight.bold,
                      fontSize: 12, color: AppColors.royalBlue)),
                  const Spacer(),
                  TextButton.icon(
                    icon: const Icon(Icons.add, size: 16),
                    label: const Text("Agregar otro", style: TextStyle(fontSize: 12)),
                    onPressed: () => setL(() =>
                      imeiCtrls.add(TextEditingController())),
                  ),
                ]),
                ...imeiCtrls.asMap().entries.map((entry) {
                  final idx = entry.key;
                  final ctrl = entry.value;
                  return Padding(
                    padding: const EdgeInsets.only(bottom: 8),
                    child: Row(children: [
                      Expanded(child: TextField(
                        controller: ctrl,
                        keyboardType: TextInputType.number,
                        decoration: InputDecoration(
                          labelText: "IMEI ${idx + 1}",
                          prefixIcon: const Icon(Icons.pin), isDense: true,
                          border: const OutlineInputBorder()),
                      )),
                      // Botón scanner por IMEI — escanea código de barras y
                      // escribe el valor en este controller específico.
                      IconButton(
                        icon: const Icon(Icons.qr_code_scanner,
                          color: AppColors.primaryBlue),
                        tooltip: "Escanear IMEI ${idx + 1}",
                        onPressed: () => Navigator.push(context,
                          MaterialPageRoute(builder: (_) => ScannerPage(
                            onDetect: (c) => setL(() => ctrl.text = c)))),
                      ),
                      if (imeiCtrls.length > 1)
                        IconButton(
                          icon: const Icon(Icons.remove_circle_outline,
                            color: AppColors.statusRed),
                          tooltip: "Quitar",
                          onPressed: () => setL(() {
                            ctrl.dispose();
                            imeiCtrls.removeAt(idx);
                          }),
                        ),
                    ]),
                  );
                }),
                const Text("Mínimo 14 dígitos por IMEI",
                  style: TextStyle(fontSize: 11, color: AppColors.textSecondary)),
              ],
            )),
          ),
          actions: [
            TextButton(
              onPressed: () {
                Navigator.pop(dialogContext);
                for (final c in imeiCtrls) c.dispose();
                tProv.dispose(); tCol.dispose(); tBat.dispose();
              },
              child: const Text("CANCELAR")),
            ElevatedButton.icon(
              icon: const Icon(Icons.save),
              label: Text("GUARDAR ${imeiCtrls.length > 1 ? '(${imeiCtrls.length})' : ''}"),
              onPressed: () async {
                if (pSel == null) {
                  ScaffoldMessenger.of(parentContext).showSnackBar(
                    const SnackBar(content: Text("Seleccione el modelo del equipo")));
                  return;
                }
                final imeisValidos = imeiCtrls
                    .map((c) => c.text.trim())
                    .where((s) => s.isNotEmpty)
                    .toList();
                if (imeisValidos.isEmpty) {
                  ScaffoldMessenger.of(parentContext).showSnackBar(
                    const SnackBar(content: Text("Ingrese al menos un IMEI")));
                  return;
                }
                final invalidos = imeisValidos.where((s) => s.length < 14).toList();
                if (invalidos.isNotEmpty) {
                  ScaffoldMessenger.of(parentContext).showSnackBar(SnackBar(
                    content: Text("IMEI inválido (menos de 14 dígitos): ${invalidos.join(', ')}")));
                  return;
                }

                // Guardar todos los IMEIs
                int guardados = 0;
                final List<String> fallidos = [];
                for (final imei in imeisValidos) {
                  try {
                    await _Api.post('stock_imei', {
                      'imei': imei,
                      'producto_codigo': pSel!.codigo,
                      'fecha_ingreso': obtenerFechaActual(),
                      'proveedor': tProv.text.trim().isEmpty ? "Sin especificar" : tProv.text.trim(),
                      'color': tCol.text.trim().isEmpty ? "N/A" : tCol.text.trim(),
                      'ubicacion': uSel,
                      'porcentaje_bateria': int.tryParse(tBat.text.trim()),
                      'vendido': 0,
                    });
                    guardados++;
                  } catch (e) {
                    fallidos.add(imei);
                    debugPrint('Error IMEI $imei: $e');
                  }
                }

                if (!mounted) return;
                Navigator.pop(dialogContext);
                await _cargar();
                for (final c in imeiCtrls) c.dispose();
                tProv.dispose(); tCol.dispose(); tBat.dispose();

                final msg = fallidos.isEmpty
                  ? "✅ $guardados equipo(s) ${pSel!.nombre} ingresado(s) correctamente"
                  : "✅ $guardados guardados — ❌ ${fallidos.length} fallidos: ${fallidos.join(', ')}";
                ScaffoldMessenger.of(parentContext).showSnackBar(SnackBar(
                  content: Text(msg),
                  backgroundColor: fallidos.isEmpty ? AppColors.statusGreen : AppColors.statusOrange));
              }),
          ],
        );
      });
    });
  }
} // fin _VentanaImeiState

// ============================================================
//  CIERRE DE CAJA — carga y guarda en la API
// ============================================================
class VentanaCierre extends StatefulWidget {
  const VentanaCierre({super.key});
  @override State<VentanaCierre> createState() => _VentanaCierreState();
}

class _VentanaCierreState extends State<VentanaCierre> {
  final List<String> tiendasDisponibles = ConfigSistema.tiendas;
  List<CierreCaja> _cierres = [];
  bool _cargando = true;
  String _tiendaFiltro = "Todas";

  @override
  void initState() {
    super.initState();
    // Si el usuario no es admin/dueño/gerente, forzar el filtro a su
    // tienda asignada — no puede ver ni seleccionar otras tiendas.
    if (!puedeVerTodasLasTiendas()) {
      final miTienda = tiendaUsuarioActual();
      if (miTienda.isNotEmpty) _tiendaFiltro = miTienda;
    }
    _cargar();
  }

  Future<void> _cargar() async {
    setState(() => _cargando = true);
    try {
      final raw = await _Api.get('cierres');
      var lista = ((raw as List?) ?? []).map((m) => CierreCaja.fromMap(m)).toList();
      // Restricción server-agnostic: si no es rol alto, quitamos cierres
      // de otras tiendas antes de mostrarlos.
      if (!puedeVerTodasLasTiendas()) {
        final miTienda = tiendaUsuarioActual();
        if (miTienda.isNotEmpty) {
          lista = lista.where((c) => c.tienda == miTienda).toList();
        }
      }
      _cierres = lista;
      cierresGlobal = _cierres;
    } catch (e) {
      debugPrint('[_cargar] Error: $e');
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Error al cargar datos: $e'), backgroundColor: AppColors.statusRed, duration: const Duration(seconds: 4)));
    } finally {
      if (mounted) setState(() => _cargando = false);
    }
  }

  void _verDetalleCierre(CierreCaja cierre) {
    final fecha = "${cierre.fecha.day.toString().padLeft(2,'0')}/"
                  "${cierre.fecha.month.toString().padLeft(2,'0')}/"
                  "${cierre.fecha.year}";

    showDialog(context: context, builder: (ctx) => AlertDialog(
      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(16)),
      title: const Row(children: [
        Icon(Icons.account_balance_wallet, color: AppColors.royalBlue),
        SizedBox(width: 8),
        Text("Detalle de Cierre",
          style: TextStyle(color: AppColors.royalBlue, fontWeight: FontWeight.bold)),
      ]),
      content: SingleChildScrollView(
        child: Column(mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.start, children: [
          // ── Info general ──────────────────────────────────
          _filaInfo("ID Operación", cierre.id),
          _filaInfo("Tienda", cierre.tienda),
          _filaInfo("Fecha", fecha),
          _filaInfo("Responsable", cierre.usuarioCierre),
          const Divider(height: 20),

          // ── Métodos de pago con colores ───────────────────
          const Row(children: [
            Icon(Icons.payments_outlined, size: 14, color: AppColors.textSecondary),
            SizedBox(width: 6),
            Text("MÉTODOS DE PAGO",
              style: TextStyle(fontWeight: FontWeight.bold,
                fontSize: 12, letterSpacing: 0.5, color: AppColors.textSecondary)),
          ]),
          const SizedBox(height: 10),

          ...cierre.metodosPago.entries.map((e) {
            final color = _colorMetodoPago(e.key);
            return Container(
              margin: const EdgeInsets.only(bottom: 8),
              padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 10),
              decoration: BoxDecoration(
                color: color.withValues(alpha: 0.06),
                borderRadius: BorderRadius.circular(10),
                border: Border.all(color: color.withValues(alpha: 0.25)),
              ),
              child: Row(children: [
                Container(
                  width: 32, height: 32,
                  decoration: BoxDecoration(
                    color: color.withValues(alpha: 0.12),
                    borderRadius: BorderRadius.circular(8)),
                  child: Icon(_iconoMetodoPago(e.key), color: color, size: 17),
                ),
                const SizedBox(width: 10),
                Expanded(child: Text(e.key,
                  style: TextStyle(fontWeight: FontWeight.w600,
                    fontSize: 13, color: color))),
                Text(formatCurrency(e.value),
                  style: TextStyle(fontWeight: FontWeight.bold,
                    fontSize: 15, color: color)),
              ]),
            );
          }),

          const Divider(height: 20),
          // ── Total destacado ───────────────────────────────
          Container(
            width: double.infinity,
            padding: const EdgeInsets.all(12),
            decoration: BoxDecoration(
              color: AppColors.statusGreen.withValues(alpha: 0.08),
              borderRadius: BorderRadius.circular(10),
            ),
            child: Row(mainAxisAlignment: MainAxisAlignment.spaceBetween, children: [
              const Text("TOTAL DEL CIERRE",
                style: TextStyle(fontWeight: FontWeight.bold,
                  fontSize: 13, color: AppColors.statusGreen)),
              Text(formatCurrency(cierre.montoTotal),
                style: const TextStyle(fontWeight: FontWeight.bold,
                  fontSize: 20, color: AppColors.statusGreen)),
            ]),
          ),
        ]),
      ),
      actions: [
        TextButton(
          onPressed: () => Navigator.pop(ctx),
          child: const Text("CERRAR")),
      ],
    ));
  }

  Widget _filaInfo(String label, String valor) => Padding(
    padding: const EdgeInsets.symmetric(vertical: 4),
    child: Row(mainAxisAlignment: MainAxisAlignment.spaceBetween, children: [
      Text(label, style: const TextStyle(fontSize: 13)),
      Text(valor, style: const TextStyle(fontWeight: FontWeight.w600, fontSize: 13)),
    ]));

  Future<void> _dialogoNuevoCierre() async {
    String tiendaSel = tiendasDisponibles[0];
    DateTime fechaSel = DateTime.now();
    bool generando = false;
    // Preview calculado antes de guardar
    Map<String, double>? previewMetodos;
    double previewTotal = 0;
    bool calculando = false;

    await showDialog(context: context, builder: (ctx) => StatefulBuilder(
      builder: (dialogCtx, setS) => AlertDialog(
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(16)),
        title: const Row(children: [
          Icon(Icons.summarize, color: AppColors.royalBlue),
          SizedBox(width: 8),
          Text("Generar Cierre de Caja"),
        ]),
        content: SingleChildScrollView(child: Column(mainAxisSize: MainAxisSize.min, children: [
          DropdownButtonFormField<String>(
            value: tiendaSel,
            decoration: const InputDecoration(
              labelText: "Tienda",
              prefixIcon: Icon(Icons.store_outlined)),
            items: tiendasDisponibles
              .map((t) => DropdownMenuItem(value: t, child: Text(t)))
              .toList(),
            onChanged: generando ? null : (val) {
              setS(() {
                tiendaSel = val!;
                previewMetodos = null; // resetear preview al cambiar tienda
              });
            }),
          const SizedBox(height: 16),
          InkWell(
            borderRadius: BorderRadius.circular(10),
            onTap: generando ? null : () async {
              final picked = await showDatePicker(
                context: dialogCtx,
                initialDate: fechaSel,
                firstDate: DateTime(2023),
                lastDate: DateTime.now());
              if (picked != null) {
                setS(() {
                  fechaSel = picked;
                  previewMetodos = null; // resetear preview al cambiar fecha
                });
              }
            },
            child: Container(
              padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 12),
              decoration: BoxDecoration(
                color: AppColors.surfaceGrey,
                borderRadius: BorderRadius.circular(10),
                border: Border.all(color: AppColors.cardBorder),
              ),
              child: Row(children: [
                const Icon(Icons.calendar_today, color: AppColors.primaryBlue, size: 18),
                const SizedBox(width: 10),
                Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                  const Text("Fecha del cierre",
                    style: TextStyle(fontSize: 11, color: AppColors.textSecondary)),
                  Text(
                    "${fechaSel.day.toString().padLeft(2,'0')}/"
                    "${fechaSel.month.toString().padLeft(2,'0')}/"
                    "${fechaSel.year}",
                    style: const TextStyle(fontWeight: FontWeight.w600, fontSize: 15)),
                ]),
                const Spacer(),
                const Icon(Icons.edit_calendar_outlined, size: 16, color: AppColors.textSecondary),
              ]),
            ),
          ),

          // ── Botón para previsualizar ──────────────────────
          const SizedBox(height: 12),
          SizedBox(
            width: double.infinity,
            child: OutlinedButton.icon(
              icon: calculando
                ? const SizedBox(width: 14, height: 14,
                    child: CircularProgressIndicator(strokeWidth: 2))
                : const Icon(Icons.preview_outlined, size: 16),
              label: Text(calculando ? "Calculando..." : "Previsualizar ventas del día"),
              style: OutlinedButton.styleFrom(
                side: const BorderSide(color: AppColors.royalBlue),
                foregroundColor: AppColors.royalBlue),
              onPressed: (calculando || generando) ? null : () async {
                setS(() => calculando = true);
                try {
                  final rawV = await _Api.get('facturas');
                  final Map<String, double> metodos = {};
                  double total = 0;
                  for (final v in ((rawV as List?) ?? [])) {
                    try {
                      final partes = (v['fecha'] as String? ?? '').split("/");
                      if (partes.length != 3) continue;
                      final fFact = DateTime(int.parse(partes[2]), int.parse(partes[1]), int.parse(partes[0]));
                      if (v['tienda'] != tiendaSel ||
                          fFact.year != fechaSel.year ||
                          fFact.month != fechaSel.month ||
                          fFact.day != fechaSel.day) continue;
                      total += double.tryParse(v['total'].toString()) ?? 0;
                      final pagos = v['pagos'] as List? ?? [];
                      if (pagos.isNotEmpty) {
                        for (final p in pagos) {
                          final met = p['metodo']?.toString() ?? 'Otros';
                          metodos[met] = (metodos[met] ?? 0) + (double.tryParse(p['monto'].toString()) ?? 0);
                        }
                      } else {
                        metodos['Ventas del día'] = (metodos['Ventas del día'] ?? 0) +
                            (double.tryParse(v['total'].toString()) ?? 0);
                      }
                    } catch (_) {}
                  }
                  setS(() {
                    previewMetodos = metodos;
                    previewTotal   = total;
                    calculando     = false;
                  });
                } catch (e) {
                  setS(() => calculando = false);
                }
              },
            ),
          ),

          // ── Preview resultado ─────────────────────────────
          if (previewMetodos != null) ...[
            const SizedBox(height: 12),
            Container(
              width: double.infinity,
              padding: const EdgeInsets.all(12),
              decoration: BoxDecoration(
                color: AppColors.surfaceGrey,
                borderRadius: BorderRadius.circular(12),
                border: Border.all(color: AppColors.cardBorder),
              ),
              child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                Row(children: [
                  const Icon(Icons.receipt_long, size: 14, color: AppColors.royalBlue),
                  const SizedBox(width: 6),
                  Text("$tiendaSel — ${fechaSel.day.toString().padLeft(2,'0')}/${fechaSel.month.toString().padLeft(2,'0')}/${fechaSel.year}",
                    style: const TextStyle(fontWeight: FontWeight.w600,
                      fontSize: 12, color: AppColors.royalBlue)),
                ]),
                const SizedBox(height: 8),
                if (previewMetodos!.isEmpty)
                  const Text("Sin ventas registradas para este día.",
                    style: TextStyle(color: AppColors.textSecondary, fontSize: 12))
                else ...[
                  ...previewMetodos!.entries.map((e) {
                    final color = _colorMetodoPago(e.key);
                    return Padding(
                      padding: const EdgeInsets.symmetric(vertical: 3),
                      child: Row(children: [
                        Icon(_iconoMetodoPago(e.key), size: 14, color: color),
                        const SizedBox(width: 6),
                        Expanded(child: Text(e.key,
                          style: TextStyle(fontSize: 12, color: color, fontWeight: FontWeight.w500))),
                        Text(formatCurrency(e.value),
                          style: TextStyle(fontSize: 12, fontWeight: FontWeight.bold, color: color)),
                      ]),
                    );
                  }),
                  const Divider(height: 12),
                  Row(children: [
                    const Expanded(child: Text("TOTAL",
                      style: TextStyle(fontWeight: FontWeight.bold, fontSize: 13))),
                    Text(formatCurrency(previewTotal),
                      style: const TextStyle(fontWeight: FontWeight.bold,
                        fontSize: 15, color: AppColors.statusGreen)),
                  ]),
                ],
              ]),
            ),
          ],

          if (generando) ...[
            const SizedBox(height: 12),
            const Row(children: [
              SizedBox(width: 20, height: 20, child: CircularProgressIndicator(strokeWidth: 2)),
              SizedBox(width: 12),
              Text("Guardando cierre...",
                style: TextStyle(fontSize: 13, color: AppColors.textSecondary)),
            ]),
          ],
        ])),
        actions: [
          TextButton(
            onPressed: generando ? null : () => Navigator.pop(dialogCtx),
            child: const Text("CANCELAR")),
          ElevatedButton.icon(
            style: ElevatedButton.styleFrom(backgroundColor: AppColors.royalBlue),
            icon: generando
              ? const SizedBox(width: 16, height: 16,
                  child: CircularProgressIndicator(color: Colors.white, strokeWidth: 2))
              : const Icon(Icons.check_circle_outline, color: Colors.white, size: 18),
            label: Text(generando ? "Generando..." : "GENERAR",
              style: const TextStyle(color: Colors.white, fontWeight: FontWeight.bold)),
            onPressed: generando ? null : () async {
              setS(() => generando = true);
              try {
                // Usar los datos del preview si ya están calculados, sino recalcular
                Map<String, double> resumenMetodos;
                double totalGeneral;

                if (previewMetodos != null) {
                  resumenMetodos = previewMetodos!;
                  totalGeneral   = previewTotal;
                } else {
                  resumenMetodos = {};
                  totalGeneral   = 0;
                  final rawV = await _Api.get('facturas');
                  for (final v in ((rawV as List?) ?? [])) {
                    try {
                      final partes = (v['fecha'] as String? ?? '').split("/");
                      if (partes.length != 3) continue;
                      final fFact = DateTime(int.parse(partes[2]), int.parse(partes[1]), int.parse(partes[0]));
                      if (v['tienda'] != tiendaSel ||
                          fFact.year  != fechaSel.year ||
                          fFact.month != fechaSel.month ||
                          fFact.day   != fechaSel.day) continue;
                      totalGeneral += double.tryParse(v['total'].toString()) ?? 0;
                      final pagos = v['pagos'] as List? ?? [];
                      if (pagos.isNotEmpty) {
                        for (final p in pagos) {
                          final metodo = p['metodo']?.toString() ?? 'Otros';
                          resumenMetodos[metodo] = (resumenMetodos[metodo] ?? 0) +
                              (double.tryParse(p['monto'].toString()) ?? 0);
                        }
                      } else {
                        resumenMetodos['Ventas del día'] = (resumenMetodos['Ventas del día'] ?? 0) +
                            (double.tryParse(v['total'].toString()) ?? 0);
                      }
                    } catch (e) { debugPrint('Error parseo cierre: $e'); }
                  }
                }

                final now = DateTime.now();
                final uid = "C-${tiendaSel.substring(0, math.min(3, tiendaSel.length)).toUpperCase()}"
                            "-${now.day.toString().padLeft(2,'0')}"
                            "${now.month.toString().padLeft(2,'0')}"
                            "${now.year.toString().substring(2)}"
                            "-${now.millisecondsSinceEpoch.toString().substring(9)}";

                await _Api.post('cierres', {
                  'uid'           : uid,
                  'tienda'        : tiendaSel,
                  'monto_total'   : totalGeneral,
                  'usuario_cierre': usuarioSesion?.nombre ?? "Sistema",
                  'metodos'       : resumenMetodos.entries
                      .map((e) => {'metodo': e.key, 'monto': e.value}).toList(),
                });

                if (!dialogCtx.mounted) return;
                Navigator.pop(dialogCtx);
                await _cargar();

                if (mounted) {
                  ScaffoldMessenger.of(this.context).showSnackBar(SnackBar(
                    content: Text(
                      "✅ Cierre generado — Total: ${formatCurrency(totalGeneral)} "
                      "· ${resumenMetodos.length} método(s)"),
                    backgroundColor: AppColors.statusGreen,
                    duration: const Duration(seconds: 5)));
                }
              } catch (e) {
                setS(() => generando = false);
                if (dialogCtx.mounted) {
                  ScaffoldMessenger.of(this.context).showSnackBar(SnackBar(
                    content: Text("Error al generar cierre: $e"),
                    backgroundColor: AppColors.statusRed,
                    duration: const Duration(seconds: 5)));
                }
              }
            },
          ),
        ],
      )));
  }

  @override
  Widget build(BuildContext context) {
    final cierresFiltrados = _tiendaFiltro == "Todas"
        ? _cierres
        : _cierres.where((c) => c.tienda == _tiendaFiltro).toList();

    return Scaffold(
      appBar: AppBar(
        title: const Text("Cierres de Caja"),
        actions: [
          IconButton(
            icon: const Icon(Icons.refresh),
            tooltip: "Actualizar",
            onPressed: _cargar),
        ],
      ),
      body: Column(children: [
        Padding(
          padding: const EdgeInsets.fromLTRB(16, 16, 16, 8),
          child: SizedBox(width: double.infinity,
            child: ElevatedButton.icon(
              style: ElevatedButton.styleFrom(
                backgroundColor: AppColors.royalBlue,
