                                ]),
                              );
                            }).toList()),
                        ],
                      ]),
                    ),
                  ));
              }),
          )),
      ]),
    );
  }

  IconData _iconoMetodoPago(String metodo) {
    final m = metodo.toLowerCase();
    if (m.contains('efectivo') || m.contains('cash')) return Icons.payments_outlined;
    if (m.contains('transferencia') || m.contains('transfer')) return Icons.swap_horiz;
    if (m.contains('tarjeta') || m.contains('card') || m.contains('débito') || m.contains('credito')) return Icons.credit_card;
    if (m.contains('zelle')) return Icons.send_to_mobile;
    if (m.contains('pago') && m.contains('movil')) return Icons.phone_android;
    if (m.contains('dolar') || m.contains('divisas') || m.contains('usd')) return Icons.attach_money;
    if (m.contains('bolivar') || m.contains('bs')) return Icons.currency_exchange;
    if (m.contains('cashea') || m.contains('weppa') || m.contains('krece') || m.contains('financ')) return Icons.account_balance_outlined;
    return Icons.payment;
  }

  Color _colorMetodoPago(String metodo) {
    final m = metodo.toLowerCase();
    if (m.contains('efectivo') || m.contains('cash'))      return const Color(0xFF2E7D32); // verde oscuro
    if (m.contains('transferencia') || m.contains('transfer')) return const Color(0xFF1565C0); // azul
    if (m.contains('tarjeta') || m.contains('débito') || m.contains('credito')) return const Color(0xFF6A1B9A); // morado
    if (m.contains('zelle'))                               return const Color(0xFF6200EA); // púrpura
    if (m.contains('pago') && m.contains('movil'))         return const Color(0xFFE65100); // naranja
    if (m.contains('dolar') || m.contains('usd'))          return const Color(0xFF00695C); // teal
    if (m.contains('bolivar') || m.contains('bs'))         return const Color(0xFF283593); // índigo
    if (m.contains('cashea'))                              return const Color(0xFFC62828); // rojo
    if (m.contains('weppa') || m.contains('krece'))        return const Color(0xFF00838F); // cyan
    return AppColors.primaryBlue;
  }
}

// ============================================================
//  FORMULARIO FACTURA — guarda en la API
// ============================================================
class FormularioFactura extends StatefulWidget {
  final now = DateTime.now();
  final String tienda;
  final FacturaModel? facturaAEditar;
  FormularioFactura({super.key, required this.tienda, this.facturaAEditar});
  @override State<FormularioFactura> createState() => _FormularioFacturaState();
}

class _FormularioFacturaState extends State<FormularioFactura>
    with WidgetsBindingObserver {
  final _telCtrl=TextEditingController();
  final _correoClienteCtrl=TextEditingController();
  final _codigo=TextEditingController(), _montoPago=TextEditingController();
  final _deudaFpb=TextEditingController(); // monto de deuda para FPB
  String _metodo = ConfigSistema.metodossPago.isNotEmpty ? ConfigSistema.metodossPago.first : "Punto de venta";
  String _tipoVenta = "Contado";
  String _nombreProductoEncontrado = "";
  String? _financiadorSeleccionado;
  late TextEditingController _cliente, _cedula, _nro;
  List<ImeiRegistro> _equipos = [];
  List<Producto> _items = [];
  List<PagoFactura> _pagos = [];

  /// Clave única del borrador persistido. Usamos una clave por usuario
  /// para que dos sesiones distintas no se pisen.
  String get _claveBorrador =>
      'factura_borrador_${usuarioSesion?.correo ?? "anon"}';

  /// Indica si ya se intentó cargar el borrador (para evitar restaurarlo
  /// más de una vez en hot-reload o múltiples didChangeDependencies).
  bool _borradorRestaurado = false;

  /// Guard para evitar que el usuario haga doble-tap en "Guardar"
  /// y se dispare el POST dos veces (lo que provocaba el error 1062
  /// "Duplicate entry" de nro_factura).
  bool _guardando = false;

  // ── Financiamiento POR PRODUCTO (bug #1) ──────────────────
  // Cada producto e IMEI agregado a la factura puede tener su propio
  // tipo de venta (Contado / Cashea / Weppa / Krece / FPB) y financiador.
  // Así se puede, por ejemplo, financiar un teléfono por Weppa y vender
  // un accesorio de contado en la misma factura.
  //
  // Se indexan por la referencia del objeto (identityHashCode) en vez de
  // por posición en la lista, para no "mover" el dato si el usuario
  // reordena o elimina items.
  final Map<int, String>  _tipoVentaItem      = {};   // identityHash → tipoVenta
  final Map<int, String?> _financiadorItem    = {};   // identityHash → financiador
  final Map<int, String>  _tipoVentaEquipo    = {};   // identityHash → tipoVenta
  final Map<int, String?> _financiadorEquipo  = {};   // identityHash → financiador

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addObserver(this);
    _cliente = TextEditingController(text: widget.facturaAEditar?.cliente ?? "");
    _cedula = TextEditingController(text: widget.facturaAEditar?.cedula ?? "");
    // ── Generación de nro_factura ÚNICO ─────────────────────────────
    // Antes: ts + (ts % 9999) — totalmente determinista, dos formularios
    // abiertos en el mismo milisegundo generaban el MISMO número.
    // Ahora: timestamp + 4 dígitos REALMENTE aleatorios + 2 más de jitter
    // para casi eliminar la posibilidad de colisión.
    final ts = DateTime.now().millisecondsSinceEpoch;
    final rnd = math.Random.secure();
    final r1 = rnd.nextInt(10000).toString().padLeft(4, '0');
    final r2 = rnd.nextInt(100).toString().padLeft(2, '0');
    _nro = TextEditingController(
        text: widget.facturaAEditar?.nroFactura ?? "$ts-$r1$r2");
    if (widget.facturaAEditar != null) {
      _equipos = List.from(widget.facturaAEditar!.equipos);
      _items = List.from(widget.facturaAEditar!.itemsSinImei);
      _pagos = List.from(widget.facturaAEditar!.pagos);
    }
    // Recargar catálogo con stock actualizado al abrir el formulario.
    // Si es una factura NUEVA (no edición), también intentar restaurar
    // un borrador previo si el proceso fue terminado por el sistema
    // (por ejemplo al abrir el scanner en pantalla completa con poca RAM).
    _refrescarCatalogo().then((_) {
      if (widget.facturaAEditar == null) _restaurarBorrador();
    });
  }

  @override
  void didChangeAppLifecycleState(AppLifecycleState state) {
    super.didChangeAppLifecycleState(state);
    // Cuando la app pasa a background (el usuario abre cámara, otra
    // app, recibe llamada, etc.) guardamos el borrador para no perder
    // el trabajo si el SO termina el proceso.
    if (state == AppLifecycleState.paused ||
        state == AppLifecycleState.inactive ||
        state == AppLifecycleState.hidden) {
      _guardarBorrador();
    }
  }

  /// Guarda el estado actual de la factura como borrador en SharedPreferences.
  /// Solo guarda si NO es edición y si hay algún dato significativo.
  Future<void> _guardarBorrador() async {
    if (widget.facturaAEditar != null) return; // sólo facturas nuevas
    if (_equipos.isEmpty && _items.isEmpty &&
        _cliente.text.trim().isEmpty &&
        _cedula.text.trim().isEmpty) {
      return; // no hay nada que guardar
    }
    try {
      final data = {
        'cliente': _cliente.text,
        'cedula': _cedula.text,
        'telefono': _telCtrl.text,
        'correo': _correoClienteCtrl.text,
        'nro': _nro.text,
        'tipoVenta': _tipoVenta,
        'deudaFpb': _deudaFpb.text,
        'equiposImeis': _equipos.map((e) => e.imei).toList(),
        'itemsCodigos': _items.map((p) => p.codigo).toList(),
        'pagos': _pagos.map((p) => {
          'metodo': p.metodo,
          'monto': p.monto,
          'tipo': p.tipo,
          'financiador': p.financiador,
        }).toList(),
        'tipoVentaItem': _tipoVentaItem.map(
            (k, v) => MapEntry(k.toString(), v)),
        'financiadorItem': _financiadorItem.map(
            (k, v) => MapEntry(k.toString(), v)),
        'tipoVentaEquipo': _tipoVentaEquipo.map(
            (k, v) => MapEntry(k.toString(), v)),
        'financiadorEquipo': _financiadorEquipo.map(
            (k, v) => MapEntry(k.toString(), v)),
        'guardadoEn': DateTime.now().toIso8601String(),
      };
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString(_claveBorrador, jsonEncode(data));
    } catch (e) {
      debugPrint('[Factura] Error guardando borrador: $e');
    }
  }

  /// Restaura un borrador previo si existe y es reciente (< 12 horas).
  /// Solo se llama si la factura es NUEVA (no edición).
  Future<void> _restaurarBorrador() async {
    if (_borradorRestaurado) return;
    _borradorRestaurado = true;
    try {
      final prefs = await SharedPreferences.getInstance();
      final raw = prefs.getString(_claveBorrador);
      if (raw == null || raw.isEmpty) return;
      final data = jsonDecode(raw) as Map<String, dynamic>;

      // Si el borrador es viejo (> 12h) lo descartamos para no llenar
      // el formulario con datos obsoletos.
      final guardadoEn = DateTime.tryParse(data['guardadoEn'] ?? '');
      if (guardadoEn != null &&
          DateTime.now().difference(guardadoEn).inHours > 12) {
        await prefs.remove(_claveBorrador);
        return;
      }

      // Si ya hay datos en el formulario (raro pero posible), no restaurar.
      if (_equipos.isNotEmpty || _items.isNotEmpty ||
          _cliente.text.isNotEmpty) {
        return;
      }

      _cliente.text = (data['cliente'] ?? '').toString();
      _cedula.text = (data['cedula'] ?? '').toString();
      _telCtrl.text = (data['telefono'] ?? '').toString();
      _correoClienteCtrl.text = (data['correo'] ?? '').toString();
      if ((data['nro'] ?? '').toString().isNotEmpty) {
        _nro.text = data['nro'].toString();
      }
      _tipoVenta = (data['tipoVenta'] ?? 'Contado').toString();
      _deudaFpb.text = (data['deudaFpb'] ?? '').toString();

      // Reconstruir equipos por IMEI
      final imeis = ((data['equiposImeis'] as List?) ?? []).cast<String>();
      for (final imei in imeis) {
        final reg = stockImeiGlobal
            .where((i) => i.imei == imei).firstOrNull;
        if (reg != null && !_equipos.contains(reg)) _equipos.add(reg);
      }
      // Reconstruir items por código
      final codigos = ((data['itemsCodigos'] as List?) ?? []).cast<String>();
      for (final cod in codigos) {
        final p = catalogoGlobal
            .where((x) => x.codigo == cod).firstOrNull;
        if (p != null) _items.add(p);
      }
      // Reconstruir pagos
      final pagosRaw = ((data['pagos'] as List?) ?? []);
      _pagos = pagosRaw.map((p) {
        final m = p as Map;
        return PagoFactura(
          metodo: (m['metodo'] ?? '').toString(),
          monto: double.tryParse(m['monto'].toString()) ?? 0,
          tipo: (m['tipo'] ?? 'Contado').toString(),
          financiador: m['financiador']?.toString(),
        );
      }).toList();

      if (mounted && (_equipos.isNotEmpty || _items.isNotEmpty)) {
        setState(() {});
        ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
          content: Text("📋 Borrador restaurado: tu factura anterior se recuperó"),
          backgroundColor: AppColors.statusGreen,
          duration: Duration(seconds: 3)));
      }
    } catch (e) {
      debugPrint('[Factura] Error restaurando borrador: $e');
    }
  }

  /// Borra el borrador. Se llama después de guardar la factura con éxito
  /// o cuando el usuario sale sin querer guardar.
  Future<void> _borrarBorrador() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.remove(_claveBorrador);
    } catch (_) {}
  }

  /// Recarga productos e IMEIs desde la API para tener el stock real
  /// al momento de crear la factura (evita vender stock agotado).
  Future<void> _refrescarCatalogo() async {
    try {
      final results = await Future.wait([
        _Api.get('productos'),
        _Api.get('stock_imei'),
      ]);
      final rawP = results[0];
      final rawI = results[1];
      final imeis = ((rawI as List?) ?? [])
          .map((m) => ImeiRegistro.fromMap(m))
          .toList();
      final prods = ((rawP as List?) ?? []).map((m) {
        final p = Producto.fromMap(m);
        if (p.categoria == 'Telefono') {
          p.stockTotal = imeis
              .where((i) => i.producto.codigo == p.codigo && !i.vendido)
              .length;
        } else {
          p.stockTotal = p.stockManual;
        }
        return p;
      }).toList();
      catalogoGlobal  = prods;
      stockImeiGlobal = imeis;
      if (mounted) setState(() {});
    } catch (e) {
      debugPrint('[FormularioFactura] Error refrescando catálogo: $e');
    }
  }

  @override
  void dispose() {
    WidgetsBinding.instance.removeObserver(this);
    _telCtrl.dispose();
    _correoClienteCtrl.dispose();
    _codigo.dispose();
    _montoPago.dispose();
    _deudaFpb.dispose();
    _cliente.dispose();
    _cedula.dispose();
    _nro.dispose();
    super.dispose();
  }

  void _verificarCodigo(String val) {
    setState(() {
      _nombreProductoEncontrado = "";
      final imei = stockImeiGlobal.where((i) => i.imei == val && !i.vendido).firstOrNull;
      if (imei != null) {
        _nombreProductoEncontrado = "📱 ${imei.producto.nombre}";
        return;
      }
      final prod = catalogoGlobal.where((p) => p.codigo == val).firstOrNull;
      if (prod != null) {
        final yaAgregados = _items.where((p) => p.codigo == val).length;
        final stockDisponible = prod.stockTotal - yaAgregados;
        _nombreProductoEncontrado = "${prod.nombre} (Stock: $stockDisponible)";
      }
    });
  }

  void _agregarProducto() {
    final val = _codigo.text.trim();
    if (val.isEmpty) return;

    // ── Buscar por IMEI (teléfonos) ──
    final imei = stockImeiGlobal.where((i) => i.imei == val && !i.vendido).firstOrNull;
    if (imei != null) {
      if (_equipos.contains(imei)) {
        ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text("Este equipo ya está en la lista")));
        return;
      }
      setState(() => _equipos.add(imei));
      _codigo.clear();
      setState(() => _nombreProductoEncontrado = "");
      return;
    }

    // ── Buscar por código SKU (accesorios / productos sin IMEI) ──
    final prod = catalogoGlobal.where((p) => p.codigo == val).firstOrNull;
    if (prod != null) {
      // Verificar stock disponible considerando los ya agregados en esta factura
      final yaAgregados = _items.where((p) => p.codigo == val).length;
      final stockDisponible = prod.stockTotal - yaAgregados;
      if (stockDisponible <= 0) {
        ScaffoldMessenger.of(context).showSnackBar(SnackBar(
          content: Text("Sin stock disponible para ${prod.nombre} (stock actual: ${prod.stockTotal})"),
          backgroundColor: Colors.orange[800],
        ));
        return;
      }
      setState(() => _items.add(prod));
      _codigo.clear();
      setState(() => _nombreProductoEncontrado = "");
      return;
    }

    ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text("Producto no encontrado o ya vendido")));
  }

  void _agregarPago({
    String? bancoDestino,
    String? bancoOrigen,
    String? referenciaPM,
    String? cedulaPagador,
    String? telefonoPagador,
    String? telefonoDestino,
    String? fechaPago,
    bool esInicial = false,
    bool? conciliadoBDV,
    int? codigoConciliacion,
    String? mensajeConciliacion,
  }) {
    final monto = double.tryParse(_montoPago.text.trim());
    if (monto == null || monto <= 0) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text("Ingrese un monto de pago válido mayor a 0"),
          backgroundColor: AppColors.statusOrange));
      return;
    }
    setState(() {
      // ── Cambio bug #1: el tipo de venta (Financiado/Contado) y el
      // financiador se derivan AHORA de los productos individuales de
      // la factura, no de un F/D global.
      //
      // Lógica — DOS conceptos distintos:
      //  · FINANCIADORA = la app con la que el cliente se lleva el
      //    equipo (Cashea/Weppa/Krece). Viene del dropdown F/D, o sea
      //    de _tipoVentaItem / _tipoVentaEquipo.
      //  · FINANCIADOR = la persona/usuario que entrega el equipo.
      //    Viene de _financiadorItem / _financiadorEquipo.
      //
      // El Reporte por Financiadora se agrupa por FINANCIADORA.
      //
      // Reglas:
      //  · Si hay ≥1 producto con F/D = Cashea/Weppa/Krece → "Financiado"
      //    y se toma esa financiadora.
      //  · Si es FPB global (switch del formulario) → "Financiado".
      //  · En otro caso → "Contado".

      // Normaliza la financiadora a una de las 3 oficiales.
      String? normFinanciadora(String tipoVenta) {
        if (tipoVenta == 'Cashea' || tipoVenta == 'Weppa'
            || tipoVenta == 'Krece') {
          return tipoVenta;
        }
        return null;
      }

      String? financiadoraDerivada;  // Cashea / Weppa / Krece (del F/D)
      String? financiadorDerivado;   // Persona que entrega (del usuario)
      bool hayFinanciado = false;
      for (final p in _items) {
        final t = _tipoVentaItem[identityHashCode(p)] ?? "Contado";
        if (t == "Cashea" || t == "Weppa" || t == "Krece") {
          hayFinanciado = true;
          financiadoraDerivada ??= normFinanciadora(t);
          financiadorDerivado  ??= _financiadorItem[identityHashCode(p)];
        }
      }
      for (final e in _equipos) {
        final t = _tipoVentaEquipo[identityHashCode(e)] ?? "Contado";
        if (t == "Cashea" || t == "Weppa" || t == "Krece") {
          hayFinanciado = true;
          financiadoraDerivada ??= normFinanciadora(t);
          financiadorDerivado  ??= _financiadorEquipo[identityHashCode(e)];
        }
      }
      final esFinanciado = hayFinanciado || _tipoVenta == "FPB";
      _pagos.add(PagoFactura(
        metodo: _metodo, monto: monto,
        tipo: esFinanciado ? "Financiado" : "Contado",
        financiador: financiadorDerivado,
        financiadora: financiadoraDerivada,
        bancoDestino: bancoDestino,
        bancoOrigen: bancoOrigen,
        referencia: referenciaPM,
        cedulaPagador: cedulaPagador,
        telefonoPagador: telefonoPagador,
        telefonoDestino: telefonoDestino,
        fechaPago: fechaPago,
        esInicial: esInicial,
        conciliadoBDV: conciliadoBDV,
        codigoConciliacion: codigoConciliacion,
        mensajeConciliacion: mensajeConciliacion,
      ));
      _montoPago.clear();
    });
  }

  Future<void> _guardarFactura() async {
    // ── Anti-doble-click ─────────────────────────────────────
    // Si el usuario presiona "Guardar" mientras ya hay un POST en
    // curso, ignoramos el segundo tap. Esto evita que se dispare el
    // INSERT dos veces y MySQL responda con error 1062 (Duplicate
    // entry para nro_factura).
    if (_guardando) {
      debugPrint('[Factura] _guardarFactura ignorado: ya hay un guardado en curso');
      return;
    }
    _guardando = true;

    try {
      await _guardarFacturaInterno();
    } finally {
      // SIEMPRE liberar la guardia, ocurra lo que ocurra (validación
      // fallida, error de red, error de BD, éxito). Sin esto, un fallo
      // dejaría el botón "trabado" hasta cerrar la pantalla.
      _guardando = false;
    }
  }

  Future<void> _guardarFacturaInterno() async {
    // ── Validaciones completas antes de guardar ──────────────
    final clienteNombre = _cliente.text.trim();
    final clienteCedula = _cedula.text.trim();
    final clienteTel    = _telCtrl.text.trim();

    if (clienteNombre.isEmpty) {
      _mostrarValidacion("Ingrese el nombre del cliente.");
      return;
    }
    if (clienteNombre.length < 3) {
      _mostrarValidacion("El nombre debe tener al menos 3 caracteres.");
      return;
    }
    if (clienteCedula.isEmpty) {
      _mostrarValidacion("Ingrese la cédula del cliente.");
      return;
    }
    // Cédula venezolana: 6–8 dígitos
    if (!RegExp(r'^\d{6,8}$').hasMatch(clienteCedula.replaceAll(RegExp(r'[VE-]'), ''))) {
      _mostrarValidacion("La cédula debe tener entre 6 y 8 dígitos.");
      return;
    }
    if (_equipos.isEmpty && _items.isEmpty) {
      _mostrarValidacion("Agregue al menos un producto a la factura.");
      return;
    }
    if (_pagos.isEmpty) {
      _mostrarValidacion("Agregue al menos un método de pago.");
      return;
    }

    // Validar que el total de pagos coincida con el total de productos
    final totalProductos = _equipos.fold(0.0, (s, e) => s + e.producto.precioVenta)
        + _items.fold(0.0, (s, p) => s + p.precioVenta);
    final totalPagos = _pagos.fold(0.0, (s, p) => s + p.monto);
    if ((totalPagos - totalProductos).abs() > 0.10) { // tolerancia de $0.10
      final confirmar = await showDialog<bool>(
        context: context,
        builder: (ctx) => AlertDialog(
          title: const Row(children: [
            Icon(Icons.warning_amber, color: Colors.orange),
            SizedBox(width: 8),
            Text("Diferencia en totales"),
          ]),
          content: Column(mainAxisSize: MainAxisSize.min,
            crossAxisAlignment: CrossAxisAlignment.start, children: [
            Text("Total productos: ${formatCurrency(totalProductos)}"),
            Text("Total pagos: ${formatCurrency(totalPagos)}"),
            const SizedBox(height: 8),
            const Text("¿Desea continuar de todas formas?",
              style: TextStyle(fontWeight: FontWeight.w500)),
          ]),
          actions: [
            TextButton(
              onPressed: () => Navigator.pop(ctx, false),
              child: const Text("Corregir")),
            ElevatedButton(
              style: ElevatedButton.styleFrom(backgroundColor: Colors.orange),
              onPressed: () => Navigator.pop(ctx, true),
              child: const Text("Continuar", style: TextStyle(color: Colors.white))),
          ],
        ),
      );
      if (confirmar != true || !mounted) return;
    }

    // Validación específica para FPB
    if (_tipoVenta == "FPB") {
      final deuda = double.tryParse(_deudaFpb.text.trim());
      if (deuda == null || deuda <= 0) {
        _mostrarValidacion(
          "Ingrese el monto de la deuda del cliente para FPB.",
          color: AppColors.statusOrange);
        return;
      }
    }

    // ── Mostrar indicador de carga ───────────────────────────
    showDialog(
      context: context,
      barrierDismissible: false,
      builder: (_) => AlertDialog(
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(16)),
        content: const Padding(
          padding: EdgeInsets.symmetric(vertical: 8),
          child: Row(children: [
            CircularProgressIndicator(),
            SizedBox(width: 20),
            Expanded(child: Text("Guardando factura y actualizando inventario...")),
          ]),
        ),
      ),
    );

    try {
      final ahora = DateTime.now();
      final fechaFormateada =
        "${ahora.day.toString().padLeft(2,'0')}/"
        "${ahora.month.toString().padLeft(2,'0')}/"
        "${ahora.year}";

      var nuevaFactura = FacturaModel(
        tienda       : widget.tienda,
        cliente      : clienteNombre,
        cedula       : clienteCedula,
        telefono     : clienteTel,
        nroFactura   : _nro.text.trim(),
        equipos      : _equipos,
        itemsSinImei : _items,
        pagos        : _pagos,
        // Guardamos el NOMBRE del usuario (no el rol). Si el nombre viene
        // vacío, cae al fallback; si el nombre que está en el perfil de
        // sesión resulta ser un rol (caso de datos mal cargados), el helper
        // `_resolverNombreVendedor` lo reemplaza por el nombre real del
        // único usuario con ese rol, si lo hay.
        vendedor     : _resolverNombreVendedor(
                         (usuarioSesion?.nombre ?? '').trim().isEmpty
                           ? "Vendedor"
                           : usuarioSesion!.nombre),
        fecha        : fechaFormateada,
      );

      // ── 1. GUARDAR FACTURA EN BASE DE DATOS ──────────────
      // Si estamos editando una factura existente, solo se actualizan
      // los datos del encabezado + pagos (PUT). NO se vuelve a tocar el
      // stock, porque ya fue descontado al crear la factura original.
      //
      // Si se está creando una factura nueva, se hace POST y luego se
      // ejecutan los efectos secundarios (pasos 2, 3, 4): marcar IMEIs,
      // decrementar stock manual y crear CxC para FPB.
      final esEdicion = widget.facturaAEditar?.id != null;

      if (esEdicion) {
        // Conservar id original para no romper relaciones (factura_equipos,
        // factura_items, factura_pagos siguen apuntando a ese id).
        nuevaFactura.id = widget.facturaAEditar!.id;
        await _Api.put('facturas', nuevaFactura.id!.toString(), nuevaFactura.toApiMap());
      } else {
        // ── POST con reintento automático si hay duplicado ────────
        // Si el backend responde con error 1062 ("Duplicate entry for
        // nro_factura"), regeneramos el número con un timestamp+random
        // nuevo y reintentamos UNA vez. Si vuelve a fallar, propagamos
        // el error al usuario.
        dynamic data;
        int reintentos = 0;
        while (true) {
          try {
            data = await _Api.post('facturas', nuevaFactura.toApiMap());
            break; // Éxito → salimos del while
          } catch (e) {
            final msg = e.toString();
            final esDuplicado = msg.contains('1062') ||
                                msg.contains('Duplicate entry') ||
                                msg.toLowerCase().contains('duplicate');
            if (esDuplicado && reintentos < 2) {
              reintentos++;
              // Generar nuevo número de factura y reintentar
              final ts2 = DateTime.now().millisecondsSinceEpoch;
              final r1 = math.Random.secure().nextInt(10000).toString().padLeft(4, '0');
              final r2 = math.Random.secure().nextInt(100).toString().padLeft(2, '0');
              final nuevoNro = "$ts2-$r1$r2";
              debugPrint('[Factura] Duplicate entry detectado. Regenerando nro: $nuevoNro');
              _nro.text = nuevoNro;
              // Recrear el FacturaModel con el nuevo nro
              nuevaFactura = FacturaModel(
                tienda       : nuevaFactura.tienda,
                cliente      : nuevaFactura.cliente,
                cedula       : nuevaFactura.cedula,
                telefono     : nuevaFactura.telefono,
                nroFactura   : nuevoNro,
                equipos      : nuevaFactura.equipos,
                itemsSinImei : nuevaFactura.itemsSinImei,
                pagos        : nuevaFactura.pagos,
                vendedor     : nuevaFactura.vendedor,
                fecha        : nuevaFactura.fecha,
              );
              continue; // Reintentar con el nuevo número
            }
            // No es duplicado o ya agotamos reintentos → propagar
            rethrow;
          }
        }
        // Extraer el id del Map devuelto, tolerando que data sea null,
        // un Map sin 'id', o que el id venga como String. Si nada de
        // esto funciona, dejamos id en null (no es bloqueante para los
        // pasos siguientes — solo no se podrá editar la factura recién
        // creada hasta que se recargue la lista).
        if (data is Map) {
          final idRaw = data['id'];
          if (idRaw != null) {
            nuevaFactura.id = idRaw is int ? idRaw : int.tryParse(idRaw.toString());
          }
        }
      }

      // ── 1a-bis. Actualizar contador local de compras ─────
      // Incrementamos el cache en memoria para que la UI refleje
      // inmediatamente la nueva factura sin tener que recargar.
      final cedulaKey = _normalizarCedula(clienteCedula);
      if (cedulaKey.isNotEmpty) {
        conteoComprasPorCedula[cedulaKey] =
            (conteoComprasPorCedula[cedulaKey] ?? 0) + 1;
      }

      // ── 1a. ACTUALIZAR LISTA LOCAL DE CLIENTES ───────────
      // Los clientes no se persisten en una tabla propia — se
      // reconstruyen desde las facturas al recargar. Mantenemos un
      // cache en memoria para que el autocompletado funcione durante
      // la sesión actual.
      try {
        final clienteData = ClienteModel(
          cedula: clienteCedula,
          nombre: clienteNombre,
          telefono: clienteTel,
          correo: _correoClienteCtrl.text.trim(),
        );
        final idx = clientesGlobal.indexWhere((c) =>
            _normalizarCedula(c.cedula) == _normalizarCedula(clienteCedula));
        if (idx >= 0) {
          // Conservar correo previo si el nuevo viene vacío
          final previo = clientesGlobal[idx];
          clientesGlobal[idx] = ClienteModel(
            cedula: clienteData.cedula,
            nombre: clienteData.nombre,
            telefono: clienteData.telefono,
            correo: clienteData.correo.isNotEmpty
                ? clienteData.correo
                : previo.correo,
          );
        } else {
          clientesGlobal.add(clienteData);
        }
      } catch (e) {
        debugPrint('[Clientes] No se pudo actualizar cache local: $e');
      }

      // ── 2. MARCAR IMEIs COMO VENDIDOS ────────────────────
      // NO se hace nada aquí. El backend (facturas.php → POST) YA
      // marca los IMEIs como vendidos atómicamente dentro de la
      // misma transacción que inserta la factura:
      //   UPDATE stock_imei SET vendido=1, fecha_venta=NOW(),
      //          factura_id=? WHERE imei=? AND vendido=0
      //
      // Antes este bloque hacía PUT /stock_imei pasando el número
      // de IMEI como si fuera el `id` (clave primaria), lo que
      // SIEMPRE fallaba (el endpoint busca por id numérico) y
      // mostraba la falsa advertencia "IMEIs no marcados como
      // vendidos". Como el backend ya hace el trabajo, eliminamos
      // la duplicación. Solo refrescamos la copia en memoria.
      final List<String> imeisFallidos = [];
      if (!esEdicion) {
        for (final equipo in _equipos) {
          equipo.vendido = true;
          final idx = stockImeiGlobal.indexWhere((i) => i.imei == equipo.imei);
          if (idx != -1) stockImeiGlobal[idx].vendido = true;
        }
      }

      // ── 3. REFRESCAR STOCK MANUAL EN LA SESIÓN ───────────
      // IMPORTANTE: el backend (api.php → guardarFactura) YA descuenta
      // el stock atómicamente dentro de la misma transacción que guarda
      // la factura. Antes aquí se volvía a descontar en Dart y se hacía
      // PUT /productos con el nuevo stock → se descontaba DOS VECES
      // (una en el INSERT de factura_items + una por el PUT de Dart),
      // causando un desajuste de inventario.
      //
      // Ahora solamente refrescamos el stock en memoria leyéndolo del
      // servidor para que la vista refleje lo que ya quedó en BD.
      final Map<String, int> cantidadPorCodigo = {};
      final List<String> productosFallidos = [];
      if (!esEdicion) {
        for (final prod in _items) {
          if (prod.categoria != 'Telefono') {
            cantidadPorCodigo[prod.codigo] =
                (cantidadPorCodigo[prod.codigo] ?? 0) + 1;
          }
        }

        for (final entry in cantidadPorCodigo.entries) {
          try {
            final rawFresh = await _Api.get('productos', {'codigo': entry.key});
            if (rawFresh == null) continue;

            int stockActual;
            if (rawFresh is List) {
              final match = (rawFresh as List)
                  .map((m) => Producto.fromMap(m as Map<String, dynamic>))
                  .where((p) => p.codigo == entry.key)
                  .firstOrNull;
              stockActual = match?.stockManual ?? 0;
            } else {
              stockActual = Producto.fromMap(
                rawFresh as Map<String, dynamic>).stockManual;
            }

            // Solo actualizamos la representación en memoria; el servidor
            // ya tiene el valor correcto.
            final prodEnSesion = catalogoGlobal
                .where((p) => p.codigo == entry.key)
                .firstOrNull;
            if (prodEnSesion != null) {
              prodEnSesion.stockManual = stockActual;
              prodEnSesion.stockTotal  = stockActual;
            }
            debugPrint('[Stock] ${entry.key}: refrescado en sesión → $stockActual');
          } catch (e) {
            debugPrint('Error refrescando stock ${entry.key}: $e');
            productosFallidos.add(entry.key);
          }
        }
      } // cierre de if (!esEdicion) del paso 3

      if (!mounted) return;
      Navigator.pop(context); // Cerrar loading

      // ── 4. CREAR CxC AUTOMÁTICA PARA FPB ─────────────────
      // Solo en creación. En edición no se crea una nueva cuenta por
      // cobrar; la original ya existe (o nunca existió si la venta no
      // era FPB cuando se creó).
      if (!esEdicion && _tipoVenta == "FPB") {
        final deuda = double.tryParse(_deudaFpb.text.trim()) ?? 0;
        if (deuda > 0) {
          // Resolver la financiadora de los pagos: el primer pago con
          // `financiador` no vacío gana. Si no hay ninguno, queda 'FPB'.
          final financiadora = _pagos
              .map((p) => (p.financiador ?? '').trim())
              .firstWhere((f) => f.isNotEmpty, orElse: () => 'FPB');
          try {
            await _Api.post('cuentas_cobrar', {
              'cedula'      : clienteCedula,
              'nombre'      : clienteNombre,
              'telefono'    : clienteTel,
              'correo'      : '',
              'monto_total' : deuda,
              'financiadora': financiadora,
              'notas'       : 'Generado automáticamente desde factura ${_nro.text.trim()}',
            });
            if (mounted) ScaffoldMessenger.of(context).showSnackBar(SnackBar(
              content: Text("✅ Cuenta por cobrar creada: $clienteNombre — ${formatCurrency(deuda)}"),
              backgroundColor: AppColors.statusGreen,
              duration: const Duration(seconds: 4)));
          } catch (e) {
            debugPrint('Error creando CxC para FPB: $e');
          }
        }
      }

      // ── 5. MOSTRAR ADVERTENCIAS SI LAS HAY ───────────────
      if (imeisFallidos.isNotEmpty || productosFallidos.isNotEmpty) {
        await showDialog(
          context: context,
          builder: (ctx) => AlertDialog(
            title: const Row(children: [
              Icon(Icons.warning_amber_rounded, color: Colors.orange),
              SizedBox(width: 8),
              Flexible(child: Text("Factura guardada con advertencias")),
            ]),
            content: SingleChildScrollView(child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              mainAxisSize: MainAxisSize.min,
              children: [
                const Text(
                  "La factura fue registrada, pero los siguientes ítems "
                  "no se pudieron actualizar en el inventario:"),
                if (imeisFallidos.isNotEmpty) ...[
                  const SizedBox(height: 12),
                  const Text("IMEIs no marcados como vendidos:",
                    style: TextStyle(fontWeight: FontWeight.bold)),
                  ...imeisFallidos.map((imei) => Text(
                    "• $imei", style: const TextStyle(color: Colors.red))),
                ],
                if (productosFallidos.isNotEmpty) ...[
                  const SizedBox(height: 12),
                  const Text("Productos sin descontar:",
                    style: TextStyle(fontWeight: FontWeight.bold)),
                  ...productosFallidos.map((cod) => Text(
                    "• $cod", style: const TextStyle(color: Colors.orange))),
                ],
                const SizedBox(height: 8),
                const Text("Verifique el inventario manualmente.",
                  style: TextStyle(fontStyle: FontStyle.italic, fontSize: 12)),
              ],
            )),
            actions: [
              ElevatedButton(
                onPressed: () => Navigator.pop(ctx),
                child: const Text("Entendido")),
            ],
          ),
        );
      }

      if (!mounted) return;
      // Factura guardada con éxito: borrar el borrador local para que
      // al abrir una nueva factura no aparezca un "borrador restaurado"
      // con datos antiguos.
      _borrarBorrador();
      Navigator.pop(context, nuevaFactura);

    } catch (e) {
      if (!mounted) return;
      Navigator.pop(context); // Cerrar loading
      ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Text("Error al guardar la factura: $e"),
        backgroundColor: AppColors.statusRed,
        duration: const Duration(seconds: 6),
      ));
    }
  }

  /// Muestra mensaje de validación con estilo coherente.
  void _mostrarValidacion(String mensaje,
      {Color color = AppColors.statusRed}) {
    if (!mounted) return;
    ScaffoldMessenger.of(context).showSnackBar(SnackBar(
      content: Row(children: [
        Icon(color == AppColors.statusRed
            ? Icons.error_outline
            : Icons.warning_amber_outlined,
          color: Colors.white, size: 18),
        const SizedBox(width: 8),
        Expanded(child: Text(mensaje)),
      ]),
      backgroundColor: color,
      duration: const Duration(seconds: 4),
      behavior: SnackBarBehavior.floating,
    ));
  }

