                  _correoClienteCtrl.text = existente.correo;
                }
              });
              final compras = contarComprasCliente(cedula);
              final msgCompras = compras == 0
                  ? 'cliente registrado, aún sin compras'
                  : compras == 1
                      ? '1 compra anterior'
                      : '$compras compras anteriores';
              ScaffoldMessenger.of(context).showSnackBar(
                SnackBar(
                  content: Text(
                      '📋 ${existente.nombre} · $msgCompras'),
                  backgroundColor: compras > 0
                      ? AppColors.primaryBlue
