  Widget _buildInfoField(String label, String value) => Padding(
    padding: const EdgeInsets.symmetric(vertical: 8),
    child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
      Text(label, style: const TextStyle(fontSize: 11, color: Colors.grey, fontWeight: FontWeight.bold)),
      const SizedBox(height: 4),
      Text(value, style: const TextStyle(fontSize: 16, color: Colors.black, fontWeight: FontWeight.w500)),
    ]));

  Widget _buildTextField(String label, TextEditingController controller) => Padding(
    padding: const EdgeInsets.symmetric(vertical: 8),
    child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
      Text(label, style: const TextStyle(fontSize: 11, color: Colors.grey, fontWeight: FontWeight.bold)),
      TextField(controller: controller, style: const TextStyle(fontSize: 15),
        decoration: InputDecoration(isDense: true,
          contentPadding: const EdgeInsets.symmetric(vertical: 8),
          enabledBorder: UnderlineInputBorder(borderSide: BorderSide(color: Colors.grey[300]!)))),
    ]));

  /// Variante de _buildTextField que dispara una callback cuando el
  /// usuario termina de escribir una cédula (pierde el foco o escribe
  /// al menos 6 dígitos). Se usa para autocompletar datos del cliente
  /// buscando en `clientesGlobal`.
  Widget _buildTextFieldConAutocompletado(
      String label, TextEditingController controller,
      {required Function(String) onCedulaCompleta}) {
    return Padding(
      padding: const EdgeInsets.symmetric(vertical: 8),
      child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
        Text(label, style: const TextStyle(fontSize: 11, color: Colors.grey, fontWeight: FontWeight.bold)),
        Focus(
          onFocusChange: (hasFocus) {
            if (!hasFocus && controller.text.trim().length >= 6) {
              onCedulaCompleta(controller.text.trim());
            }
          },
          child: TextField(
            controller: controller,
            style: const TextStyle(fontSize: 15),
            onSubmitted: (v) {
              if (v.trim().length >= 6) onCedulaCompleta(v.trim());
            },
            decoration: InputDecoration(
                isDense: true,
                contentPadding: const EdgeInsets.symmetric(vertical: 8),
                enabledBorder: UnderlineInputBorder(
                    borderSide: BorderSide(color: Colors.grey[300]!))),
          ),
        ),
      ]));
  }

  Widget _buildSectionHeader(String title, int count) => Row(children: [
    Text(title, style: const TextStyle(fontSize: 13, color: Colors.grey, fontWeight: FontWeight.w500)),
    const SizedBox(width: 8),
    Container(padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 2),
      decoration: BoxDecoration(color: Colors.grey[200], borderRadius: BorderRadius.circular(4)),
      child: Text(count.toString(), style: const TextStyle(fontSize: 11, fontWeight: FontWeight.bold))),
  ]);

  Widget _buildProductosTable() {
    if (_equipos.isEmpty && _items.isEmpty) {
      return const Padding(padding: EdgeInsets.symmetric(vertical: 10),
        child: Text("No hay productos agregados", style: TextStyle(fontSize: 12, color: Colors.grey, fontStyle: FontStyle.italic)));
    }
    // Helper: chip F/D compacto con color — misma paleta que el diálogo
    Widget chipFD(String tv) {
      const colores = <String, List<Color>>{
        'Contado': [Color(0xFFEDEDED), Color(0xFF111111)],
        'Cashea' : [Color(0xFFFFD600), Color(0xFF000000)],
        'Weppa'  : [Color(0xFF6A1B9A), Color(0xFFFFD600)],
        'Krece'  : [Color(0xFF006B7F), Color(0xFFFFFFFF)],
        'FPB'    : [Color(0xFF002366), Color(0xFFFFFFFF)],
      };
      final par = colores[tv] ?? const <Color>[Color(0xFFEDEDED), Color(0xFF111111)];
      return Container(
        margin: const EdgeInsets.only(top: 2),
        padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 2),
        decoration: BoxDecoration(color: par[0], borderRadius: BorderRadius.circular(4)),
        child: Text(tv,
            style: TextStyle(color: par[1], fontSize: 10, fontWeight: FontWeight.bold)),
      );
    }
    return Table(
      border: TableBorder(bottom: BorderSide(color: Colors.grey[200]!)),
      columnWidths: const {0: FlexColumnWidth(2.2), 1: FlexColumnWidth(1.5), 2: FlexColumnWidth(0.8)},
      children: [
        const TableRow(children: [
          Padding(padding: EdgeInsets.symmetric(vertical: 10), child: Text("DESCRIPCIÓN", style: TextStyle(fontSize: 11, fontWeight: FontWeight.bold, color: Colors.grey))),
          Padding(padding: EdgeInsets.symmetric(vertical: 10), child: Text("ID/IMEI", style: TextStyle(fontSize: 11, fontWeight: FontWeight.bold, color: Colors.grey))),
          Padding(padding: EdgeInsets.symmetric(vertical: 10), child: Text("", style: TextStyle(fontSize: 11))),
        ]),
        ..._equipos.map((e) {
          final tv = _tipoVentaEquipo[identityHashCode(e)] ?? "Contado";
          return TableRow(children: [
            Padding(
              padding: const EdgeInsets.symmetric(vertical: 10),
              child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                Text(e.producto.nombre, style: const TextStyle(fontSize: 13)),
                Text(formatCurrency(e.producto.precioVenta, symbol: ''), style: const TextStyle(fontSize: 11, color: AppColors.primaryBlue, fontWeight: FontWeight.bold)),
                // Chip F/D por equipo (bug #1)
                Align(alignment: Alignment.centerLeft, child: chipFD(tv)),
              ])),
            Padding(padding: const EdgeInsets.symmetric(vertical: 10), child: Text(e.imei, style: const TextStyle(fontSize: 12, color: Colors.deepPurple, fontWeight: FontWeight.bold))),
            InkWell(
              onTap: () => setState(() {
                _equipos.remove(e);
                _tipoVentaEquipo.remove(identityHashCode(e));
                _financiadorEquipo.remove(identityHashCode(e));
              }),
              child: const Padding(padding: EdgeInsets.symmetric(vertical: 10), child: Icon(Icons.remove_circle_outline, color: Colors.red, size: 20))),
          ]);
        }),
        ..._items.map((p) {
          final tv = _tipoVentaItem[identityHashCode(p)] ?? "Contado";
          return TableRow(children: [
            Padding(
              padding: const EdgeInsets.symmetric(vertical: 10),
              child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                Text(p.nombre, style: const TextStyle(fontSize: 13)),
                Text(formatCurrency(p.precioVenta, symbol: ''), style: const TextStyle(fontSize: 11, color: AppColors.primaryBlue, fontWeight: FontWeight.bold)),
                // Chip F/D por producto (bug #1)
                Align(alignment: Alignment.centerLeft, child: chipFD(tv)),
              ])),
            Padding(padding: const EdgeInsets.symmetric(vertical: 10), child: Text(p.codigo, style: const TextStyle(fontSize: 12, color: Colors.blueGrey))),
            InkWell(
              onTap: () => setState(() {
                _items.remove(p);
                _tipoVentaItem.remove(identityHashCode(p));
                _financiadorItem.remove(identityHashCode(p));
              }),
              child: const Padding(padding: EdgeInsets.symmetric(vertical: 10), child: Icon(Icons.remove_circle_outline, color: Colors.red, size: 20))),
          ]);
        }),
      ]);
  }

  Widget _buildPagosTable() {
    if (_pagos.isEmpty) {
      return const Padding(padding: EdgeInsets.symmetric(vertical: 10),
        child: Text("No hay pagos registrados", style: TextStyle(fontSize: 12, color: Colors.grey, fontStyle: FontStyle.italic)));
    }
    final totalPagado = _pagos.fold(0.0, (s, p) => s + p.monto);
    return Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
      Table(
        border: TableBorder(bottom: BorderSide(color: Colors.grey[200]!)),
        columnWidths: const {0: FlexColumnWidth(2), 1: FlexColumnWidth(1.2), 2: FlexColumnWidth(0.5)},
        children: [
          const TableRow(children: [
            Padding(padding: EdgeInsets.symmetric(vertical: 10), child: Text("METODO", style: TextStyle(fontSize: 11, fontWeight: FontWeight.bold, color: Colors.grey))),
            Padding(padding: EdgeInsets.symmetric(vertical: 10), child: Text("MONTO", style: TextStyle(fontSize: 11, fontWeight: FontWeight.bold, color: Colors.grey))),
            Padding(padding: EdgeInsets.symmetric(vertical: 10), child: Text("", style: TextStyle(fontSize: 11))),
          ]),
          ..._pagos.map((p) => TableRow(children: [
            Padding(
              padding: const EdgeInsets.symmetric(vertical: 10),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(p.metodo, style: const TextStyle(fontSize: 13)),
                  // Badge de conciliación BDV (sólo cuando hay un intento)
                  if (p.conciliadoBDV != null) ...[
                    const SizedBox(height: 3),
                    Container(
                      padding: const EdgeInsets.symmetric(
                          horizontal: 6, vertical: 2),
                      decoration: BoxDecoration(
                        color: p.conciliadoBDV!
                            ? AppColors.statusGreen.withValues(alpha: 0.12)
                            : Colors.orange.withValues(alpha: 0.15),
                        borderRadius: BorderRadius.circular(8),
                        border: Border.all(
                          color: p.conciliadoBDV!
                              ? AppColors.statusGreen
                              : Colors.orange.shade700,
                          width: 0.8),
                      ),
                      child: Row(mainAxisSize: MainAxisSize.min, children: [
                        Icon(
                          p.conciliadoBDV! ? Icons.verified : Icons.warning_amber,
                          size: 10,
                          color: p.conciliadoBDV!
                              ? AppColors.statusGreen
                              : Colors.orange.shade800),
                        const SizedBox(width: 3),
                        Text(
                          p.conciliadoBDV! ? "BDV ✓" : "No conciliado",
                          style: TextStyle(
                            fontSize: 9,
                            fontWeight: FontWeight.bold,
                            color: p.conciliadoBDV!
                                ? AppColors.statusGreen
                                : Colors.orange.shade800)),
                      ]),
                    ),
                  ] else if (p.referencia != null && p.referencia!.isNotEmpty) ...[
                    // Pago móvil con referencia pero sin conciliación intentada
                    const SizedBox(height: 3),
                    Text("Ref: ${p.referencia}",
                      style: const TextStyle(
                          fontSize: 10, color: AppColors.textSecondary)),
                  ],
                ],
              ),
            ),
            Padding(padding: const EdgeInsets.symmetric(vertical: 10), child: Text(formatCurrency(p.monto, symbol: ''), style: const TextStyle(fontSize: 13, fontWeight: FontWeight.bold))),
            InkWell(
              onTap: () => setState(() => _pagos.remove(p)),
              child: const Padding(padding: EdgeInsets.symmetric(vertical: 10), child: Icon(Icons.remove_circle_outline, color: Colors.red, size: 20))),
          ])),
        ]),
      const SizedBox(height: 8),
      Row(mainAxisAlignment: MainAxisAlignment.end, children: [
        const Text("TOTAL PAGADO: ", style: TextStyle(fontSize: 13, fontWeight: FontWeight.bold)),
        Text(formatCurrency(totalPagado, symbol: ''), style: const TextStyle(fontSize: 15, fontWeight: FontWeight.bold, color: AppColors.primaryBlue)),
      ]),
    ]);
  }

  void _mostrarDialogoBusqueda() {
    // Estado del diálogo: producto/equipo detectado + selección F/D por producto
    Producto? prodDetectado;
    ImeiRegistro? imeiDetectado;
    String tipoVentaSeleccionado = "Contado";
    String? financiadorSeleccionado;

    // Maps de colores para el dropdown F/D (mismo criterio visual que antes)
    const estilosFD = <String, List<Color>>{
      'Contado': [Color(0xFFEDEDED), Color(0xFF111111)],
      'Cashea' : [Color(0xFFFFD600), Color(0xFF000000)],
      'Weppa'  : [Color(0xFF6A1B9A), Color(0xFFFFD600)],
      'Krece'  : [Color(0xFF006B7F), Color(0xFFFFFFFF)],
      'FPB'    : [Color(0xFF002366), Color(0xFFFFFFFF)],
    };
    const opcionesFD = ['Contado', 'Cashea', 'Weppa', 'Krece', 'FPB'];

    Widget chipFD(String o, {bool compacto = false}) {
      final par = estilosFD[o] ?? const <Color>[Colors.white, Colors.black];
      return Container(
        padding: EdgeInsets.symmetric(
            horizontal: compacto ? 10 : 12, vertical: compacto ? 4 : 8),
        decoration: BoxDecoration(
          color: par[0],
          borderRadius: BorderRadius.circular(6),
          border: Border.all(
              color: par[0].computeLuminance() > 0.85
                  ? Colors.grey.shade400
                  : par[0],
              width: 1),
        ),
        child: Text(o,
            style: TextStyle(
                color: par[1],
                fontWeight: FontWeight.bold,
                fontSize: 13,
                letterSpacing: 0.3)),
      );
    }

    // Resuelve el código escaneado/tipeado y actualiza prodDetectado/imeiDetectado
    void resolverCodigo(String val, void Function(void Function()) setS) {
      final v = val.trim();
      prodDetectado = null;
      imeiDetectado = null;
      if (v.isEmpty) {
        setS(() {});
        return;
      }
      final imei =
          stockImeiGlobal.where((i) => i.imei == v && !i.vendido).firstOrNull;
      if (imei != null) {
        imeiDetectado = imei;
        setS(() {});
        return;
      }
      final prod = catalogoGlobal.where((p) => p.codigo == v).firstOrNull;
      if (prod != null) {
        prodDetectado = prod;
      }
      setS(() {});
    }

    showDialog(
      context: context,
      builder: (c) => StatefulBuilder(builder: (context, setS) {
        // Resumen del producto detectado
        String resumen = "";
        int? stockRestante;
        if (imeiDetectado != null) {
          resumen = "📱 ${imeiDetectado!.producto.nombre} — IMEI: ${imeiDetectado!.imei}";
        } else if (prodDetectado != null) {
          final yaAgregados =
              _items.where((p) => p.codigo == prodDetectado!.codigo).length;
          stockRestante = prodDetectado!.stockTotal - yaAgregados;
          resumen =
              "${prodDetectado!.nombre} (Stock: $stockRestante)";
        }
        final hayDetectado = imeiDetectado != null || prodDetectado != null;
        final puedeAgregar = hayDetectado &&
            (imeiDetectado != null ||
                (stockRestante != null && stockRestante > 0));

        return AlertDialog(
          title: const Row(children: [
            Icon(Icons.qr_code_scanner, color: AppColors.royalBlue),
            SizedBox(width: 8),
            Text("Añadir Producto"),
          ]),
          content: SingleChildScrollView(
            child: Column(
              mainAxisSize: MainAxisSize.min,
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                // ── Campo de código con botón scanner (cámara) ──
                Row(children: [
                  Expanded(
                    child: TextField(
                      controller: _codigo,
                      autofocus: true,
                      keyboardType: TextInputType.text,
                      decoration: InputDecoration(
                        hintText: "IMEI o código SKU",
                        hintStyle: const TextStyle(fontSize: 13),
                        prefixIcon: const Icon(Icons.keyboard, size: 20),
                        suffixIcon: _codigo.text.isNotEmpty
                            ? IconButton(
                                icon: const Icon(Icons.clear, size: 18),
                                onPressed: () {
                                  _codigo.clear();
                                  resolverCodigo('', setS);
                                })
                            : null,
                      ),
                      onChanged: (val) => resolverCodigo(val, setS),
                      onSubmitted: (_) {
                        if (puedeAgregar) {
                          _agregarProductoConFinanciamiento(
                              tipoVentaSeleccionado, financiadorSeleccionado);
                          Navigator.pop(c);
                        }
                      }),
                  ),
                  const SizedBox(width: 8),
                  // Botón grande que abre la cámara como scanner de código
                  ElevatedButton.icon(
                    icon: const Icon(Icons.qr_code_scanner, size: 20),
                    label: const Text("Escanear"),
                    style: ElevatedButton.styleFrom(
                        backgroundColor: AppColors.primaryBlue,
                        foregroundColor: Colors.white,
                        padding: const EdgeInsets.symmetric(
                            horizontal: 12, vertical: 12)),
                    onPressed: () {
                      // Guardar borrador ANTES de abrir el scanner: si el
                      // SO mata el proceso por baja memoria mientras la
                      // cámara está activa (ocurre con frecuencia en
                      // teléfonos modestos), al volver podremos restaurar
                      // todos los items ya agregados a la factura.
                      _guardarBorrador();
                      // Abre el scanner; al detectar un código, lo escribe
                      // en _codigo y llama a resolverCodigo para refrescar
                      // el estado del diálogo con el producto encontrado.
                      Navigator.push(
                        context,
                        MaterialPageRoute(
                          builder: (_) => ScannerPage(
                            onDetect: (codigo) {
                              _codigo.text = codigo;
                              resolverCodigo(codigo, setS);
                            },
                          ),
                        ),
                      );
                    },
                  ),
                ]),
                const SizedBox(height: 12),
                // Estado de detección
                if (!hayDetectado && _codigo.text.isNotEmpty)
                  Container(
                    padding: const EdgeInsets.all(8),
                    decoration: BoxDecoration(
                        color: Colors.orange[50],
                        borderRadius: BorderRadius.circular(4)),
                    child: const Row(children: [
                      Icon(Icons.search_off,
                          color: Colors.orange, size: 16),
                      SizedBox(width: 8),
                      Expanded(
                          child: Text("Producto no encontrado o sin stock",
                              style: TextStyle(
                                  color: Colors.orange, fontSize: 12))),
                    ]),
                  ),
                if (hayDetectado)
                  Container(
                    padding: const EdgeInsets.all(10),
                    decoration: BoxDecoration(
                        color: Colors.green[50],
                        borderRadius: BorderRadius.circular(6)),
                    child: Row(children: [
                      const Icon(Icons.check_circle,
                          color: Colors.green, size: 18),
                      const SizedBox(width: 8),
                      Expanded(
                          child: Text(resumen,
                              style: const TextStyle(
                                  color: Colors.green,
                                  fontWeight: FontWeight.bold,
                                  fontSize: 13))),
                    ]),
                  ),
                const SizedBox(height: 16),
                // ── F/D por producto (solo aparece con producto detectado) ──
                if (hayDetectado) ...[
                  const Text("Forma de venta (F/D) para este producto:",
                      style: TextStyle(
                          fontSize: 12,
                          fontWeight: FontWeight.bold,
                          color: AppColors.textSecondary)),
                  const SizedBox(height: 6),
                  DropdownButtonFormField<String>(
                    value: tipoVentaSeleccionado,
                    isExpanded: true,
                    decoration: const InputDecoration(
                      labelText: "F/D (Financiadora)",
                      border: OutlineInputBorder(),
                      contentPadding: EdgeInsets.symmetric(
                          horizontal: 10, vertical: 6),
                    ),
                    selectedItemBuilder: (ctx) => opcionesFD
                        .map((o) => Align(
                            alignment: Alignment.centerLeft,
                            child: chipFD(o, compacto: true)))
                        .toList(),
                    items: opcionesFD
                        .map((o) => DropdownMenuItem(
                            value: o, child: chipFD(o)))
                        .toList(),
                    onChanged: (v) {
                      if (v == null) return;
                      setS(() {
                        tipoVentaSeleccionado = v;
                        // Al cambiar de F/D se resetea el financiador
                        // (la persona) — solo aplica a ventas financiadas.
                        financiadorSeleccionado = null;
                      });
                    },
                  ),
                  // Si la venta es financiada (Cashea/Weppa/Krece), pedir
                  // el FINANCIADOR: la persona/usuario que entrega el equipo.
                  // OJO: esto es distinto de la FINANCIADORA (la app), que
                  // ya quedó definida arriba por el dropdown F/D.
                  if (tipoVentaSeleccionado == "Cashea" ||
                      tipoVentaSeleccionado == "Weppa" ||
                      tipoVentaSeleccionado == "Krece") ...[
                    const SizedBox(height: 8),
                    Container(
                      padding: const EdgeInsets.all(8),
                      decoration: BoxDecoration(
                        color: AppColors.brandBlue.withValues(alpha: 0.08),
                        borderRadius: BorderRadius.circular(8),
                      ),
                      child: Row(children: [
                        const Icon(Icons.account_balance,
                            size: 16, color: AppColors.brandBlue),
                        const SizedBox(width: 6),
                        Expanded(child: Text(
                          "Financiadora: $tipoVentaSeleccionado. "
                          "La deuda se calculará según la lista de "
                          "precios de $tipoVentaSeleccionado.",
                          style: const TextStyle(
                              fontSize: 11, height: 1.3),
                        )),
                      ]),
                    ),
                    const SizedBox(height: 10),
                    DropdownButtonFormField<String>(
                      value: financiadorSeleccionado,
                      isExpanded: true,
                      decoration: const InputDecoration(
                          labelText: "Financiador (quien entrega el equipo)",
                          border: OutlineInputBorder(),
                          isDense: true),
                      items: usuariosSistema
                          .map((u) => DropdownMenuItem(
                              value: u.nombre, child: Text(u.nombre)))
                          .toList(),
                      onChanged: (v) =>
                          setS(() => financiadorSeleccionado = v),
                    ),
                  ],
                ],
              ],
            ),
          ),
          actions: [
            TextButton(
                onPressed: () {
                  _codigo.clear();
                  Navigator.pop(c);
                },
                child: const Text("Cerrar")),
            ElevatedButton(
              style: ElevatedButton.styleFrom(
                  backgroundColor: puedeAgregar
                      ? AppColors.primaryBlue
                      : Colors.grey),
              onPressed: puedeAgregar
                  ? () {
                      _agregarProductoConFinanciamiento(
                          tipoVentaSeleccionado, financiadorSeleccionado);
                      Navigator.pop(c);
                    }
                  : null,
              child:
                  const Text("Agregar", style: TextStyle(color: Colors.white))),
          ]);
      }),
    );
  }

  /// Agrega el producto/equipo detectado (por _codigo) y registra el
  /// financiamiento por item en los mapas _tipoVentaItem/_financiadorItem.
  void _agregarProductoConFinanciamiento(
      String tipoVenta, String? financiador) {
    final val = _codigo.text.trim();
    if (val.isEmpty) return;

    final imei = stockImeiGlobal
        .where((i) => i.imei == val && !i.vendido)
        .firstOrNull;
    if (imei != null) {
      if (_equipos.contains(imei)) {
        ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
            content: Text("Este equipo ya está en la lista")));
        return;
      }
      setState(() {
        _equipos.add(imei);
        _tipoVentaEquipo[identityHashCode(imei)] = tipoVenta;
        _financiadorEquipo[identityHashCode(imei)] = financiador;
      });
      _codigo.clear();
      return;
    }

    final prod = catalogoGlobal.where((p) => p.codigo == val).firstOrNull;
    if (prod != null) {
      final yaAgregados =
          _items.where((p) => p.codigo == val).length;
      if (prod.stockTotal - yaAgregados <= 0) {
        ScaffoldMessenger.of(context).showSnackBar(SnackBar(
            content: Text(
                "Sin stock disponible para ${prod.nombre} (stock actual: ${prod.stockTotal})"),
            backgroundColor: Colors.orange[800]));
        return;
      }
      setState(() {
        _items.add(prod);
        _tipoVentaItem[identityHashCode(prod)] = tipoVenta;
        _financiadorItem[identityHashCode(prod)] = financiador;
      });
      _codigo.clear();
      return;
    }

    ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text("Producto no encontrado o ya vendido")));
  }

  /// Detecta si un nombre de método de pago corresponde a "Pago Móvil"
  /// (con o sin acento, mayúsculas/minúsculas).
  bool _esPagoMovil(String metodo) {
    final m = metodo.trim().toLowerCase();
    return m == 'pago móvil' || m == 'pago movil';
  }

  void _mostrarDialogoPago() {
    // ── Estado local del diálogo ───────────────────────────────
    // Banco destino (donde llega el pago — sólo aplica a Pago Móvil).
    // Por defecto sugerimos BDV (porque es el único con conciliación
    // automática en la app).
    String bancoDestinoSel = BancosVenezuela.codigoBDV;
    // Banco origen (de donde sale el dinero del cliente).
    String bancoOrigenSel = BancosVenezuela.codigoBDV;

    // Controllers para los campos de datos del pago móvil. Se crean
    // dentro del builder para que se reseteen cada vez que se abre
    // el diálogo. Se disponen al cerrar.
    final ctrlReferencia       = TextEditingController();
    final ctrlCedulaPagador    = TextEditingController();
    final ctrlTelefonoPagador  = TextEditingController();

    // Letra de la cédula del pagador (V/E/J/G/P).
    String letraCedula = 'V';
    // Fecha del pago — por defecto hoy.
    DateTime fechaPagoSel = DateTime.now();

    // Si el vendedor marca este pago como la INICIAL del cliente.
    // El reporte por financiadora usa este flag para saber qué monto
    // exacto restar como inicial en la fórmula (Base − Inicial) − 3.5%.
    bool marcarComoInicial = false;

    showDialog(context: context, builder: (c) => StatefulBuilder(builder: (context, setS) {
      final esPagoMovil = _esPagoMovil(_metodo);

      // ── Acción: aceptar el pago ──
      void aceptarPago() {
        final monto = double.tryParse(_montoPago.text.trim());
        if (monto == null || monto <= 0) {
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(content: Text("Ingrese un monto válido mayor a 0"),
              backgroundColor: AppColors.statusOrange));
          return;
        }

        if (esPagoMovil) {
          // Para pago móvil exigimos al menos referencia para auditoría
          if (ctrlReferencia.text.trim().isEmpty) {
            ScaffoldMessenger.of(context).showSnackBar(
              const SnackBar(content: Text("Ingrese la referencia del pago móvil"),
                backgroundColor: AppColors.statusOrange));
            return;
          }
          // Fecha del pago en formato YYYY-MM-DD
          final f = fechaPagoSel;
          final fechaFmt = '${f.year.toString().padLeft(4,"0")}-'
                           '${f.month.toString().padLeft(2,"0")}-'
                           '${f.day.toString().padLeft(2,"0")}';
          // Cédula con prefijo (puede estar vacía si el usuario no lo cargó
          // y no está intentando conciliar — el campo se queda en null)
          String? cedulaFmt;
          if (ctrlCedulaPagador.text.trim().isNotEmpty) {
            cedulaFmt = '$letraCedula${ctrlCedulaPagador.text.trim()}';
          }
          _agregarPago(
            bancoDestino       : bancoDestinoSel,
            bancoOrigen        : bancoOrigenSel,
            referenciaPM       : ctrlReferencia.text.trim(),
            cedulaPagador      : cedulaFmt,
            telefonoPagador    : ctrlTelefonoPagador.text.trim().isEmpty
                ? null : ctrlTelefonoPagador.text.trim(),
            // El teléfono destino siempre es el del comercio (no se
            // edita en el formulario, viene de ConfigBDV).
            telefonoDestino    : ConfigBDV.telefonoComercio,
            fechaPago          : fechaFmt,
            esInicial          : marcarComoInicial,
          );
        } else {
          _agregarPago(esInicial: marcarComoInicial);
        }
        Navigator.pop(c);
      }

      return AlertDialog(
        scrollable: true,
        title: Row(children: const [
          Icon(Icons.payment_outlined, color: AppColors.royalBlue),
          SizedBox(width: 8),
          Text("Registrar Pago"),
        ]),
        content: SizedBox(
          width: 420,
          child: Column(mainAxisSize: MainAxisSize.min,
              crossAxisAlignment: CrossAxisAlignment.stretch,
              children: [
            // ── Método de pago ─────────────────────────────────
            DropdownButtonFormField<String>(
              value: _metodo,
              isExpanded: true,
              decoration: const InputDecoration(
                labelText: "Método de pago",
                prefixIcon: Icon(Icons.payment)),
              items: ConfigSistema.metodossPago
                  .map((e) => DropdownMenuItem(value: e, child: Text(e))).toList(),
              onChanged: (v) => setS(() {
                _metodo = v!;
                // Al cambiar de método, reseteamos el resultado de
                // conciliación (porque puede dejar de aplicar).
              })),
            const SizedBox(height: 12),

            // ── Monto ──────────────────────────────────────────
            TextField(
              controller: _montoPago,
              autofocus: !esPagoMovil,
              keyboardType: const TextInputType.numberWithOptions(decimal: true),
              decoration: InputDecoration(
                labelText: esPagoMovil ? "Monto (Bs)" : "Monto",
                prefixIcon: const Icon(Icons.payments_outlined),
                helperText: esPagoMovil
                    ? "El importe se enviará al BDV en bolívares"
                    : null),
              onSubmitted: (_) {
                if (!esPagoMovil) aceptarPago();
              }),

            const SizedBox(height: 8),
            // ── Marcar como inicial ────────────────────────────
            // Este toggle le indica al sistema que ESTE pago en
            // específico es la inicial que el cliente paga de su
            // bolsillo. El Reporte por Financiadora lo usa en la
            // fórmula (Base − Inicial) − 3.5% = Deuda.
            Container(
              decoration: BoxDecoration(
                color: marcarComoInicial
                    ? AppColors.brandYellow.withValues(alpha: 0.15)
                    : AppColors.surfaceTintBlue,
                borderRadius: BorderRadius.circular(10),
                border: Border.all(
                  color: marcarComoInicial
                      ? AppColors.brandYellow
                      : Colors.transparent,
                  width: 1.5),
              ),
              child: SwitchListTile(
                value: marcarComoInicial,
                onChanged: (v) => setS(() => marcarComoInicial = v),
                activeColor: AppColors.brandBlue,
                contentPadding: const EdgeInsets.symmetric(horizontal: 12),
                title: const Text("Marcar como inicial del cliente",
                    style: TextStyle(
                        fontWeight: FontWeight.w700, fontSize: 13.5)),
                subtitle: const Text(
                    "Indica que este monto es la inicial que paga el "
                    "cliente. Se usa en el cálculo de deuda de la "
                    "financiadora.",
                    style: TextStyle(fontSize: 11, height: 1.3)),
                secondary: Icon(
                    marcarComoInicial
                        ? Icons.star
                        : Icons.star_outline,
                    color: marcarComoInicial
                        ? AppColors.brandYellow
                        : AppColors.textSecondary),
              ),
            ),

            // ── Bloque específico de Pago Móvil ───────────────
            if (esPagoMovil) ...[
              const SizedBox(height: 16),
              const Divider(),
              const SizedBox(height: 4),
              Row(children: const [
                Icon(Icons.account_balance, size: 16,
                    color: AppColors.royalBlue),
                SizedBox(width: 6),
                Text("DATOS DEL PAGO MÓVIL",
                    style: TextStyle(fontWeight: FontWeight.bold,
                        fontSize: 12, color: AppColors.royalBlue,
                        letterSpacing: 0.5)),
              ]),
              const SizedBox(height: 10),

              // Banco destino (donde llega el pago — el del comercio)
              DropdownButtonFormField<String>(
                value: bancoDestinoSel,
                isExpanded: true,
                decoration: const InputDecoration(
                    labelText: "Banco destino (cuenta del comercio)",
                    prefixIcon: Icon(Icons.account_balance_wallet_outlined)),
                items: BancosVenezuela.listaOrdenada
                    .map((e) => DropdownMenuItem(
                        value: e.key,
                        child: Text(
                          '${e.key} — ${e.value}',
                          overflow: TextOverflow.ellipsis,
                        )))
                    .toList(),
                onChanged: (v) => setS(() {
                  bancoDestinoSel = v!;
                })),
              const SizedBox(height: 10),

              // Banco origen (de donde paga el cliente)
              DropdownButtonFormField<String>(
                value: bancoOrigenSel,
                isExpanded: true,
                decoration: const InputDecoration(
                    labelText: "Banco origen (cuenta del cliente)",
                    prefixIcon: Icon(Icons.compare_arrows_outlined)),
                items: BancosVenezuela.listaOrdenada
                    .map((e) => DropdownMenuItem(
                        value: e.key,
                        child: Text(
                          '${e.key} — ${e.value}',
                          overflow: TextOverflow.ellipsis,
                        )))
                    .toList(),
                onChanged: (v) => setS(() {
                  bancoOrigenSel = v!;
                })),
              const SizedBox(height: 10),

              // Referencia
              TextField(
                controller: ctrlReferencia,
                keyboardType: TextInputType.number,
                decoration: const InputDecoration(
                  labelText: "Referencia *",
                  hintText: "Número de referencia del pago",
                  prefixIcon: Icon(Icons.confirmation_number_outlined)),
              ),
              const SizedBox(height: 10),

              // Fecha del pago
              Builder(builder: (_) {
                final hoy = DateTime.now();
                return InkWell(
                  borderRadius: BorderRadius.circular(10),
                  onTap: () async {
                    final picked = await showDatePicker(
                      context: context,
                      initialDate: fechaPagoSel,
                      firstDate: DateTime(2020),
                      lastDate: hoy.add(const Duration(days: 1)),
                      helpText: "Selecciona la fecha del pago móvil",
                    );
                    if (picked != null) {
                      setS(() { fechaPagoSel = picked; });
                    }
                  },
                  child: InputDecorator(
                    decoration: const InputDecoration(
                        labelText: "Fecha del pago",
                        prefixIcon: Icon(Icons.event_outlined)),
                    child: Text(
                      '${fechaPagoSel.day.toString().padLeft(2,"0")}/'
                      '${fechaPagoSel.month.toString().padLeft(2,"0")}/'
                      '${fechaPagoSel.year}',
