                  ),
                );
              }),

              // ── Datos del pagador (auditoría manual) ──────────
              const SizedBox(height: 14),
              Container(
                padding: const EdgeInsets.all(10),
                decoration: BoxDecoration(
                  color: AppColors.surfaceTintBlue,
                  borderRadius: BorderRadius.circular(8),
                ),
                child: Row(children: const [
                  Icon(Icons.info_outline, size: 16, color: AppColors.brandBlue),
                  SizedBox(width: 6),
                  Expanded(child: Text(
                    "Datos del pagador (opcional, para auditoría).",
                    style: TextStyle(fontSize: 11.5, height: 1.3),
                  )),
                ]),
              ),
              const SizedBox(height: 10),

              // Cédula del pagador (letra + número)
              Row(children: [
                SizedBox(
                  width: 90,
                  child: DropdownButtonFormField<String>(
                    value: letraCedula,
                    decoration: const InputDecoration(
                      labelText: "Tipo",
                      contentPadding: EdgeInsets.symmetric(
                          horizontal: 10, vertical: 14)),
                    items: const ['V', 'E', 'J', 'G', 'P']
                        .map((e) => DropdownMenuItem(
                            value: e, child: Text(e)))
                        .toList(),
                    onChanged: (v) => setS(() {
                      letraCedula = v!;
                    })),
                ),
                const SizedBox(width: 8),
                Expanded(child: TextField(
                  controller: ctrlCedulaPagador,
                  keyboardType: TextInputType.number,
                  decoration: const InputDecoration(
                    labelText: "Cédula del pagador (opcional)",
                    hintText: "12345678",
                    prefixIcon: Icon(Icons.badge_outlined)),
                )),
              ]),
              const SizedBox(height: 10),

              // Teléfono del pagador
              TextField(
                controller: ctrlTelefonoPagador,
                keyboardType: TextInputType.phone,
                decoration: const InputDecoration(
                  labelText: "Teléfono del pagador (opcional)",
                  hintText: "04127141363",
                  prefixIcon: Icon(Icons.phone_android)),
              ),
            ],
          ]),
        ),
        actions: [
          TextButton(
            onPressed: () { _montoPago.clear(); Navigator.pop(c); },
            child: const Text("Cancelar")),
          ElevatedButton(
            style: ElevatedButton.styleFrom(
                backgroundColor: AppColors.primaryBlue),
            onPressed: aceptarPago,
            child: const Text("Confirmar",
                style: TextStyle(color: Colors.white))),
        ]);
    })).then((_) {
      // Limpiar controllers locales al cerrar el diálogo
      ctrlReferencia.dispose();
      ctrlCedulaPagador.dispose();
      ctrlTelefonoPagador.dispose();
    });
  }

  /// Versión validada de _agregarPago — retorna true si se agregó correctamente
  bool _agregarPagoValidado() {
    final monto = double.tryParse(_montoPago.text.trim());
    if (monto == null || monto <= 0) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text("Ingrese un monto válido mayor a 0"),
          backgroundColor: AppColors.statusOrange));
      return false;
    }
    _agregarPago();
    return true;
  }

}

