//  BANNER DE RESULTADO DE CONCILIACIÓN BDV
//  Se muestra dentro del diálogo "Registrar Pago" cuando se ejecuta
//  la verificación contra el API del Banco de Venezuela.
//  · Verde   → code 1000 (transacción localizada y validada).
//  · Naranja → code 1010 u otro de negocio (no encontrado, datos
//              inválidos). El cajero puede aún registrar el pago,
//              pero queda marcado como "no conciliado".
//  · Rojo    → error de red / contrato JSON / conexión.
// ════════════════════════════════════════════════════════════════════

// ============================================================
//  BURBUJA DE AUDIO
// ============================================================
class BurbujaAudio extends StatefulWidget {
  final String path;
  const BurbujaAudio({super.key, required this.path});
  @override State<BurbujaAudio> createState() => _BurbujaAudioState();
}

class _BurbujaAudioState extends State<BurbujaAudio> {
  final AudioPlayer _audioPlayer = AudioPlayer();
  bool _reproduciendo = false;

  @override
  void initState() {
    super.initState();
    // Registrar listener una sola vez en initState, no en cada toque
    _audioPlayer.onPlayerComplete.listen((_) {
      if (mounted) setState(() => _reproduciendo = false);
    });
  }

  @override
  void dispose() {
    _audioPlayer.dispose();
    super.dispose();
  }

  Future<void> _toggleAudio() async {
    try {
      if (_reproduciendo) {
        await _audioPlayer.pause();
      } else {
        // Escoger la Source adecuada según el tipo de ruta.
        // Si viene una URL (http/https) o ruta relativa del servidor,
        // usamos UrlSource. Si es una ruta local legacy, DeviceFileSource.
        final p = widget.path;
        Source source;
        if (p.startsWith('http://') || p.startsWith('https://')) {
          source = UrlSource(p);
        } else if (p.startsWith('/') || p.startsWith('uploads/')) {
          final base = BASE_URL.replaceAll('/api.php', '');
          final sep = p.startsWith('/') ? '' : '/';
          source = UrlSource('$base$sep$p');
        } else {
          source = DeviceFileSource(p);
        }
        await _audioPlayer.play(source);
      }
      if (mounted) setState(() => _reproduciendo = !_reproduciendo);
    } catch (e) {
      debugPrint('[BurbujaAudio] Error: $e');
      if (mounted) setState(() => _reproduciendo = false);
    }
  }

  @override
  Widget build(BuildContext context) {
    return Row(mainAxisSize: MainAxisSize.min, children: [
      IconButton(
        icon: Icon(_reproduciendo ? Icons.pause : Icons.play_arrow,
          color: Colors.white),
        onPressed: _toggleAudio),
      const Text("Mensaje de voz", style: TextStyle(color: Colors.white)),
    ]);
  }
}

// ============================================================
//  ESCANER QR/IMEI
// ============================================================
class ScannerPage extends StatefulWidget {
  final Function(String) onDetect;
  const ScannerPage({super.key, required this.onDetect});
  @override
  State<ScannerPage> createState() => _ScannerPageState();
}

class _ScannerPageState extends State<ScannerPage> {
  /// Bandera para que onDetect SOLO se dispare una vez. MobileScanner
  /// emite el barcode múltiples veces por segundo mientras la cámara lo
  /// "ve", y sin este guard cada detección hacía un Navigator.pop()
  /// extra, sacando al usuario varias rutas atrás (lo que vaciaba el
  /// estado de la pantalla de factura).
  bool _yaDetectado = false;
  MobileScannerController? _controller;

  @override
  void initState() {
    super.initState();
    _controller = MobileScannerController(
      detectionSpeed: DetectionSpeed.normal,
      facing: CameraFacing.back,
    );
  }

  @override
  void dispose() {
    _controller?.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text("Escanear"),
        actions: [
          IconButton(
            icon: const Icon(Icons.flash_on),
            tooltip: "Flash",
            onPressed: () => _controller?.toggleTorch(),
          ),
          IconButton(
            icon: const Icon(Icons.cameraswitch),
            tooltip: "Cambiar cámara",
            onPressed: () => _controller?.switchCamera(),
          ),
        ],
      ),
      body: MobileScanner(
        controller: _controller,
        onDetect: (capture) {
          // Guard: solo procesar la PRIMERA detección. MobileScanner emite
          // el mismo código repetidamente y sin esta protección se hacían
          // múltiples Navigator.pop, sacando al usuario fuera de la
          // pantalla que abrió el escáner.
          if (_yaDetectado) return;
          final barcodes = capture.barcodes;
          for (final barcode in barcodes) {
            final String? code = barcode.rawValue;
            if (code != null && code.isNotEmpty) {
              _yaDetectado = true;
              // Detener la cámara INMEDIATAMENTE para que no siga emitiendo
              _controller?.stop();
              widget.onDetect(code);
              if (mounted) Navigator.pop(context);
              return;
            }
          }
        }),
    );
  }
}

// ============================================================
//  LISTAS DE PRECIOS
// ============================================================
class VentanaListasPrecios extends StatefulWidget {
  const VentanaListasPrecios({super.key});
  @override State<VentanaListasPrecios> createState() => _VentanaListasPreciosState();
}

class _VentanaListasPreciosState extends State<VentanaListasPrecios> {
  bool _cargando = true;

  /// Timer que recarga periódicamente las listas desde el servidor.
  /// Cuando el administrador edita una lista en su dispositivo, el resto
  /// de las sesiones abiertas la verán refrescada en máximo 10 segundos.
  Timer? _timerSync;

  /// Hash simple de la versión del servidor para detectar cambios y
  /// evitar setState innecesarios cuando no hubo modificaciones.
  String _ultimoHashServidor = '';

  @override
  void initState() {
    super.initState();
    _cargarDesdeServidor();
    // Auto-sincronización: cada 10 segundos pregunta al servidor por
    // las listas y, si hay cambios, refresca la pantalla de TODOS los
    // usuarios sin importar qué dispositivo hizo el cambio.
    _timerSync = Timer.periodic(const Duration(seconds: 10), (_) {
      if (!mounted) {
        _timerSync?.cancel();
        return;
      }
      _cargarDesdeServidor(silencioso: true);
    });
  }

  @override
  void dispose() {
    _timerSync?.cancel();
    super.dispose();
  }

  /// Carga las listas desde el backend.
  /// `silencioso=true` evita el spinner — usado por el polling para que
  /// no parpadee la UI.
  Future<void> _cargarDesdeServidor({bool silencioso = false}) async {
    if (!silencioso && mounted) setState(() => _cargando = true);
    try {
      final raw = await _Api.get('listas_precios');
      if (raw is List) {
        // Hash rápido (cantidad + concat de nombres + última fecha) para
        // detectar si el contenido cambió. Si es igual al último, no
        // hacemos setState — evita rebuilds inútiles.
        final nuevoHash = '${raw.length}|'
            '${raw.map((m) => '${m['id']}-${m['nombre']}-${m['fecha_creacion']}').join(',')}';
        if (nuevoHash == _ultimoHashServidor) {
          if (!silencioso && mounted) setState(() => _cargando = false);
          return;
        }
        _ultimoHashServidor = nuevoHash;
        listasPreciosGlobal = raw
            .map((m) => ListaPrecio.fromMap(m as Map<String, dynamic>))
            .toList();
        if (mounted) setState(() {});
      }
    } catch (e) {
      debugPrint('[ListasPrecios] Error al cargar: $e');
    } finally {
      if (!silencioso && mounted) setState(() => _cargando = false);
    }
  }

  /// Re-puebla la lista (productos del catálogo + tasa actual) y la
  /// PERSISTE en el backend. Antes el "Actualizar" sólo cambiaba la
  /// memoria local del admin: otros usuarios nunca veían los cambios.
  Future<void> _actualizarListaYPersistir(ListaPrecio lista) async {
    // 1) Re-poblar localmente
    setState(() => _poblarLista(lista));
    // 2) Persistir en BD: si ya tiene id, hacemos PUT; si no, POST.
    try {
      if (lista.id != null) {
        await _Api.put('listas_precios', lista.id.toString(), lista.toMap());
      } else {
        final resp = await _Api.post('listas_precios', lista.toMap());
        if (resp is Map && resp['id'] != null) {
          lista.id = resp['id'] is int
              ? resp['id']
              : int.tryParse(resp['id'].toString());
        }
      }
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(SnackBar(
          content: Text('✅ ${lista.items.length} productos actualizados '
              'y sincronizados con todos los usuarios'),
          backgroundColor: AppColors.statusGreen));
      }
      // Forzar siguiente refresh para los demás dispositivos
      _ultimoHashServidor = '';
    } catch (e) {
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(SnackBar(
          content: Text('Error al guardar en servidor: $e'),
          backgroundColor: AppColors.statusRed));
      }
    }
  }

  /// Elimina la lista en backend y local. Antes sólo borraba en memoria,
  /// así que reaparecía al recargar y los otros usuarios la seguían viendo.
  Future<void> _eliminarListaYPersistir(ListaPrecio lista) async {
    try {
      if (lista.id != null) {
        await _Api.delete('listas_precios', lista.id!.toString());
      }
      if (mounted) {
        setState(() => listasPreciosGlobal.remove(lista));
        ScaffoldMessenger.of(context).showSnackBar(SnackBar(
          content: Text('Lista "${lista.nombre}" eliminada'),
          backgroundColor: AppColors.statusGreen));
      }
      _ultimoHashServidor = '';
    } catch (e) {
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(SnackBar(
          content: Text('Error al eliminar: $e'),
          backgroundColor: AppColors.statusRed));
      }
    }
  }

  // ── Lógica de auto-población ─────────────────────────────────
  /// Puebla los ítems de la lista automáticamente según su categoría y marca.
  /// Agrupa por marca+modelo, calcula el precio según la moneda y agrega
  /// una columna "Precio Venta" predeterminada con el stock disponible.
  void _poblarLista(ListaPrecio lista) {
    // Calcular tasa a usar (BCV si está disponible)
    final tasa = lista.esEnBolivares
        ? (ConfigSistema.tasaCambio > 0 ? ConfigSistema.tasaCambio : lista.tasaDelDia)
        : 1.0;

    // Filtrar productos según categoría y marca
    final productosFiltrados = catalogoGlobal.where((p) {
      final coincideCategoria = lista.categoria == "Todos" || p.categoria == lista.categoria;
      final coincideMarca = lista.marcaFiltro == "Todas" ||
          p.marca.toLowerCase() == lista.marcaFiltro.toLowerCase();
      return coincideCategoria && coincideMarca;
    }).toList();

    // Ordenar por marca → modelo
    productosFiltrados.sort((a, b) {
      final marcaCmp = a.marca.toLowerCase().compareTo(b.marca.toLowerCase());
      return marcaCmp != 0 ? marcaCmp : a.nombre.toLowerCase().compareTo(b.nombre.toLowerCase());
    });

    // Crear columna por defecto si la lista está vacía de columnas
    if (lista.columnas.isEmpty) {
      lista.columnas.add(ColumnaPrecio(nombre: lista.esEnBolivares ? "Precio (Bs)" : "Precio (\$)"));
    }

    lista.items.clear();

    for (final p in productosFiltrados) {
      // Calcular stock disponible real
      final stock = p.categoria == 'Telefono'
          ? stockImeiGlobal.where((i) => i.producto.codigo == p.codigo && !i.vendido).length
          : p.stockManual;

      // Calcular precio según moneda de la lista
      final precioBase = lista.esEnBolivares
          ? (p.precioVenta * tasa)
          : p.precioVenta;

      lista.items.add(ItemListaPrecio(
        producto: p,
        stockDisponible: stock,
        preciosPorColumna: {
          for (var col in lista.columnas) col.nombre: precioBase
        },
      ));
    }
  }

  // ── Diálogo de creación ───────────────────────────────────────
  void _crearNuevaLista() {
    final nombreCtrl      = TextEditingController();
    final tasaCtrl        = TextEditingController(text: ConfigSistema.tasaCambio.toStringAsFixed(2));
    final pctAdicionalCtrl = TextEditingController(text: "0");    // % adicional al precio
    final financiadoraCtrl = TextEditingController();
    final pctInicialCtrl   = TextEditingController(text: "0");   // % para la inicial
    final cuotasCtrl       = TextEditingController(text: "12");  // número de cuotas
    final pctComisionWeppaCtrl = TextEditingController(text: "0"); // % comisión Weppa
    final pctRecargoCuotasCtrl = TextEditingController(text: "0"); // % recargo sobre cuotas
    String categoria    = "Telefono";
    String marcaFiltro  = "Todas";
    bool esBs           = false;
    bool esFinanc       = false;  // ¿Es lista de financiamiento?

    List<String> _marcasDisponibles(String cat) {
      final marcas = catalogoGlobal
          .where((p) => cat == "Todos" || p.categoria == cat)
          .map((p) => p.marca.trim())
          .where((m) => m.isNotEmpty)
          .toSet()
          .toList()..sort();
      return ["Todas", ...marcas];
    }

    final categorias = ["Telefono", "Accesorio", "Televisor", "Linea Blanca", "Linea", "Todos"];

    showDialog(
      context: context,
      builder: (ctx) => StatefulBuilder(
        builder: (ctx, setDlg) {
          final marcas = _marcasDisponibles(categoria);
          if (!marcas.contains(marcaFiltro)) marcaFiltro = "Todas";

          return AlertDialog(
            title: const Row(children: [
              Icon(Icons.playlist_add, color: AppColors.royalBlue),
              SizedBox(width: 8),
              Text("Nueva Lista de Precios"),
            ]),
            content: SingleChildScrollView(child: Column(
              mainAxisSize: MainAxisSize.min,
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                // Nombre
                TextField(
                  controller: nombreCtrl,
                  decoration: const InputDecoration(
                    labelText: "Nombre de la lista",
                    prefixIcon: Icon(Icons.label_outline)),
                ),
                const SizedBox(height: 16),

                // Categoría
                const Text("Categoría de productos",
                  style: TextStyle(fontWeight: FontWeight.bold, fontSize: 13)),
                const SizedBox(height: 6),
                Wrap(spacing: 8, runSpacing: 6, children: categorias.map((cat) {
                  final selected = categoria == cat;
                  return ChoiceChip(
                    avatar: Icon(_iconoCategoria(cat), size: 16,
                      color: selected ? Colors.white : AppColors.royalBlue),
                    label: Text(cat),
                    selected: selected,
                    selectedColor: AppColors.primaryBlue,
                    labelStyle: TextStyle(
                      color: selected ? Colors.white : Colors.black87,
