                  // ── % Comisión Weppa (solo visible si la financiadora es Weppa) ──
                  if (financiadoraCtrl.text.trim().toLowerCase().contains('weppa')) ...[
                    const SizedBox(height: 10),
                    Container(
                      padding: const EdgeInsets.all(10),
                      decoration: BoxDecoration(
                        color: AppColors.statusGreen.withValues(alpha: 0.06),
                        borderRadius: BorderRadius.circular(8),
                        border: Border.all(
                            color: AppColors.statusGreen.withValues(alpha: 0.4)),
                      ),
                      child: Column(
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: [
                            Row(children: const [
                              Icon(Icons.percent,
                                  size: 16, color: AppColors.statusGreen),
                              SizedBox(width: 6),
                              Text('Comisión Weppa',
                                  style: TextStyle(
                                      fontSize: 12,
                                      fontWeight: FontWeight.bold,
                                      color: AppColors.statusGreen)),
                            ]),
                            const SizedBox(height: 8),
                            TextField(
                              controller: pctComisionWeppaCtrl,
                              keyboardType:
                                  const TextInputType.numberWithOptions(
                                      decimal: true),
                              decoration: const InputDecoration(
                                labelText: '% de comisión sobre precio de venta',
                                hintText: 'Ej: 5',
                                prefixIcon: Icon(Icons.monetization_on_outlined),
                                border: OutlineInputBorder(),
                                isDense: true,
                              ),
                            ),
                            const SizedBox(height: 4),
                            const Text(
                                'Se aplicará al precio de venta de cada producto '
                                'vendido con esta financiadora para calcular la '
                                'comisión del vendedor.',
                                style: TextStyle(
                                    fontSize: 10,
                                    color: AppColors.textSecondary)),
                          ]),
                    ),
                  ],
                ],
                const SizedBox(height: 14),

                // Preview
                Builder(builder: (_) {
                  final count = catalogoGlobal.where((p) {
                    final catOk = categoria == "Todos" || p.categoria == categoria;
                    final marcaOk = marcaFiltro == "Todas" ||
                        p.marca.toLowerCase() == marcaFiltro.toLowerCase();
                    return catOk && marcaOk;
                  }).length;
                  return Container(
                    padding: const EdgeInsets.all(10),
                    decoration: BoxDecoration(
                      color: count > 0 ? Colors.green[50] : Colors.orange[50],
                      borderRadius: BorderRadius.circular(8),
                      border: Border.all(
                        color: count > 0 ? Colors.green : Colors.orange)),
                    child: Row(children: [
                      Icon(count > 0
                        ? Icons.check_circle_outline : Icons.warning_amber_outlined,
                        color: count > 0 ? Colors.green : Colors.orange, size: 18),
                      const SizedBox(width: 8),
                      Expanded(child: Text(
                        count > 0
                          ? "Se agregarán $count producto${count != 1 ? 's' : ''} automáticamente"
                          : "No hay productos de esta categoría/marca",
                        style: TextStyle(
                          fontSize: 12,
                          color: count > 0 ? Colors.green[800] : Colors.orange[800]))),
                    ]),
                  );
                }),
              ],
            )),
            actions: [
              TextButton(
                onPressed: () {
                  Navigator.pop(ctx);
                  nombreCtrl.dispose(); tasaCtrl.dispose();
                  pctAdicionalCtrl.dispose(); financiadoraCtrl.dispose();
                  pctInicialCtrl.dispose(); cuotasCtrl.dispose();
                  pctComisionWeppaCtrl.dispose();
                  pctRecargoCuotasCtrl.dispose();
                },
                child: const Text("CANCELAR")),
              ElevatedButton.icon(
                icon: const Icon(Icons.playlist_add),
                label: const Text("CREAR"),
                onPressed: () async {
                  if (nombreCtrl.text.trim().isEmpty) {
                    ScaffoldMessenger.of(context).showSnackBar(
                      const SnackBar(content: Text("Ingrese un nombre para la lista")));
                    return;
                  }
                  if (esFinanc && financiadoraCtrl.text.trim().isEmpty) {
                    ScaffoldMessenger.of(context).showSnackBar(
                      const SnackBar(content: Text("Ingrese el nombre de la financiadora")));
                    return;
                  }
                  final tasa = esBs
                    ? (double.tryParse(tasaCtrl.text) ?? ConfigSistema.tasaCambio)
                    : 1.0;
                  final pctAdicional = double.tryParse(pctAdicionalCtrl.text) ?? 0.0;
                  final pctInicial   = double.tryParse(pctInicialCtrl.text) ?? 0.0;
                  final cuotas       = int.tryParse(cuotasCtrl.text) ?? 12;
                  final pctComisionWeppa =
                      double.tryParse(pctComisionWeppaCtrl.text) ?? 0.0;
                  final pctRecargoCuotas =
                      double.tryParse(pctRecargoCuotasCtrl.text) ?? 0.0;

                  final nueva = ListaPrecio(
                    nombre: nombreCtrl.text.trim(),
                    fechaCreacion: obtenerFechaActual(),
                    categoria: categoria,
                    marcaFiltro: marcaFiltro,
                    esEnBolivares: esBs,
                    tasaDelDia: tasa,
                    porcentajeAdicional: pctAdicional,
                    esFinanciamiento: esFinanc,
                    financiadora: esFinanc ? financiadoraCtrl.text.trim() : null,
                    porcentajeInicial: pctInicial,
                    numeroCuotas: cuotas,
                    porcentajeComisionWeppa: pctComisionWeppa,
                    porcentajeRecargoCuotas: pctRecargoCuotas,
                    columnas: [ColumnaPrecio(nombre: "Precio")],
                  );
                  _poblarLista(nueva);
                  // Aplicar porcentaje adicional a los precios
                  if (pctAdicional > 0) {
                    for (final item in nueva.items) {
                      for (final col in item.preciosPorColumna.keys.toList()) {
                        item.preciosPorColumna[col] =
                          item.preciosPorColumna[col]! * (1 + pctAdicional / 100);
                      }
                    }
                  }
                  // ── Persistir en backend ──
                  // Antes la lista se agregaba sólo a `listasPreciosGlobal`
                  // (memoria de la sesión) y nunca al servidor, así que
                  // ningún otro usuario la veía y se perdía al cerrar.
                  try {
                    final resp = await _Api.post('listas_precios', nueva.toMap());
                    if (resp is Map && resp['id'] != null) {
                      nueva.id = (resp['id'] is int)
                          ? resp['id']
                          : int.tryParse(resp['id'].toString());
                    }
                    if (mounted) {
                      setState(() => listasPreciosGlobal.add(nueva));
                      Navigator.pop(ctx);
                      ScaffoldMessenger.of(context).showSnackBar(
                        const SnackBar(
                          content: Text('Lista creada y guardada en el servidor'),
                          backgroundColor: AppColors.statusGreen));
                    }
                  } catch (e) {
                    if (mounted) {
                      ScaffoldMessenger.of(context).showSnackBar(SnackBar(
                        content: Text('No se pudo guardar la lista: $e'),
                        backgroundColor: AppColors.statusRed));
                    }
                    return;
                  }
                  nombreCtrl.dispose(); tasaCtrl.dispose();
                  pctAdicionalCtrl.dispose(); financiadoraCtrl.dispose();
                  pctInicialCtrl.dispose(); cuotasCtrl.dispose();
                  pctComisionWeppaCtrl.dispose();
                  pctRecargoCuotasCtrl.dispose();
                }),
            ],
          );
        },
      ),
    );
  }
  IconData _iconoCategoria(String cat) {
    switch (cat) {
      case 'Telefono':    return Icons.phone_android;
      case 'Accesorio':  return Icons.headphones;
      case 'Televisor':  return Icons.tv;
      case 'Linea':      return Icons.sim_card;
      case 'Linea Blanca': return Icons.kitchen_outlined;
      default:           return Icons.category;
    }
  }

  @override
  Widget build(BuildContext context) {
    // Sólo Administrador ve los iconos de sync/eliminar y el botón "+ crear".
    // Los demás roles ven la lista en modo lectura.
    final esAdmin = (usuarioSesion?.rol == "Administrador" || usuarioSesion?.rol == "Maestro");
    return Scaffold(
      appBar: AppBar(
        title: const Text("Listas de Precios"),
      ),
      body: listasPreciosGlobal.isEmpty
          ? Center(child: Column(mainAxisAlignment: MainAxisAlignment.center, children: [
              const Icon(Icons.list_alt, size: 64, color: Colors.grey),
              const SizedBox(height: 12),
              const Text("No hay listas creadas", style: TextStyle(fontSize: 16, color: Colors.grey)),
              const SizedBox(height: 8),
              const Text("Presiona + para crear una lista con\nproductos agregados automáticamente",
                textAlign: TextAlign.center,
                style: TextStyle(fontSize: 12, color: Colors.grey)),
            ]))
          : ListView.builder(
              padding: const EdgeInsets.all(12),
              itemCount: listasPreciosGlobal.length,
              itemBuilder: (c, i) {
                final lista = listasPreciosGlobal[i];
                return Card(
                  child: ListTile(
                    leading: CircleAvatar(
                      backgroundColor: lista.esEnBolivares
                          ? Colors.green.withValues(alpha: 0.15)
                          : AppColors.primaryBlue.withValues(alpha: 0.15),
                      child: Icon(_iconoCategoria(lista.categoria),
                        color: lista.esEnBolivares ? Colors.green[700] : AppColors.primaryBlue)),
                    title: Text(lista.nombre, style: const TextStyle(fontWeight: FontWeight.bold)),
                    subtitle: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                      Text("${lista.categoria} · ${lista.marcaFiltro == 'Todas' ? 'Todas las marcas' : lista.marcaFiltro}"),
                      Text("${lista.items.length} productos · ${lista.esEnBolivares ? 'Bs (tasa ${lista.tasaDelDia.toStringAsFixed(2)})' : '\$ Divisas'} · ${lista.fechaCreacion}",
                        style: const TextStyle(fontSize: 11, color: Colors.grey)),
                    ]),
                    trailing: Row(mainAxisSize: MainAxisSize.min, children: [
                      // ── Sólo Administrador puede actualizar/eliminar ──
                      if (esAdmin) ...[
                        // Botón re-poblar
                        IconButton(
                          icon: const Icon(Icons.sync, color: AppColors.primaryBlue),
                          tooltip: "Actualizar productos automáticamente",
                          onPressed: () {
                            showDialog(context: context, builder: (ctx) => AlertDialog(
                              title: const Text("Actualizar lista"),
                              content: Text(
                                "¿Desea re-poblar \"${lista.nombre}\" automáticamente?\n\n"
                                "Esto actualizará los productos y stocks según el catálogo actual. "
                                "Los precios editados manualmente se perderán."),
                              actions: [
                                TextButton(onPressed: () => Navigator.pop(ctx), child: const Text("Cancelar")),
                                ElevatedButton.icon(
                                  icon: const Icon(Icons.sync),
                                  label: const Text("Actualizar"),
                                  onPressed: () async {
                                    Navigator.pop(ctx);
                                    await _actualizarListaYPersistir(lista);
                                  }),
                              ],
                            ));
                          }),
                        // Botón eliminar
                        IconButton(
                          icon: const Icon(Icons.delete_outline, color: Colors.red),
                          tooltip: "Eliminar lista",
                          onPressed: () => showDialog(context: context, builder: (ctx) => AlertDialog(
                            title: const Text("Eliminar lista"),
                            content: Text("¿Está seguro que desea eliminar \"${lista.nombre}\"?"),
                            actions: [
                              TextButton(onPressed: () => Navigator.pop(ctx), child: const Text("Cancelar")),
                              ElevatedButton(
                                style: ElevatedButton.styleFrom(backgroundColor: AppColors.statusRed),
                                onPressed: () async {
                                  Navigator.pop(ctx);
                                  await _eliminarListaYPersistir(lista);
                                },
                                child: const Text("Eliminar", style: TextStyle(color: Colors.white))),
                            ],
                          )),
                        ),
                      ],
                      const Icon(Icons.chevron_right),
                    ]),
                    onTap: () => Navigator.push(context,
                      MaterialPageRoute(builder: (_) => DetalleListaPrecio(lista: lista)))
                      .then((_) => setState(() {})),
                  ),
                );
              }),
      floatingActionButton: FloatingActionButton.extended(
        backgroundColor: AppColors.primaryBlue,
        icon: const Icon(Icons.add_chart, color: Colors.white),
        label: const Text("Nueva Lista", style: TextStyle(color: Colors.white)),
        onPressed: _crearNuevaLista,
      ),
    );
  }
}

// ============================================================
//  DETALLE LISTA DE PRECIOS — vista mejorada agrupada por marca
// ============================================================
class DetalleListaPrecio extends StatefulWidget {
  final ListaPrecio lista;
  const DetalleListaPrecio({super.key, required this.lista});
  @override State<DetalleListaPrecio> createState() => _DetalleListaPrecioState();
}

class _DetalleListaPrecioState extends State<DetalleListaPrecio> {
  String _busqueda = "";
  final _searchCtrl = TextEditingController();

  @override
  void dispose() { _searchCtrl.dispose(); super.dispose(); }

  // Agrupa los ítems por marca
  Map<String, List<ItemListaPrecio>> _agrupadosPorMarca() {
    final mapa = <String, List<ItemListaPrecio>>{};
    final filtrados = widget.lista.items.where((it) =>
      _busqueda.isEmpty ||
      it.producto.nombre.toLowerCase().contains(_busqueda.toLowerCase()) ||
      it.producto.marca.toLowerCase().contains(_busqueda.toLowerCase()) ||
      it.producto.codigo.toLowerCase().contains(_busqueda.toLowerCase())).toList();
    for (final it in filtrados) {
      final marca = it.producto.marca.isEmpty ? "Sin marca" : it.producto.marca;
      mapa.putIfAbsent(marca, () => []).add(it);
    }
    return mapa;
  }

  void _anadirColumna() {
    final colCtrl = TextEditingController();
    showDialog(context: context, builder: (c) => AlertDialog(
      title: const Text("Nueva Columna de Precio"),
      content: TextField(
        controller: colCtrl,
        autofocus: true,
        decoration: const InputDecoration(
          hintText: "Ej: Detal, Mayorista, Contado...",
          prefixIcon: Icon(Icons.view_column))),
      actions: [
        TextButton(onPressed: () => Navigator.pop(context), child: const Text("Cancelar")),
        ElevatedButton(
          onPressed: () {
            if (colCtrl.text.trim().isNotEmpty) {
              setState(() {
                final nombreCol = colCtrl.text.trim();
                widget.lista.columnas.add(ColumnaPrecio(nombre: nombreCol));
                for (var item in widget.lista.items) {
                  if (!item.preciosPorColumna.containsKey(nombreCol)) {
                    // Hereda el precio de la primera columna o el precio de venta
                    final base = item.preciosPorColumna.values.isNotEmpty
                        ? item.preciosPorColumna.values.first
                        : (widget.lista.esEnBolivares
                            ? item.producto.precioVenta * widget.lista.tasaDelDia
                            : item.producto.precioVenta);
                    item.preciosPorColumna[nombreCol] = base;
                  }
                }
              });
              colCtrl.dispose();
              Navigator.pop(context);
            }
          },
          child: const Text("Añadir")),
      ]));
  }

  void _editarPrecioItem(ItemListaPrecio item, String nombreColumna) {
    final priceCtrl = TextEditingController(
      text: (item.preciosPorColumna[nombreColumna] ?? 0.0).toStringAsFixed(2));
    showDialog(context: context, builder: (c) => AlertDialog(
      title: Text("Precio: ${item.producto.nombre}"),
      content: Column(mainAxisSize: MainAxisSize.min, children: [
        Text("Columna: $nombreColumna", style: const TextStyle(color: Colors.grey)),
        const SizedBox(height: 12),
        TextField(
          controller: priceCtrl,
          autofocus: true,
          keyboardType: TextInputType.numberWithOptions(decimal: true),
          decoration: InputDecoration(
            labelText: widget.lista.esEnBolivares ? "Precio (Bs)" : "Precio (\$)",
            prefixIcon: const Icon(Icons.attach_money))),
      ]),
      actions: [
        TextButton(onPressed: () => Navigator.pop(context), child: const Text("Cancelar")),
        ElevatedButton(
          onPressed: () {
            setState(() => item.preciosPorColumna[nombreColumna] =
                double.tryParse(priceCtrl.text) ?? 0.0);
            priceCtrl.dispose();
            Navigator.pop(context);
          },
          child: const Text("Guardar")),
      ]));
  }

  // Editar precio de TODA una columna de una vez (ajuste por porcentaje o valor fijo)
  void _editarColumnaCompleta(ColumnaPrecio col) {
    final porcentajeCtrl = TextEditingController();
    bool esPorcentaje = true;
    showDialog(context: context, builder: (ctx) => StatefulBuilder(
      builder: (ctx, setD) => AlertDialog(
        title: Text("Ajustar columna: ${col.nombre}"),
        content: Column(mainAxisSize: MainAxisSize.min, children: [
          SwitchListTile(
            title: Text(esPorcentaje ? "Ajuste por porcentaje (%)" : "Valor fijo a sumar/restar"),
            value: esPorcentaje,
            onChanged: (v) => setD(() => esPorcentaje = v),
          ),
          TextField(
            controller: porcentajeCtrl,
            autofocus: true,
            keyboardType: TextInputType.numberWithOptions(decimal: true, signed: true),
            decoration: InputDecoration(
              labelText: esPorcentaje ? "Porcentaje (ej: 10 para +10%, -5 para -5%)" : "Valor a añadir/restar",
              prefixIcon: Icon(esPorcentaje ? Icons.percent : Icons.attach_money))),
        ]),
        actions: [
          TextButton(onPressed: () => Navigator.pop(ctx), child: const Text("Cancelar")),
          ElevatedButton(
            onPressed: () {
              final val = double.tryParse(porcentajeCtrl.text);
              if (val == null) return;
              setState(() {
                for (final item in widget.lista.items) {
                  final actual = item.preciosPorColumna[col.nombre] ?? 0.0;
                  item.preciosPorColumna[col.nombre] = esPorcentaje
                      ? (actual * (1 + val / 100))
                      : (actual + val);
                }
              });
              porcentajeCtrl.dispose();
              Navigator.pop(ctx);
              ScaffoldMessenger.of(context).showSnackBar(SnackBar(
                content: Text("✅ ${widget.lista.items.length} precios actualizados en ${col.nombre}"),
                backgroundColor: AppColors.statusGreen));
            },
            child: const Text("Aplicar a todos")),
        ])));
  }

  @override
  Widget build(BuildContext context) {
    final agrupados = _agrupadosPorMarca();
    final moneda = widget.lista.esEnBolivares ? "Bs" : "\$";
    // Sólo Administrador puede crear/editar listas de precios.
    // Otros roles (incluido Dueño) las ven en modo lectura.
    final esAdmin = (usuarioSesion?.rol == "Administrador" || usuarioSesion?.rol == "Maestro");

    return Scaffold(
      appBar: AppBar(
        title: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
          Text(widget.lista.nombre, style: const TextStyle(fontSize: 16, fontWeight: FontWeight.bold)),
          Text(
            "${widget.lista.categoria} · ${widget.lista.marcaFiltro == 'Todas' ? 'Todas las marcas' : widget.lista.marcaFiltro} · $moneda"
            "${widget.lista.esFinanciamiento ? ' · ${widget.lista.financiadora ?? 'Financiamiento'} · ${widget.lista.numeroCuotas} cuotas' : ''}",
            style: const TextStyle(fontSize: 11, color: Colors.white70)),
        ]),
        backgroundColor: AppColors.royalBlue,
        actions: [
          if (esAdmin) ...[
            IconButton(icon: const Icon(Icons.view_column), tooltip: "Nueva columna", onPressed: _anadirColumna),
            IconButton(
              icon: const Icon(Icons.add_shopping_cart),
              tooltip: "Agregar productos manualmente",
              onPressed: () => Navigator.push(context,
                MaterialPageRoute(builder: (_) => SelectorProductosLista(lista: widget.lista)))
                .then((_) => setState(() {}))),
            IconButton(
              icon: const Icon(Icons.sync),
              tooltip: "Re-poblar automáticamente",
              onPressed: () => showDialog(context: context, builder: (ctx) => AlertDialog(
                title: const Text("Re-poblar lista"),
                content: const Text("¿Actualizar todos los productos automáticamente desde el catálogo?\n\nLos precios editados manualmente se resetearán."),
                actions: [
                  TextButton(onPressed: () => Navigator.pop(ctx), child: const Text("Cancelar")),
                  ElevatedButton.icon(
                    icon: const Icon(Icons.sync),
                    label: const Text("Actualizar"),
                    onPressed: () {
                      // Actualizar la tasa si usa BCV
                      if (widget.lista.esEnBolivares && TasaBCVScheduler.ultimaTasa != null) {
                        widget.lista.tasaDelDia = ConfigSistema.tasaCambio;
                      }
                      setState(() {
                        // Re-poblar usando la lógica de VentanaListasPrecios
                        final tasa = widget.lista.esEnBolivares ? ConfigSistema.tasaCambio : 1.0;
                        final filtrados = catalogoGlobal.where((p) {
                          final catOk = widget.lista.categoria == "Todos" || p.categoria == widget.lista.categoria;
                          final marcaOk = widget.lista.marcaFiltro == "Todas" ||
                              p.marca.toLowerCase() == widget.lista.marcaFiltro.toLowerCase();
                          return catOk && marcaOk;
                        }).toList()
                          ..sort((a, b) {
                            final mc = a.marca.toLowerCase().compareTo(b.marca.toLowerCase());
                            return mc != 0 ? mc : a.nombre.toLowerCase().compareTo(b.nombre.toLowerCase());
                          });
                        widget.lista.items.clear();
                        for (final p in filtrados) {
                          final stock = p.categoria == 'Telefono'
                              ? stockImeiGlobal.where((i) => i.producto.codigo == p.codigo && !i.vendido).length
                              : p.stockManual;
                          final precioBase = widget.lista.esEnBolivares ? (p.precioVenta * tasa) : p.precioVenta;
                          widget.lista.items.add(ItemListaPrecio(
                            producto: p,
                            stockDisponible: stock,
                            preciosPorColumna: { for (var col in widget.lista.columnas) col.nombre: precioBase },
                          ));
                        }
                      });
                      Navigator.pop(ctx);
                      ScaffoldMessenger.of(context).showSnackBar(SnackBar(
                        content: Text("✅ ${widget.lista.items.length} productos actualizados"),
                        backgroundColor: AppColors.statusGreen));
                    }),
                ],
              ))),
          ],
        ],
      ),
      body: widget.lista.items.isEmpty
          ? Center(child: Column(mainAxisAlignment: MainAxisAlignment.center, children: [
              const Icon(Icons.inventory_2_outlined, size: 60, color: Colors.grey),
              const SizedBox(height: 12),
              const Text("Lista vacía", style: TextStyle(fontSize: 16, color: Colors.grey)),
              const SizedBox(height: 8),
              if (esAdmin) ElevatedButton.icon(
                icon: const Icon(Icons.sync),
                label: const Text("Poblar automáticamente"),
                onPressed: () => setState(() {
                  final tasa = widget.lista.esEnBolivares ? ConfigSistema.tasaCambio : 1.0;
                  final filtrados = catalogoGlobal.where((p) {
                    final catOk = widget.lista.categoria == "Todos" || p.categoria == widget.lista.categoria;
                    final marcaOk = widget.lista.marcaFiltro == "Todas" ||
                        p.marca.toLowerCase() == widget.lista.marcaFiltro.toLowerCase();
                    return catOk && marcaOk;
                  }).toList();
                  widget.lista.items.clear();
                  for (final p in filtrados) {
                    final stock = p.categoria == 'Telefono'
                        ? stockImeiGlobal.where((i) => i.producto.codigo == p.codigo && !i.vendido).length
                        : p.stockManual;
                    final precioBase = widget.lista.esEnBolivares ? (p.precioVenta * tasa) : p.precioVenta;
                    widget.lista.items.add(ItemListaPrecio(
                      producto: p,
                      stockDisponible: stock,
                      preciosPorColumna: { for (var col in widget.lista.columnas) col.nombre: precioBase },
                    ));
                  }
                })),
            ]))
          : Column(children: [
              // Barra de búsqueda
              Padding(
                padding: const EdgeInsets.fromLTRB(12, 10, 12, 4),
                child: TextField(
                  controller: _searchCtrl,
                  decoration: InputDecoration(
                    hintText: "Buscar producto o marca...",
                    prefixIcon: const Icon(Icons.search),
                    suffixIcon: _busqueda.isNotEmpty
                        ? IconButton(icon: const Icon(Icons.clear), onPressed: () => setState(() { _busqueda = ""; _searchCtrl.clear(); }))
                        : null, isDense: true,
                    contentPadding: const EdgeInsets.symmetric(vertical: 10)),
                  onChanged: (v) => setState(() => _busqueda = v)),
              ),

              // Encabezado de columnas (sticky)
              if (widget.lista.columnas.isNotEmpty)
                Container(
                  color: AppColors.royalBlue.withValues(alpha: 0.08),
                  padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),
                  child: Row(children: [
                    const Expanded(flex: 3, child: Text("PRODUCTO", style: TextStyle(fontSize: 10, fontWeight: FontWeight.bold, color: Colors.grey))),
                    const SizedBox(width: 4),
                    const Text("STOCK", style: TextStyle(fontSize: 10, fontWeight: FontWeight.bold, color: Colors.grey)),
                    if (widget.lista.esFinanciamiento) ...[
                      const Expanded(flex: 2, child: Text("BASE", textAlign: TextAlign.right,
                        style: TextStyle(fontSize: 10, fontWeight: FontWeight.bold, color: AppColors.primaryBlue))),
                      const Expanded(flex: 2, child: Text("INICIAL", textAlign: TextAlign.right,
                        style: TextStyle(fontSize: 10, fontWeight: FontWeight.bold, color: Colors.orange))),
                      const Expanded(flex: 2, child: Text("CUOTA", textAlign: TextAlign.right,
                        style: TextStyle(fontSize: 10, fontWeight: FontWeight.bold, color: AppColors.royalBlue))),
                    ] else
                      ...widget.lista.columnas.map((col) => Expanded(
                        flex: 2,
                        child: GestureDetector(
                          onTap: esAdmin ? () => _editarColumnaCompleta(col) : null,
                          child: Row(mainAxisAlignment: MainAxisAlignment.end, children: [
                            Flexible(child: Text(col.nombre.toUpperCase(),
                              style: const TextStyle(fontSize: 10, fontWeight: FontWeight.bold, color: AppColors.primaryBlue),
                              overflow: TextOverflow.ellipsis, textAlign: TextAlign.right)),
                            if (esAdmin) const Icon(Icons.edit, size: 10, color: AppColors.primaryBlue),
                          ]),
                        ),
                      )),
                    if (esAdmin) const SizedBox(width: 32),
                  ]),
                ),

              // Lista agrupada por marca
              Expanded(
                child: ListView.builder(
                  padding: const EdgeInsets.only(bottom: 20),
                  itemCount: agrupados.length,
                  itemBuilder: (ctx, marcaIdx) {
                    final marca = agrupados.keys.elementAt(marcaIdx);
                    final items = agrupados[marca]!;
                    return Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        // Cabecera de marca
                        Container(
                          width: double.infinity,
                          padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 8),
                          color: AppColors.royalBlue.withValues(alpha: 0.06),
                          child: Row(children: [
                            const Icon(Icons.business, size: 14, color: AppColors.royalBlue),
                            const SizedBox(width: 6),
                            Text(marca, style: const TextStyle(fontWeight: FontWeight.bold, fontSize: 13, color: AppColors.royalBlue)),
                            const SizedBox(width: 8),
                            Text("(${items.length} modelos)", style: const TextStyle(fontSize: 11, color: Colors.grey)),
                          ]),
                        ),
                        // Ítems de esa marca
                        ...items.map((item) => _buildItemRow(item, esAdmin, moneda)),
                      ],
                    );
                  },
                ),
              ),
            ]),
    );
  }

  Widget _buildItemRow(ItemListaPrecio item, bool esAdmin, String moneda) {
    final stockOk = item.stockDisponible > 0;
    final esFinanc = widget.lista.esFinanciamiento;

    // Calcular valores de financiamiento
    double precioBase = 0;
    double inicial    = 0;
    double cuota      = 0;
    if (esFinanc && widget.lista.columnas.isNotEmpty) {
      precioBase = item.preciosPorColumna[widget.lista.columnas.first.nombre] ?? 0.0;
      inicial    = precioBase * (widget.lista.porcentajeInicial / 100);
      final resto = precioBase - inicial;
      // Aplicar % de recargo sobre el total a financiar antes de
      // dividir entre el número de cuotas.
      final totalConRecargo =
          resto * (1 + widget.lista.porcentajeRecargoCuotas / 100);
      final nCuotas = widget.lista.numeroCuotas > 0 ? widget.lista.numeroCuotas : 1;
      cuota = totalConRecargo / nCuotas;
    }

    return Container(
      decoration: BoxDecoration(
        border: Border(bottom: BorderSide(color: Colors.grey[200]!))),
      padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
      child: Row(crossAxisAlignment: CrossAxisAlignment.center, children: [
        // Nombre del producto
        Expanded(flex: 3, child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
          Text(item.producto.nombre,
            style: const TextStyle(fontSize: 13, fontWeight: FontWeight.w500),
            overflow: TextOverflow.ellipsis),
          Text(item.producto.codigo,
            style: const TextStyle(fontSize: 10, color: Colors.grey)),
        ])),
        const SizedBox(width: 4),
        // Stock
        Container(
          width: 38,
          alignment: Alignment.center,
          padding: const EdgeInsets.symmetric(horizontal: 4, vertical: 2),
          decoration: BoxDecoration(
            color: stockOk ? Colors.green.withValues(alpha: 0.1) : Colors.red.withValues(alpha: 0.1),
            borderRadius: BorderRadius.circular(4)),
          child: Text(
            "${item.stockDisponible}",
            style: TextStyle(
              fontSize: 12, fontWeight: FontWeight.bold,
              color: stockOk ? Colors.green[700] : Colors.red[700]))),
        // ── Columnas de financiamiento ──────────────────────────
        if (esFinanc) ...[
          Expanded(flex: 2, child: GestureDetector(
            onTap: esAdmin ? () => _editarPrecioItem(item, widget.lista.columnas.first.nombre) : null,
            child: Column(crossAxisAlignment: CrossAxisAlignment.end, children: [
              Text("$moneda ${precioBase.toStringAsFixed(2)}",
                style: TextStyle(
                  fontSize: 12, fontWeight: FontWeight.bold,
                  color: esAdmin ? AppColors.primaryBlue : Colors.black87)),
              if (esAdmin)
                const Text("base", style: TextStyle(fontSize: 8, color: Colors.grey)),
            ]),
          )),
          Expanded(flex: 2, child: Column(crossAxisAlignment: CrossAxisAlignment.end, children: [
            Text("$moneda ${inicial.toStringAsFixed(2)}",
              style: const TextStyle(
                fontSize: 12, fontWeight: FontWeight.bold, color: Colors.orange)),
            Text("${widget.lista.porcentajeInicial.toStringAsFixed(0)}%",
              style: const TextStyle(fontSize: 8, color: Colors.grey)),
          ])),
          Expanded(flex: 2, child: Column(crossAxisAlignment: CrossAxisAlignment.end, children: [
            Text("$moneda ${cuota.toStringAsFixed(2)}",
              style: const TextStyle(
                fontSize: 12, fontWeight: FontWeight.bold, color: AppColors.royalBlue)),
            Text(
              widget.lista.porcentajeRecargoCuotas > 0
                ? "x${widget.lista.numeroCuotas} (+${widget.lista.porcentajeRecargoCuotas.toStringAsFixed(0)}%)"
                : "x${widget.lista.numeroCuotas}",
              style: const TextStyle(fontSize: 8, color: Colors.grey)),
          ])),
        ] else
          // ── Columnas normales ──────────────────────────────────
          ...widget.lista.columnas.map((col) {
            final precio = item.preciosPorColumna[col.nombre] ?? 0.0;
            return Expanded(flex: 2, child: GestureDetector(
              onTap: esAdmin ? () => _editarPrecioItem(item, col.nombre) : null,
              child: Container(
                alignment: Alignment.centerRight,
                padding: const EdgeInsets.symmetric(horizontal: 4),
                child: Column(crossAxisAlignment: CrossAxisAlignment.end, children: [
                  Text(
                    "$moneda ${precio.toStringAsFixed(2)}",
                    style: TextStyle(
                      fontSize: 12, fontWeight: FontWeight.bold,
                      color: esAdmin ? AppColors.primaryBlue : Colors.black87)),
                  if (esAdmin)
                    const Text("toca para editar", style: TextStyle(fontSize: 8, color: Colors.grey)),
                ]),
              ),
            ));
          }),
        // Botón eliminar
        if (esAdmin)
          SizedBox(width: 32, child: IconButton(
            icon: const Icon(Icons.remove_circle_outline, size: 18, color: Colors.red),
            padding: EdgeInsets.zero,
            onPressed: () => setState(() => widget.lista.items.remove(item)),
          )),
      ]),
    );
  }
}

