class SelectorProductosLista extends StatefulWidget {
  final ListaPrecio lista;
  const SelectorProductosLista({super.key, required this.lista});
  @override State<SelectorProductosLista> createState() => _SelectorProductosListaState();
}

class _SelectorProductosListaState extends State<SelectorProductosLista> {
  String _busqueda = "";
  final _searchCtrl = TextEditingController();
  String _categoriaFiltro = "Todos";

  @override
  void dispose() { _searchCtrl.dispose(); super.dispose(); }

  @override
  Widget build(BuildContext context) {
    final filtrados = catalogoGlobal.where((p) {
      final catOk = _categoriaFiltro == "Todos" || p.categoria == _categoriaFiltro;
      final busqOk = _busqueda.isEmpty ||
          p.nombre.toLowerCase().contains(_busqueda.toLowerCase()) ||
          p.codigo.toLowerCase().contains(_busqueda.toLowerCase()) ||
          p.marca.toLowerCase().contains(_busqueda.toLowerCase());
      return catOk && busqOk;
    }).toList();

    return Scaffold(
      appBar: AppBar(
        title: const Text("Agregar productos"),
      ),
      body: Column(children: [
        Padding(
          padding: const EdgeInsets.all(10),
          child: Column(children: [
            TextField(
              controller: _searchCtrl,
              decoration: const InputDecoration(
                hintText: "Buscar por nombre, código o marca...",
                prefixIcon: Icon(Icons.search), isDense: true),
              onChanged: (v) => setState(() => _busqueda = v)),
            const SizedBox(height: 8),
            SingleChildScrollView(scrollDirection: Axis.horizontal,
              child: Row(children: ["Todos","Telefono","Accesorio","Televisor","Linea Blanca","Linea"].map((cat) =>
                Padding(padding: const EdgeInsets.only(right: 6),
                  child: ChoiceChip(
                    label: Text(cat),
                    selected: _categoriaFiltro == cat,
                    selectedColor: AppColors.primaryBlue,
                    labelStyle: TextStyle(color: _categoriaFiltro == cat ? Colors.white : Colors.black87),
                    onSelected: (_) => setState(() => _categoriaFiltro = cat)))).toList())),
          ]),
        ),
        Expanded(child: ListView.builder(
          itemCount: filtrados.length,
          itemBuilder: (ctx, i) {
            final p = filtrados[i];
            final yaEsta = widget.lista.items.any((it) => it.producto.codigo == p.codigo);
            final stock = p.categoria == 'Telefono'
                ? stockImeiGlobal.where((im) => im.producto.codigo == p.codigo && !im.vendido).length
                : p.stockManual;
            return ListTile(
              leading: CircleAvatar(
                backgroundColor: yaEsta ? Colors.green.withValues(alpha: 0.15) : Colors.grey[100],
                child: Icon(
                  yaEsta ? Icons.check : Icons.add,
                  color: yaEsta ? Colors.green : Colors.grey)),
              title: Text(p.nombre, style: const TextStyle(fontWeight: FontWeight.w500)),
              subtitle: Text("${p.marca} · ${p.codigo} · Stock: $stock"),
              trailing: Text(
                "${formatCurrency(p.precioVenta)}",
                style: const TextStyle(fontWeight: FontWeight.bold, color: AppColors.primaryBlue)),
              onTap: yaEsta ? null : () {
                final precioBase = widget.lista.esEnBolivares
                    ? (p.precioVenta * widget.lista.tasaDelDia)
                    : p.precioVenta;
                setState(() {
                  widget.lista.items.add(ItemListaPrecio(
                    producto: p,
                    stockDisponible: stock,
                    preciosPorColumna: { for (var col in widget.lista.columnas) col.nombre: precioBase }));
                });
                ScaffoldMessenger.of(context).showSnackBar(SnackBar(
                  content: Text("✅ ${p.nombre} agregado"),
                  backgroundColor: AppColors.statusGreen,
                  duration: const Duration(seconds: 1)));
              },
            );
          },
        )),
      ]),
    );
  }
}

// ============================================================
//  COMISIONES — carga y guarda en la API
// ============================================================
/// Parsea fechas en formato "dd/MM/yyyy" o "yyyy-MM-dd". Retorna DateTime.now() si falla.
DateTime parseFecha(String fecha) {
  try {
    if (fecha.contains('-')) {
      // Formato ISO yyyy-MM-dd
      return DateTime.parse(fecha);
    }
    final partes = fecha.split("/");
    if (partes.length == 3) {
      return DateTime(int.parse(partes[2]), int.parse(partes[1]), int.parse(partes[0]));
    }
  } catch (e) { debugPrint('parseFecha("$fecha"): $e'); }
  return DateTime.now();
}

class VentanaComisiones extends StatefulWidget {
  const VentanaComisiones({super.key});
  @override State<VentanaComisiones> createState() => _VentanaComisionesState();
}

class _VentanaComisionesState extends State<VentanaComisiones> {
  // Inicializar con la tasa BCV actual si está disponible
  double get tasa => ConfigSistema.tasaCambio;
  double _tasaManual = 0;
  bool _usarTasaBCV = true;
  bool _cargando = false; // ← controla el spinner de generarYGuardar
  DateTime? fechaInicio, fechaFin;
  List<HistorialComision> _historial = [];

  @override
  void initState() {
    super.initState();
    _tasaManual = ConfigSistema.tasaCambio;
    _cargarHistorial();
    TasaBCVScheduler.addListener(_onTasaActualizada);
  }

  @override
  void dispose() {
    TasaBCVScheduler.removeListener(_onTasaActualizada);
    super.dispose();
  }

  void _onTasaActualizada() {
    if (mounted && _usarTasaBCV) setState(() {});
  }

  Future<void> _cargarHistorial() async {
    try {
      final raw = await _Api.get('comisiones_historial');
      if (!mounted) return;
      setState(() {
        _historial = ((raw as List?) ?? [])
            .map((m) => HistorialComision.fromMap(m)).toList()
          ..sort((a, b) => b.fechaInicio.compareTo(a.fechaInicio));
        historialComisiones = _historial;
      });
    } catch (e) {
      debugPrint('Error cargando historial comisiones: $e');
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Text("Error al cargar historial: $e"),
        backgroundColor: AppColors.statusRed,
        duration: const Duration(seconds: 3)));
    }
  }

  Future<void> seleccionarFechas() async {
    final rango = await showDateRangePicker(
      context: context,
      firstDate: DateTime(2020),
      lastDate: DateTime.now(),
      helpText: 'Seleccione el rango de fechas para las comisiones',
    );
    if (rango != null && mounted) {
      setState(() { fechaInicio = rango.start; fechaFin = rango.end; });
    }
  }

  Future<List<FacturaModel>> _cargarVentasApi() async {
    try {
      // Asegurar que tenemos el catálogo en memoria para poder
      // resolver los códigos de items a sus Productos.
      if (catalogoGlobal.isEmpty) {
        try {
          final rawP = await _Api.get('productos');
          catalogoGlobal = ((rawP as List?) ?? [])
              .map((m) => Producto.fromMap(m)).toList();
        } catch (_) {}
      }
      // Necesitamos stockImeiGlobal para mapear IMEI → Producto real
      if (stockImeiGlobal.isEmpty) {
        try {
          final rawI = await _Api.get('stock_imei');
          stockImeiGlobal = ((rawI as List?) ?? [])
              .map((m) => ImeiRegistro.fromMap(m)).toList();
        } catch (_) {}
      }

      final raw = await _Api.get('facturas');
      List<FacturaModel> ventas = [];

      for (var v in ((raw as List?) ?? [])) {
        // ── Reconstruir lista de equipos (con IMEI) ──
        // El backend puede devolver `equipos` como lista, o fallback
        // al campo antiguo `imeis` (string separado por comas).
        List<ImeiRegistro> equipos = [];
        final rawEquipos = v['equipos'];
        if (rawEquipos is List && rawEquipos.isNotEmpty) {
          for (final e in rawEquipos) {
            String imei = '';
            if (e is String) {
              imei = e;
            } else if (e is Map) {
              imei = (e['imei'] ?? '').toString();
            }
            if (imei.isEmpty) continue;
            // Buscar el producto real en stockImeiGlobal
            final reg = stockImeiGlobal
                .where((r) => r.imei == imei).firstOrNull;
            if (reg != null) {
              equipos.add(reg);
            } else {
              // No se encontró el IMEI, crear registro mínimo
              // con categoría "Telefono" por defecto.
              equipos.add(ImeiRegistro(
                imei: imei,
                producto: Producto(
                    codigo: '', nombre: 'Teléfono', categoria: 'Telefono',
                    marca: '', modelo: '', tipo: '',
                    precioCosto: 0, precioVenta: 0),
                fechaIngreso: '', proveedor: '', color: '', ubicacion: ''));
            }
          }
        } else {
          // Fallback: campo antiguo "imeis" como string
          final imeisStr = (v['imeis'] ?? '').toString();
          if (imeisStr.isNotEmpty && imeisStr != 'ninguno') {
            for (final imei in imeisStr.split(',')) {
              final i = imei.trim();
              if (i.isEmpty) continue;
              final reg = stockImeiGlobal
                  .where((r) => r.imei == i).firstOrNull;
              if (reg != null) {
                equipos.add(reg);
              } else {
                equipos.add(ImeiRegistro(
                  imei: i,
                  producto: Producto(
                      codigo: '', nombre: 'Teléfono', categoria: 'Telefono',
                      marca: '', modelo: '', tipo: '',
                      precioCosto: 0, precioVenta: 0),
                  fechaIngreso: '', proveedor: '', color: '', ubicacion: ''));
              }
            }
          }
        }

        // ── Reconstruir items sin IMEI (accesorios, TVs, línea blanca) ──
        List<Producto> itemsSinImei = [];
        final rawItems = v['items'];
        if (rawItems is List) {
          for (final it in rawItems) {
            String codigo = '';
            if (it is String) {
              codigo = it;
            } else if (it is Map) {
              codigo = (it['codigo'] ?? it['producto_codigo'] ?? '').toString();
            }
            if (codigo.isEmpty) continue;
            final prod = catalogoGlobal
                .where((p) => p.codigo == codigo).firstOrNull;
            if (prod != null) {
              itemsSinImei.add(prod);
            }
          }
        }

        // ── Reconstruir pagos (para detectar financiamientos) ──
        List<PagoFactura> pagos = [];
        final rawPagos = v['pagos'];
        if (rawPagos is List) {
          for (final p in rawPagos) {
            if (p is Map) {
              pagos.add(PagoFactura(
                metodo: (p['metodo'] ?? '').toString(),
                tipo: (p['tipo'] ?? '').toString(),
                financiador: p['financiador'] as String?,
                monto: double.tryParse('${p['monto'] ?? 0}') ?? 0,
              ));
            }
          }
        }
        // Fallback: si no hay pagos pero existe `tipo_venta`, inferir
        if (pagos.isEmpty && v['tipo_venta'] != null) {
          final tv = (v['tipo_venta'] ?? '').toString();
          final tot = double.tryParse('${v['total'] ?? 0}') ?? 0;
          if (tv.isNotEmpty && tv != 'Contado') {
            pagos.add(PagoFactura(
              metodo: tv, tipo: 'Financiado',
              financiador: tv, monto: tot));
          }
        }

        ventas.add(FacturaModel(
          id: v['id'] is int
              ? v['id']
              : int.tryParse('${v['id']}'),
          cliente: v['cliente'] ?? '',
          cedula: v['cedula'] ?? '',
          tienda: v['tienda'] ?? '',
          telefono: v['telefono'] ?? '',
          nroFactura: v['nro_factura'] ?? '',
          equipos: equipos,
          itemsSinImei: itemsSinImei,
          pagos: pagos,
          vendedor: v['vendedor'] ?? '',
          fecha: v['fecha'] ?? ''));
      }
      return ventas;
    } catch (e) {
      debugPrint("Error API comisiones: $e");
      return [];
    }
  }

  /// Genera los resúmenes de comisión por vendedor para el rango de
  /// fechas seleccionado.
  ///
  /// El cálculo recorre cada categoría definida en
  /// `ConfigSistema.categoriasComision` y aplica su `tipoConteo`:
  ///
  /// - **categoriaProducto**: cuenta cada producto vendido cuya
  ///   categoría coincida con `valorConteo`.
  /// - **lineaTelefonica**: cuenta cada línea activada en la venta.
  /// - **ventaFinanciada**: cuenta cada pago financiado, atribuido al
  ///   "vendedor financiador" registrado en el pago.
  /// - **servicioTecnico**: cuenta cada servicio técnico ENTREGADO
  ///   (estado=Entregado o pagado=true) en el rango, atribuido al
  ///   técnico de la ficha.
  /// - **porcentajeWeppa**: aplica el % configurado en la lista Weppa
  ///   sobre el precio de venta de los productos financiados con Weppa.
  ///
  /// El resumen guarda un snapshot de las tarifas y nombres usados
  /// para que el historial muestre datos correctos aunque luego se
  /// modifique la configuración.
  List<ResumenComision> generarComisiones(List<FacturaModel> ventas) {
    final Map<String, ResumenComision> mapa = {};

    // Snapshot de las categorías al momento de generar — todas las
    // operaciones siguientes leen de aquí.
    final categorias = List<CategoriaComision>.from(
        ConfigSistema.categoriasComision);

    /// Helper: garantiza que un ResumenComision exista para el vendedor,
    /// y que tenga inicializadas las tarifas y nombres de TODAS las
    /// categorías activas (aunque sus conteos sean 0).
    ResumenComision obtenerResumen(String vendedor) {
      return mapa.putIfAbsent(vendedor, () {
        final r = ResumenComision(vendedor: vendedor);
        for (final c in categorias) {
          r.conteos[c.id]            = 0;
          r.tarifasUsadas[c.id]      = c.tarifaUSD;
          r.nombresCategorias[c.id]  = c.nombre;
        }
        return r;
      });
    }

    // Determinar el % de comisión Weppa activo: se toma de la lista
    // de financiamiento cuya `financiadora` contenga "weppa".
    double pctComisionWeppa = 0;
    try {
      final listaWeppa = listasPreciosGlobal.firstWhere(
        (l) => l.esFinanciamiento &&
            (l.financiadora ?? '').toLowerCase().contains('weppa'),
      );
      pctComisionWeppa = listaWeppa.porcentajeComisionWeppa;
    } catch (_) {
      pctComisionWeppa = 0;
    }

    // ── Recorrer las ventas y aplicar los tipos de conteo
    //    relacionados con productos vendidos ──
    for (final venta in ventas) {
      final rVendedor = obtenerResumen(venta.vendedor);

      // ¿Es una venta financiada con Weppa?
      bool esVentaWeppa = false;
      for (final pago in venta.pagos) {
        final fin = (pago.financiador ?? '').toLowerCase();
        if (pago.tipo == 'Financiado' && fin.contains('weppa')) {
          esVentaWeppa = true;
          break;
        }
      }

      // Equipos con IMEI: aplicar reglas categoriaProducto
      for (final eq in venta.equipos) {
        final categoriaProd = eq.producto.categoria;
        for (final cat in categorias) {
          if (cat.tipoConteo == TipoConteoComision.categoriaProducto &&
              cat.valorConteo == categoriaProd) {
            rVendedor.conteos[cat.id] =
                (rVendedor.conteos[cat.id] ?? 0) + 1;
          }
        }
        // Comisión Weppa sobre precio de venta
        if (esVentaWeppa &&
            pctComisionWeppa > 0 &&
            eq.producto.precioVenta > 0) {
          rVendedor.comisionWeppa +=
              eq.producto.precioVenta * pctComisionWeppa / 100;
        }
      }

      // Items sin IMEI: misma lógica
      for (final p in venta.itemsSinImei) {
        for (final cat in categorias) {
          if (cat.tipoConteo == TipoConteoComision.categoriaProducto &&
              cat.valorConteo == p.categoria) {
            rVendedor.conteos[cat.id] =
                (rVendedor.conteos[cat.id] ?? 0) + 1;
          }
        }
        if (esVentaWeppa && pctComisionWeppa > 0 && p.precioVenta > 0) {
          rVendedor.comisionWeppa += p.precioVenta * pctComisionWeppa / 100;
        }
      }

      // Ventas financiadas: contabilizar para el "vendedor financiador"
      // (que se registra como su propio vendedor en el resumen).
      for (final pago in venta.pagos) {
        if (pago.tipo == 'Financiado' && pago.financiador != null) {
          final rFin = obtenerResumen(pago.financiador!);
          for (final cat in categorias) {
            if (cat.tipoConteo == TipoConteoComision.ventaFinanciada) {
              // Si la categoría tiene un valorConteo configurado,
              // solo cuenta si el financiador coincide. Si está
              // vacío, cuenta cualquier financiador.
              final filtroFin = cat.valorConteo.trim().toLowerCase();
              final actualFin = pago.financiador!.toLowerCase();
              if (filtroFin.isEmpty || actualFin.contains(filtroFin)) {
                rFin.conteos[cat.id] =
                    (rFin.conteos[cat.id] ?? 0) + 1;
              }
            }
          }
        }
      }
    }

    // ── Líneas telefónicas activadas en el rango ──
    // Se cuentan directamente desde `lineasGlobal` filtrando por
    // fecha y por el flag `activada` — atribuyendo cada línea al
    // vendedor que la registró. Esto es independiente de las facturas
    // (una activación es un evento distinto a una venta).
    if (categorias.any(
        (c) => c.tipoConteo == TipoConteoComision.lineaTelefonica)) {
      for (final ln in lineasGlobal) {
        if (!ln.activada) continue;
        final vendedor = ln.vendedor.trim();
        if (vendedor.isEmpty) continue;
        // Filtrar por rango de fechas
        DateTime? fln;
        try {
          fln = DateTime.tryParse(ln.fecha);
        } catch (_) {
          fln = null;
        }
        if (fln == null) continue;
        if (fechaInicio != null && fln.isBefore(fechaInicio!)) continue;
        if (fechaFin != null &&
            fln.isAfter(fechaFin!.add(const Duration(days: 1)))) continue;

        final rVend = obtenerResumen(vendedor);
        for (final cat in categorias) {
          if (cat.tipoConteo == TipoConteoComision.lineaTelefonica) {
            rVend.conteos[cat.id] = (rVend.conteos[cat.id] ?? 0) + 1;
          }
        }
      }
    }

    // ── Servicios técnicos ENTREGADOS en el rango ──
    // Cuentan al técnico (campo `tecnico`). Solo se consideran los
    // que estén pagados o entregados — no los pendientes.
    if (categorias.any((c) =>
        c.tipoConteo == TipoConteoComision.servicioTecnico)) {
      for (final st in serviciosGlobal) {
        final tecnico = st.tecnico.trim();
        if (tecnico.isEmpty) continue;
        // Filtrar por rango de fechas (usa `fecha` de recepción).
        if (fechaInicio != null && st.fecha.isBefore(fechaInicio!)) continue;
        if (fechaFin != null &&
            st.fecha.isAfter(fechaFin!.add(const Duration(days: 1)))) {
          continue;
        }
        // Solo servicios efectivamente cobrados.
        final cobrado = st.pagado ||
            st.estado.toLowerCase() == 'entregado';
        if (!cobrado) continue;

        final rTec = obtenerResumen(tecnico);
        for (final cat in categorias) {
          if (cat.tipoConteo == TipoConteoComision.servicioTecnico) {
            rTec.conteos[cat.id] = (rTec.conteos[cat.id] ?? 0) + 1;
          }
        }
      }
    }

    // ── Asignar sueldo base del usuario (igual que antes) ──
    for (final r in mapa.values) {
      final nombreBuscado = r.vendedor.trim().toLowerCase();
      final usuario = usuariosSistema.where(
        (u) => u.nombre.trim().toLowerCase() == nombreBuscado).firstOrNull;
      r.base = (usuario != null && usuario.sueldoBase > 0)
          ? usuario.sueldoBase
          : ConfigSistema.comisionBaseDefault;
    }
    return mapa.values.toList();
  }

  Future<void> generarYGuardar() async {
    if (fechaInicio == null || fechaFin == null) {
      ScaffoldMessenger.of(context).showSnackBar(
        const SnackBar(content: Text("⚠️ Debes seleccionar un rango de fechas"),
          backgroundColor: AppColors.statusOrange));
      return;
    }

    // Mostrar loading
    setState(() => _cargando = true);
    try {
      // ── Refrescar usuarios desde el backend ANTES de generar ──
      // Así, cualquier usuario creado recientemente en VentanaUsuarios
      // con su sueldoBase queda disponible para el cálculo de comisiones.
      try {
        final rawU = await _Api.get('usuarios');
        usuariosSistema = ((rawU as List?) ?? [])
            .map((m) => Usuario.fromMap(m)).toList();
      } catch (e) {
        debugPrint('[Comisiones] No se pudo refrescar usuarios: $e');
      }

      final todasVentas = await _cargarVentasApi();
      final ventasFiltradas = todasVentas.where((v) {
        try {
          final fv = parseFecha(v.fecha);
          return !fv.isBefore(fechaInicio!) &&
                 !fv.isAfter(fechaFin!.add(const Duration(days: 1)));
        } catch (_) { return false; }
      }).toList();

      if (ventasFiltradas.isEmpty) {
        if (mounted) ScaffoldMessenger.of(context).showSnackBar(
          const SnackBar(content: Text("No hay ventas en ese rango de fechas"),
            backgroundColor: AppColors.statusOrange));
        setState(() => _cargando = false);
        return;
      }

      final resultado = generarComisiones(ventasFiltradas);
      final tasaUsada = _usarTasaBCV ? ConfigSistema.tasaCambio : _tasaManual;

      // Guardar en BD
      await _Api.post('comisiones_historial', {
        'fecha_inicio': "${fechaInicio!.year}-${fechaInicio!.month.toString().padLeft(2,'0')}-${fechaInicio!.day.toString().padLeft(2,'0')}",
        'fecha_fin'   : "${fechaFin!.year}-${fechaFin!.month.toString().padLeft(2,'0')}-${fechaFin!.day.toString().padLeft(2,'0')}",
        'tasa_bcv'    : tasaUsada,
        'data'        : resultado.map((r) => r.toMap()).toList(),
      });

      if (!mounted) return;
      setState(() => _cargando = false);
      await _cargarHistorial();

      if (!mounted) return;
      _mostrarTablaComisiones(resultado, tasaUsada,
        "${formatearFecha(fechaInicio!)} — ${formatearFecha(fechaFin!)}");

      ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
        content: Text("✅ Comisiones guardadas correctamente"),
        backgroundColor: AppColors.statusGreen));

    } catch (e) {
      debugPrint('[generarYGuardar] Error: $e');
      if (mounted) {
        setState(() => _cargando = false);
        ScaffoldMessenger.of(context).showSnackBar(SnackBar(
          content: Text("Error al guardar comisiones: $e"),
          backgroundColor: AppColors.statusRed));
      }
    }
  }

  void mostrarVentana(List<ResumenComision> lista) {
    _mostrarTablaComisiones(lista, _usarTasaBCV ? ConfigSistema.tasaCambio : _tasaManual,
      "Historial");
  }

  void _mostrarTablaComisiones(List<ResumenComision> lista, double tasaUsada, String titulo) {
    showDialog(context: context, builder: (context) {
      return Dialog(
        insetPadding: const EdgeInsets.all(10),
        child: Container(
          padding: const EdgeInsets.all(15),
          height: MediaQuery.of(context).size.height * 0.85,
          child: Column(children: [
            Row(children: [
              Expanded(child: Text("COMISIONES — $titulo",
                style: const TextStyle(fontSize: 16, fontWeight: FontWeight.bold))),
              Text("Tasa: Bs ${tasaUsada.toStringAsFixed(2)}",
                style: const TextStyle(color: AppColors.textSecondary, fontSize: 12)),
              const SizedBox(width: 8),
              IconButton(onPressed: () => Navigator.pop(context),
                icon: const Icon(Icons.close)),
            ]),
            const SizedBox(height: 10),
            Expanded(child: tabla(lista)),
            ElevatedButton(
              onPressed: () => Navigator.pop(context),
              child: const Text("Cerrar")),
          ]),
        ));
    });
  }

  Widget tabla(List<ResumenComision> lista) {
    // ── Decidir qué categorías mostrar como columnas ──
    // Tomamos como referencia las categorías "vivas" del primer
    // resumen del histórico — así el histórico se ve con los nombres
    // de cuando se generó, y los actuales con la config actual.
    // Si el resumen no tiene snapshot (datos viejos), caemos a la
    // configuración global.
    List<String> categoriaIds;
    Map<String, String> nombresCol = {};
    if (lista.isNotEmpty && lista.first.nombresCategorias.isNotEmpty) {
      categoriaIds = lista.first.nombresCategorias.keys.toList();
      nombresCol = Map<String, String>.from(lista.first.nombresCategorias);
    } else {
      categoriaIds =
          ConfigSistema.categoriasComision.map((c) => c.id).toList();
      for (final c in ConfigSistema.categoriasComision) {
        nombresCol[c.id] = c.nombre;
      }
    }

    // Solo mostrar columna Weppa si al menos un vendedor tiene comisión
    final hayWeppa = lista.any((r) => r.comisionWeppa > 0);
    final tasaActual =
        _usarTasaBCV ? ConfigSistema.tasaCambio : _tasaManual;

    return SingleChildScrollView(
      scrollDirection: Axis.horizontal,
      child: DataTable(
        columnSpacing: 18,
        headingRowColor: WidgetStateProperty.all(Colors.grey[300]),
        columns: [
          const DataColumn(label: Text("Vendedor")),
          // Una columna por cada categoría dinámica
          ...categoriaIds.map((id) => DataColumn(
              label: Text(nombresCol[id] ?? id,
                  style: const TextStyle(fontWeight: FontWeight.w600)))),
          if (hayWeppa)
            const DataColumn(
                label: Text("Com. Weppa",
                    style: TextStyle(color: AppColors.statusGreen))),
          const DataColumn(label: Text("Total Comisión")),
          const DataColumn(label: Text("Base")),
          const DataColumn(label: Text("Domingo")),
          const DataColumn(label: Text("Descuento Bs")),
          const DataColumn(label: Text("Total a pagar")),
          const DataColumn(label: Text("Total Bs")),
        ],
        rows: List.generate(lista.length, (index) {
          final r = lista[index];
          return DataRow(
            color: WidgetStateProperty.all(
                index % 2 == 0 ? Colors.white : Colors.grey[100]),
            cells: [
              DataCell(Text(r.vendedor)),
              // Conteos dinámicos por categoría — destacamos los > 0
              ...categoriaIds.map((id) {
                final n = r.conteoDe(id);
                return DataCell(Text("$n",
                    style: TextStyle(
                        color: n > 0 ? AppColors.primaryBlue : null,
                        fontWeight: n > 0 ? FontWeight.bold : null)));
              }),
              if (hayWeppa)
                DataCell(Text(formatCurrency(r.comisionWeppa),
                    style: TextStyle(
                        color: r.comisionWeppa > 0
                            ? AppColors.statusGreen
                            : null,
                        fontWeight: r.comisionWeppa > 0
                            ? FontWeight.bold
                            : null))),
              DataCell(Text(formatCurrency(r.totalComision))),
              // Base: NO editable. Viene del sueldoBase del Usuario.
              DataCell(Tooltip(
                message: 'Base del usuario (editar en Usuarios)',
                child: Container(
                  padding: const EdgeInsets.symmetric(
                      horizontal: 6, vertical: 4),
                  decoration: BoxDecoration(
                    color: AppColors.surfaceGrey,
                    borderRadius: BorderRadius.circular(4),
                  ),
                  child: Text(formatCurrency(r.base),
                      style: const TextStyle(
                          fontSize: 13,
                          color: AppColors.textSecondary,
                          fontWeight: FontWeight.w600)),
                ),
              )),
              DataCell(SizedBox(
                  width: 70,
                  child: TextField(
                      controller:
                          TextEditingController(text: r.domingo.toString()),
                      keyboardType: TextInputType.number,
                      onChanged: (v) {
                        r.domingo = double.tryParse(v) ?? 0;
                        setState(() {});
                      },
                      decoration:
                          const InputDecoration(border: InputBorder.none)))),
              DataCell(SizedBox(
                  width: 80,
                  child: TextField(
                      controller:
                          TextEditingController(text: r.descuentoBs.toString()),
                      keyboardType: TextInputType.number,
                      onChanged: (v) {
                        r.descuentoBs = double.tryParse(v) ?? 0;
                        setState(() {});
                      },
                      decoration:
                          const InputDecoration(border: InputBorder.none)))),
              DataCell(Text(formatCurrency(r.totalPagar()))),
              // Total Bs: conversión USD→Bs según la tasa actual
              DataCell(Text(
                  "Bs ${r.totalBs(tasaActual).toStringAsFixed(2)}",
                  style: const TextStyle(fontWeight: FontWeight.w600))),
            ]);
        })));
  }

  String formatearFecha(DateTime f) => "${f.day}/${f.month}/${f.year}";

  @override
  Widget build(BuildContext context) {
    final tasaActual = _usarTasaBCV ? ConfigSistema.tasaCambio : _tasaManual;
    return Scaffold(
      appBar: AppBar(
        title: const Text("Comisiones"),
        actions: const [TasaBCVBadge(), SizedBox(width: 8)],
      ),
      body: Padding(padding: const EdgeInsets.all(20), child: Column(children: [
        ElevatedButton.icon(
          icon: const Icon(Icons.date_range),
          label: Text(fechaInicio==null ? "Seleccionar Fechas"
            : "${formatearFecha(fechaInicio!)} - ${formatearFecha(fechaFin!)}"),
          onPressed: seleccionarFechas),
        const SizedBox(height: 12),
        // ── Selector de tasa con opción BCV automático ──
        Card(
          child: Padding(padding: const EdgeInsets.all(12), child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Row(mainAxisAlignment: MainAxisAlignment.spaceBetween, children: [
                const Text("Tasa de cambio", style: TextStyle(fontWeight: FontWeight.bold)),
                Row(children: [
                  const Text("BCV auto", style: TextStyle(fontSize: 12)),
                  const SizedBox(width: 4),
                  Switch(
                    value: _usarTasaBCV,
                    activeColor: AppColors.primaryBlue,
                    onChanged: (v) => setState(() { _usarTasaBCV = v; }),
                  ),
                ]),
              ]),
              if (_usarTasaBCV) ...[
                Row(children: [
                  const Icon(Icons.account_balance, size: 16, color: AppColors.primaryBlue),
                  const SizedBox(width: 6),
                  Text("Bs ${ConfigSistema.tasaCambio.toStringAsFixed(2)} / \$",
                    style: const TextStyle(fontSize: 18, fontWeight: FontWeight.bold, color: AppColors.primaryBlue)),
                  const Spacer(),
                  if (TasaBCVScheduler.ultimaTasa != null)
                    Text(TasaBCVScheduler.ultimaTasa!.esDeHoy ? "✅ Hoy" : "⚠️ Antigua",
                      style: TextStyle(
                        fontSize: 11,
                        color: TasaBCVScheduler.ultimaTasa!.esDeHoy ? Colors.green : Colors.orange)),
                ]),
                if (TasaBCVScheduler.ultimaTasa != null)
                  Text("Fuente: ${TasaBCVScheduler.ultimaTasa!.fuente} · ${TasaBCVScheduler.ultimaTasa!.fechaFormateada}",
                    style: const TextStyle(fontSize: 10, color: Colors.grey)),
                TextButton.icon(
                  icon: const Icon(Icons.refresh, size: 14),
                  label: const Text("Actualizar tasa BCV", style: TextStyle(fontSize: 12)),
                  onPressed: () async {
                    await TasaBCVScheduler.actualizarAhora();
                    if (mounted) setState(() {});
                  },
                ),
              ] else ...[
                const SizedBox(height: 8),
                TextField(
                  decoration: const InputDecoration(
                    labelText: "Tasa manual (Bs/\$)",
                    prefixIcon: Icon(Icons.edit), isDense: true,
                  ),
                  keyboardType: TextInputType.numberWithOptions(decimal: true),
                  controller: TextEditingController(text: _tasaManual.toString()),
                  onChanged: (v) => setState(() => _tasaManual = double.tryParse(v) ?? _tasaManual),
                ),
              ],
            ],
          )),
        ),
        const SizedBox(height: 8),
        Text("Tasa que se usará: Bs ${tasaActual.toStringAsFixed(2)} / \$",
          style: const TextStyle(fontSize: 12, color: Colors.grey)),
        const SizedBox(height: 12),
        ElevatedButton.icon(
          icon: _cargando
            ? const SizedBox(width: 18, height: 18,
                child: CircularProgressIndicator(color: Colors.white, strokeWidth: 2))
            : const Icon(Icons.calculate),
          label: Text(_cargando ? "Calculando..." : "Generar Comisiones"),
          onPressed: _cargando ? null : generarYGuardar),
        const Divider(height: 30),
        const Text("Historial", style: TextStyle(fontWeight: FontWeight.bold)),
        Expanded(child: ListView.builder(
          itemCount: _historial.length,
          itemBuilder: (c, i) {
            final h = _historial[i];
            return ListTile(
              title: Text("${formatearFecha(h.fechaInicio)} — ${formatearFecha(h.fechaFin)}"),
              subtitle: Text("Tasa: Bs ${h.tasa.toStringAsFixed(2)}"),
              trailing: const Icon(Icons.visibility),
              onTap: () => _mostrarTablaComisiones(
                h.data, h.tasa,
                "${formatearFecha(h.fechaInicio)} — ${formatearFecha(h.fechaFin)}"));
          })),
      ])),
    );
  }
}

// ============================================================
//  REPORTES
// ============================================================
// ── Modelo estructurado de un reporte ─────────────────────────
//
//  En lugar de guardar el reporte como archivo XLSX/PDF en disco
//  y abrirlo con una app externa, ahora cada reporte se guarda
//  como datos estructurados en el historial. Al tocarlo se
//  muestra dentro de la aplicación con un visor especializado
//  según la categoría. Desde ese visor el usuario puede
//  descargar el Excel (con todo el detalle) cuando lo necesite.
//
//  Estructura:
//   - tipoReporte: identificador interno (ventas, inventario, etc.)
//   - encabezados: títulos de columna (para tablas tabulares)
//   - filas: List<List<dynamic>>  (datos planos)
//   - detalles: List<Map<String,dynamic>>  (datos enriquecidos
//     con sub-listas — usado p.ej. para incluir productos y pagos
//     dentro de cada factura del reporte de ventas)
//   - resumen: Map<String,dynamic>  (totales, contadores, etc.)
// ──────────────────────────────────────────────────────────────
class HistorialReporteEntry {
  final String nombreArchivo;       // nombre amigable del reporte
  final String tipoReporte;         // ventas, inventario, cuentas_cobrar, etc.
  final String categoria;           // "Ventas", "Inventario", etc. (UI)
  final DateTime fecha;             // momento en que se generó
  final String generadoPor;
  final String? desdeIso;           // rango de fechas (texto ISO)
  final String? hastaIso;
  final List<String> encabezados;
  final List<List<dynamic>> filas;
  final List<Map<String, dynamic>> detalles;
  final Map<String, dynamic> resumen;

  HistorialReporteEntry({
    required this.nombreArchivo,
    required this.tipoReporte,
    required this.categoria,
    required this.fecha,
    required this.generadoPor,
    this.desdeIso,
    this.hastaIso,
    this.encabezados = const [],
    this.filas = const [],
    this.detalles = const [],
    this.resumen = const {},
  });

  /// Tamaño aproximado del payload (para mostrarlo en el historial).
  int get tamanoBytes {
    try {
      return jsonEncode(toMap()).length;
    } catch (_) { return 0; }
  }

  /// Cantidad total de registros que contiene el reporte.
  int get totalRegistros {
    if (detalles.isNotEmpty) return detalles.length;
    return filas.length;
  }

  /// Nombre del reporte legible para mostrar en encabezados/AppBar.
  String nombreReporteLegible() {
    switch (tipoReporte) {
      case 'ventas':         return 'Reporte de Ventas';
      case 'inventario':     return 'Reporte de Inventario';
      case 'cuentas_cobrar': return 'Cuentas por Cobrar';
      case 'cuentas_pagar':  return 'Cuentas por Pagar';
      case 'lineas':         return 'Reporte de Líneas';
      case 'imei':           return 'Inventario IMEI';
      case 'cierres':        return 'Cierres de Caja';
      case 'comisiones':     return 'Comisiones';
      case 'servicios':      return 'Órdenes de Servicio';
    }
    return categoria.isNotEmpty ? categoria : 'Reporte';
  }

  Map<String, dynamic> toMap() => {
    'nombre': nombreArchivo,
    'tipo_reporte': tipoReporte,
    'categoria': categoria,
    'fecha': fecha.toIso8601String(),
    'usuario': generadoPor,
    'desde': desdeIso,
    'hasta': hastaIso,
    'encabezados': encabezados,
    'filas': filas,
    'detalles': detalles,
    'resumen': resumen,
  };

  factory HistorialReporteEntry.fromMap(Map<String, dynamic> m) =>
      HistorialReporteEntry(
        nombreArchivo: m['nombre'] ?? '',
        tipoReporte:   m['tipo_reporte'] ?? '',
        categoria:     m['categoria'] ?? 'Otros',
        fecha:  DateTime.tryParse(m['fecha'] ?? '') ?? DateTime.now(),
        generadoPor: m['usuario'] ?? '',
        desdeIso: m['desde'] as String?,
        hastaIso: m['hasta'] as String?,
        encabezados: ((m['encabezados'] as List?) ?? [])
            .map((e) => e.toString()).toList(),
        filas: ((m['filas'] as List?) ?? [])
            .map<List<dynamic>>((row) =>
              (row as List?)?.toList() ?? <dynamic>[]).toList(),
        detalles: ((m['detalles'] as List?) ?? [])
            .map<Map<String,dynamic>>((d) =>
              Map<String,dynamic>.from(d as Map)).toList(),
        resumen: Map<String,dynamic>.from(m['resumen'] as Map? ?? {}),
      );
}

class HistorialReportes {
  static const _kKey = 'historial_reportes';
  static List<HistorialReporteEntry> entradas = [];

  /// Carga el historial desde SharedPreferences. Llamar al inicio de
  /// VentanaReportes.
  static Future<void> cargar() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final raw = prefs.getString(_kKey);
      if (raw == null || raw.isEmpty) return;
      final list = jsonDecode(raw) as List;
      entradas = list
          .map((m) => HistorialReporteEntry.fromMap(m as Map<String, dynamic>))
          .toList();
    } catch (e) {
      debugPrint('[HistorialReportes] cargar: $e');
    }
  }

  /// Guarda el historial actual a disco. Llamar después de cada cambio.
  static Future<void> _persistir() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString(_kKey,
          jsonEncode(entradas.map((e) => e.toMap()).toList()));
    } catch (e) {
      debugPrint('[HistorialReportes] persistir: $e');
    }
  }

  /// Agrega una entrada al historial.
  static Future<void> agregar(HistorialReporteEntry e) async {
    entradas.insert(0, e); // más recientes primero
    // Limitar a 100 últimas para no crecer indefinido
    if (entradas.length > 100) {
      entradas = entradas.sublist(0, 100);
    }
    await _persistir();
  }

  /// Elimina del historial (NO borra el archivo físico).
  static Future<void> eliminar(int indice) async {
    if (indice < 0 || indice >= entradas.length) return;
    entradas.removeAt(indice);
    await _persistir();
  }

  static Future<void> limpiarTodo() async {
    entradas.clear();
    await _persistir();
  }

  /// Categoriza un nombre de archivo en una de las secciones conocidas.
  static String categoriaPorNombre(String nombre) {
    final n = nombre.toLowerCase();
    if (n.contains('venta') || n.contains('factura')) return 'Ventas';
    if (n.contains('inventario') || n.contains('stock') || n.contains('imei')) return 'Inventario';
    if (n.contains('cuenta') || n.contains('cobrar') || n.contains('pagar')) return 'Cuentas';
    if (n.contains('linea') || n.contains('activacion')) return 'Líneas';
    if (n.contains('cierre')) return 'Cierres';
    if (n.contains('comision')) return 'Comisiones';
    if (n.contains('servicio') || n.contains('tecnico')) return 'Servicio Técnico';
    return 'Otros';
  }
}

// ════════════════════════════════════════════════════════════
//  GENERADORES DE REPORTES
//  Cada función ahora construye un objeto HistorialReporteEntry
//  con los datos completos y lo agrega al historial. NO genera
//  archivos en disco — el usuario abre el reporte dentro de la
//  app desde la pestaña de historial. Si lo necesita, puede
//  descargar el Excel desde el visor.
// ════════════════════════════════════════════════════════════

// ── Helper para registrar un reporte recién generado ─────────
Future<void> _registrarReporte(HistorialReporteEntry e) async {
  await HistorialReportes.agregar(e);
}

String _nombreReporte(String base, DateTime? d, DateTime? h) =>
    '$base — ${_etiquetaRango(d, h)}';

String _etiquetaRango(DateTime? d, DateTime? h) {
  if (d == null && h == null) return 'Histórico completo';
  String f(DateTime x) =>
      '${x.day.toString().padLeft(2, '0')}/${x.month.toString().padLeft(2, '0')}/${x.year}';
  final ds = d != null ? f(d) : 'inicio';
  final hs = h != null ? f(h) : 'hoy';
  return '$ds al $hs';
}

// ════════════════════════════════════════════════════════════
//  VENTAS — incluye TODO el detalle de cada factura:
//  cliente, número, productos (equipos por IMEI + items sin IMEI)
//  y desglose de pagos.
// ════════════════════════════════════════════════════════════
Future<void> generarReporteVentas({DateTime? desde, DateTime? hasta}) async {
  final detalles = <Map<String, dynamic>>[];
  final filas = <List<dynamic>>[];
  double granTotal = 0;
  final Map<String, double> totalPorMetodo = {};

  try {
    // Cargar facturas
    final raw = await _Api.get('facturas');

    // Cargar productos y stock IMEI para enriquecer descripciones
    List productosRaw = [];
    List stockImeiRaw = [];
    try {
      productosRaw = (await _Api.get('productos') as List?) ?? [];
    } catch (_) {}
    try {
      stockImeiRaw = (await _Api.get('stock_imei') as List?) ?? [];
    } catch (_) {}

    // Indexar por código / IMEI para búsquedas rápidas
    final prodPorCodigo = <String, Map>{};
    for (final p in productosRaw) {
      final c = (p['codigo'] ?? '').toString();
      if (c.isNotEmpty) prodPorCodigo[c] = p as Map;
    }
    final imeiInfo = <String, Map>{};
    for (final i in stockImeiRaw) {
      final imei = (i['imei'] ?? '').toString();
      if (imei.isNotEmpty) imeiInfo[imei] = i as Map;
    }

    for (var v in ((raw as List?) ?? [])) {
      if (!_enRango(v['fecha'], desde, hasta)) continue;

      final total = double.tryParse(v['total']?.toString() ?? '0') ?? 0;
      granTotal += total;

      // Construir lista de productos enriquecidos
      final productosDetalle = <Map<String, dynamic>>[];

      // Equipos con IMEI
      final rawEquipos = (v['equipos'] as List?) ?? [];
      for (final e in rawEquipos) {
        String imei = '';
        if (e is String) {
          imei = e;
        } else if (e is Map) {
          imei = (e['imei'] ?? '').toString();
        }
        // Buscar info del IMEI
        final info = imeiInfo[imei];
        final codigoProd = (info?['producto_codigo'] ?? '').toString();
        final prodInfo = prodPorCodigo[codigoProd];
        productosDetalle.add({
          'tipo': 'Equipo (IMEI)',
          'codigo': codigoProd,
          'nombre': prodInfo?['nombre']?.toString() ??
                    info?['modelo']?.toString() ?? 'Equipo',
          'marca':  prodInfo?['marca']?.toString() ?? info?['marca']?.toString() ?? '',
          'modelo': prodInfo?['modelo']?.toString() ?? info?['modelo']?.toString() ?? '',
          'imei': imei,
          'precio_venta': prodInfo?['precio_venta']?.toString() ?? '',
          'precio_costo': prodInfo?['precio_costo']?.toString() ?? '',
        });
      }

      // Items sin IMEI (accesorios, líneas, etc.)
      final rawItems = (v['items'] as List?) ?? [];
      for (final it in rawItems) {
        String codigo = '';
        if (it is String) {
          codigo = it;
        } else if (it is Map) {
          codigo = (it['codigo'] ?? '').toString();
        }
        final prodInfo = prodPorCodigo[codigo];
        productosDetalle.add({
          'tipo': prodInfo?['categoria']?.toString() ?? 'Producto',
          'codigo': codigo,
          'nombre': prodInfo?['nombre']?.toString() ?? codigo,
          'marca':  prodInfo?['marca']?.toString() ?? '',
          'modelo': prodInfo?['modelo']?.toString() ?? '',
          'imei': '',
          'precio_venta': prodInfo?['precio_venta']?.toString() ?? '',
          'precio_costo': prodInfo?['precio_costo']?.toString() ?? '',
        });
      }

      // Pagos de la factura
      final pagosDetalle = <Map<String, dynamic>>[];
      final rawPagos = (v['pagos'] as List?) ?? [];
      for (final p in rawPagos) {
        if (p is Map) {
          final monto = double.tryParse(p['monto']?.toString() ?? '0') ?? 0;
          final met = (p['metodo'] ?? '').toString();
          pagosDetalle.add({
            'metodo': met,
            'tipo': (p['tipo'] ?? '').toString(),
            'financiador': (p['financiador'] ?? '').toString(),
            'monto': monto,
          });
          totalPorMetodo[met] = (totalPorMetodo[met] ?? 0) + monto;
        }
      }

      detalles.add({
        'nro_factura': (v['nro_factura'] ?? '').toString(),
        'cliente':     (v['cliente'] ?? '').toString(),
        'cedula':      (v['cedula'] ?? '').toString(),
        'telefono':    (v['telefono'] ?? '').toString(),
        'vendedor':    (v['vendedor'] ?? '').toString(),
        'tienda':      (v['tienda'] ?? '').toString(),
        'fecha':       (v['fecha'] ?? '').toString(),
        'tipo_venta':  (v['tipo_venta'] ?? '').toString(),
        'total': total,
        'productos': productosDetalle,
        'pagos': pagosDetalle,
      });

      filas.add([
        v['nro_factura'] ?? '',
        v['cliente']     ?? '',
        v['cedula']      ?? '',
        v['telefono']    ?? '',
        v['vendedor']    ?? '',
        v['tienda']      ?? '',
        v['fecha']       ?? '',
        total,
        v['tipo_venta']  ?? '',
      ]);
    }
  } catch (e) {
    debugPrint('generarReporteVentas: $e');
  }

  await _registrarReporte(HistorialReporteEntry(
    nombreArchivo: _nombreReporte('Reporte de Ventas', desde, hasta),
    tipoReporte: 'ventas',
    categoria: 'Ventas',
    fecha: DateTime.now(),
    generadoPor: usuarioSesion?.nombre ?? '—',
    desdeIso: desde?.toIso8601String(),
    hastaIso: hasta?.toIso8601String(),
    encabezados: const [
      'Nro Factura','Cliente','Cédula','Teléfono','Vendedor',
      'Tienda','Fecha','Total','F/D'],
    filas: filas,
    detalles: detalles,
    resumen: {
      'total_facturas': detalles.length,
      'total_monto': granTotal,
      'total_por_metodo': totalPorMetodo,
    },
  ));
}

// ════════════════════════════════════════════════════════════
//  INVENTARIO
// ════════════════════════════════════════════════════════════
Future<void> generarReporteInventario({DateTime? desde, DateTime? hasta}) async {
  final filas = <List<dynamic>>[];
  final detalles = <Map<String, dynamic>>[];
  double valorTotalCosto = 0, valorTotalVenta = 0;

  try {
    final rawP = await _Api.get('productos');
    final rawI = await _Api.get('stock_imei');
    final imeis = (rawI as List?) ?? [];
    for (var p in ((rawP as List?) ?? [])) {
      final stockReal = p['categoria'] == 'Telefono'
          ? imeis.where((i) =>
              i['producto_codigo'] == p['codigo'] && (i['vendido'] ?? 0) == 0).length
          : (int.tryParse(p['stock_manual'].toString()) ?? 0);
      final pCosto = double.tryParse(p['precio_costo']?.toString() ?? '0') ?? 0;
      final pVenta = double.tryParse(p['precio_venta']?.toString() ?? '0') ?? 0;
      valorTotalCosto += pCosto * stockReal;
      valorTotalVenta += pVenta * stockReal;

      filas.add([
        p['codigo'] ?? '',
        p['nombre'] ?? '',
        p['categoria'] ?? '',
        p['marca'] ?? '',
        p['modelo'] ?? '',
        stockReal,
        pCosto,
        pVenta,
      ]);
      detalles.add({
        'codigo': (p['codigo'] ?? '').toString(),
        'nombre': (p['nombre'] ?? '').toString(),
        'categoria': (p['categoria'] ?? '').toString(),
        'marca': (p['marca'] ?? '').toString(),
        'modelo': (p['modelo'] ?? '').toString(),
        'stock': stockReal,
        'precio_costo': pCosto,
        'precio_venta': pVenta,
      });
    }
  } catch (e) {
    debugPrint('generarReporteInventario: $e');
  }

  await _registrarReporte(HistorialReporteEntry(
    nombreArchivo: _nombreReporte('Inventario General', desde, hasta),
    tipoReporte: 'inventario',
    categoria: 'Inventario',
    fecha: DateTime.now(),
    generadoPor: usuarioSesion?.nombre ?? '—',
    desdeIso: desde?.toIso8601String(),
    hastaIso: hasta?.toIso8601String(),
    encabezados: const [
      'Código','Nombre','Categoría','Marca','Modelo',
      'Stock','Precio Costo','Precio Venta'],
    filas: filas,
    detalles: detalles,
    resumen: {
      'total_productos': filas.length,
      'valor_total_costo': valorTotalCosto,
      'valor_total_venta': valorTotalVenta,
    },
  ));
}

// ════════════════════════════════════════════════════════════
//  CUENTAS POR COBRAR — incluye los pagos efectuados a cada cuenta
// ════════════════════════════════════════════════════════════
Future<void> generarReporteCuentas({DateTime? desde, DateTime? hasta}) async {
  final filas = <List<dynamic>>[];
  final detalles = <Map<String, dynamic>>[];
  double sumaTotal = 0, sumaSaldo = 0;

  try {
    final raw = await _Api.get('cuentas_cobrar');
    for (var c in ((raw as List?) ?? [])) {
      final total = double.tryParse(c['monto_total']?.toString() ?? '0') ?? 0;
      final pagosLista = (c['pagos'] as List?) ?? [];
      final pagado = pagosLista.fold<double>(
          0, (s, p) => s + (double.tryParse(p['monto']?.toString() ?? '0') ?? 0));
      final saldo = (total - pagado).clamp(0.0, double.infinity);
      final estado = saldo <= 0 ? 'Pagado' : 'Pendiente';

      sumaTotal += total;
      sumaSaldo += saldo;

      filas.add([
        c['nombre'] ?? '',
        c['cedula'] ?? '',
        c['telefono'] ?? '',
        total,
        saldo,
        estado,
      ]);
      detalles.add({
        'nombre': (c['nombre'] ?? '').toString(),
        'cedula': (c['cedula'] ?? '').toString(),
        'telefono': (c['telefono'] ?? '').toString(),
        'monto_total': total,
        'pagado': pagado,
        'saldo': saldo,
        'estado': estado,
        'pagos': pagosLista.map((p) => {
          'metodo': (p['metodo'] ?? '').toString(),
          'monto': double.tryParse(p['monto']?.toString() ?? '0') ?? 0,
          'fecha': (p['fecha'] ?? '').toString(),
        }).toList(),
      });
    }
  } catch (e) {
    debugPrint('generarReporteCuentas: $e');
  }

  await _registrarReporte(HistorialReporteEntry(
    nombreArchivo: _nombreReporte('Cuentas por Cobrar', desde, hasta),
    tipoReporte: 'cuentas_cobrar',
    categoria: 'Cuentas',
    fecha: DateTime.now(),
    generadoPor: usuarioSesion?.nombre ?? '—',
    desdeIso: desde?.toIso8601String(),
    hastaIso: hasta?.toIso8601String(),
    encabezados: const [
      'Cliente','Cédula','Teléfono','Monto Total','Saldo Pendiente','Estado'],
    filas: filas,
    detalles: detalles,
    resumen: {
      'total_cuentas': filas.length,
      'monto_total': sumaTotal,
      'saldo_total': sumaSaldo,
    },
  ));
}

// ════════════════════════════════════════════════════════════
//  CUENTAS POR PAGAR
// ════════════════════════════════════════════════════════════
Future<void> generarReporteCxPagar({DateTime? desde, DateTime? hasta}) async {
  final filas = <List<dynamic>>[];
  final detalles = <Map<String, dynamic>>[];
  double sumaTotal = 0, sumaSaldo = 0;

  try {
    final raw = await _Api.get('cuentas_pagar');
    for (var c in ((raw as List?) ?? [])) {
      final total = double.tryParse(c['monto_total']?.toString() ?? '0') ?? 0;
      final pagosLista = (c['pagos'] as List?) ?? [];
      final pagado = pagosLista.fold<double>(
          0, (s, p) => s + (double.tryParse(p['monto']?.toString() ?? '0') ?? 0));
      final saldo = (total - pagado).clamp(0.0, double.infinity);
      final ident = (c['cedula'] ?? c['rif'] ?? '').toString();

      sumaTotal += total;
      sumaSaldo += saldo;

      filas.add([
        c['nombre'] ?? '',
        ident,
        total,
        saldo,
        saldo <= 0 ? 'Pagado' : 'Pendiente',
      ]);
      detalles.add({
        'nombre': (c['nombre'] ?? '').toString(),
        'identificacion': ident,
        'monto_total': total,
        'pagado': pagado,
        'saldo': saldo,
        'estado': saldo <= 0 ? 'Pagado' : 'Pendiente',
        'pagos': pagosLista.map((p) => {
          'metodo': (p['metodo'] ?? '').toString(),
          'monto': double.tryParse(p['monto']?.toString() ?? '0') ?? 0,
          'fecha': (p['fecha'] ?? '').toString(),
        }).toList(),
      });
    }
  } catch (e) {
    debugPrint('generarReporteCxPagar: $e');
  }

  await _registrarReporte(HistorialReporteEntry(
    nombreArchivo: _nombreReporte('Cuentas por Pagar', desde, hasta),
    tipoReporte: 'cuentas_pagar',
    categoria: 'Cuentas',
    fecha: DateTime.now(),
    generadoPor: usuarioSesion?.nombre ?? '—',
    desdeIso: desde?.toIso8601String(),
    hastaIso: hasta?.toIso8601String(),
    encabezados: const [
      'Proveedor/Acreedor','Cédula/RIF','Monto Total','Saldo','Estado'],
    filas: filas,
    detalles: detalles,
    resumen: {
      'total_cuentas': filas.length,
      'monto_total': sumaTotal,
      'saldo_total': sumaSaldo,
    },
  ));
}

// ════════════════════════════════════════════════════════════
//  LÍNEAS / ACTIVACIONES
// ════════════════════════════════════════════════════════════
Future<void> generarReporteLineas({DateTime? desde, DateTime? hasta}) async {
  final filas = <List<dynamic>>[];
  final detalles = <Map<String, dynamic>>[];
  int activadas = 0, pendientes = 0;

  try {
    final raw = await _Api.get('lineas');
    for (var l in ((raw as List?) ?? [])) {
      if (!_enRango(l['fecha'], desde, hasta)) continue;
      final activa = (l['activada'] == 1 || l['activada'] == '1');
      if (activa) activadas++; else pendientes++;

      filas.add([
        l['nombre'] ?? '',
        l['cedula'] ?? '',
        l['telefono'] ?? '',
        l['tipo'] ?? '',
        l['plan'] ?? '',
        l['imei1'] ?? '',
        l['imei2'] ?? '',
        l['chip'] ?? '',
        l['patc'] ?? '',
        l['asignado'] ?? '',
        l['esim'] ?? '',
        activa ? 'Sí' : 'No',
        (l['recargada'] == 1 || l['recargada'] == '1') ? 'Sí' : 'No',
        l['vendedor'] ?? '',
        l['fecha'] ?? '',
      ]);
      detalles.add({
        'nombre': (l['nombre'] ?? '').toString(),
        'cedula': (l['cedula'] ?? '').toString(),
        'telefono': (l['telefono'] ?? '').toString(),
        'tipo': (l['tipo'] ?? '').toString(),
        'plan': (l['plan'] ?? '').toString(),
        'imei1': (l['imei1'] ?? '').toString(),
        'imei2': (l['imei2'] ?? '').toString(),
        'chip':  (l['chip'] ?? '').toString(),
        'patc':  (l['patc'] ?? '').toString(),
        'asignado': (l['asignado'] ?? '').toString(),
        'esim': (l['esim'] ?? '').toString(),
        'activada': activa,
        'recargada': (l['recargada'] == 1 || l['recargada'] == '1'),
        'vendedor': (l['vendedor'] ?? '').toString(),
        'fecha': (l['fecha'] ?? '').toString(),
      });
    }
  } catch (e) {
    debugPrint('generarReporteLineas: $e');
  }

  await _registrarReporte(HistorialReporteEntry(
    nombreArchivo: _nombreReporte('Gestión de Líneas', desde, hasta),
    tipoReporte: 'lineas',
    categoria: 'Líneas',
    fecha: DateTime.now(),
    generadoPor: usuarioSesion?.nombre ?? '—',
    desdeIso: desde?.toIso8601String(),
    hastaIso: hasta?.toIso8601String(),
    encabezados: const [
      'Nombre','Cédula','Teléfono','Tipo','Plan','IMEI 1','IMEI 2',
      'Chip','Patc','Nro Asignado','eSIM','Activada','Recargada',
      'Vendedor','Fecha'],
    filas: filas,
    detalles: detalles,
    resumen: {
      'total_lineas': filas.length,
      'activadas': activadas,
      'pendientes': pendientes,
    },
  ));
}

// ════════════════════════════════════════════════════════════
//  IMEI
// ════════════════════════════════════════════════════════════
Future<void> generarReporteIMEI({DateTime? desde, DateTime? hasta}) async {
  final filas = <List<dynamic>>[];
  final detalles = <Map<String, dynamic>>[];
  int vendidos = 0, disponibles = 0;
  // Conteos por marca y modelo para el resumen
  final Map<String, int> porMarca = {};
  final Map<String, int> porModelo = {};

  try {
    // Cargar IMEIs y productos para garantizar marca/modelo correctos.
    // Si stock_imei trae marca/modelo vacío (porque no se hizo JOIN o el
    // producto se editó después), los completamos con la tabla productos
    // usando el código del producto como llave.
    List rawI = [];
    List productosRaw = [];
    try {
      rawI = (await _Api.get('stock_imei') as List?) ?? [];
    } catch (_) {}
    try {
      productosRaw = (await _Api.get('productos') as List?) ?? [];
    } catch (_) {}

    final prodPorCodigo = <String, Map>{};
    for (final p in productosRaw) {
      final c = (p['codigo'] ?? '').toString();
      if (c.isNotEmpty) prodPorCodigo[c] = p as Map;
    }

    for (var i in rawI) {
      if (!_enRango(i['fecha_ingreso'], desde, hasta)) continue;
      final v = (i['vendido'] == 1 || i['vendido'] == '1');
      if (v) vendidos++; else disponibles++;

      // Resolver marca/modelo/nombre cruzando con productos.
      final codigoProd = (i['producto_codigo'] ?? i['codigo'] ?? '').toString();
      final prodInfo = prodPorCodigo[codigoProd];

      String marca = (i['marca'] ?? '').toString().trim();
      if (marca.isEmpty) {
        marca = (prodInfo?['marca'] ?? '').toString().trim();
      }
      String modelo = (i['modelo'] ?? '').toString().trim();
      if (modelo.isEmpty) {
        modelo = (prodInfo?['modelo'] ?? '').toString().trim();
      }
      // Nombre comercial del equipo (lo añadimos como columna extra).
      String nombreEquipo = (i['producto_nombre'] ?? i['nombre'] ?? '').toString().trim();
      if (nombreEquipo.isEmpty) {
        nombreEquipo = (prodInfo?['nombre'] ?? '').toString().trim();
      }
      // Si después de todo siguen vacíos, los marcamos como 'N/D' para
      // que en el reporte sea evidente que falta el dato en la BD.
      if (marca.isEmpty)  marca  = 'N/D';
      if (modelo.isEmpty) modelo = 'N/D';

      // Conteos
      porMarca[marca]   = (porMarca[marca]   ?? 0) + 1;
      porModelo[modelo] = (porModelo[modelo] ?? 0) + 1;

      filas.add([
        i['imei'] ?? '',
        codigoProd,
        nombreEquipo,
        marca,
        modelo,
        i['proveedor'] ?? '',
        i['color'] ?? '',
        i['porcentaje_bateria'] ?? '',
        i['ubicacion'] ?? '',
        v ? 'Sí' : 'No',
        i['fecha_ingreso'] ?? '',
      ]);
      detalles.add({
        'imei': (i['imei'] ?? '').toString(),
        'codigo': codigoProd,
        'nombre': nombreEquipo,
        'marca': marca,
        'modelo': modelo,
        'proveedor': (i['proveedor'] ?? '').toString(),
        'color': (i['color'] ?? '').toString(),
        'porcentaje_bateria': (i['porcentaje_bateria'] ?? '').toString(),
        'ubicacion': (i['ubicacion'] ?? '').toString(),
        'vendido': v,
        'fecha_ingreso': (i['fecha_ingreso'] ?? '').toString(),
      });
    }
  } catch (e) {
    debugPrint('generarReporteIMEI: $e');
  }

  // Función helper para obtener el top N de un mapa por valor descendente.
  Map<String, int> topN(Map<String, int> m, int n) {
    final entries = m.entries.toList()
      ..sort((a, b) => b.value.compareTo(a.value));
    return Map.fromEntries(entries.take(n));
  }

  await _registrarReporte(HistorialReporteEntry(
    nombreArchivo: _nombreReporte('Gestión de IMEIs', desde, hasta),
    tipoReporte: 'imei',
    categoria: 'Inventario',
    fecha: DateTime.now(),
    generadoPor: usuarioSesion?.nombre ?? '—',
    desdeIso: desde?.toIso8601String(),
    hastaIso: hasta?.toIso8601String(),
    encabezados: const [
      'IMEI','Código','Equipo','Marca','Modelo','Proveedor','Color',
      '% Batería','Ubicación','Vendido','Fecha Ingreso'],
    filas: filas,
    detalles: detalles,
    resumen: {
      'total_imeis': filas.length,
      'vendidos': vendidos,
      'disponibles': disponibles,
      'por_marca':  topN(porMarca, 10),
      'por_modelo': topN(porModelo, 10),
    },
  ));
}

// ════════════════════════════════════════════════════════════
//  CIERRES DE CAJA — incluye desglose por método de pago
// ════════════════════════════════════════════════════════════
Future<void> generarReporteCierres({DateTime? desde, DateTime? hasta}) async {
  final filas = <List<dynamic>>[];
  final detalles = <Map<String, dynamic>>[];
  double granTotal = 0;

  try {
    final raw = await _Api.get('cierres');
    for (var c in ((raw as List?) ?? [])) {
      if (!_enRango(c['fecha_cierre'], desde, hasta)) continue;
      final total = double.tryParse(c['monto_total']?.toString() ?? '0') ?? 0;
      granTotal += total;
      final metodos = (c['metodos'] as List? ?? [])
          .map((m) => "${m['metodo']}: ${m['monto']}").join(' | ');
      final metodosDetalle = (c['metodos'] as List? ?? [])
          .map((m) => {
            'metodo': (m['metodo'] ?? '').toString(),
            'monto': double.tryParse(m['monto']?.toString() ?? '0') ?? 0,
          }).toList();

      filas.add([
        c['uid'] ?? '',
        c['tienda'] ?? '',
        c['fecha_cierre'] ?? '',
        total,
        c['usuario_cierre'] ?? '',
        metodos,
      ]);
      detalles.add({
        'uid': (c['uid'] ?? '').toString(),
        'tienda': (c['tienda'] ?? '').toString(),
        'fecha_cierre': (c['fecha_cierre'] ?? '').toString(),
        'monto_total': total,
        'usuario_cierre': (c['usuario_cierre'] ?? '').toString(),
        'metodos': metodosDetalle,
      });
    }
  } catch (e) {
    debugPrint('generarReporteCierres: $e');
  }

  await _registrarReporte(HistorialReporteEntry(
    nombreArchivo: _nombreReporte('Cierres de Caja', desde, hasta),
    tipoReporte: 'cierres',
    categoria: 'Cierres',
    fecha: DateTime.now(),
    generadoPor: usuarioSesion?.nombre ?? '—',
    desdeIso: desde?.toIso8601String(),
    hastaIso: hasta?.toIso8601String(),
    encabezados: const [
      'UID','Tienda','Fecha','Total','Responsable','Métodos de Pago'],
    filas: filas,
    detalles: detalles,
    resumen: {
      'total_cierres': filas.length,
      'monto_total': granTotal,
    },
  ));
}

// ════════════════════════════════════════════════════════════
//  COMISIONES
// ════════════════════════════════════════════════════════════
Future<void> generarReporteComisiones({DateTime? desde, DateTime? hasta}) async {
  final filas = <List<dynamic>>[];
  final detalles = <Map<String, dynamic>>[];

  try {
    final raw = await _Api.get('comisiones_historial');
    for (var h in ((raw as List?) ?? [])) {
      final tasa = double.tryParse(h['tasa']?.toString() ?? '1') ?? 1;
      final periodo = "${h['fecha_inicio']} — ${h['fecha_fin']}";
      // filtrar por rango si aplica
      if (!_enRango(h['fecha_inicio'], desde, hasta) &&
          !_enRango(h['fecha_fin'], desde, hasta)) {
        // si ningún extremo cae en rango, omitir
        if (desde != null || hasta != null) continue;
      }
      for (var d in ((h['detalle'] as List?) ?? [])) {
        final r = ResumenComision.fromMap(d);
        // Usamos los IDs originales para mantener compatibilidad con
        // reportes históricos que esperan estas mismas columnas.
        filas.add([
          r.vendedor,
          r.conteoDe('telefono'),
          r.conteoDe('accesorio'),
          r.conteoDe('televisor'),
          r.conteoDe('linea'),
          r.conteoDe('linea_blanca'),
          r.conteoDe('financiador'),
          r.comisionWeppa,
          r.base,
          r.totalComision,
          r.totalPagar() * tasa,
          periodo,
        ]);
        detalles.add({
          'vendedor': r.vendedor,
          'telefonos': r.conteoDe('telefono'),
          'accesorios': r.conteoDe('accesorio'),
          'televisores': r.conteoDe('televisor'),
          'lineas': r.conteoDe('linea'),
          'linea_blanca': r.conteoDe('linea_blanca'),
          'financiador': r.conteoDe('financiador'),
          'comision_weppa': r.comisionWeppa,
          'base': r.base,
          'total_comision': r.totalComision,
          'total_bs': r.totalPagar() * tasa,
          'tasa': tasa,
          'periodo': periodo,
          // Categorías personalizadas extra (las que no están en el mapeo
          // estándar). Útil para que el reporte muestre Servicio Técnico,
          // etc. cuando existan en los datos.
          'conteos_extra': Map.fromEntries(r.conteos.entries.where((e) =>
              !{'telefono', 'accesorio', 'televisor', 'linea',
                'linea_blanca', 'financiador'}.contains(e.key))),
        });
      }
    }
  } catch (e) {
    debugPrint('generarReporteComisiones: $e');
  }

  await _registrarReporte(HistorialReporteEntry(
    nombreArchivo: _nombreReporte('Comisiones', desde, hasta),
    tipoReporte: 'comisiones',
    categoria: 'Comisiones',
    fecha: DateTime.now(),
    generadoPor: usuarioSesion?.nombre ?? '—',
    desdeIso: desde?.toIso8601String(),
    hastaIso: hasta?.toIso8601String(),
    encabezados: const [
      'Vendedor','Teléfonos','Accesorios','Televisores','Líneas',
      'L. Blanca','Financiador','Com. Weppa','Sueldo Base',
      'Total Comisión','Total Bs','Período'],
    filas: filas,
    detalles: detalles,
    resumen: {
      'total_registros': filas.length,
    },
  ));
}

// ════════════════════════════════════════════════════════════
//  SERVICIO TÉCNICO
// ════════════════════════════════════════════════════════════
Future<void> generarReporteServicios({DateTime? desde, DateTime? hasta}) async {
  final filas = <List<dynamic>>[];
  final detalles = <Map<String, dynamic>>[];
  double granTotal = 0;
  final Map<String, int> porEstado = {};

  try {
    final raw = await _Api.get('servicios');
    for (var sv in ((raw as List?) ?? [])) {
      if (!_enRango(sv['fecha'], desde, hasta)) continue;
      final monto = double.tryParse(sv['monto']?.toString() ?? '0') ?? 0;
      granTotal += monto;
      final est = (sv['estado'] ?? '').toString();
      porEstado[est] = (porEstado[est] ?? 0) + 1;

      filas.add([
        sv['id'] ?? '',
        sv['cliente'] ?? '',
        sv['telefono'] ?? '',
        sv['dispositivo'] ?? '',
        sv['falla'] ?? '',
        sv['tecnico'] ?? '',
        monto,
        est,
        sv['fecha'] ?? '',
      ]);
      detalles.add({
        'id': (sv['id'] ?? '').toString(),
        'cliente': (sv['cliente'] ?? '').toString(),
        'telefono': (sv['telefono'] ?? '').toString(),
        'dispositivo': (sv['dispositivo'] ?? '').toString(),
        'falla': (sv['falla'] ?? '').toString(),
        'tecnico': (sv['tecnico'] ?? '').toString(),
        'monto': monto,
        'estado': est,
        'fecha': (sv['fecha'] ?? '').toString(),
      });
    }
  } catch (e) {
    debugPrint('generarReporteServicios: $e');
  }

  await _registrarReporte(HistorialReporteEntry(
    nombreArchivo: _nombreReporte('Servicio Técnico', desde, hasta),
    tipoReporte: 'servicios',
    categoria: 'Servicio Técnico',
    fecha: DateTime.now(),
    generadoPor: usuarioSesion?.nombre ?? '—',
    desdeIso: desde?.toIso8601String(),
    hastaIso: hasta?.toIso8601String(),
    encabezados: const [
      'ID','Cliente','Teléfono','Dispositivo','Falla','Técnico',
      'Monto','Estado','Fecha'],
    filas: filas,
    detalles: detalles,
    resumen: {
      'total_servicios': filas.length,
      'monto_total': granTotal,
      'por_estado': porEstado,
    },
  ));
}

// ════════════════════════════════════════════════════════════
//  EXPORTACIÓN A EXCEL — bajo demanda desde el visor
//  Recibe una entrada del historial y genera el archivo XLSX
//  con TODA la información disponible (incluyendo sub-tablas
//  de productos y pagos en el caso de ventas).
// ════════════════════════════════════════════════════════════
Future<Uint8List> exportarHistorialAExcel(HistorialReporteEntry e) async {
  final excel = Excel.createExcel();

  // Hoja principal: tabla plana
  final nombreHoja = _nombreHojaSeguro(e.categoria);
  final s = excel[nombreHoja];
  // Eliminar la hoja por defecto si existe y no la estamos usando
  excel.delete('Sheet1');

  // Encabezado del reporte (metadatos)
  s.appendRow(_filaCeldas(['REPORTE: ${e.nombreArchivo}']));
  s.appendRow(_filaCeldas(['Generado por: ${e.generadoPor}']));
  s.appendRow(_filaCeldas(['Fecha de generación: ${_formatoFechaCompleta(e.fecha)}']));
  s.appendRow(_filaCeldas(['Rango: ${_etiquetaRango(
    e.desdeIso != null ? DateTime.tryParse(e.desdeIso!) : null,
    e.hastaIso != null ? DateTime.tryParse(e.hastaIso!) : null)}']));
  s.appendRow(_filaCeldas(['Total de registros: ${e.totalRegistros}']));
  s.appendRow(<CellValue?>[]);

  // Encabezados de columnas
  s.appendRow(_filaCeldas(e.encabezados.cast<dynamic>().toList()));
  // Filas
  for (final fila in e.filas) {
    s.appendRow(_filaCeldas(fila));
  }

  // Resumen al final
  if (e.resumen.isNotEmpty) {
    s.appendRow(<CellValue?>[]);
    s.appendRow(_filaCeldas(['RESUMEN']));
    e.resumen.forEach((k, v) {
      if (v is Map) {
        s.appendRow(_filaCeldas([k]));
        v.forEach((kk, vv) {
          s.appendRow(_filaCeldas(['  $kk', vv]));
        });
      } else {
        s.appendRow(_filaCeldas([k, v]));
      }
    });
  }

  // ── HOJAS ADICIONALES SEGÚN EL TIPO DE REPORTE ──────────────
  if (e.tipoReporte == 'ventas') {
    // Una hoja con TODOS los productos vendidos (línea por línea)
    final sP = excel['Productos vendidos'];
    sP.appendRow(_filaCeldas([
      'Nro Factura', 'Cliente', 'Cédula', 'Fecha', 'Tipo', 'Código',
      'Producto', 'Marca', 'Modelo', 'IMEI', 'Precio Venta', 'Precio Costo',
    ]));
    for (final f in e.detalles) {
      final productos = (f['productos'] as List?) ?? [];
      for (final p in productos) {
        sP.appendRow(_filaCeldas([
          (f['nro_factura'] ?? '').toString(),
          (f['cliente'] ?? '').toString(),
          (f['cedula'] ?? '').toString(),
          (f['fecha'] ?? '').toString(),
          (p['tipo'] ?? '').toString(),
          (p['codigo'] ?? '').toString(),
          (p['nombre'] ?? '').toString(),
          (p['marca'] ?? '').toString(),
          (p['modelo'] ?? '').toString(),
          (p['imei'] ?? '').toString(),
          p['precio_venta'],
          p['precio_costo'],
        ]));
      }
    }

    // Una hoja con TODOS los pagos
    final sPg = excel['Pagos'];
    sPg.appendRow(_filaCeldas([
      'Nro Factura', 'Cliente', 'Cédula', 'Fecha',
      'Método', 'Tipo', 'Financiador', 'Monto',
    ]));
    for (final f in e.detalles) {
      final pagos = (f['pagos'] as List?) ?? [];
      for (final p in pagos) {
        sPg.appendRow(_filaCeldas([
          (f['nro_factura'] ?? '').toString(),
          (f['cliente'] ?? '').toString(),
          (f['cedula'] ?? '').toString(),
          (f['fecha'] ?? '').toString(),
          (p['metodo'] ?? '').toString(),
          (p['tipo'] ?? '').toString(),
          (p['financiador'] ?? '').toString(),
          p['monto'],
        ]));
      }
    }
  }

  if (e.tipoReporte == 'cuentas_cobrar' || e.tipoReporte == 'cuentas_pagar') {
    // Hoja de pagos efectuados a cada cuenta
    final sPg = excel['Pagos'];
    sPg.appendRow(_filaCeldas([
      e.tipoReporte == 'cuentas_cobrar' ? 'Cliente' : 'Proveedor',
      'Identificación', 'Método', 'Monto', 'Fecha',
    ]));
    for (final c in e.detalles) {
      final id = (c['cedula'] ?? c['identificacion'] ?? '').toString();
      final pagos = (c['pagos'] as List?) ?? [];
      for (final p in pagos) {
        sPg.appendRow(_filaCeldas([
          (c['nombre'] ?? '').toString(),
          id,
          (p['metodo'] ?? '').toString(),
          p['monto'],
          (p['fecha'] ?? '').toString(),
        ]));
      }
    }
  }

  if (e.tipoReporte == 'cierres') {
    // Hoja con desglose de métodos por cierre
    final sM = excel['Métodos por cierre'];
    sM.appendRow(_filaCeldas(['UID', 'Tienda', 'Fecha', 'Método', 'Monto']));
    for (final c in e.detalles) {
      final metodos = (c['metodos'] as List?) ?? [];
      for (final m in metodos) {
        sM.appendRow(_filaCeldas([
          (c['uid'] ?? '').toString(),
          (c['tienda'] ?? '').toString(),
          (c['fecha_cierre'] ?? '').toString(),
          (m['metodo'] ?? '').toString(),
          m['monto'],
        ]));
      }
    }
  }

  final bytes = excel.encode()!;
  return Uint8List.fromList(bytes);
}

// Helpers para construir Excel ────────────────────────────────
String _nombreHojaSeguro(String s) {
  // Excel limita los nombres de hoja a 31 chars, sin / \ ? * [ ]
  var n = s.replaceAll(RegExp(r'[\/\\\?\*\[\]]'), '_');
  if (n.length > 31) n = n.substring(0, 31);
  if (n.isEmpty) n = 'Reporte';
  return n;
}

String _slug(String s) {
  var n = s.toLowerCase().replaceAll(RegExp(r'[^a-z0-9]+'), '_');
  n = n.replaceAll(RegExp(r'_+'), '_').replaceAll(RegExp(r'^_|_$'), '');
  if (n.isEmpty) n = 'reporte';
  if (n.length > 60) n = n.substring(0, 60);
  return n;
}

/// Normaliza un valor a un tipo primitivo apto para `appendRow` del paquete
/// `excel` (versiones antiguas: aceptan `String`, `int`, `double`, `bool` o
/// `null` directamente, no envoltorios `CellValue`).
/// Normaliza un valor cualquiera a un `CellValue?` que el paquete `excel`
/// (versiones 4.0+) acepta en `appendRow`. En versiones anteriores
/// `appendRow` aceptaba `List<dynamic>` directamente; ahora exige
/// `List<CellValue?>`. Esta función centraliza la conversión.
CellValue? _normalizarCelda(dynamic v) {
  if (v == null) return null;
  if (v is CellValue) return v;
  if (v is bool) return BoolCellValue(v);
  if (v is int) return IntCellValue(v);
  if (v is double) return DoubleCellValue(v);
  if (v is num) return DoubleCellValue(v.toDouble());
  if (v is DateTime) {
    return DateTimeCellValue(
      year: v.year, month: v.month, day: v.day,
      hour: v.hour, minute: v.minute, second: v.second);
  }
  return TextCellValue(v.toString());
}

/// Atajo para convertir una lista de cualquier cosa a `List<CellValue?>`
/// (formato que requiere `appendRow` en excel 4.0+).
List<CellValue?> _filaCeldas(List<dynamic> valores) =>
    valores.map(_normalizarCelda).toList();

String _formatoFechaCompleta(DateTime d) =>
    '${d.day.toString().padLeft(2,'0')}/'
    '${d.month.toString().padLeft(2,'0')}/'
    '${d.year} '
    '${d.hour.toString().padLeft(2,'0')}:'
    '${d.minute.toString().padLeft(2,'0')}';

// ── Helpers de fecha ──────────────────────────────────────────
bool _enRango(dynamic fechaRaw, DateTime? desde, DateTime? hasta) {
  if (desde == null && hasta == null) return true;
  try {
    final f = parseFecha(fechaRaw?.toString() ?? '');
    if (desde != null && f.isBefore(desde)) return false;
    if (hasta != null && f.isAfter(hasta.add(const Duration(days: 1)))) return false;
    return true;
  } catch (_) { return true; }
}

String _sufFecha(DateTime? desde, DateTime? hasta) {
  if (desde == null && hasta == null) return 'todo';
  final d = desde != null ? '${desde.day}-${desde.month}-${desde.year}' : 'inicio';
  final h = hasta != null ? '${hasta.day}-${hasta.month}-${hasta.year}' : 'hoy';
  return '${d}_al_$h';
}

String _rangoStr(DateTime? desde, DateTime? hasta) {
  if (desde == null && hasta == null) return '';
  return ' (${desde != null ? "${desde.day}/${desde.month}/${desde.year}" : "inicio"}'
      ' — ${hasta != null ? "${hasta.day}/${hasta.month}/${hasta.year}" : "hoy"})';
}

// ============================================================
//  VENTANA REPORTES — con rango de fechas por módulo
// ============================================================
class VentanaReportes extends StatefulWidget {
  const VentanaReportes({super.key});
  @override State<VentanaReportes> createState() => _VentanaReportesState();
}

class _VentanaReportesState extends State<VentanaReportes>
    with SingleTickerProviderStateMixin {
  late final TabController _tabController;
  final Set<String> _descargando = {};
  // Fechas por id de reporte
  final Map<String, DateTime?> _desde = {};
  final Map<String, DateTime?> _hasta = {};

  // Búsqueda en historial
  final TextEditingController _busquedaHistorial = TextEditingController();
  String _filtroCategoria = 'Todas';
  bool _cargandoHistorial = true;

  @override
  void initState() {
    super.initState();
    _tabController = TabController(length: 2, vsync: this);
    _cargarHistorial();
  }

  @override
  void dispose() {
    _tabController.dispose();
    _busquedaHistorial.dispose();
    super.dispose();
  }

  Future<void> _cargarHistorial() async {
    setState(() => _cargandoHistorial = true);
    await HistorialReportes.cargar();
    if (mounted) setState(() => _cargandoHistorial = false);
  }

  Future<void> _ejecutar(String id, Future<void> Function(DateTime? d, DateTime? h) fn) async {
    setState(() => _descargando.add(id));
    try {
      await fn(_desde[id], _hasta[id]);
      if (mounted) {
        // Refrescar el historial para que la nueva entrada aparezca
        // inmediatamente al cambiar de tab.
        setState(() {});
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            content: const Text("✅ Reporte generado y agregado al historial"),
            backgroundColor: AppColors.statusGreen,
            action: SnackBarAction(
              label: 'Ver historial',
              textColor: Colors.white,
              onPressed: () => _tabController.animateTo(1),
            ),
          ));
      }
    } catch (e) {
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text("Error: $e"), backgroundColor: AppColors.statusRed));
    } finally {
      if (mounted) setState(() => _descargando.remove(id));
    }
  }

  Future<void> _seleccionarFecha(String id, bool esDe) async {
    final inicial = esDe ? (_desde[id] ?? DateTime.now().subtract(const Duration(days: 30)))
                         : (_hasta[id] ?? DateTime.now());
    final picked = await showDatePicker(
      context: context,
      initialDate: inicial,
      firstDate: DateTime(2020),
      lastDate: DateTime(2030));
    if (picked != null && mounted) {
      setState(() {
        if (esDe) _desde[id] = picked;
        else _hasta[id] = picked;
      });
    }
  }

  String _labelFecha(String id) {
    final d = _desde[id];
    final h = _hasta[id];
    if (d == null && h == null) return "Todo el historial";
    final ds = d != null ? "${d.day}/${d.month}/${d.year}" : "inicio";
    final hs = h != null ? "${h.day}/${h.month}/${h.year}" : "hoy";
    return "$ds — $hs";
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text("Reportes"),
        bottom: TabBar(
          controller: _tabController,
          indicatorColor: Colors.white,
          tabs: const [
            Tab(icon: Icon(Icons.add_chart), text: "GENERAR"),
            Tab(icon: Icon(Icons.history), text: "HISTORIAL"),
          ],
        ),
      ),
      body: TabBarView(
        controller: _tabController,
        children: [
          _tabGenerar(),
          _tabHistorial(),
        ],
      ),
    );
  }

  // ════════════════════════════════════════════════════════════
  //  TAB 1 — Generar reportes (lista de cards profesionales)
  // ════════════════════════════════════════════════════════════
