    return ListView(
      padding: const EdgeInsets.all(16),
      children: [
        // ── Banner informativo profesional ──
        Container(
          padding: const EdgeInsets.all(14),
          margin: const EdgeInsets.only(bottom: 18),
          decoration: BoxDecoration(
            gradient: LinearGradient(colors: [
              AppColors.primaryBlue.withValues(alpha: 0.10),
              AppColors.royalBlue.withValues(alpha: 0.06),
            ]),
            borderRadius: BorderRadius.circular(12),
            border: Border.all(
                color: AppColors.primaryBlue.withValues(alpha: 0.25)),
          ),
          child: Row(children: [
            Container(
              padding: const EdgeInsets.all(8),
              decoration: BoxDecoration(
                color: AppColors.primaryBlue.withValues(alpha: 0.15),
                borderRadius: BorderRadius.circular(8),
              ),
              child: const Icon(Icons.dashboard_outlined,
                  color: AppColors.primaryBlue, size: 22),
            ),
            const SizedBox(width: 12),
            const Expanded(child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text("Centro de Reportes",
                  style: TextStyle(
                    fontSize: 14, fontWeight: FontWeight.bold,
                    color: AppColors.textPrimary)),
                SizedBox(height: 2),
                Text(
                  "Genere reportes con rangos de fecha personalizables. "
                  "Cada reporte queda registrado en el historial.",
                  style: TextStyle(
                    fontSize: 11.5, color: AppColors.textSecondary,
                    height: 1.4)),
              ],
            )),
          ]),
        ),

        _seccion("VENTAS Y FACTURACIÓN"),
        _cardReporte(id: "ventas", titulo: "Ventas / Facturas",
          icono: Icons.receipt_long_outlined, color: const Color(0xFF1D6F42),
          subtitulo: "Cada factura con cliente, productos, IMEIs y desglose de pagos",
          fn: (d,h) => generarReporteVentas(desde: d, hasta: h)),

        _seccion("INVENTARIO"),
