          fn: (d,h) => generarReporteIMEI(desde: d, hasta: h)),

        _seccion("CUENTAS"),
        _cardReporte(id: "cxc", titulo: "Cuentas por Cobrar",
          icono: Icons.money_off_outlined, color: const Color(0xFF7B2D8B),
          subtitulo: "Saldos pendientes y pagos efectuados por cada cliente",
          fn: (d,h) => generarReporteCuentas(desde: d, hasta: h)),
        _cardReporte(id: "cxp", titulo: "Cuentas por Pagar",
          icono: Icons.payments_outlined, color: const Color(0xFFC62828),
          subtitulo: "Deudas pendientes y abonos a proveedores y acreedores",
          fn: (d,h) => generarReporteCxPagar(desde: d, hasta: h)),

        _seccion("LÍNEAS Y ACTIVACIONES"),
        _cardReporte(id: "lineas", titulo: "Gestión de Líneas",
          icono: Icons.sim_card_outlined, color: const Color(0xFF00838F),
          subtitulo: "Todas las líneas con estado de activación y datos asignados",
          fn: (d,h) => generarReporteLineas(desde: d, hasta: h)),

        _seccion("OPERACIONES"),
        _cardReporte(id: "cierres", titulo: "Cierres de Caja",
          icono: Icons.account_balance_wallet_outlined, color: const Color(0xFF37474F),
          subtitulo: "Todos los cierres con métodos de pago desglosados",
          fn: (d,h) => generarReporteCierres(desde: d, hasta: h)),
        _cardReporte(id: "comis", titulo: "Comisiones",
          icono: Icons.savings_outlined, color: const Color(0xFFE65100),
          subtitulo: "Historial de comisiones por vendedor con tasa aplicada",
          fn: (d,h) => generarReporteComisiones(desde: d, hasta: h)),
        _cardReporte(id: "serv", titulo: "Servicio Técnico",
          icono: Icons.build_outlined, color: const Color(0xFF4527A0),
          subtitulo: "Todos los servicios técnicos registrados",
          fn: (d,h) => generarReporteServicios(desde: d, hasta: h)),

        const SizedBox(height: 24),
      ],
    );
  }

  // ════════════════════════════════════════════════════════════
  //  TAB 2 — Historial profesional con búsqueda y filtros
  // ════════════════════════════════════════════════════════════
  Widget _tabHistorial() {
    if (_cargandoHistorial) {
      return const Center(child: CircularProgressIndicator());
    }

    final entradas = HistorialReportes.entradas;

    // Filtrado
    var visibles = entradas.where((e) {
      if (_filtroCategoria != 'Todas' && e.categoria != _filtroCategoria) {
        return false;
      }
      final q = _busquedaHistorial.text.trim().toLowerCase();
      if (q.isEmpty) return true;
      return e.nombreArchivo.toLowerCase().contains(q) ||
             e.categoria.toLowerCase().contains(q) ||
             e.generadoPor.toLowerCase().contains(q);
    }).toList();

    final categorias = ['Todas', ...{
      for (final e in entradas) e.categoria
    }];

    return Column(children: [
      // ── Barra de búsqueda + filtro + acciones ──
      Container(
        padding: const EdgeInsets.fromLTRB(12, 12, 12, 8),
        decoration: BoxDecoration(
          color: AppColors.surfaceGrey.withValues(alpha: 0.4),
          border: const Border(bottom: BorderSide(
              color: AppColors.cardBorder, width: 0.5)),
        ),
        child: Column(children: [
          TextField(
            controller: _busquedaHistorial,
            onChanged: (_) => setState(() {}),
            decoration: InputDecoration(
              hintText: 'Buscar por nombre, categoría o usuario',
              prefixIcon: const Icon(Icons.search, size: 20),
              isDense: true,
              filled: true,
              fillColor: Colors.white,
              border: OutlineInputBorder(
                borderRadius: BorderRadius.circular(10),
                borderSide: BorderSide(color: AppColors.cardBorder)),
              contentPadding:
                  const EdgeInsets.symmetric(horizontal: 12, vertical: 10),
            ),
          ),
          const SizedBox(height: 8),
          SizedBox(
            height: 32,
            child: ListView.separated(
              scrollDirection: Axis.horizontal,
              itemCount: categorias.length,
              separatorBuilder: (_, __) => const SizedBox(width: 6),
              itemBuilder: (c, i) {
                final cat = categorias[i];
                final selected = cat == _filtroCategoria;
                return FilterChip(
                  label: Text(cat,
                    style: TextStyle(
                      fontSize: 11.5,
                      color: selected ? Colors.white : AppColors.textPrimary)),
                  selected: selected,
                  selectedColor: AppColors.primaryBlue,
                  backgroundColor: Colors.white,
                  side: BorderSide(
                      color: selected
                          ? AppColors.primaryBlue
                          : AppColors.cardBorder),
                  onSelected: (_) => setState(() => _filtroCategoria = cat),
                  visualDensity: VisualDensity.compact,
                  materialTapTargetSize: MaterialTapTargetSize.shrinkWrap,
                );
              },
            ),
          ),
        ]),
      ),

      // ── Lista de reportes generados ──
      Expanded(
        child: visibles.isEmpty
            ? _emptyHistorial(entradas.isEmpty)
            : ListView.separated(
                padding: const EdgeInsets.all(12),
                itemCount: visibles.length,
                separatorBuilder: (_, __) => const SizedBox(height: 8),
                itemBuilder: (c, i) =>
                    _entradaHistorial(visibles[i], entradas.indexOf(visibles[i])),
              ),
      ),

      // ── Footer con acción "Limpiar todo" ──
      if (entradas.isNotEmpty)
        Container(
          padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
          decoration: const BoxDecoration(
            color: Colors.white,
            border: Border(top: BorderSide(
                color: AppColors.cardBorder, width: 0.5)),
          ),
          child: Row(
            mainAxisAlignment: MainAxisAlignment.spaceBetween,
            children: [
              Text('${entradas.length} reporte(s) en historial',
                style: const TextStyle(
                    fontSize: 11, color: AppColors.textSecondary)),
              TextButton.icon(
                icon: const Icon(Icons.delete_sweep_outlined,
                    size: 18, color: AppColors.statusRed),
                label: const Text('Limpiar historial',
                    style: TextStyle(color: AppColors.statusRed)),
                onPressed: () async {
                  final ok = await showDialog<bool>(
                    context: context,
                    builder: (ctx) => AlertDialog(
                      title: const Text('Limpiar historial'),
                      content: const Text(
                          '¿Eliminar todas las entradas del historial? '
                          'Los archivos físicos NO se borran del dispositivo.'),
                      actions: [
                        TextButton(
                            onPressed: () => Navigator.pop(ctx, false),
                            child: const Text('Cancelar')),
                        ElevatedButton(
                          style: ElevatedButton.styleFrom(
                              backgroundColor: AppColors.statusRed),
                          onPressed: () => Navigator.pop(ctx, true),
                          child: const Text('Limpiar',
                              style: TextStyle(color: Colors.white))),
                      ],
                    ));
                  if (ok == true) {
                    await HistorialReportes.limpiarTodo();
                    if (mounted) setState(() {});
                  }
                },
              ),
            ],
          ),
        ),
    ]);
  }

  Widget _emptyHistorial(bool nadaEnTotal) {
    return Center(
      child: Padding(
        padding: const EdgeInsets.all(32),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            Icon(Icons.folder_off_outlined,
                size: 64, color: AppColors.textSecondary.withValues(alpha: 0.4)),
            const SizedBox(height: 12),
            Text(
              nadaEnTotal
                  ? 'Aún no se ha generado ningún reporte'
                  : 'Ningún reporte coincide con la búsqueda',
              textAlign: TextAlign.center,
              style: const TextStyle(
                fontSize: 14, color: AppColors.textSecondary)),
            if (nadaEnTotal) ...[
              const SizedBox(height: 4),
              const Text(
                'Genere uno desde la pestaña "GENERAR"',
                textAlign: TextAlign.center,
                style: TextStyle(
                  fontSize: 12, color: AppColors.textSecondary)),
            ],
          ],
        ),
      ),
    );
  }

  Widget _entradaHistorial(HistorialReporteEntry e, int idx) {
    // Color e icono según tipo de reporte
    Color color;
    IconData icono;
    switch (e.tipoReporte) {
      case 'ventas':
        color = const Color(0xFF1976D2); icono = Icons.point_of_sale;
        break;
      case 'inventario':
        color = const Color(0xFF388E3C); icono = Icons.inventory_2;
        break;
      case 'cuentas_cobrar':
        color = const Color(0xFFE65100); icono = Icons.account_balance_wallet;
        break;
      case 'cuentas_pagar':
        color = const Color(0xFFC62828); icono = Icons.payments;
        break;
      case 'lineas':
        color = const Color(0xFF6A1B9A); icono = Icons.sim_card;
        break;
      case 'imei':
        color = const Color(0xFF00838F); icono = Icons.qr_code_2;
        break;
      case 'cierres':
        color = const Color(0xFF455A64); icono = Icons.receipt_long;
        break;
      case 'comisiones':
        color = const Color(0xFFAD1457); icono = Icons.percent;
        break;
      case 'servicios':
        color = const Color(0xFF5D4037); icono = Icons.build;
        break;
      default:
        color = AppColors.primaryBlue; icono = Icons.assessment;
    }
    final tamano = e.tamanoBytes < 1024
        ? '${e.tamanoBytes} B'
        : e.tamanoBytes < 1024 * 1024
            ? '${(e.tamanoBytes / 1024).toStringAsFixed(1)} KB'
            : '${(e.tamanoBytes / 1024 / 1024).toStringAsFixed(2)} MB';
    final fechaTxt = '${e.fecha.day.toString().padLeft(2,'0')}/'
        '${e.fecha.month.toString().padLeft(2,'0')}/'
        '${e.fecha.year} '
        '${e.fecha.hour.toString().padLeft(2,'0')}:'
        '${e.fecha.minute.toString().padLeft(2,'0')}';

    return Material(
      color: Colors.white,
      borderRadius: BorderRadius.circular(10),
      child: InkWell(
        borderRadius: BorderRadius.circular(10),
        onTap: () async {
          await Navigator.push(
            context,
            MaterialPageRoute(
              builder: (_) => VisorReporteScreen(entrada: e),
            ),
          );
          if (mounted) setState(() {});
        },
        child: Container(
          padding: const EdgeInsets.all(12),
          decoration: BoxDecoration(
            borderRadius: BorderRadius.circular(10),
            border: Border.all(color: AppColors.cardBorder),
          ),
          child: Row(children: [
            // Icono según categoría
            Container(
              width: 44, height: 44,
              decoration: BoxDecoration(
                color: color.withValues(alpha: 0.12),
                borderRadius: BorderRadius.circular(10),
              ),
              alignment: Alignment.center,
              child: Icon(icono, color: color, size: 22),
            ),
            const SizedBox(width: 12),
            // Detalles
            Expanded(child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(e.nombreArchivo,
                  maxLines: 1, overflow: TextOverflow.ellipsis,
                  style: const TextStyle(
                    fontSize: 13.5, fontWeight: FontWeight.w600,
                    color: AppColors.textPrimary)),
                const SizedBox(height: 3),
                Wrap(
                  spacing: 8, runSpacing: 2,
                  children: [
                    _chipMini(Icons.category_outlined, e.categoria),
                    _chipMini(Icons.schedule, fechaTxt),
                    _chipMini(Icons.person_outline, e.generadoPor),
                    _chipMini(Icons.format_list_numbered,
                        '${e.totalRegistros} reg.'),
                    _chipMini(Icons.data_usage, tamano),
                  ],
                ),
              ],
            )),
            // Botón ver
            IconButton(
              icon: Icon(Icons.visibility_outlined,
                  size: 20, color: color),
              tooltip: 'Ver reporte',
              onPressed: () async {
                await Navigator.push(
                  context,
                  MaterialPageRoute(
                    builder: (_) => VisorReporteScreen(entrada: e),
                  ),
                );
                if (mounted) setState(() {});
              },
            ),
            // Botón eliminar de historial
            IconButton(
              icon: const Icon(Icons.close,
                  size: 18, color: AppColors.textSecondary),
              tooltip: 'Quitar del historial',
              onPressed: () async {
                await HistorialReportes.eliminar(idx);
                if (mounted) setState(() {});
              },
            ),
          ]),
        ),
      ),
    );
  }

  Widget _chipMini(IconData icon, String text) => Row(
    mainAxisSize: MainAxisSize.min,
    children: [
      Icon(icon, size: 11, color: AppColors.textSecondary),
      const SizedBox(width: 3),
      Text(text,
        style: const TextStyle(
            fontSize: 10.5, color: AppColors.textSecondary)),
