}

// ============================================================
//  VISOR DE REPORTES (in-app)
//  — Muestra reportes guardados en el historial sin abrir
//    apps externas. Tiene opción de descargar a Excel.
// ============================================================
class VisorReporteScreen extends StatefulWidget {
  final HistorialReporteEntry entrada;
  const VisorReporteScreen({super.key, required this.entrada});

  @override
  State<VisorReporteScreen> createState() => _VisorReporteScreenState();
}

class _VisorReporteScreenState extends State<VisorReporteScreen> {
  bool _exportando = false;
  String _filtro = '';

  HistorialReporteEntry get e => widget.entrada;

  String _fmtMoneda(num? v) {
    if (v == null) return '\$0.00';
    return '\$${v.toStringAsFixed(2)}';
  }

  /// Conversión robusta a double que soporta:
  /// - num (int/double) → toDouble()
  /// - String "500.00" / "500,00" → 500.0
  /// - null o tipos inesperados → null
  double? _aDouble(dynamic v) {
    if (v == null) return null;
    if (v is num) return v.toDouble();
    if (v is String) {
      final s = v.trim().replaceAll(',', '.');
      if (s.isEmpty) return null;
      return double.tryParse(s);
    }
    return null;
  }

  String _fmtFecha(String? iso) {
    if (iso == null || iso.isEmpty) return '—';
    try {
      final d = DateTime.parse(iso);
      return '${d.day.toString().padLeft(2,'0')}/'
          '${d.month.toString().padLeft(2,'0')}/${d.year}';
    } catch (_) {
      return iso;
    }
  }

  String _fmtFechaHora(DateTime d) =>
      '${d.day.toString().padLeft(2,'0')}/'
      '${d.month.toString().padLeft(2,'0')}/${d.year} '
      '${d.hour.toString().padLeft(2,'0')}:'
      '${d.minute.toString().padLeft(2,'0')}';

  String _rangoTexto() {
    final d = e.desdeIso;
    final h = e.hastaIso;
    if (d == null && h == null) return 'Todo el periodo';
    if (d != null && h != null) return 'Del ${_fmtFecha(d)} al ${_fmtFecha(h)}';
    if (d != null) return 'Desde ${_fmtFecha(d)}';
    return 'Hasta ${_fmtFecha(h)}';
  }

  Future<void> _descargarExcel() async {
    if (_exportando) return;
    setState(() => _exportando = true);
    try {
      final bytes = await exportarHistorialAExcel(e);
      if (!mounted) return;
      await descargarArchivo(
        bytes,
        '${_slug(e.nombreArchivo)}.xlsx',
        'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      );
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
          content: Text('📥 Excel generado correctamente'),
          backgroundColor: AppColors.statusGreen,
        ));
      }
    } catch (err) {
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Text('Error al exportar: $err'),
        backgroundColor: AppColors.statusRed));
    } finally {
      if (mounted) setState(() => _exportando = false);
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: AppColors.surfaceTintBlue,
      appBar: AppBar(
        backgroundColor: AppColors.primaryBlue,
        foregroundColor: Colors.white,
        title: Text(e.nombreReporteLegible(),
          style: const TextStyle(fontWeight: FontWeight.bold)),
        actions: [
          if (_exportando)
            const Padding(
              padding: EdgeInsets.symmetric(horizontal: 16),
              child: Center(
                child: SizedBox(
                  width: 20, height: 20,
                  child: CircularProgressIndicator(
                    strokeWidth: 2, color: Colors.white))),
            )
          else
            IconButton(
              icon: const Icon(Icons.download_rounded),
              tooltip: 'Descargar Excel',
              onPressed: _descargarExcel,
            ),
        ],
      ),
      body: Column(
        children: [
          // Encabezado con metadatos
          Container(
            width: double.infinity,
            padding: const EdgeInsets.all(14),
            color: AppColors.primaryBlue.withValues(alpha: 0.06),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Row(children: [
                  const Icon(Icons.calendar_today,
                      size: 14, color: AppColors.textSecondary),
                  const SizedBox(width: 6),
                  Text(_rangoTexto(),
                    style: const TextStyle(
                      fontSize: 12.5, color: AppColors.textPrimary,
                      fontWeight: FontWeight.w600)),
                ]),
                const SizedBox(height: 6),
                Wrap(spacing: 12, runSpacing: 4, children: [
                  _metaItem(Icons.person_outline,
                      'Generado por: ${e.generadoPor}'),
                  _metaItem(Icons.schedule,
                      _fmtFechaHora(e.fecha)),
                  _metaItem(Icons.format_list_numbered,
                      '${e.totalRegistros} registros'),
                ]),
              ],
            ),
          ),
          // Resumen (si existe)
          if (e.resumen.isNotEmpty)
            _buildResumen(),
          // Cuerpo
          Expanded(
            child: e.detalles.isEmpty && e.filas.isEmpty
                ? const Center(
                    child: Column(
                      mainAxisAlignment: MainAxisAlignment.center,
                      children: [
                        Icon(Icons.inbox_outlined,
                            size: 64, color: AppColors.textSecondary),
                        SizedBox(height: 8),
                        Text('Sin datos en este reporte',
                          style: TextStyle(
                            fontSize: 14, color: AppColors.textSecondary)),
                      ],
                    ),
                  )
                : (e.tipoReporte == 'ventas'
                    ? _buildVistaVentas()
                    : _buildVistaTabla()),
          ),
        ],
      ),
    );
  }

  Widget _metaItem(IconData icono, String texto) => Row(
    mainAxisSize: MainAxisSize.min,
    children: [
      Icon(icono, size: 12, color: AppColors.textSecondary),
      const SizedBox(width: 4),
      Text(texto,
        style: const TextStyle(
            fontSize: 11, color: AppColors.textSecondary)),
    ],
  );

  Widget _buildResumen() {
    final items = <Widget>[];
    e.resumen.forEach((k, v) {
      // Casos especiales: total_por_metodo y por_estado son mapas
      if (v is Map) {
        items.add(Padding(
          padding: const EdgeInsets.only(top: 6, bottom: 2),
          child: Text(_legibleClave(k),
            style: const TextStyle(
              fontSize: 11, fontWeight: FontWeight.bold,
              color: AppColors.textSecondary, letterSpacing: 0.8)),
        ));
        v.forEach((k2, v2) {
          items.add(_chipResumen(_legibleClave(k2.toString()),
              _formatearValorResumen(v2)));
        });
      } else {
        items.add(_chipResumen(_legibleClave(k),
            _formatearValorResumen(v)));
      }
    });
    if (items.isEmpty) return const SizedBox.shrink();
    return Container(
      width: double.infinity,
      padding: const EdgeInsets.all(12),
      decoration: const BoxDecoration(
        color: Colors.white,
        border: Border(
          bottom: BorderSide(color: AppColors.cardBorder, width: 1)),
