  String _legibleClave(String k) {
    final s = k.replaceAll('_', ' ');
    if (s.isEmpty) return s;
    return s[0].toUpperCase() + s.substring(1);
  }

  String _formatearValorResumen(dynamic v) {
    if (v is num) {
      if (v == v.toInt()) return v.toInt().toString();
      return v.toStringAsFixed(2);
    }
    // Si viene como String numérico (ej. "500.00" desde MySQL DECIMAL),
    // intentamos parsearlo y formatearlo correctamente.
    final asDouble = _aDouble(v);
    if (asDouble != null) {
      if (asDouble == asDouble.toInt()) return asDouble.toInt().toString();
      return asDouble.toStringAsFixed(2);
    }
    return v?.toString() ?? '';
  }

