// ============================================================
//  SERVICIO DE NOTIFICACIONES
//  — Polling cada 30s con lógica diferenciada por ROL:
//
//  • TODOS LOS ROLES   → Mensajes nuevos no leídos
//  • ACTIVADOR         → Nueva línea registrada
//                      → Código ingresado por vendedor en una línea
//  • VENDEDOR          → Línea donde se solicitó el código (para ingresar)
//                      → Línea que fue activada exitosamente
// ============================================================
class NotificacionesService {
  static Timer? _timer;
  static final List<VoidCallback> _listeners = [];

  // ── Estado interno para detectar cambios entre polls ─────
  // Mensajes: último id conocido por receptor
  static int _ultimoIdMensaje = 0;
  // Líneas conocidas por id → estado anterior
  static final Map<int, _EstadoLineaAnterior> _estadoLineas = {};

  static void addListener(VoidCallback cb) {
    if (!_listeners.contains(cb)) _listeners.add(cb);
  }
  static void removeListener(VoidCallback cb) => _listeners.remove(cb);
  static void notificarCambio() {
    for (final cb in List.from(_listeners)) cb();
  }

  static void iniciar() {
    // Reiniciar estado al iniciar sesión
    _ultimoIdMensaje = 0;
    _estadoLineas.clear();
    _cargarNotificaciones();
    _timer?.cancel();
    // Polling cada 15 segundos. Antes era 3s y se acumulaban llamadas
    // si una respuesta tardaba más, además de saturar el servidor con
    // pings innecesarios. 15s es buen balance entre tiempo real y carga.
    _timer = Timer.periodic(const Duration(seconds: 15), (_) {
      // No volver a llamar si la sesión ya no está activa.
      if (usuarioSesion == null) {
        _timer?.cancel();
        _timer = null;
        return;
      }
      _cargarNotificaciones();
    });
  }

  static void detener() {
    _timer?.cancel();
    _timer = null;
    _estadoLineas.clear();
    _ultimoIdMensaje = 0;
  }

  // ── Carga principal orquestada por rol ────────────────────
  static Future<void> _cargarNotificaciones() async {
    if (usuarioSesion == null) return;
    try {
      // 1. Siempre: cargar notificaciones genéricas del servidor
      await _cargarNotificacionesServidor();
      // 2. Siempre: verificar mensajes nuevos
      await _verificarMensajesNuevos();
      // 3. Según rol: verificar eventos de líneas
      final rol = usuarioSesion!.rol;
      if (rol == 'Activador' || rol == 'Administrador' || rol == 'Dueño' || rol == 'Gerente') {
        await _verificarEventosActivador();
      }
      if (rol == 'Vendedor' || rol == 'Encargado' || rol == 'Administrador' || rol == 'Dueño' || rol == 'Gerente') {
        await _verificarEventosVendedor();
      }
    } catch (e) {
      debugPrint('[Notificaciones] Error general: $e');
    }
  }

  // ── 1. Notificaciones genéricas del servidor ──────────────
  static Future<void> _cargarNotificacionesServidor() async {
    try {
      final raw = await _Api.get('notificaciones', {
        'usuario': usuarioSesion?.correo ?? '',
      });
      final delServidor = ((raw as List?) ?? [])
          .map((m) => NotificacionSistema.fromMap(m))
          .where((n) =>
              // Filtro defensivo: descartar notificaciones vacías que
              // pudieran haber quedado en la BD de versiones anteriores.
              (n.titulo.trim().isNotEmpty || n.mensaje.trim().isNotEmpty))
          .toList();
      // ── Servidor es la única fuente de verdad ─────────────
      // Antes hacíamos un merge con notificaciones locales sin id,
      // lo que dejaba fantasmas si el POST al servidor fallaba (la
      // notificación local quedaba para siempre y aparecía como
      // "nueva" en cada polling).
      // Ahora simplemente reemplazamos la lista global con lo que
      // dice el servidor — si una notificación se perdió en el POST,
      // se pierde y ya, pero no contamina el contador.
      notificacionesGlobal = delServidor;
      notificarCambio();
    } catch (e) {
      debugPrint('[Notificaciones] servidor: $e');
    }
  }

  // ── 2. Detección de mensajes nuevos (todos los roles) ─────
  static Future<void> _verificarMensajesNuevos() async {
    try {
      final raw = await _Api.get('mensajes', {
        'receptor': usuarioSesion!.correo,
      });
      final mensajes = ((raw as List?) ?? [])
          .map((m) => MensajeInterno.fromMap(m))
          .toList();
      if (mensajes.isEmpty) return;

      // ── PRIMERA CARGA TRAS LOGIN ─────────────────────────────
      // Si _ultimoIdMensaje == 0 estamos en la primera carga del
      // poll. NO debemos notificar mensajes existentes (ya están
      // en la pantalla del chat para que el usuario los vea allí).
      // Solo establecemos el baseline con el id máximo conocido.
      if (_ultimoIdMensaje == 0) {
        final maxId = mensajes
            .where((m) => m.id != null)
            .fold(0, (mx, m) => m.id! > mx ? m.id! : mx);
        _ultimoIdMensaje = maxId;
        return;
      }

      // ── A partir de la 2ª carga, sí notificamos los nuevos ──
      final nuevos = mensajes.where((m) {
        final idActual = m.id ?? 0;
        return idActual > _ultimoIdMensaje;
      }).toList();

      if (nuevos.isNotEmpty) {
        // Agrupar por emisor
        final porEmisor = <String, List<MensajeInterno>>{};
        for (final m in nuevos) {
          porEmisor.putIfAbsent(m.emisor, () => []).add(m);
        }
        for (final entry in porEmisor.entries) {
          final emisorNombre = _nombreDeCorreo(entry.key);
          final cant = entry.value.length;
          final textoMensaje = cant == 1
              ? entry.value.first.contenido.isNotEmpty
                  ? entry.value.first.contenido
                  : '📎 Archivo adjunto'
              : '$cant mensajes nuevos';
          _agregarNotificacionLocal(
            titulo: '💬 Mensaje de $emisorNombre',
            mensaje: textoMensaje,
            tipo: 'mensaje',
          );
        }
        // Actualizar el último id conocido
        final maxId = mensajes
            .where((m) => m.id != null)
            .fold(0, (max, m) => m.id! > max ? m.id! : max);
        if (maxId > _ultimoIdMensaje) _ultimoIdMensaje = maxId;
        notificarCambio();
      }
    } catch (e) {
      debugPrint('[Notificaciones] mensajes: $e');
    }
  }

  // ── 3a. Eventos para ACTIVADOR ────────────────────────────
  //   • Nueva línea registrada
  //   • Código ingresado por el vendedor en una línea pendiente
  static Future<void> _verificarEventosActivador() async {
    try {
      final raw = await _Api.get('lineas');
      final lineasActuales = ((raw as List?) ?? [])
          .map((m) => LineaModel.fromMap(m))
          .toList();

      final bool esPrimeraCarga = _estadoLineas.isEmpty;

      for (final linea in lineasActuales) {
        if (linea.id == null) continue;
        final anterior = _estadoLineas[linea.id!];

        if (anterior == null) {
          // Línea nueva detectada
          if (!esPrimeraCarga) {
            _agregarNotificacionLocal(
              titulo: '📱 Nueva línea registrada',
              mensaje: '${linea.nombre} · ${linea.tipo} · Vendedor: ${linea.vendedor}',
              tipo: 'linea_nueva',
            );
          }
        } else {
          // Código ingresado: antes no tenía código o era vacío, ahora sí tiene
          final teniaCodigo = anterior.codigoSolicitado != null &&
              anterior.codigoSolicitado!.isNotEmpty;
          final tieneCodigo = linea.codigoSolicitado != null &&
              linea.codigoSolicitado!.isNotEmpty;
          if (!teniaCodigo && tieneCodigo && !linea.activada) {
            _agregarNotificacionLocal(
              titulo: '🔑 Código recibido',
              mensaje: '${linea.nombre}: ${linea.codigoSolicitado}',
              tipo: 'codigo_recibido',
            );
          }
        }

        // Actualizar estado conocido
        _estadoLineas[linea.id!] = _EstadoLineaAnterior(
          solicitandoCodigo: linea.solicitandoCodigo,
          codigoSolicitado: linea.codigoSolicitado,
          activada: linea.activada,
        );
      }

      if (!esPrimeraCarga) notificarCambio();
    } catch (e) {
      debugPrint('[Notificaciones] activador: $e');
    }
  }

  // ── 3b. Eventos para VENDEDOR ─────────────────────────────
  //   • Se solicita código para una línea suya
  //   • Línea suya fue activada exitosamente
  static Future<void> _verificarEventosVendedor() async {
    try {
      final raw = await _Api.get('lineas');
      final lineasActuales = ((raw as List?) ?? [])
          .map((m) => LineaModel.fromMap(m))
          .toList();

      final miNombre = usuarioSesion!.nombre;
      // Filtrar solo líneas asignadas a este vendedor
      final misLineas = lineasActuales.where((l) =>
          l.vendedor.toLowerCase() == miNombre.toLowerCase()).toList();

      final bool esPrimeraCarga = _estadoLineas.isEmpty;

      for (final linea in misLineas) {
        if (linea.id == null) continue;
        final anterior = _estadoLineas[linea.id!];

        if (anterior != null && !esPrimeraCarga) {
          // Nueva solicitud de código (activador pidió el código)
          if (!anterior.solicitandoCodigo && linea.solicitandoCodigo &&
              (linea.codigoSolicitado == null || linea.codigoSolicitado!.isEmpty)) {
            _agregarNotificacionLocal(
              titulo: '⚠️ Código solicitado',
              mensaje: 'Se requiere el código para la línea de ${linea.nombre}',
              tipo: 'codigo_solicitado',
            );
          }
          // Línea activada exitosamente
          if (!anterior.activada && linea.activada) {
            _agregarNotificacionLocal(
              titulo: '✅ Línea activada',
              mensaje: 'La línea de ${linea.nombre} fue activada correctamente',
              tipo: 'linea_activada',
            );
          }
        }

        // Actualizar estado (se comparte con verificarEventosActivador, solo actualizar si no existe)
        _estadoLineas.putIfAbsent(
          linea.id!,
          () => _EstadoLineaAnterior(
            solicitandoCodigo: linea.solicitandoCodigo,
            codigoSolicitado: linea.codigoSolicitado,
            activada: linea.activada,
          ),
        );
      }

      if (!esPrimeraCarga) notificarCambio();
    } catch (e) {
      debugPrint('[Notificaciones] vendedor: $e');
    }
  }

  // ── Agrega notificación local (sin ir al servidor) ────────
  static void _agregarNotificacionLocal({
    required String titulo,
    required String mensaje,
    required String tipo,
  }) {
    final ahora = DateTime.now();
    final fecha =
        '${ahora.day.toString().padLeft(2, '0')}/${ahora.month.toString().padLeft(2, '0')}/${ahora.year} '
        '${ahora.hour.toString().padLeft(2, '0')}:${ahora.minute.toString().padLeft(2, '0')}';
    final n = NotificacionSistema(
      titulo: titulo,
      mensaje: mensaje,
      fecha: fecha,
      leida: false,
    );
    notificacionesGlobal.insert(0, n);
    // 1) Mostrar notificación nativa (emergente) en el teléfono
    PushNotifier.mostrar(titulo: titulo, mensaje: mensaje);
    // 2) Persistir en el servidor para que sobreviva al próximo poll
    //    (que reemplaza notificacionesGlobal) y llegue al otro equipo.
    //    Se ejecuta en background sin await para no bloquear la UI.
    _persistirEnServidor(n, tipo);
  }

  /// Persiste la notificación en el backend para que sobreviva al
  /// siguiente ciclo de polling y llegue a cualquier otro usuario
  /// que esté consultando `notificaciones`. Si el POST falla, la
  /// notificación se mantiene al menos en memoria local.
  static Future<void> _persistirEnServidor(
      NotificacionSistema n, String tipo) async {
    try {
      final resp = await _Api.post('notificaciones', {
        'titulo': n.titulo,
        'mensaje': n.mensaje,
        'fecha': n.fecha,
        'tipo': tipo,
        'usuario': usuarioSesion?.correo ?? '',
        'leida': 0,
      });
      // ── BUG CRÍTICO: asignar ID devuelto al objeto local ──
      // Antes el POST se hacía y se ignoraba el ID. La notificación
      // quedaba en memoria con id=null, así que cuando el usuario la
      // tocaba para marcarla como leída, la condición
      // `if (n.id != null)` fallaba y NUNCA se marcaba leída.
      // Al cerrar/reabrir la app, el polling traía la misma notif del
      // servidor (sin marcar como leída) y aparecía como nueva otra vez.
      if (resp is Map && resp['id'] != null) {
        n.id = resp['id'] is int
            ? resp['id'] as int
            : int.tryParse(resp['id'].toString());
      }
    } catch (e) {
      debugPrint('[Notificaciones] persistir: $e');
    }
  }

  // ── Helper: obtener nombre amigable a partir del correo ───
  static String _nombreDeCorreo(String correo) {
    final usuario = usuariosSistema
        .where((u) => u.correo == correo)
        .firstOrNull;
    return usuario?.nombre ?? correo.split('@').first;
  }

  // ── CRUD de notificaciones ────────────────────────────────
  static Future<void> marcarLeida(int id) async {
    try {
      await _Api.put('notificaciones', id.toString(), {'leida': 1});
      final n = notificacionesGlobal.where((n) => n.id == id).firstOrNull;
      if (n != null) { n.leida = true; notificarCambio(); }
    } catch (e) { debugPrint('[Notificaciones] marcarLeida: $e'); }
  }

  static Future<void> marcarTodasLeidas() async {
    try {
      await _Api.post('notificaciones', {
        'accion': 'marcar_todas_leidas',
        'usuario': usuarioSesion?.correo ?? '',
      });
      for (final n in notificacionesGlobal) n.leida = true;
      notificarCambio();
    } catch (e) { debugPrint('[Notificaciones] marcarTodas: $e'); }
  }

  static Future<void> eliminar(int id) async {
    try {
      await _Api.delete('notificaciones', id.toString());
      notificacionesGlobal.removeWhere((n) => n.id == id);
      notificarCambio();
    } catch (e) { debugPrint('[Notificaciones] eliminar: $e'); }
  }

  /// Cuenta sólo notificaciones NO leídas Y con contenido.
  /// Excluye las "fantasma" vacías para que la campanita y el badge
  /// no muestren un número falso.
  static int get noLeidas => notificacionesGlobal
      .where((n) => !n.leida &&
          (n.titulo.trim().isNotEmpty || n.mensaje.trim().isNotEmpty))
      .length;
}

// ── Estado anterior de una línea para comparar cambios ───────
class _EstadoLineaAnterior {
  final bool solicitandoCodigo;
  final String? codigoSolicitado;
  final bool activada;
  const _EstadoLineaAnterior({
    required this.solicitandoCodigo,
    required this.codigoSolicitado,
    required this.activada,
  });
}

