// ── Pantalla de notificaciones ────────────────────────────────
class VentanaNotificaciones extends StatefulWidget {
  const VentanaNotificaciones({super.key});
  @override State<VentanaNotificaciones> createState() => _VentanaNotificacionesState();
}

class _VentanaNotificacionesState extends State<VentanaNotificaciones> {
  bool _cargando = false;

  @override
  void initState() {
    super.initState();
    NotificacionesService.addListener(_onCambio);
  }
  @override
  void dispose() {
    NotificacionesService.removeListener(_onCambio);
    super.dispose();
  }
  void _onCambio() { if (mounted) setState(() {}); }

  Future<void> _refresh() async {
    setState(() => _cargando = true);
    try {
      final raw = await _Api.get('notificaciones',
        {'usuario': usuarioSesion?.correo ?? ''});
      notificacionesGlobal = ((raw as List?) ?? [])
          .map((m) => NotificacionSistema.fromMap(m))
          // Defensa: descartar notificaciones vacías heredadas que
          // pudieran haber quedado en la BD antes del fix.
          .where((n) =>
              n.titulo.trim().isNotEmpty || n.mensaje.trim().isNotEmpty)
          .toList();
      NotificacionesService.notificarCambio();
    } catch (e) {
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Error: $e'),
          backgroundColor: AppColors.statusRed));
    } finally {
      if (mounted) setState(() => _cargando = false);
    }
  }

  @override
  Widget build(BuildContext context) {
    // Filtro UI: aunque la BD tenga vacías, la pantalla sólo muestra
    // las que tienen al menos título O mensaje con contenido.
    final notifs = notificacionesGlobal.where((n) =>
        n.titulo.trim().isNotEmpty || n.mensaje.trim().isNotEmpty).toList();
    final noLeidas = notifs.where((n) => !n.leida).length;
    return Scaffold(
      appBar: AppBar(
        title: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
          const Text("Notificaciones"),
          if (noLeidas > 0)
            Text("$noLeidas sin leer",
              style: const TextStyle(fontSize: 12, color: Colors.white70)),
        ]),
        actions: [
          if (noLeidas > 0)
            TextButton.icon(
              icon: const Icon(Icons.done_all, color: Colors.white, size: 18),
              label: const Text("Leer todas",
                style: TextStyle(color: Colors.white, fontSize: 12)),
              onPressed: () async {
                await NotificacionesService.marcarTodasLeidas();
                if (mounted) setState(() {});
              },
            ),
          IconButton(
            icon: const Icon(Icons.refresh),
            tooltip: "Actualizar",
            onPressed: _refresh,
          ),
        ],
      ),
      body: _cargando
        ? const Center(child: CircularProgressIndicator())
        : notifs.isEmpty
          ? Center(child: Column(mainAxisSize: MainAxisSize.min, children: [
              Icon(Icons.notifications_off_outlined, size: 72, color: Colors.grey[300]),
              const SizedBox(height: 12),
              Text("No hay notificaciones",
                style: TextStyle(color: Colors.grey[500], fontSize: 16)),
              const SizedBox(height: 8),
              TextButton.icon(
                icon: const Icon(Icons.refresh),
                label: const Text("Actualizar"),
                onPressed: _refresh),
            ]))
          : RefreshIndicator(
              onRefresh: _refresh,
              child: ListView.separated(
                padding: const EdgeInsets.symmetric(vertical: 8),
                itemCount: notifs.length,
                separatorBuilder: (_, __) =>
                  const Divider(height: 1, indent: 72),
                itemBuilder: (context, i) {
                  final n = notifs[i];
                  final esLeida = n.leida;
                  return Dismissible(
                    key: Key('notif_${n.id ?? i}'),
                    direction: DismissDirection.endToStart,
                    background: Container(
                      alignment: Alignment.centerRight,
                      padding: const EdgeInsets.only(right: 20),
                      color: AppColors.statusRed,
                      child: const Icon(Icons.delete_outline,
                        color: Colors.white, size: 28)),
                    confirmDismiss: (_) async {
                      return await showDialog<bool>(
                        context: context,
                        builder: (ctx) => AlertDialog(
                          title: const Text("Eliminar notificación"),
                          content: const Text(
                            "¿Eliminar esta notificación permanentemente?"),
                          actions: [
                            TextButton(
                              onPressed: () => Navigator.pop(ctx, false),
                              child: const Text("Cancelar")),
                            ElevatedButton(
                              style: ElevatedButton.styleFrom(
                                backgroundColor: AppColors.statusRed),
                              onPressed: () => Navigator.pop(ctx, true),
                              child: const Text("Eliminar",
                                style: TextStyle(color: Colors.white))),
                          ],
                        ),
                      ) ?? false;
                    },
                    onDismissed: (_) async {
                      if (n.id != null) {
                        await NotificacionesService.eliminar(n.id!);
                      } else {
                        notificacionesGlobal.remove(n);
                        NotificacionesService.notificarCambio();
                      }
                    },
                    child: InkWell(
                      onTap: () async {
                        if (!esLeida && n.id != null) {
                          await NotificacionesService.marcarLeida(n.id!);
                        }
                        if (!mounted) return;
                        showDialog(
                          context: context,
                          builder: (ctx) => AlertDialog(
                            title: Row(children: [
                              Icon(_iconoPorTitulo(n.titulo),
                                color: AppColors.royalBlue, size: 22),
                              const SizedBox(width: 8),
                              Expanded(child: Text(n.titulo,
                                style: const TextStyle(fontSize: 16))),
                            ]),
                            content: Column(
                              mainAxisSize: MainAxisSize.min,
                              crossAxisAlignment: CrossAxisAlignment.start,
                              children: [
                                Text(n.mensaje),
                                const SizedBox(height: 12),
                                Row(children: [
                                  const Icon(Icons.access_time, size: 14,
                                    color: AppColors.textSecondary),
                                  const SizedBox(width: 4),
                                  Text(n.fecha, style: const TextStyle(
                                    fontSize: 12, color: AppColors.textSecondary)),
                                ]),
                              ],
                            ),
                            actions: [
                              TextButton(
                                onPressed: () => Navigator.pop(ctx),
                                child: const Text("Cerrar")),
                            ],
                          ),
                        );
                      },
                      child: Container(
                        color: esLeida ? null
                          : AppColors.primaryBlue.withValues(alpha: 0.04),
                        padding: const EdgeInsets.symmetric(
                          horizontal: 16, vertical: 12),
                        child: Row(
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: [
                          Container(
                            width: 44, height: 44,
                            decoration: BoxDecoration(
                              color: (esLeida
                                ? AppColors.textSecondary
                                : AppColors.primaryBlue)
                                  .withValues(alpha: 0.1),
                              borderRadius: BorderRadius.circular(12)),
                            child: Icon(_iconoPorTitulo(n.titulo), size: 22,
                              color: esLeida
                                ? AppColors.textSecondary
                                : AppColors.primaryBlue),
                          ),
                          const SizedBox(width: 12),
                          Expanded(child: Column(
                            crossAxisAlignment: CrossAxisAlignment.start,
                            children: [
                              Row(children: [
                                Expanded(child: Text(n.titulo,
                                  style: TextStyle(
                                    fontWeight: esLeida
                                      ? FontWeight.w500 : FontWeight.bold,
                                    color: esLeida
                                      ? AppColors.textSecondary
                                      : AppColors.textPrimary,
                                    fontSize: 14))),
                                if (!esLeida)
                                  Container(width: 8, height: 8,
                                    decoration: const BoxDecoration(
                                      color: AppColors.primaryBlue,
                                      shape: BoxShape.circle)),
                              ]),
                              const SizedBox(height: 3),
                              Text(n.mensaje,
                                maxLines: 2,
                                overflow: TextOverflow.ellipsis,
                                style: const TextStyle(fontSize: 13,
                                  color: AppColors.textSecondary)),
                              const SizedBox(height: 4),
                              Text(n.fecha, style: const TextStyle(
                                fontSize: 11, color: AppColors.textSecondary)),
                            ],
                          )),
                        ]),
                      ),
                    ),
                  );
                },
              ),
            ),
    );
  }

  IconData _iconoPorTitulo(String titulo) {
    final t = titulo.toLowerCase();
    // Mensajes internos
    if (t.contains('mensaje') || t.contains('💬'))
      return Icons.chat_bubble_outline;
    // Código solicitado / recibido
    if (t.contains('código') || t.contains('codigo') || t.contains('🔑') || t.contains('⚠️'))
      return Icons.key_outlined;
    // Nueva línea registrada
    if (t.contains('nueva línea') || t.contains('nueva linea') || t.contains('📱'))
      return Icons.sim_card_outlined;
    // Línea activada
    if (t.contains('activada') || t.contains('✅'))
      return Icons.check_circle_outline;
    // Ventas / facturas
    if (t.contains('venta') || t.contains('factura'))
      return Icons.receipt_long_outlined;
    // Inventario / stock
    if (t.contains('stock') || t.contains('inventario'))
      return Icons.inventory_2_outlined;
    // Pagos / cuentas
    if (t.contains('pago') || t.contains('cobr') || t.contains('pagar'))
      return Icons.payments_outlined;
    // Líneas / activaciones genérico
    if (t.contains('línea') || t.contains('linea') || t.contains('activ'))
      return Icons.sim_card_outlined;
    if (t.contains('usuario')) return Icons.person_outline;
    if (t.contains('error') || t.contains('alerta'))
      return Icons.warning_amber_outlined;
    return Icons.notifications_outlined;
  }

  Color _colorPorTitulo(String titulo) {
    final t = titulo.toLowerCase();
    if (t.contains('mensaje') || t.contains('💬'))    return AppColors.primaryBlue;
    if (t.contains('código') || t.contains('codigo') || t.contains('🔑')) return AppColors.statusOrange;
    if (t.contains('⚠️'))                              return AppColors.statusOrange;
    if (t.contains('nueva línea') || t.contains('nueva linea') || t.contains('📱')) return AppColors.royalBlue;
    if (t.contains('activada') || t.contains('✅'))   return AppColors.statusGreen;
    if (t.contains('error') || t.contains('alerta'))  return AppColors.statusRed;
    return AppColors.primaryBlue;
  }
}

// ============================================================
//  MODELO CONFIGURACIÓN GLOBAL DEL SISTEMA
// ============================================================
// ============================================================
//  ENCABEZADO DE SEDE — datos que aparecen en la factura PDF
// ============================================================
class EncabezadoSede {
  String nombreSede;      // nombre del punto de venta (ej. "Tecno Líder Principal")
  String rif;             // RIF de la empresa (ej. "J-12345678-9")
  String direccion;       // dirección física de la sede
  String telefono;        // teléfono de contacto
  String correo;          // correo de la sede (opcional)
  Uint8List? logoBytes;   // bytes de la imagen del logo (PNG/JPG)

  EncabezadoSede({
    required this.nombreSede,
    this.rif = '',
    this.direccion = '',
    this.telefono = '',
    this.correo = '',
    this.logoBytes,
  });

  /// Copia con valores actualizados
  /// Usa [clearLogo] = true para quitar el logo explícitamente.
  EncabezadoSede copyWith({
    String? nombreSede,
    String? rif,
    String? direccion,
    String? telefono,
    String? correo,
    Uint8List? logoBytes,
    bool clearLogo = false,
  }) => EncabezadoSede(
    nombreSede: nombreSede ?? this.nombreSede,
    rif: rif ?? this.rif,
    direccion: direccion ?? this.direccion,
    telefono: telefono ?? this.telefono,
    correo: correo ?? this.correo,
    logoBytes: clearLogo ? null : (logoBytes ?? this.logoBytes),
  );

  bool get tieneInformacion =>
      rif.isNotEmpty || direccion.isNotEmpty || telefono.isNotEmpty;
}

class ConfigSistema {
  // Vacío por defecto: si el usuario no configura un nombre de empresa,
  // las impresiones NO mostrarán "Tecno Líder App". Los layouts PDF detectan
  // cadena vacía y omiten la línea completamente.
  static String nombreEmpresa = "";
  static String moneda = "\$";
  static double tasaCambio = 40.0;
  static bool permitirVentaSinStock = false;
  static bool requiereAprobacionDescuento = true;
  static double maxDescuentoPorcentaje = 10.0;
  static bool mostrarCostoEnFactura = false;
  static List<String> tiendas = ["Tecno Líder Principal", "Tecno Líder Sucursal"];
  static List<String> metodossPago = ["Punto de venta","Zelle","Divisas","Pago Móvil","Efectivo Bs","Efectivo \$","Transferencia","Cashea"];
  static List<String> ubicacionesAlmacen = ["Almacen","Tienda 1","Tienda 2"];
  static String textoFacturaPie = "Gracias por su compra. No se aceptan devoluciones sin factura.";
  static int diasGarantia = 30;

  // ── Sistema de comisiones (DINÁMICO) ─────────────────────
  // La lista `categoriasComision` es la fuente de verdad. El admin
  // puede agregar/editar/eliminar categorías desde el panel.
  // Las 6 originales (accesorio, teléfono, línea, televisor, línea
  // blanca, financiador) están protegidas y no se pueden eliminar.
  // Los getters de abajo (comisionAccesorio, etc.) son por
  // retrocompatibilidad — leen de la lista dinámica.
  static List<CategoriaComision> categoriasComision =
      CategoriaComision.defaults();

  /// Helper: devuelve la categoría con el ID dado, o null si no existe.
  static CategoriaComision? categoriaComisionPorId(String id) {
    try {
      return categoriasComision.firstWhere((c) => c.id == id);
    } catch (_) {
      return null;
    }
  }

  // ── Getters de retrocompatibilidad ───────────────────────
  // Permiten que el código antiguo que aún use estos nombres siga
  // funcionando. Leen del sistema dinámico de categorías.
  static double get comisionAccesorio   => categoriaComisionPorId('accesorio')?.tarifaUSD   ?? 0.50;
  static double get comisionTelefono    => categoriaComisionPorId('telefono')?.tarifaUSD    ?? 1.00;
  static double get comisionLinea       => categoriaComisionPorId('linea')?.tarifaUSD       ?? 0.50;
  static double get comisionTelevisor   => categoriaComisionPorId('televisor')?.tarifaUSD   ?? 2.00;
  static double get comisionFinanciador => categoriaComisionPorId('financiador')?.tarifaUSD ?? 1.00;
  static double get comisionLineaBlanca => categoriaComisionPorId('linea_blanca')?.tarifaUSD ?? 1.00;

  static double comisionBaseDefault = 40.00; // sueldo base semanal por defecto

  // ── Configuración SMTP para envío de correos ─────────────
  // Usado por el módulo "Contrato Weppa" (y cualquier otro que
  // necesite enviar correos con adjuntos). Se edita desde el
  // Panel de Configuración → Correos SMTP.
  static String smtpHost      = "smtp.gmail.com";
  static int    smtpPort      = 587;       // 587 TLS, 465 SSL
  static bool   smtpSsl       = false;     // true si usas 465
  static String smtpUsername  = "";        // ej: ventas@weppa.io
  static String smtpPassword  = "";        // contraseña de aplicación
  static String smtpNombreRemitente = "WEPPA GROUP INVESTMENTS";
  static String smtpCorreoRemitente = "";  // si queda vacío, usa smtpUsername

  // ── Encabezados por sede ─────────────────────────────────
  /// Mapa: nombreTienda → EncabezadoSede
  static Map<String, EncabezadoSede> encabezadosSede = {};

  /// Obtiene el encabezado de una sede. Si no existe, crea uno vacío.
  static EncabezadoSede encabezadoDe(String nombreSede) {
    return encabezadosSede.putIfAbsent(
      nombreSede,
      () => EncabezadoSede(nombreSede: nombreSede),
    );
  }

  /// Guarda o actualiza el encabezado de una sede.
  static void guardarEncabezado(EncabezadoSede encabezado) {
    encabezadosSede[encabezado.nombreSede] = encabezado;
  }

  // ── Persistencia de categorías de comisión ──────────────
  // Guardamos el JSON completo de la lista en SharedPreferences
  // bajo la clave 'categorias_comision'. El admin puede modificar,
  // agregar y eliminar categorías; el cambio sobrevive reinicios.

  /// Carga las categorías de comisión desde SharedPreferences.
  /// Si no hay nada guardado o el JSON es inválido, restaura las 6
  /// categorías por defecto. Las categorías protegidas (los IDs de
  /// las 6 originales) siempre quedan presentes — si alguien borró
  /// el archivo o el JSON está corrupto, se reinyectan.
  static Future<void> cargarCategoriasComision() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final raw = prefs.getString('categorias_comision');
      if (raw == null || raw.trim().isEmpty) {
        categoriasComision = CategoriaComision.defaults();
        return;
      }
      final lista = (jsonDecode(raw) as List)
          .map((m) => CategoriaComision.fromMap(Map<String, dynamic>.from(m)))
          .toList();
      // Garantizar que las 6 protegidas existan siempre. Si falta
      // alguna (por ejemplo, datos viejos pre-refactor), la añadimos.
      final defaults = CategoriaComision.defaults();
      for (final def in defaults) {
        if (!lista.any((c) => c.id == def.id)) lista.add(def);
      }
      categoriasComision = lista;
    } catch (e) {
      debugPrint('[ConfigSistema] cargarCategoriasComision error: $e');
      categoriasComision = CategoriaComision.defaults();
    }
  }

  /// Persiste la lista actual de categorías de comisión.
  static Future<void> guardarCategoriasComision() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final raw = jsonEncode(
          categoriasComision.map((c) => c.toMap()).toList());
      await prefs.setString('categorias_comision', raw);
    } catch (e) {
      debugPrint('[ConfigSistema] guardarCategoriasComision error: $e');
    }
  }

  /// Restaura las 6 categorías por defecto, descartando las
  /// personalizadas que el admin haya agregado. Llamado desde el
  /// botón "Restaurar valores originales" del panel.
  static Future<void> restaurarCategoriasComisionPorDefecto() async {
    categoriasComision = CategoriaComision.defaults();
    await guardarCategoriasComision();
  }
}

// ============================================================
//  SERVICIO DE CORREO SMTP
//  Envía correos con adjuntos usando la configuración SMTP de
//  ConfigSistema. Soporta Gmail, Outlook, Yahoo, y cualquier
//  servidor SMTP estándar.
//
//  Para Gmail: activa verificación en 2 pasos y genera una
//  contraseña de aplicación en https://myaccount.google.com/apppasswords
// ============================================================
class ServicioCorreo {
  /// Resultado del envío con detalles para depuración.
  static Future<ResultadoEnvioCorreo> enviar({
    required String destinatario,
    required String asunto,
    required String cuerpo,
    List<AdjuntoCorreo> adjuntos = const [],
    List<String> copia = const [],
    List<String> copiaOculta = const [],
    String? htmlCuerpo,
  }) async {
    // Validar configuración
    if (ConfigSistema.smtpUsername.isEmpty ||
        ConfigSistema.smtpPassword.isEmpty) {
      return ResultadoEnvioCorreo(
        exitoso: false,
        mensaje:
            'SMTP no configurado. Configure usuario y contraseña en el Panel de Configuración → Correos SMTP.',
      );
    }

    try {
      // Construir servidor SMTP
      final servidor = smtp.SmtpServer(
        ConfigSistema.smtpHost,
        port: ConfigSistema.smtpPort,
        ssl: ConfigSistema.smtpSsl,
        username: ConfigSistema.smtpUsername,
        password: ConfigSistema.smtpPassword,
        allowInsecure: false,
      );

      final remitente = ConfigSistema.smtpCorreoRemitente.isNotEmpty
          ? ConfigSistema.smtpCorreoRemitente
          : ConfigSistema.smtpUsername;

      final mensaje = mailer.Message()
        ..from = mailer.Address(remitente, ConfigSistema.smtpNombreRemitente)
        ..recipients.add(destinatario)
        ..ccRecipients.addAll(copia)
        ..bccRecipients.addAll(copiaOculta)
        ..subject = asunto
        ..text = cuerpo;

      if (htmlCuerpo != null && htmlCuerpo.isNotEmpty) {
        mensaje.html = htmlCuerpo;
      }

      // Adjuntos
      for (final adj in adjuntos) {
        mensaje.attachments.add(mailer.StreamAttachment(
          Stream.value(adj.bytes),
          adj.mimeType,
          fileName: adj.nombreArchivo,
        ));
      }

      final resultado = await mailer.send(mensaje, servidor);
      debugPrint('[SMTP] Correo enviado: ${resultado.toString()}');
      return ResultadoEnvioCorreo(
        exitoso: true,
        mensaje: 'Correo enviado correctamente a $destinatario',
      );
    } on mailer.MailerException catch (e) {
      final errores = e.problems.map((p) => p.msg).join('; ');
      debugPrint('[SMTP] Error del servidor: $errores');
      return ResultadoEnvioCorreo(
        exitoso: false,
        mensaje: 'Error al enviar: $errores',
      );
    } catch (e) {
      debugPrint('[SMTP] Error inesperado: $e');
      return ResultadoEnvioCorreo(
        exitoso: false,
        mensaje: 'Error inesperado: $e',
      );
    }
  }

  /// Prueba rápida de conexión SMTP enviándose un correo a sí mismo.
  static Future<ResultadoEnvioCorreo> probarConexion() async {
    final correo = ConfigSistema.smtpCorreoRemitente.isNotEmpty
        ? ConfigSistema.smtpCorreoRemitente
        : ConfigSistema.smtpUsername;
    if (correo.isEmpty) {
      return ResultadoEnvioCorreo(
        exitoso: false,
        mensaje: 'Configure primero los datos SMTP.',
      );
    }
    return enviar(
      destinatario: correo,
      asunto: '✅ Prueba de conexión SMTP - Weppa App',
      cuerpo:
          'Si recibe este correo, la configuración SMTP está funcionando correctamente.\n\n'
          'Servidor: ${ConfigSistema.smtpHost}:${ConfigSistema.smtpPort}\n'
          'SSL: ${ConfigSistema.smtpSsl ? "Sí" : "No (STARTTLS)"}',
    );
  }
}

class ResultadoEnvioCorreo {
  final bool exitoso;
  final String mensaje;
  ResultadoEnvioCorreo({required this.exitoso, required this.mensaje});
}

class AdjuntoCorreo {
  final Uint8List bytes;
  final String nombreArchivo;
  final String mimeType;
  AdjuntoCorreo({
    required this.bytes,
    required this.nombreArchivo,
    this.mimeType = 'application/pdf',
  });
}

// ============================================================
//  PANEL ADMINISTRATIVO
// ============================================================
class VentanaPanelAdmin extends StatefulWidget {
  const VentanaPanelAdmin({super.key});
  @override State<VentanaPanelAdmin> createState() => _VentanaPanelAdminState();
}

class _VentanaPanelAdminState extends State<VentanaPanelAdmin>
    with SingleTickerProviderStateMixin {
  late TabController _tabs;

  double _totalVentasMes = 0, _totalCostoInventario = 0, _totalVentaInventario = 0;
  double _totalCxCobrar = 0, _totalCxPagar = 0, _totalComisionesMes = 0;
  int _totalProductos = 0, _totalImeis = 0, _totalImeisVendidos = 0;
  int _totalLineas = 0, _totalLineasActivadas = 0, _totalServicios = 0;
  List<Map<String,dynamic>> _topVendedores = [];
  List<Map<String,dynamic>> _ventasRecientes = [];
  List<Map<String,dynamic>> _financiadoras = [];
  bool _cargando = true;
  String? _error;

  @override
  void initState() {
    super.initState();
    _tabs = TabController(length: 7, vsync: this);
    TasaBCVScheduler.addListener(_onTasaActualizada);
    _cargar();
  }

  void _onTasaActualizada() { if (mounted) setState(() {}); }

  @override
  void dispose() {
    _tabs.dispose();
    TasaBCVScheduler.removeListener(_onTasaActualizada);
    super.dispose();
  }

  Future<void> _cargar() async {
    setState(() { _cargando = true; _error = null; });
    try {
      final now = DateTime.now();

      // ── Cargar TODOS los recursos en paralelo ──────────────
      final results = await Future.wait([
        _Api.get('facturas').catchError((e) { debugPrint('facturas: $e'); return null; }),       // 0
        _Api.get('productos').catchError((e) { debugPrint('productos: $e'); return null; }),      // 1
        _Api.get('stock_imei').catchError((e) { debugPrint('stock_imei: $e'); return null; }),    // 2
        _Api.get('cuentas_cobrar').catchError((e) { debugPrint('cxc: $e'); return null; }),       // 3
        _Api.get('cuentas_pagar').catchError((e) { debugPrint('cxp: $e'); return null; }),        // 4
        _Api.get('lineas').catchError((e) { debugPrint('lineas: $e'); return null; }),             // 5
        _Api.get('servicios').catchError((e) { debugPrint('servicios: $e'); return null; }),      // 6
        _Api.get('comisiones_historial').catchError((e) { debugPrint('comisiones: $e'); return null; }),    // 7
      ]);

      final rawFacturas = ((results[0] as List?) ?? []);
      final rawProds    = ((results[1] as List?) ?? []);
      final rawImeis    = ((results[2] as List?) ?? []);
      final rawCxC      = ((results[3] as List?) ?? []);
      final rawCxP      = ((results[4] as List?) ?? []);
      final rawLineas   = ((results[5] as List?) ?? []);
      final rawServ     = ((results[6] as List?) ?? []);
      final rawComis    = ((results[7] as List?) ?? []);

      // ── Ventas ────────────────────────────────────────────
      _totalVentasMes = 0;
      final Map<String,double> porVendedor = {};
      final Map<String,int>    cantPorVendedor = {};
      for (var f in rawFacturas) {
        final total = double.tryParse(f['total'].toString()) ?? 0;
        try {
          final fecha = parseFecha(f['fecha'] ?? '');
          if (fecha.month == now.month && fecha.year == now.year) _totalVentasMes += total;
        } catch (_) {}
        final vend = f['vendedor']?.toString() ?? 'Sin vendedor';
        porVendedor[vend] = (porVendedor[vend] ?? 0) + total;
        cantPorVendedor[vend] = (cantPorVendedor[vend] ?? 0) + 1;
      }
      final entries = porVendedor.entries.toList()..sort((a,b) => b.value.compareTo(a.value));
      _topVendedores = entries.take(5).map((e) {
        final u = usuariosSistema.where((u) => u.nombre == e.key).firstOrNull;
        return {'nombre': e.key, 'total': e.value,
          'cantidad': cantPorVendedor[e.key] ?? 0,
          'sueldo_base': u?.sueldoBase ?? 0.0, 'rol': u?.rol ?? ''};
      }).toList();
      _ventasRecientes = rawFacturas.reversed.take(10).map((f) => Map<String,dynamic>.from(f)).toList();

      // ── Inventario ────────────────────────────────────────
      _totalProductos = rawProds.length;
      _totalImeis = rawImeis.length;
      _totalImeisVendidos = rawImeis.where((i) => (i['vendido'] ?? 0) == 1).length;
      _totalCostoInventario = 0; _totalVentaInventario = 0;
      for (var p in rawProds) {
        final costo = double.tryParse(p['precio_costo'].toString()) ?? 0;
        final venta = double.tryParse(p['precio_venta'].toString()) ?? 0;
        final stockReal = p['categoria'] == 'Telefono'
            ? rawImeis.where((i) => i['producto_codigo'] == p['codigo'] && (i['vendido']??0)==0).length
            : (int.tryParse(p['stock_manual'].toString()) ?? 0);
        _totalCostoInventario += costo * stockReal;
        _totalVentaInventario += venta * stockReal;
      }

      // ── Cuentas por cobrar ────────────────────────────────
      _totalCxCobrar = rawCxC.fold(0.0, (s, c) {
        final total = double.tryParse(c['monto_total'].toString()) ?? 0;
        final pagos = (c['pagos'] as List? ?? []).fold(0.0, (sp, p) => sp + (double.tryParse(p['monto'].toString()) ?? 0));
        return s + (total - pagos).clamp(0, double.infinity);
      });

      // ── Cuentas por pagar ─────────────────────────────────
      _totalCxPagar = rawCxP.fold(0.0, (s, c) {
        final total = double.tryParse(c['monto_total'].toString()) ?? 0;
        final pagos = (c['pagos'] as List? ?? []).fold(0.0, (sp, p) => sp + (double.tryParse(p['monto'].toString()) ?? 0));
        return s + (total - pagos).clamp(0, double.infinity);
      });

      // ── Líneas ────────────────────────────────────────────
      _totalLineas = rawLineas.length;
      _totalLineasActivadas = rawLineas.where((l) => (l['activada']??0)==1).length;

      // ── Servicios ─────────────────────────────────────────
      _totalServicios = rawServ.length;

      // ── Comisiones del mes ────────────────────────────────
      _totalComisionesMes = 0;
      for (var h in rawComis) {
        try {
          // Usar tryParse para evitar crash en fecha_inicio vacía
          final fi = DateTime.tryParse(h['fecha_inicio']?.toString() ?? '') ?? DateTime(2000);
          if (fi.month == now.month && fi.year == now.year) {
            final tasa = double.tryParse(h['tasa'].toString()) ?? 1;
            for (var d in ((h['detalle'] as List?) ?? [])) {
              final r = ResumenComision.fromMap(d);
              _totalComisionesMes += r.totalPagar() * tasa;
            }
          }
        } catch (_) {}
      }

      // ── Financiadoras ─────────────────────────────────────
      _financiadoras = listasPreciosGlobal
          .where((l) => l.esFinanciamiento && l.financiadora != null)
          .fold(<Map<String,dynamic>>[], (acc, l) {
            if (!acc.any((f) => f['nombre'] == l.financiadora)) {
              acc.add({'nombre': l.financiadora!, 'lista': l.nombre,
                'pct_adicional': l.porcentajeAdicional,
                'pct_inicial': l.porcentajeInicial, 'cuotas': l.numeroCuotas});
            }
            return acc;
          });

      if (mounted) setState(() => _cargando = false);
    } catch (e) {
      debugPrint('PanelAdmin error: $e');
      if (mounted) setState(() { _cargando = false; _error = e.toString(); });
    }
  }


  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: AppColors.surfaceTintBlue,
      appBar: AppBar(
        title: const Text("Panel Administrativo"),
        backgroundColor: AppColors.royalBlue,
        foregroundColor: Colors.white,
        actions: [
          const TasaBCVBadge(),
          const SizedBox(width: 4),
          IconButton(icon: const Icon(Icons.refresh), onPressed: _cargar),
        ],
        bottom: TabBar(
          controller: _tabs,
          labelColor: Colors.white,
          unselectedLabelColor: Colors.white60,
          indicatorColor: AppColors.primaryBlue,
          isScrollable: true,
          tabs: const [
            Tab(icon: Icon(Icons.dashboard), text: "Resumen"),
            Tab(icon: Icon(Icons.trending_up), text: "Ventas"),
            Tab(icon: Icon(Icons.inventory_2), text: "Inventario"),
            Tab(icon: Icon(Icons.people_alt), text: "Equipo"),
            Tab(icon: Icon(Icons.account_balance_outlined), text: "Financ."),
            Tab(icon: Icon(Icons.calculate_outlined), text: "Costos"),
            Tab(icon: Icon(Icons.work_history_outlined), text: "Prestaciones"),
          ],
        ),
      ),
      body: _cargando
          ? const Center(child: Column(mainAxisAlignment: MainAxisAlignment.center, children: [
              CircularProgressIndicator(),
              SizedBox(height: 16),
              Text("Cargando datos administrativos..."),
            ]))
          : _error != null
              ? Center(child: Column(mainAxisAlignment: MainAxisAlignment.center, children: [
                  const Icon(Icons.error_outline, size: 60, color: Colors.red),
                  const SizedBox(height: 12),
                  const Text("Error al cargar datos", style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold)),
                  const SizedBox(height: 8),
                  Padding(
                    padding: const EdgeInsets.symmetric(horizontal: 32),
                    child: Text(_error!, textAlign: TextAlign.center, style: const TextStyle(color: Colors.grey))),
                  const SizedBox(height: 20),
                  ElevatedButton.icon(icon: const Icon(Icons.refresh), label: const Text("Reintentar"), onPressed: _cargar),
                ]))
              : TabBarView(controller: _tabs, children: [
                  _tabResumen(),
                  _tabVentas(),
                  _tabInventario(),
                  _tabEquipo(),
                  _tabFinanciadoras(),
                  const VentanaCostosFinanzas(),
                  const VentanaPrestacionesSociales(),
                ]),
    );
  }

