  Widget _barraBalance(String label, double valor, Color color, {double? maxValor}) {
    final max = maxValor ?? (_totalCxCobrar + _totalCxPagar);
    final pct = max == 0 ? 0.0 : (valor / max).clamp(0.0, 1.0);
    return Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
      Row(mainAxisAlignment: MainAxisAlignment.spaceBetween, children: [
        Text(label, style: const TextStyle(fontSize: 13)),
        Text(formatCurrency(valor), style: TextStyle(fontWeight: FontWeight.bold, color: color)),
      ]),
      const SizedBox(height: 4),
      ClipRRect(
        borderRadius: BorderRadius.circular(4),
        child: LinearProgressIndicator(value: pct, minHeight: 10,
          backgroundColor: Colors.grey[200],
          valueColor: AlwaysStoppedAnimation(color))),
    ]);
  }

  Widget _accionCard(IconData icon, String label, Color color, VoidCallback onTap) {
    return InkWell(onTap: onTap, child: Container(
      width: 140, padding: const EdgeInsets.symmetric(vertical: 14, horizontal: 12),
      decoration: BoxDecoration(color: color.withValues(alpha: 0.1), borderRadius: BorderRadius.circular(10), border: Border.all(color: color.withValues(alpha: 0.3))),
      child: Row(children: [
