// ============================================================
//  VENTANA CONECTAR IMPRESORA (accesible para TODOS los roles)
//  Versión reducida que sólo muestra la sección de impresora,
//  sin tabs ni el resto de la configuración del sistema.
// ============================================================
class VentanaConectarImpresora extends StatefulWidget {
  const VentanaConectarImpresora({super.key});
  @override
  State<VentanaConectarImpresora> createState() => _VentanaConectarImpresoraState();
}

class _VentanaConectarImpresoraState extends State<VentanaConectarImpresora> {
  /// Diálogo para elegir una impresora del sistema operativo (USB, red,
  /// AirPrint, etc.) y guardarla como preferida. Funciona en Windows,
  /// macOS, Linux, Android e iOS.
  Future<void> _seleccionarImpresoraSistema() async {
    // Mostrar progreso mientras se escanea
    showDialog(
      context: context,
      barrierDismissible: false,
      builder: (_) => const AlertDialog(
        content: Row(children: [
          CircularProgressIndicator(),
          SizedBox(width: 16),
          Expanded(child: Text("Buscando impresoras del sistema...")),
        ]),
      ),
    );
    List<Printer> printers = [];
    try {
      printers = await ImpresoraSistema.listarImpresoras();
    } catch (e) {
      debugPrint('[Impresora sistema] error: $e');
    }
    if (!mounted) return;
    Navigator.pop(context); // cerrar el progreso

    if (printers.isEmpty) {
      if (!mounted) return;
      showDialog(
        context: context,
        builder: (_) => AlertDialog(
          shape: RoundedRectangleBorder(
              borderRadius: BorderRadius.circular(14)),
          icon: const Icon(Icons.print_disabled,
              color: AppColors.statusOrange, size: 40),
          title: const Text("Sin impresoras"),
          content: const Text(
            "No se detectaron impresoras del sistema.\n\n"
            "Verifique que:\n"
            "• La impresora esté encendida y conectada\n"
            "• En PC: que esté instalada en el panel de control\n"
            "• En móvil: que esté en la misma red WiFi\n"
            "• Si es USB en PC, que el cable esté firme",
            style: TextStyle(fontSize: 13)),
          actions: [
            TextButton(
              onPressed: () => Navigator.pop(context),
              child: const Text("Entendido")),
          ],
        ),
      );
      return;
    }

    // Mostrar lista de impresoras
    final elegida = await showDialog<Printer>(
      context: context,
      builder: (c) => AlertDialog(
        shape: RoundedRectangleBorder(
            borderRadius: BorderRadius.circular(14)),
        title: const Row(children: [
          Icon(Icons.print, color: AppColors.royalBlue),
          SizedBox(width: 8),
          Text("Seleccionar impresora"),
        ]),
        content: SizedBox(
          width: double.maxFinite,
          child: ListView.builder(
            shrinkWrap: true,
            itemCount: printers.length,
            itemBuilder: (_, i) {
              final p = printers[i];
              final esPreferida =
                  p.url == ImpresoraSistema.urlImpresoraPreferida;
              return Card(
                elevation: 0,
                shape: RoundedRectangleBorder(
                  borderRadius: BorderRadius.circular(8),
                  side: BorderSide(color: esPreferida
                      ? AppColors.statusGreen
                      : Colors.grey.shade300, width: esPreferida ? 2 : 1)),
                child: ListTile(
                  leading: Icon(
                    p.isDefault ? Icons.star : Icons.print,
                    color: esPreferida
                        ? AppColors.statusGreen
                        : AppColors.royalBlue),
                  title: Text(p.name,
                      style: const TextStyle(fontSize: 13.5,
                          fontWeight: FontWeight.w600)),
                  subtitle: Text(p.url,
                      maxLines: 1, overflow: TextOverflow.ellipsis,
                      style: const TextStyle(
                          fontSize: 11, fontFamily: 'monospace')),
                  trailing: esPreferida
                      ? const Icon(Icons.check_circle,
                          color: AppColors.statusGreen)
                      : null,
                  onTap: () => Navigator.pop(c, p),
                ),
              );
            },
          ),
        ),
        actions: [
          TextButton(
              onPressed: () => Navigator.pop(c),
              child: const Text("Cancelar")),
        ],
      ),
    );

    if (elegida != null) {
      await ImpresoraSistema.guardarPreferida(elegida);
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(SnackBar(
          content: Text("✓ Impresora configurada: ${elegida.name}"),
          backgroundColor: AppColors.statusGreen,
          duration: const Duration(seconds: 2)));
      }
    }
  }

  Widget _seccion(String titulo, IconData icon, List<Widget> hijos) {
    return Card(
      elevation: 0,
      shape: RoundedRectangleBorder(
        borderRadius: BorderRadius.circular(12),
        side: BorderSide(color: Colors.grey.shade300)),
      child: Padding(
        padding: const EdgeInsets.all(16),
        child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
          Row(children: [
            Icon(icon, size: 20, color: AppColors.royalBlue),
            const SizedBox(width: 8),
            Text(titulo, style: const TextStyle(
              fontSize: 15, fontWeight: FontWeight.bold)),
          ]),
          const SizedBox(height: 14),
          ...hijos,
        ]),
      ),
    );
  }

  Widget _pasoGuia(String numero, String texto) => Padding(
    padding: const EdgeInsets.symmetric(vertical: 5),
    child: Row(crossAxisAlignment: CrossAxisAlignment.start, children: [
      Container(
        width: 24, height: 24,
