          ),
          const SizedBox(height: 16),

          // ── Estado de la impresora configurada ──
          _seccion("Impresora configurada", Icons.print_outlined, [
            if (ImpresoraBT.macImpresoraPreferida != null) ...[
              Container(
                padding: const EdgeInsets.all(12),
                decoration: BoxDecoration(
                  color: AppColors.statusGreen.withValues(alpha: 0.08),
