  }
}

// ============================================================
//  SISTEMA DE CONFIGURACIÓN (solo Administrador / Dueño)
// ============================================================
class VentanaConfiguracion extends StatefulWidget {
  const VentanaConfiguracion({super.key});
  @override State<VentanaConfiguracion> createState() => _VentanaConfiguracionState();
}

class _VentanaConfiguracionState extends State<VentanaConfiguracion>
    with SingleTickerProviderStateMixin {
  late TabController _tabs;

  // Controladores para los campos editables
  late TextEditingController _ctrlNombreEmpresa;
  late TextEditingController _ctrlMoneda;
  late TextEditingController _ctrlTasa;
  late TextEditingController _ctrlMaxDescuento;
  late TextEditingController _ctrlPiePagina;
  late TextEditingController _ctrlGarantia;
  late TextEditingController _ctrlIpServidor;
  late TextEditingController _ctrlNuevaTienda;
  late TextEditingController _ctrlNuevoMetodo;
  late TextEditingController _ctrlNuevaUbicacion;

  // ── Controllers del tab de COMISIONES ────────────────────
  // Solo queda el sueldo base — las tarifas individuales se editan
  // ahora en una lista dinámica de categorías (CategoriaComision).
  late TextEditingController _ctrlComBase;

  bool _cambiosPendientes = false;

  @override
  void initState() {
    super.initState();
    _tabs = TabController(length: 7, vsync: this);
    _ctrlNombreEmpresa = TextEditingController(text: ConfigSistema.nombreEmpresa);
    _ctrlMoneda = TextEditingController(text: ConfigSistema.moneda);
    _ctrlTasa = TextEditingController(text: ConfigSistema.tasaCambio.toStringAsFixed(2));
    _ctrlMaxDescuento = TextEditingController(text: ConfigSistema.maxDescuentoPorcentaje.toString());
    _ctrlPiePagina = TextEditingController(text: ConfigSistema.textoFacturaPie);
    _ctrlGarantia = TextEditingController(text: ConfigSistema.diasGarantia.toString());
    _ctrlIpServidor = TextEditingController(text: _ipFisica);
    _ctrlNuevaTienda = TextEditingController();
    _ctrlNuevoMetodo = TextEditingController();
    _ctrlNuevaUbicacion = TextEditingController();
    // Comisiones (solo el sueldo base — las tarifas son dinámicas)
    _ctrlComBase = TextEditingController(
        text: ConfigSistema.comisionBaseDefault.toStringAsFixed(2));
    // Escuchar cambios automáticos de la tasa BCV
    TasaBCVScheduler.addListener(_onTasaBCVActualizada);
  }

  void _onTasaBCVActualizada() {
    if (!mounted) return;
    setState(() {
      // Sincronizar el campo manual con la nueva tasa BCV
      _ctrlTasa.text = ConfigSistema.tasaCambio.toStringAsFixed(2);
    });
  }

  @override
  void dispose() {
    _tabs.dispose();
    TasaBCVScheduler.removeListener(_onTasaBCVActualizada);
    _ctrlNombreEmpresa.dispose(); _ctrlMoneda.dispose();
    _ctrlTasa.dispose(); _ctrlMaxDescuento.dispose();
    _ctrlPiePagina.dispose(); _ctrlGarantia.dispose();
    _ctrlIpServidor.dispose(); _ctrlNuevaTienda.dispose();
    _ctrlNuevoMetodo.dispose(); _ctrlNuevaUbicacion.dispose();
    _ctrlComBase.dispose();
    super.dispose();
  }

  void _marcarCambio() => setState(() => _cambiosPendientes = true);

  void _guardarTodo() {
    // Aplicar cambios al objeto estático global.
    // Si el usuario deja el nombre vacío, lo dejamos vacío (las impresiones
    // omiten esa línea). Antes se forzaba "Tecno Líder App" como fallback, lo
    // que hacía que el texto volviera a aparecer aunque el usuario lo borrara.
    ConfigSistema.nombreEmpresa = _ctrlNombreEmpresa.text.trim();
    ConfigSistema.moneda = _ctrlMoneda.text.trim().isEmpty ? "\$" : _ctrlMoneda.text.trim();
    ConfigSistema.tasaCambio = double.tryParse(_ctrlTasa.text) ?? ConfigSistema.tasaCambio;
    ConfigSistema.maxDescuentoPorcentaje = double.tryParse(_ctrlMaxDescuento.text) ?? ConfigSistema.maxDescuentoPorcentaje;
    ConfigSistema.textoFacturaPie = _ctrlPiePagina.text;
    ConfigSistema.diasGarantia = int.tryParse(_ctrlGarantia.text) ?? ConfigSistema.diasGarantia;
    // ── Comisiones ──
    // Sueldo base por defecto (las tarifas individuales viven ahora en
    // ConfigSistema.categoriasComision — se persisten al editar cada
    // categoría desde su propio diálogo).
    ConfigSistema.comisionBaseDefault =
        double.tryParse(_ctrlComBase.text) ?? ConfigSistema.comisionBaseDefault;
    // Persistir las categorías al disco (por si se editaron tarifas
    // sin pasar por el diálogo de edición individual).
    ConfigSistema.guardarCategoriasComision();
    setState(() => _cambiosPendientes = false);
    ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
      content: Row(children: [
        Icon(Icons.check_circle, color: Colors.white),
        SizedBox(width: 8),
        Text("Configuración guardada exitosamente"),
      ]),
      backgroundColor: AppColors.statusGreen,
    ));
  }

  void _confirmarReset() {
    showDialog(context: context, builder: (ctx) => AlertDialog(
      title: const Row(children: [
        Icon(Icons.warning_amber_rounded, color: Colors.orange),
        SizedBox(width: 8),
        Text("Restablecer valores"),
      ]),
      content: const Text("¿Está seguro que desea restablecer toda la configuración a los valores por defecto? Esta acción no se puede deshacer."),
      actions: [
        TextButton(onPressed: () => Navigator.pop(ctx), child: const Text("Cancelar")),
        ElevatedButton(
          style: ElevatedButton.styleFrom(backgroundColor: AppColors.statusRed),
          onPressed: () {
            ConfigSistema.nombreEmpresa = "";
            ConfigSistema.moneda = "\$";
            ConfigSistema.tasaCambio = 40.0;
            ConfigSistema.permitirVentaSinStock = false;
            ConfigSistema.requiereAprobacionDescuento = true;
            ConfigSistema.maxDescuentoPorcentaje = 10.0;
            ConfigSistema.mostrarCostoEnFactura = false;
            ConfigSistema.textoFacturaPie = "Gracias por su compra. No se aceptan devoluciones sin factura.";
            ConfigSistema.diasGarantia = 30;
            ConfigSistema.tiendas = ["Tecno Líder Principal", "Tecno Líder Sucursal"];
            ConfigSistema.metodossPago = ["Punto de venta","Zelle","Divisas","Pago Móvil","Efectivo Bs","Efectivo \$","Transferencia"];
            ConfigSistema.ubicacionesAlmacen = ["Almacen","Tienda 1","Tienda 2"];
            ConfigSistema.encabezadosSede.clear(); // limpiar encabezados
            _ctrlNombreEmpresa.text = ConfigSistema.nombreEmpresa;
            _ctrlMoneda.text = ConfigSistema.moneda;
            _ctrlTasa.text = ConfigSistema.tasaCambio.toString();
            _ctrlMaxDescuento.text = ConfigSistema.maxDescuentoPorcentaje.toString();
            _ctrlPiePagina.text = ConfigSistema.textoFacturaPie;
            _ctrlGarantia.text = ConfigSistema.diasGarantia.toString();
            Navigator.pop(ctx);
            setState(() => _cambiosPendientes = false);
            ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content: Text("Configuración restablecida")));
          },
          child: const Text("Restablecer", style: TextStyle(color: Colors.white))),
      ],
    ));
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: AppColors.surfaceTintBlue,
      appBar: AppBar(
        title: const Text("Configuración del Sistema"),
        backgroundColor: AppColors.royalBlue,
        foregroundColor: Colors.white,
        actions: [
          if (_cambiosPendientes)
            Padding(
              padding: const EdgeInsets.only(right: 8),
              child: TextButton.icon(
                icon: const Icon(Icons.save, color: Colors.white),
                label: const Text("Guardar", style: TextStyle(color: Colors.white, fontWeight: FontWeight.bold)),
                onPressed: _guardarTodo,
              ),
            ),
          IconButton(icon: const Icon(Icons.restore), tooltip: "Restablecer", onPressed: _confirmarReset),
        ],
        bottom: TabBar(
          controller: _tabs,
          labelColor: Colors.white,
          unselectedLabelColor: Colors.white60,
          indicatorColor: AppColors.primaryBlue,
          isScrollable: true,
          tabs: const [
            Tab(icon: Icon(Icons.business), text: "Empresa"),
            Tab(icon: Icon(Icons.receipt_long), text: "Facturación"),
            Tab(icon: Icon(Icons.store), text: "Tiendas"),
            Tab(icon: Icon(Icons.account_balance_outlined), text: "Financiad."),
            Tab(icon: Icon(Icons.paid_outlined), text: "Comisiones"),
            Tab(icon: Icon(Icons.print_outlined), text: "Impresora"),
            Tab(icon: Icon(Icons.dns), text: "Sistema"),
          ],
        ),
      ),
      body: TabBarView(controller: _tabs, children: [
        _tabEmpresa(),
        _tabFacturacion(),
        _tabTiendas(),
        _tabFinanciadoras(),
        _tabComisiones(),
        _tabImpresora(),
        _tabSistema(),
      ]),
    );
  }

  // ── Sección empresa ──────────────────────────────────────
  Widget _tabEmpresa() {
    final tasa = TasaBCVScheduler.ultimaTasa;
    return SingleChildScrollView(
      padding: const EdgeInsets.all(20),
      child: Column(children: [
        _seccionCard("Información de la Empresa", Icons.business, [
          _campoTexto("Nombre de la Empresa", _ctrlNombreEmpresa, Icons.store),
          const SizedBox(height: 12),
          _campoTexto("Símbolo de Moneda", _ctrlMoneda, Icons.attach_money),
          const SizedBox(height: 12),
          _campoTexto("Días de Garantía por defecto", _ctrlGarantia, Icons.verified_user, tipo: TextInputType.number),
        ]),
        const SizedBox(height: 16),

        // ── Tarjeta de tasa BCV ────────────────────────────
        _seccionCard("Tasa de Cambio BCV", Icons.account_balance, [
          // Estado actual
          Container(
            padding: const EdgeInsets.all(14),
            decoration: BoxDecoration(
              gradient: const LinearGradient(
                colors: [AppColors.royalBlue, AppColors.primaryBlue],
                begin: Alignment.topLeft, end: Alignment.bottomRight),
              borderRadius: BorderRadius.circular(10)),
            child: Row(children: [
              const Icon(Icons.currency_exchange, color: Colors.white, size: 36),
              const SizedBox(width: 14),
              Expanded(child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                const Text("TASA OFICIAL BCV", style: TextStyle(color: Colors.white70, fontSize: 11, letterSpacing: 1)),
                Text(
                  "Bs ${ConfigSistema.tasaCambio.toStringAsFixed(2)}",
                  style: const TextStyle(color: Colors.white, fontSize: 28, fontWeight: FontWeight.bold)),
                if (tasa != null) ...[
                  Text("Fuente: ${tasa.fuente}", style: const TextStyle(color: Colors.white70, fontSize: 11)),
                  Text("Actualizado: ${tasa.fechaFormateada}", style: const TextStyle(color: Colors.white60, fontSize: 10)),
                ] else
                  const Text("Sin datos del BCV aún", style: TextStyle(color: Colors.white60, fontSize: 11)),
              ])),
              Column(children: [
                Container(
                  padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
                  decoration: BoxDecoration(
                    color: (tasa?.esDeHoy == true) ? Colors.green : Colors.orange,
                    borderRadius: BorderRadius.circular(12)),
                  child: Text(
                    (tasa?.esDeHoy == true) ? "✅ Al día" : "⚠️ Antigua",
                    style: const TextStyle(color: Colors.white, fontSize: 10, fontWeight: FontWeight.bold))),
              ]),
            ]),
          ),
          const SizedBox(height: 12),

          // Botón actualizar manual
          SizedBox(width: double.infinity, child: ElevatedButton.icon(
            icon: TasaBCVScheduler.actualizando
                ? const SizedBox(width: 16, height: 16, child: CircularProgressIndicator(strokeWidth: 2, color: Colors.white))
                : const Icon(Icons.refresh),
            label: Text(TasaBCVScheduler.actualizando ? "Consultando BCV..." : "Actualizar tasa del BCV ahora"),
            onPressed: TasaBCVScheduler.actualizando ? null : () async {
              final result = await TasaBCVScheduler.actualizarAhora();
              if (!mounted) return;
              setState(() {
                if (result != null) {
                  _ctrlTasa.text = result.valor.toStringAsFixed(2);
                }
              });
              ScaffoldMessenger.of(context).showSnackBar(SnackBar(
                content: Text(result != null
                    ? "✅ Tasa BCV actualizada: Bs ${result.valor.toStringAsFixed(2)} (${result.fuente})"
                    : "❌ No se pudo obtener la tasa. Verifique la conexión."),
                backgroundColor: result != null ? Colors.green : Colors.red,
              ));
            },
          )),
          const SizedBox(height: 8),

          // Info scheduler
          Container(
            padding: const EdgeInsets.all(10),
            decoration: BoxDecoration(color: AppColors.brandBlue.withValues(alpha: 0.08), borderRadius: BorderRadius.circular(8)),
            child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
              Row(children: [
                const Icon(Icons.schedule, size: 14, color: AppColors.primaryBlue),
                const SizedBox(width: 6),
                const Text("Actualización automática", style: TextStyle(fontWeight: FontWeight.bold, fontSize: 12, color: AppColors.primaryBlue)),
              ]),
              const SizedBox(height: 4),
              const Text("La tasa se actualiza automáticamente cada día a las 9:00 PM hora Venezuela (VET, UTC-4) desde el Banco Central de Venezuela.", style: TextStyle(fontSize: 11, color: Colors.grey)),
              const SizedBox(height: 4),
              Text("Próxima actualización en: ${TasaBCVScheduler.proximaActualizacion}", style: const TextStyle(fontSize: 11, fontWeight: FontWeight.w600, color: AppColors.royalBlue)),
            ]),
          ),
          const SizedBox(height: 12),

          // Tasa manual de respaldo
          const Divider(),
          const Text("Tasa manual de respaldo", style: TextStyle(fontWeight: FontWeight.bold, fontSize: 13)),
          const Text("Se usa solo si la actualización automática falla.", style: TextStyle(fontSize: 11, color: Colors.grey)),
          const SizedBox(height: 8),
          _campoTexto("Tasa manual (Bs/\$)", _ctrlTasa, Icons.edit_note, tipo: TextInputType.numberWithOptions(decimal: true)),
        ]),
        const SizedBox(height: 16),

        _seccionCard("Permisos de Ventas", Icons.security, [
          _switchConf(
            "Permitir venta sin stock",
            "Permite facturar productos aunque el inventario esté en 0",
            ConfigSistema.permitirVentaSinStock,
            (v) { setState(() => ConfigSistema.permitirVentaSinStock = v); _marcarCambio(); }),
          const Divider(),
          _switchConf(
            "Requerir aprobación para descuentos",
            "El administrador debe aprobar descuentos mayores al límite",
            ConfigSistema.requiereAprobacionDescuento,
            (v) { setState(() => ConfigSistema.requiereAprobacionDescuento = v); _marcarCambio(); }),
          const SizedBox(height: 8),
          _campoTexto("Descuento máximo permitido (%)", _ctrlMaxDescuento, Icons.discount, tipo: TextInputType.numberWithOptions(decimal: true)),
        ]),
      ]),
    );
  }

  // ── Sección facturación ──────────────────────────────────
  Widget _tabFacturacion() {
    return SingleChildScrollView(
      padding: const EdgeInsets.all(20),
      child: Column(children: [
        _seccionCard("Opciones de Factura", Icons.receipt_long, [
          _switchConf(
            "Mostrar costo en factura interna",
            "Muestra el precio de costo en el PDF (solo para uso interno)",
            ConfigSistema.mostrarCostoEnFactura,
            (v) { setState(() => ConfigSistema.mostrarCostoEnFactura = v); _marcarCambio(); }),
          const Divider(),
          const SizedBox(height: 8),
          _campoTexto("Texto al pie de la factura", _ctrlPiePagina, Icons.text_snippet, maxLines: 3),
        ]),
        const SizedBox(height: 16),
        _seccionCard("Métodos de Pago Disponibles", Icons.payment, [
          ..._listaEditable(
            items: ConfigSistema.metodossPago,
            controller: _ctrlNuevoMetodo,
            hintAgregar: "Nuevo método de pago...",
            onAgregar: () {
              final v = _ctrlNuevoMetodo.text.trim();
              if (v.isNotEmpty && !ConfigSistema.metodossPago.contains(v)) {
                setState(() { ConfigSistema.metodossPago.add(v); _ctrlNuevoMetodo.clear(); _cambiosPendientes = true; });
              }
            },
            onEliminar: (item) {
              if (ConfigSistema.metodossPago.length <= 1) return;
              setState(() { ConfigSistema.metodossPago.remove(item); _cambiosPendientes = true; });
            }),
        ]),
      ]),
    );
  }

  // ── Sección tiendas, ubicaciones y encabezados de factura ──
  Widget _tabTiendas() {
    return SingleChildScrollView(
      padding: const EdgeInsets.all(20),
      child: Column(children: [
        // ─── Puntos de Venta ────────────────────────────────
        _seccionCard("Puntos de Venta / Tiendas", Icons.store, [
          ..._listaEditable(
            items: ConfigSistema.tiendas,
            controller: _ctrlNuevaTienda,
            hintAgregar: "Nueva tienda...",
            onAgregar: () {
              final v = _ctrlNuevaTienda.text.trim();
              if (v.isNotEmpty && !ConfigSistema.tiendas.contains(v)) {
                setState(() {
                  ConfigSistema.tiendas.add(v);
                  _ctrlNuevaTienda.clear();
                  _cambiosPendientes = true;
                });
              }
            },
            onEliminar: (item) {
              if (ConfigSistema.tiendas.length <= 1) {
                ScaffoldMessenger.of(context).showSnackBar(
                  const SnackBar(content: Text("Debe existir al menos una tienda")));
                return;
              }
              setState(() { ConfigSistema.tiendas.remove(item); _cambiosPendientes = true; });
            }),
        ]),
        const SizedBox(height: 16),

        // ─── Encabezados de Factura por Sede ────────────────
        _seccionCard("Encabezados de Factura por Sede", Icons.receipt_long, [
          Container(
            padding: const EdgeInsets.all(10),
            margin: const EdgeInsets.only(bottom: 12),
            decoration: BoxDecoration(
              color: AppColors.primaryBlue.withValues(alpha: 0.06),
              borderRadius: BorderRadius.circular(8),
              border: Border.all(color: AppColors.primaryBlue.withValues(alpha: 0.2)),
            ),
            child: const Row(children: [
              Icon(Icons.info_outline, color: AppColors.primaryBlue, size: 16),
              SizedBox(width: 8),
              Expanded(child: Text(
                "Configura el logo, RIF, dirección y teléfono que aparecerán "
                "en el encabezado de las facturas de cada sede al imprimirlas.",
                style: TextStyle(fontSize: 12, color: AppColors.textSecondary))),
            ]),
          ),
          ...ConfigSistema.tiendas.map((tienda) => _cardEncabezadoSede(tienda)),
        ]),
        const SizedBox(height: 16),

        // ─── Ubicaciones de Almacén ─────────────────────────
        _seccionCard("Ubicaciones de Almacén", Icons.warehouse, [
          ..._listaEditable(
            items: ConfigSistema.ubicacionesAlmacen,
            controller: _ctrlNuevaUbicacion,
            hintAgregar: "Nueva ubicación...",
            onAgregar: () {
              final v = _ctrlNuevaUbicacion.text.trim();
              if (v.isNotEmpty && !ConfigSistema.ubicacionesAlmacen.contains(v)) {
                setState(() { ConfigSistema.ubicacionesAlmacen.add(v); _ctrlNuevaUbicacion.clear(); _cambiosPendientes = true; });
              }
            },
            onEliminar: (item) {
              if (ConfigSistema.ubicacionesAlmacen.length <= 1) return;
              setState(() { ConfigSistema.ubicacionesAlmacen.remove(item); _cambiosPendientes = true; });
            }),
        ]),
      ]),
    );
  }

  /// Tarjeta de encabezado de factura para una sede específica
  Widget _cardEncabezadoSede(String nombreSede) {
    final enc = ConfigSistema.encabezadoDe(nombreSede);
    final tieneInfo = enc.tieneInformacion;
    final tieneLogo = enc.logoBytes != null;

    return Card(
      margin: const EdgeInsets.only(bottom: 10),
      elevation: 1,
      shape: RoundedRectangleBorder(
        borderRadius: BorderRadius.circular(12),
        side: tieneInfo || tieneLogo
          ? const BorderSide(color: AppColors.statusGreen, width: 1)
          : BorderSide(color: Colors.grey[200]!),
      ),
      child: Padding(
        padding: const EdgeInsets.all(14),
        child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
          // Cabecera de la card
          Row(children: [
            Container(
              padding: const EdgeInsets.all(8),
              decoration: BoxDecoration(
                color: AppColors.royalBlue.withValues(alpha: 0.08),
                borderRadius: BorderRadius.circular(8),
              ),
              child: const Icon(Icons.store_outlined, color: AppColors.royalBlue, size: 20),
            ),
            const SizedBox(width: 10),
            Expanded(child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
              Text(nombreSede, style: const TextStyle(fontWeight: FontWeight.bold, fontSize: 14)),
              Text(
                tieneInfo || tieneLogo ? "Encabezado configurado" : "Sin encabezado configurado",
                style: TextStyle(
                  fontSize: 11,
                  color: tieneInfo || tieneLogo ? AppColors.statusGreen : AppColors.textSecondary,
                  fontWeight: tieneInfo || tieneLogo ? FontWeight.w600 : FontWeight.normal,
                ),
              ),
            ])),
            ElevatedButton.icon(
              onPressed: () => _abrirEditorEncabezado(nombreSede),
              icon: Icon(tieneInfo || tieneLogo ? Icons.edit_outlined : Icons.add, size: 16),
              label: Text(tieneInfo || tieneLogo ? "Editar" : "Configurar"),
              style: ElevatedButton.styleFrom(
                padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 8),
                textStyle: const TextStyle(fontSize: 12),
              ),
            ),
          ]),

          // Preview del encabezado si existe info
          if (tieneInfo || tieneLogo) ...[
            const Divider(height: 16),
            Row(crossAxisAlignment: CrossAxisAlignment.start, children: [
              // Mini preview logo
              if (tieneLogo) ...[
                ClipRRect(
                  borderRadius: BorderRadius.circular(6),
                  child: Image.memory(enc.logoBytes!, width: 48, height: 48, fit: BoxFit.contain,
                    errorBuilder: (_, __, ___) => Container(
                      width: 48, height: 48,
                      decoration: BoxDecoration(color: Colors.grey[100], borderRadius: BorderRadius.circular(6)),
                      child: const Icon(Icons.image_not_supported_outlined, color: Colors.grey, size: 20)),
                  ),
                ),
                const SizedBox(width: 10),
              ],
              Expanded(child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                if (enc.rif.isNotEmpty) _infoLineEnc(Icons.receipt_outlined, "RIF", enc.rif),
                if (enc.direccion.isNotEmpty) _infoLineEnc(Icons.location_on_outlined, "Dirección", enc.direccion),
                if (enc.telefono.isNotEmpty) _infoLineEnc(Icons.phone_outlined, "Teléfono", enc.telefono),
                if (enc.correo.isNotEmpty) _infoLineEnc(Icons.email_outlined, "Correo", enc.correo),
              ])),
            ]),
          ],
        ]),
      ),
    );
  }

  Widget _infoLineEnc(IconData icon, String label, String valor) => Padding(
    padding: const EdgeInsets.symmetric(vertical: 2),
    child: Row(children: [
      Icon(icon, size: 13, color: AppColors.textSecondary),
      const SizedBox(width: 5),
      Text("$label: ", style: const TextStyle(color: AppColors.textSecondary, fontSize: 11)),
      Expanded(child: Text(valor,
        style: const TextStyle(fontSize: 11, fontWeight: FontWeight.w500),
        overflow: TextOverflow.ellipsis)),
    ]),
  );

  /// Abre el editor de encabezado de factura para una sede
  void _abrirEditorEncabezado(String nombreSede) {
    final enc = ConfigSistema.encabezadoDe(nombreSede);
    final rifCtrl       = TextEditingController(text: enc.rif);
    final dirCtrl       = TextEditingController(text: enc.direccion);
    final telCtrl       = TextEditingController(text: enc.telefono);
    final emailCtrl     = TextEditingController(text: enc.correo);
    Uint8List? logoBytes = enc.logoBytes;
    bool cargandoLogo = false;

    showModalBottomSheet(
      context: context,
      isScrollControlled: true,
      useSafeArea: true,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(20))),
      builder: (ctx) => StatefulBuilder(
        builder: (context, setS) => Padding(
          padding: EdgeInsets.only(
            bottom: MediaQuery.of(ctx).viewInsets.bottom,
            left: 20, right: 20, top: 20),
          child: SingleChildScrollView(
            child: Column(mainAxisSize: MainAxisSize.min, children: [
              // Handle
              Center(child: Container(
                width: 40, height: 4,
                decoration: BoxDecoration(color: Colors.grey[300], borderRadius: BorderRadius.circular(2)),
              )),
              const SizedBox(height: 16),

              // Título
              Row(children: [
                const Icon(Icons.receipt_long, color: AppColors.royalBlue),
                const SizedBox(width: 8),
                Expanded(child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                  const Text("Encabezado de Factura",
                    style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold)),
                  Text(nombreSede,
                    style: const TextStyle(color: AppColors.textSecondary, fontSize: 13)),
                ])),
              ]),
              const SizedBox(height: 20),

              // ─── Sección logo ─────────────────────────────
              Container(
                padding: const EdgeInsets.all(14),
                decoration: BoxDecoration(
                  color: AppColors.surfaceGrey,
                  borderRadius: BorderRadius.circular(12),
                  border: Border.all(color: AppColors.cardBorder),
                ),
                child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                  const Row(children: [
                    Icon(Icons.image_outlined, color: AppColors.royalBlue, size: 16),
                    SizedBox(width: 6),
                    Text("Logo de la sede", style: TextStyle(fontWeight: FontWeight.bold, fontSize: 13)),
                  ]),
                  const SizedBox(height: 8),
                  const Text(
                    "El logo aparecerá en la esquina superior izquierda de cada factura. "
                    "Formatos soportados: PNG, JPG. Tamaño recomendado: cuadrado (ej. 300×300 px).",
                    style: TextStyle(fontSize: 11, color: AppColors.textSecondary)),
                  const SizedBox(height: 12),
                  Row(children: [
                    // Preview del logo
                    Container(
                      width: 80, height: 80,
                      decoration: BoxDecoration(
                        color: Colors.white,
                        borderRadius: BorderRadius.circular(10),
                        border: Border.all(color: AppColors.cardBorder),
                      ),
                      child: logoBytes != null
                        ? ClipRRect(
                            borderRadius: BorderRadius.circular(9),
                            child: Image.memory(logoBytes!, fit: BoxFit.contain,
                              errorBuilder: (_, __, ___) => const Icon(Icons.broken_image_outlined,
                                size: 36, color: Colors.grey)),
                          )
                        : const Center(child: Icon(Icons.add_photo_alternate_outlined,
                            size: 36, color: Colors.grey)),
                    ),
                    const SizedBox(width: 14),
                    Expanded(child: Column(children: [
                      SizedBox(
                        width: double.infinity,
                        child: ElevatedButton.icon(
                          icon: cargandoLogo
                            ? const SizedBox(width: 16, height: 16,
                                child: CircularProgressIndicator(strokeWidth: 2, color: Colors.white))
                            : const Icon(Icons.upload_outlined, size: 18),
                          label: const Text("Seleccionar logo"),
                          onPressed: cargandoLogo ? null : () async {
                            setS(() => cargandoLogo = true);
                            try {
                              final picker = ImagePicker();
                              final picked = await picker.pickImage(
                                source: ImageSource.gallery,
                                maxWidth: 400,
                                maxHeight: 400,
                                imageQuality: 90,
                              );
                              if (picked != null) {
                                final bytes = await picked.readAsBytes();
                                setS(() { logoBytes = bytes; cargandoLogo = false; });
                              } else {
                                setS(() => cargandoLogo = false);
                              }
                            } catch (e) {
                              setS(() => cargandoLogo = false);
                              if (ctx.mounted) ScaffoldMessenger.of(context).showSnackBar(
                                SnackBar(content: Text("Error al cargar imagen: $e"),
                                  backgroundColor: AppColors.statusRed));
                            }
                          },
                        ),
                      ),
                      if (logoBytes != null) ...[
                        const SizedBox(height: 6),
                        SizedBox(
                          width: double.infinity,
                          child: OutlinedButton.icon(
                            icon: const Icon(Icons.delete_outline, color: Colors.red, size: 18),
                            label: const Text("Quitar logo", style: TextStyle(color: Colors.red)),
                            style: OutlinedButton.styleFrom(side: const BorderSide(color: Colors.red)),
                            onPressed: () => setS(() => logoBytes = null),
                          ),
                        ),
                      ],
                    ])),
                  ]),
                ]),
              ),
              const SizedBox(height: 14),

              // ─── Datos de la sede ─────────────────────────
              Container(
                padding: const EdgeInsets.all(14),
                decoration: BoxDecoration(
                  color: AppColors.surfaceGrey,
                  borderRadius: BorderRadius.circular(12),
                  border: Border.all(color: AppColors.cardBorder),
                ),
                child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                  const Row(children: [
                    Icon(Icons.store_outlined, color: AppColors.royalBlue, size: 16),
                    SizedBox(width: 6),
                    Text("Datos de la sede", style: TextStyle(fontWeight: FontWeight.bold, fontSize: 13)),
                  ]),
                  const SizedBox(height: 12),
                  TextField(
                    controller: rifCtrl,
                    textCapitalization: TextCapitalization.characters,
                    decoration: const InputDecoration(
                      labelText: "RIF de la empresa",
                      hintText: "Ej: J-12345678-9",
                      prefixIcon: Icon(Icons.receipt_outlined),
                    ),
                  ),
                  const SizedBox(height: 10),
                  TextField(
                    controller: dirCtrl,
                    maxLines: 2,
                    textCapitalization: TextCapitalization.sentences,
                    decoration: const InputDecoration(
                      labelText: "Dirección física de la sede",
                      hintText: "Av. Principal, Cc. Nombre, Local 1, Ciudad",
                      prefixIcon: Icon(Icons.location_on_outlined),
                    ),
                  ),
                  const SizedBox(height: 10),
                  TextField(
                    controller: telCtrl,
                    keyboardType: TextInputType.phone,
                    decoration: const InputDecoration(
                      labelText: "Teléfono de contacto",
                      hintText: "Ej: 0212-555-5555 / 0414-555-5555",
                      prefixIcon: Icon(Icons.phone_outlined),
                    ),
                  ),
                  const SizedBox(height: 10),
                  TextField(
                    controller: emailCtrl,
                    keyboardType: TextInputType.emailAddress,
                    decoration: const InputDecoration(
                      labelText: "Correo electrónico (opcional)",
                      hintText: "sede@empresa.com",
                      prefixIcon: Icon(Icons.email_outlined),
                    ),
                  ),
                ]),
              ),
              const SizedBox(height: 14),

              // ─── Preview del encabezado ───────────────────
              Container(
                padding: const EdgeInsets.all(12),
                decoration: BoxDecoration(
                  color: Colors.white,
                  borderRadius: BorderRadius.circular(10),
                  border: Border.all(color: AppColors.cardBorder),
                ),
                child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                  const Row(children: [
                    Icon(Icons.visibility_outlined, size: 14, color: AppColors.textSecondary),
                    SizedBox(width: 6),
                    Text("Vista previa del encabezado",
                      style: TextStyle(fontSize: 11, color: AppColors.textSecondary, fontWeight: FontWeight.w600)),
                  ]),
                  const Divider(height: 12),
                  Row(crossAxisAlignment: CrossAxisAlignment.start, children: [
                    if (logoBytes != null) ...[
                      ClipRRect(
                        borderRadius: BorderRadius.circular(4),
                        child: Image.memory(logoBytes!, width: 40, height: 40, fit: BoxFit.contain),
                      ),
                      const SizedBox(width: 8),
                    ],
                    Expanded(child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                      Text(ConfigSistema.nombreEmpresa,
                        style: const TextStyle(fontWeight: FontWeight.bold, fontSize: 14, color: AppColors.royalBlue)),
                      Text(nombreSede, style: const TextStyle(fontSize: 11, color: AppColors.textSecondary)),
                      if (rifCtrl.text.isNotEmpty)
                        Text("RIF: ${rifCtrl.text}", style: const TextStyle(fontSize: 10, color: AppColors.textSecondary)),
                      if (dirCtrl.text.isNotEmpty)
                        Text(dirCtrl.text, style: const TextStyle(fontSize: 10, color: AppColors.textSecondary)),
                      if (telCtrl.text.isNotEmpty)
                        Text("Telf: ${telCtrl.text}", style: const TextStyle(fontSize: 10, color: AppColors.textSecondary)),
                    ])),
                    Column(crossAxisAlignment: CrossAxisAlignment.end, children: [
                      Container(
                        padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 2),
                        color: AppColors.royalBlue,
                        child: const Text("FACTURA", style: TextStyle(color: Colors.white, fontSize: 9, fontWeight: FontWeight.bold)),
                      ),
                      const Text("FAC-000000", style: TextStyle(fontSize: 10, fontWeight: FontWeight.bold)),
                      const Text("Fecha: hoy", style: TextStyle(fontSize: 9, color: AppColors.textSecondary)),
                    ]),
                  ]),
                ]),
              ),
              const SizedBox(height: 20),

              // ─── Botones ──────────────────────────────────
              Row(children: [
                Expanded(child: OutlinedButton(
                  onPressed: () => Navigator.pop(ctx),
                  child: const Text("Cancelar"),
                )),
                const SizedBox(width: 12),
                Expanded(flex: 2, child: ElevatedButton.icon(
                  icon: const Icon(Icons.save_outlined, size: 18),
                  label: const Text("Guardar encabezado"),
                  onPressed: () {
                    final nuevo = EncabezadoSede(
                      nombreSede: nombreSede,
                      rif: rifCtrl.text.trim(),
                      direccion: dirCtrl.text.trim(),
                      telefono: telCtrl.text.trim(),
                      correo: emailCtrl.text.trim(),
                      logoBytes: logoBytes,
                    );
                    ConfigSistema.guardarEncabezado(nuevo);
                    Navigator.pop(ctx);
                    setState(() => _cambiosPendientes = true);
                    ScaffoldMessenger.of(context).showSnackBar(SnackBar(
                      content: Text("Encabezado de '$nombreSede' guardado correctamente"),
                      backgroundColor: AppColors.statusGreen,
                    ));
                  },
                )),
              ]),
              const SizedBox(height: 24),
            ]),
          ),
        ),
      ),
    );
  }

