                    ]),
                  ]),
                ),
              ]),
            ),
          )),
          const SizedBox(height: 8),
          SizedBox(width: double.infinity,
            child: OutlinedButton.icon(
              icon: const Icon(Icons.add),
              label: const Text("Nueva Lista de Financiamiento"),
              onPressed: () => Navigator.push(context,
                MaterialPageRoute(builder: (_) => const VentanaListasPrecios()))
                .then((_) => setState(() {})),
            )),
        ],
      ]),
    );
  }

  Widget _cfKpi(String label, String value, Color color) => Expanded(
    child: Container(
      padding: const EdgeInsets.symmetric(vertical: 8),
      decoration: BoxDecoration(
        color: color.withValues(alpha: 0.07),
        borderRadius: BorderRadius.circular(8)),
      child: Column(children: [
        Text(value, style: TextStyle(
          fontWeight: FontWeight.bold, fontSize: 15, color: color)),
        Text(label, style: const TextStyle(
          fontSize: 10, color: AppColors.textSecondary)),
      ]),
    ));

  Widget _cfTextField(String label, String initial, ValueChanged<String> onChange) {
    // Usamos StatefulBuilder con un controller estable para evitar el memory
    // leak que ocurre al crear un TextEditingController en cada build().
    return StatefulBuilder(
      builder: (ctx, setSt) {
        final ctrl = TextEditingController(text: initial)
          ..selection = TextSelection.fromPosition(
              TextPosition(offset: initial.length));
        return TextField(
          controller: ctrl,
          keyboardType: const TextInputType.numberWithOptions(decimal: true),
          decoration: InputDecoration(labelText: label, isDense: true,
            border: const OutlineInputBorder()),
          onChanged: onChange,
        );
      },
    );
  }

  // ── Sección comisiones (solo Admin/Dueño pueden editar) ───
  Widget _tabComisiones() {
    final esAdmin = (usuarioSesion?.rol == 'Administrador' || usuarioSesion?.rol == 'Maestro') ||
                    (usuarioSesion?.rol == 'Dueño' || usuarioSesion?.rol == 'Maestro');

    // Si no es admin, mostrar bloqueo
    if (!esAdmin) {
      return Center(
        child: Padding(
          padding: const EdgeInsets.all(32),
          child: Column(
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              Icon(Icons.lock_outline, size: 64, color: Colors.grey[400]),
              const SizedBox(height: 16),
              const Text("Acceso restringido",
                style: TextStyle(fontSize: 18, fontWeight: FontWeight.bold,
                  color: AppColors.textSecondary)),
              const SizedBox(height: 8),
              const Text(
                "Solo el Administrador o el Dueño pueden ver y editar las "
                "tarifas de comisión.",
                textAlign: TextAlign.center,
                style: TextStyle(color: AppColors.textSecondary)),
            ],
          ),
        ),
      );
    }

    return SingleChildScrollView(
      padding: const EdgeInsets.all(20),
      child: Column(children: [
        // ── Aviso informativo ──
        Container(
          padding: const EdgeInsets.all(12),
          decoration: BoxDecoration(
            color: AppColors.primaryBlue.withValues(alpha: 0.08),
            borderRadius: BorderRadius.circular(10),
            border: Border.all(color: AppColors.primaryBlue.withValues(alpha: 0.2))),
          child: Row(children: [
            const Icon(Icons.info_outline, color: AppColors.primaryBlue, size: 20),
            const SizedBox(width: 10),
            Expanded(child: Text(
              "Estos valores definen cuánto gana el vendedor por cada unidad vendida. "
              "Se aplican automáticamente al calcular comisiones.",
              style: TextStyle(
                fontSize: 12,
                color: AppColors.primaryBlue.withValues(alpha: 0.85)))),
          ]),
        ),
        const SizedBox(height: 16),

        // ── Lista dinámica de categorías de comisión ──
        _seccionCard("Categorías de comisión",
            Icons.paid_outlined, [
          // Aviso si la lista está vacía (no debería pasar — siempre
          // hay 6 protegidas — pero por si acaso).
          if (ConfigSistema.categoriasComision.isEmpty)
            const Padding(
              padding: EdgeInsets.symmetric(vertical: 10),
              child: Text(
                  "No hay categorías configuradas. Pulsa \"Agregar\" abajo.",
                  textAlign: TextAlign.center,
                  style: TextStyle(color: AppColors.textSecondary)),
            ),
          // Lista de categorías existentes
          ...ConfigSistema.categoriasComision.map((cat) {
            return Padding(
              padding: const EdgeInsets.only(bottom: 10),
              child: _filaCategoriaComision(cat),
            );
          }),
          const SizedBox(height: 8),
          // Botón Agregar nueva categoría
          OutlinedButton.icon(
            icon: const Icon(Icons.add),
            label: const Text("Agregar categoría"),
            style: OutlinedButton.styleFrom(
              padding: const EdgeInsets.symmetric(vertical: 12),
              shape: RoundedRectangleBorder(
                borderRadius: BorderRadius.circular(10)),
            ),
            onPressed: () => _editarCategoriaComision(null),
          ),
        ]),
        const SizedBox(height: 16),

        // ── Sueldo base ──
        _seccionCard("Sueldo base semanal", Icons.account_balance_wallet_outlined, [
          _campoTexto(
            "Base semanal por defecto (USD)",
            _ctrlComBase,
            Icons.monetization_on_outlined,
            tipo: const TextInputType.numberWithOptions(decimal: true)),
          const SizedBox(height: 8),
          Container(
            padding: const EdgeInsets.all(10),
            decoration: BoxDecoration(
              color: Colors.grey[100],
              borderRadius: BorderRadius.circular(8)),
            child: Row(children: [
              Icon(Icons.lightbulb_outline, size: 16, color: Colors.grey[700]),
              const SizedBox(width: 8),
              Expanded(child: Text(
                "Valor que se asigna como sueldo base al crear un nuevo "
                "período de comisiones. Se puede ajustar después por vendedor.",
                style: TextStyle(fontSize: 11, color: Colors.grey[700]))),
            ]),
          ),
        ]),
        const SizedBox(height: 16),

        // ── Ejemplo de cálculo ──
        _seccionCard("Ejemplo de cálculo", Icons.calculate_outlined, [
          Builder(builder: (_) {
            // Tomamos las primeras 3 categorías "categoriaProducto"
            // o "lineaTelefonica" como ejemplo (o todas si hay menos).
            final categoriasMuestra = ConfigSistema.categoriasComision
                .where((c) =>
                    c.tipoConteo ==
                        TipoConteoComision.categoriaProducto ||
                    c.tipoConteo == TipoConteoComision.lineaTelefonica ||
                    c.tipoConteo == TipoConteoComision.servicioTecnico)
                .take(3)
                .toList();
            final vBase = double.tryParse(_ctrlComBase.text) ?? 0;
            // Ejemplo: 2 unidades de cada una de las primeras categorías
            const cantidadEjemplo = 2;
            double subtotal = 0;
            final filas = <Widget>[];
            for (final c in categoriasMuestra) {
              final monto = cantidadEjemplo * c.tarifaUSD;
              subtotal += monto;
              filas.add(_filaEjemplo(
                  "$cantidadEjemplo × ${c.nombre} × ${formatCurrency(c.tarifaUSD)}",
                  monto));
            }
            final totalEjemplo = subtotal + vBase;
            return Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(
                      "Ejemplo: $cantidadEjemplo unidades de cada categoría:",
                      style: const TextStyle(
                          fontSize: 13, fontWeight: FontWeight.w600)),
                  const SizedBox(height: 10),
                  ...filas,
                  if (filas.isEmpty)
                    const Padding(
                      padding: EdgeInsets.symmetric(vertical: 8),
                      child: Text(
                          "Agrega al menos una categoría para ver el ejemplo.",
                          style: TextStyle(
                              fontSize: 12,
                              color: AppColors.textSecondary,
                              fontStyle: FontStyle.italic)),
                    ),
                  const Divider(),
                  _filaEjemplo("Subtotal comisiones", subtotal, bold: true),
                  _filaEjemplo("+ Sueldo base", vBase),
                  const Divider(thickness: 1.5),
                  _filaEjemplo("TOTAL A PAGAR", totalEjemplo,
                      bold: true, destacado: true),
                  const SizedBox(height: 6),
                  // Conversión a Bs usando la tasa actual
                  Builder(builder: (_) {
                    final tasa = ConfigSistema.tasaCambio;
                    final totalBs = totalEjemplo * tasa;
                    return Text(
                        "Equivalente: Bs ${totalBs.toStringAsFixed(2)} "
                        "(tasa BCV ${tasa.toStringAsFixed(2)})",
                        style: const TextStyle(
                            fontSize: 11,
                            color: AppColors.textSecondary,
                            fontStyle: FontStyle.italic));
                  }),
                ]);
          }),
        ]),
        const SizedBox(height: 16),

        // ── Botón restaurar valores por defecto ──
        OutlinedButton.icon(
          icon: const Icon(Icons.restore),
          label: const Text("Restaurar categorías originales"),
          onPressed: () {
            showDialog(
              context: context,
              builder: (ctx) => AlertDialog(
                title: const Text("¿Restaurar categorías?"),
                content: const Text(
                    "Se restaurarán las 6 categorías originales con sus "
                    "tarifas por defecto, y se ELIMINARÁN todas las "
                    "categorías personalizadas que hayas agregado.\n\n"
                    "¿Continuar?"),
                actions: [
                  TextButton(
                      onPressed: () => Navigator.pop(ctx),
                      child: const Text("Cancelar")),
                  ElevatedButton(
                    style: ElevatedButton.styleFrom(
                        backgroundColor: AppColors.statusOrange),
                    onPressed: () async {
                      await ConfigSistema
                          .restaurarCategoriasComisionPorDefecto();
                      _ctrlComBase.text = "40.00";
                      if (mounted) setState(() => _cambiosPendientes = true);
                      if (ctx.mounted) Navigator.pop(ctx);
                    },
                    child: const Text("Restaurar",
                        style: TextStyle(color: Colors.white))),
                ],
              ),
            );
          },
        ),
      ]),
    );
  }

  // ════════════════════════════════════════════════════════════
  //  HELPERS DEL TAB COMISIONES (SISTEMA DINÁMICO)
