  /// Renderiza una fila de categoría: ícono + nombre + descripción +
  /// tarifa editable rápido + botones (editar / eliminar).
  Widget _filaCategoriaComision(CategoriaComision cat) {
    final color = cat.color;
    return Container(
      padding: const EdgeInsets.all(10),
      decoration: BoxDecoration(
          color: color.withValues(alpha: 0.05),
          borderRadius: BorderRadius.circular(10),
          border: Border.all(color: color.withValues(alpha: 0.2))),
      child: Row(children: [
        // Ícono coloreado
        Container(
          width: 40,
          height: 40,
          decoration: BoxDecoration(
              color: color.withValues(alpha: 0.15),
              borderRadius: BorderRadius.circular(10)),
          child: Icon(cat.icono, color: color, size: 22),
        ),
        const SizedBox(width: 12),
        // Nombre + descripción del tipo
        Expanded(
            child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
              Row(children: [
                Flexible(
                  child: Text(cat.nombre,
                      overflow: TextOverflow.ellipsis,
                      style: const TextStyle(
                          fontSize: 14, fontWeight: FontWeight.w600)),
                ),
                if (cat.protegida) ...[
                  const SizedBox(width: 4),
                  Icon(Icons.lock_outline,
                      size: 12, color: Colors.grey[600]),
                ],
              ]),
              Text(cat.tipoConteo.descripcion,
                  maxLines: 2,
                  overflow: TextOverflow.ellipsis,
                  style: TextStyle(fontSize: 11, color: Colors.grey[600])),
            ])),
        const SizedBox(width: 8),
        // Tarifa editable rápida (in-place)
        if (cat.tipoConteo != TipoConteoComision.porcentajeWeppa)
          SizedBox(
            width: 80,
            child: TextField(
              controller: TextEditingController(
                  text: cat.tarifaUSD.toStringAsFixed(2)),
              keyboardType:
                  const TextInputType.numberWithOptions(decimal: true),
              textAlign: TextAlign.right,
              onSubmitted: (v) async {
                final nuevo = double.tryParse(v);
                if (nuevo != null && nuevo >= 0) {
                  cat.tarifaUSD = nuevo;
                  await ConfigSistema.guardarCategoriasComision();
                  if (mounted) setState(() {});
                }
              },
              style: TextStyle(
                  fontWeight: FontWeight.bold,
                  color: color,
                  fontSize: 16),
              decoration: InputDecoration(
                  prefixText: "\$",
                  prefixStyle: TextStyle(
                      color: color, fontWeight: FontWeight.bold),
                  isDense: true,
                  contentPadding: const EdgeInsets.symmetric(
                      horizontal: 8, vertical: 10),
                  filled: true,
                  fillColor: Colors.white,
                  border: OutlineInputBorder(
                      borderRadius: BorderRadius.circular(8),
                      borderSide:
                          BorderSide(color: color.withValues(alpha: 0.4)))),
            ),
          ),
        // Botón editar
        IconButton(
          icon: Icon(Icons.edit_outlined, color: color, size: 20),
          tooltip: "Editar",
          onPressed: () => _editarCategoriaComision(cat),
        ),
        // Botón eliminar (solo si NO es protegida)
        if (!cat.protegida)
          IconButton(
            icon: const Icon(Icons.delete_outline,
                color: AppColors.statusRed, size: 20),
            tooltip: "Eliminar",
            onPressed: () => _eliminarCategoriaComision(cat),
          ),
      ]),
    );
  }

  /// Diálogo para crear o editar una categoría de comisión.
  /// Si [existente] es null se crea una nueva; si trae valor se edita.
  void _editarCategoriaComision(CategoriaComision? existente) {
    final esNueva = existente == null;
    final ctrlNombre = TextEditingController(text: existente?.nombre ?? '');
    final ctrlTarifa = TextEditingController(
        text: (existente?.tarifaUSD ?? 1.0).toStringAsFixed(2));
    final ctrlValor =
        TextEditingController(text: existente?.valorConteo ?? '');
    TipoConteoComision tipoSel =
        existente?.tipoConteo ?? TipoConteoComision.categoriaProducto;
    String iconoSel = existente?.iconoKey ?? 'work';
    String colorSel = existente?.colorHex ?? '#1565C0';

    // Paleta de colores predefinida
    const paleta = [
      '#1565C0', '#009688', '#7B1FA2', '#E64A19', '#3949AB',
      '#5D4037', '#2E7D32', '#C62828', '#00838F', '#6A1B9A',
      '#EF6C00', '#37474F',
    ];
    // Iconos disponibles — leídos del mapa estático de la clase
    // (preserva tree-shaking, todos los IconData son const).
    final iconos = CategoriaComision.iconosDisponibles.entries.toList();

    showDialog(
        context: context,
        builder: (c) => StatefulBuilder(builder: (context, setS) {
              return AlertDialog(
                scrollable: true,
                title: Text(esNueva
                    ? "Nueva categoría de comisión"
                    : "Editar: ${existente.nombre}"),
                content: SizedBox(
                    width: 380,
                    child: Column(
                        mainAxisSize: MainAxisSize.min,
                        crossAxisAlignment: CrossAxisAlignment.stretch,
                        children: [
                          TextField(
                            controller: ctrlNombre,
                            decoration: const InputDecoration(
                                labelText: "Nombre",
                                hintText: "Ej: Servicio Técnico",
                                prefixIcon: Icon(Icons.label_outline)),
                          ),
                          const SizedBox(height: 12),
                          TextField(
                            controller: ctrlTarifa,
                            keyboardType:
                                const TextInputType.numberWithOptions(
                                    decimal: true),
                            decoration: const InputDecoration(
                                labelText: "Tarifa USD por unidad",
                                prefixText: "\$ ",
                                prefixIcon: Icon(Icons.attach_money)),
                          ),
                          const SizedBox(height: 12),
                          // Tipo de conteo
                          DropdownButtonFormField<TipoConteoComision>(
                            initialValue: tipoSel,
                            isExpanded: true,
                            decoration: const InputDecoration(
                                labelText: "Cómo se cuenta",
                                prefixIcon: Icon(Icons.rule_outlined)),
                            items: TipoConteoComision.values
                                .where((t) =>
                                    t != TipoConteoComision.porcentajeWeppa)
                                .map((t) => DropdownMenuItem(
                                    value: t,
                                    child: Text(t.descripcion,
                                        overflow: TextOverflow.ellipsis,
                                        style: const TextStyle(fontSize: 12))))
                                .toList(),
                            onChanged: (v) =>
                                setS(() => tipoSel = v ?? tipoSel),
                          ),
                          const SizedBox(height: 12),
                          // Valor del tipo de conteo (solo si aplica)
                          if (tipoSel ==
                                  TipoConteoComision.categoriaProducto ||
                              tipoSel == TipoConteoComision.ventaFinanciada)
                            TextField(
                              controller: ctrlValor,
                              decoration: InputDecoration(
                                  labelText: tipoSel ==
                                          TipoConteoComision
                                              .categoriaProducto
                                      ? "Categoría de producto a contar"
                                      : "Filtro de financiador (opcional)",
                                  hintText: tipoSel ==
                                          TipoConteoComision
                                              .categoriaProducto
                                      ? "Ej: Accesorio, Telefono, Televisor"
                                      : "Vacío = cualquier financiador",
                                  prefixIcon:
                                      const Icon(Icons.filter_alt_outlined)),
                            ),
                          const SizedBox(height: 16),
                          // Selector de color
                          const Text("Color",
                              style: TextStyle(
                                  fontWeight: FontWeight.w600, fontSize: 13)),
                          const SizedBox(height: 8),
                          Wrap(
                            spacing: 8,
                            runSpacing: 8,
                            children: paleta.map((hex) {
                              final selected = colorSel == hex;
                              final color = Color(int.parse(
                                  'FF${hex.replaceAll("#", "")}',
                                  radix: 16));
                              return GestureDetector(
                                onTap: () => setS(() => colorSel = hex),
                                child: Container(
                                  width: 32,
                                  height: 32,
                                  decoration: BoxDecoration(
                                      color: color,
                                      shape: BoxShape.circle,
                                      border: selected
                                          ? Border.all(
                                              color: Colors.black,
                                              width: 3)
                                          : null),
                                ),
                              );
                            }).toList(),
                          ),
                          const SizedBox(height: 16),
                          // Selector de ícono
                          const Text("Ícono",
                              style: TextStyle(
                                  fontWeight: FontWeight.w600, fontSize: 13)),
                          const SizedBox(height: 8),
                          Wrap(
                            spacing: 8,
                            runSpacing: 8,
                            children: iconos.map((entry) {
                              // entry.key = clave string, entry.value = IconData
                              final ic = entry.value;
                              final selected = iconoSel == entry.key;
                              final color = Color(int.parse(
                                  'FF${colorSel.replaceAll("#", "")}',
                                  radix: 16));
                              return GestureDetector(
                                onTap: () =>
                                    setS(() => iconoSel = entry.key),
                                child: Container(
                                  width: 36,
                                  height: 36,
                                  decoration: BoxDecoration(
                                      color: selected
                                          ? color.withValues(alpha: 0.2)
                                          : Colors.grey.shade100,
                                      borderRadius: BorderRadius.circular(8),
                                      border: selected
                                          ? Border.all(color: color, width: 2)
                                          : null),
                                  child: Icon(ic,
                                      color: selected
                                          ? color
                                          : Colors.grey.shade700,
                                      size: 20),
                                ),
                              );
                            }).toList(),
                          ),
                        ])),
                actions: [
                  TextButton(
                      onPressed: () => Navigator.pop(c),
                      child: const Text("Cancelar")),
                  ElevatedButton(
                    style: ElevatedButton.styleFrom(
                        backgroundColor: AppColors.statusGreen,
                        foregroundColor: Colors.white),
                    onPressed: () async {
                      final nombre = ctrlNombre.text.trim();
                      if (nombre.isEmpty) {
                        ScaffoldMessenger.of(context).showSnackBar(
                            const SnackBar(
                                content: Text("Ingresa un nombre"),
                                backgroundColor: AppColors.statusOrange));
                        return;
                      }
                      final tarifa = double.tryParse(ctrlTarifa.text) ?? 0;
                      if (esNueva) {
                        // Generar un id único basado en timestamp
                        final id = 'cat_${DateTime.now().millisecondsSinceEpoch}';
                        ConfigSistema.categoriasComision.add(
                            CategoriaComision(
                                id: id,
                                nombre: nombre,
                                tarifaUSD: tarifa,
                                tipoConteo: tipoSel,
                                valorConteo: ctrlValor.text.trim(),
                                iconoKey: iconoSel,
                                colorHex: colorSel,
                                protegida: false));
                      } else {
                        existente.nombre = nombre;
                        existente.tarifaUSD = tarifa;
                        existente.tipoConteo = tipoSel;
                        existente.valorConteo = ctrlValor.text.trim();
                        existente.iconoKey = iconoSel;
                        existente.colorHex = colorSel;
                      }
                      await ConfigSistema.guardarCategoriasComision();
                      if (mounted) setState(() {});
                      if (c.mounted) Navigator.pop(c);
                    },
                    child: Text(esNueva ? "Crear" : "Guardar"),
                  ),
                ],
              );
            }));
  }

  /// Confirma y elimina una categoría no protegida.
  void _eliminarCategoriaComision(CategoriaComision cat) {
    if (cat.protegida) return; // Defensivo: las protegidas no se eliminan
    showDialog(
        context: context,
        builder: (ctx) => AlertDialog(
              title: Text("¿Eliminar \"${cat.nombre}\"?"),
              content: const Text(
                  "Esta acción es permanente. Los históricos de comisión "
                  "ya generados conservarán los datos de esta categoría, "
                  "pero las nuevas generaciones ya no la incluirán."),
              actions: [
                TextButton(
                    onPressed: () => Navigator.pop(ctx),
                    child: const Text("Cancelar")),
                ElevatedButton(
                    style: ElevatedButton.styleFrom(
                        backgroundColor: AppColors.statusRed,
                        foregroundColor: Colors.white),
                    onPressed: () async {
                      ConfigSistema.categoriasComision
                          .removeWhere((c) => c.id == cat.id);
                      await ConfigSistema.guardarCategoriasComision();
                      if (mounted) setState(() {});
                      if (ctx.mounted) Navigator.pop(ctx);
                    },
                    child: const Text("Eliminar")),
              ],
            ));
  }

  // Helper para las filas del ejemplo de cálculo
  Widget _filaEjemplo(String label, double monto,
      {bool bold = false, bool destacado = false}) {
    final estilo = TextStyle(
      fontSize: destacado ? 15 : 13,
      fontWeight: bold ? FontWeight.bold : FontWeight.normal,
      color: destacado ? AppColors.primaryBlue : null);
    return Padding(
      padding: const EdgeInsets.symmetric(vertical: 3),
      child: Row(mainAxisAlignment: MainAxisAlignment.spaceBetween, children: [
        Text(label, style: estilo),
        Text(formatCurrency(monto), style: estilo),
      ]),
    );
  }

