  // ── Helpers de UI ─────────────────────────────────────────
  /// Formatea un string JSON con indentación de 2 espacios.
  /// Si el string no es JSON válido, lo retorna tal cual.
  String _prettyJson(String raw) {
    if (raw.trim().isEmpty) return '(vacío)';
    try {
      final obj = jsonDecode(raw);
      const encoder = JsonEncoder.withIndent('  ');
      return encoder.convert(obj);
    } catch (_) {
      return raw;
    }
  }

  Widget _seccionCard(String titulo, IconData icon, List<Widget> hijos) {
    return Card(
      elevation: 2,
      child: Padding(padding: const EdgeInsets.all(16), child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(children: [
            Icon(icon, color: AppColors.royalBlue, size: 20),
            const SizedBox(width: 8),
            Text(titulo, style: const TextStyle(fontWeight: FontWeight.bold, fontSize: 15)),
          ]),
          const SizedBox(height: 16),
          ...hijos,
        ],
      )),
    );
  }

  Widget _campoTexto(String label, TextEditingController ctrl, IconData icon,
      {TextInputType tipo = TextInputType.text, int maxLines = 1}) {
