// ============================================================
//  VENTANA COSTOS Y FINANZAS
//  Visible solo para: Administrador, Gerente, Dueño
//  Recrea las hojas del modelo financiero Excel:
//  Inventarios · Compras · Ventas · Nómina · Gastos ·
//  Punto de Equilibrio · Resultados · Otros Ingresos/Egresos ·
//  Carga Financiera · Flujo de Caja
// ============================================================

// ── Modelos de datos ─────────────────────────────────────────

class ItemInventarioCF {
  String concepto;
  double invInicialUnidades;
  double costoUnitarioInicial;
  double comprasUnidades;
  double precioUnitarioCompra;
  double ventaUnidades;
  double costoUnitarioSalida;

  ItemInventarioCF({
    this.concepto = '',
    this.invInicialUnidades = 0,
    this.costoUnitarioInicial = 0,
    this.comprasUnidades = 0,
    this.precioUnitarioCompra = 0,
    this.ventaUnidades = 0,
    this.costoUnitarioSalida = 0,
  });

  double get invInicialValorado => invInicialUnidades * costoUnitarioInicial;
  double get comprasTotales => comprasUnidades * precioUnitarioCompra;
  double get inventarioTotalUnidades => invInicialUnidades + comprasUnidades;
  double get valorInventarioUltimaCompra => inventarioTotalUnidades * precioUnitarioCompra;
  double get costoTotalSalida => ventaUnidades * costoUnitarioSalida;
  double get inventarioFinalUnidades => inventarioTotalUnidades - ventaUnidades;
  double get inventarioFinalValorado => inventarioFinalUnidades * costoUnitarioSalida;
}

class ItemComprasCF {
  DateTime? fecha;
  String producto;
  double cantidad;
  double tasaDia;
  double precioUnitario;

  ItemComprasCF({this.fecha, this.producto = '', this.cantidad = 0, this.tasaDia = 0, this.precioUnitario = 0});

  double get totalCompraUsd => cantidad * precioUnitario;
  double get totalCompraBs => totalCompraUsd * tasaDia;
}

class ItemVentasCF {
  DateTime? fecha;
  String producto;
  double cantidad;
  double tasaDia;
  double precioUnitario;

  ItemVentasCF({this.fecha, this.producto = '', this.cantidad = 0, this.tasaDia = 0, this.precioUnitario = 0});

  double get totalVentaUsd => cantidad * precioUnitario;
  double get totalVentaBs => totalVentaUsd * tasaDia;
}

class ItemNominaCF {
  String cargo;
  double cantidad;
  double sueldo;
  double ivss;
  double inces;
  double banavih;
  double vacac;
  double comisiones;
  double utilidades;
  double lcp;
  double prestSociales;

  ItemNominaCF({
    this.cargo = '',
    this.cantidad = 1,
    this.sueldo = 0,
    this.ivss = 0,
    this.inces = 0,
    this.banavih = 0,
    this.vacac = 0,
    this.comisiones = 0,
    this.utilidades = 0,
    this.lcp = 0,
    this.prestSociales = 0,
  });

  double get totalSueldo => cantidad * sueldo;
  double get totalIvss => totalSueldo * 0.11;
  double get totalInces => totalSueldo * 0.02;
  double get totalBanavih => totalSueldo * 0.03;
  double get total => totalSueldo + totalIvss + totalInces + totalBanavih + vacac + comisiones + utilidades + lcp + prestSociales;
}

class ItemGastoCF {
  String concepto;
  double monto;
  ItemGastoCF({this.concepto = '', this.monto = 0});
}

class ItemOtroIngresoEgresoCF {
  String concepto;
  double monto;
  bool esIngreso;
  ItemOtroIngresoEgresoCF({this.concepto = '', this.monto = 0, this.esIngreso = true});
}

class ItemFlujoCF {
  String mes;
  double ingresoVentas;
  double costoVentas;
  double gastosAdmin;
  double gastosOperacion;
  double gastosInversion;
  double cargaFinanciera;
  double otrosIngresos;
  double otrosEgresos;
  double saldoInicial;

  ItemFlujoCF({
    this.mes = '',
    this.ingresoVentas = 0,
    this.costoVentas = 0,
    this.gastosAdmin = 0,
    this.gastosOperacion = 0,
    this.gastosInversion = 0,
    this.cargaFinanciera = 0,
    this.otrosIngresos = 0,
    this.otrosEgresos = 0,
    this.saldoInicial = 0,
  });

  double get totalEgresos => costoVentas + gastosAdmin + gastosOperacion + gastosInversion;
  double get flujoOperativo => ingresoVentas - totalEgresos;
  double get otrosNeto => otrosIngresos - otrosEgresos;
  double get flujoNeto => flujoOperativo - cargaFinanciera + otrosNeto;
  double get saldoFinal => saldoInicial + flujoNeto;
}

// ── Widget principal ─────────────────────────────────────────

class VentanaCostosFinanzas extends StatefulWidget {
  const VentanaCostosFinanzas({super.key});
  @override
  State<VentanaCostosFinanzas> createState() => _VentanaCostosFinanzasState();
}

class _VentanaCostosFinanzasState extends State<VentanaCostosFinanzas>
    with SingleTickerProviderStateMixin {
  late TabController _tabs;

  // ── Inventario ──
  final List<ItemInventarioCF> _inventario = [];

  // ── Compras ──
  final List<ItemComprasCF> _compras = [];
  double _tasaBinanceCompras = 0;

  // ── Ventas ──
  final List<ItemVentasCF> _ventas = [];
  double _tasaBinanceVentas = 0;

  // ── Nómina ──
  final List<ItemNominaCF> _nomina = [];

  // ── Gastos ──
  final List<ItemGastoCF> _gastosAdmin = [];
  final List<ItemGastoCF> _gastosOperacion = [];
  final List<ItemGastoCF> _gastosInversion = [];

  // ── Otros ingresos / egresos ──
  final List<ItemOtroIngresoEgresoCF> _otrosMovimientos = [];

  // ── Carga financiera ──
  double _capitalPrestamo = 0;
  double _tasaInteresPct = 12;
  double _plazoAnios = 1;

  // ── Flujo ──
  final List<ItemFlujoCF> _flujo = [];

  // ── Mes/año en análisis ────────────────────────────────────
  // Toda la información cargada automáticamente (inventario, ventas
  // y nómina) corresponde al mes seleccionado. Por defecto el mes
  // actual; el usuario puede cambiarlo con un selector en el AppBar.
  late int _mesSel;
  late int _anioSel;
  bool _cargandoAuto = false;

  static const _nombresMes = [
    'Enero','Febrero','Marzo','Abril','Mayo','Junio',
    'Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre',
  ];

  @override
  void initState() {
    super.initState();
    _tabs = TabController(length: 9, vsync: this);
    // Iniciar tasa BCV
    _tasaBinanceCompras = ConfigSistema.tasaCambio;
    _tasaBinanceVentas = ConfigSistema.tasaCambio;
    // Pre-cargar un mes de flujo vacío
    for (final m in ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre']) {
      _flujo.add(ItemFlujoCF(mes: m));
    }
    // Mes/año actual
    final now = DateTime.now();
    _mesSel = now.month;
    _anioSel = now.year;
    // Carga automática inicial: jala inventario, ventas, nómina del
    // mes en curso desde la BD (facturas + productos + comisiones).
    WidgetsBinding.instance.addPostFrameCallback((_) =>
        _cargarDatosDelSistema());
  }

  @override
  void dispose() {
    _tabs.dispose();
    super.dispose();
  }

  /// Carga automática desde la BD: ventas (facturas), inventario
  /// (productos con su stock e histórico), nómina (comisiones).
  /// Funciona para el mes seleccionado en _mesSel/_anioSel.
  Future<void> _cargarDatosDelSistema() async {
    if (!mounted) return;
    setState(() => _cargandoAuto = true);
    try {
      // 1) Tasa Binance del día (la actual del sistema)
      _tasaBinanceVentas = ConfigSistema.tasaCambio;
      _tasaBinanceCompras = ConfigSistema.tasaCambio;

      // 2) Cargar productos, facturas e IMEIs en paralelo
      final results = await Future.wait([
        _Api.get('productos'),
        _Api.get('facturas'),
        _Api.get('stock_imei'),
      ]);
      final prods = ((results[0] as List?) ?? [])
          .map((m) => Producto.fromMap(m as Map<String, dynamic>))
          .toList();
      final prodPorCodigo = <String, Producto>{
        for (final p in prods) p.codigo: p
      };
      final imeisRaw = ((results[2] as List?) ?? []);
      final imeiPorNumero = <String, ImeiRegistro>{
        for (final i in imeisRaw)
          (i as Map)['imei'].toString():
              ImeiRegistro.fromMap(i as Map<String, dynamic>)
      };

      // 3) Filtrar facturas del mes seleccionado
      final inicioMes = DateTime(_anioSel, _mesSel, 1);
      final finMes = DateTime(_anioSel, _mesSel + 1, 1)
          .subtract(const Duration(seconds: 1));
      final facturasMes = <FacturaModel>[];
      for (final m in ((results[1] as List?) ?? [])) {
        final mp = m as Map<String, dynamic>;
        final f = parseFechaFlexible(mp['fecha']?.toString() ?? '');
        if (f == null) continue;
        if (f.isBefore(inicioMes) || f.isAfter(finMes)) continue;
        final equipos = <ImeiRegistro>[];
        for (final imei in (mp['equipos'] as List? ?? [])) {
          final r = imeiPorNumero[imei.toString()];
          if (r != null) equipos.add(r);
        }
        final items = <Producto>[];
        for (final cod in (mp['items'] as List? ?? [])) {
          final p = prodPorCodigo[cod.toString()];
          if (p != null) items.add(p);
        }
        facturasMes.add(FacturaModel(
          id: mp['id'] is int ? mp['id']
              : int.tryParse(mp['id']?.toString() ?? ''),
          cliente: mp['cliente']?.toString() ?? '',
          cedula: mp['cedula']?.toString() ?? '',
          telefono: mp['telefono']?.toString() ?? '',
          nroFactura: mp['nro_factura']?.toString() ?? '',
          vendedor: mp['vendedor']?.toString() ?? '',
          tienda: mp['tienda']?.toString() ?? '',
          fecha: mp['fecha']?.toString() ?? '',
          equipos: equipos,
          itemsSinImei: items,
          pagos: ((mp['pagos'] as List?) ?? [])
              .map((p) => PagoFactura.fromMap(p as Map<String, dynamic>))
              .toList(),
        ));
      }

      // ─── VENTAS ─────────────────────────────────────────────
      // Cada equipo / item de cada factura del mes es una línea de
      // venta. El precio de venta se toma del INVENTARIO ACTUAL del
      // producto (no del histórico de la factura) como pidió el user.
      _ventas.clear();
      for (final fac in facturasMes) {
        final fecha = parseFechaFlexible(fac.fecha);
        for (final eq in fac.equipos) {
          _ventas.add(ItemVentasCF(
            fecha: fecha,
            producto: eq.producto.nombre.isEmpty
                ? eq.producto.codigo : eq.producto.nombre,
            cantidad: 1,
            tasaDia: _tasaBinanceVentas,
            precioUnitario:
                prodPorCodigo[eq.producto.codigo]?.precioVenta
                    ?? eq.producto.precioVenta,
          ));
        }
        for (final p in fac.itemsSinImei) {
          _ventas.add(ItemVentasCF(
            fecha: fecha,
            producto: p.nombre.isEmpty ? p.codigo : p.nombre,
            cantidad: 1,
            tasaDia: _tasaBinanceVentas,
            precioUnitario:
                prodPorCodigo[p.codigo]?.precioVenta ?? p.precioVenta,
          ));
        }
      }

      // ─── INVENTARIO ─────────────────────────────────────────
      // Política de fuentes (definida por el usuario):
      //  · Inv. inicial uds       → el STOCK ACTUAL de cada producto.
      //  · Inv. inicial costo     → precio de costo registrado al producto.
      //  · Compras uds            → vienen de la pestaña Compras
      //                             (entradas manuales en _compras).
      //  · Precio unit. de compra → de la pestaña Compras.
      //  · Ventas uds             → de las facturas del mes.
      //  · Costo unit. salida     → precio de costo del producto.
      //
      // NOTA: el catálogo no guarda "el stock al primero del mes",
      // solo el stock actual. Tomamos ese stock actual como inicial,
      // que es lo que el usuario pidió expresamente.
      _inventario.clear();
      // NO limpiamos _compras: lo que el usuario haya capturado en la
      // pestaña Compras debe sobrevivir al recargar el inventario.
      // (En el primer load _compras viene vacía; tras ingresar compras
      // y pulsar refrescar, las compras del mes anterior se reemplazan
      // explícitamente desde el _cambiarMes.)

      // Unidades vendidas en el mes por código (de las facturas)
      final ventasPorCodigo = <String, int>{};
      for (final f in facturasMes) {
        for (final eq in f.equipos) {
          ventasPorCodigo[eq.producto.codigo] =
              (ventasPorCodigo[eq.producto.codigo] ?? 0) + 1;
        }
        for (final p in f.itemsSinImei) {
          ventasPorCodigo[p.codigo] =
              (ventasPorCodigo[p.codigo] ?? 0) + 1;
        }
      }

      for (final p in prods.where((p) => p.productoPadreCodigo.isEmpty)) {
        int stockHoy;
        if (p.categoria == 'Telefono') {
          stockHoy = imeisRaw.where((i) {
            final mp = i as Map;
            return (mp['producto_codigo']?.toString() ?? '') == p.codigo
                && ((mp['vendido']?.toString() ?? '0') == '0'
                  || (mp['vendido']?.toString() ?? '0') == 'false');
          }).length;
        } else {
          stockHoy = p.stockManual;
        }
        final vendidoMes = ventasPorCodigo[p.codigo] ?? 0;
        _inventario.add(ItemInventarioCF(
          concepto: p.nombre.isEmpty ? p.codigo : p.nombre,
          invInicialUnidades: stockHoy.toDouble(),
          costoUnitarioInicial: p.precioCosto,
          comprasUnidades: 0,             // se completa desde Compras
          precioUnitarioCompra: 0,        // se completa desde Compras
          ventaUnidades: vendidoMes.toDouble(),
          costoUnitarioSalida: p.precioCosto,
        ));
      }
      // Aplicar las compras que ya estén capturadas en _compras
      // (en cambio de mes vienen vacías; tras ingresar manualmente, esta
      // función las refleja en el inventario).
      _recalcularInventarioConCompras();

      // ─── NÓMINA (comisiones por vendedor) ───────────────────
      await _cargarNominaDesdeComisiones(facturasMes);

      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(SnackBar(
            content: Text(
                "✅ Datos cargados: ${_nombresMes[_mesSel-1]} $_anioSel"),
            backgroundColor: AppColors.statusGreen,
            duration: const Duration(seconds: 2)));
      }
    } catch (e) {
      debugPrint('[CostosFinanzas] cargar error: $e');
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(SnackBar(
          content: Text("Error al cargar datos: $e"),
          backgroundColor: AppColors.statusRed));
    } finally {
      if (mounted) setState(() => _cargandoAuto = false);
    }
  }

  /// Calcula nómina (ítems) a partir de comisiones del mes.
  /// El total comisión va al campo `comisiones`; sueldo en 0 porque
  /// en este sistema la nómina ES la comisión + base.
  Future<void> _cargarNominaDesdeComisiones(
      List<FacturaModel> facturasMes) async {
    _nomina.clear();
    if (facturasMes.isEmpty) return;

    final categorias = List<CategoriaComision>.from(
        ConfigSistema.categoriasComision);
    final mapa = <String, ResumenComision>{};

    ResumenComision obtenerResumen(String vendedor) {
      return mapa.putIfAbsent(vendedor, () {
        final r = ResumenComision(vendedor: vendedor);
        for (final c in categorias) {
          r.conteos[c.id] = 0;
          r.tarifasUsadas[c.id] = c.tarifaUSD;
          r.nombresCategorias[c.id] = c.nombre;
        }
        return r;
      });
    }

    for (final fac in facturasMes) {
      final vendedor = fac.vendedor.trim();
      if (vendedor.isEmpty) continue;
      final r = obtenerResumen(vendedor);
      for (final eq in fac.equipos) {
        for (final c in categorias) {
          if (c.tipoConteo == TipoConteoComision.categoriaProducto
              && c.valorConteo.toLowerCase() ==
                  eq.producto.categoria.toLowerCase()) {
            r.conteos[c.id] = (r.conteos[c.id] ?? 0) + 1;
          }
        }
      }
      for (final p in fac.itemsSinImei) {
        for (final c in categorias) {
          if (c.tipoConteo == TipoConteoComision.categoriaProducto
              && c.valorConteo.toLowerCase() ==
                  p.categoria.toLowerCase()) {
            r.conteos[c.id] = (r.conteos[c.id] ?? 0) + 1;
          }
        }
      }
    }

    for (final entry in mapa.entries) {
      final r = entry.value;
      final totalUsd = r.totalPagar();
      _nomina.add(ItemNominaCF(
        cargo: entry.key,
        cantidad: 1,
        sueldo: 0,
        comisiones: totalUsd,
      ));
    }
  }

  /// Cambia el mes/año en análisis y recarga.
  Future<void> _cambiarMes() async {
    final inicial = DateTime(_anioSel, _mesSel, 1);
    final picked = await showDatePicker(
      context: context,
      initialDate: inicial,
      firstDate: DateTime(2020),
      lastDate: DateTime.now().add(const Duration(days: 30)),
      helpText: 'Selecciona el mes',
    );
    if (picked != null) {
      setState(() {
        _mesSel = picked.month;
        _anioSel = picked.year;
        // Al cambiar de mes SÍ limpiamos las compras manuales —
        // las compras pertenecen al mes en análisis. (Si quieres
        // que persistan por mes en BD, sería un módulo aparte.)
        _compras.clear();
      });
      await _cargarDatosDelSistema();
    }
  }

  /// Refleja las compras de la pestaña Compras en el inventario.
  ///
  /// Para cada producto: suma todas las unidades compradas en el mes
  /// y calcula el precio promedio ponderado de compra. Eso llena
  /// `comprasUnidades` y `precioUnitarioCompra` del ItemInventarioCF.
  ///
  /// Se llama:
  ///  · Al final de _cargarDatosDelSistema (con _compras vacía o no)
  ///  · Cada vez que el usuario edita una fila en la pestaña Compras
  ///    (vía setState en el callback de los TextFields)
  void _recalcularInventarioConCompras() {
    // Agrupar compras por nombre de producto.
    final agreg = <String, _AggCompra>{};
    for (final c in _compras) {
      final key = c.producto.trim();
      if (key.isEmpty) continue;
      final a = agreg.putIfAbsent(key, () => _AggCompra());
      a.unidades   += c.cantidad;
      a.totalUsd   += c.totalCompraUsd;
    }
    // Aplicar al inventario
    for (final inv in _inventario) {
      final a = agreg[inv.concepto.trim()];
      if (a == null) {
        inv.comprasUnidades = 0;
        inv.precioUnitarioCompra = 0;
      } else {
        inv.comprasUnidades = a.unidades;
        inv.precioUnitarioCompra =
            a.unidades > 0 ? (a.totalUsd / a.unidades) : 0;
      }
    }
  }

  /// Genera y comparte un reporte Excel del mes (Resumen + Ventas +
  /// Inventario + Nómina). Útil al cierre de mes.
  Future<void> _generarReporteFinDeMes() async {
    try {
      final excel = Excel.createExcel();
      excel.delete('Sheet1');

      // ── Hoja Resumen ──
      final s = excel['Resumen'];
      s.appendRow([TextCellValue(
          'Reporte Mensual — ${_nombresMes[_mesSel-1]} $_anioSel')]);
      s.appendRow([TextCellValue('')]);
      s.appendRow([TextCellValue('Concepto'), TextCellValue('USD'),
          TextCellValue('Bs')]);
      s.appendRow([TextCellValue('Total Ventas'),
          DoubleCellValue(_totalVentasUsd),
          DoubleCellValue(_totalVentasBs)]);
      s.appendRow([TextCellValue('Costo de ventas'),
          DoubleCellValue(_costoVentas),
          DoubleCellValue(_costoVentas * _tasaBinanceVentas)]);
      s.appendRow([TextCellValue('Utilidad bruta'),
          DoubleCellValue(_utilidadBruta),
          DoubleCellValue(_utilidadBruta * _tasaBinanceVentas)]);
      s.appendRow([TextCellValue('Total Nómina'),
          DoubleCellValue(_totalNomina),
          DoubleCellValue(_totalNomina * _tasaBinanceVentas)]);
      s.appendRow([TextCellValue('Total Gastos'),
          DoubleCellValue(_totalGastos),
          DoubleCellValue(_totalGastos * _tasaBinanceVentas)]);
      s.appendRow([TextCellValue('Utilidad NETA'),
          DoubleCellValue(_utilidadNeta),
          DoubleCellValue(_utilidadNeta * _tasaBinanceVentas)]);

      // ── Hoja Ventas ──
      final sv = excel['Ventas'];
      sv.appendRow([TextCellValue('Fecha'), TextCellValue('Producto'),
          TextCellValue('Cant.'), TextCellValue('P. Unit USD'),
          TextCellValue('Total USD'), TextCellValue('Total Bs')]);
      for (final v in _ventas) {
        sv.appendRow([
          TextCellValue(v.fecha == null ? '' :
              '${v.fecha!.day.toString().padLeft(2,"0")}/'
              '${v.fecha!.month.toString().padLeft(2,"0")}/${v.fecha!.year}'),
          TextCellValue(v.producto),
          DoubleCellValue(v.cantidad),
          DoubleCellValue(v.precioUnitario),
          DoubleCellValue(v.totalVentaUsd),
          DoubleCellValue(v.totalVentaBs),
        ]);
      }

      // ── Hoja Inventario ──
      final si = excel['Inventario'];
      si.appendRow([TextCellValue('Producto'),
          TextCellValue('Inv. inicial uds'),
          TextCellValue('Compras uds'),
          TextCellValue('Ventas uds'),
          TextCellValue('Inv. final uds'),
          TextCellValue('Valor final USD')]);
      for (final i in _inventario) {
        si.appendRow([
          TextCellValue(i.concepto),
          DoubleCellValue(i.invInicialUnidades),
          DoubleCellValue(i.comprasUnidades),
          DoubleCellValue(i.ventaUnidades),
          DoubleCellValue(i.inventarioFinalUnidades),
          DoubleCellValue(i.inventarioFinalValorado),
        ]);
      }

      // ── Hoja Nómina ──
      final sn = excel['Nomina'];
      sn.appendRow([TextCellValue('Empleado'),
          TextCellValue('Comisiones USD'),
          TextCellValue(
              'Bs (tasa ${_tasaBinanceVentas.toStringAsFixed(2)})')]);
      for (final n in _nomina) {
        sn.appendRow([
          TextCellValue(n.cargo),
          DoubleCellValue(n.comisiones),
          DoubleCellValue(n.comisiones * _tasaBinanceVentas),
        ]);
      }

      final bytes = excel.encode();
      if (bytes == null) throw 'No se pudo generar Excel';
      final nombre = 'Reporte_${_nombresMes[_mesSel-1]}_$_anioSel.xlsx';
      await descargarArchivo(
        Uint8List.fromList(bytes),
        nombre,
        'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      );
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(SnackBar(
          content: Text('✅ Reporte $nombre generado'),
          backgroundColor: AppColors.statusGreen));
    } catch (e) {
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(SnackBar(
          content: Text('Error al generar reporte: $e'),
          backgroundColor: AppColors.statusRed));
    }
  }

  // ── Cálculos globales ─────────────────────────────────────
  double get _totalVentasUsd => _ventas.fold(0, (s, v) => s + v.totalVentaUsd);
  double get _totalVentasBs => _ventas.fold(0, (s, v) => s + v.totalVentaBs);
  double get _costoVentas => _inventario.fold(0, (s, i) => s + i.costoTotalSalida);
  double get _utilidadBruta => _totalVentasUsd - _costoVentas;
  double get _totalGastosAdmin => _gastosAdmin.fold(0, (s, g) => s + g.monto);
  double get _totalGastosOper => _gastosOperacion.fold(0, (s, g) => s + g.monto);
  double get _totalGastosInv => _gastosInversion.fold(0, (s, g) => s + g.monto);
  double get _totalGastos => _totalGastosAdmin + _totalGastosOper + _totalGastosInv;
  double get _utilidadOperativa => _utilidadBruta - _totalGastos;
  double get _otrosIngresos => _otrosMovimientos.where((o) => o.esIngreso).fold(0, (s, o) => s + o.monto);
  double get _otrosEgresos => _otrosMovimientos.where((o) => !o.esIngreso).fold(0, (s, o) => s + o.monto);
  double get _utilidadNeta => _utilidadOperativa + _otrosIngresos - _otrosEgresos;
  double get _totalNomina => _nomina.fold(0, (s, n) => s + n.total);

  // Punto de equilibrio
  double get _precioPromedioVenta {
    if (_ventas.isEmpty) return 0;
    final totalCantidad = _ventas.fold(0.0, (s, v) => s + v.cantidad);
    return totalCantidad == 0 ? 0 : _totalVentasUsd / totalCantidad;
  }
  double get _costoVariableUnitario {
    if (_compras.isEmpty) return 0;
    final totalCantidad = _compras.fold(0.0, (s, c) => s + c.cantidad);
    return totalCantidad == 0 ? 0 : _compras.fold(0.0, (s, c) => s + c.totalCompraUsd) / totalCantidad;
  }
  double get _peUnidades {
    final margen = _precioPromedioVenta - _costoVariableUnitario;
    return margen == 0 ? 0 : _totalGastosAdmin / margen;
  }
  double get _peFinanciero => _peUnidades * _precioPromedioVenta;

  // Carga financiera PMT
  double get _cuotaMes {
    if (_capitalPrestamo <= 0 || _tasaInteresPct <= 0 || _plazoAnios <= 0) return 0;
    final r = _tasaInteresPct / 100 / 12;
    final n = _plazoAnios * 12;
    return _capitalPrestamo * r * _pow(1 + r, n) / (_pow(1 + r, n) - 1);
  }

  double _pow(double base, double exp) => math.pow(base, exp).toDouble();

  // ── Helpers UI ───────────────────────────────────────────
  Widget _cardTitulo(String titulo, IconData icon, Color color, Widget child) {
    return Card(
      elevation: 2,
      margin: const EdgeInsets.symmetric(vertical: 6),
      child: Column(children: [
        Container(
          width: double.infinity,
          padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 10),
          decoration: BoxDecoration(
            color: color.withOpacity(0.1),
            borderRadius: const BorderRadius.vertical(top: Radius.circular(12)),
          ),
          child: Row(children: [
            Icon(icon, color: color, size: 18),
            const SizedBox(width: 8),
            Text(titulo, style: TextStyle(fontWeight: FontWeight.bold, color: color, fontSize: 14)),
          ]),
        ),
        Padding(padding: const EdgeInsets.all(12), child: child),
      ]),
    );
  }

  Widget _fila(String label, String valor, {Color? color}) {
    return Padding(
      padding: const EdgeInsets.symmetric(vertical: 4),
      child: Row(mainAxisAlignment: MainAxisAlignment.spaceBetween, children: [
        Expanded(child: Text(label, style: const TextStyle(fontSize: 12, color: Colors.grey))),
        Text(valor, style: TextStyle(fontWeight: FontWeight.bold, fontSize: 12, color: color)),
      ]),
    );
  }

  Widget _inputNum(String label, double value, Function(double) onChanged, {int maxLines = 1}) {
    return Padding(
      padding: const EdgeInsets.symmetric(vertical: 4),
      child: TextFormField(
        initialValue: value == 0 ? '' : value.toStringAsFixed(2),
        keyboardType: const TextInputType.numberWithOptions(decimal: true),
        decoration: InputDecoration(
          labelText: label, isDense: true,
          border: const OutlineInputBorder(),
          filled: true,
          fillColor: Colors.grey[50],
        ),
        onChanged: (v) => onChanged(double.tryParse(v) ?? 0),
      ),
    );
  }

  Widget _inputTxt(String label, String value, Function(String) onChanged) {
    return Padding(
      padding: const EdgeInsets.symmetric(vertical: 4),
      child: TextFormField(
        initialValue: value,
        decoration: InputDecoration(
          labelText: label, isDense: true,
          border: const OutlineInputBorder(),
          filled: true, fillColor: Colors.grey[50],
        ),
        onChanged: onChanged,
      ),
    );
  }

  // ── TABS ─────────────────────────────────────────────────

  bool get _tieneAcceso =>
      (usuarioSesion?.rol == "Administrador" || usuarioSesion?.rol == "Maestro") ||
      (usuarioSesion?.rol == "Gerente" || usuarioSesion?.rol == "Maestro") ||
      (usuarioSesion?.rol == "Dueño" || usuarioSesion?.rol == "Maestro");

  @override
  Widget build(BuildContext context) {
    if (!_tieneAcceso) {
      return const Scaffold(
        backgroundColor: Color(0xFFF5F5F5),
        body: Center(
          child: Column(mainAxisAlignment: MainAxisAlignment.center, children: [
            Icon(Icons.lock_outline, size: 72, color: Colors.grey),
            SizedBox(height: 16),
            Text("Acceso restringido", style: TextStyle(fontSize: 20, fontWeight: FontWeight.bold, color: Colors.grey)),
            SizedBox(height: 8),
            Text("Solo Administradores, Gerentes y Dueños pueden ver esta sección.",
              textAlign: TextAlign.center,
              style: TextStyle(color: Colors.grey)),
          ]),
        ),
      );
    }
    return Scaffold(
      backgroundColor: AppColors.surfaceTintBlue,
      appBar: PreferredSize(
        // Aumentamos altura para incluir una barra de mes/acciones
        // arriba del TabBar.
        preferredSize: const Size.fromHeight(kToolbarHeight + 48),
        child: Container(
          color: const Color(0xFF1E3A5F),
          child: Column(children: [
            // ── Barra superior con mes activo + acciones ──────
            SafeArea(
              bottom: false,
              child: Container(
                height: 48,
                padding: const EdgeInsets.symmetric(horizontal: 8),
                child: Row(children: [
                  // Selector de mes
                  Expanded(child: InkWell(
                    onTap: _cargandoAuto ? null : _cambiarMes,
                    borderRadius: BorderRadius.circular(8),
                    child: Container(
                      padding: const EdgeInsets.symmetric(
                          horizontal: 10, vertical: 6),
                      decoration: BoxDecoration(
                        color: Colors.white.withValues(alpha: 0.12),
                        borderRadius: BorderRadius.circular(8),
                      ),
                      child: Row(children: [
                        const Icon(Icons.calendar_month,
                            color: Colors.white, size: 18),
                        const SizedBox(width: 6),
                        Expanded(child: Text(
                          'Mes: ${_nombresMes[_mesSel-1]} $_anioSel',
                          style: const TextStyle(
                              color: Colors.white,
                              fontWeight: FontWeight.w600,
                              fontSize: 13))),
                        const Icon(Icons.arrow_drop_down,
                            color: Colors.white, size: 18),
                      ]),
                    ),
                  )),
                  const SizedBox(width: 6),
                  // Recargar datos del mes
                  IconButton(
                    icon: _cargandoAuto
                        ? const SizedBox(width: 18, height: 18,
                            child: CircularProgressIndicator(
                                color: Colors.white, strokeWidth: 2))
                        : const Icon(Icons.refresh, color: Colors.white),
                    tooltip: 'Recargar datos',
                    onPressed: _cargandoAuto
                        ? null : _cargarDatosDelSistema,
                  ),
                  // Generar reporte de cierre de mes
                  IconButton(
                    icon: const Icon(Icons.summarize_outlined,
                        color: Colors.amber),
                    tooltip: 'Generar reporte del mes (Excel)',
                    onPressed: _generarReporteFinDeMes,
                  ),
                ]),
              ),
            ),
            // ── TabBar con las 9 secciones ──────────────────
            TabBar(
              controller: _tabs,
              labelColor: Colors.white,
              unselectedLabelColor: Colors.white54,
              indicatorColor: Colors.amber,
              isScrollable: true,
              tabs: const [
                Tab(icon: Icon(Icons.inventory_2_outlined, size: 18), text: "Inventario"),
                Tab(icon: Icon(Icons.shopping_cart_outlined, size: 18), text: "Compras"),
                Tab(icon: Icon(Icons.point_of_sale_outlined, size: 18), text: "Ventas"),
                Tab(icon: Icon(Icons.people_outline, size: 18), text: "Nómina"),
                Tab(icon: Icon(Icons.receipt_long_outlined, size: 18), text: "Gastos"),
                Tab(icon: Icon(Icons.balance_outlined, size: 18), text: "P. Equilibrio"),
                Tab(icon: Icon(Icons.bar_chart_outlined, size: 18), text: "Resultados"),
                Tab(icon: Icon(Icons.account_balance_outlined, size: 18), text: "Carga Fin."),
                Tab(icon: Icon(Icons.waterfall_chart_outlined, size: 18), text: "Flujo Caja"),
              ],
            ),
          ]),
        ),
      ),
      body: TabBarView(controller: _tabs, children: [
        _tabInventario(),
        _tabCompras(),
        _tabVentas(),
        _tabNomina(),
        _tabGastos(),
        _tabPuntoEquilibrio(),
        _tabResultados(),
        _tabCargaFinanciera(),
        _tabFlujoCaja(),
      ]),
      floatingActionButton: FloatingActionButton.extended(
        backgroundColor: const Color(0xFF1E3A5F),
        icon: const Icon(Icons.add, color: Colors.white),
        label: const Text("Agregar fila", style: TextStyle(color: Colors.white)),
        onPressed: _agregarFilaSegunTab,
      ),
    );
  }

  void _agregarFilaSegunTab() {
    setState(() {
      switch (_tabs.index) {
        case 0: _inventario.add(ItemInventarioCF()); break;
        case 1:
          _compras.add(ItemComprasCF(
              fecha: DateTime.now(), tasaDia: _tasaBinanceCompras));
          _recalcularInventarioConCompras();
          break;
        case 2: _ventas.add(ItemVentasCF(fecha: DateTime.now(), tasaDia: _tasaBinanceVentas)); break;
        case 3: _nomina.add(ItemNominaCF()); break;
        case 4: _gastosAdmin.add(ItemGastoCF()); break;
        case 7: break; // Carga financiera no agrega filas
        default: break;
      }
    });
  }

