  // ── TAB COMPRAS ────────────────────────────────────────
  Widget _tabCompras() {
    final totalUsd = _compras.fold(0.0, (s, c) => s + c.totalCompraUsd);
    final totalBs = _compras.fold(0.0, (s, c) => s + c.totalCompraBs);

    return SingleChildScrollView(
      padding: const EdgeInsets.all(12),
      child: Column(children: [
        _cardTitulo("Configuración", Icons.settings, Colors.grey, Row(children: [
          Expanded(child: _inputNum("Tasa Binance del período", _tasaBinanceCompras, (v) => setState(() => _tasaBinanceCompras = v))),
        ])),
        _cardTitulo("Compras", Icons.shopping_cart, Colors.teal, Column(children: [
          Row(children: [
            Expanded(child: _kpiMini("Total Compras \$", "\$${totalUsd.toStringAsFixed(2)}", Colors.teal)),
            const SizedBox(width: 8),
            Expanded(child: _kpiMini("Total Compras Bs", "Bs ${totalBs.toStringAsFixed(2)}", Colors.blueGrey)),
          ]),
          const SizedBox(height: 12),
          SingleChildScrollView(
            scrollDirection: Axis.horizontal,
            child: DataTable(
              headingRowColor: WidgetStateProperty.all(Colors.teal[50]),
              columnSpacing: 12,
              headingTextStyle: const TextStyle(fontSize: 11, fontWeight: FontWeight.bold, color: Colors.teal),
              dataTextStyle: const TextStyle(fontSize: 11),
              columns: const [
                DataColumn(label: Text("Fecha")),
                DataColumn(label: Text("Producto")),
                DataColumn(label: Text("Cantidad")),
                DataColumn(label: Text("Tasa Día")),
                DataColumn(label: Text("P.Unitario")),
                DataColumn(label: Text("Total \$")),
                DataColumn(label: Text("Total Bs")),
                DataColumn(label: Text("Acc.")),
              ],
              rows: _compras.asMap().entries.map((e) {
                final c = e.value;
                final idx = e.key;
                // Cualquier cambio en una fila de compras debe
                // reflejarse en el inventario y en los cálculos
                // dependientes. Llamamos al recálculo dentro del
                // setState para que sea inmediato.
                void cambio(VoidCallback aplicar) {
                  setState(() {
                    aplicar();
                    _recalcularInventarioConCompras();
                  });
                }
                return DataRow(cells: [
                  DataCell(_editableCell(_formatFecha(c.fecha), (v) {})),
                  DataCell(_editableCell(c.producto,
                      (v) => cambio(() => c.producto = v))),
                  DataCell(_numCell(c.cantidad,
                      (v) => cambio(() => c.cantidad = v))),
                  DataCell(_numCell(c.tasaDia,
                      (v) => cambio(() => c.tasaDia = v))),
                  DataCell(_numCell(c.precioUnitario,
                      (v) => cambio(() => c.precioUnitario = v))),
                  DataCell(Text(c.totalCompraUsd.toStringAsFixed(2), style: const TextStyle(color: Colors.teal))),
                  DataCell(Text(c.totalCompraBs.toStringAsFixed(2), style: const TextStyle(color: Colors.blueGrey))),
                  DataCell(IconButton(icon: const Icon(Icons.delete_outline, color: Colors.red, size: 18),
                    onPressed: () => cambio(() => _compras.removeAt(idx)))),
                ]);
              }).toList(),
            ),
          ),
          if (_compras.isEmpty)
            const Padding(padding: EdgeInsets.all(24), child: Center(child: Text("Sin registros. Presiona + para agregar.", style: TextStyle(color: Colors.grey)))),
        ])),
      ]),
    );
  }

