  // ── TAB RESULTADOS ─────────────────────────────────────
  Widget _tabResultados() {
    final pctUB = _totalVentasUsd == 0 ? 0.0 : _utilidadBruta / _totalVentasUsd * 100;
    final pctUO = _totalVentasUsd == 0 ? 0.0 : _utilidadOperativa / _totalVentasUsd * 100;
    final pctUN = _totalVentasUsd == 0 ? 0.0 : _utilidadNeta / _totalVentasUsd * 100;

    return SingleChildScrollView(
      padding: const EdgeInsets.all(16),
      child: Column(children: [
        _cardTitulo("Estado de Resultados", Icons.bar_chart, AppColors.brandBlue, Column(children: [
          _filaResultado("INGRESOS POR VENTAS", _totalVentasUsd, _totalVentasBs, 100, Colors.green),
          const Divider(),
          _filaResultado("(-) COSTO DE VENTAS", _costoVentas, _costoVentas * ConfigSistema.tasaCambio,
              _totalVentasUsd == 0 ? 0 : _costoVentas / _totalVentasUsd * 100, Colors.red),
          _filaResultadoBold("UTILIDAD BRUTA EN VENTAS", _utilidadBruta, _utilidadBruta * ConfigSistema.tasaCambio, pctUB, _utilidadBruta >= 0 ? Colors.green : Colors.red),
          const Divider(),
          _filaResultado("(-) GASTOS DE ADMINISTRACIÓN", _totalGastosAdmin, _totalGastosAdmin * ConfigSistema.tasaCambio,
              _totalVentasUsd == 0 ? 0 : _totalGastosAdmin / _totalVentasUsd * 100, Colors.orange),
          _filaResultado("(-) GASTOS DE OPERACIÓN", _totalGastosOper, _totalGastosOper * ConfigSistema.tasaCambio,
              _totalVentasUsd == 0 ? 0 : _totalGastosOper / _totalVentasUsd * 100, Colors.orange),
          _filaResultado("(-) GASTOS DE INVERSIÓN", _totalGastosInv, _totalGastosInv * ConfigSistema.tasaCambio,
              _totalVentasUsd == 0 ? 0 : _totalGastosInv / _totalVentasUsd * 100, Colors.orange),
          _filaResultado("TOTAL GASTOS", _totalGastos, _totalGastos * ConfigSistema.tasaCambio,
              _totalVentasUsd == 0 ? 0 : _totalGastos / _totalVentasUsd * 100, Colors.deepOrange),
          _filaResultadoBold("UTILIDAD OPERATIVA", _utilidadOperativa, _utilidadOperativa * ConfigSistema.tasaCambio, pctUO, _utilidadOperativa >= 0 ? Colors.green : Colors.red),
          const Divider(),
          _filaResultado("(+) OTROS INGRESOS", _otrosIngresos, _otrosIngresos * ConfigSistema.tasaCambio, 0, Colors.teal),
          _filaResultado("(-) OTROS EGRESOS", _otrosEgresos, _otrosEgresos * ConfigSistema.tasaCambio, 0, Colors.pink),
          const Divider(),
          _filaResultadoBold("UTILIDAD NETA DEL PERÍODO", _utilidadNeta, _utilidadNeta * ConfigSistema.tasaCambio, pctUN, _utilidadNeta >= 0 ? Colors.green[800]! : Colors.red[800]!),
        ])),
      ]),
    );
  }

