// ════════════════════════════════════════════════════════════════════
//  CALCULADORA DE PRESTACIONES SOCIALES LOTTT (Venezuela)
//
//  Basada en el modelo de cálculo de la Ley Orgánica del Trabajo,
//  los Trabajadores y las Trabajadoras (LOTTT).
//
//  Conceptos calculados:
//   · Literal (a): 15 días de salario integral x trimestre (después 3er mes)
//   · Literal (b): 60 días de salario integral por año (aplica al 1er año)
//   · Literal (c): 30 días de salario integral por año completo
//   · Días adicionales (Art. 71 RLOT): 2 días/año a partir del 2do año
//   · Intereses sobre prestaciones (tasa BCV)
//
//  El cálculo final toma el MAYOR entre:
//    · (Literal a + Literal b) → Régimen trimestral
//    · (Literal c)             → Régimen antigüedad (30 días/año)
// ════════════════════════════════════════════════════════════════════

/// Datos de un mes en el cálculo de prestaciones LOTTT.
class MesPrestacion {
  DateTime fechaDesde;
  DateTime fechaHasta;
  double salarioMensual;       // Salario mensual (Bs o USD)
  int diasBonoVacacional;      // Art. 192 LOTTT: 15 días mínimo + 1 por año
  int diasUtilidades;          // Art. 131 LOTTT: 30 días mínimo, 60 días máximo
  double tasaInteres;          // Tasa BCV del mes (ej: 0.30 = 30%)
  double anticipo;             // Anticipo de prestaciones del mes (75% máx)
  double anticipoIntereses;    // Anticipo de intereses del mes

  MesPrestacion({
    required this.fechaDesde,
    required this.fechaHasta,
    required this.salarioMensual,
    this.diasBonoVacacional = 15,
    this.diasUtilidades = 30,
    this.tasaInteres = 0.30,
    this.anticipo = 0,
    this.anticipoIntereses = 0,
  });

  // ── CÁLCULOS DERIVADOS (fórmulas del Excel) ────────────────
  /// Salario Normal Diario = Salario / 30
  double get salarioNormalDiario => salarioMensual / 30;

  /// Alícuota Bono Vacacional = (Salario diario × Días BV) / 360
  double get alicuotaBonoVacacional =>
    (salarioNormalDiario * diasBonoVacacional) / 360;

  /// Alícuota Utilidades = (Salario diario × Días utilidades) / 360
  double get alicuotaUtilidades =>
    (salarioNormalDiario * diasUtilidades) / 360;

  /// Salario Integral = Salario diario + Alícuota BV + Alícuota Utilidades
  double get salarioIntegral =>
    salarioNormalDiario + alicuotaBonoVacacional + alicuotaUtilidades;
}

/// Resultado del cálculo completo de prestaciones de un trabajador.
class ResultadoPrestaciones {
  final String nombreTrabajador;
  final String cedula;
  final String cargo;
  final DateTime fechaIngreso;
  final DateTime fechaEgreso;

  final List<MesPrestacion> meses;

  // ── Totales calculados ──
  final double literalAyB;         // Prestaciones régimen trimestral
  final double literalC;           // 30 días × año (antigüedad)
  final double diasAdicionales;    // Días adicionales Art. 71 RLOT
  final double totalPrestaciones;  // MAYOR entre (a+b) y (c)
  final double interesesAcumulados;
  final double totalAnticipos;
  final double totalAnticiposIntereses;
  final double netoPrestaciones;
  final double netoIntereses;
  final int tiempoServicioAnios;
  final int tiempoServicioMeses;
  final int tiempoServicioDias;

  ResultadoPrestaciones({
    required this.nombreTrabajador,
    required this.cedula,
    required this.cargo,
    required this.fechaIngreso,
    required this.fechaEgreso,
    required this.meses,
    required this.literalAyB,
    required this.literalC,
    required this.diasAdicionales,
    required this.totalPrestaciones,
    required this.interesesAcumulados,
    required this.totalAnticipos,
    required this.totalAnticiposIntereses,
    required this.netoPrestaciones,
    required this.netoIntereses,
    required this.tiempoServicioAnios,
    required this.tiempoServicioMeses,
    required this.tiempoServicioDias,
  });
}

/// Calculadora principal LOTTT.
class CalculadoraLOTTT {
  /// Calcula las prestaciones completas para un trabajador.
  ///
  /// Reglas aplicadas:
  /// - Literal (a): 15 días × trimestre de servicio después del 3er mes
  /// - Literal (b): 60 días del salario integral × año (primer año completo)
  /// - Literal (c): 30 días × año completo al salario integral actual
  /// - Art. 71 RLOT: 2 días adicionales/año a partir del 2do año (máx 30)
  /// - Intereses mensuales acumulativos según tasa BCV
  static ResultadoPrestaciones calcular({
    required String nombreTrabajador,
    required String cedula,
    required String cargo,
    required DateTime fechaIngreso,
    required DateTime fechaEgreso,
    required List<MesPrestacion> meses,
  }) {
    // ── 1) Calcular tiempo de servicio ──
    final Duration diferencia = fechaEgreso.difference(fechaIngreso);
    final int totalDias = diferencia.inDays;
    final int anios = totalDias ~/ 365;
    final int diasRestantes = totalDias - (anios * 365);
    final int mesesExtra = diasRestantes ~/ 30;
    final int diasFinales = diasRestantes - (mesesExtra * 30);

    // ── 2) Variables acumuladoras ──
    double prestacionesAcum = 0;       // V: prestaciones acumuladas
    double anticiposAcum = 0;           // X: anticipos acumulados
    double interesesAcum = 0;           // AB: intereses acumulados
    double interesesPagados = 0;        // AD: anticipos de intereses
    double diasAdicionalesAcum = 0;     // Días Art. 71 RLOT

    // ── 3) Iterar mes por mes ──
    for (int i = 0; i < meses.length; i++) {
      final m = meses[i];

      // --- DÍAS PRESTACIONES DEL MES ---
      // Patrón LOTTT: se acreditan 15 días cada trimestre (3 meses)
      // después del 1er trimestre de servicio.
      // Desde el 4° mes en adelante: cada 3 meses = 15 días
      int diasPrestacionesMes = 0;
      if (i >= 3 && (i - 3) % 3 == 0) {
        diasPrestacionesMes = 15;
      }

      // --- VALOR PRESTACIONES DEL MES ---
      // Salario integral del mes × días del mes
      final double valorPrestacionMes =
        m.salarioIntegral * diasPrestacionesMes;

      // --- DÍAS ADICIONALES (Art. 71 RLOT / Literal b) ---
      // 2 días/año a partir del 2do año de servicio
      // Se acredita en el aniversario (cada 12 meses tras cumplir 1 año)
      int diasAdicionalesMes = 0;
      if (i >= 12 && (i - 12) % 12 == 0) {
        final int aniosCumplidos = ((i - 12) ~/ 12) + 1;
        diasAdicionalesMes = 2 * aniosCumplidos;
        // Máximo 30 días adicionales
        if (diasAdicionalesMes > 30) diasAdicionalesMes = 30;
      }
      diasAdicionalesAcum += diasAdicionalesMes;

      final double valorAdicionalesMes =
        m.salarioIntegral * diasAdicionalesMes;

      // --- ACUMULAR PRESTACIONES Y ANTICIPOS ---
      prestacionesAcum += valorPrestacionMes + valorAdicionalesMes;
      anticiposAcum += m.anticipo;
      final double neto = prestacionesAcum - anticiposAcum;

      // --- INTERESES MENSUALES ---
      // Interés mensual = neto × (tasa / 12)
      final double interesMes = neto * (m.tasaInteres / 12);
      interesesAcum += interesMes;
      interesesPagados += m.anticipoIntereses;
    }

    final double netoPrestaciones = prestacionesAcum - anticiposAcum;
    final double netoIntereses = interesesAcum - interesesPagados;

    // ── 4) Calcular LITERAL C (30 días × año al último salario integral) ──
    double ultimoSalarioIntegral = meses.isNotEmpty
      ? meses.last.salarioIntegral : 0;
    final double literalC = ultimoSalarioIntegral * 30 * anios;

    // ── 5) Literal (a+b) = prestaciones acumuladas
    final double literalAyB = prestacionesAcum;

    // ── 6) Total prestaciones = MAYOR entre (a+b) y c
    final double totalPrestaciones =
      literalAyB > literalC ? literalAyB : literalC;

    return ResultadoPrestaciones(
      nombreTrabajador: nombreTrabajador,
      cedula: cedula,
      cargo: cargo,
      fechaIngreso: fechaIngreso,
      fechaEgreso: fechaEgreso,
      meses: meses,
      literalAyB: literalAyB,
      literalC: literalC,
      diasAdicionales: diasAdicionalesAcum,
      totalPrestaciones: totalPrestaciones,
      interesesAcumulados: interesesAcum,
      totalAnticipos: anticiposAcum,
      totalAnticiposIntereses: interesesPagados,
      netoPrestaciones: netoPrestaciones,
      netoIntereses: netoIntereses,
      tiempoServicioAnios: anios,
      tiempoServicioMeses: mesesExtra,
      tiempoServicioDias: diasFinales,
    );
  }
}

// ════════════════════════════════════════════════════════════════════
//  VENTANA: Calculadora de Prestaciones Sociales LOTTT
// ════════════════════════════════════════════════════════════════════
class VentanaPrestacionesSociales extends StatefulWidget {
  const VentanaPrestacionesSociales({super.key});
  @override
  State<VentanaPrestacionesSociales> createState() =>
    _VentanaPrestacionesSocialesState();
}

class _VentanaPrestacionesSocialesState
    extends State<VentanaPrestacionesSociales> {

  // ── Datos del trabajador ──
  final _nombreCtrl = TextEditingController();
  final _cedulaCtrl = TextEditingController();
  final _cargoCtrl = TextEditingController();
  DateTime? _fechaIngreso;
  DateTime? _fechaEgreso;

  // ── Lista de meses configurados ──
  final List<MesPrestacion> _meses = [];

  // ── Parámetros globales ──
  int _diasBVPorDefecto = 15;
  int _diasUtilidadesPorDefecto = 30;
  double _tasaInteresPorDefecto = 0.30;
  final _salarioPorDefectoCtrl = TextEditingController();

  ResultadoPrestaciones? _resultado;

  @override
  void dispose() {
    _nombreCtrl.dispose();
    _cedulaCtrl.dispose();
    _cargoCtrl.dispose();
    _salarioPorDefectoCtrl.dispose();
    super.dispose();
  }

  // ── Generar meses automáticamente entre dos fechas ─────────
  void _generarMeses() {
    if (_fechaIngreso == null || _fechaEgreso == null) {
      ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
        content: Text("Seleccione fecha de ingreso y egreso primero"),
        backgroundColor: AppColors.statusRed));
      return;
    }
    if (_fechaEgreso!.isBefore(_fechaIngreso!)) {
      ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
        content: Text("La fecha de egreso debe ser posterior al ingreso"),
        backgroundColor: AppColors.statusRed));
      return;
    }
    final salarioDefault =
      double.tryParse(_salarioPorDefectoCtrl.text) ?? 0;
    if (salarioDefault <= 0) {
      ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
        content: Text("Ingrese un salario inicial válido"),
        backgroundColor: AppColors.statusRed));
      return;
    }

    setState(() {
      _meses.clear();
      DateTime actual = _fechaIngreso!;
      while (actual.isBefore(_fechaEgreso!) ||
             actual.isAtSameMomentAs(_fechaEgreso!)) {
        final siguiente = DateTime(actual.year,
          actual.month + 1, actual.day);
        _meses.add(MesPrestacion(
          fechaDesde: actual,
          fechaHasta: siguiente,
          salarioMensual: salarioDefault,
          diasBonoVacacional: _diasBVPorDefecto,
          diasUtilidades: _diasUtilidadesPorDefecto,
          tasaInteres: _tasaInteresPorDefecto,
        ));
        actual = siguiente;
      }
    });
    ScaffoldMessenger.of(context).showSnackBar(SnackBar(
      content: Text("Se generaron ${_meses.length} meses"),
      backgroundColor: AppColors.statusGreen));
  }

  // ── Calcular prestaciones ──────────────────────────────────
  void _calcular() {
    if (_fechaIngreso == null || _fechaEgreso == null ||
        _nombreCtrl.text.trim().isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
        content: Text("Complete todos los datos del trabajador"),
        backgroundColor: AppColors.statusRed));
      return;
    }
    if (_meses.isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
        content: Text("Debe generar al menos un mes de cálculo"),
        backgroundColor: AppColors.statusOrange));
      return;
    }
    setState(() {
      _resultado = CalculadoraLOTTT.calcular(
        nombreTrabajador: _nombreCtrl.text.trim(),
        cedula: _cedulaCtrl.text.trim(),
        cargo: _cargoCtrl.text.trim(),
        fechaIngreso: _fechaIngreso!,
        fechaEgreso: _fechaEgreso!,
        meses: _meses,
      );
    });
  }

  // ── Editar un mes específico ───────────────────────────────
  Future<void> _editarMes(int idx) async {
    final m = _meses[idx];
    final salarioCtrl = TextEditingController(
      text: m.salarioMensual.toStringAsFixed(2));
    final bvCtrl = TextEditingController(
      text: m.diasBonoVacacional.toString());
    final utilCtrl = TextEditingController(
      text: m.diasUtilidades.toString());
    final tasaCtrl = TextEditingController(
      text: (m.tasaInteres * 100).toStringAsFixed(2));
    final anticipoCtrl = TextEditingController(
      text: m.anticipo.toStringAsFixed(2));
    final anticIntCtrl = TextEditingController(
      text: m.anticipoIntereses.toStringAsFixed(2));

    await showDialog(context: context, builder: (ctx) => AlertDialog(
      title: Text("Mes ${idx + 1}: "
        "${m.fechaDesde.day}/${m.fechaDesde.month}/${m.fechaDesde.year}"),
      content: SingleChildScrollView(child: Column(
        mainAxisSize: MainAxisSize.min, children: [
        TextField(controller: salarioCtrl,
          keyboardType: TextInputType.number,
          decoration: const InputDecoration(
            labelText: "Salario mensual",
            prefixIcon: Icon(Icons.attach_money))),
        const SizedBox(height: 10),
        TextField(controller: bvCtrl,
          keyboardType: TextInputType.number,
          decoration: const InputDecoration(
            labelText: "Días Bono Vacacional",
            hintText: "15 mínimo",
            prefixIcon: Icon(Icons.beach_access))),
        const SizedBox(height: 10),
        TextField(controller: utilCtrl,
          keyboardType: TextInputType.number,
          decoration: const InputDecoration(
            labelText: "Días Utilidades",
            hintText: "30 mínimo",
            prefixIcon: Icon(Icons.card_giftcard))),
        const SizedBox(height: 10),
        TextField(controller: tasaCtrl,
          keyboardType: TextInputType.number,
          decoration: const InputDecoration(
            labelText: "Tasa BCV (%)",
            hintText: "Ej: 30",
            prefixIcon: Icon(Icons.percent))),
        const SizedBox(height: 10),
        TextField(controller: anticipoCtrl,
          keyboardType: TextInputType.number,
          decoration: const InputDecoration(
            labelText: "Anticipo prestaciones",
            prefixIcon: Icon(Icons.account_balance_wallet))),
        const SizedBox(height: 10),
        TextField(controller: anticIntCtrl,
          keyboardType: TextInputType.number,
          decoration: const InputDecoration(
            labelText: "Anticipo intereses",
            prefixIcon: Icon(Icons.account_balance))),
      ])),
      actions: [
        TextButton(onPressed: () => Navigator.pop(ctx),
          child: const Text("Cancelar")),
        ElevatedButton(onPressed: () {
          setState(() {
            m.salarioMensual = double.tryParse(salarioCtrl.text) ?? 0;
            m.diasBonoVacacional = int.tryParse(bvCtrl.text) ?? 15;
            m.diasUtilidades = int.tryParse(utilCtrl.text) ?? 30;
            m.tasaInteres = (double.tryParse(tasaCtrl.text) ?? 30) / 100;
            m.anticipo = double.tryParse(anticipoCtrl.text) ?? 0;
            m.anticipoIntereses = double.tryParse(anticIntCtrl.text) ?? 0;
          });
          Navigator.pop(ctx);
        }, child: const Text("Guardar")),
      ],
    ));
  }

  // ── Aplicar cambio masivo (cambiar salario de varios meses) ──
  Future<void> _aplicarCambioMasivo() async {
    if (_meses.isEmpty) return;
    final desdeCtrl = TextEditingController(text: "1");
    final hastaCtrl = TextEditingController(text: _meses.length.toString());
    final salarioCtrl = TextEditingController();

    await showDialog(context: context, builder: (ctx) => AlertDialog(
      title: const Text("Aplicar salario a rango"),
      content: Column(mainAxisSize: MainAxisSize.min, children: [
        Row(children: [
          Expanded(child: TextField(
            controller: desdeCtrl,
            keyboardType: TextInputType.number,
            decoration: const InputDecoration(labelText: "Desde mes #"))),
          const SizedBox(width: 10),
          Expanded(child: TextField(
            controller: hastaCtrl,
            keyboardType: TextInputType.number,
            decoration: const InputDecoration(labelText: "Hasta mes #"))),
        ]),
        const SizedBox(height: 12),
        TextField(
          controller: salarioCtrl,
          keyboardType: TextInputType.number,
          decoration: const InputDecoration(
            labelText: "Nuevo salario mensual",
            prefixIcon: Icon(Icons.attach_money))),
      ]),
      actions: [
        TextButton(onPressed: () => Navigator.pop(ctx),
          child: const Text("Cancelar")),
        ElevatedButton(onPressed: () {
          final d = (int.tryParse(desdeCtrl.text) ?? 1) - 1;
          final h = (int.tryParse(hastaCtrl.text) ?? _meses.length) - 1;
          final s = double.tryParse(salarioCtrl.text) ?? 0;
          if (s > 0) {
            setState(() {
              for (int i = d; i <= h && i < _meses.length; i++) {
                _meses[i].salarioMensual = s;
              }
            });
          }
          Navigator.pop(ctx);
        }, child: const Text("Aplicar")),
      ],
    ));
  }

  @override
  Widget build(BuildContext context) {
    return SingleChildScrollView(
      padding: const EdgeInsets.all(16),
      child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [

        // ═══════════════════════════════════════════════════════
        //  BANNER INFORMATIVO
        // ═══════════════════════════════════════════════════════
        Container(
          padding: const EdgeInsets.all(14),
          decoration: BoxDecoration(
            gradient: LinearGradient(
              colors: [AppColors.primaryBlue.withValues(alpha: 0.8),
