                "Neto: ${r.netoIntereses.toStringAsFixed(2)}",
                style: const TextStyle(fontSize: 13,
                  color: AppColors.statusGreen, fontWeight: FontWeight.w600)),
            ])),
          ]),
        ),
      ]),
    );
  }

  Widget _filaInfo(String etiqueta, String valor) => Padding(
    padding: const EdgeInsets.symmetric(vertical: 3),
    child: Row(children: [
      SizedBox(width: 120, child: Text(etiqueta,
        style: const TextStyle(fontSize: 12,
          color: AppColors.textSecondary))),
      Expanded(child: Text(valor.isEmpty ? "—" : valor,
        style: const TextStyle(fontSize: 13,
          fontWeight: FontWeight.w600))),
    ]),
  );

  Widget _tarjetaResultado(String titulo, double valor,
      {bool esGanador = false, bool esCantidad = false, String? subtitulo}) {
    return Container(
      padding: const EdgeInsets.all(12),
      decoration: BoxDecoration(
        color: esGanador
          ? AppColors.statusGreen.withValues(alpha: 0.1)
          : Colors.white,
        borderRadius: BorderRadius.circular(8),
        border: Border.all(
          color: esGanador ? AppColors.statusGreen : Colors.grey[300]!,
          width: esGanador ? 2 : 1)),
      child: Row(children: [
        Expanded(child: Column(crossAxisAlignment: CrossAxisAlignment.start,
          children: [
          Row(children: [
            if (esGanador)
              const Icon(Icons.check_circle,
                color: AppColors.statusGreen, size: 16),
            if (esGanador) const SizedBox(width: 4),
            Expanded(child: Text(titulo,
              style: TextStyle(fontSize: 12,
                fontWeight: esGanador ? FontWeight.bold : FontWeight.normal))),
          ]),
          if (subtitulo != null) Padding(
            padding: const EdgeInsets.only(top: 2),
            child: Text(subtitulo,
              style: const TextStyle(
                fontSize: 10, color: AppColors.textSecondary))),
        ])),
        const SizedBox(width: 8),
        Text(esCantidad
          ? "${valor.toStringAsFixed(0)} días"
          : valor.toStringAsFixed(2),
          style: TextStyle(fontSize: 16,
            fontWeight: FontWeight.bold,
            color: esGanador
              ? AppColors.statusGreen
              : AppColors.primaryBlue)),
      ]),
    );
  }
}

// ════════════════════════════════════════════════════════════════════
//                                                                  
//  VENTANA: REPORTE POR VENDEDOR                                   
//                                                                  
// ════════════════════════════════════════════════════════════════════
//  Genera un reporte detallado de ventas filtrable por:           
//    · Rango de fechas                                             
//    · Vendedor específico (o todos)                               
//    · Tienda (o todas)                                            
//    · Método de pago (o todos)                                    
//                                                                  
//  Vista en 2 pestañas:                                           
//    · RESUMEN: agrupado por vendedor con totales                  
//    · DETALLE: tabla plana con TODO lo que vendió cada uno,       
//      incluyendo marca y modelo de cada producto                  
//                                                                  
//  Exportable a Excel y PDF.                                       
// ════════════════════════════════════════════════════════════════════
class VentanaReporteVendedor extends StatefulWidget {
  const VentanaReporteVendedor({super.key});
  @override
  State<VentanaReporteVendedor> createState() => _VentanaReporteVendedorState();
}

class _VentanaReporteVendedorState extends State<VentanaReporteVendedor>
    with SingleTickerProviderStateMixin {
  // ── Filtros ──────────────────────────────────────────────────
  DateTime? _desde;
  DateTime? _hasta;
  String? _vendedorFiltro;   // null = todos
  String? _tiendaFiltro;     // null = todas
  String? _metodoPagoFiltro; // null = todos
  String? _marcaFiltro;      // null = todas
  String? _modeloFiltro;     // null = todos

  late TabController _tabCtrl;
  bool _cargando = false;

  @override
  void initState() {
    super.initState();
    _tabCtrl = TabController(length: 2, vsync: this);
    // Por defecto: mes actual
    final now = DateTime.now();
    _desde = DateTime(now.year, now.month, 1);
    _hasta = now;
    // Cargar facturas del backend si la lista global está vacía
    // (esto pasa cuando el usuario abre el reporte sin haber ido
    // antes a la pantalla de Facturas).
    if (ventasGlobal.isEmpty) _cargarFacturas();
  }

  Future<void> _cargarFacturas() async {
    setState(() => _cargando = true);
    try {
      final raw = await _Api.get('facturas');
      final lista = ((raw as List?) ?? [])
          .map((m) => _construirFactura(m as Map<String, dynamic>))
          .toList();
      ventasGlobal = lista;
    } catch (e) {
      debugPrint('[ReporteVendedor] error cargando facturas: $e');
    } finally {
      if (mounted) setState(() => _cargando = false);
    }
  }

  /// Construye un FacturaModel desde el Map del backend.
  /// El backend devuelve equipos como List<String> (IMEIs) e items como
  /// List<String> (códigos). Los resolvemos contra catalogoGlobal /
  /// stockImeiGlobal para tener objetos completos.
  FacturaModel _construirFactura(Map<String, dynamic> m) {
    // Resolver equipos (IMEIs → ImeiRegistro)
    final equipos = <ImeiRegistro>[];
    for (final imei in (m['equipos'] as List? ?? [])) {
      final imeiStr = imei.toString();
      final reg = stockImeiGlobal.where((i) => i.imei == imeiStr).firstOrNull;
      if (reg != null) equipos.add(reg);
    }
    // Resolver items (códigos → Producto)
    final items = <Producto>[];
    for (final cod in (m['items'] as List? ?? [])) {
      final codStr = cod.toString();
      final prod = catalogoGlobal.where((p) => p.codigo == codStr).firstOrNull;
      if (prod != null) items.add(prod);
    }
    // Pagos
    final pagos = ((m['pagos'] as List?) ?? [])
        .map((p) => PagoFactura.fromMap(p as Map<String, dynamic>))
        .toList();

    return FacturaModel(
      id          : m['id'] is int ? m['id'] : int.tryParse(m['id']?.toString() ?? ''),
      cliente     : m['cliente']?.toString() ?? '',
      cedula      : m['cedula']?.toString() ?? '',
      telefono    : m['telefono']?.toString() ?? '',
      nroFactura  : m['nro_factura']?.toString() ?? '',
      vendedor    : m['vendedor']?.toString() ?? '',
      tienda      : m['tienda']?.toString() ?? '',
      fecha       : m['fecha']?.toString() ?? '',
      equipos     : equipos,
      itemsSinImei: items,
      pagos       : pagos,
    );
  }

  @override
  void dispose() {
    _tabCtrl.dispose();
    super.dispose();
  }

  // ─────────────────────────────────────────────────────────────
  //  CÁLCULOS
  // ─────────────────────────────────────────────────────────────

  /// Facturas filtradas según los selectores actuales.
  List<FacturaModel> get _facturasFiltradas {
    return ventasGlobal.where((f) {
      // Filtro fecha (parsea f.fecha que es String yyyy-MM-dd...)
      final fecha = parseFechaFlexible(f.fecha);
      if (fecha != null) {
        if (_desde != null && fecha.isBefore(_desde!)) return false;
        if (_hasta != null) {
          // Incluir el día completo
          final fin = DateTime(_hasta!.year, _hasta!.month, _hasta!.day, 23, 59, 59);
          if (fecha.isAfter(fin)) return false;
        }
      }
      // Filtro vendedor
      if (_vendedorFiltro != null && f.vendedor != _vendedorFiltro) return false;
      // Filtro tienda
      if (_tiendaFiltro != null && f.tienda != _tiendaFiltro) return false;
      // Filtro método de pago: la factura cuenta si AL MENOS un pago
      // coincide con el método elegido.
      if (_metodoPagoFiltro != null) {
        final tieneMetodo = f.pagos.any((p) => p.metodo == _metodoPagoFiltro);
        if (!tieneMetodo) return false;
      }
      // Filtro marca: la factura cuenta si AL MENOS un producto/equipo
      // es de la marca elegida.
      if (_marcaFiltro != null) {
        final tieneMarca = f.equipos.any((e) => e.producto.marca == _marcaFiltro)
            || f.itemsSinImei.any((p) => p.marca == _marcaFiltro);
        if (!tieneMarca) return false;
      }
      // Filtro modelo: igual pero por modelo específico.
      if (_modeloFiltro != null) {
        final tieneModelo = f.equipos.any((e) => e.producto.modelo == _modeloFiltro)
            || f.itemsSinImei.any((p) => p.modelo == _modeloFiltro);
        if (!tieneModelo) return false;
      }
      return true;
    }).toList();
  }

  /// Marcas únicas en el catálogo global (ordenadas).
  List<String> get _marcasDisponibles {
    final set = catalogoGlobal
        .map((p) => p.marca)
        .where((m) => m.isNotEmpty && m != 'Genérico')
        .toSet();
    return set.toList()..sort();
  }

  /// Modelos disponibles. Si hay marca elegida, filtra por esa marca.
  List<String> get _modelosDisponibles {
    final filtrados = _marcaFiltro == null
        ? catalogoGlobal
        : catalogoGlobal.where((p) => p.marca == _marcaFiltro);
    final set = filtrados
        .map((p) => p.modelo)
        .where((m) => m.isNotEmpty && m != 'N/A')
        .toSet();
    return set.toList()..sort();
  }

  /// Lista única de vendedores conocidos en ventasGlobal (para el dropdown).
  List<String> get _vendedoresDisponibles {
    final set = ventasGlobal.map((f) => f.vendedor).toSet();
    final lista = set.toList()..sort();
    return lista;
  }

  /// Lista única de métodos de pago.
  List<String> get _metodosPagoDisponibles {
    final set = <String>{};
    for (final f in ventasGlobal) {
      for (final p in f.pagos) { set.add(p.metodo); }
    }
    final lista = set.toList()..sort();
    return lista;
  }

  /// Resumen por vendedor: cantidad de facturas, total $, productos vendidos.
  /// Devuelve mapa { vendedor: { facturas: n, total: x, productos: y } }
  Map<String, Map<String, dynamic>> get _resumenPorVendedor {
    final r = <String, Map<String, dynamic>>{};
    for (final f in _facturasFiltradas) {
      final v = r.putIfAbsent(f.vendedor, () => {
        'facturas': 0, 'total': 0.0, 'productos': 0,
      });
      v['facturas'] = (v['facturas'] as int) + 1;
      v['total']    = (v['total'] as double) + f.total;
      v['productos'] = (v['productos'] as int) + f.equipos.length + f.itemsSinImei.length;
    }
    return r;
  }

  /// Total general (todas las ventas filtradas).
  double get _totalGeneral =>
      _facturasFiltradas.fold(0.0, (s, f) => s + f.total);

  /// Cada producto vendido con su factura/vendedor (para la pestaña de detalle).
  /// Estructura plana: una fila por producto vendido.
  List<Map<String, dynamic>> get _detallePlano {
    final filas = <Map<String, dynamic>>[];
    for (final f in _facturasFiltradas) {
      // Equipos con IMEI
      for (final eq in f.equipos) {
        filas.add({
          'vendedor' : f.vendedor,
          'tienda'   : f.tienda,
          'fecha'    : f.fecha,
          'cliente'  : f.cliente,
          'cedula'   : f.cedula,
          'nroFact'  : f.nroFactura,
          'tipo'     : 'IMEI',
          'codigo'   : eq.producto.codigo,
          'nombre'   : eq.producto.nombre,
          'marca'    : eq.producto.marca,
          'modelo'   : eq.producto.modelo,
          'imei'     : eq.imei,
          'precio'   : eq.producto.precioVenta,
          'costo'    : eq.producto.precioCosto,
        });
      }
      // Items sin IMEI
      for (final p in f.itemsSinImei) {
        filas.add({
          'vendedor' : f.vendedor,
          'tienda'   : f.tienda,
          'fecha'    : f.fecha,
          'cliente'  : f.cliente,
          'cedula'   : f.cedula,
          'nroFact'  : f.nroFactura,
          'tipo'     : 'SIN-IMEI',
          'codigo'   : p.codigo,
          'nombre'   : p.nombre,
          'marca'    : p.marca,
          'modelo'   : p.modelo,
          'imei'     : '',
          'precio'   : p.precioVenta,
          'costo'    : p.precioCosto,
        });
      }
    }
    // Ordenar: vendedor → fecha desc → nro factura
    filas.sort((a, b) {
      final c1 = (a['vendedor'] as String).compareTo(b['vendedor'] as String);
      if (c1 != 0) return c1;
      return (b['fecha'] as String).compareTo(a['fecha'] as String);
    });
    return filas;
  }

  // ─────────────────────────────────────────────────────────────
  //  EXPORTACIÓN
  // ─────────────────────────────────────────────────────────────

  Future<void> _exportarExcel() async {
    try {
      final excel = Excel.createExcel();
      excel.delete('Sheet1');

      // ── Hoja 1: Resumen por vendedor ────────────────────────
      final sR = excel['Resumen por Vendedor'];
      sR.appendRow(_filaCeldas(['REPORTE POR VENDEDOR — TECNO LÍDER']));
      sR.appendRow(_filaCeldas([
        'Periodo: ${_desde != null ? _ymd(_desde!) : "-"} a ${_hasta != null ? _ymd(_hasta!) : "-"}'
      ]));
      sR.appendRow(<CellValue?>[]);
      sR.appendRow(_filaCeldas(['Vendedor', 'Facturas', 'Productos', 'Total Ventas']));
      _resumenPorVendedor.forEach((vendedor, datos) {
        sR.appendRow(_filaCeldas([
          vendedor,
          datos['facturas'],
          datos['productos'],
          datos['total'],
        ]));
      });
      sR.appendRow(<CellValue?>[]);
      sR.appendRow(_filaCeldas([
        'TOTAL GENERAL', '', '', _totalGeneral,
      ]));

      // ── Hoja 2: Detalle de productos ────────────────────────
      final sD = excel['Detalle de Productos'];
      sD.appendRow(_filaCeldas([
        'Vendedor', 'Tienda', 'Fecha', 'Nro Factura', 'Cliente', 'Cédula',
        'Tipo', 'Código', 'Producto', 'Marca', 'Modelo', 'IMEI',
        'Precio Venta', 'Precio Costo',
      ]));
      for (final fila in _detallePlano) {
        sD.appendRow(_filaCeldas([
          fila['vendedor'], fila['tienda'], fila['fecha'], fila['nroFact'],
          fila['cliente'], fila['cedula'], fila['tipo'], fila['codigo'],
          fila['nombre'], fila['marca'], fila['modelo'], fila['imei'],
          fila['precio'], fila['costo'],
        ]));
      }

      final bytes = excel.encode();
      if (bytes == null) throw 'No se pudo generar el archivo';
      final ts = DateTime.now().millisecondsSinceEpoch;
      await descargarArchivo(
        Uint8List.fromList(bytes),
        'reporte_vendedor_$ts.xlsx',
        'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      );
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
        content: Text('✅ Excel generado'),
        backgroundColor: AppColors.statusGreen));
    } catch (e) {
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Error al exportar Excel: $e'),
          backgroundColor: AppColors.statusRed));
    }
  }

  Future<void> _exportarPDF() async {
    try {
      final pdf = pw.Document();
      final fmt = pw.TextStyle(fontSize: 9);
      final bold = pw.TextStyle(fontSize: 9, fontWeight: pw.FontWeight.bold);

      pdf.addPage(pw.MultiPage(
        pageFormat: PdfPageFormat.a4,
        margin: const pw.EdgeInsets.all(28),
        build: (ctx) => [
          // ── Encabezado ──
          pw.Container(
            padding: const pw.EdgeInsets.all(10),
            decoration: pw.BoxDecoration(
              color: PdfColor.fromInt(0xFF2E3192),
              borderRadius: pw.BorderRadius.circular(6),
            ),
            child: pw.Column(crossAxisAlignment: pw.CrossAxisAlignment.start, children: [
              pw.Text('REPORTE POR VENDEDOR — TECNO LÍDER',
                style: pw.TextStyle(fontSize: 14, fontWeight: pw.FontWeight.bold, color: PdfColors.white)),
              pw.SizedBox(height: 4),
              pw.Text(
                'Periodo: ${_desde != null ? _ymd(_desde!) : "-"} a ${_hasta != null ? _ymd(_hasta!) : "-"}',
                style: const pw.TextStyle(fontSize: 10, color: PdfColors.white)),
              if (_vendedorFiltro != null) pw.Text('Vendedor: $_vendedorFiltro',
                style: const pw.TextStyle(fontSize: 10, color: PdfColors.white)),
              if (_tiendaFiltro != null) pw.Text('Tienda: $_tiendaFiltro',
                style: const pw.TextStyle(fontSize: 10, color: PdfColors.white)),
              if (_metodoPagoFiltro != null) pw.Text('Método de pago: $_metodoPagoFiltro',
                style: const pw.TextStyle(fontSize: 10, color: PdfColors.white)),
            ]),
          ),
          pw.SizedBox(height: 16),

          // ── Resumen por vendedor ──
          pw.Text('Resumen por Vendedor',
            style: pw.TextStyle(fontSize: 12, fontWeight: pw.FontWeight.bold)),
          pw.SizedBox(height: 6),
          pw.Table.fromTextArray(
            headerStyle: pw.TextStyle(
                fontSize: 9, fontWeight: pw.FontWeight.bold, color: PdfColors.white),
            headerDecoration: const pw.BoxDecoration(color: PdfColor.fromInt(0xFF1F2270)),
            cellStyle: fmt,
            cellAlignment: pw.Alignment.centerLeft,
            cellAlignments: {1: pw.Alignment.centerRight, 2: pw.Alignment.centerRight, 3: pw.Alignment.centerRight},
            data: [
              ['Vendedor', 'Facturas', 'Productos', 'Total'],
              ..._resumenPorVendedor.entries.map((e) => [
                e.key,
                '${e.value['facturas']}',
                '${e.value['productos']}',
                formatCurrency(e.value['total']),
              ]),
              ['TOTAL GENERAL', '', '', formatCurrency(_totalGeneral)],
            ],
          ),
          pw.SizedBox(height: 16),

          // ── Detalle agrupado por vendedor ──
          pw.Text('Detalle de productos vendidos por cada vendedor',
            style: pw.TextStyle(fontSize: 12, fontWeight: pw.FontWeight.bold)),
          pw.SizedBox(height: 6),
          ..._resumenPorVendedor.keys.expand((vendedor) {
            final filas = _detallePlano.where((f) => f['vendedor'] == vendedor).toList();
            return [
              pw.SizedBox(height: 8),
              pw.Container(
                padding: const pw.EdgeInsets.symmetric(horizontal: 6, vertical: 3),
                color: PdfColor.fromInt(0xFFFFC20E),
                child: pw.Text(vendedor.toUpperCase(),
                    style: pw.TextStyle(fontSize: 10, fontWeight: pw.FontWeight.bold)),
              ),
              pw.SizedBox(height: 4),
              pw.Table.fromTextArray(
                headerStyle: pw.TextStyle(fontSize: 8, fontWeight: pw.FontWeight.bold),
                cellStyle: pw.TextStyle(fontSize: 8),
                cellAlignment: pw.Alignment.centerLeft,
                cellAlignments: {6: pw.Alignment.centerRight},
                data: [
                  ['Fecha', 'Factura', 'Marca', 'Modelo', 'IMEI', 'Cliente', 'Precio'],
                  ...filas.map((f) => [
                    f['fecha'].toString().split(' ').first,
                    f['nroFact'].toString(),
                    f['marca'].toString(),
                    f['modelo'].toString(),
                    f['imei'].toString(),
                    f['cliente'].toString(),
                    formatCurrency((f['precio'] as num).toDouble()),
                  ]),
                ],
              ),
            ];
          }),
        ],
      ));

      final bytes = await pdf.save();
      final ts = DateTime.now().millisecondsSinceEpoch;
      await Printing.sharePdf(
        bytes: bytes,
        filename: 'reporte_vendedor_$ts.pdf',
      );
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
        content: Text('✅ PDF generado'),
        backgroundColor: AppColors.statusGreen));
    } catch (e) {
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Error al exportar PDF: $e'),
          backgroundColor: AppColors.statusRed));
    }
  }

  String _ymd(DateTime d) =>
    '${d.year}-${d.month.toString().padLeft(2,'0')}-${d.day.toString().padLeft(2,'0')}';

  // ─────────────────────────────────────────────────────────────
  //  UI
  // ─────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: AppColors.surfaceTintBlue,
      appBar: AppBar(
        title: const Text('Reporte por Vendedor'),
        bottom: TabBar(
          controller: _tabCtrl,
          tabs: const [
            Tab(icon: Icon(Icons.insights_outlined), text: 'Resumen'),
            Tab(icon: Icon(Icons.list_alt_outlined), text: 'Detalle'),
          ],
        ),
        actions: [
          IconButton(
            icon: const Icon(Icons.table_chart_outlined),
            tooltip: 'Exportar Excel',
            onPressed: _facturasFiltradas.isEmpty ? null : _exportarExcel),
          IconButton(
            icon: const Icon(Icons.picture_as_pdf_outlined),
            tooltip: 'Exportar PDF',
            onPressed: _facturasFiltradas.isEmpty ? null : _exportarPDF),
        ],
      ),
      body: Column(children: [
        // ── Panel de filtros ────────────────────────────────────
        _buildFiltros(),

        // ── Contenido de las pestañas ───────────────────────────
        Expanded(child: TabBarView(
          controller: _tabCtrl,
          children: [
            _buildVistaResumen(),
            _buildVistaDetalle(),
          ],
        )),
      ]),
    );
  }

  Widget _buildFiltros() {
    return Container(
      padding: const EdgeInsets.all(12),
      color: Colors.white,
      child: Column(children: [
        // Fila 1: rango de fechas
        Row(children: [
          Expanded(child: _campoFecha(
            label: 'Desde',
            valor: _desde,
            onChanged: (d) => setState(() => _desde = d),
          )),
          const SizedBox(width: 10),
          Expanded(child: _campoFecha(
            label: 'Hasta',
            valor: _hasta,
            onChanged: (d) => setState(() => _hasta = d),
          )),
        ]),
        const SizedBox(height: 10),
        // Fila 2: vendedor + tienda
        Row(children: [
          Expanded(child: _dropdownFiltro(
            label: 'Vendedor',
            valor: _vendedorFiltro,
            opciones: _vendedoresDisponibles,
            onChanged: (v) => setState(() => _vendedorFiltro = v),
          )),
          const SizedBox(width: 10),
          Expanded(child: _dropdownFiltro(
            label: 'Tienda',
            valor: _tiendaFiltro,
            opciones: ConfigSistema.tiendas,
            onChanged: (v) => setState(() => _tiendaFiltro = v),
          )),
        ]),
        const SizedBox(height: 10),
        // Fila 3: método de pago
        Row(children: [
          Expanded(child: _dropdownFiltro(
            label: 'Método de pago',
            valor: _metodoPagoFiltro,
            opciones: _metodosPagoDisponibles,
            onChanged: (v) => setState(() => _metodoPagoFiltro = v),
          )),
        ]),
        const SizedBox(height: 10),
        // Fila 4: marca + modelo
        Row(children: [
          Expanded(child: _dropdownFiltro(
            label: 'Marca',
            valor: _marcaFiltro,
            opciones: _marcasDisponibles,
            onChanged: (v) => setState(() {
              _marcaFiltro = v;
              // Si cambia la marca, el modelo deja de ser válido
              if (v != null && _modeloFiltro != null
                  && !_modelosDisponibles.contains(_modeloFiltro)) {
                _modeloFiltro = null;
              }
            }),
          )),
          const SizedBox(width: 10),
          Expanded(child: _dropdownFiltro(
            label: 'Modelo',
            valor: _modeloFiltro,
            opciones: _modelosDisponibles,
            onChanged: (v) => setState(() => _modeloFiltro = v),
          )),
        ]),
        const SizedBox(height: 10),
        // Fila 5: botón limpiar
        Row(children: [
          OutlinedButton.icon(
            icon: const Icon(Icons.restart_alt, size: 16),
            label: const Text('Limpiar todos los filtros'),
            onPressed: () {
              setState(() {
                _vendedorFiltro = null;
                _tiendaFiltro = null;
                _metodoPagoFiltro = null;
                _marcaFiltro = null;
                _modeloFiltro = null;
                final now = DateTime.now();
                _desde = DateTime(now.year, now.month, 1);
                _hasta = now;
              });
            },
          ),
        ]),
        const SizedBox(height: 8),
        // Indicador de resultados
        Container(
          padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),
          decoration: BoxDecoration(
            color: AppColors.brandBlue.withValues(alpha: 0.08),
            borderRadius: BorderRadius.circular(8),
          ),
          child: Row(children: [
            const Icon(Icons.filter_alt_outlined,
                size: 16, color: AppColors.brandBlue),
            const SizedBox(width: 6),
            Text('${_facturasFiltradas.length} facturas · ${_detallePlano.length} productos',
                style: const TextStyle(
                  color: AppColors.brandBlue,
                  fontWeight: FontWeight.w600, fontSize: 12)),
            const Spacer(),
            Text(formatCurrency(_totalGeneral),
                style: const TextStyle(
                  color: AppColors.brandBlueDeeper,
                  fontWeight: FontWeight.w800, fontSize: 14)),
          ]),
        ),
      ]),
    );
  }

  Widget _campoFecha({
    required String label,
    required DateTime? valor,
    required ValueChanged<DateTime?> onChanged,
  }) {
    return InkWell(
      onTap: () async {
        final d = await showDatePicker(
          context: context,
          initialDate: valor ?? DateTime.now(),
          firstDate: DateTime(2020),
          lastDate: DateTime.now().add(const Duration(days: 1)),
        );
        if (d != null) onChanged(d);
      },
      child: InputDecorator(
        decoration: InputDecoration(
          labelText: label,
          prefixIcon: const Icon(Icons.calendar_today_outlined, size: 18),
          isDense: true,
        ),
        child: Text(valor != null ? _ymd(valor) : '—',
            style: TextStyle(
              color: valor != null ? AppColors.textPrimary : AppColors.textSecondary,
              fontWeight: FontWeight.w500,
            )),
      ),
    );
  }

  Widget _dropdownFiltro({
    required String label,
    required String? valor,
    required List<String> opciones,
    required ValueChanged<String?> onChanged,
  }) {
    return DropdownButtonFormField<String?>(
      initialValue: valor,
      decoration: InputDecoration(labelText: label, isDense: true),
      isExpanded: true,
      items: [
        const DropdownMenuItem<String?>(value: null, child: Text('Todos')),
        ...opciones.map((o) => DropdownMenuItem<String?>(
              value: o,
              child: Text(o, overflow: TextOverflow.ellipsis),
            )),
      ],
      onChanged: onChanged,
    );
  }

  Widget _buildVistaResumen() {
    final resumen = _resumenPorVendedor;
    if (resumen.isEmpty) {
      return const Center(child: Padding(
        padding: EdgeInsets.all(40),
        child: Text('Sin datos para los filtros seleccionados.',
          style: TextStyle(color: AppColors.textSecondary)),
      ));
    }
    // Ordenar por total descendente
    final sorted = resumen.entries.toList()
      ..sort((a, b) =>
          (b.value['total'] as double).compareTo(a.value['total'] as double));

    return ListView.builder(
      padding: const EdgeInsets.all(12),
      itemCount: sorted.length + 1,
      itemBuilder: (ctx, i) {
        if (i == sorted.length) {
          // Tarjeta total general
          return Card(
            color: AppColors.brandBlueDark,
            child: Padding(
              padding: const EdgeInsets.all(16),
              child: Row(children: [
                const Icon(Icons.attach_money, color: AppColors.brandYellow, size: 28),
                const SizedBox(width: 12),
                const Expanded(
                  child: Text('TOTAL GENERAL',
                    style: TextStyle(
                      color: Colors.white,
                      fontWeight: FontWeight.w800,
                      fontSize: 14, letterSpacing: 1)),
                ),
                Text(formatCurrency(_totalGeneral),
                    style: const TextStyle(
                      color: AppColors.brandYellow,
                      fontWeight: FontWeight.w900,
                      fontSize: 18)),
              ]),
            ),
          );
        }
        final entry = sorted[i];
        final vendedor = entry.key;
        final datos = entry.value;
        // Posición / medalla
        final medalla = i == 0 ? '🥇' : i == 1 ? '🥈' : i == 2 ? '🥉' : '#${i+1}';
        return Card(
          margin: const EdgeInsets.only(bottom: 10),
          child: Padding(
            padding: const EdgeInsets.all(14),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Row(children: [
                  Container(
                    width: 40, height: 40,
                    decoration: BoxDecoration(
                      gradient: const LinearGradient(colors: [
                        AppColors.brandYellow, AppColors.brandYellowDark]),
                      borderRadius: BorderRadius.circular(20),
                    ),
                    alignment: Alignment.center,
                    child: Text(medalla,
                      style: const TextStyle(fontSize: 16, fontWeight: FontWeight.w900)),
                  ),
                  const SizedBox(width: 12),
                  Expanded(child: Text(vendedor,
                    style: const TextStyle(
                      fontSize: 15, fontWeight: FontWeight.w800,
                      color: AppColors.textPrimary))),
                  Text(formatCurrency(datos['total'] as double),
                    style: const TextStyle(
                      fontSize: 16, fontWeight: FontWeight.w900,
                      color: AppColors.brandBlue)),
                ]),
                const SizedBox(height: 10),
                Row(children: [
                  _miniStat('Facturas', '${datos['facturas']}', Icons.receipt_long),
                  const SizedBox(width: 18),
                  _miniStat('Productos', '${datos['productos']}', Icons.inventory_2_outlined),
                  const SizedBox(width: 18),
                  _miniStat(
                    'Promedio/factura',
                    formatCurrency((datos['total'] as double) / (datos['facturas'] as int)),
                    Icons.calculate_outlined,
                  ),
                ]),
              ],
            ),
          ),
        );
      },
    );
  }

  Widget _miniStat(String label, String valor, IconData icon) {
    return Row(children: [
      Icon(icon, size: 14, color: AppColors.textSecondary),
      const SizedBox(width: 4),
      Text('$label: ',
        style: const TextStyle(color: AppColors.textSecondary, fontSize: 12)),
      Text(valor,
        style: const TextStyle(
          fontWeight: FontWeight.w700,
          color: AppColors.textPrimary, fontSize: 12)),
    ]);
  }

  Widget _buildVistaDetalle() {
    final filas = _detallePlano;
    if (filas.isEmpty) {
      return const Center(child: Padding(
        padding: EdgeInsets.all(40),
        child: Text('Sin productos vendidos en los filtros seleccionados.',
          style: TextStyle(color: AppColors.textSecondary)),
      ));
    }
    // Agrupar por vendedor para mostrar separadores visuales
    final porVendedor = <String, List<Map<String, dynamic>>>{};
    for (final f in filas) {
      porVendedor.putIfAbsent(f['vendedor'] as String, () => []).add(f);
    }

    return ListView(
      padding: const EdgeInsets.all(8),
      children: porVendedor.entries.map((e) {
        return Padding(
          padding: const EdgeInsets.only(bottom: 14),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              // Encabezado del grupo (vendedor)
              Container(
                padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
                decoration: BoxDecoration(
                  gradient: const LinearGradient(colors: [
                    AppColors.brandBlue, AppColors.brandBlueDark]),
                  borderRadius: const BorderRadius.only(
                    topLeft: Radius.circular(10),
                    topRight: Radius.circular(10),
                  ),
                ),
                child: Row(children: [
                  const Icon(Icons.person, color: Colors.white, size: 18),
                  const SizedBox(width: 8),
                  Expanded(child: Text(e.key,
                    style: const TextStyle(
                      color: Colors.white,
                      fontWeight: FontWeight.w800,
                      letterSpacing: 0.5))),
                  Text('${e.value.length} productos',
                    style: const TextStyle(
                      color: AppColors.brandYellow,
                      fontWeight: FontWeight.w700, fontSize: 12)),
                ]),
              ),
              // Tabla de productos
              Container(
                decoration: BoxDecoration(
                  color: Colors.white,
                  borderRadius: const BorderRadius.only(
                    bottomLeft: Radius.circular(10),
                    bottomRight: Radius.circular(10),
                  ),
                  border: Border.all(
                    color: AppColors.brandBlue.withValues(alpha: 0.15),
                  ),
                ),
                child: Column(children: e.value.map((f) {
                  return Padding(
                    padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        Row(children: [
                          // Marca + modelo (lo más importante)
                          Expanded(child: Text(
                            '${f['marca']} ${f['modelo']}'.trim().isEmpty
                                ? f['nombre']
                                : '${f['marca']} ${f['modelo']}',
                            style: const TextStyle(
                              fontWeight: FontWeight.w700,
                              color: AppColors.textPrimary, fontSize: 13))),
                          Text(formatCurrency((f['precio'] as num).toDouble()),
                            style: const TextStyle(
                              fontWeight: FontWeight.w800,
                              color: AppColors.brandBlue, fontSize: 13)),
                        ]),
                        const SizedBox(height: 2),
                        // Línea secundaria: cliente + fecha + IMEI
                        DefaultTextStyle.merge(
                          style: const TextStyle(
                            fontSize: 11,
                            color: AppColors.textSecondary),
                          child: Wrap(spacing: 12, children: [
                            Text('Cliente: ${f['cliente']}'),
                            Text('Fact: ${f['nroFact']}'),
                            Text(f['fecha'].toString().split(' ').first),
                            if ((f['imei'] as String).isNotEmpty)
                              Text('IMEI: ${f['imei']}'),
                          ]),
                        ),
                      ],
                    ),
                  );
                }).expand((w) sync* {
                  yield w;
                  yield const Divider(height: 1);
                }).toList()..removeLast()),
              ),
            ],
          ),
        );
      }).toList(),
    );
  }
}

// ════════════════════════════════════════════════════════════════════
//                                                                  
//  VENTANA: REPORTE POR FINANCIADORA                               
//                                                                  
// ════════════════════════════════════════════════════════════════════
//  Muestra para cada financiadora (Cashea, Weppa, FPB Tecno Líder, etc):
//    · Pendiente: total de cuotas que aún quedan por cobrar         
//    · Cobrado: total ya cobrado a esa financiadora                  
//    · Total Ventas: monto total de ventas asociadas a la financiadora
// ════════════════════════════════════════════════════════════════════
class VentanaReporteFinanciadora extends StatefulWidget {
  const VentanaReporteFinanciadora({super.key});
  @override
  State<VentanaReporteFinanciadora> createState() => _VentanaReporteFinanciadoraState();
}

class _VentanaReporteFinanciadoraState extends State<VentanaReporteFinanciadora> {
  bool _cargando = true;
  String? _error;
  List<CuentaPorCobrar> _cxc = [];
  List<ListaPrecio> _listas = [];
  // Pagos que las financiadoras han hecho a la tienda
  List<Map<String, dynamic>> _pagosFinanc = [];

  // ── Filtro por rango de fechas ────────────────────────────────
  DateTime? _desde;
  DateTime? _hasta;
  // Filtro de financiadora (null = todas)
  String? _financiadoraFiltro;

  @override
  void initState() {
    super.initState();
    final now = DateTime.now();
    _desde = DateTime(now.year, now.month, 1);
    _hasta = now;
    _cargar();
  }

  Future<void> _cargar() async {
    setState(() { _cargando = true; _error = null; });
    try {
      // Cargar TODO en paralelo. Es CRÍTICO traer productos e IMEIs
      // frescos: sin ellos no se pueden resolver los equipos de cada
      // factura y el cálculo de "precio_lista" quedaría en 0.
      //
      // Antes esto dependía de `catalogoGlobal` / `stockImeiGlobal`
      // que podían estar vacíos si el usuario no había abierto el
      // inventario — por eso el reporte salía en blanco.
      final results = await Future.wait([
        _Api.get('cuentas_cobrar'),
        _Api.get('facturas'),
        _Api.get('listas_precios'),
        _Api.get('productos'),
        _Api.get('stock_imei'),
        _Api.get('pagos_financiadora').catchError((e) {
          debugPrint('[ReporteFinanc] pagos_financiadora falló: $e');
          return <dynamic>[]; // si la tabla aún no existe, lista vacía
        }),
      ]);

      // ── Productos e IMEIs PRIMERO (los necesita la resolución) ──
      final productos = ((results[3] as List?) ?? [])
          .map((m) => Producto.fromMap(m as Map<String, dynamic>))
          .toList();
      catalogoGlobal = productos;

      final imeis = ((results[4] as List?) ?? [])
          .map((m) => ImeiRegistro.fromMap(m as Map<String, dynamic>))
          .toList();
      stockImeiGlobal = imeis;

      // Índices rápidos para resolver por código / imei
      final prodPorCodigo = <String, Producto>{
        for (final p in productos) p.codigo: p
      };
      final imeiPorNumero = <String, ImeiRegistro>{
        for (final i in imeis) i.imei: i
      };

      // ── CxC ──────────────────────────────────────────────────
      _cxc = ((results[0] as List?) ?? [])
          .map((m) => CuentaPorCobrar.fromMap(m as Map<String, dynamic>))
          .toList();

      // ── Facturas (siempre se recargan, con equipos resueltos) ──
      ventasGlobal = ((results[1] as List?) ?? []).map((m) {
        final mp = m as Map<String, dynamic>;
        // Resolver equipos: la lista viene como [imei1, imei2, ...]
        final equipos = <ImeiRegistro>[];
        for (final imei in (mp['equipos'] as List? ?? [])) {
          final reg = imeiPorNumero[imei.toString()];
          if (reg != null) equipos.add(reg);
        }
        // Resolver items sin imei: [codigo1, codigo2, ...]
        final items = <Producto>[];
        for (final cod in (mp['items'] as List? ?? [])) {
          final prod = prodPorCodigo[cod.toString()];
          if (prod != null) items.add(prod);
        }
        final pagos = ((mp['pagos'] as List?) ?? [])
            .map((p) => PagoFactura.fromMap(p as Map<String, dynamic>))
            .toList();
        return FacturaModel(
          id          : mp['id'] is int ? mp['id'] : int.tryParse(mp['id']?.toString() ?? ''),
          cliente     : mp['cliente']?.toString() ?? '',
          cedula      : mp['cedula']?.toString() ?? '',
          telefono    : mp['telefono']?.toString() ?? '',
          nroFactura  : mp['nro_factura']?.toString() ?? '',
          vendedor    : mp['vendedor']?.toString() ?? '',
          tienda      : mp['tienda']?.toString() ?? '',
          fecha       : mp['fecha']?.toString() ?? '',
          equipos     : equipos,
          itemsSinImei: items,
          pagos       : pagos,
        );
      }).toList();

      // ── Listas de precios (precio por financiadora) ──────────
      _listas = ((results[2] as List?) ?? [])
          .map((m) => ListaPrecio.fromMap(m as Map<String, dynamic>))
          .toList();

      // ── Pagos de financiadoras ───────────────────────────────
      _pagosFinanc = ((results[5] as List?) ?? [])
          .map((m) => Map<String, dynamic>.from(m as Map))
          .toList();

      // Log de diagnóstico (visible en la consola de depuración)
      debugPrint('[ReporteFinanc] cargado: '
          '${ventasGlobal.length} facturas, '
          '${_listas.length} listas de precios, '
          '${_pagosFinanc.length} pagos de financiadora, '
          '${productos.length} productos, ${imeis.length} IMEIs');
    } catch (e) {
      _error = e.toString();
      debugPrint('[ReporteFinanc] ERROR: $e');
    } finally {
      if (mounted) setState(() => _cargando = false);
    }
  }

  // ─────────────────────────────────────────────────────────────
  //  CÁLCULOS POR FINANCIADORA
  // ─────────────────────────────────────────────────────────────

  /// Lista oficial de financiadoras soportadas en el sistema.
  /// El reporte SOLO muestra estas 3 — cualquier otra (mayúsculas,
  /// minúsculas, con espacios, "F/D Weppa", etc.) se normaliza a una
  /// de ellas o se descarta.
  static const List<String> _financiadorasOficiales =
      ['Cashea', 'Weppa', 'Krece'];

  /// Normaliza el nombre de financiadora a una de las 3 oficiales.
  /// Devuelve null si no coincide con ninguna (ej: pago con "Contado",
  /// "Otro", etc. — se descartan del reporte).
  String? _normalizarFinanciadora(String? raw) {
    if (raw == null) return null;
    final s = raw.toLowerCase().trim();
    if (s.isEmpty) return null;
    // Coincidencia por contenido (tolerante a "F/D Cashea", "CASHEA", etc.)
    if (s.contains('cashea')) return 'Cashea';
    if (s.contains('weppa'))  return 'Weppa';
    if (s.contains('krece'))  return 'Krece';
    return null; // No es ninguna de las 3 oficiales
  }

  /// Devuelve el precio que la financiadora paga por un código de producto.
  /// Busca primero en una lista de precios cuya `financiadora` coincida.
  /// Si no encuentra, devuelve null (usaremos el precio de venta normal).
  ///
  /// Cada lista de precios tiene columnas (planes de pago) y cada item
  /// tiene un precio por columna. Para el cálculo del reporte usamos
  /// el PRIMER precio definido en `preciosPorColumna` — si la lista tiene
  /// una sola columna (lo normal para financiadoras), ese es el precio
  /// que la financiadora paga. Si tiene varias, asumimos que la primera
  /// es la principal.
  double? _precioPorFinanciadora(String financiadora, String codigoProducto) {
    final norm = financiadora.toLowerCase().trim();
    final codNorm = codigoProducto.toLowerCase().trim();
    for (final lp in _listas) {
      final lpFin = (lp.financiadora ?? '').toLowerCase().trim();
      // Aceptar coincidencia laxa (Weppa = WEPPA = weppa = "F/D Weppa")
      if (!lpFin.contains(norm) && !norm.contains(lpFin)) continue;
      for (final item in lp.items) {
        if (item.producto.codigo.toLowerCase().trim() != codNorm) continue;
        if (item.preciosPorColumna.isEmpty) continue;
        return item.preciosPorColumna.values.first;
      }
    }
    return null;
  }

  /// Devuelve todas las facturas que están dentro del rango de fechas
  /// seleccionado Y que tienen al menos un pago con financiadora.
  List<FacturaModel> get _facturasFiltradas {
    return ventasGlobal.where((f) {
      final fecha = parseFechaFlexible(f.fecha);
      if (fecha == null) return false;
      if (_desde != null && fecha.isBefore(
          DateTime(_desde!.year, _desde!.month, _desde!.day))) return false;
      if (_hasta != null) {
        final fin = DateTime(_hasta!.year, _hasta!.month, _hasta!.day, 23, 59, 59);
        if (fecha.isAfter(fin)) return false;
      }
      // La factura cuenta si AL MENOS UN pago tiene una FINANCIADORA
      // (Cashea / Weppa / Krece). NOTA: usamos el campo `financiadora`,
      // NO `financiador` — son cosas distintas:
      //   · financiadora = la app (Cashea/Weppa/Krece) ← lo que agrupa
      //   · financiador  = la persona que entrega el equipo
      return f.pagos.any((p) =>
          _normalizarFinanciadora(p.financiadora) != null);
    }).toList();
  }

  /// Resumen por financiadora basado en el rango de fechas + listas de precios.
  ///
  /// Lógica:
  ///   · Por cada factura financiada (al menos un pago con `financiador`):
  ///     - "precio_lista"  = suma del precio de cada equipo según la lista
  ///                         de precios de esa financiadora (lo que ella
  ///                         debería pagarme por esos equipos)
  ///     - "inicial"       = suma de los pagos con tipo "Contado" o sin
  ///                         financiador (lo que el cliente puso de su
  ///                         bolsillo como inicial)
  ///     - "deuda_financ"  = precio_lista − inicial (lo que la financiadora
  ///                         me debe en realidad)
  ///   · "pagos_recib"   = suma de los pagos que la financiadora ya me hizo
  ///                       (tabla pagos_financiadora) dentro del rango
  ///   · "pendiente"     = deuda_financ − pagos_recib
  Map<String, Map<String, dynamic>> get _porFinanciadora {
    final r = <String, Map<String, dynamic>>{};

    for (final f in _facturasFiltradas) {
      // Identificar la financiadora de la factura. La primera con
      // valor no vacío gana. Una factura solo debería tener UNA
      // financiadora — si hay varias, se atribuye a la primera.
      //
      // El nombre que viene del pago se NORMALIZA a una de las tres
      // financiadoras oficiales (Cashea / Weppa / Krece). Si no
      // coincide con ninguna, la factura se descarta del reporte
      // (no aparecerá en ninguna columna).
      String? financiadora;
      for (final p in f.pagos) {
        final norm = _normalizarFinanciadora(p.financiadora);
        if (norm != null) { financiadora = norm; break; }
      }
      if (financiadora == null) continue;

      final entry = r.putIfAbsent(financiadora, () => {
        'precio_lista' : 0.0,   // ∑ Base: precio según lista de la financiadora
        'inicial'      : 0.0,   // ∑ pagos "Contado" (la inicial del cliente)
        'comision'     : 0.0,   // 3.5% de (Base − Inicial)
        'deuda_financ' : 0.0,   // (Base − Inicial) − 3.5%
        'pagos_recib'  : 0.0,   // ∑ pagos_financiadora en el rango
        'pendiente'    : 0.0,   // deuda_financ − pagos_recib
        'facturas'     : <String>{},
        'equipos'      : <Map<String, dynamic>>[],
      });

      (entry['facturas'] as Set<String>).add(f.nroFactura);

      // ── 1. Calcular precio según lista de la financiadora ──────
      // Por cada equipo o ítem de la factura, sumamos el precio de la
      // lista de precios. Si no hay precio en la lista, usamos el de venta.
      for (final eq in f.equipos) {
        final prod = eq.producto;
        final precioFin = _precioPorFinanciadora(financiadora, prod.codigo)
                          ?? prod.precioVenta;
        entry['precio_lista'] = (entry['precio_lista'] as double) + precioFin;
        (entry['equipos'] as List).add({
          'imei'      : eq.imei,
          'marca'     : prod.marca,
          'modelo'    : prod.modelo,
          'nombre'    : prod.nombre,
          'codigo'    : prod.codigo,
          'precio_fin': precioFin,
          'precio_venta': prod.precioVenta,
          'nro_factura': f.nroFactura,
          'fecha'     : f.fecha,
          'cliente'   : f.cliente,
        });
      }
      for (final it in f.itemsSinImei) {
        final precioFin = _precioPorFinanciadora(financiadora, it.codigo)
                          ?? it.precioVenta;
        entry['precio_lista'] = (entry['precio_lista'] as double) + precioFin;
        (entry['equipos'] as List).add({
          'imei'      : '',
          'marca'     : it.marca,
          'modelo'    : it.modelo,
          'nombre'    : it.nombre,
          'codigo'    : it.codigo,
          'precio_fin': precioFin,
          'precio_venta': it.precioVenta,
          'nro_factura': f.nroFactura,
          'fecha'     : f.fecha,
          'cliente'   : f.cliente,
        });
      }

      // ── 2. Calcular la inicial pagada por el cliente ──────────
      // Prioridad 1: si HAY pagos marcados explícitamente como inicial
      //              (esInicial == true), se suman SOLO esos. El
      //              vendedor decidió exactamente qué es la inicial.
      // Prioridad 2: si NINGÚN pago está marcado, caemos al criterio
      //              automático anterior — pagos de tipo "Contado" o
      //              sin financiador (compatibilidad con facturas
      //              viejas creadas antes de tener el toggle).
      final hayMarcados = f.pagos.any((p) => p.esInicial);
      if (hayMarcados) {
        for (final p in f.pagos) {
          if (p.esInicial) {
            entry['inicial'] = (entry['inicial'] as double) + p.monto;
          }
        }
      } else {
        // Criterio automático: un pago es "inicial" si NO tiene
        // financiadora (es plata que puso el cliente, no financiada)
        // o si su tipo es "Contado".
        for (final p in f.pagos) {
          final tieneFinanciadora =
              _normalizarFinanciadora(p.financiadora) != null;
          if (!tieneFinanciadora || p.tipo.toLowerCase() == 'contado') {
            entry['inicial'] = (entry['inicial'] as double) + p.monto;
          }
        }
      }
    }

    // ── 3. Calcular deuda real de la financiadora ──────────────
    // Fórmula oficial:  (Base − Inicial) − 3.5% = Deuda
    //   · Base    = precio del producto en la lista de la financiadora
    //   · Inicial = lo que el cliente pagó de contado
    //   · 3.5%    = comisión que la financiadora retiene sobre el neto
    // El 3.5% se aplica sobre (Base − Inicial), NO sobre la Base sola.
    const double comisionFinanciadora = 0.035; // 3.5%
    for (final entry in r.values) {
      final base    = entry['precio_lista'] as double;
      final inicial = entry['inicial'] as double;
      final neto    = (base - inicial).clamp(0.0, double.infinity);
      final comision = neto * comisionFinanciadora;
      entry['comision']     = comision;          // monto del 3.5%
      entry['deuda_financ'] = (neto - comision).clamp(0.0, double.infinity);
    }

    // ── 4. Restar pagos de la financiadora ya recibidos ───────
    for (final pago in _pagosFinanc) {
      final financiadora = _normalizarFinanciadora(pago['financiadora']?.toString());
      if (financiadora == null) continue;
      final fechaPg = parseFechaFlexible(pago['fecha']?.toString());
      if (fechaPg == null) continue;
      if (_desde != null && fechaPg.isBefore(
          DateTime(_desde!.year, _desde!.month, _desde!.day))) continue;
      if (_hasta != null) {
        final fin = DateTime(_hasta!.year, _hasta!.month, _hasta!.day, 23, 59, 59);
        if (fechaPg.isAfter(fin)) continue;
      }
      final entry = r[financiadora];
      if (entry == null) continue;
      final monto = double.tryParse(pago['monto']?.toString() ?? '0') ?? 0;
      entry['pagos_recib'] = (entry['pagos_recib'] as double) + monto;
    }

    // ── 5. Calcular pendiente final ──────────────────────────
    for (final entry in r.values) {
      entry['pendiente'] = ((entry['deuda_financ'] as double)
                            - (entry['pagos_recib'] as double))
                          .clamp(0.0, double.infinity);
    }

    // Filtrar si hay financiadora específica seleccionada
    if (_financiadoraFiltro != null) {
      r.removeWhere((k, v) => k != _financiadoraFiltro);
    }
    return r;
  }

