  /// Diálogo para registrar un pago de la financiadora.
  Future<void> _registrarPago(String financiadora) async {
    final montoCtrl = TextEditingController();
    final refCtrl   = TextEditingController();
    final notasCtrl = TextEditingController();
    DateTime fecha  = DateTime.now();

    final ok = await showDialog<bool>(
      context: context,
      builder: (ctx) {
        return StatefulBuilder(builder: (ctx, setS) {
          return AlertDialog(
            title: Text('Pago recibido — $financiadora',
              style: const TextStyle(fontWeight: FontWeight.w800)),
            content: SingleChildScrollView(
              child: Column(mainAxisSize: MainAxisSize.min, children: [
                TextField(
                  controller: montoCtrl,
                  decoration: const InputDecoration(
                    labelText: 'Monto del pago (USD)',
                    prefixIcon: Icon(Icons.attach_money),
                  ),
                  keyboardType: const TextInputType.numberWithOptions(decimal: true),
                ),
                const SizedBox(height: 12),
                InkWell(
                  onTap: () async {
                    final picked = await showDatePicker(
                      context: ctx,
                      initialDate: fecha,
                      firstDate: DateTime(2020),
                      lastDate: DateTime.now().add(const Duration(days: 30)),
                    );
                    if (picked != null) setS(() => fecha = picked);
                  },
                  child: InputDecorator(
                    decoration: const InputDecoration(
                      labelText: 'Fecha del pago',
                      prefixIcon: Icon(Icons.calendar_today),
                    ),
                    child: Text(
                      '${fecha.day.toString().padLeft(2,'0')}/'
                      '${fecha.month.toString().padLeft(2,'0')}/'
                      '${fecha.year}',
                    ),
                  ),
                ),
                const SizedBox(height: 12),
                TextField(
                  controller: refCtrl,
                  decoration: const InputDecoration(
                    labelText: 'Referencia (opcional)',
                    prefixIcon: Icon(Icons.confirmation_number_outlined),
                  ),
                ),
                const SizedBox(height: 12),
                TextField(
                  controller: notasCtrl,
                  decoration: const InputDecoration(
                    labelText: 'Notas (opcional)',
                    prefixIcon: Icon(Icons.notes),
                  ),
                  maxLines: 2,
                ),
              ]),
            ),
            actions: [
              TextButton(
                onPressed: () => Navigator.pop(ctx, false),
                child: const Text('Cancelar')),
              ElevatedButton.icon(
                onPressed: () => Navigator.pop(ctx, true),
                icon: const Icon(Icons.check),
                label: const Text('Registrar pago'),
                style: ElevatedButton.styleFrom(
                  backgroundColor: AppColors.brandBlue,
                  foregroundColor: Colors.white),
              ),
            ],
          );
        });
      },
    );

    if (ok != true) return;
    final monto = double.tryParse(montoCtrl.text.trim()) ?? 0;
    if (monto <= 0) {
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
        content: Text('Monto inválido'),
        backgroundColor: AppColors.statusRed));
      return;
    }
    try {
      await _Api.post('pagos_financiadora', {
        'financiadora': financiadora,
        'monto'       : monto,
        'fecha'       : "${fecha.day.toString().padLeft(2,'0')}/"
                        "${fecha.month.toString().padLeft(2,'0')}/"
                        "${fecha.year}",
        'referencia'  : refCtrl.text.trim(),
        'notas'       : notasCtrl.text.trim(),
      });
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Text('✅ Pago registrado: $financiadora — ${formatCurrency(monto)}'),
        backgroundColor: AppColors.statusGreen));
      await _cargar();
    } catch (e) {
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Text('Error al registrar pago: $e'),
        backgroundColor: AppColors.statusRed));
    }
  }

  /// Selector de rango de fechas
  Future<void> _seleccionarRango() async {
    final picked = await showDateRangePicker(
      context: context,
      firstDate: DateTime(2020),
      lastDate: DateTime.now().add(const Duration(days: 30)),
      initialDateRange: (_desde != null && _hasta != null)
          ? DateTimeRange(start: _desde!, end: _hasta!)
          : null,
    );
    if (picked != null) {
      setState(() {
        _desde = picked.start;
        _hasta = picked.end;
      });
    }
  }

  /// Muestra el listado completo de equipos vendidos por una financiadora
  /// en el rango de fechas elegido (marca, modelo, IMEI, precio).
  void _verEquiposVendidos(String financiadora, List<Map<String, dynamic>> equipos) {
    showModalBottomSheet(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.white,
      shape: const RoundedRectangleBorder(
        borderRadius: BorderRadius.vertical(top: Radius.circular(20))),
      builder: (ctx) => DraggableScrollableSheet(
        initialChildSize: 0.85,
        maxChildSize: 0.95,
        minChildSize: 0.5,
        expand: false,
        builder: (ctx, scroll) {
          // Agrupar por marca + modelo para ver cantidad
          final agrupado = <String, List<Map<String, dynamic>>>{};
          for (final e in equipos) {
            final key = "${e['marca']} ${e['modelo']}".trim().isEmpty
                ? (e['nombre']?.toString() ?? 'Sin nombre')
                : "${e['marca']} ${e['modelo']}";
            agrupado.putIfAbsent(key, () => []).add(e);
          }

          return ListView(controller: scroll, children: [
            Container(
              padding: const EdgeInsets.all(20),
              decoration: const BoxDecoration(
                gradient: LinearGradient(
                  colors: [AppColors.brandBlue, AppColors.brandBlueDark])),
              child: Row(children: [
                const Icon(Icons.inventory_2, color: Colors.white, size: 28),
                const SizedBox(width: 12),
                Expanded(child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text('Equipos vendidos — $financiadora',
                      style: const TextStyle(
                        color: Colors.white,
                        fontWeight: FontWeight.w800,
                        fontSize: 16)),
                    Text('${equipos.length} unidad(es) · ${agrupado.length} modelo(s)',
                      style: const TextStyle(color: Colors.white70, fontSize: 12)),
                  ])),
              ]),
            ),
            const SizedBox(height: 8),
            ...agrupado.entries.map((g) {
              final unidades = g.value;
              final totalPrecio = unidades.fold<double>(
                0, (s, e) => s + (e['precio_fin'] as double));
              return Container(
                margin: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),
                decoration: BoxDecoration(
                  color: Colors.white,
                  borderRadius: BorderRadius.circular(12),
                  border: Border.all(color: AppColors.surfaceGrey),
                ),
                child: ExpansionTile(
                  title: Text(g.key,
                    style: const TextStyle(fontWeight: FontWeight.w700)),
                  subtitle: Text(
                    '${unidades.length} unidad(es) — Total: ${formatCurrency(totalPrecio)}',
                    style: const TextStyle(
                      color: AppColors.textSecondary, fontSize: 12)),
                  children: unidades.map((u) => ListTile(
                    dense: true,
                    leading: const Icon(Icons.phone_android, size: 18,
                      color: AppColors.brandBlue),
                    title: Text(u['imei']?.toString().isNotEmpty == true
                        ? 'IMEI: ${u['imei']}'
                        : 'Cód: ${u['codigo']}',
                      style: const TextStyle(fontSize: 13)),
                    subtitle: Text(
                      'Factura ${u['nro_factura']} · ${u['cliente']} · ${u['fecha']}',
                      style: const TextStyle(fontSize: 11)),
                    trailing: Text(formatCurrency(u['precio_fin'] as double),
                      style: const TextStyle(
                        fontWeight: FontWeight.w700,
                        color: AppColors.brandBlue)),
                  )).toList(),
                ),
              );
            }),
            const SizedBox(height: 24),
          ]);
        },
      ),
    );
  }

