  //  EXPORTAR
  // ─────────────────────────────────────────────────────────────

  Future<void> _exportarExcel(String financiadora,
      List<Map<String, dynamic>> equipos, Map<String, dynamic> resumen) async {
    try {
      final excel = Excel.createExcel();
      excel.delete('Sheet1');

      // Hoja 1: Resumen
      final hojaRes = excel['Resumen'];
      hojaRes.appendRow(_filaCeldas(['Reporte — $financiadora']));
      hojaRes.appendRow(_filaCeldas([
        'Rango:',
        '${_desde?.day.toString().padLeft(2,'0')}/'
        '${_desde?.month.toString().padLeft(2,'0')}/${_desde?.year}',
        '—',
        '${_hasta?.day.toString().padLeft(2,'0')}/'
        '${_hasta?.month.toString().padLeft(2,'0')}/${_hasta?.year}',
      ]));
      hojaRes.appendRow(_filaCeldas([]));
      hojaRes.appendRow(_filaCeldas(['Indicador', 'Monto USD']));
      hojaRes.appendRow(_filaCeldas([
        'Base (precio lista financiadora)', resumen['precio_lista']]));
      hojaRes.appendRow(_filaCeldas([
        'Inicial pagada por cliente', resumen['inicial']]));
      hojaRes.appendRow(_filaCeldas([
        'Comisión financiadora (3.5%)', resumen['comision']]));
      hojaRes.appendRow(_filaCeldas([
        'Deuda de la financiadora', resumen['deuda_financ']]));
      hojaRes.appendRow(_filaCeldas([
        'Pagos recibidos de la financiadora', resumen['pagos_recib']]));
      hojaRes.appendRow(_filaCeldas([
        'Pendiente por cobrar', resumen['pendiente']]));
      hojaRes.appendRow(_filaCeldas([]));
      hojaRes.appendRow(_filaCeldas([
        'Cantidad de facturas',
        (resumen['facturas'] as Set).length]));
      hojaRes.appendRow(_filaCeldas([
        'Cantidad de equipos', equipos.length]));

      // Hoja 2: Detalle de equipos
      final hojaDet = excel['Equipos'];
      hojaDet.appendRow(_filaCeldas([
        'Factura', 'Fecha', 'Cliente', 'Marca', 'Modelo',
        'IMEI / Código', 'Precio Financiadora', 'Precio Venta']));
      for (final e in equipos) {
        hojaDet.appendRow(_filaCeldas([
          e['nro_factura'],
          e['fecha'],
          e['cliente'],
          e['marca'],
          e['modelo'],
          e['imei']?.toString().isNotEmpty == true ? e['imei'] : e['codigo'],
          e['precio_fin'],
          e['precio_venta'],
        ]));
      }

      // Generar y descargar el archivo
      final bytes = excel.encode();
      if (bytes == null) throw 'No se pudo generar el Excel';
      final ts = DateTime.now().millisecondsSinceEpoch;
      // `descargarArchivo` funciona en TODAS las plataformas:
      //  · Web    → dispara la descarga del navegador (blob)
      //  · Móvil  → guarda temporal y abre el sharesheet nativo
      await descargarArchivo(
        Uint8List.fromList(bytes),
        'Reporte_${financiadora}_$ts.xlsx',
        'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      );
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Text('✅ Excel de $financiadora generado'),
        backgroundColor: AppColors.statusGreen));
    } catch (e) {
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Text('Error al exportar Excel: $e'),
        backgroundColor: AppColors.statusRed));
    }
  }

  Future<void> _exportarPDF(String financiadora,
      List<Map<String, dynamic>> equipos, Map<String, dynamic> resumen) async {
    try {
      final pdf = pw.Document();
      final fmt = (double n) => '\$${n.toStringAsFixed(2)}';
      final rangoStr = '${_desde?.day.toString().padLeft(2,'0')}/'
          '${_desde?.month.toString().padLeft(2,'0')}/${_desde?.year}'
          ' — ${_hasta?.day.toString().padLeft(2,'0')}/'
          '${_hasta?.month.toString().padLeft(2,'0')}/${_hasta?.year}';

      pdf.addPage(pw.MultiPage(
        pageFormat: PdfPageFormat.a4,
        margin: const pw.EdgeInsets.all(28),
        build: (ctx) => [
          // Header
          pw.Container(
            padding: const pw.EdgeInsets.all(14),
            decoration: const pw.BoxDecoration(color: PdfColor.fromInt(0xFF2E3192)),
            child: pw.Column(
              crossAxisAlignment: pw.CrossAxisAlignment.start,
              children: [
                pw.Text('REPORTE POR FINANCIADORA',
                  style: pw.TextStyle(
                    color: PdfColors.white,
                    fontSize: 18,
                    fontWeight: pw.FontWeight.bold)),
                pw.SizedBox(height: 4),
                pw.Text(financiadora,
                  style: pw.TextStyle(
                    color: const PdfColor.fromInt(0xFFFFC20E),
                    fontSize: 14,
                    fontWeight: pw.FontWeight.bold)),
                pw.SizedBox(height: 2),
                pw.Text('Rango: $rangoStr',
                  style: const pw.TextStyle(color: PdfColors.white, fontSize: 10)),
              ],
            ),
          ),
          pw.SizedBox(height: 14),
          pw.Text('Resumen',
            style: pw.TextStyle(fontSize: 14, fontWeight: pw.FontWeight.bold)),
          pw.SizedBox(height: 6),
          pw.Table.fromTextArray(
            cellAlignment: pw.Alignment.centerLeft,
            headerStyle: pw.TextStyle(fontWeight: pw.FontWeight.bold,
              color: PdfColors.white),
            headerDecoration: const pw.BoxDecoration(color: PdfColor.fromInt(0xFF2E3192)),
            headers: ['Indicador', 'Valor'],
            data: [
              ['Base (precio lista financiadora)', fmt(resumen['precio_lista'] as double)],
              ['Inicial pagada por cliente', fmt(resumen['inicial'] as double)],
              ['Comisión financiadora (3.5%)', fmt(resumen['comision'] as double)],
              ['Deuda de la financiadora', fmt(resumen['deuda_financ'] as double)],
              ['Pagos recibidos', fmt(resumen['pagos_recib'] as double)],
              ['Pendiente por cobrar', fmt(resumen['pendiente'] as double)],
              ['Cantidad de facturas', (resumen['facturas'] as Set).length.toString()],
              ['Cantidad de equipos', equipos.length.toString()],
            ],
          ),
          pw.SizedBox(height: 18),
          pw.Text('Equipos vendidos',
            style: pw.TextStyle(fontSize: 14, fontWeight: pw.FontWeight.bold)),
          pw.SizedBox(height: 6),
          pw.Table.fromTextArray(
            cellStyle: const pw.TextStyle(fontSize: 9),
            headerStyle: pw.TextStyle(fontWeight: pw.FontWeight.bold,
              color: PdfColors.white, fontSize: 9),
            headerDecoration: const pw.BoxDecoration(color: PdfColor.fromInt(0xFF2E3192)),
            headers: ['Factura', 'Fecha', 'Cliente', 'Marca', 'Modelo',
                      'IMEI/Cód', 'Precio Financ.'],
            data: equipos.map((e) => [
              e['nro_factura']?.toString() ?? '',
              e['fecha']?.toString() ?? '',
              e['cliente']?.toString() ?? '',
              e['marca']?.toString() ?? '',
              e['modelo']?.toString() ?? '',
              e['imei']?.toString().isNotEmpty == true
                  ? e['imei'].toString()
                  : e['codigo']?.toString() ?? '',
              fmt(e['precio_fin'] as double),
            ]).toList(),
          ),
        ],
      ));

      final bytes = await pdf.save();
      // `Printing.sharePdf` funciona en TODAS las plataformas:
      //  · Web    → descarga el PDF del navegador
      //  · Móvil  → abre el sharesheet nativo
      // No usa path_provider, así que no falla en web.
      await Printing.sharePdf(
        bytes: bytes,
        filename: 'Reporte_${financiadora}_'
            '${DateTime.now().millisecondsSinceEpoch}.pdf',
      );
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Text('✅ PDF de $financiadora generado'),
        backgroundColor: AppColors.statusGreen));
    } catch (e) {
      if (mounted) ScaffoldMessenger.of(context).showSnackBar(SnackBar(
        content: Text('Error al exportar PDF: $e'),
        backgroundColor: AppColors.statusRed));
    }
  }

  // ─────────────────────────────────────────────────────────────
  //  BUILD
  // ─────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: AppColors.surfaceTintBlue,
      appBar: AppBar(
        title: const Text('Reporte por Financiadora'),
        actions: [
          IconButton(
            tooltip: 'Refrescar',
            icon: const Icon(Icons.refresh),
            onPressed: _cargar),
        ],
      ),
      body: _cargando
          ? const Center(child: CircularProgressIndicator())
          : _error != null
              ? Center(child: Padding(
                  padding: const EdgeInsets.all(24),
                  child: Text('Error al cargar: $_error',
                    style: const TextStyle(color: AppColors.statusRed)),
                ))
              : _buildContenido(),
    );
  }

  Widget _buildContenido() {
    final datos = _porFinanciadora;

    return Column(children: [
      // ── Barra de filtros ──────────────────────────────────────
      Container(
        color: Colors.white,
        padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 10),
        child: Row(children: [
          Expanded(child: InkWell(
            onTap: _seleccionarRango,
            borderRadius: BorderRadius.circular(8),
            child: Container(
              padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 10),
              decoration: BoxDecoration(
                color: AppColors.surfaceTintBlue,
                borderRadius: BorderRadius.circular(8),
                border: Border.all(color: AppColors.brandBlue.withValues(alpha: 0.30)),
              ),
              child: Row(children: [
                const Icon(Icons.date_range, color: AppColors.brandBlue, size: 18),
                const SizedBox(width: 8),
                Expanded(child: Text(
                  _desde == null || _hasta == null
                      ? 'Seleccionar rango'
                      : '${_desde!.day.toString().padLeft(2,'0')}/'
                        '${_desde!.month.toString().padLeft(2,'0')}/${_desde!.year}'
                        ' → ${_hasta!.day.toString().padLeft(2,'0')}/'
                        '${_hasta!.month.toString().padLeft(2,'0')}/${_hasta!.year}',
                  style: const TextStyle(
                    fontWeight: FontWeight.w600, fontSize: 13))),
              ]),
            ),
          )),
          const SizedBox(width: 8),
          IconButton(
            tooltip: 'Limpiar rango',
            icon: const Icon(Icons.clear),
            onPressed: () => setState(() {
              _desde = null;
              _hasta = null;
            }),
          ),
        ]),
      ),
      if (datos.isEmpty)
        const Expanded(child: Center(child: Padding(
          padding: EdgeInsets.all(40),
          child: Text(
            'No hay ventas con financiadora en el rango seleccionado.',
            textAlign: TextAlign.center,
            style: TextStyle(color: AppColors.textSecondary)),
        )))
      else
        Expanded(child: _buildListado(datos)),
    ]);
  }

  Widget _buildListado(Map<String, Map<String, dynamic>> datos) {
    // Totales globales
    final totalDeuda  = datos.values.fold<double>(0,
        (s, e) => s + (e['deuda_financ'] as double));
    final totalPagos   = datos.values.fold<double>(0,
        (s, e) => s + (e['pagos_recib'] as double));
    final totalPend    = datos.values.fold<double>(0,
        (s, e) => s + (e['pendiente'] as double));

    // Ordenar por pendiente desc
    final sorted = datos.entries.toList()
      ..sort((a, b) => (b.value['pendiente'] as double)
          .compareTo(a.value['pendiente'] as double));

    return Column(children: [
      // ── Header con totales globales ───────────────────────────
      Container(
        padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 16),
        decoration: const BoxDecoration(
          gradient: LinearGradient(colors: [
            AppColors.brandBlue, AppColors.brandBlueDark]),
        ),
        child: Row(children: [
          Expanded(child: _kpiHeader('Deuda total',
              totalDeuda, AppColors.brandYellow, Icons.account_balance)),
          Container(width: 1, height: 40, color: Colors.white24),
          Expanded(child: _kpiHeader('Recibido',
              totalPagos, AppColors.statusGreen, Icons.check_circle_outline)),
          Container(width: 1, height: 40, color: Colors.white24),
          Expanded(child: _kpiHeader('Pendiente',
              totalPend, AppColors.statusOrange, Icons.pending_actions)),
        ]),
      ),
      // ── Tarjetas por financiadora ─────────────────────────────
      Expanded(child: ListView.builder(
        padding: const EdgeInsets.all(12),
        itemCount: sorted.length,
        itemBuilder: (ctx, i) {
          final f = sorted[i];
          return _buildCardFinanciadora(f.key, f.value);
        },
      )),
    ]);
  }

  Widget _buildCardFinanciadora(String financiadora,
      Map<String, dynamic> data) {
    final precioLista = data['precio_lista'] as double;
    final inicial     = data['inicial']      as double;
    final comision    = data['comision']     as double;
    final deudaFin    = data['deuda_financ'] as double;
    final pagosRecib  = data['pagos_recib']  as double;
    final pendiente   = data['pendiente']    as double;
    final facturas    = (data['facturas'] as Set).length;
    final equipos     = (data['equipos'] as List).cast<Map<String, dynamic>>();
    final pctCobrado  = deudaFin > 0
        ? (pagosRecib / deudaFin).clamp(0.0, 1.0) : 0.0;
    // Neto = Base − Inicial (antes de aplicar la comisión del 3.5%)
    final neto = (precioLista - inicial).clamp(0.0, double.infinity);

    return Card(
      margin: const EdgeInsets.only(bottom: 12),
      child: Padding(
        padding: const EdgeInsets.all(14),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            // Cabecera con nombre y stats rápidos
            Row(children: [
              Container(
                width: 44, height: 44,
                decoration: BoxDecoration(
                  color: AppColors.brandBlue.withValues(alpha: 0.10),
                  borderRadius: BorderRadius.circular(12),
                ),
                child: const Icon(Icons.account_balance,
                    color: AppColors.brandBlue, size: 24),
              ),
              const SizedBox(width: 12),
              Expanded(child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(financiadora,
                    style: const TextStyle(
                      fontSize: 16,
                      fontWeight: FontWeight.w800,
                      color: AppColors.textPrimary)),
                  Text('$facturas factura(s) · ${equipos.length} equipo(s)',
                    style: const TextStyle(
                      color: AppColors.textSecondary, fontSize: 12)),
                ])),
            ]),
            const SizedBox(height: 14),
            // ── Desglose del cálculo ─────────────────────────────
            // Fórmula:  (Base − Inicial) − 3.5% = Deuda
            Container(
              padding: const EdgeInsets.all(10),
              decoration: BoxDecoration(
                color: AppColors.surfaceTintBlue,
                borderRadius: BorderRadius.circular(8),
              ),
              child: Column(children: [
                _lineaCalculo('Base (precio lista financiadora)', precioLista,
                    color: AppColors.brandBlue),
                _lineaCalculo('− Inicial cliente', inicial,
                    color: AppColors.textSecondary, prefix: '-'),
                const Divider(height: 14),
                _lineaCalculo('= Neto', neto,
                    color: AppColors.textPrimary, bold: true),
                _lineaCalculo('− Comisión financiadora (3.5%)', comision,
                    color: AppColors.statusOrange, prefix: '-'),
                const Divider(height: 14),
                _lineaCalculo('= Deuda de la financiadora', deudaFin,
                    color: AppColors.brandBlueDark, bold: true),
                _lineaCalculo('− Pagos recibidos', pagosRecib,
                    color: AppColors.statusGreen, prefix: '-'),
                const Divider(height: 14),
                _lineaCalculo('= Pendiente por cobrar', pendiente,
                    color: pendiente > 0
                        ? AppColors.statusOrange
                        : AppColors.statusGreen,
                    bold: true),
              ]),
            ),
            const SizedBox(height: 10),
            // Barra de progreso
            ClipRRect(
              borderRadius: BorderRadius.circular(6),
              child: LinearProgressIndicator(
                value: pctCobrado,
                minHeight: 8,
                backgroundColor: AppColors.surfaceGrey,
                valueColor: const AlwaysStoppedAnimation(AppColors.statusGreen),
              ),
            ),
            const SizedBox(height: 4),
            Text('${(pctCobrado * 100).toStringAsFixed(1)}% cobrado',
              style: const TextStyle(
                color: AppColors.textSecondary, fontSize: 11)),
            const SizedBox(height: 14),
            // ── Botones de acción ─────────────────────────────
            Wrap(spacing: 8, runSpacing: 8, children: [
              OutlinedButton.icon(
                onPressed: () => _registrarPago(financiadora),
                icon: const Icon(Icons.payments, size: 18),
                label: const Text('Registrar pago'),
                style: OutlinedButton.styleFrom(
                  foregroundColor: AppColors.brandBlue,
                  side: const BorderSide(color: AppColors.brandBlue),
                ),
              ),
              OutlinedButton.icon(
                onPressed: equipos.isEmpty
                    ? null
                    : () => _verEquiposVendidos(financiadora, equipos),
                icon: const Icon(Icons.inventory_2, size: 18),
                label: Text('Ver equipos (${equipos.length})'),
              ),
              OutlinedButton.icon(
                onPressed: equipos.isEmpty
                    ? null
                    : () => _exportarExcel(financiadora, equipos, data),
                icon: const Icon(Icons.table_chart, size: 18,
                    color: Colors.green),
                label: const Text('Excel'),
              ),
              OutlinedButton.icon(
                onPressed: equipos.isEmpty
                    ? null
                    : () => _exportarPDF(financiadora, equipos, data),
                icon: const Icon(Icons.picture_as_pdf, size: 18,
                    color: Colors.red),
                label: const Text('PDF'),
              ),
            ]),
          ],
        ),
      ),
    );
  }

  /// Línea de cálculo (etiqueta a la izquierda, monto a la derecha).
  /// El prefijo "-" se usa para mostrar restas, el "+" para sumas, "" para nada.
  Widget _lineaCalculo(String label, double valor,
      {Color color = AppColors.textPrimary,
       bool bold = false, String prefix = ''}) {
    return Padding(
      padding: const EdgeInsets.symmetric(vertical: 2),
      child: Row(children: [
        Expanded(child: Text(label,
          style: TextStyle(
            color: color,
            fontSize: bold ? 14 : 13,
            fontWeight: bold ? FontWeight.w800 : FontWeight.w500))),
        Text('$prefix${formatCurrency(valor)}',
          style: TextStyle(
            color: color,
            fontSize: bold ? 15 : 13,
            fontWeight: bold ? FontWeight.w900 : FontWeight.w600)),
      ]),
    );
  }

  Widget _kpiHeader(String label, double valor, Color color, IconData icon) {
    return Column(children: [
      Icon(icon, color: color, size: 22),
      const SizedBox(height: 6),
      Text(formatCurrency(valor),
        style: TextStyle(
          color: color,
          fontWeight: FontWeight.w900,
          fontSize: 14)),
      Text(label,
        style: const TextStyle(
          color: Colors.white70, fontSize: 11, letterSpacing: 0.5)),
    ]);
  }

  Widget _kpiCelda(String label, String valor, Color color) {
    return Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
      Text(label,
        style: const TextStyle(
          color: AppColors.textSecondary, fontSize: 11)),
      const SizedBox(height: 2),
      Text(valor,
        style: TextStyle(
          fontWeight: FontWeight.w800,
          color: color, fontSize: 14)),
    ]);
  }
}

// ════════════════════════════════════════════════════════════════════
//                                                                  
//  VENTANA: REPORTE DE RENTABILIDAD DE SERVICIOS TÉCNICOS          
//                                                                  
// ════════════════════════════════════════════════════════════════════
//  Calcula la rentabilidad real del servicio técnico:             
//    Cobrado al cliente − Costo de repuestos = Ganancia            
//                                                                  
//  Vista en 3 pestañas:                                            
//    · POR SERVICIO (línea por línea)                              
//    · POR TÉCNICO (cuánto facturó y ganó cada técnico)            
//    · POR PERÍODO (resumen mensual)                               
// ════════════════════════════════════════════════════════════════════
class VentanaReporteRentabilidadServicios extends StatefulWidget {
  final List<ServicioTecnico> servicios;
  const VentanaReporteRentabilidadServicios({super.key, required this.servicios});
  @override
  State<VentanaReporteRentabilidadServicios> createState() =>
      _VentanaReporteRentabilidadServiciosState();
}

class _VentanaReporteRentabilidadServiciosState
    extends State<VentanaReporteRentabilidadServicios>
    with SingleTickerProviderStateMixin {
  late TabController _tabCtrl;
  DateTime? _desde;
  DateTime? _hasta;

  @override
  void initState() {
    super.initState();
    _tabCtrl = TabController(length: 3, vsync: this);
  }

  @override
  void dispose() { _tabCtrl.dispose(); super.dispose(); }

  List<ServicioTecnico> get _filtrados {
    return widget.servicios.where((s) {
      if (_desde != null && s.fecha.isBefore(_desde!)) return false;
      if (_hasta != null) {
        final fin = DateTime(_hasta!.year, _hasta!.month, _hasta!.day, 23, 59, 59);
        if (s.fecha.isAfter(fin)) return false;
      }
      return true;
    }).toList();
  }

  double get _totalCobrado    => _filtrados.fold(0, (s, x) => s + x.monto);
  double get _totalCostos     => _filtrados.fold(0, (s, x) => s + x.costoRepuestos);
  double get _totalGanancia   => _totalCobrado - _totalCostos;
  double get _margenGlobal    =>
      _totalCobrado > 0 ? (_totalGanancia / _totalCobrado * 100) : 0;

  String _ymd(DateTime d) =>
    '${d.year}-${d.month.toString().padLeft(2,'0')}-${d.day.toString().padLeft(2,'0')}';

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: AppColors.surfaceTintBlue,
      appBar: AppBar(
        title: const Text('Rentabilidad de Servicios'),
        bottom: TabBar(
          controller: _tabCtrl,
          isScrollable: true,
          tabAlignment: TabAlignment.start,
          tabs: const [
            Tab(icon: Icon(Icons.list_alt_outlined), text: 'Por servicio'),
            Tab(icon: Icon(Icons.engineering_outlined), text: 'Por técnico'),
            Tab(icon: Icon(Icons.calendar_month_outlined), text: 'Por mes'),
          ],
        ),
      ),
      body: Column(children: [
        // ── Filtro de fechas ──
        _buildFiltroFechas(),
        // ── Banner global ──
        Container(
          padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 12),
          decoration: const BoxDecoration(
            gradient: LinearGradient(colors: [
              AppColors.brandBlue, AppColors.brandBlueDark]),
          ),
          child: Row(children: [
            Expanded(child: _kpiBanner('Cobrado',
                formatCurrency(_totalCobrado), Colors.white, Icons.attach_money)),
            Container(width: 1, height: 36, color: Colors.white24),
            Expanded(child: _kpiBanner('Costo Rep.',
                formatCurrency(_totalCostos), Colors.orangeAccent, Icons.build_outlined)),
            Container(width: 1, height: 36, color: Colors.white24),
            Expanded(child: _kpiBanner('Ganancia',
                formatCurrency(_totalGanancia),
                _totalGanancia >= 0 ? AppColors.brandYellow : Colors.redAccent,
                Icons.trending_up)),
            Container(width: 1, height: 36, color: Colors.white24),
            Expanded(child: _kpiBanner('Margen',
                '${_margenGlobal.toStringAsFixed(1)}%',
                _totalGanancia >= 0 ? Colors.greenAccent : Colors.redAccent,
                Icons.percent)),
          ]),
        ),
        Expanded(child: TabBarView(
          controller: _tabCtrl,
          children: [
            _vistaPorServicio(),
            _vistaPorTecnico(),
            _vistaPorMes(),
          ],
        )),
      ]),
    );
  }

  Widget _buildFiltroFechas() {
    return Container(
      color: Colors.white,
      padding: const EdgeInsets.fromLTRB(12, 10, 12, 10),
      child: Row(children: [
        Expanded(child: InkWell(
          onTap: () async {
            final d = await showDatePicker(
              context: context,
              initialDate: _desde ?? DateTime.now(),
              firstDate: DateTime(2020),
              lastDate: DateTime.now().add(const Duration(days: 1)),
            );
            if (d != null) setState(() => _desde = d);
          },
          child: InputDecorator(
            decoration: const InputDecoration(
              labelText: 'Desde', isDense: true,
              prefixIcon: Icon(Icons.calendar_today_outlined, size: 16),
            ),
            child: Text(_desde != null ? _ymd(_desde!) : '—'),
          ),
        )),
        const SizedBox(width: 10),
        Expanded(child: InkWell(
          onTap: () async {
            final d = await showDatePicker(
              context: context,
              initialDate: _hasta ?? DateTime.now(),
              firstDate: DateTime(2020),
              lastDate: DateTime.now().add(const Duration(days: 1)),
            );
            if (d != null) setState(() => _hasta = d);
          },
          child: InputDecorator(
            decoration: const InputDecoration(
              labelText: 'Hasta', isDense: true,
              prefixIcon: Icon(Icons.calendar_today_outlined, size: 16),
            ),
            child: Text(_hasta != null ? _ymd(_hasta!) : '—'),
          ),
        )),
        const SizedBox(width: 8),
        IconButton(
          icon: const Icon(Icons.restart_alt),
          tooltip: 'Limpiar fechas',
          onPressed: () => setState(() { _desde = null; _hasta = null; }),
        ),
      ]),
    );
  }

  Widget _kpiBanner(String label, String valor, Color color, IconData icon) {
    return Column(children: [
      Icon(icon, color: color, size: 18),
      const SizedBox(height: 4),
      Text(valor,
        style: TextStyle(
          color: color, fontWeight: FontWeight.w900, fontSize: 13)),
      Text(label,
        style: const TextStyle(
          color: Colors.white70, fontSize: 10, letterSpacing: 0.4)),
    ]);
  }

  // ── Vista 1: por servicio ──────────────────────────────────────
  Widget _vistaPorServicio() {
    final lista = List<ServicioTecnico>.from(_filtrados)
      ..sort((a, b) => b.fecha.compareTo(a.fecha));
    if (lista.isEmpty) {
      return const Center(child: Text('Sin servicios en el rango.',
        style: TextStyle(color: AppColors.textSecondary)));
    }
    return ListView.builder(
      padding: const EdgeInsets.all(10),
      itemCount: lista.length,
      itemBuilder: (ctx, i) {
        final s = lista[i];
        final ganancia = s.ganancia;
        final margen = s.monto > 0 ? (ganancia / s.monto * 100) : 0;
        return Card(
          margin: const EdgeInsets.only(bottom: 8),
          child: Padding(
            padding: const EdgeInsets.all(12),
            child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
              Row(children: [
                Expanded(child: Text(
                  '${s.marca} ${s.modelo}'.trim().isEmpty
                      ? s.nombreCliente
                      : '${s.marca} ${s.modelo}',
                  style: const TextStyle(
                    fontWeight: FontWeight.w700, fontSize: 14))),
                Text(_ymd(s.fecha),
                  style: const TextStyle(
                    color: AppColors.textSecondary, fontSize: 11)),
              ]),
              const SizedBox(height: 2),
              Text('Cliente: ${s.nombreCliente} · Téc: ${s.tecnico}',
                style: const TextStyle(
                  color: AppColors.textSecondary, fontSize: 12)),
              const SizedBox(height: 8),
              Row(children: [
                Expanded(child: _miniKpi('Cobro',
                    formatCurrency(s.monto), AppColors.brandBlue)),
                Expanded(child: _miniKpi('Repuestos',
                    formatCurrency(s.costoRepuestos), AppColors.statusOrange)),
                Expanded(child: _miniKpi('Ganancia',
                    formatCurrency(ganancia),
                    ganancia >= 0 ? AppColors.statusGreen : AppColors.statusRed)),
                Expanded(child: _miniKpi('Margen',
                    '${margen.toStringAsFixed(1)}%',
                    ganancia >= 0 ? AppColors.statusGreen : AppColors.statusRed)),
              ]),
            ]),
          ),
        );
      },
    );
  }

  // ── Vista 2: por técnico ───────────────────────────────────────
  Widget _vistaPorTecnico() {
    final r = <String, Map<String, dynamic>>{};
    for (final s in _filtrados) {
      final tec = s.tecnico.trim().isEmpty ? '(sin asignar)' : s.tecnico;
      final e = r.putIfAbsent(tec, () => {
        'cobrado': 0.0, 'costo': 0.0, 'ganancia': 0.0, 'cantidad': 0,
      });
      e['cobrado']  = (e['cobrado']  as double) + s.monto;
      e['costo']    = (e['costo']    as double) + s.costoRepuestos;
      e['ganancia'] = (e['ganancia'] as double) + s.ganancia;
      e['cantidad'] = (e['cantidad'] as int) + 1;
    }
    if (r.isEmpty) {
      return const Center(child: Text('Sin servicios en el rango.',
        style: TextStyle(color: AppColors.textSecondary)));
    }
    final sorted = r.entries.toList()
      ..sort((a, b) =>
          (b.value['ganancia'] as double).compareTo(a.value['ganancia'] as double));
    return ListView.builder(
      padding: const EdgeInsets.all(12),
      itemCount: sorted.length,
      itemBuilder: (ctx, i) {
        final e = sorted[i];
        final cobrado  = e.value['cobrado']  as double;
        final costo    = e.value['costo']    as double;
        final ganancia = e.value['ganancia'] as double;
        final cantidad = e.value['cantidad'] as int;
        final margen = cobrado > 0 ? (ganancia / cobrado * 100) : 0;
        return Card(
          margin: const EdgeInsets.only(bottom: 10),
          child: Padding(
            padding: const EdgeInsets.all(14),
            child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
              Row(children: [
                Container(
                  width: 40, height: 40,
                  decoration: BoxDecoration(
                    color: AppColors.brandBlue.withValues(alpha: 0.1),
                    borderRadius: BorderRadius.circular(20),
                  ),
                  child: const Icon(Icons.engineering_outlined,
                      color: AppColors.brandBlue),
                ),
                const SizedBox(width: 10),
                Expanded(child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(e.key,
                      style: const TextStyle(
                        fontWeight: FontWeight.w800, fontSize: 14)),
                    Text('$cantidad servicio${cantidad == 1 ? "" : "s"}',
                      style: const TextStyle(
                        color: AppColors.textSecondary, fontSize: 11)),
                  ],
                )),
                Text('${margen.toStringAsFixed(1)}%',
                  style: TextStyle(
                    fontWeight: FontWeight.w800,
                    color: ganancia >= 0
                        ? AppColors.statusGreen : AppColors.statusRed)),
              ]),
              const SizedBox(height: 12),
              Row(children: [
                Expanded(child: _miniKpi('Cobrado',
                    formatCurrency(cobrado), AppColors.brandBlue)),
                Expanded(child: _miniKpi('Repuestos',
                    formatCurrency(costo), AppColors.statusOrange)),
                Expanded(child: _miniKpi('Ganancia',
                    formatCurrency(ganancia),
                    ganancia >= 0 ? AppColors.statusGreen : AppColors.statusRed)),
              ]),
            ]),
          ),
        );
      },
    );
  }

  // ── Vista 3: por mes ───────────────────────────────────────────
  Widget _vistaPorMes() {
    final r = <String, Map<String, dynamic>>{};
    for (final s in _filtrados) {
      final clave = '${s.fecha.year}-${s.fecha.month.toString().padLeft(2, '0')}';
      final e = r.putIfAbsent(clave, () => {
        'cobrado': 0.0, 'costo': 0.0, 'ganancia': 0.0, 'cantidad': 0,
      });
      e['cobrado']  = (e['cobrado']  as double) + s.monto;
      e['costo']    = (e['costo']    as double) + s.costoRepuestos;
      e['ganancia'] = (e['ganancia'] as double) + s.ganancia;
      e['cantidad'] = (e['cantidad'] as int) + 1;
    }
    if (r.isEmpty) {
      return const Center(child: Text('Sin servicios en el rango.',
        style: TextStyle(color: AppColors.textSecondary)));
    }
    // Ordenar por mes descendente (más reciente primero)
    final sorted = r.entries.toList()..sort((a, b) => b.key.compareTo(a.key));

    final meses = ['Ene','Feb','Mar','Abr','May','Jun',
                   'Jul','Ago','Sep','Oct','Nov','Dic'];

    return ListView.builder(
      padding: const EdgeInsets.all(12),
      itemCount: sorted.length,
      itemBuilder: (ctx, i) {
        final e = sorted[i];
        final partes = e.key.split('-');
        final anio = partes[0];
        final mes = int.tryParse(partes[1]) ?? 1;
        final nombreMes = '${meses[mes-1]} $anio';
        final cobrado  = e.value['cobrado']  as double;
        final costo    = e.value['costo']    as double;
        final ganancia = e.value['ganancia'] as double;
        final cantidad = e.value['cantidad'] as int;
        final margen = cobrado > 0 ? (ganancia / cobrado * 100) : 0;

        return Card(
          margin: const EdgeInsets.only(bottom: 10),
          child: Padding(
            padding: const EdgeInsets.all(14),
            child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
              Row(children: [
                const Icon(Icons.calendar_month, color: AppColors.brandBlue),
                const SizedBox(width: 10),
                Expanded(child: Text(nombreMes,
                  style: const TextStyle(
                    fontWeight: FontWeight.w800, fontSize: 15))),
                Text('$cantidad servicios',
                  style: const TextStyle(
                    color: AppColors.textSecondary, fontSize: 12)),
              ]),
              const SizedBox(height: 10),
              Row(children: [
                Expanded(child: _miniKpi('Cobrado',
                    formatCurrency(cobrado), AppColors.brandBlue)),
                Expanded(child: _miniKpi('Repuestos',
                    formatCurrency(costo), AppColors.statusOrange)),
                Expanded(child: _miniKpi('Ganancia',
                    formatCurrency(ganancia),
                    ganancia >= 0 ? AppColors.statusGreen : AppColors.statusRed)),
                Expanded(child: _miniKpi('Margen',
                    '${margen.toStringAsFixed(1)}%',
                    ganancia >= 0 ? AppColors.statusGreen : AppColors.statusRed)),
              ]),
            ]),
          ),
        );
      },
    );
  }

  Widget _miniKpi(String label, String valor, Color color) {
    return Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
      Text(label,
        style: const TextStyle(
          color: AppColors.textSecondary, fontSize: 10)),
      const SizedBox(height: 1),
      Text(valor,
        style: TextStyle(
          fontWeight: FontWeight.w800, color: color, fontSize: 13)),
    ]);
  }
}

// ════════════════════════════════════════════════════════════
//  VENTANA DE ESTADÍSTICAS DE PRODUCTOS
// ════════════════════════════════════════════════════════════
//  Muestra rankings de productos y modelos por unidades vendidas
//  e ingreso generado, filtrable por rango de fechas. Permite
//  responder preguntas como: ¿cuál fue el modelo más vendido el
//  mes pasado? ¿cuánto ingresó la marca Xiaomi? ¿qué categoría
//  está rindiendo más?
class VentanaEstadisticasProductos extends StatefulWidget {
  const VentanaEstadisticasProductos({super.key});
  @override State<VentanaEstadisticasProductos> createState() =>
      _VentanaEstadisticasProductosState();
}

class _VentanaEstadisticasProductosState
    extends State<VentanaEstadisticasProductos>
    with SingleTickerProviderStateMixin {
  // Filtros
  DateTime? _desde;
  DateTime? _hasta;
  String? _marcaFiltro;     // null = todas
  String? _categoriaFiltro; // null = todas

  late TabController _tabs;
  bool _cargando = false;

  @override
  void initState() {
    super.initState();
    _tabs = TabController(length: 3, vsync: this);
    final now = DateTime.now();
    _desde = DateTime(now.year, now.month, 1);
    _hasta = now;
    _cargar();
  }

  @override
  void dispose() {
    _tabs.dispose();
    super.dispose();
  }

  Future<void> _cargar() async {
    setState(() => _cargando = true);
    try {
      // Cargar productos, IMEIs y facturas frescas en paralelo.
      final results = await Future.wait([
        _Api.get('productos'),
        _Api.get('stock_imei'),
        _Api.get('facturas'),
      ]);
      catalogoGlobal = ((results[0] as List?) ?? [])
          .map((m) => Producto.fromMap(m as Map<String, dynamic>))
          .toList();
      stockImeiGlobal = ((results[1] as List?) ?? [])
          .map((m) => ImeiRegistro.fromMap(m as Map<String, dynamic>))
          .toList();

      final prodPorCodigo = <String, Producto>{
        for (final p in catalogoGlobal) p.codigo: p
      };
      final imeiPorNumero = <String, ImeiRegistro>{
        for (final i in stockImeiGlobal) i.imei: i
      };

      ventasGlobal = ((results[2] as List?) ?? []).map((m) {
        final mp = m as Map<String, dynamic>;
        final equipos = <ImeiRegistro>[];
        for (final imei in (mp['equipos'] as List? ?? [])) {
          final r = imeiPorNumero[imei.toString()];
          if (r != null) equipos.add(r);
        }
        final items = <Producto>[];
        for (final cod in (mp['items'] as List? ?? [])) {
          final p = prodPorCodigo[cod.toString()];
          if (p != null) items.add(p);
        }
        return FacturaModel(
          id: mp['id'] is int ? mp['id'] : int.tryParse(mp['id']?.toString() ?? ''),
          cliente: mp['cliente']?.toString() ?? '',
          cedula: mp['cedula']?.toString() ?? '',
          telefono: mp['telefono']?.toString() ?? '',
          nroFactura: mp['nro_factura']?.toString() ?? '',
          vendedor: mp['vendedor']?.toString() ?? '',
          tienda: mp['tienda']?.toString() ?? '',
          fecha: mp['fecha']?.toString() ?? '',
          equipos: equipos,
          itemsSinImei: items,
          pagos: ((mp['pagos'] as List?) ?? [])
              .map((p) => PagoFactura.fromMap(p as Map<String, dynamic>))
              .toList(),
        );
      }).toList();
    } catch (e) {
      debugPrint('[Estadisticas] error: $e');
    } finally {
      if (mounted) setState(() => _cargando = false);
    }
  }

  /// Recorre las facturas filtradas y agrega TODOS los productos
  /// vendidos (con IMEI y sin IMEI). Devuelve un map producto→stats
  /// con unidades y total ingresado.
  Map<String, _StatsItem> _calcularRanking() {
    final m = <String, _StatsItem>{};
    for (final f in ventasGlobal) {
      final fecha = parseFechaFlexible(f.fecha);
      if (fecha == null) continue;
      if (_desde != null && fecha.isBefore(
          DateTime(_desde!.year, _desde!.month, _desde!.day))) continue;
      if (_hasta != null) {
        final fin = DateTime(_hasta!.year, _hasta!.month, _hasta!.day, 23, 59, 59);
        if (fecha.isAfter(fin)) continue;
      }
      for (final eq in f.equipos) {
        _registrar(m, eq.producto, 1, eq.producto.precioVenta);
      }
      for (final it in f.itemsSinImei) {
        _registrar(m, it, 1, it.precioVenta);
      }
    }
    return m;
  }

  void _registrar(Map<String, _StatsItem> m, Producto p,
      int unidades, double monto) {
    // Filtros
    if (_marcaFiltro != null && p.marca != _marcaFiltro) return;
    if (_categoriaFiltro != null && p.categoria != _categoriaFiltro) return;
    final key = p.codigo;
    final e = m.putIfAbsent(key, () => _StatsItem(producto: p));
    e.unidades += unidades;
    e.total    += monto;
  }

  List<String> get _marcasDisponibles {
    final set = catalogoGlobal
        .map((p) => p.marca)
        .where((m) => m.isNotEmpty && m != 'Genérico')
        .toSet();
    return set.toList()..sort();
  }

  List<String> get _categoriasDisponibles {
    return List<String>.from(CategoriasProductos.lista)..sort();
  }

  @override
  Widget build(BuildContext context) {
    final ranking = _calcularRanking().values.toList()
      ..sort((a,b) => b.unidades.compareTo(a.unidades));
    final porModelo = _agruparPor((p) => '${p.marca} ${p.modelo}'.trim(), ranking);
    final porMarca  = _agruparPor((p) => p.marca, ranking);
    final totalU = ranking.fold<int>(0, (s,e) => s + e.unidades);
    final totalI = ranking.fold<double>(0, (s,e) => s + e.total);

    return Scaffold(
      appBar: AppBar(
        title: const Text('Estadísticas de Productos'),
        backgroundColor: AppColors.brandBlue,
        foregroundColor: Colors.white,
        bottom: TabBar(
          controller: _tabs,
          labelColor: Colors.white,
          unselectedLabelColor: Colors.white60,
          indicatorColor: AppColors.brandYellow,
          tabs: const [
            Tab(icon: Icon(Icons.inventory_2), text: 'Productos'),
            Tab(icon: Icon(Icons.phone_android), text: 'Modelos'),
            Tab(icon: Icon(Icons.business), text: 'Marcas'),
          ],
        ),
        actions: [
          IconButton(
              icon: const Icon(Icons.refresh),
              tooltip: "Actualizar",
              onPressed: _cargar),
        ],
      ),
      body: Column(children: [
        _buildFiltros(),
        _buildKPIs(totalU, totalI),
        Expanded(child: _cargando
            ? const Center(child: CircularProgressIndicator())
            : TabBarView(controller: _tabs, children: [
                _buildLista(ranking),
                _buildLista(porModelo),
                _buildLista(porMarca),
              ])),
      ]),
    );
  }

  /// Agrupa el ranking de productos por una clave arbitraria.
  /// Devuelve una lista de _StatsItem con la suma agregada y un
  /// "producto representativo" (el primero del grupo) para mostrar.
  List<_StatsItem> _agruparPor(
      String Function(Producto) keyOf, List<_StatsItem> items) {
    final agrup = <String, _StatsItem>{};
    for (final e in items) {
      final k = keyOf(e.producto);
      if (k.trim().isEmpty) continue;
      final a = agrup.putIfAbsent(k, () => _StatsItem(producto: e.producto));
      a.unidades += e.unidades;
      a.total    += e.total;
    }
    return agrup.values.toList()
      ..sort((a,b) => b.unidades.compareTo(a.unidades));
  }

  Widget _buildFiltros() {
    return Container(
      padding: const EdgeInsets.all(12),
      color: AppColors.surfaceTintBlue,
      child: Column(children: [
        InkWell(
          onTap: () async {
            final r = await showDateRangePicker(
              context: context,
              firstDate: DateTime(2020),
              lastDate: DateTime.now(),
              initialDateRange: _desde != null && _hasta != null
                  ? DateTimeRange(start: _desde!, end: _hasta!) : null,
            );
            if (r != null) setState(() {
              _desde = r.start; _hasta = r.end;
            });
          },
          child: InputDecorator(
            decoration: const InputDecoration(
              labelText: 'Rango de fechas',
              prefixIcon: Icon(Icons.event),
              isDense: true,
              border: OutlineInputBorder(),
            ),
            child: Text(
              '${_desde?.day.toString().padLeft(2,"0")}/'
              '${_desde?.month.toString().padLeft(2,"0")}/${_desde?.year}'
              '  →  '
              '${_hasta?.day.toString().padLeft(2,"0")}/'
              '${_hasta?.month.toString().padLeft(2,"0")}/${_hasta?.year}',
            ),
          ),
        ),
        const SizedBox(height: 8),
        Row(children: [
          Expanded(child: DropdownButtonFormField<String?>(
            value: _marcaFiltro,
            isExpanded: true,
            decoration: const InputDecoration(
                labelText: 'Marca', isDense: true,
                border: OutlineInputBorder()),
            items: [
              const DropdownMenuItem<String?>(value: null,
                  child: Text('Todas')),
              ..._marcasDisponibles.map((m) =>
                  DropdownMenuItem<String?>(value: m, child: Text(m))),
            ],
            onChanged: (v) => setState(() => _marcaFiltro = v),
          )),
          const SizedBox(width: 8),
          Expanded(child: DropdownButtonFormField<String?>(
            value: _categoriaFiltro,
            isExpanded: true,
            decoration: const InputDecoration(
                labelText: 'Categoría', isDense: true,
                border: OutlineInputBorder()),
            items: [
              const DropdownMenuItem<String?>(value: null,
                  child: Text('Todas')),
              ..._categoriasDisponibles.map((c) =>
                  DropdownMenuItem<String?>(value: c, child: Text(c))),
            ],
            onChanged: (v) => setState(() => _categoriaFiltro = v),
          )),
        ]),
      ]),
    );
  }

  Widget _buildKPIs(int unidades, double total) {
    return Container(
      color: AppColors.brandBlue,
      padding: const EdgeInsets.all(14),
      child: Row(children: [
        Expanded(child: _kpi(
          'Unidades vendidas', '$unidades', Icons.shopping_bag,
          AppColors.brandYellow)),
        Container(width: 1, height: 30, color: Colors.white24),
        Expanded(child: _kpi(
          'Ingreso total',
          '\$${total.toStringAsFixed(2)}',
          Icons.attach_money,
          AppColors.statusGreen)),
      ]),
    );
  }

  Widget _kpi(String label, String value, IconData icon, Color color) {
    return Column(children: [
      Icon(icon, color: color, size: 22),
      const SizedBox(height: 4),
      Text(value, style: TextStyle(
          color: color, fontWeight: FontWeight.w900, fontSize: 18)),
      Text(label, style: const TextStyle(
          color: Colors.white70, fontSize: 11)),
    ]);
  }

  Widget _buildLista(List<_StatsItem> items) {
    if (items.isEmpty) {
      return const Center(child: Padding(
        padding: EdgeInsets.all(40),
        child: Text(
          'Sin ventas en el rango seleccionado',
          style: TextStyle(color: AppColors.textSecondary)),
      ));
    }
    final maxU = items.first.unidades;
    return ListView.builder(
      padding: const EdgeInsets.all(12),
      itemCount: items.length,
      itemBuilder: (_, i) {
        final e = items[i];
        final pct = maxU > 0 ? e.unidades / maxU : 0.0;
        return Container(
          margin: const EdgeInsets.only(bottom: 8),
          padding: const EdgeInsets.all(12),
          decoration: BoxDecoration(
            color: Colors.white,
            borderRadius: BorderRadius.circular(10),
            border: Border.all(color: Colors.grey.shade300),
          ),
          child: Column(crossAxisAlignment: CrossAxisAlignment.start,
              children: [
            Row(children: [
              Container(
                width: 32, height: 32,
                decoration: BoxDecoration(
                  color: i < 3
                      ? AppColors.brandYellow.withValues(alpha: 0.2)
                      : AppColors.surfaceGrey,
                  borderRadius: BorderRadius.circular(8),
                ),
                child: Center(child: Text('#${i+1}',
                    style: TextStyle(
                        fontWeight: FontWeight.w900,
                        color: i < 3 ? AppColors.brandBlue
                                     : AppColors.textSecondary))),
              ),
              const SizedBox(width: 10),
              Expanded(child: Column(
                crossAxisAlignment: CrossAxisAlignment.start, children: [
                  Text(_etiqueta(e.producto),
                      style: const TextStyle(
                          fontWeight: FontWeight.w700, fontSize: 14)),
                  Text('${e.producto.categoria} · ${e.producto.marca}',
                      style: const TextStyle(
                          fontSize: 11,
                          color: AppColors.textSecondary)),
                ])),
              Column(crossAxisAlignment: CrossAxisAlignment.end, children: [
                Text('${e.unidades} u.',
                    style: const TextStyle(
                        fontWeight: FontWeight.w900,
                        color: AppColors.brandBlue, fontSize: 15)),
                Text('\$${e.total.toStringAsFixed(2)}',
                    style: const TextStyle(
                        color: AppColors.statusGreen,
                        fontWeight: FontWeight.w700, fontSize: 12)),
              ]),
            ]),
            const SizedBox(height: 8),
            ClipRRect(
              borderRadius: BorderRadius.circular(4),
              child: LinearProgressIndicator(
                value: pct,
                minHeight: 6,
                backgroundColor: AppColors.surfaceGrey,
                valueColor: AlwaysStoppedAnimation<Color>(
                    i < 3 ? AppColors.brandYellow : AppColors.brandBlue),
              ),
            ),
          ]),
        );
      },
    );
  }

  String _etiqueta(Producto p) {
    if (p.modelo.isNotEmpty && p.modelo != 'N/A') {
      return '${p.marca} ${p.modelo}'.trim();
    }
    return p.nombre;
  }
}

class _StatsItem {
  final Producto producto;
  int unidades;
  double total;
  _StatsItem({required this.producto, this.unidades = 0, this.total = 0});
}

/// Estructura auxiliar para agregar compras por producto al
/// reflejarlas en el inventario (suma de unidades y suma de USD,
/// para luego computar el precio promedio ponderado).
class _AggCompra {
  double unidades = 0;
  double totalUsd = 0;
}
